async function showStudentPromotion() {
    const pageTitle = document.getElementById('pageTitle');
    if (pageTitle) pageTitle.innerHTML = '<i class="fas fa-arrow-up mr-2"></i>Promote Students';
    
    try {
        const classesRes = await fetch('/api/school/classes');
        const classes = await classesRes.json();
        
        const studentsRes = await fetch('/api/students');
        const students = await studentsRes.json();
        
        const enrollmentsRes = await fetch('/api/enrollments');
        let enrollments = await enrollmentsRes.json();
        
        const { currentYear } = currentAcademicSettings;
        const nextYear = currentYear + 1;
        
        // Get current enrollments
        const currentEnrollments = enrollments.filter(e => e.academicYear === currentYear && e.isCurrent);
        
        // Map students to their current class
        const studentsWithClass = students.map(student => {
            const enrollment = currentEnrollments.find(e => e.studentId === student.id);
            const classObj = classes.find(c => c.id === enrollment?.classId);
            return {
                ...student,
                currentClassId: enrollment?.classId,
                currentClassName: classObj?.name || 'Not Enrolled',
                enrollmentId: enrollment?.id
            };
        }).filter(s => s.currentClassId);
        
        const html = `
            <div class="bg-white rounded-xl shadow-sm p-6">
                <div class="flex justify-between items-center mb-6">
                    <h2 class="text-xl font-bold">🎓 Promote Students to Next Class</h2>
                    <div class="text-sm text-gray-500">
                        Promoting from ${currentYear} to ${nextYear}
                    </div>
                </div>
                
                <div class="grid grid-cols-1 md:grid-cols-2 gap-6 mb-6">
                    <div>
                        <label class="block text-sm font-medium mb-2">From Class</label>
                        <select id="fromClassSelect" class="w-full border rounded-lg px-3 py-2">
                            <option value="">Select Current Class</option>
                            ${classes.map(c => `<option value="${c.id}">${c.name}</option>`).join('')}
                        </select>
                    </div>
                    <div>
                        <label class="block text-sm font-medium mb-2">To Class</label>
                        <select id="toClassSelect" class="w-full border rounded-lg px-3 py-2">
                            <option value="">Select Next Class</option>
                            ${classes.map(c => `<option value="${c.id}">${c.name}</option>`).join('')}
                        </select>
                    </div>
                </div>
                
                <button onclick="loadStudentsForPromotion()" class="bg-blue-600 text-white px-6 py-2 rounded-lg hover:bg-blue-700">
                    <i class="fas fa-users"></i> Load Students
                </button>
                
                <div id="promotionStudentsList" class="mt-6"></div>
            </div>
        `;
        
        const mainContent = document.getElementById('mainContent');
        if (mainContent) mainContent.innerHTML = html;
        
        // Store data globally for use in loadStudentsForPromotion
        window.promotionClasses = classes;
        window.promotionStudents = studentsWithClass;
        window.promotionCurrentYear = currentYear;
        window.promotionNextYear = nextYear;
        
    } catch (error) {
        console.error('Error loading promotion page:', error);
        const mainContent = document.getElementById('mainContent');
        if (mainContent) {
            mainContent.innerHTML = `
                <div class="bg-red-50 border border-red-200 rounded-lg p-6 text-center">
                    <i class="fas fa-exclamation-triangle text-red-600 text-4xl mb-3"></i>
                    <p class="text-red-600">Error loading promotion page</p>
                    <button onclick="showStudentPromotion()" class="mt-3 bg-red-600 text-white px-4 py-2 rounded">Retry</button>
                </div>
            `;
        }
    }
}

