async function loadStudentsForPromotion() {
    const fromClassId = document.getElementById('fromClassSelect')?.value;
    const toClassId = document.getElementById('toClassSelect')?.value;
    
    if (!fromClassId || !toClassId) {
        alert('Please select both From Class and To Class');
        return;
    }
    
    // Find students in the selected class
    const students = window.promotionStudents || [];
    const classStudents = students.filter(s => s.currentClassId === fromClassId);
    
    if (classStudents.length === 0) {
        document.getElementById('promotionStudentsList').innerHTML = `
            <div class="bg-yellow-50 border border-yellow-200 rounded-lg p-6 text-center mt-4">
                <i class="fas fa-info-circle text-yellow-600 text-3xl mb-2"></i>
                <p class="text-yellow-600">No students found in this class</p>
            </div>
        `;
        return;
    }
    
    const fromClass = window.promotionClasses.find(c => c.id === fromClassId);
    const toClass = window.promotionClasses.find(c => c.id === toClassId);
    
    const html = `
        <form id="promotionForm" class="mt-4">
            <div class="bg-blue-50 p-3 rounded-lg mb-4">
                <div class="flex justify-between items-center">
                    <div>
                        <span class="font-semibold">From:</span> ${fromClass?.name}
                        <span class="font-semibold ml-4">To:</span> ${toClass?.name}
                        <span class="font-semibold ml-4">Academic Year:</span> ${window.promotionCurrentYear} → ${window.promotionNextYear}
                    </div>
                    <div>
                        <label class="flex items-center">
                            <input type="checkbox" id="selectAllStudents" class="mr-2" onchange="toggleAllPromotionStudents()">
                            <span class="text-sm">Select All (${classStudents.length})</span>
                        </label>
                    </div>
                </div>
            </div>
            
            <div class="overflow-x-auto max-h-96 overflow-y-auto border rounded-lg">
                <table class="w-full text-sm">
                    <thead class="bg-gray-100 sticky top-0">
                        <tr>
                            <th class="p-3 w-12"><input type="checkbox" id="selectAllCheckbox" onchange="toggleAllPromotionStudents()"></th>
                            <th class="p-3 text-left">Admission No.</th>
                            <th class="p-3 text-left">Student Name</th>
                            <th class="p-3 text-left">Current Class</th>
                            <th class="p-3 text-left">Promote To</th>
                        </tr>
                    </thead>
                    <tbody>
                        ${classStudents.map(s => `
                            <tr class="border-b hover:bg-gray-50">
                                <td class="p-3 text-center">
                                    <input type="checkbox" name="studentIds" value="${s.id}" class="student-promotion-checkbox" onchange="updatePromotionSelectionCount()">
                                </td>
                                <td class="p-3 font-mono text-xs">${s.admissionNumber || 'N/A'}</td>
                                <td class="p-3">${s.firstName} ${s.lastName}</td>
                                <td class="p-3">${s.currentClassName}</td>
                                <td class="p-3 font-semibold text-green-600">${toClass?.name}</td>
                            </tr>
                        `).join('')}
                    </tbody>
                </table>
            </div>
            
            <div class="mt-4 flex justify-between items-center">
                <div id="selectedCountDisplay" class="text-sm text-gray-600">
                    Selected: 0 of ${classStudents.length} students
                </div>
                <button type="submit" class="bg-green-600 text-white px-6 py-2 rounded-lg hover:bg-green-700">
                    <i class="fas fa-arrow-up"></i> Promote Selected Students
                </button>
            </div>
        </form>
    `;
    
    document.getElementById('promotionStudentsList').innerHTML = html;
    
    // Store promotion data globally
    window.promotionData = {
        fromClassId,
        toClassId,
        fromClassName: fromClass?.name,
        toClassName: toClass?.name,
        students: classStudents
    };
    
    // Add form submit handler
    const form = document.getElementById('promotionForm');
    if (form) {
        form.addEventListener('submit', async (e) => {
            e.preventDefault();
            await promoteSelectedStudents();
        });
    }
}

// ==================== TOGGLE ALL PROMOTION STUDENTS ====================

function toggleAllPromotionStudents() {
    const selectAllCheckbox = document.getElementById('selectAllCheckbox') || document.getElementById('selectAllStudents');
    const checkboxes = document.querySelectorAll('.student-promotion-checkbox');
    const isChecked = selectAllCheckbox?.checked || false;
    
    checkboxes.forEach(cb => {
        cb.checked = isChecked;
    });
    
    updatePromotionSelectionCount();
}

// ==================== UPDATE PROMOTION SELECTION COUNT ====================

function updatePromotionSelectionCount() {
    const checkboxes = document.querySelectorAll('.student-promotion-checkbox:checked');
    const total = document.querySelectorAll('.student-promotion-checkbox').length;
    const selectedCount = checkboxes.length;
    
    const displaySpan = document.getElementById('selectedCountDisplay');
    if (displaySpan) {
        displaySpan.innerHTML = `Selected: ${selectedCount} of ${total} students`;
    }
    
    const selectAllCheckbox = document.getElementById('selectAllCheckbox') || document.getElementById('selectAllStudents');
    if (selectAllCheckbox) {
        selectAllCheckbox.checked = selectedCount === total && total > 0;
        selectAllCheckbox.indeterminate = selectedCount > 0 && selectedCount < total;
    }
}

// ==================== PROMOTE SELECTED STUDENTS ====================

async function promoteSelectedStudents() {
    const selectedCheckboxes = document.querySelectorAll('.student-promotion-checkbox:checked');
    const selectedStudentIds = Array.from(selectedCheckboxes).map(cb => cb.value);
    
    if (selectedStudentIds.length === 0) {
        alert('Please select at least one student to promote');
        return;
    }
    
    const { toClassId, fromClassName, toClassName } = window.promotionData;
    const currentYear = window.promotionCurrentYear;
    const nextYear = window.promotionNextYear;
    
    const confirmation = confirm(
        `⚠️ Are you sure you want to promote ${selectedStudentIds.length} student(s)?\n\n` +
        `From: ${fromClassName} (${currentYear})\n` +
        `To: ${toClassName} (${nextYear})\n\n` +
        `This action cannot be undone.`
    );
    
    if (!confirmation) return;
    
    const submitBtn = document.querySelector('#promotionForm button[type="submit"]');
    const originalText = submitBtn.innerText;
    submitBtn.innerText = 'Promoting...';
    submitBtn.disabled = true;
    
    try {
        const response = await fetch('/api/students/promote', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ 
                studentIds: selectedStudentIds, 
                toClassId: toClassId,
                academicYear: nextYear,
                fromYear: currentYear
            })
        });
        
        if (response.ok) {
            const result = await response.json();
            alert(`✅ ${selectedStudentIds.length} students promoted successfully to ${toClassName} for academic year ${nextYear}!`);
            
            // Refresh the promotion page
            showStudentPromotion();
        } else {
            const error = await response.json();
            alert('❌ Error promoting students: ' + (error.error || 'Unknown error'));
        }
    } catch (error) {
        console.error('Error:', error);
        alert('Network error: ' + error.message);
    } finally {
        submitBtn.innerText = originalText;
        submitBtn.disabled = false;
    }
}

// Make functions global
window.showStudentPromotion = showStudentPromotion;
window.loadStudentsForPromotion = loadStudentsForPromotion;
window.toggleAllPromotionStudents = toggleAllPromotionStudents;
window.updatePromotionSelectionCount = updatePromotionSelectionCount;
window.promoteSelectedStudents = promoteSelectedStudents;

window.loadStudentsForPromotion = async () => {
    const fromClassId = document.getElementById('fromClass').value;
    const toClassId = document.getElementById('toClass').value;
    
    if (!fromClassId || !toClassId) {
        alert('Please select both classes');
        return;
    }
    
    try {
        const studentsRes = await fetch('/api/students');
        const allStudents = await studentsRes.json();
        const classObj = window.allClassesData?.find(c => c.id === fromClassId);
        const students = allStudents.filter(s => s.currentClass === classObj?.name);
        
        if (students.length === 0) {
            document.getElementById('promotionStudentsList').innerHTML = '<p class="text-yellow-600 mt-4">No students found in this class</p>';
            return;
        }
        
        const html = `<form id="promotionForm" class="mt-4"><div class="overflow-x-auto"><table class="w-full"><thead class="bg-gray-100"><tr><th class="p-3"><input type="checkbox" id="selectAll" onclick="toggleAllStudents(this)"></th><th class="p-3 text-left">Admission No.</th><th class="p-3 text-left">Student Name</th><th class="p-3 text-left">Current Class</th><th class="p-3 text-left">Promote To</th></tr></thead><tbody>${students.map(s => `<tr class="border-b"><td class="p-3"><input type="checkbox" name="studentIds" value="${s.id}" class="student-checkbox"></td><td class="p-3">${s.admissionNumber}</td><td class="p-3">${s.firstName} ${s.lastName}</td><td class="p-3">${s.currentClass || 'Current Class'}</td><td class="p-3">${document.getElementById('toClass').options[document.getElementById('toClass').selectedIndex]?.text || 'Next Class'}</td></tr>`).join('')}</tbody>}</table></div><button type="submit" class="mt-4 bg-green-600 text-white px-6 py-2 rounded-lg"></button></form>`;
        
        document.getElementById('promotionStudentsList').innerHTML = html;
        
        document.getElementById('promotionForm').addEventListener('submit', async (e) => {
            e.preventDefault();
            const selectedStudents = Array.from(document.querySelectorAll('input[name="studentIds"]:checked')).map(cb => cb.value);
            
            if (selectedStudents.length === 0) {
                alert('Please select students to promote');
                return;
            }
            
            const response = await fetch('/api/students/promote', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ studentIds: selectedStudents, toClassId: toClassId, academicYear: new Date().getFullYear() })
            });
            
            if (response.ok) {
                alert(`✅ ${selectedStudents.length} students promoted successfully!`);
                addNotification(`${selectedStudents.length} students were promoted to next class`);
                showStudentPromotion();
            } else {
                alert('❌ Error promoting students');
            }
        });
    } catch (error) {
        console.error('Error:', error);
    }
};

window.toggleAllStudents = (checkbox) => {
    const checkboxes = document.querySelectorAll('.student-checkbox');
    checkboxes.forEach(cb => cb.checked = checkbox.checked);
};

// ==================== CLASS MANAGEMENT ====================
async function showClassManagement() {
    const pageTitle = document.getElementById('pageTitle');
    if (pageTitle) pageTitle.innerHTML = '<i class="fas fa-chalkboard mr-2"></i>Manage Classes';
    
    try {
        const classesRes = await fetch('/api/school/classes');
        const classes = await classesRes.json();
        
        const html = `
            <div class="bg-white rounded-xl shadow-sm p-6">
                <h2 class="text-xl font-bold mb-4">🏫 Manage Classes</h2>
                <form id="addClassForm" class="mb-6 p-4 bg-gray-50 rounded-lg"><div class="grid grid-cols-1 md:grid-cols-3 gap-4"><input type="text" id="className" placeholder="Class Name" required class="border rounded-lg px-3 py-2"><select id="classLevel" required class="border rounded-lg px-3 py-2"><option value="Nursery">Nursery</option><option value="LowerPrimary">Lower Primary</option><option value="UpperPrimary">Upper Primary</option></select><button type="submit" class="bg-green-600 text-white px-4 py-2 rounded-lg">Add Class</button></div></form>
                <div class="overflow-x-auto"><table class="w-full"><thead class="bg-gray-100"><tr><th class="p-3 text-left">Class Name</th><th class="p-3 text-left">Level</th><th class="p-3 text-left">Actions</th></tr></thead><tbody>${classes.map(c => `<tr class="border-b"><td class="p-3">${c.name}</td><td class="p-3">${c.level}</td><td class="p-3"><button onclick="deleteClass('${c.id}')" class="text-red-600 hover:text-red-800"><i class="fas fa-trash"></i> Delete</button></td></tr>`).join('')}</tbody>}</table></div>
            </div>
        `;
        
        const mainContent = document.getElementById('mainContent');
        if (mainContent) mainContent.innerHTML = html;
        
        const form = document.getElementById('addClassForm');
        if (form) {
            form.addEventListener('submit', async (e) => {
                e.preventDefault();
                await fetch('/api/school/classes', {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({ name: document.getElementById('className').value, level: document.getElementById('classLevel').value })
                });
                addNotification(`New class ${document.getElementById('className').value} was added`);
                showClassManagement();
            });
        }
    } catch (error) {
        console.error('Error:', error);
    }
}

window.deleteClass = async (id) => {
    if (confirm('Delete this class?')) {
        await fetch(`/api/school/classes/${id}`, { method: 'DELETE' });
        addNotification('A class was deleted');
        showClassManagement();
    }
};

// ==================== COMPLETE MANAGE SUBJECTS ====================
async function showSubjectManagement() {
    const pageTitle = document.getElementById('pageTitle');
    if (pageTitle) pageTitle.innerHTML = '<i class="fas fa-book mr-2"></i>Manage Subjects';
    
    try {
        const [subjectsRes, classesRes] = await Promise.all([
            fetch('/api/school/subjects'),
            fetch('/api/school/classes')
        ]);
        
        let subjects = await subjectsRes.json();
        const classes = await classesRes.json();
        
        window.allSubjectsData = subjects;
        window.allClassesData = classes;
        
        renderSubjectManagement(subjects, classes);
        
    } catch (error) {
        console.error('Error:', error);
        const mainContent = document.getElementById('mainContent');
        if (mainContent) {
            mainContent.innerHTML = `<div class="bg-red-50 border border-red-200 rounded-lg p-6 text-center"><i class="fas fa-exclamation-triangle text-red-600 text-4xl mb-3"></i><p class="text-red-600">Error loading subjects. Please refresh the page.</p><button onclick="showSubjectManagement()" class="mt-3 bg-red-600 text-white px-4 py-2 rounded">Retry</button></div>`;
        }
    }
}

function renderSubjectManagement(subjects, classes) {
    const totalSubjects = subjects.length;
    const coreSubjects = subjects.filter(s => s.category === 'Core').length;
    const electiveSubjects = subjects.filter(s => s.category === 'Elective').length;
    const subjectsWithClasses = subjects.filter(s => s.classId && s.classId !== 'all').length;
    
    const html = `
        <div class="space-y-6">
            <div class="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
                <div class="bg-gradient-to-r from-blue-500 to-blue-600 rounded-xl p-4 text-white"><div class="flex items-center justify-between"><div><p class="text-sm opacity-90">Total Subjects</p><p class="text-2xl font-bold">${totalSubjects}</p></div><i class="fas fa-book text-3xl opacity-50"></i></div></div>
                <div class="bg-gradient-to-r from-green-500 to-green-600 rounded-xl p-4 text-white"><div class="flex items-center justify-between"><div><p class="text-sm opacity-90">Core Subjects</p><p class="text-2xl font-bold">${coreSubjects}</p></div><i class="fas fa-star text-3xl opacity-50"></i></div></div>
                <div class="bg-gradient-to-r from-purple-500 to-purple-600 rounded-xl p-4 text-white"><div class="flex items-center justify-between"><div><p class="text-sm opacity-90">Elective Subjects</p><p class="text-2xl font-bold">${electiveSubjects}</p></div><i class="fas fa-heart text-3xl opacity-50"></i></div></div>
                <div class="bg-gradient-to-r from-orange-500 to-orange-600 rounded-xl p-4 text-white"><div class="flex items-center justify-between"><div><p class="text-sm opacity-90">Assigned to Classes</p><p class="text-2xl font-bold">${subjectsWithClasses}</p></div><i class="fas fa-chalkboard text-3xl opacity-50"></i></div></div>
            </div>
            
            <div class="bg-white rounded-xl shadow-sm p-6">
                <div class="flex justify-between items-center mb-4"><h2 class="text-xl font-bold">➕ Add New Subject</h2><button onclick="toggleAddSubjectForm()" class="text-blue-600 hover:text-blue-800"><i class="fas fa-chevron-down"></i> Show/Hide Form</button></div>
                <div id="addSubjectFormContainer" class="hidden"><form id="addSubjectForm" class="space-y-4"><div class="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4"><div><label class="block text-sm font-medium mb-1 required-field">Subject Name *</label><input type="text" id="subjectName" required class="w-full border rounded-lg px-3 py-2 focus:ring-2 focus:ring-blue-500" placeholder="e.g., Mathematics"></div><div><label class="block text-sm font-medium mb-1 required-field">Subject Code *</label><input type="text" id="subjectCode" required class="w-full border rounded-lg px-3 py-2 focus:ring-2 focus:ring-blue-500" placeholder="e.g., MATH"></div><div><label class="block text-sm font-medium mb-1 required-field">Category *</label><select id="subjectCategory" required class="w-full border rounded-lg px-3 py-2 focus:ring-2 focus:ring-blue-500"><option value="">Select Category</option><option value="Core">📚 Core Subject</option><option value="Elective">⭐ Elective Subject</option><option value="Extra">🎨 Extra Curricular</option></select></div><div><label class="block text-sm font-medium mb-1">Assign to Class</label><select id="subjectClass" class="w-full border rounded-lg px-3 py-2 focus:ring-2 focus:ring-blue-500"><option value="all">All Classes</option>${classes.map(c => `<option value="${c.id}">${c.name} (${c.level === 'Nursery' ? 'Nursery' : c.level === 'LowerPrimary' ? 'Lower Primary' : 'Upper Primary'})</option>`).join('')}</select></div></div><div><label class="block text-sm font-medium mb-1">Description (Optional)</label><textarea id="subjectDescription" rows="2" class="w-full border rounded-lg px-3 py-2 focus:ring-2 focus:ring-blue-500" placeholder="Brief description of the subject"></textarea></div><div class="flex gap-2"><button type="submit" class="bg-blue-600 text-white px-6 py-2 rounded-lg hover:bg-blue-700"><i class="fas fa-save"></i> Add Subject</button><button type="button" onclick="resetSubjectForm()" class="bg-gray-300 text-gray-700 px-6 py-2 rounded-lg hover:bg-gray-400">Clear Form</button></div></form></div>
            </div>
            
            <div class="bg-white rounded-xl shadow-sm p-4">
                <div class="grid grid-cols-1 md:grid-cols-4 gap-4">
                    <div class="relative"><i class="fas fa-search absolute left-3 top-3 text-gray-400"></i><input type="text" id="subjectSearch" placeholder="Search subjects..." class="w-full pl-10 pr-4 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500"></div>
                    <div><select id="categoryFilter" class="w-full border rounded-lg px-3 py-2 focus:ring-2 focus:ring-blue-500"><option value="">All Categories</option><option value="Core">Core Subjects</option><option value="Elective">Elective Subjects</option><option value="Extra">Extra Curricular</option></select></div>
                    <div><select id="classFilter" class="w-full border rounded-lg px-3 py-2 focus:ring-2 focus:ring-blue-500"><option value="">All Classes</option><option value="all">All Classes (General)</option>${classes.map(c => `<option value="${c.id}">${c.name}</option>`).join('')}</select></div>
                    <div><button onclick="exportSubjectsData()" class="w-full bg-green-600 text-white px-4 py-2 rounded-lg hover:bg-green-700"><i class="fas fa-download"></i> Export Subjects</button></div>
                </div>
            </div>
            
            <div class="bg-white rounded-xl shadow-sm overflow-hidden">
                <div class="border-b"><div class="flex overflow-x-auto" id="classTabs"><button class="class-tab px-6 py-3 font-medium text-sm focus:outline-none active" data-class="all">All Subjects</button>${classes.map(c => `<button class="class-tab px-6 py-3 font-medium text-sm focus:outline-none" data-class="${c.id}">${c.name}</button>`).join('')}</div></div>
                <div id="subjectsView" class="p-6">${renderSubjectsTable(subjects)}</div>
            </div>
            
            <div class="bg-white rounded-xl shadow-sm p-6"><h3 class="font-bold text-lg mb-4">📊 Subjects Distribution by Class</h3><div class="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-3"><div class="bg-gradient-to-r from-blue-50 to-purple-50 rounded-lg p-3"><p class="font-semibold text-sm">All Classes</p><p class="text-2xl font-bold text-blue-600">${subjects.length}</p><p class="text-xs text-gray-500">total subjects</p></div>${classes.map(c => { const classSubjects = subjects.filter(s => s.classId === c.id).length; return `<div class="bg-gradient-to-r from-green-50 to-blue-50 rounded-lg p-3 cursor-pointer hover:shadow-md transition" onclick="filterByClass('${c.id}')"><p class="font-semibold text-sm">${c.name}</p><p class="text-2xl font-bold text-green-600">${classSubjects}</p><p class="text-xs text-gray-500">subjects</p></div>`; }).join('')}</div></div>
        </div>
    `;
    
    const mainContent = document.getElementById('mainContent');
    if (mainContent) {
        mainContent.innerHTML = html;
        initializeSubjectFilters();
        initializeClassTabs();
        
        const addForm = document.getElementById('addSubjectForm');
        if (addForm) addForm.addEventListener('submit', handleAddSubject);
    }
}

function renderSubjectsTable(subjects) {
    if (subjects.length === 0) return `<div class="text-center py-12"><i class="fas fa-book-open text-gray-400 text-6xl mb-4"></i><p class="text-gray-500">No subjects found. Click "Add New Subject" to get started.</p></div>`;
    
    const coreSubjects = subjects.filter(s => s.category === 'Core');
    const electiveSubjects = subjects.filter(s => s.category === 'Elective');
    const extraSubjects = subjects.filter(s => s.category === 'Extra');
    
    return `${coreSubjects.length > 0 ? `<div class="mb-8"><h3 class="text-lg font-bold mb-3 flex items-center"><i class="fas fa-star text-yellow-500 mr-2"></i>Core Subjects (${coreSubjects.length})</h3><div class="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">${coreSubjects.map(subject => renderSubjectCard(subject)).join('')}</div></div>` : ''}${electiveSubjects.length > 0 ? `<div class="mb-8"><h3 class="text-lg font-bold mb-3 flex items-center"><i class="fas fa-heart text-pink-500 mr-2"></i>Elective Subjects (${electiveSubjects.length})</h3><div class="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">${electiveSubjects.map(subject => renderSubjectCard(subject)).join('')}</div></div>` : ''}${extraSubjects.length > 0 ? `<div class="mb-8"><h3 class="text-lg font-bold mb-3 flex items-center"><i class="fas fa-palette text-purple-500 mr-2"></i>Extra Curricular (${extraSubjects.length})</h3><div class="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">${extraSubjects.map(subject => renderSubjectCard(subject)).join('')}</div></div>` : ''}`;
}

function renderSubjectCard(subject) {
    const categoryColors = { 'Core': 'bg-yellow-100 text-yellow-800', 'Elective': 'bg-pink-100 text-pink-800', 'Extra': 'bg-purple-100 text-purple-800' };
    const categoryColor = categoryColors[subject.category] || 'bg-gray-100 text-gray-800';
    const classInfo = subject.classId === 'all' ? 'All Classes' : getClassName(subject.classId);
    
    return `<div class="border rounded-lg p-4 hover:shadow-md transition subject-card" data-subject-id="${subject.id}"><div class="flex justify-between items-start mb-3"><div><h4 class="font-bold text-lg">${subject.name}</h4><p class="text-sm text-gray-500">Code: ${subject.code}</p></div><span class="px-2 py-1 rounded-full text-xs ${categoryColor}">${subject.category}</span></div><div class="space-y-2"><div class="flex items-center text-sm text-gray-600"><i class="fas fa-chalkboard w-5"></i><span>${classInfo}</span></div>${subject.description ? `<div class="flex items-start text-sm text-gray-600"><i class="fas fa-info-circle w-5 mt-0.5"></i><span class="flex-1">${subject.description}</span></div>` : ''}<div class="flex items-center text-sm text-gray-600"><i class="fas fa-calendar-alt w-5"></i><span>Added: ${new Date(subject.createdAt).toLocaleDateString()}</span></div></div><div class="flex gap-2 mt-4 pt-3 border-t"><button onclick="editSubject('${subject.id}')" class="flex-1 text-green-600 hover:text-green-800 text-sm"><i class="fas fa-edit"></i> Edit</button><button onclick="deleteSubject('${subject.id}')" class="flex-1 text-red-600 hover:text-red-800 text-sm"><i class="fas fa-trash"></i> Delete</button><button onclick="assignToClass('${subject.id}')" class="flex-1 text-blue-600 hover:text-blue-800 text-sm"><i class="fas fa-users"></i> Assign</button></div></div>`;
}

function getClassName(classId) {
    const classObj = window.allClassesData?.find(c => c.id === classId);
    return classObj ? classObj.name : 'Unknown Class';
}

function initializeSubjectFilters() {
    const searchInput = document.getElementById('subjectSearch');
    const categoryFilter = document.getElementById('categoryFilter');
    const classFilter = document.getElementById('classFilter');
    const filters = [searchInput, categoryFilter, classFilter];
    filters.forEach(filter => { if (filter) { filter.addEventListener('input', applySubjectFilters); filter.addEventListener('change', applySubjectFilters); } });
}

function applySubjectFilters() {
    const searchTerm = document.getElementById('subjectSearch')?.value.toLowerCase() || '';
    const categoryValue = document.getElementById('categoryFilter')?.value || '';
    const classValue = document.getElementById('classFilter')?.value || '';
    
    let filtered = window.allSubjectsData.filter(subject => {
        const matchesSearch = searchTerm === '' || subject.name.toLowerCase().includes(searchTerm) || subject.code.toLowerCase().includes(searchTerm);
        const matchesCategory = categoryValue === '' || subject.category === categoryValue;
        let matchesClass = true;
        if (classValue !== '') {
            if (classValue === 'all') matchesClass = subject.classId === 'all' || !subject.classId;
            else matchesClass = subject.classId === classValue;
        }
        return matchesSearch && matchesCategory && matchesClass;
    });
    
    const subjectsView = document.getElementById('subjectsView');
    if (subjectsView) subjectsView.innerHTML = renderSubjectsTable(filtered);
}

function initializeClassTabs() {
    const tabs = document.querySelectorAll('.class-tab');
    tabs.forEach(tab => {
        tab.addEventListener('click', () => {
            tabs.forEach(t => t.classList.remove('active', 'border-blue-600', 'text-blue-600'));
            tab.classList.add('active', 'border-blue-600', 'text-blue-600');
            filterSubjectsByClass(tab.dataset.class);
        });
    });
}

function filterSubjectsByClass(classId) {
    let filtered = window.allSubjectsData;
    if (classId !== 'all') filtered = window.allSubjectsData.filter(subject => subject.classId === classId);
    const subjectsView = document.getElementById('subjectsView');
    if (subjectsView) subjectsView.innerHTML = renderSubjectsTable(filtered);
}

function filterByClass(classId) {
    const classFilter = document.getElementById('classFilter');
    if (classFilter) { classFilter.value = classId; applySubjectFilters(); }
    document.getElementById('subjectsView')?.scrollIntoView({ behavior: 'smooth' });
}

async function handleAddSubject(e) {
    e.preventDefault();
    
    const subjectData = {
        name: document.getElementById('subjectName').value,
        code: document.getElementById('subjectCode').value.toUpperCase(),
        category: document.getElementById('subjectCategory').value,
        classId: document.getElementById('subjectClass').value,
        description: document.getElementById('subjectDescription').value
    };
    
    if (!subjectData.name || !subjectData.code || !subjectData.category) {
        alert('Please fill in all required fields');
        return;
    }
    
    const submitBtn = e.target.querySelector('button[type="submit"]');
    const originalText = submitBtn.innerText;
    submitBtn.innerText = 'Adding...';
    submitBtn.disabled = true;
    
    try {
        const response = await fetch('/api/school/subjects', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(subjectData)
        });
        
        if (response.ok) {
            alert('✅ Subject added successfully!');
            addNotification(`New subject "${subjectData.name}" was added to the curriculum`);
            resetSubjectForm();
            showSubjectManagement();
        } else {
            alert('❌ Error adding subject');
        }
    } catch (error) {
        console.error('Error:', error);
        alert('Error adding subject');
    } finally {
        submitBtn.innerText = originalText;
        submitBtn.disabled = false;
    }
}

function resetSubjectForm() {
    document.getElementById('subjectName').value = '';
    document.getElementById('subjectCode').value = '';
    document.getElementById('subjectCategory').value = '';
    document.getElementById('subjectClass').value = 'all';
    document.getElementById('subjectDescription').value = '';
}

function toggleAddSubjectForm() {
    const container = document.getElementById('addSubjectFormContainer');
    if (container) container.classList.toggle('hidden');
}

async function editSubject(subjectId) {
    const subject = window.allSubjectsData.find(s => s.id === subjectId);
    if (!subject) return;
    const classes = window.allClassesData;
    
    const modalHtml = `<div class="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50"><div class="bg-white rounded-2xl p-6 max-w-md w-full mx-4"><h3 class="text-xl font-bold mb-4">Edit Subject</h3><form id="editSubjectForm"><div class="space-y-4"><div><label class="block text-sm font-medium mb-1">Subject Name</label><input type="text" id="editName" value="${subject.name}" class="w-full border rounded-lg px-3 py-2"></div><div><label class="block text-sm font-medium mb-1">Subject Code</label><input type="text" id="editCode" value="${subject.code}" class="w-full border rounded-lg px-3 py-2"></div><div><label class="block text-sm font-medium mb-1">Category</label><select id="editCategory" class="w-full border rounded-lg px-3 py-2"><option value="Core" ${subject.category === 'Core' ? 'selected' : ''}>Core Subject</option><option value="Elective" ${subject.category === 'Elective' ? 'selected' : ''}>Elective Subject</option><option value="Extra" ${subject.category === 'Extra' ? 'selected' : ''}>Extra Curricular</option></select></div><div><label class="block text-sm font-medium mb-1">Assigned Class</label><select id="editClass" class="w-full border rounded-lg px-3 py-2"><option value="all" ${subject.classId === 'all' ? 'selected' : ''}>All Classes</option>${classes.map(c => `<option value="${c.id}" ${subject.classId === c.id ? 'selected' : ''}>${c.name}</option>`).join('')}</select></div><div><label class="block text-sm font-medium mb-1">Description</label><textarea id="editDescription" rows="3" class="w-full border rounded-lg px-3 py-2">${subject.description || ''}</textarea></div></div><div class="flex gap-3 mt-6"><button type="submit" class="flex-1 bg-blue-600 text-white px-4 py-2 rounded-lg">Save Changes</button><button type="button" onclick="closeModal()" class="flex-1 bg-gray-300 text-gray-700 px-4 py-2 rounded-lg">Cancel</button></div></form></div></div>`;
    document.body.insertAdjacentHTML('beforeend', modalHtml);
    
    document.getElementById('editSubjectForm').addEventListener('submit', async (e) => {
        e.preventDefault();
        const updatedData = {
            name: document.getElementById('editName').value,
            code: document.getElementById('editCode').value,
            category: document.getElementById('editCategory').value,
            classId: document.getElementById('editClass').value,
            description: document.getElementById('editDescription').value
        };
        alert('✅ Subject updated successfully!');
        addNotification(`Subject "${updatedData.name}" was updated`);
        closeModal();
        showSubjectManagement();
    });
}

async function assignToClass(subjectId) {
    const subject = window.allSubjectsData.find(s => s.id === subjectId);
    if (!subject) return;
    const classes = window.allClassesData;
    
    const modalHtml = `<div class="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50"><div class="bg-white rounded-2xl p-6 max-w-md w-full mx-4"><h3 class="text-xl font-bold mb-4">Assign Subject to Class</h3><p class="text-gray-600 mb-4">Subject: <strong>${subject.name}</strong></p><form id="assignSubjectForm"><div class="space-y-3"><div><label class="block text-sm font-medium mb-1">Select Class</label><select id="assignClass" class="w-full border rounded-lg px-3 py-2"><option value="all" ${subject.classId === 'all' ? 'selected' : ''}>All Classes</option>${classes.map(c => `<option value="${c.id}" ${subject.classId === c.id ? 'selected' : ''}>${c.name} (${c.level === 'Nursery' ? 'Nursery' : c.level === 'LowerPrimary' ? 'Lower Primary' : 'Upper Primary'})</option>`).join('')}</select></div><div class="bg-blue-50 p-3 rounded-lg"><p class="text-sm text-blue-800"><i class="fas fa-info-circle"></i> Selecting "All Classes" makes this subject available to every class.</p></div></div><div class="flex gap-3 mt-6"><button type="submit" class="flex-1 bg-blue-600 text-white px-4 py-2 rounded-lg">Assign Subject</button><button type="button" onclick="closeModal()" class="flex-1 bg-gray-300 text-gray-700 px-4 py-2 rounded-lg">Cancel</button></div></form></div></div>`;
    document.body.insertAdjacentHTML('beforeend', modalHtml);
    
    document.getElementById('assignSubjectForm').addEventListener('submit', async (e) => {
        e.preventDefault();
        const newClassId = document.getElementById('assignClass').value;
        alert(`✅ Subject "${subject.name}" has been assigned to ${newClassId === 'all' ? 'All Classes' : getClassName(newClassId)}`);
        addNotification(`Subject "${subject.name}" was reassigned`);
        closeModal();
        showSubjectManagement();
    });
}

window.deleteSubject = async (id) => {
    if (confirm('⚠️ Are you sure you want to delete this subject? This will affect all classes using it.')) {
        try {
            const response = await fetch(`/api/school/subjects/${id}`, { method: 'DELETE' });
            if (response.ok) {
                alert('✅ Subject deleted successfully!');
                addNotification('A subject was removed from the curriculum');
                showSubjectManagement();
            } else {
                alert('❌ Error deleting subject');
            }
        } catch (error) {
            console.error('Error:', error);
            alert('Error deleting subject');
        }
    }
};

function exportSubjectsData() {
    if (window.allSubjectsData.length === 0) { alert('No subjects to export'); return; }
    const exportData = window.allSubjectsData.map(subject => ({ 'Subject Name': subject.name, 'Subject Code': subject.code, 'Category': subject.category, 'Assigned Class': subject.classId === 'all' ? 'All Classes' : getClassName(subject.classId), 'Description': subject.description || '', 'Date Created': new Date(subject.createdAt).toLocaleDateString() }));
    const csv = convertToCSV(exportData);
    downloadCSV(csv, `subjects_export_${new Date().toISOString().split('T')[0]}.csv`);
    addNotification('Subjects data exported successfully');
}

