style.textContent = `.class-tab { border-bottom: 2px solid transparent; transition: all 0.3s ease; } .class-tab.active { border-bottom-color: #3b82f6; color: #3b82f6; } .class-tab:hover:not(.active) { border-bottom-color: #93c5fd; color: #2563eb; } .subject-card { transition: transform 0.2s ease, box-shadow 0.2s ease; } .subject-card:hover { transform: translateY(-2px); }`;
document.head.appendChild(style);

// ==================== COMPLETE TEACHERS MANAGEMENT WITH PASSWORD FEATURE ====================
// Version: 2.0 - Added Password Management during registration and profile view

async function showTeacherManagement() {
    const pageTitle = document.getElementById('pageTitle');
    if (pageTitle) pageTitle.innerHTML = '<i class="fas fa-chalkboard-user mr-2"></i>Teachers Management';
    
    try {
        const [teachersRes, subjectsRes, classesRes] = await Promise.all([
            fetch('/api/teachers'),
            fetch('/api/school/subjects'),
            fetch('/api/school/classes')
        ]);
        
        let teachers = await teachersRes.json();
        const subjects = await subjectsRes.json();
        const classes = await classesRes.json();
        
        window.allTeachersData = teachers;
        window.allSubjectsData = subjects;
        window.allClassesData = classes;
        
        renderTeacherManagement(teachers, subjects, classes);
        
    } catch (error) {
        console.error('Error:', error);
        const mainContent = document.getElementById('mainContent');
        if (mainContent) {
            mainContent.innerHTML = `<div class="bg-red-50 border border-red-200 rounded-lg p-6 text-center"><i class="fas fa-exclamation-triangle text-red-600 text-4xl mb-3"></i><p class="text-red-600">Error loading teachers. Please refresh the page.</p><button onclick="showTeacherManagement()" class="mt-3 bg-red-600 text-white px-4 py-2 rounded">Retry</button></div>`;
        }
    }
}

