// ==================== RESET TEACHER PASSWORD ====================
async function resetTeacherPassword(teacherId) {
    // Generate a new 6-digit numeric password
    const newPassword = Math.floor(100000 + Math.random() * 900000).toString();
    
    // Confirm with the user
    if (!confirm(`Are you sure you want to reset the password for this teacher?\n\nNew password will be: ${newPassword}\n\nThis will be saved in the database.`)) {
        return;
    }
    
    try {
        const response = await fetch(`/api/teachers/${teacherId}`, {
            method: 'PUT',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ password: newPassword })
        });
        
        if (response.ok) {
            const updatedTeacher = await response.json();
            alert(`✅ Password reset successfully!\n\n🔑 New Password: ${newPassword}\n\nPlease provide this to the teacher.`);
            
            // Refresh the teacher management page and re-open the profile
            closeModal();
            await showTeacherManagement();
            
            // Re-open the profile with updated data
            setTimeout(() => {
                viewTeacherDetails(teacherId);
            }, 500);
            
            addNotification(`Password reset for teacher ${updatedTeacher.firstName} ${updatedTeacher.lastName}`);
        } else {
            alert('❌ Error resetting password. Please try again.');
        }
    } catch (error) {
        console.error('Error resetting password:', error);
        alert('Network error: ' + error.message);
    }
}

// ==================== EDIT TEACHER ====================
async function editTeacher(teacherId) {
    try {
        const response = await fetch(`/api/teachers/${teacherId}`);
        const teacher = await response.json();
        const [subjectsRes, classesRes] = await Promise.all([fetch('/api/school/subjects'), fetch('/api/school/classes')]);
        const subjects = await subjectsRes.json();
        const classes = await classesRes.json();
        
        const modalHtml = `<div class="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50 overflow-y-auto"><div class="bg-white rounded-2xl p-6 max-w-2xl w-full mx-4 my-8 max-h-[90vh] overflow-y-auto"><h3 class="text-xl font-bold mb-4">Edit Teacher Information</h3><form id="editTeacherForm"><div class="grid grid-cols-2 gap-4"><div><label class="block text-sm font-medium mb-1">First Name</label><input type="text" id="editFirstName" value="${teacher.firstName || ''}" class="w-full border rounded-lg px-3 py-2"></div><div><label class="block text-sm font-medium mb-1">Last Name</label><input type="text" id="editLastName" value="${teacher.lastName || ''}" class="w-full border rounded-lg px-3 py-2"></div><div><label class="block text-sm font-medium mb-1">Phone</label><input type="text" id="editPhone" value="${teacher.phone || ''}" class="w-full border rounded-lg px-3 py-2"></div><div><label class="block text-sm font-medium mb-1">Email</label><input type="email" id="editEmail" value="${teacher.email || ''}" class="w-full border rounded-lg px-3 py-2"></div><div><label class="block text-sm font-medium mb-1">Qualification</label><select id="editQualification" class="w-full border rounded-lg px-3 py-2"><option value="">Select Qualification</option><option value="Bachelor's Degree" ${teacher.qualification === "Bachelor's Degree" ? 'selected' : ''}>Bachelor's Degree</option><option value="Master's Degree" ${teacher.qualification === "Master's Degree" ? 'selected' : ''}>Master's Degree</option><option value="Diploma" ${teacher.qualification === "Diploma" ? 'selected' : ''}>Diploma</option><option value="Certificate" ${teacher.qualification === "Certificate" ? 'selected' : ''}>Certificate</option></select></div><div><label class="block text-sm font-medium mb-1">Specialization</label><input type="text" id="editSpecialization" value="${teacher.specialization || ''}" class="w-full border rounded-lg px-3 py-2"></div><div><label class="block text-sm font-medium mb-1">Status</label><select id="editStatus" class="w-full border rounded-lg px-3 py-2"><option value="Active" ${teacher.status === 'Active' ? 'selected' : ''}>Active</option><option value="On Leave" ${teacher.status === 'On Leave' ? 'selected' : ''}>On Leave</option><option value="Inactive" ${teacher.status === 'Inactive' ? 'selected' : ''}>Inactive</option></select></div><div><label class="block text-sm font-medium mb-1">Joined Date</label><input type="date" id="editJoinedDate" value="${teacher.joinedAt || ''}" class="w-full border rounded-lg px-3 py-2"></div><div class="col-span-2"><label class="block text-sm font-medium mb-1">Address</label><textarea id="editAddress" rows="2" class="w-full border rounded-lg px-3 py-2">${teacher.address || ''}</textarea></div><div class="col-span-2"><label class="block text-sm font-medium mb-1">Subjects Taught</label><select id="editSubjects" multiple class="w-full border rounded-lg px-3 py-2" size="4">${subjects.map(s => `<option value="${s.id}" ${teacher.subjects?.includes(s.id) ? 'selected' : ''}>${s.name} (${s.category})</option>`).join('')}</select><p class="text-xs text-gray-500 mt-1">Hold Ctrl/Cmd to select multiple subjects</p></div><div class="col-span-2"><label class="block text-sm font-medium mb-1">Assigned Classes</label><select id="editClasses" multiple class="w-full border rounded-lg px-3 py-2" size="4">${classes.map(c => `<option value="${c.id}" ${teacher.classes?.includes(c.id) ? 'selected' : ''}>${c.name} (${c.level === 'Nursery' ? 'Nursery' : c.level === 'LowerPrimary' ? 'Lower Primary' : 'Upper Primary'})</option>`).join('')}</select><p class="text-xs text-gray-500 mt-1">Hold Ctrl/Cmd to select multiple classes</p></div></div><div class="flex gap-3 mt-6"><button type="submit" class="flex-1 bg-blue-600 text-white px-4 py-2 rounded-lg">Save Changes</button><button type="button" onclick="closeModal()" class="flex-1 bg-gray-300 text-gray-700 px-4 py-2 rounded-lg">Cancel</button></div></form></div></div>`;
        document.body.insertAdjacentHTML('beforeend', modalHtml);
        
        document.getElementById('editTeacherForm').addEventListener('submit', async (e) => {
            e.preventDefault();
            const subjectsSelect = document.getElementById('editSubjects');
            const selectedSubjects = Array.from(subjectsSelect.selectedOptions).map(opt => opt.value);
            const classesSelect = document.getElementById('editClasses');
            const selectedClasses = Array.from(classesSelect.selectedOptions).map(opt => opt.value);
            
            const updatedData = {
                firstName: document.getElementById('editFirstName').value,
                lastName: document.getElementById('editLastName').value,
                phone: document.getElementById('editPhone').value,
                email: document.getElementById('editEmail').value,
                qualification: document.getElementById('editQualification').value,
                specialization: document.getElementById('editSpecialization').value,
                status: document.getElementById('editStatus').value,
                joinedAt: document.getElementById('editJoinedDate').value,
                address: document.getElementById('editAddress').value,
                subjects: selectedSubjects,
                classes: selectedClasses,
                updatedAt: new Date().toISOString()
            };
            
            const updateResponse = await fetch(`/api/teachers/${teacherId}`, { method: 'PUT', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(updatedData) });
            if (updateResponse.ok) {
                alert('✅ Teacher information updated successfully');
                addNotification(`Teacher ${updatedData.firstName} ${updatedData.lastName} was updated`);
                closeModal();
                showTeacherManagement();
            } else { alert('❌ Error updating teacher'); }
        });
    } catch (error) { console.error('Error:', error); alert('Error loading teacher data'); }
}

// ==================== RESET TEACHER FORM ====================
function resetTeacherForm() {
    document.getElementById('teacherFirstName').value = '';
    document.getElementById('teacherLastName').value = '';
    document.getElementById('teacherGender').value = '';
    document.getElementById('teacherPhone').value = '';
    document.getElementById('teacherEmail').value = '';
    document.getElementById('teacherDob').value = '';
    document.getElementById('teacherQualification').value = '';
    document.getElementById('teacherSpecialization').value = '';
    document.getElementById('teacherAddress').value = '';
    document.getElementById('teacherPassword').value = '';
    const subjectsSelect = document.getElementById('teacherSubjects');
    if (subjectsSelect) { Array.from(subjectsSelect.options).forEach(opt => opt.selected = false); }
    const classesSelect = document.getElementById('teacherClasses');
    if (classesSelect) { Array.from(classesSelect.options).forEach(opt => opt.selected = false); }
}

