function toggleAddTeacherForm() {
    const container = document.getElementById('addTeacherFormContainer');
    if (container) container.classList.toggle('hidden');
}

// ==================== FILTER FUNCTIONS ====================
function initializeTeacherFilters() {
    const searchInput = document.getElementById('teacherSearch');
    const genderFilter = document.getElementById('genderFilter');
    const statusFilter = document.getElementById('statusFilter');
    const qualificationFilter = document.getElementById('qualificationFilter');
    const filters = [searchInput, genderFilter, statusFilter, qualificationFilter];
    filters.forEach(filter => { if (filter) { filter.addEventListener('input', applyTeacherFilters); filter.addEventListener('change', applyTeacherFilters); } });
}

function applyTeacherFilters() {
    const searchTerm = document.getElementById('teacherSearch')?.value.toLowerCase() || '';
    const genderValue = document.getElementById('genderFilter')?.value || '';
    const statusValue = document.getElementById('statusFilter')?.value || '';
    const qualificationValue = document.getElementById('qualificationFilter')?.value || '';
    
    let filtered = window.allTeachersData.filter(teacher => {
        const matchesSearch = searchTerm === '' || (teacher.firstName && teacher.firstName.toLowerCase().includes(searchTerm)) || (teacher.lastName && teacher.lastName.toLowerCase().includes(searchTerm)) || (teacher.teacherId && teacher.teacherId.toLowerCase().includes(searchTerm)) || (teacher.phone && teacher.phone.includes(searchTerm));
        const matchesGender = genderValue === '' || teacher.gender === genderValue;
        const matchesStatus = statusValue === '' || teacher.status === statusValue;
        const matchesQualification = qualificationValue === '' || teacher.qualification === qualificationValue;
        return matchesSearch && matchesGender && matchesStatus && matchesQualification;
    });
    
    const teachersGrid = document.getElementById('teachersGrid');
    if (teachersGrid) {
        if (filtered.length === 0) {
            teachersGrid.innerHTML = `<div class="col-span-full bg-gray-50 rounded-lg p-12 text-center"><i class="fas fa-search text-gray-400 text-4xl mb-3"></i><p class="text-gray-500">No teachers found matching your filters</p><button onclick="clearTeacherFilters()" class="mt-3 text-blue-600 hover:text-blue-800">Clear Filters</button></div>`;
        } else {
            teachersGrid.innerHTML = filtered.map(teacher => renderTeacherCard(teacher, window.allSubjectsData, window.allClassesData)).join('');
        }
    }
}

function clearTeacherFilters() {
    const searchInput = document.getElementById('teacherSearch');
    const genderFilter = document.getElementById('genderFilter');
    const statusFilter = document.getElementById('statusFilter');
    const qualificationFilter = document.getElementById('qualificationFilter');
    if (searchInput) searchInput.value = '';
    if (genderFilter) genderFilter.value = '';
    if (statusFilter) statusFilter.value = '';
    if (qualificationFilter) qualificationFilter.value = '';
    applyTeacherFilters();
}

