// ==================== SCORE ENTRY ====================
async function showScoreEntry() {
    const pageTitle = document.getElementById('pageTitle');
    if (pageTitle) pageTitle.innerHTML = '<i class="fas fa-pen mr-2"></i>Enter Scores';
    try {
        const [classesRes, subjectsRes] = await Promise.all([fetch('/api/school/classes'), fetch('/api/school/subjects')]);
        const classes = await classesRes.json();
        const subjects = await subjectsRes.json();
        const html = `<div class="bg-white rounded-xl shadow-sm p-6"><h2 class="text-xl font-bold mb-4">✏️ Enter Student Scores</h2><div class="grid grid-cols-1 md:grid-cols-3 gap-4 mb-4"><select id="scoreClass" class="border rounded-lg px-3 py-2"><option value="">Select Class</option>${classes.map(c => `<option value="${c.id}">${c.name}</option>`).join('')}</select><select id="scoreSubject" class="border rounded-lg px-3 py-2"><option value="">Select Subject</option>${subjects.map(s => `<option value="${s.id}">${s.name}</option>`).join('')}</select><select id="assessmentType" class="border rounded-lg px-3 py-2"><option value="CAT1">CAT 1</option><option value="CAT2">CAT 2</option><option value="Exam">Exam</option></select></div><button onclick="loadStudentsForScores()" class="bg-blue-600 text-white px-6 py-2 rounded-lg">Load Students</button><div id="scoreEntryForm" class="mt-4"></div></div>`;
        const mainContent = document.getElementById('mainContent');
        if (mainContent) mainContent.innerHTML = html;
    } catch (error) { console.error('Error:', error); }
}

window.loadStudentsForScores = async () => {
    const classId = document.getElementById('scoreClass').value;
    const subjectId = document.getElementById('scoreSubject').value;
    const assessmentType = document.getElementById('assessmentType').value;
    if (!classId || !subjectId) { alert('Please select class and subject'); return; }
    try {
        const studentsRes = await fetch('/api/students');
        const students = await studentsRes.json();
        const classObj = window.allClassesData?.find(c => c.id === classId);
        const classStudents = students.filter(s => s.currentClass === classObj?.name);
        if (classStudents.length === 0) { document.getElementById('scoreEntryForm').innerHTML = '<p class="text-yellow-600 mt-4">No students found</p>'; return; }
        const html = `<form id="scoresForm" class="mt-4"><div class="overflow-x-auto"><table class="w-full"><thead class="bg-gray-100"><tr><th class="p-3">Student</th><th class="p-3">Admission</th><th class="p-3">Score (0-100)</th><th class="p-3">Remarks</th></tr></thead><tbody>${classStudents.map(s => `<tr class="border-b"><td class="p-3">${s.firstName} ${s.lastName}</td><td class="p-3">${s.admissionNumber}</td><td class="p-3"><input type="number" id="score_${s.id}" class="w-24 border rounded px-2 py-1" min="0" max="100"></td><td class="p-3"><input type="text" id="remark_${s.id}" class="w-full border rounded px-2 py-1" placeholder="Optional"></td></td>`).join('')}</tbody>}<table></div><button type="submit" class="mt-4 bg-green-600 text-white px-6 py-2 rounded-lg">Save Scores</button></form>`;
        document.getElementById('scoreEntryForm').innerHTML = html;
        document.getElementById('scoresForm').addEventListener('submit', async (e) => {
            e.preventDefault();
            const assessmentRes = await fetch('/api/academics/assessments', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ name: `${assessmentType} - ${new Date().toLocaleDateString()}`, type: assessmentType, subjectId, classId, term: 1, year: 2026, maxScore: 100, weight: 100 }) });
            const assessmentData = await assessmentRes.json();
            const scores = classStudents.map(s => ({ studentId: s.id, score: parseInt(document.getElementById(`score_${s.id}`).value) || 0, remarks: document.getElementById(`remark_${s.id}`).value })).filter(s => s.score > 0);
            await fetch('/api/academics/scores', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ assessmentId: assessmentData.assessment.id, scores }) });
            alert('✅ Scores saved successfully!');
            addNotification(`Scores for ${assessmentType} were recorded`);
            showScoreEntry();
        });
    } catch (error) { console.error('Error:', error); alert('Error loading students'); }
};

// ==================== VIEW SCORES ====================
async function showViewScores() {
    const pageTitle = document.getElementById('pageTitle');
    if (pageTitle) pageTitle.innerHTML = '<i class="fas fa-eye mr-2"></i>View Scores';
    try {
        const [classesRes, subjectsRes, assessmentsRes] = await Promise.all([fetch('/api/school/classes'), fetch('/api/school/subjects'), fetch('/api/academics/assessments')]);
        const classes = await classesRes.json();
        const subjects = await subjectsRes.json();
        const assessments = await assessmentsRes.json();
        const html = `<div class="bg-white rounded-xl shadow-sm p-6"><h2 class="text-xl font-bold mb-4">📊 View Student Scores</h2><div class="grid grid-cols-1 md:grid-cols-3 gap-4 mb-4"><select id="viewClass" class="border rounded-lg px-3 py-2"><option value="">Select Class</option>${classes.map(c => `<option value="${c.id}">${c.name}</option>`).join('')}</select><select id="viewSubject" class="border rounded-lg px-3 py-2"><option value="">Select Subject</option>${subjects.map(s => `<option value="${s.id}">${s.name}</option>`).join('')}</select><select id="viewAssessment" class="border rounded-lg px-3 py-2"><option value="">Select Assessment</option>${assessments.map(a => `<option value="${a.id}">${a.name} (${a.type})</option>`).join('')}</select></div><button onclick="loadScoresToView()" class="bg-blue-600 text-white px-6 py-2 rounded-lg">View Scores</button><div id="scoresViewResult" class="mt-6"></div></div>`;
        const mainContent = document.getElementById('mainContent');
        if (mainContent) mainContent.innerHTML = html;
    } catch (error) { console.error('Error:', error); }
}

window.loadScoresToView = async () => {
    const assessmentId = document.getElementById('viewAssessment').value;
    if (!assessmentId) { alert('Please select an assessment'); return; }
    try {
        const scoresRes = await fetch('/api/academics/scores');
        const allScores = await scoresRes.json();
        const studentsRes = await fetch('/api/students');
        const students = await studentsRes.json();
        const assessmentScores = allScores.filter(s => s.assessmentId === assessmentId);
        if (assessmentScores.length === 0) { document.getElementById('scoresViewResult').innerHTML = '<p class="text-yellow-600 mt-4">No scores recorded for this assessment</p>'; return; }
        const scoresWithStudents = assessmentScores.map(score => { const student = students.find(s => s.id === score.studentId); return { ...score, studentName: student ? `${student.firstName} ${student.lastName}` : 'Unknown', admissionNumber: student?.admissionNumber }; });
        const html = `<div class="mt-4 overflow-x-auto"><table class="w-full"><thead class="bg-gray-100"><tr><th class="p-3">Admission</th><th class="p-3">Student</th><th class="p-3">Score</th><th class="p-3">Remarks</th><th class="p-3">Date</th></tr></thead><tbody>${scoresWithStudents.map(s => `<tr class="border-b"><td class="p-3">${s.admissionNumber}</td><td class="p-3">${s.studentName}</td><td class="p-3 text-center font-bold">${s.score}%</td><td class="p-3">${s.remarks || '-'}</td><td class="p-3 text-sm">${new Date(s.recordedAt).toLocaleDateString()}</td></tr>`).join('')}</tbody>}</table></div>`;
        document.getElementById('scoresViewResult').innerHTML = html;
    } catch (error) { console.error('Error:', error); alert('Error loading scores'); }
};

// ==================== PERFORMANCE ANALYSIS ====================
async function showPerformanceAnalysis() {
    const pageTitle = document.getElementById('pageTitle');
    if (pageTitle) pageTitle.innerHTML = '<i class="fas fa-chart-line mr-2"></i>Performance';
    try {
        const classesRes = await fetch('/api/school/classes');
        const classes = await classesRes.json();
        const html = `<div class="bg-white rounded-xl shadow-sm p-6"><h2 class="text-xl font-bold mb-4">📊 Performance Analysis</h2><div class="grid grid-cols-2 gap-4 mb-4"><select id="performanceClass" class="border rounded-lg px-4 py-2"><option value="">Select Class</option>${classes.map(c => `<option value="${c.id}">${c.name}</option>`).join('')}</select><button onclick="loadPerformanceData()" class="bg-blue-600 text-white px-4 py-2 rounded-lg">Load</button></div><div id="performanceResults"></div></div>`;
        const mainContent = document.getElementById('mainContent');
        if (mainContent) mainContent.innerHTML = html;
    } catch (error) { console.error('Error:', error); }
}

window.loadPerformanceData = async () => {
    const classId = document.getElementById('performanceClass').value;
    if (!classId) { alert('Select a class'); return; }
    try {
        const response = await fetch(`/api/academics/performance/${classId}/1/2026`);
        const data = await response.json();
        if (data.performance.length === 0) { document.getElementById('performanceResults').innerHTML = '<p class="text-yellow-600">No performance data available</p>'; return; }
        const avgScore = (data.performance.reduce((sum, s) => sum + parseFloat(s.percentage), 0) / data.performance.length).toFixed(1);
        const topStudent = data.performance[0];
        document.getElementById('performanceResults').innerHTML = `<div class="mt-4"><div class="grid grid-cols-3 gap-4 mb-6"><div class="bg-green-50 p-4 rounded text-center"><p class="text-sm text-gray-600">Average Score</p><p class="text-2xl font-bold text-green-600">${avgScore}%</p></div><div class="bg-blue-50 p-4 rounded text-center"><p class="text-sm text-gray-600">Top Student</p><p class="text-lg font-bold text-blue-600">${topStudent?.studentName}</p><p class="text-sm">${topStudent?.percentage}%</p></div><div class="bg-purple-50 p-4 rounded text-center"><p class="text-sm text-gray-600">Total Students</p><p class="text-2xl font-bold text-purple-600">${data.performance.length}</p></div></div><h3 class="font-bold mb-3">Top Performers</h3>${data.performance.slice(0, 5).map((s, i) => `<div class="flex justify-between p-3 bg-gray-50 mt-2 rounded"><span>${i+1}. ${s.studentName}</span><span class="font-bold">${s.percentage}% (${s.grade})</span></div>`).join('')}</div>`;
    } catch (error) { console.error('Error:', error); alert('Error loading performance data'); }
};

