// ==================== INITIALIZE FINANCIAL CHARTS ====================
function initializeFinancialCharts(monthNames, monthlyTotals, tuitionTotal, activityTotal, developmentTotal, cashTotal, bankTotal, mobileTotal) {
    // Monthly Collection Chart
    const monthlyCtx = document.getElementById('monthlyCollectionChart')?.getContext('2d');
    if (monthlyCtx) {
        new Chart(monthlyCtx, {
            type: 'bar',
            data: {
                labels: monthNames,
                datasets: [{
                    label: 'Amount Collected (UGX)',
                    data: monthlyTotals,
                    backgroundColor: 'rgba(59, 130, 246, 0.6)',
                    borderColor: '#3b82f6',
                    borderWidth: 1,
                    borderRadius: 8
                }]
            },
            options: {
                responsive: true,
                maintainAspectRatio: true,
                plugins: {
                    tooltip: {
                        callbacks: {
                            label: function(context) {
                                return 'UGX ' + (context.raw / 1000000).toFixed(2) + 'M';
                            }
                        }
                    }
                },
                scales: {
                    y: {
                        beginAtZero: true,
                        ticks: {
                            callback: function(value) {
                                if (value >= 1000000) return 'UGX ' + (value / 1000000).toFixed(1) + 'M';
                                if (value >= 1000) return 'UGX ' + (value / 1000).toFixed(0) + 'K';
                                return 'UGX ' + value;
                            }
                        },
                        title: { display: true, text: 'Amount (UGX)' }
                    },
                    x: { title: { display: true, text: 'Month' } }
                }
            }
        });
    }
    
    // Fee Type Pie Chart
    const feeTypeCtx = document.getElementById('feeTypeChart')?.getContext('2d');
    if (feeTypeCtx) {
        new Chart(feeTypeCtx, {
            type: 'doughnut',
            data: {
                labels: ['Tuition Fee', 'Activity Fee', 'Development Fee'],
                datasets: [{
                    data: [tuitionTotal, activityTotal, developmentTotal],
                    backgroundColor: ['#3b82f6', '#10b981', '#f59e0b'],
                    borderWidth: 0
                }]
            },
            options: {
                responsive: true,
                maintainAspectRatio: true,
                plugins: {
                    legend: { position: 'bottom' },
                    tooltip: {
                        callbacks: {
                            label: function(context) {
                                const total = tuitionTotal + activityTotal + developmentTotal;
                                const percentage = total > 0 ? ((context.raw / total) * 100).toFixed(1) : 0;
                                return `${context.label}: UGX ${(context.raw / 1000000).toFixed(2)}M (${percentage}%)`;
                            }
                        }
                    }
                }
            }
        });
    }
    
    // Payment Methods Pie Chart
    const paymentCtx = document.getElementById('paymentMethodChart')?.getContext('2d');
    if (paymentCtx) {
        new Chart(paymentCtx, {
            type: 'pie',
            data: {
                labels: ['Cash', 'Bank Transfer', 'Mobile Money'],
                datasets: [{
                    data: [cashTotal, bankTotal, mobileTotal],
                    backgroundColor: ['#10b981', '#3b82f6', '#8b5cf6'],
                    borderWidth: 0
                }]
            },
            options: {
                responsive: true,
                maintainAspectRatio: true,
                plugins: {
                    legend: { position: 'bottom' },
                    tooltip: {
                        callbacks: {
                            label: function(context) {
                                const total = cashTotal + bankTotal + mobileTotal;
                                const percentage = total > 0 ? ((context.raw / total) * 100).toFixed(1) : 0;
                                return `${context.label}: UGX ${(context.raw / 1000000).toFixed(2)}M (${percentage}%)`;
                            }
                        }
                    }
                }
            }
        });
    }
}

// ==================== EXPORT FINANCIAL REPORT ====================
function exportFinancialReport() {
    const students = window.allStudentsData || [];
    const payments = window.currentTermPayments || [];
    
    const summaryData = [
        ['FINANCIAL REPORT SUMMARY', ''],
        ['Generated:', new Date().toLocaleString()],
        ['Academic Year:', currentAcademicSettings.currentYear],
        ['', ''],
        ['STUDENT STATISTICS', ''],
        ['Total Students', students.length],
        ['Active Students', students.filter(s => s.status === 'Active').length],
        ['Male Students', students.filter(s => s.gender === 'Male').length],
        ['Female Students', students.filter(s => s.gender === 'Female').length],
        ['', ''],
        ['FINANCIAL SUMMARY', ''],
        ['Total Collected', `UGX ${payments.reduce((s, p) => s + (p.totalAmount || p.amount || 0), 0).toLocaleString()}`],
        ['Total Transactions', payments.length],
        ['', ''],
        ['PAYMENT METHODS BREAKDOWN', ''],
        ['Cash', `UGX ${payments.filter(p => p.method === 'cash').reduce((s, p) => s + (p.totalAmount || p.amount || 0), 0).toLocaleString()}`],
        ['Bank Transfer', `UGX ${payments.filter(p => p.method === 'bank').reduce((s, p) => s + (p.totalAmount || p.amount || 0), 0).toLocaleString()}`],
        ['Mobile Money', `UGX ${payments.filter(p => p.method === 'mobile').reduce((s, p) => s + (p.totalAmount || p.amount || 0), 0).toLocaleString()}`]
    ];
    
    const csvRows = summaryData.map(row => row.join(','));
    const csv = csvRows.join('\n');
    
    const blob = new Blob([csv], { type: 'text/csv' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `financial_report_${new Date().toISOString().split('T')[0]}.csv`;
    a.click();
    URL.revokeObjectURL(url);
    alert('✅ Financial report exported successfully');
}

// Make functions global
window.showReports = showReports;
window.exportFinancialReport = exportFinancialReport;
window.generateReportCard = async () => {
    const admissionNumber = document.getElementById('studentId').value;
    if (!admissionNumber) { alert('Enter admission number'); return; }
    try {
        const studentsRes = await fetch('/api/students');
        const students = await studentsRes.json();
        const student = students.find(s => s.admissionNumber === admissionNumber);
        if (!student) { alert('Student not found'); return; }
        const reportRes = await fetch(`/api/reports/report-card/${student.id}/1/2026`);
        const report = await reportRes.json();
        document.getElementById('reportCardResult').innerHTML = `<div class="mt-4 p-4 border rounded bg-gray-50"><h4 class="font-bold">Report Card</h4><p><strong>Student:</strong> ${report.student.name}</p><p><strong>Admission:</strong> ${report.student.admissionNumber}</p><p><strong>Average:</strong> ${report.summary.average}%</p><p><strong>Grade:</strong> ${report.summary.grade}</p><p><strong>Remark:</strong> ${report.summary.remark}</p><button onclick="window.print()" class="mt-3 bg-blue-600 text-white px-4 py-1 rounded text-sm">Print</button></div>`;
    } catch (error) { console.error('Error:', error); alert('Error generating report'); }
};

window.generateSchoolSummary = async () => {
    try {
        const summaryRes = await fetch('/api/reports/school-summary/2026');
        const summary = await summaryRes.json();
        document.getElementById('schoolSummaryResult').innerHTML = `<div class="mt-4 p-4 border rounded bg-gray-50"><h4 class="font-bold">School Summary ${summary.year}</h4><p>Total Students: ${summary.totalStudents}</p><p>Active Students: ${summary.activeStudents}</p><p>Total Teachers: ${summary.totalTeachers}</p><p>Total Classes: ${summary.totalClasses}</p><p>Male: ${summary.genderDistribution?.male || 0} | Female: ${summary.genderDistribution?.female || 0}</p></div>`;
    } catch (error) { console.error('Error:', error); alert('Error generating summary'); }
};

// ==================== ATTENDANCE ====================
async function showAttendance() {
    const pageTitle = document.getElementById('pageTitle');
    if (pageTitle) pageTitle.innerHTML = '<i class="fas fa-calendar-check mr-2"></i>Attendance';
    const today = new Date().toISOString().split('T')[0];
    const html = `<div class="bg-white rounded-xl shadow-sm p-6"><h2 class="text-xl font-bold mb-4">📅 Daily Attendance</h2><div class="mb-4"><label class="block text-sm font-medium mb-2">Date</label><input type="date" id="attendanceDate" value="${today}" class="border rounded-lg px-4 py-2"></div><button onclick="loadAttendanceSheet()" class="bg-blue-600 text-white px-6 py-2 rounded-lg">Load Attendance</button><div id="attendanceSheet" class="mt-6"></div></div>`;
    const mainContent = document.getElementById('mainContent');
    if (mainContent) mainContent.innerHTML = html;
}

window.loadAttendanceSheet = async () => {
    try {
        const studentsRes = await fetch('/api/students');
        const students = await studentsRes.json();
        if (students.length === 0) { document.getElementById('attendanceSheet').innerHTML = '<p class="text-yellow-600">No students found</p>'; return; }
        const date = document.getElementById('attendanceDate').value;
        const html = `<form id="attendanceForm"><div class="overflow-x-auto"><table class="w-full"><thead class="bg-gray-100"><tr><th class="p-3">Student</th><th class="p-3">Present</th><th class="p-3">Absent</th><th class="p-3">Remarks</th></tr></thead><tbody>${students.map(s => `<tr class="border-b"><td class="p-3">${s.firstName} ${s.lastName}</td><td class="p-3 text-center"><input type="radio" name="attendance_${s.id}" value="present" checked></td><td class="p-3 text-center"><input type="radio" name="attendance_${s.id}" value="absent"></td><td class="p-3"><input type="text" id="remark_${s.id}" class="border rounded px-2 py-1 w-full"></td></tr>`).join('')}</tbody>}</tr></div><button type="submit" class="mt-4 bg-green-600 text-white px-6 py-2 rounded-lg">Save Attendance for ${date}</button></form>`;
        document.getElementById('attendanceSheet').innerHTML = html;
        document.getElementById('attendanceForm').addEventListener('submit', (e) => { e.preventDefault(); alert('✅ Attendance saved successfully!'); addNotification(`Attendance recorded for ${date}`); loadAttendanceSheet(); });
    } catch (error) { console.error('Error:', error); }
};

// ==================== TIMETABLE ====================
async function showTimetable() {
    const pageTitle = document.getElementById('pageTitle');
    if (pageTitle) pageTitle.innerHTML = '<i class="fas fa-calendar-alt mr-2"></i>Timetable';
    try {
        const classesRes = await fetch('/api/school/classes');
        const classes = await classesRes.json();
        const html = `<div class="bg-white rounded-xl shadow-sm p-6"><h2 class="text-xl font-bold mb-4">📅 Class Timetable</h2><div class="mb-4"><label class="block text-sm font-medium mb-2">Select Class</label><select id="timetableClass" class="w-full md:w-1/2 border rounded-lg px-3 py-2"><option value="">Choose Class</option>${classes.map(c => `<option value="${c.id}">${c.name}</option>`).join('')}</select></div><button onclick="loadTimetable()" class="bg-blue-600 text-white px-6 py-2 rounded-lg">Load Timetable</button><div id="timetableView" class="mt-6 overflow-x-auto"></div><div class="mt-6"><button onclick="showEditTimetable()" class="bg-green-600 text-white px-6 py-2 rounded-lg"><i class="fas fa-edit"></i> Edit Timetable</button></div></div>`;
        const mainContent = document.getElementById('mainContent');
        if (mainContent) mainContent.innerHTML = html;
    } catch (error) { console.error('Error:', error); }
}

window.loadTimetable = () => {
    const classId = document.getElementById('timetableClass').value;
    if (!classId) { alert('Please select a class'); return; }
    const savedTimetable = localStorage.getItem(`timetable_${classId}`);
    const timetable = savedTimetable ? JSON.parse(savedTimetable) : {};
    const days = ['Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday'];
    const periods = ['8:00-8:40', '8:40-9:20', '9:20-10:00', '10:00-10:40', '11:00-11:40', '11:40-12:20', '12:20-1:00', '2:00-2:40', '2:40-3:20', '3:20-4:00'];
    let html = '<table class="w-full border"><thead><tr class="bg-gray-100"><th class="p-2 border">Time</th>';
    days.forEach(day => { html += `<th class="p-2 border">${day}</th>`; });
    html += '</tr></thead><tbody>';
    periods.forEach(period => {
        html += `<tr><td class="p-2 border font-bold">${period}</td>`;
        days.forEach(day => { const subject = timetable[`${day}_${period}`] || '-'; html += `<td class="p-2 border">${subject}</td>`; });
        html += '</tr>';
    });
    html += '</tbody></table>';
    document.getElementById('timetableView').innerHTML = html;
};

window.showEditTimetable = async () => {
    const classId = document.getElementById('timetableClass').value;
    if (!classId) { alert('Please select a class first'); return; }
    const subjectsRes = await fetch('/api/school/subjects');
    const subjects = await subjectsRes.json();
    const days = ['Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday'];
    const periods = ['8:00-8:40', '8:40-9:20', '9:20-10:00', '10:00-10:40', '11:00-11:40', '11:40-12:20', '12:20-1:00', '2:00-2:40', '2:40-3:20', '3:20-4:00'];
    const savedTimetable = localStorage.getItem(`timetable_${classId}`);
    const timetable = savedTimetable ? JSON.parse(savedTimetable) : {};
    let html = '<form id="editTimetableForm"><table class="w-full border"><thead><tr class="bg-gray-100"><th class="p-2 border">Time</th>';
    days.forEach(day => { html += `<th class="p-2 border">${day}</th>`; });
    html += '</tr></thead><tbody>';
    periods.forEach(period => {
        html += `<tr><td class="p-2 border font-bold">${period}</td>`;
        days.forEach(day => {
            const currentSubject = timetable[`${day}_${period}`] || '';
            html += `<td class="p-2 border"><select name="slot_${day}_${period}" class="w-full border rounded px-1 py-1 text-sm"><option value="">- Select -</option>${subjects.map(s => `<option value="${s.name}" ${currentSubject === s.name ? 'selected' : ''}>${s.name}</option>`).join('')}</select></td>`;
        });
        html += '</tr>';
    });
    html += '</tbody></table><div class="mt-4 flex gap-2"><button type="submit" class="bg-blue-600 text-white px-6 py-2 rounded-lg">Save Timetable</button><button type="button" onclick="loadTimetable()" class="bg-gray-600 text-white px-6 py-2 rounded-lg">Cancel</button></div></form>';
    document.getElementById('timetableView').innerHTML = html;
    document.getElementById('editTimetableForm').addEventListener('submit', (e) => {
        e.preventDefault();
        const formData = new FormData(e.target);
        const newTimetable = {};
        for (let [key, value] of formData.entries()) { newTimetable[key.replace('slot_', '')] = value; }
        localStorage.setItem(`timetable_${classId}`, JSON.stringify(newTimetable));
        alert('✅ Timetable saved successfully!');
        addNotification('Timetable was updated');
        loadTimetable();
    });
};

// ==================== EVENTS MANAGEMENT ====================
async function showEvents() {
    const pageTitle = document.getElementById('pageTitle');
    if (pageTitle) pageTitle.innerHTML = '<i class="fas fa-bullhorn mr-2"></i>Events & Announcements';
    const events = JSON.parse(localStorage.getItem('schoolEvents') || '[]');
    const html = `<div class="bg-white rounded-xl shadow-sm p-6"><div class="flex justify-between items-center mb-4"><h2 class="text-xl font-bold">📢 School Events & Announcements</h2><button onclick="showAddEventForm()" class="bg-green-600 text-white px-4 py-2 rounded-lg"><i class="fas fa-plus"></i> Add Event</button></div><div id="eventsList" class="space-y-4">${events.length > 0 ? events.map(event => `<div class="border rounded-lg p-4 ${event.type === 'holiday' ? 'bg-red-50' : event.type === 'exam' ? 'bg-yellow-50' : 'bg-blue-50'}"><div class="flex justify-between items-start"><div class="flex-1"><div class="flex items-center gap-2 mb-2"><span class="px-2 py-1 rounded-full text-xs ${event.type === 'holiday' ? 'bg-red-200 text-red-800' : event.type === 'exam' ? 'bg-yellow-200 text-yellow-800' : 'bg-blue-200 text-blue-800'}">${event.type.toUpperCase()}</span><span class="text-sm text-gray-500">${event.date}</span></div><h3 class="font-bold text-lg">${event.title}</h3><p class="text-gray-600 mt-1">${event.description}</p></div><button onclick="deleteEvent('${event.id}')" class="text-red-600 hover:text-red-800"><i class="fas fa-trash"></i></button></div></div>`).join('') : '<p class="text-gray-500 text-center py-8">No events scheduled. Click "Add Event" to create one.</p>'}</div></div>`;
    const mainContent = document.getElementById('mainContent');
    if (mainContent) mainContent.innerHTML = html;
}

window.showAddEventForm = () => {
    const html = `<div class="bg-white rounded-xl shadow-sm p-6"><h2 class="text-xl font-bold mb-4">Add New Event</h2><form id="addEventForm" class="space-y-4"><div><label class="block text-sm font-medium mb-1">Event Title *</label><input type="text" id="eventTitle" required class="w-full border rounded-lg px-3 py-2"></div><div><label class="block text-sm font-medium mb-1">Event Type</label><select id="eventType" class="w-full border rounded-lg px-3 py-2"><option value="general">General Announcement</option><option value="exam">Examination</option><option value="holiday">Holiday</option><option value="meeting">Meeting</option></select></div><div><label class="block text-sm font-medium mb-1">Date</label><input type="date" id="eventDate" required class="w-full border rounded-lg px-3 py-2"></div><div><label class="block text-sm font-medium mb-1">Description</label><textarea id="eventDescription" rows="3" class="w-full border rounded-lg px-3 py-2"></textarea></div><div class="flex gap-2"><button type="submit" class="bg-blue-600 text-white px-6 py-2 rounded-lg">Save Event</button><button type="button" onclick="showEvents()" class="bg-gray-600 text-white px-6 py-2 rounded-lg">Cancel</button></div></form></div>`;
    const mainContent = document.getElementById('mainContent');
    if (mainContent) mainContent.innerHTML = html;
    document.getElementById('addEventForm').addEventListener('submit', (e) => {
        e.preventDefault();
        const events = JSON.parse(localStorage.getItem('schoolEvents') || '[]');
        const newEvent = { id: Date.now().toString(), title: document.getElementById('eventTitle').value, type: document.getElementById('eventType').value, date: document.getElementById('eventDate').value, description: document.getElementById('eventDescription').value, createdAt: new Date().toISOString() };
        events.push(newEvent);
        localStorage.setItem('schoolEvents', JSON.stringify(events));
        alert('✅ Event added successfully!');
        addNotification(`New event: ${newEvent.title}`);
        showEvents();
    });
};

window.deleteEvent = (id) => {
    if (confirm('Delete this event?')) {
        let events = JSON.parse(localStorage.getItem('schoolEvents') || '[]');
        events = events.filter(e => e.id !== id);
        localStorage.setItem('schoolEvents', JSON.stringify(events));
        showEvents();
    }
};

