// ================================================================
// FIXED: saveSchoolProfile Function (PERSISTENCE FIX)
// ================================================================

async function saveSchoolProfile() {
    console.log('=== SAVE SCHOOL PROFILE ===');
    
    try {
        const schoolName = document.getElementById('schoolName')?.value || '';
        const schoolMotto = document.getElementById('schoolMotto')?.value || '';
        const schoolPhone = document.getElementById('schoolPhone')?.value || '';
        const schoolEmail = document.getElementById('schoolEmail')?.value || '';
        const schoolAddress = document.getElementById('schoolAddress')?.value || '';
        const schoolLogo = document.getElementById('schoolLogo')?.value || '';
        
        if (!schoolName.trim()) {
            showToast('❌ School Name is required', 'error');
            return;
        }
        
        const saveBtn = document.getElementById('saveSchoolBtn');
        if (saveBtn) {
            saveBtn.disabled = true;
            saveBtn.innerHTML = '<i class="fas fa-spinner fa-spin"></i> Saving...';
        }
        
        const payload = {
            schoolName: schoolName.trim(),
            motto: schoolMotto.trim(),
            phone: schoolPhone.trim(),
            email: schoolEmail.trim(),
            address: schoolAddress.trim(),
            logo: schoolLogo.trim()
        };
        
        console.log('📤 Sending payload:', payload);
        
        const response = await fetch('/api/school/setup', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(payload)
        });
        
        const result = await response.json();
        console.log('📥 Response:', result);
        
        if (saveBtn) {
            saveBtn.disabled = false;
            saveBtn.innerHTML = '<i class="fas fa-save"></i> Save School Profile';
        }
        
        if (result.success) {
            // ✅ Save to localStorage
            try {
                localStorage.setItem('schoolData', JSON.stringify(result.school));
                console.log('✅ School data saved to localStorage');
            } catch (e) {
                console.warn('Could not save to localStorage:', e);
            }
            
            // ⭐⭐⭐ FORCE SIDEBAR UPDATE - DIRECT APPROACH
            const nameEl = document.getElementById('sidebarSchoolName');
            if (nameEl) {
                nameEl.textContent = result.school.schoolName || 'My School';
                console.log('✅ Sidebar name updated directly to:', result.school.schoolName);
            }
            
            // Also update logo
            const logoImg = document.getElementById('sidebarSchoolLogo');
            const iconEl = document.getElementById('sidebarSchoolIcon');
            const container = document.getElementById('schoolLogoContainer');
            
            if (result.school.logo) {
                if (logoImg) {
                    logoImg.src = result.school.logo;
                    logoImg.classList.remove('hidden');
                    logoImg.classList.add('block');
                }
                if (iconEl) {
                    iconEl.classList.add('hidden');
                }
                if (container) {
                    container.classList.remove('bg-gradient-to-r', 'from-blue-600', 'to-purple-600');
                    container.classList.add('bg-white');
                }
            } else {
                if (logoImg) {
                    logoImg.classList.add('hidden');
                    logoImg.classList.remove('block');
                }
                if (iconEl) {
                    iconEl.classList.remove('hidden');
                }
                if (container) {
                    container.classList.add('bg-gradient-to-r', 'from-blue-600', 'to-purple-600');
                    container.classList.remove('bg-white');
                }
            }
            
            // Also try the global function if it exists
            if (typeof window.forceUpdateSidebar === 'function') {
                window.forceUpdateSidebar();
            }
            if (typeof window.updateSidebarUI === 'function') {
                window.updateSidebarUI(result.school);
            }
            
            showToast('✅ School profile saved successfully!', 'success');
            
            const statusDiv = document.getElementById('schoolSaveStatus');
            if (statusDiv) {
                statusDiv.className = 'p-3 rounded-lg bg-green-50 border border-green-200 text-green-700';
                statusDiv.innerHTML = `
                    <i class="fas fa-check-circle"></i> 
                    School profile saved successfully! 
                    <span class="text-sm text-gray-500 ml-2">(${new Date().toLocaleTimeString()})</span>
                `;
                statusDiv.classList.remove('hidden');
                setTimeout(() => {
                    statusDiv.classList.add('hidden');
                }, 5000);
            }
        } else {
            showToast('❌ Failed to save: ' + (result.error || 'Unknown error'), 'error');
            
            const statusDiv = document.getElementById('schoolSaveStatus');
            if (statusDiv) {
                statusDiv.className = 'p-3 rounded-lg bg-red-50 border border-red-200 text-red-700';
                statusDiv.innerHTML = `<i class="fas fa-exclamation-circle"></i> Failed to save: ${result.error || 'Unknown error'}`;
                statusDiv.classList.remove('hidden');
            }
        }
    } catch (error) {
        console.error('Error saving school profile:', error);
        showToast('❌ Error saving school profile: ' + error.message, 'error');
        
        const saveBtn = document.getElementById('saveSchoolBtn');
        if (saveBtn) {
            saveBtn.disabled = false;
            saveBtn.innerHTML = '<i class="fas fa-save"></i> Save School Profile';
        }
    }
}
// ================================================================
// UPDATE SETTINGS FORM
// ================================================================

function updateSchoolInfoUI(school) {
    if (!school) return;
    
    // Update any other UI elements that display school name
    const headerTitle = document.querySelector('.header-title');
    if (headerTitle) {
        headerTitle.textContent = school.schoolName || 'School Name';
    }
}

// ================================================================
// FORCE SIDEBAR UPDATE
// ================================================================

function forceSidebarUpdate() {
    console.log('🔄 Forcing sidebar update...');
    
    // Try to get school data from localStorage
    let school = null;
    try {
        const saved = localStorage.getItem('schoolData');
        if (saved) {
            school = JSON.parse(saved);
        }
    } catch (e) {}
    
    // If not in localStorage, try to fetch
    if (!school) {
        fetch('/api/school')
            .then(res => res.json())
            .then(data => {
                if (data.school) {
                    updateSchoolInfoUI(data.school);
                }
            })
            .catch(e => console.warn('Could not fetch school for sidebar update:', e));
        return;
    }
    
    updateSchoolInfoUI(school);
}
// ================================================================
// HELPER: updateSchoolInfoUI
// ================================================================

function updateSchoolInfoUI(school) {
    if (!school) return;
    
    console.log('🔄 Updating UI with school name:', school.schoolName);
    
    // Try multiple selectors for school name
    const selectors = [
        '#schoolNameSidebar',
        '.sidebar-school-name',
        '.school-name',
        '#schoolName',
        '.navbar-brand',
        '.header-school-name'
    ];
    
    let found = false;
    for (const selector of selectors) {
        const el = document.querySelector(selector);
        if (el) {
            el.textContent = school.schoolName || 'School Name';
            found = true;
            console.log(`✅ Updated ${selector} to:`, school.schoolName);
        }
    }
    
    if (!found) {
        console.warn('⚠️ No school name element found. Tried:', selectors.join(', '));
        
        // Try to find any element containing "School Name" text and update it
        const allElements = document.querySelectorAll('*');
        for (const el of allElements) {
            if (el.textContent === 'School Name' && el.children.length === 0) {
                el.textContent = school.schoolName || 'School Name';
                console.log('✅ Updated fallback element:', el.tagName);
                break;
            }
        }
    }
    
    // Update page title
    document.title = school.schoolName || 'School Management System';
    
    // Update logo
    const logoSelectors = ['#schoolLogoImg', '.sidebar-logo img', '.school-logo'];
    for (const selector of logoSelectors) {
        const logo = document.querySelector(selector);
        if (logo && school.logo) {
            logo.src = school.logo;
            logo.classList.remove('hidden');
            break;
        }
    }
}


// ================================================================
// FIXED: previewSchoolLogo Function
// ================================================================

function previewSchoolLogo(event) {
    console.log('=== PREVIEW SCHOOL LOGO ===');
    const file = event.target.files[0];
    if (!file) return;
    
    // Validate file type
    if (!file.type.startsWith('image/')) {
        showToast('❌ Please upload an image file', 'error');
        return;
    }
    
    // Validate file size (max 2MB)
    if (file.size > 2 * 1024 * 1024) {
        showToast('❌ Image too large. Max 2MB', 'error');
        return;
    }
    
    const reader = new FileReader();
    reader.onload = function(e) {
        const dataUrl = e.target.result;
        console.log('📸 Logo loaded, size:', dataUrl.length);
        
        // Update preview
        const preview = document.getElementById('logoPreview');
        const placeholder = document.getElementById('logoPlaceholder');
        
        if (preview) {
            preview.src = dataUrl;
            preview.classList.remove('hidden');
        }
        if (placeholder) {
            placeholder.style.display = 'none';
        }
        
        // ✅ Store in hidden input
        const logoInput = document.getElementById('schoolLogo');
        if (logoInput) {
            logoInput.value = dataUrl;
        }
        
        showToast('✅ Logo uploaded successfully! Click "Save School Profile" to apply.', 'success');
    };
    reader.onerror = function(e) {
        console.error('Error reading file:', e);
        showToast('❌ Error reading image file', 'error');
    };
    reader.readAsDataURL(file);
}


// ================================================================
// FIXED: removeSchoolLogo Function
// ================================================================

function removeSchoolLogo() {
    console.log('=== REMOVE SCHOOL LOGO ===');
    
    const preview = document.getElementById('logoPreview');
    const placeholder = document.getElementById('logoPlaceholder');
    const logoInput = document.getElementById('schoolLogo');
    const fileInput = document.getElementById('logoInput');
    
    if (preview) {
        preview.src = '';
        preview.classList.add('hidden');
    }
    if (placeholder) {
        placeholder.style.display = 'block';
    }
    if (logoInput) {
        logoInput.value = '';
    }
    if (fileInput) {
        fileInput.value = '';
    }
    
    showToast('🗑️ Logo removed. Click "Save School Profile" to apply.', 'info');
}


// ================================================================
// FIXED: resetSchoolProfile Function
// ================================================================

function resetSchoolProfile() {
    console.log('=== RESET SCHOOL PROFILE ===');
    
    if (!confirm('Reset school profile to default? This will clear all changes.')) {
        return;
    }
    
    document.getElementById('schoolName').value = '';
    document.getElementById('schoolMotto').value = 'Quality Education for All';
    document.getElementById('schoolPhone').value = '';
    document.getElementById('schoolEmail').value = '';
    document.getElementById('schoolAddress').value = '';
    
    removeSchoolLogo();
    
    showToast('🔄 School profile reset. Click "Save School Profile" to save.', 'info');
}

// ==================== IMPORT FUNCTIONS ====================

function downloadImportTemplate() {
    window.location.href = '/api/students/import/template';
}

function handleImportFileSelect(event) {
    const file = event.target.files[0];
    if (file) {
        displayImportFileInfo(file);
    }
}

function displayImportFileInfo(file) {
    const infoDiv = document.getElementById('importFileInfo');
    const fileName = document.getElementById('importFileName');
    const fileSize = document.getElementById('importFileSize');
    
    if (infoDiv) {
        infoDiv.classList.remove('hidden');
        // Validate file type
        const ext = file.name.split('.').pop().toLowerCase();
        if (!['xlsx', 'xls', 'csv'].includes(ext)) {
            alert('⚠️ Please upload an Excel (.xlsx, .xls) or CSV file');
            document.getElementById('importFileInput').value = '';
            infoDiv.classList.add('hidden');
            return;
        }
        
        // Validate file size (max 10MB)
        if (file.size > 10 * 1024 * 1024) {
            alert('⚠️ File size exceeds 10MB limit');
            document.getElementById('importFileInput').value = '';
            infoDiv.classList.add('hidden');
            return;
        }
        
        fileName.textContent = file.name;
        fileSize.textContent = `(${(file.size / 1024).toFixed(1)} KB)`;
    }
}

function clearImportFile() {
    document.getElementById('importFileInput').value = '';
    document.getElementById('importFileInfo').classList.add('hidden');
    document.getElementById('importResults').classList.add('hidden');
    document.getElementById('importProgressContainer').classList.add('hidden');
}

async function importStudentData() {
    const fileInput = document.getElementById('importFileInput');
    const file = fileInput.files[0];
    
    if (!file) {
        alert('⚠️ Please select a file to import');
        return;
    }
    
    const importBtn = document.getElementById('importBtn');
    const progressContainer = document.getElementById('importProgressContainer');
    const progressBar = document.getElementById('importProgressBar');
    const progressText = document.getElementById('importProgressText');
    const resultsDiv = document.getElementById('importResults');
    
    // Disable button and show progress
    importBtn.disabled = true;
    importBtn.innerHTML = '<i class="fas fa-spinner fa-spin"></i> Importing...';
    progressContainer.classList.remove('hidden');
    resultsDiv.classList.add('hidden');
    
    // Create form data
    const formData = new FormData();
    formData.append('file', file);
    formData.append('updateExisting', document.getElementById('updateExisting').checked ? 'true' : 'false');
    formData.append('skipInvalid', document.getElementById('skipInvalid').checked ? 'true' : 'false');
    formData.append('createMissing', document.getElementById('createMissing').checked ? 'true' : 'false');
    
    try {
        // Simulate progress
        let progress = 0;
        const progressInterval = setInterval(() => {
            progress += 5;
            if (progress > 90) clearInterval(progressInterval);
            progressBar.style.width = progress + '%';
            progressText.textContent = progress + '%';
        }, 200);
        
        const response = await fetch('/api/students/import', {
            method: 'POST',
            body: formData
        });
        
        clearInterval(progressInterval);
        progressBar.style.width = '100%';
        progressText.textContent = '100%';
        
        const result = await response.json();
        
        if (response.ok) {
            // Show success results
            const successCount = result.results?.success || 0;
            const failedCount = result.results?.failed || 0;
            const errors = result.results?.errors || [];
            
            let errorHtml = '';
            if (errors.length > 0) {
                errorHtml = `
                    <div class="mt-3">
                        <p class="font-semibold text-red-600">Errors:</p>
                        <ul class="list-disc list-inside text-sm text-red-600 max-h-40 overflow-y-auto">
                            ${errors.map(e => `<li>${escapeHtml(e)}</li>`).join('')}
                        </ul>
                    </div>
                `;
            }
            
            resultsDiv.innerHTML = `
                <div class="p-4 bg-green-50 rounded-lg border border-green-200">
                    <div class="flex items-start gap-3">
                        <i class="fas fa-check-circle text-green-600 text-2xl mt-1"></i>
                        <div>
                            <h4 class="font-bold text-green-800">Import Complete!</h4>
                            <p class="text-sm text-green-700">
                                ✅ ${successCount} students processed successfully
                                ${failedCount > 0 ? `⚠️ ${failedCount} rows failed` : ''}
                            </p>
                            ${errorHtml}
                        </div>
                    </div>
                    <button onclick="clearImportFile()" class="mt-3 bg-green-600 text-white px-4 py-2 rounded-lg hover:bg-green-700 transition">
                        <i class="fas fa-check"></i> Done
                    </button>
                </div>
            `;
            resultsDiv.classList.remove('hidden');
            
            // Ask if user wants to view the updated student list
            if (successCount > 0) {
                setTimeout(() => {
                    if (confirm(`${successCount} students imported successfully! Do you want to view the student list?`)) {
                        showStudentList();
                    }
                }, 1000);
            }
            
        } else {
            // Show error
            resultsDiv.innerHTML = `
                <div class="p-4 bg-red-50 rounded-lg border border-red-200">
                    <div class="flex items-start gap-3">
                        <i class="fas fa-exclamation-triangle text-red-600 text-2xl mt-1"></i>
                        <div>
                            <h4 class="font-bold text-red-800">Import Failed</h4>
                            <p class="text-sm text-red-700">${result.error || 'Unknown error occurred'}</p>
                            <p class="text-xs text-red-600 mt-1">Please check your file format and try again</p>
                        </div>
                    </div>
                    <button onclick="clearImportFile()" class="mt-3 bg-red-600 text-white px-4 py-2 rounded-lg hover:bg-red-700 transition">
                        <i class="fas fa-times"></i> Close
                    </button>
                </div>
            `;
            resultsDiv.classList.remove('hidden');
        }
        
    } catch (error) {
        console.error('Import error:', error);
        resultsDiv.innerHTML = `
            <div class="p-4 bg-red-50 rounded-lg border border-red-200">
                <div class="flex items-start gap-3">
                    <i class="fas fa-exclamation-triangle text-red-600 text-2xl mt-1"></i>
                    <div>
                        <h4 class="font-bold text-red-800">Network Error</h4>
                        <p class="text-sm text-red-700">${error.message}</p>
                        <p class="text-xs text-red-600 mt-1">Please check your connection and try again</p>
                    </div>
                </div>
                <button onclick="clearImportFile()" class="mt-3 bg-red-600 text-white px-4 py-2 rounded-lg hover:bg-red-700 transition">
                    <i class="fas fa-times"></i> Close
                </button>
            </div>
        `;
        resultsDiv.classList.remove('hidden');
    } finally {
        importBtn.disabled = false;
        importBtn.innerHTML = '<i class="fas fa-upload"></i> Import Students';
    }
}

// ==================== DRAG AND DROP SUPPORT ====================

function initializeDragAndDrop() {
    const dropZone = document.getElementById('dropZone');
    if (!dropZone) return;
    
    // Remove any existing listeners to avoid duplicates
    dropZone.removeEventListener('dragover', handleDragOver);
    dropZone.removeEventListener('dragleave', handleDragLeave);
    dropZone.removeEventListener('drop', handleDrop);
    dropZone.removeEventListener('click', handleDropZoneClick);
    
    dropZone.addEventListener('dragover', handleDragOver);
    dropZone.addEventListener('dragleave', handleDragLeave);
    dropZone.addEventListener('drop', handleDrop);
    dropZone.addEventListener('click', handleDropZoneClick);
}

function handleDragOver(e) {
    e.preventDefault();
    this.classList.add('border-blue-500', 'bg-blue-50');
}

function handleDragLeave(e) {
    e.preventDefault();
    this.classList.remove('border-blue-500', 'bg-blue-50');
}

function handleDrop(e) {
    e.preventDefault();
    this.classList.remove('border-blue-500', 'bg-blue-50');
    
    const files = e.dataTransfer.files;
    if (files.length > 0) {
        const file = files[0];
        const input = document.getElementById('importFileInput');
        
        // Create a FileList-like object
        const dataTransfer = new DataTransfer();
        dataTransfer.items.add(file);
        input.files = dataTransfer.files;
        
        // Trigger change event
        input.dispatchEvent(new Event('change'));
    }
}

function handleDropZoneClick() {
    document.getElementById('importFileInput').click();
}

