// ==================== SETTINGS HELPER FUNCTIONS ====================

function initializeSettingsTabs() {
    const tabs = document.querySelectorAll('.settings-tab');
    tabs.forEach(tab => {
        tab.addEventListener('click', () => {
            const tabId = tab.dataset.tab;
            tabs.forEach(t => {
                t.classList.remove('active', 'border-b-2', 'border-blue-600', 'text-blue-600');
                t.classList.add('text-gray-600');
            });
            tab.classList.add('active', 'border-b-2', 'border-blue-600', 'text-blue-600');
            tab.classList.remove('text-gray-600');
            
            document.querySelectorAll('.settings-tab-content').forEach(c => c.classList.add('hidden'));
            const activeTab = document.getElementById(tabId);
            if (activeTab) activeTab.classList.remove('hidden');
        });
    });
}

function getDefaultGradingSystem() {
    return {
        'A': { min: 80, max: 100, remark: 'Excellent' },
        'B': { min: 70, max: 79, remark: 'Very Good' },
        'C': { min: 60, max: 69, remark: 'Good' },
        'D': { min: 50, max: 59, remark: 'Satisfactory' },
        'E': { min: 40, max: 49, remark: 'Fair' },
        'F': { min: 0, max: 39, remark: 'Poor' }
    };
}

function renderGradingForm(gradingSystem) {
    if (!gradingSystem) gradingSystem = getDefaultGradingSystem();
    
    return Object.entries(gradingSystem).map(([grade, data]) => `
        <div class="bg-white rounded-lg p-3 border grade-row" data-grade="${grade}">
            <div class="flex justify-between items-center mb-2">
                <input type="text" value="${grade}" class="w-12 border rounded px-2 py-1 text-center font-bold grade-letter" readonly>
                <button type="button" onclick="removeGradeLevel('${grade}')" class="text-red-600 hover:text-red-800">
                    <i class="fas fa-trash"></i>
                </button>
            </div>
            <div>
                <label class="text-xs text-gray-500">Min %</label>
                <input type="number" class="w-full border rounded px-2 py-1 text-sm grade-min" value="${data.min}">
            </div>
            <div class="mt-2">
                <label class="text-xs text-gray-500">Max %</label>
                <input type="number" class="w-full border rounded px-2 py-1 text-sm grade-max" value="${data.max}">
            </div>
            <div class="mt-2">
                <label class="text-xs text-gray-500">Remark</label>
                <input type="text" class="w-full border rounded px-2 py-1 text-sm grade-remark" value="${data.remark}">
            </div>
        </div>
    `).join('');
}

function addGradeLevel() {
    const container = document.getElementById('gradingTable');
    const newGradeLetter = prompt('Enter grade letter (e.g., A+, A-, etc.):');
    if (!newGradeLetter) return;
    
    const newGradeHtml = `
        <div class="bg-white rounded-lg p-3 border grade-row" data-grade="${newGradeLetter}">
            <div class="flex justify-between items-center mb-2">
                <input type="text" value="${newGradeLetter}" class="w-12 border rounded px-2 py-1 text-center font-bold grade-letter" readonly>
                <button type="button" onclick="removeGradeLevel('${newGradeLetter}')" class="text-red-600 hover:text-red-800">
                    <i class="fas fa-trash"></i>
                </button>
            </div>
            <div>
                <label class="text-xs text-gray-500">Min %</label>
                <input type="number" class="w-full border rounded px-2 py-1 text-sm grade-min" value="0">
            </div>
            <div class="mt-2">
                <label class="text-xs text-gray-500">Max %</label>
                <input type="number" class="w-full border rounded px-2 py-1 text-sm grade-max" value="0">
            </div>
            <div class="mt-2">
                <label class="text-xs text-gray-500">Remark</label>
                <input type="text" class="w-full border rounded px-2 py-1 text-sm grade-remark" value="">
            </div>
        </div>
    `;
    
    container.insertAdjacentHTML('beforeend', newGradeHtml);
}

function removeGradeLevel(grade) {
    const element = document.querySelector(`.grade-row[data-grade="${grade}"]`);
    if (element) element.remove();
}

async function saveSchoolProfile() {
    console.log('=== SAVE SCHOOL PROFILE ===');
    
    try {
        const schoolName = document.getElementById('schoolName')?.value || '';
        const schoolMotto = document.getElementById('schoolMotto')?.value || '';
        const schoolPhone = document.getElementById('schoolPhone')?.value || '';
        const schoolEmail = document.getElementById('schoolEmail')?.value || '';
        const schoolAddress = document.getElementById('schoolAddress')?.value || '';
        const schoolLogo = document.getElementById('schoolLogo')?.value || '';
        
        // Validate required fields
        if (!schoolName.trim()) {
            showToast('❌ School Name is required', 'error');
            return;
        }
        
        const payload = {
            schoolName: schoolName.trim(),
            motto: schoolMotto.trim(),
            phone: schoolPhone.trim(),
            email: schoolEmail.trim(),
            address: schoolAddress.trim(),
            logo: schoolLogo.trim()
        };
        
        console.log('📤 Sending payload:', payload);
        
        const response = await fetch('/api/school/setup', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(payload)
        });
        
        const result = await response.json();
        console.log('📥 Response:', result);
        
        if (result.success) {
            // ✅ Update local storage
            try {
                localStorage.setItem('schoolData', JSON.stringify(result.school));
            } catch (e) {}
            
            showToast('✅ School profile saved successfully!', 'success');
            
            // ✅ Update UI
            updateSchoolInfoUI(result.school);
        } else {
            showToast('❌ Failed to save: ' + (result.error || 'Unknown error'), 'error');
        }
    } catch (error) {
        console.error('Error saving school profile:', error);
        showToast('❌ Error saving school profile: ' + error.message, 'error');
    }
}

// ================================================================
// FIXED: updateSchoolInfoUI - Updates ALL UI elements
// ================================================================

function updateSchoolInfoUI(school) {
    if (!school) {
        console.warn('⚠️ No school data to update UI');
        return;
    }
    
    console.log('🔄 Updating UI with school data:', school.schoolName);
    
    // 1. Update sidebar school name
    const schoolNameEl = document.getElementById('schoolNameSidebar');
    if (schoolNameEl) {
        schoolNameEl.textContent = school.schoolName || 'School Name';
        console.log('✅ Updated sidebar school name to:', school.schoolName);
    } else {
        console.warn('⚠️ Could not find #schoolNameSidebar element');
    }
    
    // 2. Update sidebar motto
    const mottoEl = document.getElementById('schoolMottoSidebar');
    if (mottoEl) {
        mottoEl.textContent = school.motto || 'Quality Education for All';
    }
    
    // 3. Update sidebar logo
    const logoImg = document.getElementById('schoolLogoImg');
    if (logoImg && school.logo) {
        logoImg.src = school.logo;
        logoImg.classList.remove('hidden');
        console.log('✅ Updated sidebar logo');
    } else if (logoImg) {
        logoImg.classList.add('hidden');
    }
    
    // 4. Update page title
    document.title = school.schoolName || 'School Management System';
    
    // 5. Update any header title
    const headerTitle = document.querySelector('.header-title');
    if (headerTitle) {
        headerTitle.textContent = school.schoolName || 'School Name';
    }
    
    // 6. Update dashboard school name if visible
    const dashboardSchoolName = document.getElementById('dashboardSchoolName');
    if (dashboardSchoolName) {
        dashboardSchoolName.textContent = school.schoolName || 'School Name';
    }
    
    // 7. Update any breadcrumb or navigation
    const navSchoolName = document.querySelector('.nav-school-name');
    if (navSchoolName) {
        navSchoolName.textContent = school.schoolName || 'School Name';
    }
    
    // 8. Update any footer
    const footerSchool = document.getElementById('footerSchoolName');
    if (footerSchool) {
        footerSchool.textContent = school.schoolName || 'School Name';
    }
    
    console.log('✅ UI updated successfully');
}

function previewLogo(event) {
    const file = event.target.files[0];
    if (file) {
        const reader = new FileReader();
        reader.onload = function(e) {
            const previewContainer = document.getElementById('logoPreviewContainer');
            const placeholder = document.getElementById('logoPlaceholder');
            const existingImg = document.getElementById('logoPreview');
            
            if (existingImg) existingImg.remove();
            if (placeholder) placeholder.style.display = 'none';
            
            const img = document.createElement('img');
            img.id = 'logoPreview';
            img.src = e.target.result;
            img.className = 'w-full h-full object-cover';
            previewContainer.appendChild(img);
            
            document.getElementById('schoolLogo').value = e.target.result;
        };
        reader.readAsDataURL(file);
    }
}

function removeLogo() {
    const previewContainer = document.getElementById('logoPreviewContainer');
    const img = document.getElementById('logoPreview');
    const placeholder = document.getElementById('logoPlaceholder');
    
    if (img) img.remove();
    if (placeholder) placeholder.style.display = 'flex';
    
    document.getElementById('schoolLogo').value = '';
}

function resetSchoolForm() {
    // Reload the page to reset form
    showSettings();
}




// ==================== FIXED ACADEMIC PERIOD UPDATE FUNCTION ====================
// ==================== FIXED UPDATE ACADEMIC PERIOD FOR SETTINGS PAGE ====================
// ==================== COMPLETE WORKING UPDATE ACADEMIC PERIOD ====================
// ==================== FIXED UPDATE ACADEMIC PERIOD WITH VERIFICATION ====================
// ==================== FIXED UPDATE ACADEMIC PERIOD ====================
async function updateAcademicPeriod() {
    console.log('updateAcademicPeriod called');
    
    const yearSelect = document.getElementById('academicYearSelect');
    const termSelect = document.getElementById('academicTermSelect');
    
    if (!yearSelect || !termSelect) {
        alert('Please refresh the page and try again');
        return;
    }
    
    const selectedYear = parseInt(yearSelect.value);
    const selectedTerm = parseInt(termSelect.value);
    
    if (isNaN(selectedYear) || isNaN(selectedTerm)) {
        alert('Please select valid year and term');
        return;
    }
    
    const updateBtn = event?.target;
    let originalText = 'Update Current Period';
    if (updateBtn) {
        originalText = updateBtn.innerHTML;
        updateBtn.innerHTML = '<i class="fas fa-spinner fa-spin"></i> Updating...';
        updateBtn.disabled = true;
    }
    
    try {
        // Update server
        const response = await fetch('/api/academic/settings', {
            method: 'PUT',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
                currentYear: selectedYear,
                currentTerm: selectedTerm
            })
        });
        
        if (!response.ok) {
            throw new Error('Server update failed');
        }
        
        const result = await response.json();
        console.log('Update result:', result);
        
        // Update local variables
        currentAcademicSettings.currentYear = selectedYear;
        currentAcademicSettings.currentTerm = selectedTerm;
        localStorage.setItem('currentAcademicYear', selectedYear.toString());
        localStorage.setItem('currentAcademicTerm', selectedTerm.toString());
        
        // Update header
        updateAcademicHeader();
        
        const termName = getTermName(selectedTerm);
        showToast(`✅ Switched to ${termName} ${selectedYear}`, 'success');
        
        // CRITICAL: Close modal and force reload the current page
        closeModal();
        
        // Force reload the page to show fresh data
        setTimeout(() => {
            forceReloadAllPages();
        }, 500);
        
    } catch (error) {
        console.error('Error:', error);
        alert('❌ Error updating academic period: ' + error.message);
    } finally {
        if (updateBtn) {
            updateBtn.innerHTML = originalText;
            updateBtn.disabled = false;
        }
    }
}

