async function createNewAcademicYear() {
    const newYear = prompt('Enter new academic year (e.g., 2027):');
    if (!newYear || isNaN(parseInt(newYear))) return;
    
    try {
        const response = await fetch('/api/academic/years', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ year: parseInt(newYear) })
        });
        
        if (response.ok) {
            alert(`✅ Academic year ${newYear} created successfully!`);
            showSettings();
        } else {
            alert('❌ Error creating academic year');
        }
    } catch (error) {
        console.error('Error:', error);
        alert('Network error: ' + error.message);
    }
}

async function copyDataFromPreviousYear() {
    const yearsRes = await fetch('/api/academic/years');
    const years = await yearsRes.json();
    const fromYear = prompt(`Select year to copy from:\nAvailable years: ${years.join(', ')}`);
    const toYear = prompt('Enter target year:');
    
    if (!fromYear || !toYear) return;
    
    try {
        const response = await fetch(`/api/academic/years/${toYear}/copy-from/${fromYear}`, {
            method: 'POST'
        });
        
        if (response.ok) {
            alert(`✅ Data copied from ${fromYear} to ${toYear}`);
            showSettings();
        } else {
            alert('❌ Error copying data');
        }
    } catch (error) {
        console.error('Error:', error);
        alert('Network error: ' + error.message);
    }
}

function getDefaultTermDate(term, type) {
    const year = new Date().getFullYear();
    const dates = {
        1: { start: `${year}-01-10`, end: `${year}-04-10` },
        2: { start: `${year}-05-10`, end: `${year}-08-10` },
        3: { start: `${year}-09-10`, end: `${year}-12-10` }
    };
    return dates[term][type];
}

async function saveTermRanges() {
    const termRanges = {};
    for (let term = 1; term <= 3; term++) {
        termRanges[term] = {
            name: term === 1 ? 'First Term' : term === 2 ? 'Second Term' : 'Third Term',
            startDate: document.getElementById(`term${term}Start`).value,
            endDate: document.getElementById(`term${term}End`).value,
            isActive: true
        };
    }
    
    try {
        const response = await fetch('/api/academic/term-ranges', {
            method: 'PUT',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ termRanges })
        });
        
        if (response.ok) {
            alert('✅ Term dates saved successfully!');
        } else {
            alert('❌ Error saving term dates');
        }
    } catch (error) {
        console.error('Error:', error);
        alert('Network error: ' + error.message);
    }
}

async function saveGradingSystem() {
    const gradingSystem = {};
    const rows = document.querySelectorAll('.grade-row');
    
    rows.forEach(row => {
        const grade = row.querySelector('.grade-letter').value;
        const min = parseInt(row.querySelector('.grade-min').value);
        const max = parseInt(row.querySelector('.grade-max').value);
        const remark = row.querySelector('.grade-remark').value;
        
        if (grade && !isNaN(min) && !isNaN(max)) {
            gradingSystem[grade] = { min, max, remark };
        }
    });
    
    try {
        const response = await fetch('/api/school/grading', {
            method: 'PUT',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ gradingSystem })
        });
        
        if (response.ok) {
            alert('✅ Grading system saved successfully!');
        } else {
            alert('❌ Error saving grading system');
        }
    } catch (error) {
        console.error('Error:', error);
        alert('Network error: ' + error.message);
    }
}

function resetGradingSystem() {
    const defaultSystem = getDefaultGradingSystem();
    const container = document.getElementById('gradingTable');
    container.innerHTML = renderGradingForm(defaultSystem);
}

async function saveRegistrationFeeSettings() {
    const amount = parseInt(document.getElementById('registrationFeeAmount').value);
    const enabled = document.getElementById('registrationFeeEnabled').checked;
    
    let settings = await fetch('/api/school').then(r => r.json());
    settings = settings.settings || {};
    
    settings.registrationFee = amount;
    settings.registrationFeeEnabled = enabled;
    
    try {
        const response = await fetch('/api/school/settings', {
            method: 'PUT',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(settings)
        });
        
        if (response.ok) {
            alert('✅ Registration fee settings saved!');
        } else {
            alert('❌ Error saving registration fee settings');
        }
    } catch (error) {
        console.error('Error:', error);
        alert('Network error: ' + error.message);
    }
}

