// Also update the sidebar school name when loaded
function updateSidebarSchoolName() {
    fetch('/api/school')
        .then(res => res.json())
        .then(data => {
            const school = data.school;
            if (school && school.schoolName) {
                const sidebarSchoolName = document.getElementById('sidebarSchoolName');
                if (sidebarSchoolName) {
                    sidebarSchoolName.innerText = school.schoolName.substring(0, 20);
                }
            }
        })
        .catch(error => console.error('Error fetching school:', error));
}

