// ==================== EXPORT FUNCTIONS ====================

// Full Backup to JSON
async function exportFullBackup() {
    try {
        const response = await fetch('/api/reports/export-all');
        const data = await response.json();
        
        const backupData = {
            ...data,
            exportDate: new Date().toISOString(),
            version: '2.0',
            systemInfo: {
                schoolName: currentSchool?.schoolName || 'School Name',
                exportType: 'Full Backup'
            }
        };
        
        const jsonStr = JSON.stringify(backupData, null, 2);
        const blob = new Blob([jsonStr], { type: 'application/json' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `school_full_backup_${new Date().toISOString().split('T')[0]}.json`;
        a.click();
        URL.revokeObjectURL(url);
        
        // Save backup info
        const fileSize = (jsonStr.length / 1024).toFixed(2);
        localStorage.setItem('lastBackupDate', new Date().toLocaleString());
        localStorage.setItem('backupSize', `${fileSize} KB`);
        
        alert(`✅ Full backup created successfully!\nFile size: ${fileSize} KB`);
    } catch (error) {
        console.error('Error creating backup:', error);
        alert('❌ Error creating backup: ' + error.message);
    }
}

// Export Students to Excel (CSV)
async function exportStudentsToExcel() {
    try {
        const response = await fetch('/api/students');
        let students = await response.json();
        
        // Fetch classes for class names
        const classesRes = await fetch('/api/school/classes');
        const classes = await classesRes.json();
        
        // Enhance students with class names
        students = students.map(student => {
            let currentClass = 'Not Assigned';
            if (student.currentClassId) {
                const classObj = classes.find(c => c.id === student.currentClassId);
                currentClass = classObj ? classObj.name : 'Not Assigned';
            }
            return { ...student, currentClass };
        });
        
        const exportData = students.map(s => ({
            'Admission Number': s.admissionNumber || '',
            'First Name': s.firstName || '',
            'Last Name': s.lastName || '',
            'Gender': s.gender || '',
            'Date of Birth': s.dateOfBirth || '',
            'Class': s.currentClass || 'Not Assigned',
            'Status': s.status || 'Active',
            'Parent Name': s.parentInfo?.name || '',
            'Parent Phone': s.parentInfo?.phone || '',
            'Parent Email': s.parentInfo?.email || '',
            'Parent Alt Phone': s.parentInfo?.altPhone || '',
            'Parent Occupation': s.parentInfo?.occupation || '',
            'Address': s.address || '',
            'Blood Group': s.medicalInfo?.bloodGroup || '',
            'Allergies': s.medicalInfo?.allergies || '',
            'Medical Conditions': s.medicalInfo?.conditions || '',
            'Emergency Contact': s.medicalInfo?.emergencyContact || '',
            'Previous School': s.previousSchool || '',
            'Admission Type': s.admissionType || 'New',
            'Enrollment Date': s.enrolledAt ? new Date(s.enrolledAt).toLocaleDateString() : '',
            'Created At': s.createdAt ? new Date(s.createdAt).toLocaleDateString() : ''
        }));
        
        downloadCSV(exportData, `students_export_${new Date().toISOString().split('T')[0]}.csv`);
        alert(`✅ ${students.length} students exported successfully!`);
    } catch (error) {
        console.error('Error exporting students:', error);
        alert('❌ Error exporting students: ' + error.message);
    }
}

