async function generateStudentReport() {
    try {
        const response = await fetch('/api/students');
        const students = await response.json();
        
        const reportData = students.map(s => ({
            'Admission Number': s.admissionNumber || '',
            'Student Name': `${s.firstName || ''} ${s.lastName || ''}`.trim(),
            'Gender': s.gender || '',
            'Status': s.status || 'Active',
            'Parent Name': s.parentInfo?.name || '',
            'Parent Phone': s.parentInfo?.phone || '',
            'Enrollment Date': s.enrolledAt ? new Date(s.enrolledAt).toLocaleDateString() : ''
        }));
        
        downloadCSV(reportData, `student_report_${new Date().toISOString().split('T')[0]}.csv`);
        alert(`✅ Student report generated with ${students.length} records!`);
    } catch (error) {
        alert('Error generating student report: ' + error.message);
    }
}

async function generateFinancialReport() {
    try {
        const response = await fetch('/api/fee/payments');
        const payments = await response.json();
        
        const totalCollected = payments.reduce((sum, p) => sum + (p.totalAmount || p.amount || 0), 0);
        
        const reportData = [
            { 'Metric': 'Total Payments', 'Value': payments.length },
            { 'Metric': 'Total Amount Collected', 'Value': `UGX ${totalCollected.toLocaleString()}` },
            { 'Metric': 'Cash Payments', 'Value': payments.filter(p => p.method === 'cash').length },
            { 'Metric': 'Bank Transfers', 'Value': payments.filter(p => p.method === 'bank').length },
            { 'Metric': 'Mobile Money', 'Value': payments.filter(p => p.method === 'mobile').length },
            { 'Metric': 'Report Generated', 'Value': new Date().toLocaleString() }
        ];
        
        downloadCSV(reportData, `financial_report_${new Date().toISOString().split('T')[0]}.csv`);
        alert(`✅ Financial report generated! Total collected: UGX ${(totalCollected / 1000000).toFixed(2)}M`);
    } catch (error) {
        alert('Error generating financial report: ' + error.message);
    }
}

async function generateFeeSummaryReport() {
    try {
        const [studentsRes, feeStructuresRes, feePaymentsRes] = await Promise.all([
            fetch('/api/students'),
            fetch('/api/fee/structures'),
            fetch('/api/fee/payments')
        ]);
        
        const students = await studentsRes.json();
        const feeStructures = await feeStructuresRes.json();
        const payments = await feePaymentsRes.json();
        
        const reportData = students.map(s => {
            const studentPayments = payments.filter(p => p.studentId === s.id);
            const totalPaid = studentPayments.reduce((sum, p) => sum + (p.totalAmount || p.amount || 0), 0);
            
            return {
                'Admission Number': s.admissionNumber || '',
                'Student Name': `${s.firstName || ''} ${s.lastName || ''}`.trim(),
                'Total Payments': studentPayments.length,
                'Total Amount Paid': `UGX ${totalPaid.toLocaleString()}`,
                'Last Payment': studentPayments.length > 0 ? new Date(Math.max(...studentPayments.map(p => new Date(p.date)))).toLocaleDateString() : 'Never'
            };
        }).filter(s => s['Total Payments'] > 0);
        
        downloadCSV(reportData, `fee_summary_report_${new Date().toISOString().split('T')[0]}.csv`);
        alert(`✅ Fee summary report generated with ${reportData.length} students who have made payments!`);
    } catch (error) {
        alert('Error generating fee summary report: ' + error.message);
    }
}

