function showAutoBackupSettings() {
    const modalHtml = `
        <div class="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50">
            <div class="bg-white rounded-2xl p-6 max-w-md w-full mx-4">
                <div class="flex justify-between items-center mb-4">
                    <h3 class="text-xl font-bold">Auto Backup Settings</h3>
                    <button onclick="closeModal()" class="text-gray-500 text-2xl">&times;</button>
                </div>
                <div class="space-y-4">
                    <div>
                        <label class="block text-sm font-medium mb-2">Auto Backup Frequency</label>
                        <select id="autoBackupFrequency" class="w-full border rounded-lg px-3 py-2">
                            <option value="disabled">Disabled</option>
                            <option value="daily">Daily</option>
                            <option value="weekly">Weekly</option>
                            <option value="monthly">Monthly</option>
                        </select>
                    </div>
                    <div>
                        <label class="block text-sm font-medium mb-2">Backup Location</label>
                        <select id="backupLocation" class="w-full border rounded-lg px-3 py-2">
                            <option value="local">Local Storage (Browser)</option>
                            <option value="download">Auto Download</option>
                        </select>
                    </div>
                    <div class="bg-yellow-50 p-3 rounded-lg">
                        <p class="text-sm text-yellow-800">
                            <i class="fas fa-info-circle"></i> Auto backups will be saved to your browser's local storage. 
                            For manual backups, use the export buttons above.
                        </p>
                    </div>
                    <div class="flex gap-3">
                        <button onclick="saveAutoBackupSettings()" class="flex-1 bg-blue-600 text-white py-2 rounded-lg">Save Settings</button>
                        <button onclick="closeModal()" class="flex-1 bg-gray-300 text-gray-700 py-2 rounded-lg">Cancel</button>
                    </div>
                </div>
            </div>
        </div>
    `;
    document.body.insertAdjacentHTML('beforeend', modalHtml);
}

function saveAutoBackupSettings() {
    const frequency = document.getElementById('autoBackupFrequency').value;
    const location = document.getElementById('backupLocation').value;
    
    localStorage.setItem('autoBackupFrequency', frequency);
    localStorage.setItem('backupLocation', location);
    
    alert('✅ Auto backup settings saved!');
    closeModal();
}

async function resetSystem() {
    const confirmation = prompt('⚠️ WARNING: This will delete ALL data!\n\nType "RESET ALL DATA" to confirm:');
    if (confirmation === 'RESET ALL DATA') {
        try {
            const response = await fetch('/api/system/reset', { method: 'DELETE' });
            if (response.ok) {
                localStorage.clear();
                alert('✅ System reset successfully! The page will now reload.');
                setTimeout(() => window.location.reload(), 1500);
            } else {
                alert('❌ Error resetting system');
            }
        } catch (error) {
            alert('Network error: ' + error.message);
        }
    } else {
        alert('Reset cancelled');
    }
}

