// Function to remove tangible item
function removeTangibleItemFromPayment(id) {
    window.selectedTangibleItems = window.selectedTangibleItems.filter(i => i.id !== id);
    updateTangibleItemsDisplay();
}

// Update tangible items display
function updateTangibleItemsDisplay() {
    const container = document.getElementById('tangibleItemsList');
    if (!container) return;
    if (window.selectedTangibleItems.length === 0) {
        container.innerHTML = '<p class="text-gray-500 text-sm">No items added yet</p>';
        return;
    }
    container.innerHTML = window.selectedTangibleItems.map(item => `
        <div class="flex justify-between items-center p-2 bg-white rounded border mb-1">
            <span>${item.name}</span>
            <div><span class="font-semibold mr-3">Qty: ${item.quantity}</span><button type="button" onclick="removeTangibleItemFromPayment('${item.id}')" class="text-red-600"><i class="fas fa-times"></i></button></div>
        </div>
    `).join('');
}

