// Toggle activity search box
function toggleActivitySearchBox() {
    const box = document.getElementById('activitySearchBox');
    if (box) {
        box.classList.toggle('hidden');
        if (!box.classList.contains('hidden')) box.focus();
        else { box.value = ''; filterActivityComponentsList(); }
    }
}

// Filter activity components list
function filterActivityComponentsList() {
    const searchTerm = document.getElementById('activitySearchBox')?.value.toLowerCase() || '';
    document.querySelectorAll('#activityComponentsList label').forEach(label => {
        const text = label.innerText.toLowerCase();
        label.style.display = text.includes(searchTerm) ? '' : 'none';
    });
}

// Reset collection form
function resetCollectionForm() {
    const tuitionInput = document.getElementById('tuitionAmount');
    if (tuitionInput) tuitionInput.value = '0';
    
    const fullTuitionCheck = document.getElementById('fullTuitionCheck');
    if (fullTuitionCheck) fullTuitionCheck.checked = false;
    
    // Clear all activity inputs
    document.querySelectorAll('.cashAmount, .itemsBrought').forEach(input => {
        input.value = '';
    });
    
    // Reset item totals
    document.querySelectorAll('[id^="itemTotal_"]').forEach(span => {
        span.innerHTML = 'UGX 0';
    });
    
    // Reset period totals
    const periodTotals = ['one_timeTotalSelected', 'termlyTotalSelected', 'yearlyTotalSelected'];
    periodTotals.forEach(id => {
        const span = document.getElementById(id);
        if (span) span.innerHTML = 'UGX 0';
    });
    
    // Clear payment details
    const paymentReference = document.getElementById('paymentReference');
    const paymentNotes = document.getElementById('paymentNotes');
    if (paymentReference) paymentReference.value = '';
    if (paymentNotes) paymentNotes.value = '';
    
    updateCollectionTotal();
}

window.resetCollectionForm = resetCollectionForm;

