let paymentHistoryLoaded = false;

// ==================== FIXED PAYMENT HISTORY WITH STUDENT-SPECIFIC EXPECTED AMOUNTS ====================
// ==================== COMPLETELY FIXED PAYMENT HISTORY - READS STUDENT CUSTOM VALUES ====================
// ==================== COMPLETELY REBUILT LOAD PAYMENT HISTORY WITH OVER-DELIVERY HANDLING ====================
// Version: 8.0 - Handles over-delivered items correctly

// ==================== COMPLETE REBUILT PAYMENT HISTORY ====================
// Version: FINAL - Fixed status display and arrow direction

// ==================== COMPLETE REBUILT PAYMENT HISTORY ====================
// Version: 14.0 - Shows ALL item names, correct statuses, clean display

// ==================== COMPLETE REBUILT PAYMENT HISTORY ====================
// Version: 7.0 - Properly displays item names from all payment structures

async function loadPaymentHistoryIntoTable() {
    console.log('loadPaymentHistoryIntoTable called - Version 7.0 (Item Names Fixed)');
    
    const container = document.getElementById('paymentHistoryTableContainer');
    if (!container) return;
    
    container.innerHTML = '<div class="text-center p-8 text-gray-500"><div class="loading-spinner"></div> Loading payment history...</div>';
    
    try {
        const { currentYear, currentTerm } = currentAcademicSettings;
        
        // ========== FETCH ALL REQUIRED DATA ==========
        const [paymentsRes, studentsRes, feeStructuresRes, feeAssignmentsRes, feeBursariesRes] = await Promise.all([
            fetch(`/api/fee/payments`), // Get ALL payments, filter later
            fetch('/api/students'),
            fetch('/api/fee/structures'),
            fetch('/api/student-fee-assignments'),
            fetch('/api/fee/bursaries')
        ]);
        
        // ========== PARSE DATA ==========
        let allPayments = await paymentsRes.json();
        allPayments = Array.isArray(allPayments) ? allPayments : [];
        
        let students = await studentsRes.json();
        students = Array.isArray(students) ? students : [];
        
        let feeStructures = await feeStructuresRes.json();
        feeStructures = Array.isArray(feeStructures) ? feeStructures : [];
        
        let feeAssignments = await feeAssignmentsRes.json();
        feeAssignments = Array.isArray(feeAssignments) ? feeAssignments : [];
        
        let feeBursaries = await feeBursariesRes.json();
        feeBursaries = Array.isArray(feeBursaries) ? feeBursaries : [];
        
        // ========== FILTER PAYMENTS FOR CURRENT TERM ==========
        const payments = allPayments.filter(p => 
            p && p.term === currentTerm && p.academicYear === currentYear.toString()
        );
        
        console.log(`📊 Found ${payments.length} payments for Term ${currentTerm} ${currentYear}`);
        
        // ========== BUILD MAPS ==========
        const studentMap = {};
        students.forEach(s => { if (s) studentMap[s.id] = s; });
        
        const feeStructureMap = {};
        feeStructures.forEach(fs => { if (fs) feeStructureMap[fs.id] = fs; });
        
        const assignmentMap = {};
        feeAssignments.forEach(a => { if (a && a.studentId) assignmentMap[a.studentId] = a; });
        
        const bursaryMap = {};
        feeBursaries.forEach(b => { if (b) bursaryMap[b.id] = b; });
        
        // ========== HELPER: GET CUSTOMIZED ITEM VALUE ==========
        function getCustomizedItemValue(student, itemId, defaultAmount, defaultQuantity, defaultPaymentOption, defaultUnitPrice) {
            if (!student) {
                return {
                    amount: defaultAmount || 0,
                    quantity: defaultQuantity || 1,
                    paymentOption: defaultPaymentOption || 'either',
                    unitPrice: defaultUnitPrice || (defaultAmount / (defaultQuantity || 1)),
                    isCustomized: false,
                    reason: null,
                    updatedAt: null,
                    customAmount: null,
                    customQuantity: null,
                    defaultAmount: defaultAmount || 0,
                    defaultQuantity: defaultQuantity || 1
                };
            }
            
            if (student.customItemOverrides && student.customItemOverrides[itemId]) {
                const custom = student.customItemOverrides[itemId];
                if (custom.isActive !== false) {
                    const customAmount = (custom.customAmount !== null && custom.customAmount !== undefined) 
                        ? custom.customAmount 
                        : defaultAmount;
                    const customQuantity = (custom.customQuantity !== null && custom.customQuantity !== undefined) 
                        ? custom.customQuantity 
                        : defaultQuantity;
                    const customPaymentOption = custom.paymentOption || defaultPaymentOption;
                    
                    let customUnitPrice = defaultUnitPrice;
                    if (customQuantity > 0 && customAmount > 0) {
                        customUnitPrice = customAmount / customQuantity;
                    } else if (customAmount > 0) {
                        customUnitPrice = customAmount / (customQuantity || 1);
                    } else if (customQuantity > 0) {
                        customUnitPrice = defaultUnitPrice || (defaultAmount / (defaultQuantity || 1));
                    }
                    
                    return {
                        amount: customAmount,
                        quantity: customQuantity,
                        paymentOption: customPaymentOption,
                        unitPrice: customUnitPrice,
                        isCustomized: true,
                        reason: custom.reason || null,
                        updatedAt: custom.updatedAt || null,
                        customAmount: custom.customAmount,
                        customQuantity: custom.customQuantity,
                        defaultAmount: custom.defaultAmount || defaultAmount,
                        defaultQuantity: custom.defaultQuantity || defaultQuantity
                    };
                }
            }
            
            return {
                amount: defaultAmount || 0,
                quantity: defaultQuantity || 1,
                paymentOption: defaultPaymentOption || 'either',
                unitPrice: defaultUnitPrice || (defaultAmount / (defaultQuantity || 1)),
                isCustomized: false,
                reason: null,
                updatedAt: null,
                customAmount: null,
                customQuantity: null,
                defaultAmount: defaultAmount || 0,
                defaultQuantity: defaultQuantity || 1
            };
        }
        
        // ========== HELPER: FIND ITEM IN FEE STRUCTURE ==========
        function findItemInFeeStructure(feeStructure, componentName, itemName, periodType) {
            if (!feeStructure || !feeStructure.activityComponents) return null;
            
            for (const comp of feeStructure.activityComponents) {
                const compMatch = comp.name && comp.name.toLowerCase() === componentName.toLowerCase();
                const periodMatch = periodType ? comp.periodType === periodType : true;
                
                if (compMatch && periodMatch) {
                    for (const item of (comp.items || [])) {
                        if (item.name && item.name.toLowerCase() === itemName.toLowerCase()) {
                            return {
                                ...item,
                                componentName: comp.name,
                                periodType: comp.periodType,
                                statusGroupName: comp.statusGroupName || comp.name
                            };
                        }
                    }
                }
            }
            return null;
        }
        
        // ========== HELPER: GET EXPECTED AMOUNT WITH CUSTOM VALUES ==========
        function getExpectedAmountWithCustom(student, feeStructure, componentName, itemName, periodType) {
            const feeItem = findItemInFeeStructure(feeStructure, componentName, itemName, periodType);
            
            if (!feeItem) {
                return { totalAmount: 0, quantityRequired: 1, unitPrice: 0, paymentOption: 'either', isCustomized: false };
            }
            
            const defaultAmount = feeItem.totalAmount || 0;
            const defaultQuantity = feeItem.quantity || 1;
            const defaultUnitPrice = feeItem.unitPrice || (defaultAmount / defaultQuantity);
            const defaultPaymentOption = feeItem.paymentOption || 'either';
            const itemId = feeItem.id || itemName;
            
            const custom = getCustomizedItemValue(
                student,
                itemId,
                defaultAmount,
                defaultQuantity,
                defaultPaymentOption,
                defaultUnitPrice
            );
            
            const isTransportation = componentName.toLowerCase().includes('transport') || 
                                    itemName.toLowerCase().includes('van') ||
                                    itemName.toLowerCase().includes('transport');
            
            let finalAmount = custom.amount;
            let finalQuantity = custom.quantity;
            let finalUnitPrice = custom.unitPrice;
            let finalPaymentOption = custom.paymentOption;
            
            if (isTransportation && student && student.customTransportation) {
                if (student.customTransportation.hasTransportation === false) {
                    return { totalAmount: 0, quantityRequired: 0, unitPrice: 0, paymentOption: 'cash_only', isCustomized: true };
                }
                if (student.customTransportation.amount) {
                    finalAmount = student.customTransportation.amount;
                    finalUnitPrice = finalAmount / (finalQuantity || 1);
                }
            }
            
            return {
                totalAmount: finalAmount,
                quantityRequired: finalQuantity,
                unitPrice: finalUnitPrice,
                paymentOption: finalPaymentOption,
                isCustomized: custom.isCustomized,
                reason: custom.reason,
                customAmount: custom.customAmount,
                customQuantity: custom.customQuantity,
                defaultAmount: defaultAmount,
                defaultQuantity: defaultQuantity
            };
        }
        
        // ========== PROCESS EACH PAYMENT ==========
        for (const payment of payments) {
            const student = studentMap[payment.studentId];
            const assignment = assignmentMap[payment.studentId] || {};
            const feeStructure = feeStructureMap[assignment.feeStructureId];
            
            // ========== CALCULATE TUITION ==========
            let expectedTuition = feeStructure?.tuition || 0;
            let tuitionPaid = payment.tuitionPaid || 0;
            let discountAmount = 0;
            let appliedBursary = null;
            
            if (student && student.customBursary && student.customBursary.amount > 0) {
                discountAmount = student.customBursary.amount;
                expectedTuition = Math.max(0, expectedTuition - discountAmount);
                appliedBursary = { name: 'Custom Bursary', isCustom: true };
            } else if (assignment.bursaryId && bursaryMap[assignment.bursaryId]) {
                const bursary = bursaryMap[assignment.bursaryId];
                appliedBursary = bursary;
                if (bursary.type === 'percentage') {
                    discountAmount = (expectedTuition * bursary.value) / 100;
                    expectedTuition = Math.max(0, expectedTuition - discountAmount);
                } else {
                    discountAmount = bursary.value;
                    expectedTuition = Math.max(0, expectedTuition - discountAmount);
                }
            }
            
            const tuitionRemaining = Math.max(0, expectedTuition - tuitionPaid);
            
            payment._tuitionRemaining = tuitionRemaining;
            payment._tuitionExpected = expectedTuition;
            payment._tuitionPaid = tuitionPaid;
            payment._discountAmount = discountAmount;
            payment._appliedBursary = appliedBursary;
            
            // ========== PROCESS ACTIVITY ITEMS - FIXED TO EXTRACT ITEM NAMES ==========
            const processItem = (item, periodType) => {
                // ========== GET THE ACTUAL ITEM NAME ==========
                const itemName = item.itemName || item.name || 'Unnamed Item';
                const componentName = item.componentName || periodType || 'Activity';
                
                // ========== GET EXPECTED VALUES ==========
                const expected = getExpectedAmountWithCustom(
                    student,
                    feeStructure,
                    componentName,
                    itemName,
                    periodType || item.periodType
                );
                
                const paidAmount = item.paymentType === 'paid_cash' ? (item.amountPaid || 0) : (item.cashEquivalent || 0);
                let itemsBrought = item.itemsBrought || 0;
                let quantityRequired = expected.quantityRequired || 1;
                let expectedAmount = expected.totalAmount || 0;
                let unitPrice = expected.unitPrice || 1;
                let isCustomized = expected.isCustomized || false;
                let customReason = expected.reason || null;
                
                // ========== CALCULATE REMAINING CORRECTLY ==========
                let remainingAmount = 0;
                let remainingQuantity = 0;
                let isFullyPaid = false;
                let isOverDelivered = false;
                let originalItemsBrought = itemsBrought;
                
                if (item.paymentType === 'paid_cash') {
                    isFullyPaid = paidAmount >= expectedAmount;
                    remainingAmount = Math.max(0, expectedAmount - paidAmount);
                    remainingQuantity = 0;
                } else if (item.paymentType === 'brought_item') {
                    if (itemsBrought > quantityRequired && quantityRequired > 0) {
                        isOverDelivered = true;
                        isFullyPaid = true;
                        remainingQuantity = 0;
                        remainingAmount = 0;
                    } else {
                        isFullyPaid = itemsBrought >= quantityRequired;
                        remainingQuantity = Math.max(0, quantityRequired - itemsBrought);
                        remainingAmount = remainingQuantity * unitPrice;
                    }
                }
                
                // ========== STORE ALL DATA WITH PROPER ITEM NAMES ==========
                item._itemName = itemName; // CRITICAL: Store the actual item name
                item._componentName = componentName;
                item._expectedAmount = expectedAmount;
                item._quantityRequired = quantityRequired;
                item._remainingAmount = remainingAmount;
                item._remainingQuantity = remainingQuantity;
                item._isFullyPaid = isFullyPaid;
                item._isOverDelivered = isOverDelivered;
                item._originalItemsBrought = originalItemsBrought;
                item._unitPrice = unitPrice;
                item._paymentOption = expected.paymentOption || 'either';
                item._isCustomized = isCustomized;
                item._customReason = customReason;
                item._defaultAmount = expected.defaultAmount;
                item._defaultQuantity = expected.defaultQuantity;
                item._paidAmount = paidAmount;
                item._itemsBrought = itemsBrought;
                item._periodType = periodType || item.periodType;
                
                // ========== DETERMINE STATUS TEXT ==========
                if (isFullyPaid) {
                    item._statusText = '✅ Fully Paid';
                    item._statusClass = 'bg-green-100 text-green-800';
                } else if (isOverDelivered) {
                    item._statusText = '💰 Credit (Over-delivered)';
                    item._statusClass = 'bg-blue-100 text-blue-800';
                } else if (paidAmount > 0 || itemsBrought > 0) {
                    item._statusText = '⚠️ Partial Payment';
                    item._statusClass = 'bg-yellow-100 text-yellow-800';
                } else {
                    item._statusText = '❌ Not Paid';
                    item._statusClass = 'bg-red-100 text-red-600';
                }
            };
            
            // ========== PROCESS ALL PAYMENT ITEMS ==========
            // 1. From activityItemPayments
            if (payment.activityItemPayments) {
                for (const item of payment.activityItemPayments) {
                    processItem(item, item.periodType || 'termly');
                }
            }
            
            // 2. From paymentsByPeriodType
            if (payment.paymentsByPeriodType) {
                for (const period of ['one_time', 'termly', 'yearly']) {
                    const periodItems = payment.paymentsByPeriodType[period] || [];
                    for (const item of periodItems) {
                        processItem(item, period);
                    }
                }
            }
        }
        
        // ========== BUILD STATUS GROUPS MAP ==========
        const statusGroupsMap = new Map();
        statusGroupsMap.set('Tuition', { name: 'Tuition', periodType: 'termly' });
        
        for (const payment of payments) {
            const processItemsForGroups = (items) => {
                for (const item of items) {
                    if (item._componentName) {
                        let normalized = item._componentName;
                        if (normalized.toLowerCase().includes('transport')) normalized = 'Transportation';
                        else if (normalized.toLowerCase().includes('admission')) normalized = 'Admission';
                        else if (normalized.toLowerCase().includes('scholastic')) normalized = 'Scholastic';
                        else if (normalized.toLowerCase().includes('sports')) normalized = 'Sports';
                        else if (normalized.toLowerCase().includes('development')) normalized = 'Development';
                        else if (normalized.toLowerCase().includes('uniform')) normalized = 'Uniform';
                        else if (normalized.toLowerCase().includes('requirement')) normalized = 'Scholastic';
                        
                        if (!statusGroupsMap.has(normalized)) {
                            statusGroupsMap.set(normalized, { 
                                name: normalized, 
                                periodType: item._periodType || item.periodType || 'termly' 
                            });
                        }
                    }
                }
            };
            
            if (payment.activityItemPayments) processItemsForGroups(payment.activityItemPayments);
            if (payment.paymentsByPeriodType) {
                for (const period of ['one_time', 'termly', 'yearly']) {
                    processItemsForGroups(payment.paymentsByPeriodType[period] || []);
                }
            }
        }
        
        const sortedStatusGroups = Array.from(statusGroupsMap.values()).sort((a, b) => {
            const order = { 'Transportation': 1, 'Admission': 2, 'Scholastic': 3, 'Uniform': 4, 'Tuition': 5 };
            return (order[a.name] || 99) - (order[b.name] || 99);
        });
        
        const sortedPayments = [...payments].sort((a, b) => new Date(b.date) - new Date(a.date));
        
        // ========== HELPER FUNCTIONS ==========
        function formatMoney(amount) {
            const num = Math.round(amount || 0);
            return num.toLocaleString('en-US');
        }
        
        function escapeHtml(text) {
            if (!text) return '';
            const div = document.createElement('div');
            div.textContent = text;
            return div.innerHTML;
        }
        
        function getStatusBadge(item) {
            if (item._isFullyPaid && !item._isOverDelivered) {
                return '<span class="bg-green-100 text-green-800 text-xs px-2 py-0.5 rounded-full">✅ Fully Paid</span>';
            } else if (item._isOverDelivered) {
                return '<span class="bg-blue-100 text-blue-800 text-xs px-2 py-0.5 rounded-full">💰 Credit</span>';
            } else if (item._paidAmount > 0 || item._itemsBrought > 0) {
                return '<span class="bg-yellow-100 text-yellow-800 text-xs px-2 py-0.5 rounded-full">⚠️ Partial</span>';
            } else {
                return '<span class="bg-red-100 text-red-600 text-xs px-2 py-0.5 rounded-full">❌ Unpaid</span>';
            }
        }
        
        // ========== BUILD TABLE HTML ==========
        let tableHtml = `
            <div class="overflow-x-auto" style="max-height: 70vh; overflow-y: auto;">
                <table class="w-full text-sm border-collapse" id="paymentHistoryTable">
                    <thead class="bg-gray-100 sticky top-0 z-10 shadow-sm">
                        <tr>
                            <th class="p-3 border-b w-8"></th>
                            <th class="p-3 border-b w-24">Date</th>
                            <th class="p-3 border-b w-32">Receipt</th>
                            <th class="p-3 border-b text-left">Student</th>
                            ${sortedStatusGroups.map(sg => `<th class="p-3 border-b text-center min-w-28">🏷️ ${escapeHtml(sg.name)}</th>`).join('')}
                            <th class="p-3 border-b text-right w-28">Total</th>
                            <th class="p-3 border-b w-24">Method</th>
                            <th class="p-3 border-b text-center w-16">Actions</th>
                        </tr>
                    </thead>
                    <tbody>
        `;
        
        for (let idx = 0; idx < sortedPayments.length; idx++) {
            const payment = sortedPayments[idx];
            
            const groupTotals = {};
            const groupItems = {};
            const groupRemaining = {};
            const groupExpected = {};
            const groupCustomized = {};
            const groupStatus = {};
            
            for (const sg of sortedStatusGroups) {
                groupTotals[sg.name] = 0;
                groupItems[sg.name] = [];
                groupRemaining[sg.name] = 0;
                groupExpected[sg.name] = 0;
                groupCustomized[sg.name] = 0;
                groupStatus[sg.name] = 'fully_paid';
            }
            
            // ========== ADD TUITION TO GROUP TOTALS ==========
            if (payment._tuitionPaid > 0) {
                groupTotals['Tuition'] = (groupTotals['Tuition'] || 0) + payment._tuitionPaid;
                groupRemaining['Tuition'] = payment._tuitionRemaining || 0;
                groupExpected['Tuition'] = payment._tuitionExpected || 0;
                groupStatus['Tuition'] = payment._tuitionRemaining <= 0 ? 'fully_paid' : 'partial';
            }
            
            // ========== PROCESS UNIQUE ITEMS WITH PROPER NAMES ==========
            const uniqueItems = new Map();
            
            const addUniqueItem = (item) => {
                // ========== USE THE CORRECT ITEM NAME ==========
                const itemName = item._itemName || item.itemName || item.name || 'Unnamed Item';
                const componentName = item._componentName || item.componentName || 'Other';
                const key = `${componentName}_${itemName}`;
                
                if (!uniqueItems.has(key)) {
                    const paidAmount = item.paymentType === 'paid_cash' ? (item.amountPaid || 0) : (item.cashEquivalent || 0);
                    uniqueItems.set(key, {
                        name: itemName, // This is what displays in the table!
                        component: componentName,
                        amount: paidAmount,
                        paymentType: item.paymentType,
                        itemsBrought: item.itemsBrought || 0,
                        originalItemsBrought: item._originalItemsBrought || 0,
                        quantityRequired: item._quantityRequired || 1,
                        expectedAmount: item._expectedAmount || 0,
                        remainingAmount: item._remainingAmount || 0,
                        remainingQuantity: item._remainingQuantity || 0,
                        isFullyPaid: item._isFullyPaid || false,
                        isOverDelivered: item._isOverDelivered || false,
                        isCustomized: item._isCustomized || false,
                        customReason: item._customReason || null,
                        defaultAmount: item._defaultAmount || 0,
                        defaultQuantity: item._defaultQuantity || 1,
                        unitPrice: item._unitPrice || 1,
                        statusText: item._statusText || 'Not Paid',
                        statusClass: item._statusClass || 'bg-red-100 text-red-600',
                        componentName: componentName,
                        periodType: item._periodType || item.periodType
                    });
                }
            };
            
            // ========== EXTRACT ITEMS FROM BOTH LOCATIONS ==========
            if (payment.activityItemPayments) {
                for (const item of payment.activityItemPayments) {
                    addUniqueItem(item);
                }
            }
            
            if (payment.paymentsByPeriodType) {
                for (const period of ['one_time', 'termly', 'yearly']) {
                    const periodItems = payment.paymentsByPeriodType[period] || [];
                    for (const item of periodItems) {
                        addUniqueItem(item);
                    }
                }
            }
            
            // ========== DISTRIBUTE ITEMS TO STATUS GROUPS ==========
            for (const [key, item] of uniqueItems) {
                let groupName = item.component || 'Other';
                if (groupName.toLowerCase().includes('transport')) groupName = 'Transportation';
                else if (groupName.toLowerCase().includes('admission')) groupName = 'Admission';
                else if (groupName.toLowerCase().includes('scholastic')) groupName = 'Scholastic';
                else if (groupName.toLowerCase().includes('uniform')) groupName = 'Uniform';
                else if (groupName.toLowerCase().includes('sports')) groupName = 'Sports';
                else if (groupName.toLowerCase().includes('development')) groupName = 'Development';
                else if (groupName.toLowerCase().includes('requirement')) groupName = 'Scholastic';
                
                const matchedGroup = sortedStatusGroups.find(sg => sg.name === groupName);
                if (matchedGroup) {
                    groupTotals[matchedGroup.name] = (groupTotals[matchedGroup.name] || 0) + item.amount;
                    groupRemaining[matchedGroup.name] = item.remainingAmount;
                    groupExpected[matchedGroup.name] = item.expectedAmount;
                    groupItems[matchedGroup.name].push(item);
                    if (item.isCustomized) groupCustomized[matchedGroup.name]++;
                    if (!item.isFullyPaid) groupStatus[matchedGroup.name] = 'partial';
                }
            }
            
            const totalAmount = Object.values(groupTotals).reduce((s, v) => s + v, 0);
            const hasDetails = payment._tuitionPaid > 0 || uniqueItems.size > 0;
            
            const methodIcon = payment.method === 'cash' ? '💵' : 
                              payment.method === 'bank' ? '🏦' : 
                              payment.method === 'mobile' ? '📱' : '🏫';
            const methodClass = payment.method === 'cash' ? 'bg-green-100 text-green-800' : 
                               payment.method === 'bank' ? 'bg-blue-100 text-blue-800' : 
                               payment.method === 'mobile' ? 'bg-purple-100 text-purple-800' : 'bg-orange-100 text-orange-800';
            
            const safeReceipt = payment.receiptNumber?.replace(/[^a-zA-Z0-9]/g, '_') || Date.now().toString();
            const mainRowId = `payment_main_${safeReceipt}_${idx}`;
            const detailRowId = `payment_detail_${safeReceipt}_${idx}`;
            
            // ========== BUILD STATUS GROUP CELLS WITH ITEM NAMES ==========
            let groupCells = '';
            for (const sg of sortedStatusGroups) {
                const amount = groupTotals[sg.name] || 0;
                const remaining = groupRemaining[sg.name] || 0;
                const expected = groupExpected[sg.name] || 0;
                const items = groupItems[sg.name] || [];
                const itemsCount = items.length;
                const customizedCount = groupCustomized[sg.name] || 0;
                const isFullyPaid = remaining <= 0 && amount > 0;
                const hasItems = itemsCount > 0;
                
                let displayText = '';
                if (amount > 0 && isFullyPaid) {
                    displayText = `<span class="text-green-600 font-semibold">UGX ${formatMoney(amount)}</span><div class="text-xs text-green-500">✓ Fully Paid</div>`;
                } else if (amount > 0 && remaining > 0) {
                    displayText = `<span class="text-yellow-600 font-semibold">UGX ${formatMoney(amount)}</span><div class="text-xs text-red-500">Remaining: UGX ${formatMoney(remaining)}</div>`;
                } else if (amount > 0) {
                    displayText = `<span class="text-green-600 font-semibold">UGX ${formatMoney(amount)}</span>`;
                } else if (hasItems) {
                    displayText = `<span class="text-gray-400">-</span>`;
                } else {
                    displayText = `<span class="text-gray-400">-</span>`;
                }
                
                // ========== SHOW ITEM NAMES IN THE CELL ==========
                let itemsDisplay = '';
                if (hasItems) {
                    const itemNames = items.map(i => i.name).slice(0, 3);
                    const more = items.length > 3 ? ` +${items.length - 3} more` : '';
                    itemsDisplay = `
                        <div class="text-xs text-gray-400 mt-1">
                            ${itemNames.join(', ')}${more}
                            ${customizedCount > 0 ? ` <span class="text-orange-500">⚡${customizedCount}</span>` : ''}
                        </div>
                    `;
                }
                
                const customBadge = customizedCount > 0 ? 
                    `<span class="text-xs text-orange-500 ml-1">⚡${customizedCount}</span>` : '';
                
                groupCells += `
                    <td class="p-3 text-center border-b">
                        ${displayText}
                        ${itemsDisplay}
                        ${hasItems ? `<div class="text-xs text-gray-400">${itemsCount} item(s)${customBadge}</div>` : ''}
                    </td>
                `;
            }
            
            tableHtml += `
                <tr class="border-b payment-main-row cursor-pointer" id="${mainRowId}" data-detail-id="${detailRowId}">
                    <td class="p-3 text-center border-b">
                        ${hasDetails ? `<i class="fas fa-chevron-down text-gray-400 expand-icon transition-transform" id="expand_icon_${safeReceipt}_${idx}"></i>` : ''}
                    </td>
                    <td class="p-3 whitespace-nowrap border-b">
                        <span class="text-sm">${new Date(payment.date).toLocaleDateString()}</span>
                    </td>
                    <td class="p-3 font-mono text-xs font-semibold text-blue-600 border-b">${payment.receiptNumber || 'N/A'}</td>
                    <td class="p-3 font-medium border-b">${escapeHtml(payment.studentName || 'N/A')}</td>
                    ${groupCells}
                    <td class="p-3 text-right font-bold border-b">UGX ${formatMoney(totalAmount)}</td>
                    <td class="p-3 border-b">
                        <span class="px-2 py-1 rounded-full text-xs ${methodClass} inline-flex items-center gap-1">
                            ${methodIcon} ${(payment.method || 'CASH').toUpperCase()}
                        </span>
                    </td>
                    <td class="p-3 text-center border-b">
                        <button onclick="event.stopPropagation(); printPaymentReceipt('${payment.receiptNumber}')" 
                                class="text-blue-600 hover:text-blue-800 p-1 rounded hover:bg-blue-50 transition"
                                title="Print Receipt">
                            <i class="fas fa-print"></i>
                        </button>
                    </td>
                </tr>
            `;
            
            // ========== DETAIL ROW - SHOWS FULL ITEM NAMES ==========
            if (hasDetails) {
                tableHtml += `
                    <tr id="${detailRowId}" class="hidden payment-detail-row">
                        <td colspan="${3 + sortedStatusGroups.length + 3}" class="p-0">
                            <div class="payment-detail-content p-4 bg-gray-100 border-t border-b">
                                <div class="bg-white rounded-lg shadow-md overflow-hidden">
                                    <div class="bg-gradient-to-r from-blue-600 to-purple-600 px-4 py-2 text-white">
                                        <p class="text-sm font-semibold flex items-center gap-2">
                                            <i class="fas fa-receipt"></i> Payment Details - Receipt: ${payment.receiptNumber}
                                        </p>
                                        ${payment._appliedBursary ? `<p class="text-xs opacity-75">🎖️ Bursary: ${payment._appliedBursary.name}${payment._appliedBursary.isCustom ? ' (Custom)' : ''}</p>` : ''}
                                        ${payment._discountAmount > 0 ? `<p class="text-xs opacity-75">Discount: UGX ${formatMoney(payment._discountAmount)}</p>` : ''}
                                    </div>
                                    <div class="p-4">
                                        <!-- Tuition -->
                                        ${payment._tuitionPaid > 0 ? `
                                            <div class="mb-4">
                                                <div class="flex justify-between items-center p-3 bg-blue-50 rounded-lg border border-blue-200">
                                                    <div class="flex items-center gap-2">
                                                        <i class="fas fa-money-bill-wave text-blue-600 text-lg"></i>
                                                        <span class="font-semibold">💰 Tuition Fee</span>
                                                        ${payment._appliedBursary ? `<span class="text-xs text-green-600">🎖️ ${payment._appliedBursary.name}</span>` : ''}
                                                    </div>
                                                    <div class="text-right">
                                                        <div class="font-bold text-green-600 text-lg">UGX ${formatMoney(payment._tuitionPaid)}</div>
                                                        ${payment._tuitionRemaining > 0 ? 
                                                            `<div class="text-xs text-red-500">Remaining: UGX ${formatMoney(payment._tuitionRemaining)} out of UGX ${formatMoney(payment._tuitionExpected)}</div>` : 
                                                            payment._tuitionExpected > 0 ? `<div class="text-xs text-green-500">✓ Fully Paid (UGX ${formatMoney(payment._tuitionExpected)})</div>` : ''
                                                        }
                                                        ${payment._discountAmount > 0 ? `<div class="text-xs text-blue-500">Discount: UGX ${formatMoney(payment._discountAmount)}</div>` : ''}
                                                    </div>
                                                </div>
                                            </div>
                                        ` : ''}
                                        
                                        <!-- Status Groups -->
                                        <div class="space-y-3">
                                            ${sortedStatusGroups.map(sg => {
                                                const sgItems = groupItems[sg.name] || [];
                                                if (sgItems.length === 0) return '';
                                                const sgTotal = groupTotals[sg.name] || 0;
                                                const sgRemaining = groupRemaining[sg.name] || 0;
                                                const sgExpected = groupExpected[sg.name] || 0;
                                                const sgCustomized = groupCustomized[sg.name] || 0;
                                                const sgIsFullyPaid = sgRemaining <= 0 && sgTotal > 0;
                                                const groupCollapseId = `group_detail_${safeReceipt}_${idx}_${sg.name.replace(/[^a-zA-Z0-9]/g, '_')}`;
                                                
                                                return `
                                                    <div class="border rounded-lg overflow-hidden shadow-sm">
                                                        <div class="status-group-header flex justify-between items-center p-3 bg-gray-50 cursor-pointer"
                                                             onclick="toggleStatusGroup('${groupCollapseId}')">
                                                            <div class="flex items-center gap-2 flex-wrap">
                                                                <i class="fas fa-chevron-right text-gray-400 text-xs transition-transform" id="icon_${groupCollapseId}"></i>
                                                                <i class="fas fa-tag text-purple-500"></i>
                                                                <span class="font-semibold">🏷️ ${escapeHtml(sg.name)}</span>
                                                                <span class="text-xs text-gray-500 bg-gray-200 px-2 py-0.5 rounded-full">${sgItems.length} item${sgItems.length !== 1 ? 's' : ''}</span>
                                                                ${sgCustomized > 0 ? `<span class="text-xs bg-orange-100 text-orange-700 px-2 py-0.5 rounded-full">⚡ ${sgCustomized} customized</span>` : ''}
                                                                ${sgIsFullyPaid ? `<span class="text-xs bg-green-100 text-green-800 px-2 py-0.5 rounded-full">✅ Fully Paid</span>` : sgTotal > 0 ? `<span class="text-xs bg-yellow-100 text-yellow-800 px-2 py-0.5 rounded-full">⚠️ Partial</span>` : ''}
                                                            </div>
                                                            <div class="flex items-center gap-3">
                                                                <div class="text-right">
                                                                    <span class="font-bold text-green-600">UGX ${formatMoney(sgTotal)}</span>
                                                                    ${sgRemaining > 0 ? 
                                                                        `<div class="text-xs text-red-500">Remaining: UGX ${formatMoney(sgRemaining)} out of UGX ${formatMoney(sgExpected)}</div>` : 
                                                                        sgExpected > 0 ? `<div class="text-xs text-green-500">✓ Fully Paid (UGX ${formatMoney(sgExpected)})</div>` : ''
                                                                    }
                                                                </div>
                                                            </div>
                                                        </div>
                                                        <div id="${groupCollapseId}" class="hidden p-3 bg-white border-t">
                                                            <div class="group-detail-content max-h-80 overflow-y-auto">
                                                                <div class="text-sm font-semibold mb-3 pb-2 border-b flex items-center gap-2">
                                                                    <i class="fas fa-boxes text-gray-500"></i> Items Breakdown:
                                                                    ${sgCustomized > 0 ? `<span class="text-xs bg-orange-100 text-orange-700 px-2 py-0.5 rounded-full ml-2">⚡ ${sgCustomized} customized</span>` : ''}
                                                                </div>
                                                                <div class="space-y-2">
                                                                    ${sgItems.map(item => {
                                                                        // ========== DISPLAY THE ACTUAL ITEM NAME ==========
                                                                        const displayName = item.name || 'Unnamed Item';
                                                                        const isCustomized = item.isCustomized;
                                                                        const isFullyPaid = item.isFullyPaid;
                                                                        const isOverDelivered = item.isOverDelivered;
                                                                        
                                                                        // Determine status
                                                                        let statusText = '';
                                                                        let statusClass = '';
                                                                        if (isFullyPaid && !isOverDelivered) {
                                                                            statusText = '✅ Fully Paid';
                                                                            statusClass = 'bg-green-100 text-green-800';
                                                                        } else if (isOverDelivered) {
                                                                            statusText = '💰 Credit';
                                                                            statusClass = 'bg-blue-100 text-blue-800';
                                                                        } else if (item.amount > 0 || item.itemsBrought > 0) {
                                                                            statusText = '⚠️ Partial';
                                                                            statusClass = 'bg-yellow-100 text-yellow-800';
                                                                        } else {
                                                                            statusText = '❌ Unpaid';
                                                                            statusClass = 'bg-red-100 text-red-600';
                                                                        }
                                                                        
                                                                        const customBadge = isCustomized ? 
                                                                            `<span class="ml-2 text-xs bg-orange-100 text-orange-700 px-1.5 py-0.5 rounded-full">⚡ Custom</span>` : '';
                                                                        
                                                                        let customComparison = '';
                                                                        if (isCustomized) {
                                                                            const amountChanged = item.customAmount !== null && item.customAmount !== item.defaultAmount;
                                                                            const qtyChanged = item.customQuantity !== null && item.customQuantity !== item.defaultQuantity;
                                                                            const changes = [];
                                                                            if (amountChanged) changes.push(`UGX ${formatMoney(item.defaultAmount)} → UGX ${formatMoney(item.customAmount)}`);
                                                                            if (qtyChanged) changes.push(`Qty: ${item.defaultQuantity} → ${item.customQuantity}`);
                                                                            if (changes.length > 0) {
                                                                                customComparison = `
                                                                                    <div class="text-xs text-orange-600 bg-orange-50 p-1 rounded border border-orange-200 mt-1">
                                                                                        <i class="fas fa-edit"></i> Customized: ${changes.join(' | ')}
                                                                                        ${item.customReason ? `<br>📝 ${escapeHtml(item.customReason)}` : ''}
                                                                                    </div>
                                                                                `;
                                                                            }
                                                                        }
                                                                        
                                                                        let paymentDetail = '';
                                                                        let bgColor = isCustomized ? 'bg-orange-50' : 'bg-white';
                                                                        
                                                                        if (item.paymentType === 'paid_cash') {
                                                                            const remaining = Math.max(0, item.expectedAmount - item.amount);
                                                                            paymentDetail = `
                                                                                <div class="mt-2">
                                                                                    <div class="flex justify-between text-xs mb-1">
                                                                                        <span>💵 Paid Cash:</span>
                                                                                        <span class="font-semibold text-green-600">UGX ${formatMoney(item.amount)}</span>
                                                                                    </div>
                                                                                    <div class="flex justify-between text-xs">
                                                                                        <span>Expected Total:</span>
                                                                                        <span class="font-semibold">UGX ${formatMoney(item.expectedAmount)}</span>
                                                                                    </div>
                                                                                    ${remaining > 0 ? `
                                                                                        <div class="flex justify-between text-xs text-red-600 mt-1">
                                                                                            <span>⚠️ Remaining:</span>
                                                                                            <span class="font-semibold">UGX ${formatMoney(remaining)}</span>
                                                                                        </div>
                                                                                    ` : `
                                                                                        <div class="flex justify-between text-xs text-green-600 mt-1">
                                                                                            <span>✓ Fully Paid</span>
                                                                                            <span class="font-semibold">UGX 0 remaining</span>
                                                                                        </div>
                                                                                    `}
                                                                                    ${isCustomized ? `
                                                                                        <div class="text-xs text-gray-400 mt-1">
                                                                                            Default: UGX ${formatMoney(item.defaultAmount)}
                                                                                        </div>
                                                                                    ` : ''}
                                                                                    <div class="w-full bg-gray-200 rounded-full h-1.5 mt-2">
                                                                                        <div class="bg-green-500 rounded-full h-1.5" style="width: ${Math.min(100, (item.amount / item.expectedAmount) * 100)}%"></div>
                                                                                    </div>
                                                                                </div>
                                                                            `;
                                                                        } else if (item.paymentType === 'brought_item') {
                                                                            const isComplete = item.itemsBrought >= item.quantityRequired;
                                                                            const isOverDelivered = item.itemsBrought > item.quantityRequired;
                                                                            const percentComplete = item.quantityRequired > 0 ? (item.itemsBrought / item.quantityRequired) * 100 : 0;
                                                                            
                                                                            paymentDetail = `
                                                                                <div class="mt-2">
                                                                                    <div class="flex justify-between text-xs mb-1">
                                                                                        <span>📦 Items Required:</span>
                                                                                        <span class="font-semibold">${item.quantityRequired} item(s)</span>
                                                                                    </div>
                                                                                    <div class="flex justify-between text-xs mb-1">
                                                                                        <span>📦 Items Delivered:</span>
                                                                                        <span class="font-semibold ${isComplete ? 'text-green-600' : 'text-orange-600'}">
                                                                                            ${item.itemsBrought} of ${item.quantityRequired} required
                                                                                            ${isOverDelivered ? ` (${item.itemsBrought - item.quantityRequired} extra)` : ''}
                                                                                        </span>
                                                                                    </div>
                                                                                    ${isCustomized ? `
                                                                                        <div class="text-xs text-gray-400 mt-1">
                                                                                            Default Qty: ${item.defaultQuantity}
                                                                                        </div>
                                                                                    ` : ''}
                                                                                    <div class="w-full bg-gray-200 rounded-full h-2">
                                                                                        <div class="bg-green-500 rounded-full h-2 transition-all" style="width: ${Math.min(100, percentComplete)}%"></div>
                                                                                    </div>
                                                                                </div>
                                                                            `;
                                                                        }
                                                                        
                                                                        return `
                                                                            <div class="${bgColor} rounded-lg p-3 border shadow-sm hover:shadow-md transition ${isCustomized ? 'border-l-4 border-l-orange-400' : ''}">
                                                                                <div class="flex justify-between items-start">
                                                                                    <div class="flex-1">
                                                                                        <div class="flex items-center gap-2 flex-wrap">
                                                                                            <p class="font-semibold text-gray-800">📦 ${escapeHtml(displayName)}</p>
                                                                                            <span class="text-xs text-gray-400 bg-gray-100 px-2 py-0.5 rounded-full">${escapeHtml(item.component)}</span>
                                                                                            ${customBadge}
                                                                                            ${isOverDelivered ? '<span class="text-xs bg-blue-100 text-blue-700 px-2 py-0.5 rounded-full">💰 Credit</span>' : ''}
                                                                                            <span class="px-2 py-0.5 rounded-full text-xs ${statusClass}">${statusText}</span>
                                                                                        </div>
                                                                                        ${paymentDetail}
                                                                                        ${customComparison}
                                                                                    </div>
                                                                                    <div class="text-right ml-4">
                                                                                        <p class="text-base font-bold ${item.paymentType === 'brought_item' && item.itemsBrought >= item.quantityRequired ? 'text-blue-600' : 'text-green-600'}">
                                                                                            ${item.paymentType === 'brought_item' ? `${item.itemsBrought}/${item.quantityRequired} item(s)` : `UGX ${formatMoney(item.amount)}`}
                                                                                        </p>
                                                                                        <p class="text-xs text-gray-400">${isCustomized ? '⚡ Custom value' : 'Default value'}</p>
                                                                                    </div>
                                                                                </div>
                                                                            </div>
                                                                        `;
                                                                    }).join('')}
                                                                </div>
                                                            </div>
                                                        </div>
                                                    </div>
                                                `;
                                            }).join('')}
                                        </div>
                                        
                                        ${payment.reference ? `
                                            <div class="mt-4 p-3 bg-gray-50 rounded-lg border">
                                                <p class="text-sm text-gray-600"><i class="fas fa-hashtag text-gray-400 mr-2"></i> Reference: <span class="font-mono">${payment.reference}</span></p>
                                            </div>
                                        ` : ''}
                                        ${payment.notes ? `
                                            <div class="mt-2 p-3 bg-yellow-50 rounded-lg border border-yellow-200">
                                                <p class="text-sm text-yellow-700"><i class="fas fa-pencil-alt mr-2"></i> Notes: ${payment.notes}</p>
                                            </div>
                                        ` : ''}
                                    </div>
                                </div>
                            </div>
                        </td>
                    </tr>
                `;
            }
        }
        
        tableHtml += `
                    </tbody>
                </table>
            </div>
        `;
        
        container.innerHTML = tableHtml;
        
        // ========== ATTACH CLICK HANDLERS FOR ARROW TOGGLING ==========
        document.querySelectorAll('.payment-main-row').forEach(row => {
            const detailId = row.getAttribute('data-detail-id');
            if (detailId) {
                row.addEventListener('click', function(e) {
                    if (e.target.closest('button')) return;
                    
                    const detailRow = document.getElementById(detailId);
                    const expandIcon = this.querySelector('.expand-icon');
                    
                    if (detailRow) {
                        if (detailRow.classList.contains('hidden')) {
                            detailRow.classList.remove('hidden');
                            if (expandIcon) {
                                expandIcon.classList.remove('fa-chevron-down');
                                expandIcon.classList.add('fa-chevron-up');
                            }
                        } else {
                            detailRow.classList.add('hidden');
                            if (expandIcon) {
                                expandIcon.classList.remove('fa-chevron-up');
                                expandIcon.classList.add('fa-chevron-down');
                            }
                        }
                    }
                });
            }
        });
        
        // ========== INITIALIZE FILTERS ==========
        initializePaymentHistoryFilters();
        
        const filteredCountSpan = document.getElementById('paymentFilteredCount');
        if (filteredCountSpan) filteredCountSpan.innerText = sortedPayments.length;
        
        console.log(`✅ Payment history loaded: ${sortedPayments.length} payments`);
        
    } catch (error) {
        console.error('Error loading payment history:', error);
        const container = document.getElementById('paymentHistoryTableContainer');
        if (container) {
            container.innerHTML = `
                <div class="text-center p-8 bg-red-50 rounded-lg border border-red-200">
                    <i class="fas fa-exclamation-triangle text-red-600 text-4xl mb-3"></i>
                    <p class="text-red-600">Error loading payment history: ${error.message}</p>
                    <button onclick="loadPaymentHistoryIntoTable()" class="mt-3 bg-red-600 text-white px-4 py-2 rounded">Retry</button>
                </div>
            `;
        }
    }
}

// ========== TOGGLE STATUS GROUP ==========
function toggleStatusGroup(collapseId) {
    const detailsDiv = document.getElementById(collapseId);
    const icon = document.getElementById(`icon_${collapseId}`);
    
    if (detailsDiv) {
        if (detailsDiv.classList.contains('hidden')) {
            detailsDiv.classList.remove('hidden');
            if (icon) {
                icon.style.transform = 'rotate(90deg)';
            }
        } else {
            detailsDiv.classList.add('hidden');
            if (icon) {
                icon.style.transform = 'rotate(0deg)';
            }
        }
    }
}

// ========== INITIALIZE PAYMENT HISTORY FILTERS ==========
function initializePaymentHistoryFilters() {
    const searchInput = document.getElementById('paymentSearchInput');
    const methodFilter = document.getElementById('paymentMethodFilter');
    
    if (!searchInput && !methodFilter) return;
    
    function filterPayments() {
        const searchTerm = (searchInput?.value || '').toLowerCase().trim();
        const methodValue = methodFilter?.value || '';
        
        const rows = document.querySelectorAll('#paymentHistoryTable .payment-main-row');
        let visibleCount = 0;
        
        rows.forEach(row => {
            const receipt = row.querySelector('td:nth-child(3)')?.innerText || '';
            const student = row.querySelector('td:nth-child(4)')?.innerText.toLowerCase() || '';
            const methodCell = row.querySelector('td:nth-last-child(2) span')?.innerText.toLowerCase() || '';
            
            let matchesSearch = true;
            if (searchTerm) {
                matchesSearch = receipt.toLowerCase().includes(searchTerm) || 
                               student.includes(searchTerm);
            }
            
            let matchesMethod = true;
            if (methodValue) {
                matchesMethod = methodCell.includes(methodValue);
            }
            
            const isVisible = matchesSearch && matchesMethod;
            row.style.display = isVisible ? '' : 'none';
            if (isVisible) visibleCount++;
            
            const detailId = row.getAttribute('data-detail-id');
            if (detailId) {
                const detailRow = document.getElementById(detailId);
                if (detailRow) detailRow.style.display = isVisible ? '' : 'none';
            }
        });
        
        const filteredCountSpan = document.getElementById('paymentFilteredCount');
        if (filteredCountSpan) filteredCountSpan.innerText = visibleCount;
    }
    
    if (searchInput) {
        searchInput.addEventListener('input', filterPayments);
        searchInput.addEventListener('keyup', filterPayments);
    }
    if (methodFilter) methodFilter.addEventListener('change', filterPayments);
    
    setTimeout(filterPayments, 100);
}

// ========== SETUP HISTORY TAB LISTENER ==========
function setupPaymentHistoryTab() {
    const historyTab = document.querySelector('.fee-tab[data-tab="history"]');
    if (historyTab) {
        historyTab.removeEventListener('click', paymentHistoryTabClickHandler);
        historyTab.addEventListener('click', paymentHistoryTabClickHandler);
    }
}

function paymentHistoryTabClickHandler() {
    console.log('History tab clicked - loading payments...');
    setTimeout(() => {
        loadPaymentHistoryIntoTable();
    }, 100);
}

