// ==================== COMPLETELY REBUILT PRINT PAYMENT RECEIPT ====================
// Version: 10.0 - Properly reads from fee structure, handles over-delivery, and shows accurate amounts

// ==================== COMPLETE REBUILT PRINT PAYMENT RECEIPT ====================
// Version: FINAL - Clean parent-friendly receipt with custom values support

// ==================== COMPLETE FIXED PRINT PAYMENT RECEIPT ====================
// ==================== COMPLETE REBUILT PRINT PAYMENT RECEIPT ====================
// Version: 11.0 - Follows Period Protocols (one_time, yearly, termly)
// - one_time: paid status checked across ALL years/terms FOREVER
// - yearly: paid status checked across ALL terms within the current academic year
// - termly: paid status checked only for the current term

// ==================== COMPLETE FIXED PRINT PAYMENT RECEIPT ====================
// Version: 12.0 - Fixed "bursary is not defined" error

// ==================== COMPLETE REBUILT PRINT PAYMENT RECEIPT ====================
// Version: 15.0 - Shows ALL item names with proper breakdown

// ==================== COMPLETE REBUILT PRINT PAYMENT RECEIPT ====================
// Version: 15.0 - Properly displays item names, period types, and outstanding items

async function printPaymentReceipt(receiptNumber) {
    console.log('printPaymentReceipt called for receipt:', receiptNumber);
    
    if (!receiptNumber || receiptNumber === 'undefined' || receiptNumber === 'null') {
        alert('Invalid receipt number. Cannot print receipt.');
        return;
    }
    
    try {
        // ========== FETCH ALL REQUIRED DATA ==========
        const [paymentsRes, studentsRes, feeStructuresRes, feeAssignmentsRes, feeBursariesRes] = await Promise.all([
            fetch('/api/fee/payments'),
            fetch('/api/students'),
            fetch('/api/fee/structures'),
            fetch('/api/student-fee-assignments'),
            fetch('/api/fee/bursaries')
        ]);
        
        const allPayments = await paymentsRes.json();
        let students = await studentsRes.json();
        students = Array.isArray(students) ? students : [];
        
        let feeStructures = await feeStructuresRes.json();
        feeStructures = Array.isArray(feeStructures) ? feeStructures : [];
        
        let feeAssignments = await feeAssignmentsRes.json();
        feeAssignments = Array.isArray(feeAssignments) ? feeAssignments : [];
        
        let feeBursaries = await feeBursariesRes.json();
        feeBursaries = Array.isArray(feeBursaries) ? feeBursaries : [];
        
        // ========== FIND PAYMENT ==========
        let payment = allPayments.find(p => p.receiptNumber === receiptNumber);
        if (!payment) payment = allPayments.find(p => p.receiptNumber?.toLowerCase() === receiptNumber.toLowerCase());
        if (!payment) payment = allPayments.find(p => p.receiptNumber?.includes(receiptNumber) || receiptNumber.includes(p.receiptNumber));
        
        if (!payment) {
            alert(`Payment record not found for receipt: ${receiptNumber}`);
            return;
        }
        
        // ========== GET STUDENT DATA ==========
        const student = students.find(s => s.id === payment.studentId);
        const assignment = feeAssignments.find(a => a.studentId === payment.studentId) || {};
        let feeStructure = feeStructures.find(f => f.id === assignment.feeStructureId);
        
        const { currentYear, currentTerm } = currentAcademicSettings || { currentYear: new Date().getFullYear(), currentTerm: 1 };
        const isFirstTerm = currentTerm === 1;
        const termNames = { 1: 'First Term', 2: 'Second Term', 3: 'Third Term' };
        const termName = termNames[currentTerm] || `Term ${currentTerm}`;
        
        // ========== HELPER: GET CUSTOMIZED ITEM VALUE ==========
        function getCustomizedItemValue(studentData, itemId, defaultAmount, defaultQuantity, defaultPaymentOption, defaultUnitPrice) {
            if (!studentData) {
                return {
                    amount: defaultAmount || 0,
                    quantity: defaultQuantity || 1,
                    paymentOption: defaultPaymentOption || 'either',
                    unitPrice: defaultUnitPrice || (defaultAmount / (defaultQuantity || 1)),
                    isCustomized: false,
                    reason: null,
                    updatedAt: null
                };
            }
            
            if (studentData.customItemOverrides && studentData.customItemOverrides[itemId]) {
                const custom = studentData.customItemOverrides[itemId];
                if (custom.isActive !== false) {
                    const customAmount = (custom.customAmount !== null && custom.customAmount !== undefined) 
                        ? custom.customAmount 
                        : defaultAmount;
                    const customQuantity = (custom.customQuantity !== null && custom.customQuantity !== undefined) 
                        ? custom.customQuantity 
                        : defaultQuantity;
                    const customPaymentOption = custom.paymentOption || defaultPaymentOption;
                    
                    let customUnitPrice = defaultUnitPrice;
                    if (customQuantity > 0 && customAmount > 0) {
                        customUnitPrice = customAmount / customQuantity;
                    } else if (customAmount > 0) {
                        customUnitPrice = customAmount / (customQuantity || 1);
                    } else if (customQuantity > 0) {
                        customUnitPrice = defaultUnitPrice || (defaultAmount / (defaultQuantity || 1));
                    }
                    
                    return {
                        amount: customAmount,
                        quantity: customQuantity,
                        paymentOption: customPaymentOption,
                        unitPrice: customUnitPrice,
                        isCustomized: true,
                        reason: custom.reason || null,
                        updatedAt: custom.updatedAt || null
                    };
                }
            }
            
            return {
                amount: defaultAmount || 0,
                quantity: defaultQuantity || 1,
                paymentOption: defaultPaymentOption || 'either',
                unitPrice: defaultUnitPrice || (defaultAmount / (defaultQuantity || 1)),
                isCustomized: false,
                reason: null,
                updatedAt: null
            };
        }

        // ========== HELPER: FIND ITEM IN FEE STRUCTURE ==========
        function findItemInFeeStructure(fs, componentName, itemName, periodType) {
            if (!fs || !fs.activityComponents) return null;
            
            for (const comp of fs.activityComponents) {
                const compMatch = comp.name && comp.name.toLowerCase() === componentName.toLowerCase();
                const periodMatch = periodType ? comp.periodType === periodType : true;
                
                if (compMatch && periodMatch) {
                    for (const item of (comp.items || [])) {
                        if (item.name && item.name.toLowerCase() === itemName.toLowerCase()) {
                            return {
                                ...item,
                                componentName: comp.name,
                                periodType: comp.periodType,
                                statusGroupName: comp.statusGroupName || comp.name
                            };
                        }
                    }
                }
            }
            return null;
        }

        // ========== GET EXPECTED AMOUNT WITH CUSTOM VALUES AND PERIOD SCOPE ==========
        function getExpectedAmountWithCustomAndScope(studentData, fs, componentName, itemName, periodType) {
            const feeItem = findItemInFeeStructure(fs, componentName, itemName, periodType);
            
            if (!feeItem) {
                return { totalAmount: 0, quantityRequired: 1, unitPrice: 0, paymentOption: 'either', isCustomized: false };
            }
            
            const defaultAmount = feeItem.totalAmount || 0;
            const defaultQuantity = feeItem.quantity || 1;
            const defaultUnitPrice = feeItem.unitPrice || (defaultAmount / defaultQuantity);
            const defaultPaymentOption = feeItem.paymentOption || 'either';
            const itemId = feeItem.id || itemName;
            
            const custom = getCustomizedItemValue(
                studentData,
                itemId,
                defaultAmount,
                defaultQuantity,
                defaultPaymentOption,
                defaultUnitPrice
            );
            
            const isTransportation = componentName.toLowerCase().includes('transport') || 
                                    itemName.toLowerCase().includes('van') ||
                                    itemName.toLowerCase().includes('transport');
            
            let finalAmount = custom.amount;
            let finalQuantity = custom.quantity;
            let finalUnitPrice = custom.unitPrice;
            let finalPaymentOption = custom.paymentOption;
            
            if (isTransportation && studentData && studentData.customTransportation) {
                if (studentData.customTransportation.hasTransportation === false) {
                    return { totalAmount: 0, quantityRequired: 0, unitPrice: 0, paymentOption: 'cash_only', isCustomized: true };
                }
                if (studentData.customTransportation.amount) {
                    finalAmount = studentData.customTransportation.amount;
                    finalUnitPrice = finalAmount / (finalQuantity || 1);
                }
            }
            
            return {
                totalAmount: finalAmount,
                quantityRequired: finalQuantity,
                unitPrice: finalUnitPrice,
                paymentOption: finalPaymentOption,
                isCustomized: custom.isCustomized,
                reason: custom.reason,
                customAmount: custom.customAmount,
                customQuantity: custom.customQuantity,
                defaultAmount: defaultAmount,
                defaultQuantity: defaultQuantity
            };
        }

        // ========== GET ALL UNPAID ITEMS WITH PERIOD SCOPE ==========
        function getAllUnpaidItems(studentData, fs, allPaymentsData) {
            const unpaidItems = [];
            const studentPayments = allPaymentsData.filter(p => p.studentId === studentData?.id);
            
            if (!fs || !fs.activityComponents) return unpaidItems;
            
            // Build payment maps for quick lookup
            const paymentMap = {};
            
            // Process all payments for this student
            for (const payment of studentPayments) {
                // Process activityItemPayments
                if (payment.activityItemPayments) {
                    for (const item of payment.activityItemPayments) {
                        const key = `${item.componentName}_${item.itemName}_${item.periodType || 'termly'}`;
                        if (!paymentMap[key]) paymentMap[key] = { cash: 0, items: 0, payments: [] };
                        
                        if (item.paymentType === 'paid_cash') {
                            paymentMap[key].cash += item.amountPaid || 0;
                        } else if (item.paymentType === 'brought_item') {
                            paymentMap[key].items += item.itemsBrought || 0;
                        }
                        paymentMap[key].payments.push(payment);
                    }
                }
                
                // Process paymentsByPeriodType
                if (payment.paymentsByPeriodType) {
                    for (const period of ['one_time', 'termly', 'yearly']) {
                        const periodItems = payment.paymentsByPeriodType[period] || [];
                        for (const item of periodItems) {
                            const key = `${item.componentName}_${item.itemName}_${period}`;
                            if (!paymentMap[key]) paymentMap[key] = { cash: 0, items: 0, payments: [] };
                            
                            if (item.paymentType === 'paid_cash') {
                                paymentMap[key].cash += item.amountPaid || 0;
                            } else if (item.paymentType === 'brought_item') {
                                paymentMap[key].items += item.itemsBrought || 0;
                            }
                            paymentMap[key].payments.push(payment);
                        }
                    }
                }
            }
            
            // For each component in the fee structure
            for (const component of fs.activityComponents) {
                const periodType = component.periodType || 'termly';
                
                // Determine if this period should be included
                let shouldInclude = false;
                let scopeDescription = '';
                
                if (periodType === 'termly') {
                    shouldInclude = true;
                    scopeDescription = 'Termly (per term)';
                } else if (periodType === 'one_time') {
                    shouldInclude = true;
                    scopeDescription = 'One-Time (forever)';
                } else if (periodType === 'yearly') {
                    shouldInclude = true;
                    scopeDescription = 'Yearly (per year)';
                }
                
                if (!shouldInclude) continue;
                
                const isTransportation = component.name.toLowerCase().includes('transport') || 
                                        (component.statusGroupName && component.statusGroupName.toLowerCase().includes('transport'));
                
                // Check if transportation is disabled for this student
                if (isTransportation && studentData && studentData.customTransportation) {
                    if (studentData.customTransportation.hasTransportation === false) {
                        continue;
                    }
                }
                
                for (const item of (component.items || [])) {
                    const itemName = item.name;
                    const quantityRequired = item.quantity || 1;
                    const totalAmount = item.totalAmount || 0;
                    const unitPrice = item.unitPrice || (totalAmount / quantityRequired);
                    const paymentOption = item.paymentOption || 'either';
                    
                    // Get expected amount with custom values
                    const expected = getExpectedAmountWithCustomAndScope(
                        studentData,
                        fs,
                        component.name,
                        itemName,
                        periodType
                    );
                    
                    const effectiveQuantity = expected.quantityRequired || quantityRequired;
                    const effectiveAmount = expected.totalAmount || totalAmount;
                    const effectiveUnitPrice = expected.unitPrice || unitPrice;
                    const effectivePaymentOption = expected.paymentOption || paymentOption;
                    
                    // Scope payments based on period type
                    let scopeCash = 0;
                    let scopeItems = 0;
                    
                    if (periodType === 'one_time') {
                        const key = `${component.name}_${itemName}_${periodType}`;
                        const paidData = paymentMap[key] || { cash: 0, items: 0 };
                        scopeCash = paidData.cash;
                        scopeItems = paidData.items;
                    } else if (periodType === 'yearly') {
                        const yearlyPayments = studentPayments.filter(p => 
                            p.academicYear === currentYear.toString()
                        );
                        let cash = 0, items = 0;
                        for (const p of yearlyPayments) {
                            if (p.activityItemPayments) {
                                for (const paidItem of p.activityItemPayments) {
                                    if (paidItem.componentName === component.name && 
                                        paidItem.itemName === itemName &&
                                        paidItem.periodType === periodType) {
                                        if (paidItem.paymentType === 'paid_cash') cash += paidItem.amountPaid || 0;
                                        else if (paidItem.paymentType === 'brought_item') items += paidItem.itemsBrought || 0;
                                    }
                                }
                            }
                            if (p.paymentsByPeriodType) {
                                const periodItems = p.paymentsByPeriodType[periodType] || [];
                                for (const paidItem of periodItems) {
                                    if (paidItem.componentName === component.name && 
                                        paidItem.itemName === itemName) {
                                        if (paidItem.paymentType === 'paid_cash') cash += paidItem.amountPaid || 0;
                                        else if (paidItem.paymentType === 'brought_item') items += paidItem.itemsBrought || 0;
                                    }
                                }
                            }
                        }
                        scopeCash = cash;
                        scopeItems = items;
                    } else {
                        const termPayments = studentPayments.filter(p => 
                            p.term === currentTerm && 
                            p.academicYear === currentYear.toString()
                        );
                        let cash = 0, items = 0;
                        for (const p of termPayments) {
                            if (p.activityItemPayments) {
                                for (const paidItem of p.activityItemPayments) {
                                    if (paidItem.componentName === component.name && 
                                        paidItem.itemName === itemName &&
                                        paidItem.periodType === periodType) {
                                        if (paidItem.paymentType === 'paid_cash') cash += paidItem.amountPaid || 0;
                                        else if (paidItem.paymentType === 'brought_item') items += paidItem.itemsBrought || 0;
                                    }
                                }
                            }
                            if (p.paymentsByPeriodType) {
                                const periodItems = p.paymentsByPeriodType[periodType] || [];
                                for (const paidItem of periodItems) {
                                    if (paidItem.componentName === component.name && 
                                        paidItem.itemName === itemName) {
                                        if (paidItem.paymentType === 'paid_cash') cash += paidItem.amountPaid || 0;
                                        else if (paidItem.paymentType === 'brought_item') items += paidItem.itemsBrought || 0;
                                    }
                                }
                            }
                        }
                        scopeCash = cash;
                        scopeItems = items;
                    }
                    
                    // Calculate remaining
                    let remainingAmount = 0;
                    let remainingQuantity = 0;
                    let isFullyPaid = false;
                    let isOverDelivered = false;
                    
                    if (effectivePaymentOption === 'cash_only') {
                        remainingAmount = Math.max(0, effectiveAmount - scopeCash);
                        isFullyPaid = remainingAmount <= 0;
                    } else if (effectivePaymentOption === 'item_only') {
                        remainingQuantity = Math.max(0, effectiveQuantity - scopeItems);
                        isFullyPaid = remainingQuantity <= 0;
                        isOverDelivered = scopeItems > effectiveQuantity;
                    } else {
                        const totalPaidValue = scopeCash + (scopeItems * effectiveUnitPrice);
                        const totalRequired = effectiveQuantity * effectiveUnitPrice;
                        isFullyPaid = totalPaidValue >= totalRequired;
                        isOverDelivered = scopeItems > effectiveQuantity && scopeCash === 0;
                        if (!isFullyPaid) {
                            remainingAmount = Math.max(0, totalRequired - totalPaidValue);
                            remainingQuantity = Math.ceil(remainingAmount / effectiveUnitPrice);
                        }
                    }
                    
                    // If not fully paid, add to unpaid items
                    if (!isFullyPaid || isOverDelivered) {
                        let displayText = '';
                        let displayType = '';
                        
                        if (effectivePaymentOption === 'cash_only') {
                            displayText = `💵 UGX ${Math.round(remainingAmount).toLocaleString()}`;
                            displayType = 'cash';
                        } else if (effectivePaymentOption === 'item_only') {
                            displayText = `📦 ${remainingQuantity} item(s)`;
                            displayType = 'items';
                        } else {
                            const parts = [];
                            if (remainingAmount > 0) parts.push(`💵 UGX ${Math.round(remainingAmount).toLocaleString()}`);
                            if (remainingQuantity > 0) parts.push(`📦 ${remainingQuantity} item(s)`);
                            displayText = parts.join(' OR ');
                            displayType = 'mixed';
                        }
                        
                        // For over-delivered items, show credit
                        if (isOverDelivered) {
                            displayText = `💰 Credit (${scopeItems - effectiveQuantity} extra items)`;
                            displayType = 'credit';
                        }
                        
                        const isSpecialItem = isTransportation || 
                                             component.name.toLowerCase().includes('uniform') ||
                                             itemName.toLowerCase().includes('uniform');
                        
                        // For special items, show as cash only
                        if (isSpecialItem && !isOverDelivered) {
                            displayText = `💵 UGX ${Math.round(remainingAmount).toLocaleString()}`;
                            displayType = 'special';
                        }
                        
                        const statusGroupName = component.statusGroupName || component.name || 'Other';
                        
                        // Get period icon
                        let periodIcon = '';
                        if (periodType === 'one_time') periodIcon = '⭐ ';
                        else if (periodType === 'yearly') periodIcon = '📆 ';
                        else periodIcon = '📅 ';
                        
                        // Check if item is customized
                        const isItemCustomized = expected.isCustomized;
                        const customReason = expected.reason;
                        const customBadge = isItemCustomized ? ' ⚡' : '';
                        
                        unpaidItems.push({
                            name: itemName,
                            componentName: component.name,
                            statusGroupName: statusGroupName,
                            periodType: periodType,
                            periodIcon: periodIcon,
                            paymentOption: effectivePaymentOption,
                            remainingAmount: remainingAmount,
                            remainingQuantity: remainingQuantity,
                            displayText: displayText,
                            displayType: displayType,
                            isFullyPaid: isFullyPaid,
                            isOverDelivered: isOverDelivered,
                            isSpecialItem: isSpecialItem,
                            isTransportation: isTransportation,
                            quantityRequired: effectiveQuantity,
                            totalAmount: effectiveAmount,
                            unitPrice: effectiveUnitPrice,
                            scopeDescription: scopeDescription,
                            isCustomized: isItemCustomized,
                            customReason: customReason,
                            customBadge: customBadge,
                            defaultAmount: expected.defaultAmount,
                            defaultQuantity: expected.defaultQuantity
                        });
                    }
                }
            }
            
            return unpaidItems;
        }

        // ========== GET ALL UNPAID ITEMS ==========
        const unpaidItems = getAllUnpaidItems(student, feeStructure, allPayments);
        
        // ========== GROUP UNPAID ITEMS BY STATUS GROUP ==========
        const unpaidByGroup = {};
        let totalCashOutstanding = 0;
        let totalItemsOutstanding = 0;
        
        for (const item of unpaidItems) {
            // Get display name for status group
            let groupName = item.statusGroupName || 'Other';
            if (groupName === 'schoolastic requirement') groupName = 'Scholastic Requirements';
            if (groupName === 'Admission Fee') groupName = 'Admission';
            if (groupName === 'Transportation Fee') groupName = 'Transportation';
            
            if (!unpaidByGroup[groupName]) {
                unpaidByGroup[groupName] = {
                    name: groupName,
                    items: [],
                    totalCash: 0,
                    totalItems: 0,
                    hasCashOnly: false,
                    hasItemOnly: false,
                    hasMixed: false,
                    isTransportation: false,
                    periodType: item.periodType,
                    periodIcon: item.periodIcon || ''
                };
            }
            
            unpaidByGroup[groupName].items.push(item);
            
            if (item.paymentOption === 'cash_only' || item.isSpecialItem) {
                unpaidByGroup[groupName].totalCash += item.remainingAmount;
                unpaidByGroup[groupName].hasCashOnly = true;
                totalCashOutstanding += item.remainingAmount;
            } else if (item.paymentOption === 'item_only') {
                unpaidByGroup[groupName].totalItems += item.remainingQuantity;
                unpaidByGroup[groupName].hasItemOnly = true;
                totalItemsOutstanding += item.remainingQuantity;
            } else {
                // Mixed - add both
                unpaidByGroup[groupName].totalCash += item.remainingAmount;
                unpaidByGroup[groupName].totalItems += item.remainingQuantity;
                unpaidByGroup[groupName].hasMixed = true;
                totalCashOutstanding += item.remainingAmount;
                totalItemsOutstanding += item.remainingQuantity;
            }
            
            if (item.isTransportation) {
                unpaidByGroup[groupName].isTransportation = true;
            }
        }

        // ========== GET TUITION BALANCE ==========
        function getTuitionBalance(studentData, fs, allPaymentsData, assignmentData, bursariesData) {
            if (!fs) return { expected: 0, paid: 0, balance: 0, isFullyPaid: true, discountAmount: 0, bursaryName: null };
            
            let tuition = fs.tuition || 0;
            let discountAmount = 0;
            let bursaryName = null;
            
            if (studentData && studentData.customBursary && studentData.customBursary.amount > 0) {
                discountAmount = studentData.customBursary.amount;
                tuition = Math.max(0, tuition - discountAmount);
                bursaryName = 'Custom Bursary';
            } else if (assignmentData.bursaryId && bursariesData) {
                const bursary = bursariesData.find(b => b.id === assignmentData.bursaryId);
                if (bursary) {
                    bursaryName = bursary.name;
                    if (bursary.type === 'percentage') {
                        discountAmount = (tuition * bursary.value) / 100;
                        tuition = Math.max(0, tuition - discountAmount);
                    } else {
                        discountAmount = bursary.value;
                        tuition = Math.max(0, tuition - discountAmount);
                    }
                }
            }
            
            const termPayments = allPaymentsData.filter(p => 
                p.studentId === studentData?.id && 
                p.term === currentTerm && 
                p.academicYear === currentYear.toString()
            );
            const tuitionPaid = termPayments.reduce((sum, p) => sum + (p.tuitionPaid || 0), 0);
            
            const balance = tuition - tuitionPaid;
            
            return {
                expected: tuition,
                paid: tuitionPaid,
                balance: balance,
                isFullyPaid: balance <= 0,
                discountAmount: discountAmount,
                bursaryName: bursaryName
            };
        }

        const tuitionBalance = getTuitionBalance(student, feeStructure, allPayments, assignment, feeBursaries);
        
        // Calculate total outstanding
        const totalOutstanding = Math.max(0, tuitionBalance.balance) + totalCashOutstanding;

        // ========== GET PAID ITEMS FOR THIS PAYMENT ==========
        function getPaidItemsForPayment(payment, fs, studentData) {
            const items = [];
            const processedKeys = new Set();
            
            // Process activityItemPayments
            if (payment.activityItemPayments) {
                for (const item of payment.activityItemPayments) {
                    const key = `${item.componentName}_${item.itemName}_${item.periodType}`;
                    if (processedKeys.has(key)) continue;
                    processedKeys.add(key);
                    
                    const periodType = item.periodType || 'termly';
                    const paidAmount = item.paymentType === 'paid_cash' ? (item.amountPaid || 0) : (item.cashEquivalent || 0);
                    const itemsBrought = item.paymentType === 'brought_item' ? (item.itemsBrought || 0) : 0;
                    
                    // Get expected amount with custom values
                    const expected = getExpectedAmountWithCustomAndScope(
                        studentData,
                        fs,
                        item.componentName,
                        item.itemName,
                        periodType
                    );
                    
                    const totalAmount = expected.totalAmount || item.totalAmount || 0;
                    const unitPrice = expected.unitPrice || item.unitPrice || 1;
                    const quantityRequired = expected.quantityRequired || item.quantityRequired || 1;
                    
                    let remainingAmount = Math.max(0, totalAmount - paidAmount);
                    let remainingQuantity = Math.max(0, quantityRequired - itemsBrought);
                    let isFullyPaid = remainingAmount <= 0 && remainingQuantity <= 0;
                    let isOverDelivered = itemsBrought > quantityRequired;
                    
                    if (isOverDelivered) {
                        remainingQuantity = 0;
                        remainingAmount = 0;
                        isFullyPaid = true;
                    }
                    
                    // Get period icon
                    let periodIcon = '';
                    let periodDisplay = '';
                    if (periodType === 'one_time') { periodIcon = '⭐'; periodDisplay = 'One-Time'; }
                    else if (periodType === 'yearly') { periodIcon = '📆'; periodDisplay = 'Yearly'; }
                    else { periodIcon = '📅'; periodDisplay = 'Termly'; }
                    
                    const statusGroupName = item.componentName || 'Other';
                    
                    items.push({
                        name: item.itemName,
                        componentName: item.componentName,
                        statusGroupName: statusGroupName,
                        periodType: periodType,
                        periodIcon: periodIcon,
                        periodDisplay: periodDisplay,
                        paymentOption: expected.paymentOption || item.paymentOption || 'either',
                        totalAmount: totalAmount,
                        paidAmount: paidAmount,
                        itemsBrought: itemsBrought,
                        quantityRequired: quantityRequired,
                        unitPrice: unitPrice,
                        remainingAmount: remainingAmount,
                        remainingQuantity: remainingQuantity,
                        isFullyPaid: isFullyPaid,
                        isOverDelivered: isOverDelivered,
                        isCustomized: expected.isCustomized,
                        customReason: expected.reason,
                        customBadge: expected.isCustomized ? ' ⚡' : '',
                        defaultAmount: expected.defaultAmount,
                        defaultQuantity: expected.defaultQuantity,
                        paymentType: item.paymentType
                    });
                }
            }
            
            // Process paymentsByPeriodType
            if (payment.paymentsByPeriodType) {
                for (const period of ['one_time', 'termly', 'yearly']) {
                    const periodItems = payment.paymentsByPeriodType[period] || [];
                    for (const item of periodItems) {
                        const key = `${item.componentName}_${item.itemName}_${period}`;
                        if (processedKeys.has(key)) continue;
                        processedKeys.add(key);
                        
                        const paidAmount = item.paymentType === 'paid_cash' ? (item.amountPaid || 0) : (item.cashEquivalent || 0);
                        const itemsBrought = item.paymentType === 'brought_item' ? (item.itemsBrought || 0) : 0;
                        
                        const expected = getExpectedAmountWithCustomAndScope(
                            studentData,
                            fs,
                            item.componentName,
                            item.itemName,
                            period
                        );
                        
                        const totalAmount = expected.totalAmount || item.totalAmount || 0;
                        const unitPrice = expected.unitPrice || item.unitPrice || 1;
                        const quantityRequired = expected.quantityRequired || item.quantityRequired || 1;
                        
                        let remainingAmount = Math.max(0, totalAmount - paidAmount);
                        let remainingQuantity = Math.max(0, quantityRequired - itemsBrought);
                        let isFullyPaid = remainingAmount <= 0 && remainingQuantity <= 0;
                        let isOverDelivered = itemsBrought > quantityRequired;
                        
                        if (isOverDelivered) {
                            remainingQuantity = 0;
                            remainingAmount = 0;
                            isFullyPaid = true;
                        }
                        
                        let periodIcon = '';
                        let periodDisplay = '';
                        if (period === 'one_time') { periodIcon = '⭐'; periodDisplay = 'One-Time'; }
                        else if (period === 'yearly') { periodIcon = '📆'; periodDisplay = 'Yearly'; }
                        else { periodIcon = '📅'; periodDisplay = 'Termly'; }
                        
                        const statusGroupName = item.componentName || 'Other';
                        
                        items.push({
                            name: item.itemName,
                            componentName: item.componentName,
                            statusGroupName: statusGroupName,
                            periodType: period,
                            periodIcon: periodIcon,
                            periodDisplay: periodDisplay,
                            paymentOption: expected.paymentOption || item.paymentOption || 'either',
                            totalAmount: totalAmount,
                            paidAmount: paidAmount,
                            itemsBrought: itemsBrought,
                            quantityRequired: quantityRequired,
                            unitPrice: unitPrice,
                            remainingAmount: remainingAmount,
                            remainingQuantity: remainingQuantity,
                            isFullyPaid: isFullyPaid,
                            isOverDelivered: isOverDelivered,
                            isCustomized: expected.isCustomized,
                            customReason: expected.reason,
                            customBadge: expected.isCustomized ? ' ⚡' : '',
                            defaultAmount: expected.defaultAmount,
                            defaultQuantity: expected.defaultQuantity,
                            paymentType: item.paymentType
                        });
                    }
                }
            }
            
            return items;
        }

        const paidItems = getPaidItemsForPayment(payment, feeStructure, student);
        
        // Calculate totals for this payment
        const tuitionPaid = payment.tuitionPaid || 0;
        const totalPaid = tuitionPaid + paidItems.reduce((sum, i) => sum + i.paidAmount, 0);
        
        const showOutstandingBalance = tuitionBalance.balance > 0 || totalCashOutstanding > 0 || totalItemsOutstanding > 0;

        // ========== GET SCHOOL INFO ==========
        let school = {};
        try {
            const schoolRes = await fetch('/api/school');
            if (schoolRes.ok) {
                const schoolData = await schoolRes.json();
                school = schoolData.school || {};
            }
        } catch (e) {}

        // ========== BUILD OUTSTANDING ITEMS HTML ==========
        function buildOutstandingItemsHtml() {
            const groupKeys = Object.keys(unpaidByGroup);
            if (groupKeys.length === 0) return '';
            
            let html = `
                <div style="margin-top: 15px; padding-top: 12px; border-top: 2px dashed #e5e7eb;">
                    <div style="font-size: 13px; font-weight: 700; color: #991b1b; margin-bottom: 10px;">
                        ⚠️ OUTSTANDING ITEMS
                    </div>
                    <div style="font-size: 11px; color: #6b7280; margin-bottom: 10px;">
                        The following items still need to be paid or delivered:
                    </div>
            `;
            
            // Sort groups by priority
            const sortedGroups = groupKeys.sort((a, b) => {
                const order = { 'Transportation': 1, 'Uniform': 2, 'Admission': 3, 'Scholastic Requirements': 4 };
                const aOrder = order[a] || 99;
                const bOrder = order[b] || 99;
                return aOrder - bOrder;
            });
            
            for (const groupName of sortedGroups) {
                const group = unpaidByGroup[groupName];
                if (group.items.length === 0) continue;
                
                const isTransport = group.isTransportation;
                const transportIcon = isTransport ? '🚌 ' : '';
                const periodIcon = group.periodIcon || '';
                
                html += `
                    <div style="background: #fef2f2; border-radius: 8px; padding: 10px 12px; margin-bottom: 8px; border-left: 4px solid #dc2626;">
                        <div style="font-weight: 600; font-size: 12px; color: #991b1b; margin-bottom: 4px;">
                            ${periodIcon}${transportIcon}${escapeHtml(groupName)}
                            <span style="font-weight: 400; color: #6b7280; font-size: 10px; margin-left: 6px;">
                                (${group.periodType || 'termly'})
                            </span>
                        </div>
                        <div style="font-size: 11px; color: #6b7280;">
                            ${group.items.map(item => {
                                let display = '';
                                if (item.isOverDelivered) {
                                    display = `💰 Credit (${item.quantityRequired} required, ${item.quantityRequired + item.remainingQuantity} delivered)`;
                                } else if (item.paymentOption === 'cash_only' || item.isSpecialItem) {
                                    display = `💵 UGX ${Math.round(item.remainingAmount).toLocaleString()}`;
                                } else if (item.paymentOption === 'item_only') {
                                    display = `📦 ${item.remainingQuantity} item(s)`;
                                } else {
                                    const parts = [];
                                    if (item.remainingAmount > 0) parts.push(`💵 UGX ${Math.round(item.remainingAmount).toLocaleString()}`);
                                    if (item.remainingQuantity > 0) parts.push(`📦 ${item.remainingQuantity} item(s)`);
                                    display = parts.join(' OR ');
                                }
                                
                                const customBadge = item.isCustomized ? ' ⚡' : '';
                                const reasonDisplay = item.isCustomized && item.customReason ? 
                                    `<span style="font-size: 9px; color: #d97706; margin-left: 4px;">(${escapeHtml(item.customReason)})</span>` : '';
                                
                                // Check if this item has a customized amount
                                const hasCustomAmount = item.isCustomized && item.customAmount !== null && item.customAmount !== item.defaultAmount;
                                const amountDisplay = hasCustomAmount ? 
                                    `<span style="font-size: 9px; color: #d97706;">(Custom: UGX ${Math.round(item.customAmount).toLocaleString()})</span>` : '';
                                
                                return `
                                    <div style="display: flex; justify-content: space-between; padding: 2px 0; border-bottom: 1px dashed #fecaca; font-size: 11px;">
                                        <span>📌 ${escapeHtml(item.name)}${customBadge} ${reasonDisplay} ${amountDisplay}</span>
                                        <span style="font-weight: 600; color: #dc2626;">${display}</span>
                                    </div>
                                `;
                            }).join('')}
                        </div>
                    </div>
                `;
            }
            
            // Calculate total outstanding items summary
            let totalOutstandingItems = 0;
            let totalOutstandingCash = 0;
            for (const group of Object.values(unpaidByGroup)) {
                totalOutstandingItems += group.totalItems;
                totalOutstandingCash += group.totalCash;
            }
            
            if (totalOutstandingItems > 0 || totalOutstandingCash > 0) {
                let summaryParts = [];
                if (totalOutstandingCash > 0) summaryParts.push(`💵 UGX ${Math.round(totalOutstandingCash).toLocaleString()}`);
                if (totalOutstandingItems > 0) summaryParts.push(`📦 ${totalOutstandingItems} item(s)`);
                html += `
                    <div style="margin-top: 8px; padding: 8px 12px; background: #fef3c7; border-radius: 6px; border: 1px solid #fcd34d; font-size: 12px; text-align: center;">
                        <span style="font-weight: 600; color: #92400e;">Total Outstanding:</span>
                        <span style="font-weight: 700; color: #dc2626;">${summaryParts.join(' + ')}</span>
                    </div>
                `;
            }
            
            html += `</div>`;
            return html;
        }

        // ========== BUILD PAID ITEMS HTML ==========
        function buildPaidItemsHtml() {
            if (paidItems.length === 0) return '';
            
            // Group paid items by status group
            const paidByGroup = {};
            for (const item of paidItems) {
                let groupName = item.statusGroupName || 'Other';
                if (groupName === 'schoolastic requirement') groupName = 'Scholastic Requirements';
                if (groupName === 'Admission Fee') groupName = 'Admission';
                if (groupName === 'Transportation Fee') groupName = 'Transportation';
                
                if (!paidByGroup[groupName]) paidByGroup[groupName] = [];
                paidByGroup[groupName].push(item);
            }
            
            let html = '';
            const groupKeys = Object.keys(paidByGroup);
            
            for (const groupName of groupKeys) {
                const items = paidByGroup[groupName];
                let displayGroupName = groupName;
                if (displayGroupName === 'schoolastic requirement') displayGroupName = 'Scholastic Requirements';
                if (displayGroupName === 'Admission Fee') displayGroupName = 'Admission';
                if (displayGroupName === 'Transportation Fee') displayGroupName = 'Transportation';
                
                const hasPaidItems = items.some(i => i.paidAmount > 0 || i.itemsBrought > 0);
                if (!hasPaidItems) continue;
                
                html += `
                    <div style="margin-top: 12px; padding-top: 10px; border-top: 1px solid #e5e7eb;">
                        <div style="font-size: 12px; font-weight: 600; color: #1f2937; margin-bottom: 8px;">
                            📦 ${escapeHtml(displayGroupName)}
                        </div>
                `;
                
                for (const item of items) {
                    if (item.paidAmount === 0 && item.itemsBrought === 0) continue;
                    
                    const isFullyPaid = item.isFullyPaid;
                    const isOverDelivered = item.isOverDelivered;
                    const customBadge = item.isCustomized ? ' ⚡' : '';
                    const periodIcon = item.periodIcon || '📅';
                    
                    // Show the actual item name
                    const displayName = item.name || 'Unnamed Item';
                    
                    // Show quantity details for brought items
                    let quantityDisplay = '';
                    if (item.paymentType === 'brought_item') {
                        quantityDisplay = `${item.itemsBrought} items`;
                        if (isOverDelivered) {
                            quantityDisplay += ` (${item.itemsBrought - item.quantityRequired} extra)`;
                        }
                    }
                    
                    // Custom amount display
                    const hasCustomAmount = item.isCustomized && item.customAmount !== null && item.customAmount !== item.defaultAmount;
                    const customAmountDisplay = hasCustomAmount ? 
                        `<span style="font-size: 9px; color: #d97706;">(Custom: UGX ${Math.round(item.customAmount).toLocaleString()})</span>` : '';
                    
                    html += `
                        <div style="background: #f8fafc; border-radius: 6px; padding: 8px 10px; margin-bottom: 6px; border-left: 3px solid ${isFullyPaid ? '#10b981' : '#f59e0b'};">
                            <div style="display: flex; justify-content: space-between; align-items: center; flex-wrap: wrap;">
                                <div>
                                    <span style="font-size: 12px; font-weight: 500;">${periodIcon} ${escapeHtml(displayName)}${customBadge}</span>
                                    ${item.isCustomized && item.customReason ? `<span style="font-size: 9px; color: #d97706; margin-left: 4px;">(Custom: ${escapeHtml(item.customReason)})</span>` : ''}
                                    ${customAmountDisplay}
                                    ${item.isOverDelivered ? '<span style="font-size: 9px; color: #2563eb; margin-left: 4px;">💰 Credit</span>' : ''}
                                </div>
                                <div style="text-align: right;">
                                    ${item.paymentType === 'brought_item' ? 
                                        `<span style="font-size: 12px; font-weight: 600; color: #2563eb;">${quantityDisplay}</span>` :
                                        `<span style="font-size: 12px; font-weight: 600; color: #059669;">UGX ${Math.round(item.paidAmount).toLocaleString()}`
                                    }
                                    ${!isFullyPaid && !isOverDelivered ? `
                                        <div style="font-size: 10px; color: #d97706;">Expected: UGX ${Math.round(item.totalAmount).toLocaleString()}</div>
                                        <div style="font-size: 10px; color: #dc2626;">⚠️ Balance Due: UGX ${Math.round(item.remainingAmount).toLocaleString()}</div>
                                    ` : isOverDelivered ? `
                                        <div style="font-size: 10px; color: #2563eb;">💰 Credit (Over-delivered)</div>
                                    ` : `
                                        <div style="font-size: 10px; color: #059669;">✓ Fully Paid</div>
                                    `}
                                </div>
                            </div>
                            <div style="display: flex; justify-content: space-between; margin-top: 4px; font-size: 10px; color: #6b7280;">
                                <span>Period: ${item.periodDisplay || item.periodType || 'termly'}</span>
                                ${item.paymentOption === 'cash_only' ? '<span>💵 Cash Only</span>' : 
                                  item.paymentOption === 'item_only' ? '<span>📦 Item Only</span>' : 
                                  '<span>🔄 Cash or Item</span>'}
                                <span>Qty: ${item.quantityRequired}</span>
                            </div>
                        </div>
                    `;
                }
                
                html += `</div>`;
            }
            
            return html;
        }

        // ========== OPEN PRINT WINDOW ==========
        const printWindow = window.open('', '_blank');
        
        function escapeHtml(text) {
            if (!text) return '';
            const div = document.createElement('div');
            div.textContent = text;
            return div.innerHTML;
        }
        
        // ========== BUILD COMPLETE RECEIPT HTML ==========
        printWindow.document.write(`
            <!DOCTYPE html>
            <html>
            <head>
                <title>Payment Receipt - ${payment.receiptNumber}</title>
                <meta charset="UTF-8">
                <style>
                    * { margin: 0; padding: 0; box-sizing: border-box; }
                    body { 
                        font-family: 'Segoe UI', 'Roboto', Arial, sans-serif; 
                        padding: 30px; 
                        background: #f0f2f5; 
                    }
                    .receipt { 
                        max-width: 700px; 
                        margin: 0 auto; 
                        background: white; 
                        border-radius: 16px; 
                        overflow: hidden; 
                        box-shadow: 0 10px 40px rgba(0,0,0,0.12); 
                    }
                    
                    /* Header */
                    .header { 
                        background: linear-gradient(135deg, #1a3a5c, #2a5298); 
                        color: white; 
                        text-align: center; 
                        padding: 30px 25px 25px; 
                    }
                    .school-name { 
                        font-size: 22px; 
                        font-weight: 700; 
                        letter-spacing: 0.5px; 
                    }
                    .school-motto { 
                        font-size: 12px; 
                        opacity: 0.8; 
                        margin-top: 4px; 
                        font-style: italic; 
                    }
                    .receipt-title { 
                        font-size: 13px; 
                        letter-spacing: 3px; 
                        margin-top: 12px; 
                        opacity: 0.9; 
                        font-weight: 600; 
                    }
                    .receipt-no { 
                        font-size: 13px; 
                        background: rgba(255,255,255,0.15); 
                        display: inline-block; 
                        padding: 5px 16px; 
                        border-radius: 20px; 
                        margin-top: 12px; 
                        font-family: 'Courier New', monospace; 
                        letter-spacing: 0.5px; 
                    }
                    
                    /* Content */
                    .content { padding: 25px 30px; }
                    
                    /* Info Rows */
                    .info-grid {
                        display: grid;
                        grid-template-columns: 1fr 1fr;
                        gap: 8px 20px;
                        margin-bottom: 18px;
                        padding-bottom: 15px;
                        border-bottom: 2px solid #eef2f6;
                    }
                    .info-item { display: flex; flex-direction: column; }
                    .info-label { font-size: 10px; color: #8a9baa; text-transform: uppercase; letter-spacing: 0.5px; }
                    .info-value { font-size: 14px; font-weight: 600; color: #1f2937; margin-top: 2px; }
                    
                    /* Sections */
                    .section { margin-top: 12px; margin-bottom: 12px; }
                    .section-title { 
                        font-size: 13px; 
                        font-weight: 700; 
                        color: #1a3a5c; 
                        border-left: 4px solid #2a5298; 
                        padding-left: 12px; 
                        margin-bottom: 10px; 
                    }
                    
                    /* Fee Items */
                    .fee-item { 
                        background: #f8fafc; 
                        border-radius: 8px; 
                        padding: 12px 14px; 
                        margin-bottom: 6px; 
                        border: 1px solid #eef2f6; 
                    }
                    .fee-item:last-child { margin-bottom: 0; }
                    
                    .fee-header { 
                        display: flex; 
                        justify-content: space-between; 
                        align-items: center; 
                        flex-wrap: wrap;
                    }
                    .fee-name { 
                        font-weight: 600; 
                        font-size: 12px; 
                        color: #1f2937; 
                    }
                    .fee-amount { 
                        font-weight: 700; 
                        font-size: 13px; 
                        color: #059669; 
                        white-space: nowrap; 
                    }
                    
                    .fee-detail { 
                        font-size: 11px; 
                        color: #6b7280; 
                        margin-top: 4px; 
                        padding-top: 4px; 
                        border-top: 1px dashed #e5e7eb; 
                    }
                    .fee-detail-row {
                        display: flex;
                        justify-content: space-between;
                        padding: 2px 0;
                    }
                    
                    /* Status Indicators */
                    .status-paid { color: #059669; font-weight: 600; }
                    .status-partial { color: #d97706; font-weight: 600; }
                    .status-unpaid { color: #dc2626; font-weight: 600; }
                    .status-credit { color: #2563eb; font-weight: 600; }
                    
                    /* Balance Box */
                    .balance-box { 
                        background: #fffbeb; 
                        border-radius: 6px; 
                        padding: 8px 12px; 
                        margin-top: 6px; 
                        border: 1px solid #fde68a; 
                    }
                    .balance-box.green { 
                        background: #ecfdf5; 
                        border-color: #6ee7b7; 
                    }
                    .balance-box.blue { 
                        background: #eff6ff; 
                        border-color: #93c5fd; 
                    }
                    .balance-label { 
                        font-size: 10px; 
                        font-weight: 700; 
                        color: #92400e; 
                    }
                    .balance-label.green { color: #065f46; }
                    .balance-label.blue { color: #1e40af; }
                    .balance-amount { 
                        font-size: 13px; 
                        font-weight: 700; 
                        color: #dc2626; 
                    }
                    .balance-amount.green { color: #059669; }
                    .balance-amount.blue { color: #2563eb; }
                    
                    /* Custom badge */
                    .custom-badge {
                        font-size: 9px;
                        background: #fef3c7;
                        color: #d97706;
                        padding: 1px 6px;
                        border-radius: 10px;
                        margin-left: 4px;
                    }
                    
                    /* Period badge */
                    .period-badge {
                        font-size: 9px;
                        background: #e5e7eb;
                        color: #4b5563;
                        padding: 1px 6px;
                        border-radius: 10px;
                        margin-left: 4px;
                    }
                    
                    /* Total Row */
                    .total-row { 
                        display: flex; 
                        justify-content: space-between; 
                        margin-top: 15px; 
                        padding-top: 12px; 
                        border-top: 2px solid #1a3a5c; 
                        font-size: 16px; 
                        font-weight: 700; 
                    }
                    .total-amount { 
                        color: #059669; 
                        font-size: 18px; 
                    }
                    
                    /* Outstanding Box */
                    .outstanding-box {
                        margin-top: 15px;
                        padding: 14px 18px;
                        border-radius: 10px;
                        text-align: center;
                    }
                    .outstanding-box.due { background: #fef2f2; border: 1px solid #fca5a5; }
                    .outstanding-box.paid { background: #ecfdf5; border: 1px solid #6ee7b7; }
                    .outstanding-box.credit { background: #eff6ff; border: 1px solid #93c5fd; }
                    
                    .outstanding-label { font-size: 12px; font-weight: 600; }
                    .outstanding-label.due { color: #991b1b; }
                    .outstanding-label.paid { color: #065f46; }
                    .outstanding-label.credit { color: #1e40af; }
                    
                    .outstanding-amount { 
                        font-size: 18px; 
                        font-weight: 700; 
                        margin-top: 4px; 
                    }
                    .outstanding-amount.due { color: #dc2626; }
                    .outstanding-amount.paid { color: #059669; }
                    .outstanding-amount.credit { color: #2563eb; }
                    
                    /* Notes */
                    .notes-box {
                        margin-top: 12px;
                        padding: 10px 14px;
                        background: #fffbeb;
                        border-radius: 6px;
                        border: 1px solid #fde68a;
                    }
                    .notes-label { font-size: 10px; font-weight: 600; color: #92400e; }
                    .notes-text { font-size: 11px; color: #78350f; margin-top: 3px; }
                    
                    /* Footer */
                    .footer { 
                        background: #f8fafc; 
                        text-align: center; 
                        padding: 15px 20px; 
                        font-size: 10px; 
                        color: #9ca3af; 
                        border-top: 1px solid #eef2f6; 
                    }
                    .footer span { margin: 0 6px; }
                    
                    /* Item Detail Styles */
                    .item-detail {
                        margin-top: 4px;
                        padding: 4px 8px;
                        background: #f8fafc;
                        border-radius: 4px;
                        font-size: 11px;
                    }
                    .item-detail-row {
                        display: flex;
                        justify-content: space-between;
                        padding: 2px 0;
                        border-bottom: 1px dashed #e5e7eb;
                    }
                    .item-detail-row:last-child {
                        border-bottom: none;
                    }
                    
                    /* Print Styles */
                    @media print {
                        body { padding: 0; background: white; }
                        .receipt { box-shadow: none; border-radius: 0; }
                        .no-print { display: none; }
                        .header { background: #1a3a5c !important; -webkit-print-color-adjust: exact; print-color-adjust: exact; }
                    }
                </style>
            </head>
            <body>
                <div class="receipt">
                    <!-- HEADER -->
                    <div class="header">
                        <div class="school-name">${escapeHtml(school.schoolName || 'Eden Junior')}</div>
                        <div class="school-motto">${escapeHtml(school.motto || 'Quality Education for All')}</div>
                        <div class="receipt-title">FEE PAYMENT RECEIPT</div>
                        <div class="receipt-no">Receipt: ${payment.receiptNumber}</div>
                    </div>
                    
                    <!-- CONTENT -->
                    <div class="content">
                        <!-- Student Information -->
                        <div class="info-grid">
                            <div class="info-item">
                                <span class="info-label">Student Name</span>
                                <span class="info-value">${escapeHtml(payment.studentName || 'N/A')}</span>
                            </div>
                            <div class="info-item">
                                <span class="info-label">Admission No.</span>
                                <span class="info-value">${payment.admissionNumber || 'N/A'}</span>
                            </div>
                            <div class="info-item">
                                <span class="info-label">Date</span>
                                <span class="info-value">${new Date(payment.date).toLocaleDateString()}</span>
                            </div>
                            <div class="info-item">
                                <span class="info-label">Period</span>
                                <span class="info-value">${termName} ${currentYear}</span>
                            </div>
                            <div class="info-item">
                                <span class="info-label">Payment Method</span>
                                <span class="info-value">${(payment.method || 'CASH').toUpperCase()}</span>
                            </div>
                            ${payment.reference ? `
                            <div class="info-item">
                                <span class="info-label">Reference</span>
                                <span class="info-value">${escapeHtml(payment.reference)}</span>
                            </div>
                            ` : ''}
                        </div>
                        
                        <!-- Tuition Payment -->
                        ${tuitionPaid > 0 ? `
                            <div class="section">
                                <div class="section-title">💰 Tuition Payment</div>
                                <div class="fee-item">
                                    <div class="fee-header">
                                        <span class="fee-name">Tuition Fee</span>
                                        <span class="fee-amount">UGX ${Math.round(tuitionPaid).toLocaleString()}</span>
                                    </div>
                                    <div class="fee-detail">
                                        <div class="fee-detail-row">
                                            <span>Expected:</span>
                                            <span>UGX ${Math.round(tuitionBalance.expected).toLocaleString()}</span>
                                        </div>
                                        ${tuitionBalance.discountAmount > 0 ? `
                                            <div class="fee-detail-row">
                                                <span>Bursary Applied:</span>
                                                <span style="color: #059669;">- UGX ${Math.round(tuitionBalance.discountAmount).toLocaleString()}</span>
                                            </div>
                                        ` : ''}
                                        ${tuitionBalance.balance > 0 ? `
                                            <div class="balance-box" style="margin-top: 6px;">
                                                <div class="balance-label">⚠️ Balance Due</div>
                                                <div class="balance-amount">UGX ${Math.round(tuitionBalance.balance).toLocaleString()}</div>
                                            </div>
                                        ` : tuitionPaid > 0 ? `
                                            <div class="balance-box green" style="margin-top: 6px;">
                                                <div class="balance-label green">✓ Fully Paid</div>
                                            </div>
                                        ` : ''}
                                    </div>
                                </div>
                            </div>
                        ` : ''}
                        
                        <!-- PAID ITEMS SECTION -->
                        ${buildPaidItemsHtml()}
                        
                        <!-- TOTAL -->
                        <div class="total-row">
                            <span>TOTAL PAID</span>
                            <span class="total-amount">UGX ${Math.round(totalPaid).toLocaleString()}</span>
                        </div>
                        
                        <!-- OUTSTANDING ITEMS SUMMARY -->
                        ${buildOutstandingItemsHtml()}
                        
                        <!-- OUTSTANDING BALANCE -->
                        ${showOutstandingBalance ? `
                            <div class="outstanding-box due" style="margin-top: 15px;">
                                <div class="outstanding-label due">⚠️ TOTAL OUTSTANDING BALANCE</div>
                                <div class="outstanding-amount due">UGX ${Math.round(totalOutstanding).toLocaleString()}</div>
                                <div style="font-size: 11px; color: #991b1b; margin-top: 4px;">Please clear this balance to complete payment</div>
                            </div>
                        ` : totalPaid > 0 ? `
                            <div class="outstanding-box paid" style="margin-top: 15px;">
                                <div class="outstanding-label paid">✅ NO OUTSTANDING BALANCE</div>
                                <div class="outstanding-amount paid">Fully Paid</div>
                                <div style="font-size: 11px; color: #065f46; margin-top: 4px;">All fees and items are fully paid</div>
                            </div>
                        ` : ''}
                        
                        <!-- NOTES -->
                        ${payment.notes ? `
                            <div class="notes-box">
                                <div class="notes-label">📝 Notes</div>
                                <div class="notes-text">${escapeHtml(payment.notes)}</div>
                            </div>
                        ` : ''}
                    </div>
                    
                    <!-- FOOTER -->
                    <div class="footer">
                        Thank you for your payment!<br>
                        This is a computer-generated receipt. Please keep it for your records.
                    </div>
                </div>
                
                <!-- PRINT BUTTONS -->
                <div class="no-print" style="text-align: center; margin-top: 20px;">
                    <button onclick="window.print()" style="padding: 12px 28px; background: #1a3a5c; color: white; border: none; border-radius: 8px; cursor: pointer; margin-right: 12px; font-size: 14px; font-weight: 600;">
                        🖨️ Print Receipt
                    </button>
                    <button onclick="window.close()" style="padding: 12px 28px; background: #6b7280; color: white; border: none; border-radius: 8px; cursor: pointer; font-size: 14px; font-weight: 600;">
                        Close
                    </button>
                </div>
            </body>
            </html>
        `);
        
        printWindow.document.close();
        
    } catch (error) {
        console.error('Error printing receipt:', error);
        alert('Error printing receipt: ' + error.message);
    }
}

