// ========== GLOBAL DECLARATION ==========
// Make sure the function is defined at the top level

/**
 * Main entry point for fee collection - Uses multi-period system
 * @param {Object} student - The student object
 * @param {number} currentYear - Current academic year
 * @param {number} currentTerm - Current term
 * @param {string} termName - Name of the current term
 */
async function loadCollectionForm(student, currentYear, currentTerm, termName) {
    console.log('=== loadCollectionForm CALLED ===');
    console.log('Student:', student?.firstName, student?.lastName);
    console.log('Period:', currentYear, 'Term', currentTerm);
    
    // If student object has an id, use the multi-period system
    if (student && student.id) {
        console.log('🔄 Using Multi-Period Collection System');
        await loadMultiPeriodCollectionForm(student.id);
        return;
    }
    
    // If student is a string (ID), fetch the student first
    if (typeof student === 'string') {
        console.log('🔄 Fetching student data for ID:', student);
        try {
            const response = await fetch(`/api/students/${student}`);
            if (response.ok) {
                const studentData = await response.json();
                await loadMultiPeriodCollectionForm(studentData.id);
                return;
            }
        } catch (e) {
            console.error('Error fetching student:', e);
        }
    }
    
    // Fallback: Show error
    const container = document.getElementById('collectionFormContainer');
    if (container) {
        container.innerHTML = `
            <div class="bg-red-50 p-6 text-center rounded-lg border border-red-200">
                <i class="fas fa-exclamation-triangle text-red-500 text-4xl mb-2"></i>
                <p class="text-red-700 font-semibold">Unable to load collection form</p>
                <p class="text-red-600 text-sm mt-1">Please select a student from the dropdown</p>
                <button onclick="location.reload()" class="mt-3 bg-red-600 text-white px-4 py-2 rounded-lg hover:bg-red-700">
                    <i class="fas fa-sync-alt"></i> Refresh Page
                </button>
            </div>
        `;
    }
}

