function formatMoney(amount) {
    const num = Math.round(amount || 0);
    return num.toLocaleString('en-US');
}

// ========== ESCAPE HTML ==========
function escapeHtml(text) {
    if (!text) return '';
    const div = document.createElement('div');
    div.textContent = text;
    return div.innerHTML;
}

// ========== GET TERM NAME ==========
function getTermName(term) {
    const names = { 1: 'First Term', 2: 'Second Term', 3: 'Third Term' };
    return names[term] || `Term ${term}`;
}

// ========== CLOSE MODAL ==========
function closeModal() {
    const modal = document.querySelector('.fixed.inset-0.bg-black.bg-opacity-50');
    if (modal) modal.remove();
}

// ========== SHOW TOAST NOTIFICATION ==========
function showToast(message, type = 'success') {
    const existing = document.querySelector('.fixed.bottom-4.right-4');
    if (existing) existing.remove();
    
    const toast = document.createElement('div');
    const bgColor = type === 'success' ? 'bg-green-500' : 
                    type === 'error' ? 'bg-red-500' : 
                    type === 'warning' ? 'bg-yellow-500' : 'bg-blue-500';
    toast.className = `fixed bottom-4 right-4 ${bgColor} text-white px-4 py-2 rounded-lg shadow-lg z-50 max-w-sm`;
    toast.innerHTML = message;
    document.body.appendChild(toast);
    setTimeout(() => toast.remove(), 4000);
}

// ========== GET SCHOOL PREFIX FOR RECEIPTS ==========
async function getSchoolReceiptPrefix() {
    try {
        const response = await fetch('/api/school');
        if (response.ok) {
            const data = await response.json();
            const school = data.school || {};
            const schoolName = school.schoolName || 'School';
            let prefix = schoolName.replace(/[^a-zA-Z0-9]/g, '').substring(0, 4).toUpperCase();
            if (prefix.length < 2) prefix = 'SCH';
            return prefix;
        }
        return 'SCH';
    } catch (error) {
        console.warn('Could not fetch school name, using default prefix');
        return 'SCH';
    }
}

// ========== GENERATE RECEIPT NUMBER ==========
async function generateReceiptNumberWithPrefix(periodKey) {
    const isCurrent = periodKey === window.multiPeriodData?.currentPeriod?.periodKey;
    const prefix = isCurrent ? await getSchoolReceiptPrefix() : 'PB';
    const timestamp = Date.now().toString().slice(-6);
    const random = Math.floor(Math.random() * 900 + 100).toString();
    const receiptNumber = `${prefix}${timestamp}${random}`;
    
    const receiptInput = document.getElementById(`receiptNumber_${periodKey}`);
    if (receiptInput) {
        receiptInput.value = receiptNumber;
        receiptInput.style.borderColor = '#10b981';
        receiptInput.style.backgroundColor = '#f0fdf4';
        setTimeout(() => {
            receiptInput.style.borderColor = '';
            receiptInput.style.backgroundColor = '';
        }, 2000);
    }
    return receiptNumber;
}

// ========== GET CURRENT DATE/TIME ==========
function getCurrentDateTimeForInput() {
    const now = new Date();
    const year = now.getFullYear();
    const month = String(now.getMonth() + 1).padStart(2, '0');
    const day = String(now.getDate()).padStart(2, '0');
    const hours = String(now.getHours()).padStart(2, '0');
    const minutes = String(now.getMinutes()).padStart(2, '0');
    return {
        date: `${year}-${month}-${day}`,
        time: `${hours}:${minutes}`,
        dateTime: `${year}-${month}-${day}T${hours}:${minutes}`
    };
}

// ========== FORCE RELOAD ACADEMIC SETTINGS ==========
async function forceReloadAcademicSettings() {
    try {
        const response = await fetch('/api/academic/settings');
        if (response.ok) {
            const settings = await response.json();
            if (settings.currentYear && settings.currentTerm) {
                currentAcademicSettings.currentYear = settings.currentYear;
                currentAcademicSettings.currentTerm = settings.currentTerm;
                localStorage.setItem('currentAcademicYear', settings.currentYear.toString());
                localStorage.setItem('currentAcademicTerm', settings.currentTerm.toString());
                updateAcademicHeader();
                console.log('✅ Academic settings reloaded:', settings);
                return true;
            }
        }
        return false;
    } catch (error) {
        console.warn('Could not reload academic settings:', error);
        return false;
    }
}

// ========== COMPLETE FIXED: LOAD MULTI-PERIOD COLLECTION FORM ==========
// Version: 19.0 - FILTERS OUT FUTURE PERIODS

// ========== COMPLETE REBUILT: LOAD MULTI-PERIOD COLLECTION FORM ==========
// Version: 20.0 - FIXED: Custom Overrides properly loaded and applied
async function loadMultiPeriodCollectionForm(studentId) {
    console.log('=== LOAD MULTI-PERIOD COLLECTION FORM v24.0 (FINAL) ===');
    await forceReloadAcademicSettings();

    const container = document.getElementById('collectionFormContainer');
    if (!container) return;
    container.innerHTML = `<div class="flex justify-center items-center p-8"><div class="loading-spinner"></div><span class="ml-3 text-gray-500">Loading student data...</span></div>`;

    try {
        // 1. Fetch student
        const studentRes = await fetch(`/api/students/${studentId}`);
        if (!studentRes.ok) throw new Error(`Failed to fetch student (${studentRes.status})`);
        const student = await studentRes.json();
        window.currentStudent = student;

        // 2. Fetch all payments for this student
        const paymentsRes = await fetch(`/api/fee/payments`);
        let allPayments = paymentsRes.ok ? await paymentsRes.json() : [];
        allPayments = allPayments.filter(p => p.studentId === studentId);
        console.log(`📊 Found ${allPayments.length} payments`);

        // 3. Fetch fee structures and assignment
        const fsRes = await fetch(`/api/fee/structures`);
        const feeStructures = fsRes.ok ? await fsRes.json() : [];
        const assignRes = await fetch(`/api/student-fee-assignments`);
        const feeAssignments = assignRes.ok ? await assignRes.json() : [];
        const assignment = feeAssignments.find(a => a.studentId === studentId) || {};
        let feeStructure = feeStructures.find(f => f.id === assignment.feeStructureId);
        if (!feeStructure) console.warn('⚠️ No fee structure found');

        // 4. Build period data
        const { currentYear, currentTerm } = currentAcademicSettings;
        const periodData = buildPeriodData(student, feeStructure, allPayments, currentYear, currentTerm);

        // 5. Store and render
        window.multiPeriodData = periodData;
        renderMultiPeriodCollectionForm(periodData, student);

    } catch (error) {
        console.error(error);
        container.innerHTML = `
            <div class="bg-red-50 p-6 text-center rounded-lg border border-red-200">
                <i class="fas fa-exclamation-triangle text-red-500 text-4xl mb-2"></i>
                <p class="text-red-600 font-semibold">Error loading student data</p>
                <p class="text-red-500 text-sm mt-1">${escapeHtml(error.message)}</p>
                <button onclick="loadMultiPeriodCollectionForm('${studentId}')" class="mt-3 bg-red-600 text-white px-4 py-2 rounded-lg hover:bg-red-700">
                    <i class="fas fa-sync-alt"></i> Retry
                </button>
            </div>
        `;
    }
}
function buildPeriodData(student, feeStructure, allPayments, currentYear, currentTerm) {
    console.log('=== buildPeriodData v25.0 - FIXED ONE-TIME ALL PERIODS ===');
    
    const removedItems = student.removedItems || {};
    const customOverrides = student.customItemOverrides || {};
    const customTransportation = student.customTransportation || null;
    const customBursary = student.customBursary || null;

    // Group payments by period
    const paymentsByPeriod = {};
    for (const p of allPayments) {
        const key = `${p.academicYear}_${p.term}`;
        if (!paymentsByPeriod[key]) {
            paymentsByPeriod[key] = { 
                year: parseInt(p.academicYear), 
                term: parseInt(p.term), 
                payments: [] 
            };
        }
        paymentsByPeriod[key].payments.push(p);
    }

    // ================================================================
    // HELPER: Get payments for a specific item in a period
    // ================================================================
    function getItemPayment(itemName, componentName, periodType, periodKey) {
        const periodData = paymentsByPeriod[periodKey];
        if (!periodData) return { cashPaid: 0, itemsBrought: 0, histories: [] };
        
        let cashPaid = 0;
        let itemsBrought = 0;
        const histories = [];
        const processedKeys = new Set();
        
        for (const payment of periodData.payments) {
            // Check activityItemPayments
            if (payment.activityItemPayments && Array.isArray(payment.activityItemPayments)) {
                for (const paidItem of payment.activityItemPayments) {
                    if (!paidItem || !paidItem.itemName) continue;
                    
                    // ✅ FIX: For one_time items, ignore periodType match
                    let match = paidItem.itemName === itemName && 
                               paidItem.componentName === componentName;
                    
                    // For termly & yearly, also match periodType (if not one_time)
                    if (periodType !== 'one_time' && paidItem.periodType) {
                        match = match && (paidItem.periodType === periodType);
                    }
                    
                    if (match) {
                        const key = `${payment.id}_${paidItem.itemName}_${paidItem.componentName}`;
                        if (processedKeys.has(key)) continue;
                        processedKeys.add(key);
                        
                        if (paidItem.paymentType === 'paid_cash') {
                            const amount = paidItem.amountPaid || 0;
                            cashPaid += amount;
                            histories.push({
                                paymentId: payment.id,
                                id: payment.id,
                                type: 'cash',
                                amount: amount,
                                date: payment.date,
                                receiptNumber: payment.receiptNumber,
                                method: payment.method,
                                academicYear: payment.academicYear,
                                term: payment.term,
                                isPreviousBalancePayment: payment.isPreviousBalancePayment || false
                            });
                        } else if (paidItem.paymentType === 'brought_item') {
                            const qty = paidItem.itemsBrought || 0;
                            itemsBrought += qty;
                            histories.push({
                                paymentId: payment.id,
                                id: payment.id,
                                type: 'item',
                                itemsBrought: qty,
                                date: payment.date,
                                receiptNumber: payment.receiptNumber,
                                method: payment.method,
                                academicYear: payment.academicYear,
                                term: payment.term,
                                isPreviousBalancePayment: payment.isPreviousBalancePayment || false
                            });
                        }
                    }
                }
            }
            
            // Check paymentsByPeriodType
            if (payment.paymentsByPeriodType && typeof payment.paymentsByPeriodType === 'object') {
                const periodTypes = ['one_time', 'termly', 'yearly'];
                for (const pt of periodTypes) {
                    const periodItems = payment.paymentsByPeriodType[pt] || [];
                    for (const paidItem of periodItems) {
                        if (!paidItem || !paidItem.itemName) continue;
                        
                        // ✅ FIX: For one_time items, ignore periodType match
                        let match = paidItem.itemName === itemName && 
                                   paidItem.componentName === componentName;
                        
                        // For termly & yearly, also match periodType
                        if (periodType !== 'one_time') {
                            match = match && (pt === periodType);
                        }
                        
                        if (match) {
                            const key = `${payment.id}_${paidItem.itemName}_${paidItem.componentName}`;
                            if (processedKeys.has(key)) continue;
                            processedKeys.add(key);
                            
                            if (paidItem.paymentType === 'paid_cash') {
                                const amount = paidItem.amountPaid || 0;
                                cashPaid += amount;
                                histories.push({
                                    paymentId: payment.id,
                                    id: payment.id,
                                    type: 'cash',
                                    amount: amount,
                                    date: payment.date,
                                    receiptNumber: payment.receiptNumber,
                                    method: payment.method,
                                    academicYear: payment.academicYear,
                                    term: payment.term,
                                    isPreviousBalancePayment: payment.isPreviousBalancePayment || false
                                });
                            } else if (paidItem.paymentType === 'brought_item') {
                                const qty = paidItem.itemsBrought || 0;
                                itemsBrought += qty;
                                histories.push({
                                    paymentId: payment.id,
                                    id: payment.id,
                                    type: 'item',
                                    itemsBrought: qty,
                                    date: payment.date,
                                    receiptNumber: payment.receiptNumber,
                                    method: payment.method,
                                    academicYear: payment.academicYear,
                                    term: payment.term,
                                    isPreviousBalancePayment: payment.isPreviousBalancePayment || false
                                });
                            }
                        }
                    }
                }
            }
        }
        
        return { cashPaid, itemsBrought, histories };
    }

    // ================================================================
    // HELPER: Get previous period payments (for one-time items - DEPRECATED)
    // ================================================================
    function getPreviousPeriodPayment(itemName, componentName, periodType) {
        let totalCashPaid = 0;
        let totalItemsBrought = 0;
        const allHistories = [];
        
        for (const [periodKey, periodData] of Object.entries(paymentsByPeriod)) {
            if (periodKey === `${currentYear}_${currentTerm}`) continue;
            
            const result = getItemPayment(itemName, componentName, periodType, periodKey);
            totalCashPaid += result.cashPaid;
            totalItemsBrought += result.itemsBrought;
            for (const h of result.histories) {
                allHistories.push({
                    ...h,
                    paymentId: h.paymentId || h.id
                });
            }
        }
        
        return { cashPaid: totalCashPaid, itemsBrought: totalItemsBrought, histories: allHistories };
    }

    // ================================================================
    // HELPER: Get yearly item payments (all terms in the same year)
    // ================================================================
    function getYearlyItemPayment(itemName, componentName, periodType, year) {
        let totalCashPaid = 0;
        let totalItemsBrought = 0;
        const allHistories = [];
        
        for (const [periodKey, periodData] of Object.entries(paymentsByPeriod)) {
            if (periodData.year !== year) continue;
            
            const result = getItemPayment(itemName, componentName, periodType, periodKey);
            totalCashPaid += result.cashPaid;
            totalItemsBrought += result.itemsBrought;
            for (const h of result.histories) {
                allHistories.push({
                    ...h,
                    paymentId: h.paymentId || h.id
                });
            }
        }
        
        return { cashPaid: totalCashPaid, itemsBrought: totalItemsBrought, histories: allHistories };
    }

    // ================================================================
    // HELPER: Calculate remaining with OR logic
    // ================================================================
    function calculateRemaining(item, cashPaid, itemsBrought) {
        const { quantity, totalAmount, unitPrice, paymentOption } = item;
        
        if (paymentOption === 'cash_only') {
            const rem = Math.max(0, totalAmount - cashPaid);
            return { remainingCash: rem, remainingItems: 0, isFullyPaid: rem === 0 };
        }
        
        if (paymentOption === 'item_only') {
            const rem = Math.max(0, quantity - itemsBrought);
            return { remainingCash: 0, remainingItems: rem, isFullyPaid: rem === 0 };
        }
        
        // EITHER (OR Logic)
        const itemsBroughtCapped = Math.min(itemsBrought, quantity);
        const cashValue = itemsBroughtCapped * unitPrice;
        const remainingCash = Math.max(0, totalAmount - cashPaid - cashValue);
        const itemsCoveredByCash = unitPrice > 0 ? Math.floor(cashPaid / unitPrice) : 0;
        const remainingItems = Math.max(0, quantity - itemsBroughtCapped - itemsCoveredByCash);
        const totalCovered = cashPaid + (itemsBroughtCapped * unitPrice);
        const totalRequired = quantity * unitPrice;
        const isFullyPaid = totalCovered >= totalRequired;
        
        return { remainingCash, remainingItems, isFullyPaid };
    }

    // ================================================================
    // BUILD ITEMS FOR A PERIOD
    // ================================================================
    function buildPeriodItems(periodKey, year, term) {
        const items = [];
        const statusGroupMap = {};
        let totalCashExpected = 0, totalCashPaid = 0, totalItemsBrought = 0, totalItemsRequired = 0, totalItemsRemaining = 0;

        if (!feeStructure || !feeStructure.activityComponents) {
            return { items, totalCashExpected, totalCashPaid, totalItemsBrought, totalItemsRequired, totalItemsRemaining, statusGroupMap };
        }

        for (const component of feeStructure.activityComponents) {
            const periodType = component.periodType || 'termly';
            
            // All items are always visible (termly, one-time, yearly)
            let shouldInclude = true;
            if (!shouldInclude) continue;

            const groupName = component.statusGroupName || component.name || 'Other';
            const isTransportation = component.name.toLowerCase().includes('transport') || 
                                    (component.statusGroupName && component.statusGroupName.toLowerCase().includes('transport'));

            if (!statusGroupMap[groupName]) {
                statusGroupMap[groupName] = { 
                    name: groupName, 
                    componentName: component.name, 
                    periodType, 
                    items: [], 
                    totalExpected: 0, 
                    totalPaid: 0, 
                    totalBalance: 0, 
                    itemsRemaining: 0, 
                    itemsBrought: 0, 
                    itemsRequired: 0 
                };
            }

            for (const item of (component.items || [])) {
                const itemId = item.id || item.name;
                
                // Skip removed items
                if (removedItems[itemId] && removedItems[itemId].isActive !== false) continue;

                let totalAmount = item.totalAmount || 0;
                let quantity = item.quantity || 1;
                let unitPrice = item.unitPrice || (totalAmount / quantity);
                let paymentOption = item.paymentOption || 'either';

                // ============================================================
                // APPLY CUSTOM OVERRIDES
                // ============================================================
                if (customOverrides && customOverrides[itemId]) {
                    const custom = customOverrides[itemId];
                    if (custom.isActive !== false) {
                        if (custom.customAmount !== undefined && custom.customAmount !== null && custom.customAmount > 0) {
                            totalAmount = custom.customAmount;
                        }
                        if (custom.customQuantity !== undefined && custom.customQuantity !== null && custom.customQuantity > 0) {
                            quantity = custom.customQuantity;
                        }
                        if (custom.paymentOption) {
                            paymentOption = custom.paymentOption;
                        }
                    }
                }

                // ============================================================
                // APPLY CUSTOM TRANSPORTATION
                // ============================================================
                if (isTransportation && customTransportation) {
                    if (customTransportation.hasTransportation === false) continue;
                    if (customTransportation.amount) {
                        totalAmount = customTransportation.amount;
                        unitPrice = totalAmount / quantity;
                    }
                }

                // ============================================================
                // GET PAYMENT DATA BASED ON PERIOD TYPE
                // ============================================================
                let cashPaid = 0, itemsBrought = 0, histories = [];
                
                if (periodType === 'one_time') {
                    // ✅ FIX: One-time: Check ALL periods (including current)
                    let totalCashPaid = 0;
                    let totalItemsBrought = 0;
                    let allHistories = [];
                    for (const [pKey, pData] of Object.entries(paymentsByPeriod)) {
                        const result = getItemPayment(item.name, component.name, periodType, pKey);
                        totalCashPaid += result.cashPaid;
                        totalItemsBrought += result.itemsBrought;
                        allHistories = allHistories.concat(result.histories);
                    }
                    cashPaid = totalCashPaid;
                    itemsBrought = totalItemsBrought;
                    histories = allHistories;
                } else if (periodType === 'yearly') {
                    // ✅ Yearly: Check ALL terms in the SAME year
                    const yearlyResult = getYearlyItemPayment(item.name, component.name, periodType, year);
                    cashPaid = yearlyResult.cashPaid;
                    itemsBrought = yearlyResult.itemsBrought;
                    histories = yearlyResult.histories;
                } else {
                    // ✅ Termly: Check ONLY current term
                    const curr = getItemPayment(item.name, component.name, periodType, periodKey);
                    cashPaid = curr.cashPaid;
                    itemsBrought = curr.itemsBrought;
                    histories = curr.histories;
                }

                // ============================================================
                // CALCULATE REMAINING
                // ============================================================
                const result = calculateRemaining({ quantity, totalAmount, unitPrice, paymentOption }, cashPaid, itemsBrought);
                
                const cashExpected = (paymentOption === 'cash_only') ? totalAmount :
                                     (paymentOption === 'either') ? Math.max(0, totalAmount - (Math.min(itemsBrought, quantity) * unitPrice)) : 0;

                // ============================================================
                // BUILD ITEM DATA
                // ============================================================
                const itemData = {
                    componentId: component.id || component.name,
                    componentName: component.name,
                    periodType: periodType,
                    itemId: itemId,
                    itemName: item.name,
                    quantity: quantity,
                    totalAmount: totalAmount,
                    unitPrice: unitPrice,
                    paymentOption: paymentOption,
                    cashExpected: cashExpected,
                    cashPaid: cashPaid,
                    itemsBrought: Math.min(itemsBrought, quantity),
                    remainingAmount: result.remainingCash,
                    remainingQuantity: result.remainingItems,
                    isFullyPaid: result.isFullyPaid,
                    isCustomized: !!(customOverrides && customOverrides[itemId]),
                    customReason: customOverrides?.[itemId]?.reason || null,
                    statusGroupName: groupName,
                    isTransportation: isTransportation,
                    isSpecialItem: isTransportation || paymentOption === 'cash_only' || paymentOption === 'item_only',
                    paymentHistories: histories,
                    _debug: {
                        periodType: periodType,
                        year: year,
                        term: term,
                        cashPaid: cashPaid,
                        itemsBrought: itemsBrought,
                        historiesCount: histories.length
                    }
                };

                items.push(itemData);
                statusGroupMap[groupName].items.push(itemData);
                statusGroupMap[groupName].totalExpected += totalAmount;
                statusGroupMap[groupName].totalPaid += cashPaid;
                statusGroupMap[groupName].totalBalance += result.remainingCash;
                statusGroupMap[groupName].itemsRemaining += result.remainingItems;
                statusGroupMap[groupName].itemsBrought += Math.min(itemsBrought, quantity);
                statusGroupMap[groupName].itemsRequired += quantity;

                totalCashExpected += cashExpected;
                totalCashPaid += cashPaid;
                totalItemsBrought += Math.min(itemsBrought, quantity);
                totalItemsRequired += quantity;
                totalItemsRemaining += result.remainingItems;
            }
        }
        
        return { 
            items, 
            totalCashExpected, 
            totalCashPaid, 
            totalItemsBrought, 
            totalItemsRequired, 
            totalItemsRemaining, 
            statusGroupMap 
        };
    }

    // ================================================================
    // BUILD CURRENT PERIOD
    // ================================================================
    const currentPeriodKey = `${currentYear}_${currentTerm}`;
    const currentResult = buildPeriodItems(currentPeriodKey, currentYear, currentTerm);

    // ================================================================
    // CALCULATE TUITION
    // ================================================================
    let tuitionExpected = feeStructure?.tuition || 0;
    let bursaryAmount = 0, bursaryName = null, isCustomBursary = false;
    
    if (customBursary && customBursary.amount > 0) {
        bursaryAmount = customBursary.amount;
        bursaryName = 'Custom Bursary';
        isCustomBursary = true;
        tuitionExpected = Math.max(0, tuitionExpected - bursaryAmount);
    }
    
    let tuitionPaid = 0;
    const currentPayments = paymentsByPeriod[currentPeriodKey]?.payments || [];
    for (const p of currentPayments) {
        tuitionPaid += p.tuitionPaid || 0;
    }

    // ================================================================
    // BUILD CURRENT PERIOD OBJECT
    // ================================================================
    const currentPeriod = {
        periodKey: currentPeriodKey,
        year: currentYear,
        term: currentTerm,
        isCurrent: true,
        isEmpty: currentResult.items.length === 0 && tuitionExpected === 0,
        isFullyPaid: false,
        hasBalance: false,
        tuition: { 
            expected: tuitionExpected, 
            paid: tuitionPaid, 
            balance: tuitionExpected - tuitionPaid, 
            bursaryAmount, 
            bursaryName, 
            isCustomBursary 
        },
        activity: {
            expected: currentResult.totalCashExpected,
            paid: currentResult.totalCashPaid,
            balance: currentResult.totalCashExpected - currentResult.totalCashPaid,
            itemsRequired: currentResult.totalItemsRequired,
            itemsBrought: currentResult.totalItemsBrought,
            itemsRemaining: currentResult.totalItemsRemaining,
            items: currentResult.items
        },
        total: {
            expected: tuitionExpected + currentResult.totalCashExpected,
            paid: tuitionPaid + currentResult.totalCashPaid,
            balance: (tuitionExpected - tuitionPaid) + (currentResult.totalCashExpected - currentResult.totalCashPaid)
        },
        statusGroupBreakdown: currentResult.statusGroupMap,
        payments: currentPayments,
        itemCount: currentResult.items.length,
        feeStructure: feeStructure,
        hasCustomizations: Object.keys(customOverrides).length > 0,
        customizationCount: Object.keys(customOverrides).length,
        removedItemsCount: Object.keys(removedItems).length
    };
    
    currentPeriod.hasBalance = currentPeriod.total.balance > 0 || currentPeriod.activity.itemsRemaining > 0;
    currentPeriod.isFullyPaid = !currentPeriod.hasBalance && currentPeriod.total.paid > 0;

    // ================================================================
    // BUILD PREVIOUS PERIODS
    // ================================================================
    const previousPeriods = [];
    for (const [key, data] of Object.entries(paymentsByPeriod)) {
        if (key === currentPeriodKey) continue;
        
        const year = data.year, term = data.term;
        
        // Skip future periods
        if (year > currentYear || (year === currentYear && term > currentTerm)) continue;
        
        const result = buildPeriodItems(key, year, term);
        
        let periodTuitionPaid = 0;
        for (const p of data.payments) {
            periodTuitionPaid += p.tuitionPaid || 0;
        }
        
        // Use same tuition expected (from fee structure)
        const periodTuitionExpected = tuitionExpected;
        
        const period = {
            periodKey: key,
            year: year,
            term: term,
            isCurrent: false,
            isEmpty: result.items.length === 0 && periodTuitionExpected === 0,
            isFullyPaid: false,
            hasBalance: false,
            tuition: { 
                expected: periodTuitionExpected, 
                paid: periodTuitionPaid, 
                balance: periodTuitionExpected - periodTuitionPaid 
            },
            activity: {
                expected: result.totalCashExpected,
                paid: result.totalCashPaid,
                balance: result.totalCashExpected - result.totalCashPaid,
                itemsRequired: result.totalItemsRequired,
                itemsBrought: result.totalItemsBrought,
                itemsRemaining: result.totalItemsRemaining,
                items: result.items
            },
            total: {
                expected: periodTuitionExpected + result.totalCashExpected,
                paid: periodTuitionPaid + result.totalCashPaid,
                balance: (periodTuitionExpected - periodTuitionPaid) + (result.totalCashExpected - result.totalCashPaid)
            },
            statusGroupBreakdown: result.statusGroupMap,
            payments: data.payments,
            itemCount: result.items.length,
            feeStructure: feeStructure,
            hasCustomizations: Object.keys(customOverrides).length > 0,
            customizationCount: Object.keys(customOverrides).length,
            removedItemsCount: Object.keys(removedItems).length
        };
        
        period.hasBalance = period.total.balance > 0 || period.activity.itemsRemaining > 0;
        period.isFullyPaid = !period.hasBalance && period.total.paid > 0;
        
        previousPeriods.push(period);
    }
    
    // Sort previous periods: newest first
    previousPeriods.sort((a, b) => (b.year - a.year) || (b.term - a.term));

    // ================================================================
    // CALCULATE TOTALS
    // ================================================================
    let totalPreviousBalance = 0, totalPreviousItems = 0;
    for (const p of previousPeriods) {
        totalPreviousBalance += p.total.balance || 0;
        totalPreviousItems += p.activity.itemsRemaining || 0;
    }

    // ================================================================
    // RETURN PERIOD DATA
    // ================================================================
    return {
        success: true,
        currentPeriod: currentPeriod,
        previousPeriods: previousPeriods,
        totalPreviousBalance: totalPreviousBalance,
        totalPreviousItems: totalPreviousItems,
        feeStructure: feeStructure,
        metadata: {
            currentYear: currentYear,
            currentTerm: currentTerm,
            isFirstTerm: currentTerm === 1,
            totalPeriods: 1 + previousPeriods.length,
            periodsWithBalance: previousPeriods.filter(p => p.hasBalance).length,
            hasCustomizations: Object.keys(customOverrides).length > 0,
            hasRemovedItems: Object.keys(removedItems).length > 0,
            hasCustomBursary: !!(customBursary && customBursary.amount > 0),
            hasCustomTransportation: !!(customTransportation && customTransportation.hasTransportation !== false),
            totalItems: currentPeriod.activity.items.length + previousPeriods.reduce((sum, p) => sum + p.activity.items.length, 0),
            totalPayments: allPayments.length
        }
    };
}

async function rebuildPeriodData(periodData, student, currentYear, currentTerm) {
    console.log('=== REBUILD PERIOD DATA WITH CORRECT STATISTICS ===');
    
    const currentPeriodKey = `${currentYear}_${currentTerm}`;
    let currentPeriod = periodData.currentPeriod;
    
    // If current period doesn't exist or needs rebuilding
    if (!currentPeriod || currentPeriod.periodKey !== currentPeriodKey) {
        console.log('🔄 Rebuilding current period...');
        
        let feeStructure = periodData.feeStructure || null;
        
        // Try to get fee structure
        if (!feeStructure && student.assignedFeeStructureId) {
            try {
                const fsRes = await fetch(`/api/fee/structures`);
                if (fsRes.ok) {
                    const structures = await fsRes.json();
                    feeStructure = structures.find(f => f.id === student.assignedFeeStructureId);
                }
            } catch (e) {
                console.warn('Could not load fee structure:', e);
            }
        }
        
        if (!feeStructure && periodData.previousPeriods) {
            for (const prevPeriod of periodData.previousPeriods) {
                if (prevPeriod.feeStructure) {
                    feeStructure = prevPeriod.feeStructure;
                    break;
                }
            }
        }
        
        // Build period from fee structure
        currentPeriod = buildPeriodFromFeeStructure(student, feeStructure, currentYear, currentTerm);
        periodData.currentPeriod = currentPeriod;
    } else {
        console.log('✅ Current period exists, recalculating totals...');
        // Recalculate totals to ensure consistency
        currentPeriod = recalculatePeriodTotals(currentPeriod, student);
        periodData.currentPeriod = currentPeriod;
    }
    
    // Also rebuild previous periods for consistency
    if (periodData.previousPeriods) {
        periodData.previousPeriods = periodData.previousPeriods.map(p => 
            recalculatePeriodTotals(p, student)
        );
    }
    
    return periodData;
}

function buildPeriodFromFeeStructure(student, feeStructure, year, term) {
    console.log(`📋 Building period: ${year} Term ${term}`);
    
    const isFirstTerm = term === 1;
    const removedItems = student.removedItems || {};
    const customOverrides = student.customItemOverrides || {};
    const customTransportation = student.customTransportation || null;
    const customBursary = student.customBursary || null;
    
    // Calculate tuition with bursary
    let tuitionExpected = feeStructure?.tuition || 0;
    let bursaryAmount = 0;
    let bursaryName = null;
    let isCustomBursary = false;
    
    if (customBursary && customBursary.amount > 0) {
        bursaryAmount = customBursary.amount;
        bursaryName = 'Custom Bursary';
        isCustomBursary = true;
        tuitionExpected = Math.max(0, tuitionExpected - bursaryAmount);
    }
    
    // Build activity items
    const activityItems = [];
    let totalActivityExpected = 0;
    let totalActivityCashExpected = 0;
    let totalCashPaid = 0;
    let totalItemsBrought = 0;
    let totalItemsRequired = 0;
    let totalItemsRemaining = 0;
    
    const statusGroupBreakdown = {};
    
    if (feeStructure && feeStructure.activityComponents) {
        for (const component of feeStructure.activityComponents) {
            const periodType = component.periodType || 'termly';
            
            // Determine if this component should be included
            let shouldInclude = false;
            if (periodType === 'termly') shouldInclude = true;
            else if (periodType === 'one_time') shouldInclude = true;
            else if (periodType === 'yearly') shouldInclude = isFirstTerm;
            
            if (!shouldInclude) continue;
            
            const groupName = component.statusGroupName || component.name || 'Other';
            const isTransportation = component.name.toLowerCase().includes('transport') ||
                                    (component.statusGroupName && component.statusGroupName.toLowerCase().includes('transport'));
            
            if (!statusGroupBreakdown[groupName]) {
                statusGroupBreakdown[groupName] = {
                    name: groupName,
                    componentName: component.name,
                    periodType: periodType,
                    items: [],
                    totalExpected: 0,
                    totalPaid: 0,
                    totalBalance: 0,
                    itemsRemaining: 0,
                    itemsBrought: 0,
                    itemsRequired: 0
                };
            }
            
            for (const item of (component.items || [])) {
                const itemId = item.id || item.name;
                
                // Skip removed items
                if (removedItems[itemId] && removedItems[itemId].isActive !== false) {
                    console.log(`⏭️ Skipping removed item: ${item.name}`);
                    continue;
                }
                
                let totalAmount = item.totalAmount || 0;
                let quantity = item.quantity || 1;
                let unitPrice = item.unitPrice || (totalAmount / quantity);
                let paymentOption = item.paymentOption || 'either';
                
                // Apply custom override
                if (customOverrides && customOverrides[itemId]) {
                    const custom = customOverrides[itemId];
                    if (custom.isActive !== false) {
                        if (custom.customAmount !== null && custom.customAmount !== undefined && custom.customAmount > 0) {
                            totalAmount = custom.customAmount;
                        }
                        if (custom.customQuantity !== null && custom.customQuantity !== undefined && custom.customQuantity > 0) {
                            quantity = custom.customQuantity;
                        }
                        if (custom.paymentOption) {
                            paymentOption = custom.paymentOption;
                        }
                    }
                }
                
                // Handle custom transportation
                if (isTransportation && customTransportation) {
                    if (customTransportation.hasTransportation === false) {
                        console.log(`🚌 Transportation disabled: ${item.name}`);
                        continue;
                    }
                    if (customTransportation.amount) {
                        totalAmount = customTransportation.amount;
                        unitPrice = totalAmount / quantity;
                    }
                }
                
                // Determine if this item has been paid
                let cashPaid = 0;
                let itemsBrought = 0;
                
                // Check payments in this period
                if (currentPeriod && currentPeriod.payments) {
                    for (const payment of currentPeriod.payments) {
                        // Check activityItemPayments
                        if (payment.activityItemPayments) {
                            for (const paidItem of payment.activityItemPayments) {
                                if (paidItem.itemName === item.name && 
                                    paidItem.componentName === component.name &&
                                    paidItem.periodType === periodType) {
                                    if (paidItem.paymentType === 'paid_cash') {
                                        cashPaid += paidItem.amountPaid || 0;
                                    } else if (paidItem.paymentType === 'brought_item') {
                                        itemsBrought += paidItem.itemsBrought || 0;
                                    }
                                }
                            }
                        }
                        
                        // Check paymentsByPeriodType
                        if (payment.paymentsByPeriodType) {
                            const periodItems = payment.paymentsByPeriodType[periodType] || [];
                            for (const paidItem of periodItems) {
                                if (paidItem.itemName === item.name && 
                                    paidItem.componentName === component.name) {
                                    if (paidItem.paymentType === 'paid_cash') {
                                        cashPaid += paidItem.amountPaid || 0;
                                    } else if (paidItem.paymentType === 'brought_item') {
                                        itemsBrought += paidItem.itemsBrought || 0;
                                    }
                                }
                            }
                        }
                    }
                }
                
                // Also check previous periods for one-time items
                if (periodType === 'one_time' && periodData && periodData.previousPeriods) {
                    for (const prevPeriod of periodData.previousPeriods) {
                        if (prevPeriod.payments) {
                            for (const payment of prevPeriod.payments) {
                                if (payment.activityItemPayments) {
                                    for (const paidItem of payment.activityItemPayments) {
                                        if (paidItem.itemName === item.name && 
                                            paidItem.componentName === component.name &&
                                            paidItem.periodType === periodType) {
                                            if (paidItem.paymentType === 'paid_cash') {
                                                cashPaid += paidItem.amountPaid || 0;
                                            } else if (paidItem.paymentType === 'brought_item') {
                                                itemsBrought += paidItem.itemsBrought || 0;
                                            }
                                        }
                                    }
                                }
                            }
                        }
                    }
                }
                
                // Calculate remaining using OR logic
                const result = calculateRemainingWithORLogic(
                    { quantity, totalAmount, unitPrice, paymentOption },
                    cashPaid,
                    itemsBrought
                );
                
                const remainingAmount = result.remainingCash;
                const remainingQuantity = result.remainingItems;
                const isFullyPaid = result.isFullyPaid;
                
                // Calculate cash expected for this item
                let cashExpected = 0;
                if (paymentOption === 'cash_only') {
                    cashExpected = totalAmount;
                } else if (paymentOption === 'either') {
                    const itemsBroughtCapped = Math.min(itemsBrought, quantity);
                    cashExpected = Math.max(0, totalAmount - (itemsBroughtCapped * unitPrice));
                } else {
                    cashExpected = 0;
                }
                
                // Update totals
                totalActivityExpected += totalAmount;
                totalActivityCashExpected += cashExpected;
                totalCashPaid += cashPaid;
                totalItemsBrought += Math.min(itemsBrought, quantity);
                totalItemsRequired += quantity;
                totalItemsRemaining += remainingQuantity;
                
                const itemData = {
                    componentId: component.id || component.name,
                    componentName: component.name,
                    periodType: periodType,
                    itemId: itemId,
                    itemName: item.name,
                    quantity: quantity,
                    totalAmount: totalAmount,
                    unitPrice: unitPrice,
                    paymentOption: paymentOption,
                    cashExpected: cashExpected,
                    cashPaid: cashPaid,
                    itemsBrought: Math.min(itemsBrought, quantity),
                    remainingAmount: remainingAmount,
                    remainingQuantity: remainingQuantity,
                    isFullyPaid: isFullyPaid,
                    isCustomized: !!(customOverrides && customOverrides[itemId]),
                    customReason: customOverrides?.[itemId]?.reason || null,
                    statusGroupName: groupName,
                    isTransportation: isTransportation,
                    isSpecialItem: isTransportation || paymentOption === 'cash_only' || paymentOption === 'item_only',
                    paymentHistories: []
                };
                
                activityItems.push(itemData);
                statusGroupBreakdown[groupName].items.push(itemData);
                statusGroupBreakdown[groupName].totalExpected += totalAmount;
                statusGroupBreakdown[groupName].totalPaid += cashPaid;
                statusGroupBreakdown[groupName].totalBalance += remainingAmount;
                statusGroupBreakdown[groupName].itemsRemaining += remainingQuantity;
                statusGroupBreakdown[groupName].itemsBrought += Math.min(itemsBrought, quantity);
                statusGroupBreakdown[groupName].itemsRequired += quantity;
            }
        }
    }
    
    // Build the period object
    const period = {
        periodKey: `${year}_${term}`,
        year: year,
        term: term,
        isCurrent: true,
        isEmpty: activityItems.length === 0 && tuitionExpected === 0,
        isFullyPaid: false,
        hasBalance: false,
        tuition: {
            expected: tuitionExpected,
            paid: 0,
            balance: tuitionExpected,
            bursaryAmount: bursaryAmount,
            bursaryName: bursaryName,
            isCustomBursary: isCustomBursary
        },
        activity: {
            expected: totalActivityExpected,
            cashExpected: totalActivityCashExpected,
            paid: totalCashPaid,
            balance: totalActivityCashExpected - totalCashPaid,
            itemsRequired: totalItemsRequired,
            itemsBrought: totalItemsBrought,
            itemsRemaining: totalItemsRemaining,
            items: activityItems
        },
        total: {
            expected: tuitionExpected + totalActivityExpected,
            paid: totalCashPaid,
            balance: tuitionExpected + totalActivityCashExpected - totalCashPaid
        },
        statusGroupBreakdown: statusGroupBreakdown,
        payments: currentPeriod?.payments || [],
        itemCount: activityItems.length,
        feeStructure: feeStructure,
        hasCustomizations: Object.keys(customOverrides).length > 0,
        customizationCount: Object.keys(customOverrides).length
    };
    
    // Set flags
    period.hasBalance = period.total.balance > 0 || period.activity.itemsRemaining > 0;
    period.isFullyPaid = !period.hasBalance && period.total.paid > 0;
    
    console.log(`✅ Period built: ${year} Term ${term}`);
    console.log(`   Total Expected: UGX ${formatMoney(period.total.expected)}`);
    console.log(`   Total Paid: UGX ${formatMoney(period.total.paid)}`);
    console.log(`   Total Balance: UGX ${formatMoney(period.total.balance)}`);
    console.log(`   Items Remaining: ${period.activity.itemsRemaining}`);
    console.log(`   Items Brought: ${period.activity.itemsBrought}`);
    
    return period;
}

function recalculatePeriodTotals(period, student) {
    if (!period || !period.activity || !period.activity.items) {
        return period;
    }
    
    console.log(`🔄 Recalculating totals for ${period.year} Term ${period.term}`);
    
    const removedItems = student?.removedItems || {};
    let totalCashPaid = 0;
    let totalItemsBrought = 0;
    let totalItemsRemaining = 0;
    let totalBalance = 0;
    
    // Filter out removed items and recalculate
    const filteredItems = period.activity.items.filter(item => {
        const itemId = item.itemId || item.name;
        return !(removedItems[itemId] && removedItems[itemId].isActive !== false);
    });
    
    // Recalculate each item
    const recalculatedItems = filteredItems.map(item => {
        const { quantity, totalAmount, unitPrice, paymentOption, cashPaid, itemsBrought } = item;
        
        const result = calculateRemainingWithORLogic(
            { quantity, totalAmount, unitPrice, paymentOption },
            cashPaid,
            itemsBrought
        );
        
        totalCashPaid += cashPaid;
        totalItemsBrought += Math.min(itemsBrought, quantity);
        totalItemsRemaining += result.remainingItems;
        totalBalance += result.remainingCash;
        
        return {
            ...item,
            remainingAmount: result.remainingCash,
            remainingQuantity: result.remainingItems,
            isFullyPaid: result.isFullyPaid
        };
    });
    
    // Update period totals
    period.activity.items = recalculatedItems;
    period.activity.itemsRemaining = totalItemsRemaining;
    period.activity.itemsBrought = totalItemsBrought;
    period.activity.balance = totalBalance;
    period.activity.paid = totalCashPaid;
    
    period.total.balance = (period.tuition?.balance || 0) + totalBalance;
    period.total.paid = totalCashPaid;
    
    period.hasBalance = period.total.balance > 0 || period.activity.itemsRemaining > 0;
    period.isFullyPaid = !period.hasBalance && period.total.paid > 0;
    
    // Recalculate status groups
    if (period.statusGroupBreakdown) {
        for (const [sgName, sgData] of Object.entries(period.statusGroupBreakdown)) {
            const sgItems = sgData.items || [];
            let sgTotalExpected = 0;
            let sgTotalPaid = 0;
            let sgTotalBalance = 0;
            let sgItemsRemaining = 0;
            let sgItemsBrought = 0;
            let sgItemsRequired = 0;
            
            for (const item of sgItems) {
                // Find the recalculated item
                const recalcItem = recalculatedItems.find(i => i.itemId === item.itemId && i.itemName === item.itemName);
                if (recalcItem) {
                    sgTotalExpected += recalcItem.totalAmount || 0;
                    sgTotalPaid += recalcItem.cashPaid || 0;
                    sgTotalBalance += recalcItem.remainingAmount || 0;
                    sgItemsRemaining += recalcItem.remainingQuantity || 0;
                    sgItemsBrought += Math.min(recalcItem.itemsBrought || 0, recalcItem.quantity || 1);
                    sgItemsRequired += recalcItem.quantity || 1;
                }
            }
            
            sgData.totalExpected = sgTotalExpected;
            sgData.totalPaid = sgTotalPaid;
            sgData.totalBalance = sgTotalBalance;
            sgData.itemsRemaining = sgItemsRemaining;
            sgData.itemsBrought = sgItemsBrought;
            sgData.itemsRequired = sgItemsRequired;
        }
    }
    
    return period;
}

function calculateRemainingWithORLogic(item, cashPaid, itemsBrought) {
    const { quantity, totalAmount, unitPrice, paymentOption } = item;
    
    if (paymentOption === 'cash_only') {
        const remainingCash = Math.max(0, totalAmount - cashPaid);
        return { 
            remainingCash, 
            remainingItems: 0, 
            isFullyPaid: remainingCash === 0 
        };
    }
    
    if (paymentOption === 'item_only') {
        const remainingItems = Math.max(0, quantity - itemsBrought);
        return { 
            remainingCash: 0, 
            remainingItems, 
            isFullyPaid: remainingItems === 0 
        };
    }
    
    // EITHER (OR Logic)
    const itemsBroughtCapped = Math.min(itemsBrought, quantity);
    const cashValueOfItems = itemsBroughtCapped * unitPrice;
    const remainingCash = Math.max(0, totalAmount - cashPaid - cashValueOfItems);
    const itemsCoveredByCash = unitPrice > 0 ? Math.floor(cashPaid / unitPrice) : 0;
    const remainingItems = Math.max(0, quantity - itemsBroughtCapped - itemsCoveredByCash);
    const totalValueCovered = cashPaid + (itemsBroughtCapped * unitPrice);
    const totalRequired = quantity * unitPrice;
    const isFullyPaid = totalValueCovered >= totalRequired;
    
    return { remainingCash, remainingItems, isFullyPaid };
}

// ========== HELPER: FILTER VALID PERIODS ==========
function filterValidPeriods(periods, currentYear, currentTerm) {
    if (!periods || periods.length === 0) return [];
    
    return periods.filter(period => {
        // Skip if period is in the future
        if (period.year > currentYear) return false;
        if (period.year === currentYear && period.term > currentTerm) return false;
        
        // Keep if period is in the past or current
        return true;
    });
}

