// ==================== HELPER: GET ITEM PAYMENT HISTORIES ====================
// Used to determine if an item has been paid with cash or items

function getItemPaymentHistories(periodKey, componentName, itemName, periodType) {
    const histories = [];
    
    // Search in the current period's payment histories
    const periodData = window.multiPeriodData;
    if (!periodData) return histories;
    
    // Find the period
    let period = null;
    if (periodData.currentPeriod && periodData.currentPeriod.periodKey === periodKey) {
        period = periodData.currentPeriod;
    } else if (periodData.previousPeriods) {
        period = periodData.previousPeriods.find(p => p.periodKey === periodKey);
    }
    
    if (!period) return histories;
    
    // Check payments in this period
    if (period.payments) {
        for (const payment of period.payments) {
            // Check activityItemPayments
            if (payment.activityItemPayments) {
                for (const item of payment.activityItemPayments) {
                    if (item.componentName === componentName && 
                        item.itemName === itemName && 
                        item.periodType === periodType) {
                        if (item.paymentType === 'paid_cash') {
                            histories.push({ 
                                type: 'cash', 
                                amount: item.amountPaid || 0,
                                date: payment.date
                            });
                        } else if (item.paymentType === 'brought_item') {
                            histories.push({ 
                                type: 'item', 
                                itemsBrought: item.itemsBrought || 0,
                                date: payment.date
                            });
                        }
                    }
                }
            }
            
            // Check paymentsByPeriodType
            if (payment.paymentsByPeriodType) {
                const periodItems = payment.paymentsByPeriodType[periodType] || [];
                for (const item of periodItems) {
                    if (item.componentName === componentName && 
                        item.itemName === itemName) {
                        if (item.paymentType === 'paid_cash') {
                            histories.push({ 
                                type: 'cash', 
                                amount: item.amountPaid || 0,
                                date: payment.date
                            });
                        } else if (item.paymentType === 'brought_item') {
                            histories.push({ 
                                type: 'item', 
                                itemsBrought: item.itemsBrought || 0,
                                date: payment.date
                            });
                        }
                    }
                }
            }
        }
    }
    
    return histories;
}
