// ========== PAY FULL PERIOD ==========
function payFullPeriod(periodKey, balance) {
    if (!balance || balance <= 0) {
        showToast('No balance to pay for this period', 'warning');
        return;
    }
    
    const periodData = window.multiPeriodData;
    if (!periodData) { 
        showToast('Period data not loaded', 'error');
        return; 
    }
    
    let period = null;
    let isCurrent = false;
    
    if (periodData.currentPeriod && periodData.currentPeriod.periodKey === periodKey) {
        period = periodData.currentPeriod;
        isCurrent = true;
    } else if (periodData.previousPeriods) {
        period = periodData.previousPeriods.find(p => p.periodKey === periodKey);
    }
    
    if (!period) { 
        showToast('Period not found', 'error');
        return; 
    }
    
    const periodLabel = isCurrent ? 'Current Period' : `${period.year} Term ${period.term}`;
    
    const confirmed = confirm(
        `⚠️ Pay full balance for ${periodLabel}?\n\n` +
        `💰 Amount: UGX ${formatMoney(balance)}\n` +
        `📦 Items: ${period.activity?.itemsRemaining || 0} item(s) remaining\n\n` +
        `This will mark this period as fully paid.`
    );
    
    if (!confirmed) return;
    
    const tuitionInput = document.getElementById(`tuitionAmount_${periodKey}`);
    if (tuitionInput) {
        tuitionInput.value = balance;
        tuitionInput.dispatchEvent(new Event('input'));
    }
    
    document.querySelectorAll(`#periodItems_${periodKey} .cash-amount-input`).forEach(input => {
        const maxCash = parseFloat(input.dataset.maxCash) || 0;
        if (maxCash > 0) { input.value = maxCash; input.dispatchEvent(new Event('input')); }
    });
    
    document.querySelectorAll(`#periodItems_${periodKey} .item-quantity-input`).forEach(input => {
        const maxItems = parseFloat(input.dataset.maxItems) || 0;
        if (maxItems > 0) { input.value = maxItems; input.dispatchEvent(new Event('input')); }
    });
    
    updatePeriodTotal(periodKey);
    submitPeriodPayment(periodKey);
}

// ========== RESET PERIOD FORM ==========
function resetPeriodForm(periodKey) {
    document.querySelectorAll(`#periodItems_${periodKey} .cash-amount-input`).forEach(input => {
        input.value = '0';
        input.dispatchEvent(new Event('input'));
    });
    
    document.querySelectorAll(`#periodItems_${periodKey} .item-quantity-input`).forEach(input => {
        input.value = '0';
        input.dispatchEvent(new Event('input'));
    });
    
    const tuitionInput = document.getElementById(`tuitionAmount_${periodKey}`);
    if (tuitionInput) tuitionInput.value = '0';
    
    const receiptInput = document.getElementById(`receiptNumber_${periodKey}`);
    if (receiptInput) receiptInput.value = '';
    const referenceInput = document.getElementById(`reference_${periodKey}`);
    if (referenceInput) referenceInput.value = '';
    const notesInput = document.getElementById(`notes_${periodKey}`);
    if (notesInput) notesInput.value = '';
    
    const currentDateTime = getCurrentDateTimeForInput();
    const dateInput = document.getElementById(`paymentDate_${periodKey}`);
    if (dateInput) dateInput.value = currentDateTime.date;
    const timeInput = document.getElementById(`paymentTime_${periodKey}`);
    if (timeInput) timeInput.value = currentDateTime.time;
    
    updatePeriodTotal(periodKey);
    showToast('✅ Form has been reset', 'success');
}

// ========== TOGGLE FUNCTIONS ==========
function togglePeriodForm(periodKey, collapseId, iconId) {
    const collapse = document.getElementById(collapseId);
    const icon = document.getElementById(iconId);
    
    if (!collapse) {
        console.warn('Collapse element not found for:', collapseId);
        return;
    }
    
    if (collapse.classList.contains('hidden')) {
        collapse.classList.remove('hidden');
        if (icon) {
            icon.classList.remove('fa-chevron-down');
            icon.classList.add('fa-chevron-up');
        }
        window.activeExpandedPeriod = periodKey;
    } else {
        collapse.classList.add('hidden');
        if (icon) {
            icon.classList.remove('fa-chevron-up');
            icon.classList.add('fa-chevron-down');
        }
        if (window.activeExpandedPeriod === periodKey) {
            window.activeExpandedPeriod = null;
        }
    }
}

function toggleStatusGroup(collapseId) {
    const element = document.getElementById(collapseId);
    if (!element) return;
    
    const icon = document.getElementById(`${collapseId}_icon`);
    
    if (element.classList.contains('hidden')) {
        element.classList.remove('hidden');
        if (icon) {
            icon.classList.remove('fa-chevron-down');
            icon.classList.add('fa-chevron-up');
        }
    } else {
        element.classList.add('hidden');
        if (icon) {
            icon.classList.remove('fa-chevron-up');
            icon.classList.add('fa-chevron-down');
        }
    }
}

function toggleItemHistory(historyId) {
    const element = document.getElementById(historyId);
    if (!element) return;
    
    if (!window.expandedHistories) window.expandedHistories = {};
    window.expandedHistories[historyId] = !window.expandedHistories[historyId];
    element.classList.toggle('hidden');
    
    const parentContainer = element.closest('.bg-white');
    if (parentContainer) {
        const button = parentContainer.querySelector('button');
        if (button) {
            const historyItems = element.querySelectorAll('.flex.justify-between.items-center').length;
            const isExpanded = window.expandedHistories[historyId];
            button.innerHTML = `
                <i class="fas ${isExpanded ? 'fa-chevron-up' : 'fa-chevron-down'}"></i>
                ${isExpanded ? 'Hide' : 'View'} History (${historyItems})
            `;
        }
    }
}

function expandAllPeriods() {
    document.querySelectorAll('[id^="periodCollapse_"]').forEach(el => {
        el.classList.remove('hidden');
    });
    document.querySelectorAll('[id^="periodIcon_"]').forEach(el => {
        el.classList.remove('fa-chevron-down');
        el.classList.add('fa-chevron-up');
    });
}

function collapseAllPeriods() {
    document.querySelectorAll('[id^="periodCollapse_"]').forEach(el => {
        const parent = el.closest('.border-2');
        if (parent && parent.classList.contains('border-blue-400')) return;
        el.classList.add('hidden');
    });
    document.querySelectorAll('[id^="periodIcon_"]').forEach(el => {
        const parent = el.closest('.border-2');
        if (parent && parent.classList.contains('border-blue-400')) {
            el.classList.remove('fa-chevron-down');
            el.classList.add('fa-chevron-up');
            return;
        }
        el.classList.remove('fa-chevron-up');
        el.classList.add('fa-chevron-down');
    });
}

function expandAllItems(periodKey) {
    const container = document.getElementById(`periodItems_${periodKey}`);
    if (!container) return;
    
    container.querySelectorAll('[id^="sg_"]').forEach(el => {
        el.classList.remove('hidden');
        const iconId = `${el.id}_icon`;
        const icon = document.getElementById(iconId);
        if (icon) {
            icon.classList.remove('fa-chevron-down');
            icon.classList.add('fa-chevron-up');
        }
    });
}

function toggleAllItems(periodKey) {
    const container = document.getElementById(`periodItems_${periodKey}`);
    if (!container) return;
    
    const allSgs = container.querySelectorAll('[id^="sg_"]');
    const areAllHidden = Array.from(allSgs).every(el => el.classList.contains('hidden'));
    
    allSgs.forEach(el => {
        if (areAllHidden) {
            el.classList.remove('hidden');
            const iconId = `${el.id}_icon`;
            const icon = document.getElementById(iconId);
            if (icon) {
                icon.classList.remove('fa-chevron-down');
                icon.classList.add('fa-chevron-up');
            }
        } else {
            el.classList.add('hidden');
            const iconId = `${el.id}_icon`;
            const icon = document.getElementById(iconId);
            if (icon) {
                icon.classList.remove('fa-chevron-up');
                icon.classList.add('fa-chevron-down');
            }
        }
    });
}

// ========== SEARCH AND FILTER ==========
function initializePeriodFilters() {
    filterPeriodItems();
}

function filterPeriodItems() {
    const searchTerm = (document.getElementById('periodItemSearch')?.value || '').toLowerCase().trim();
    const statusFilter = document.getElementById('periodStatusFilter')?.value || 'all';
    const typeFilter = document.getElementById('periodTypeFilter')?.value || 'all';
    
    const itemGroups = document.querySelectorAll('.item-group');
    let visibleCount = 0;
    
    itemGroups.forEach(group => {
        const items = group.querySelectorAll('[id^="item_"]');
        let groupHasVisible = false;
        
        items.forEach(item => {
            const nameEl = item.querySelector('.font-medium');
            const itemName = nameEl ? nameEl.innerText.replace('📦', '').trim().toLowerCase() : '';
            const status = item.dataset.itemStatus || 'unpaid';
            const periodType = item.dataset.itemPeriod || 'termly';
            
            let matchesSearch = true;
            if (searchTerm) matchesSearch = itemName.includes(searchTerm);
            
            let matchesStatus = true;
            if (statusFilter !== 'all') matchesStatus = status === statusFilter;
            
            let matchesType = true;
            if (typeFilter !== 'all') matchesType = periodType === typeFilter;
            
            const isVisible = matchesSearch && matchesStatus && matchesType;
            item.style.display = isVisible ? '' : 'none';
            if (isVisible) groupHasVisible = true;
        });
        
        group.style.display = groupHasVisible ? '' : 'none';
        if (groupHasVisible) visibleCount++;
    });
}

function clearPeriodFilters() {
    const searchInput = document.getElementById('periodItemSearch');
    const statusFilter = document.getElementById('periodStatusFilter');
    const typeFilter = document.getElementById('periodTypeFilter');
    
    if (searchInput) searchInput.value = '';
    if (statusFilter) statusFilter.value = 'all';
    if (typeFilter) typeFilter.value = 'all';
    
    filterPeriodItems();
    showToast('Filters cleared', 'info');
}

