// ==================== SET PARTIAL AMOUNT ====================
function setPartialAmount(percentage) {
    const input = document.getElementById('partialPaymentAmount');
    if (!input) return;
    
    const max = parseFloat(input.max) || 0;
    const amount = Math.round((max * percentage) / 100);
    input.value = amount;
    
    // Highlight the input
    input.style.borderColor = '#f59e0b';
    input.style.backgroundColor = '#fef3c7';
    setTimeout(() => {
        input.style.borderColor = '';
        input.style.backgroundColor = '';
    }, 1000);
}

// ==================== CLOSE PARTIAL PAYMENT MODAL ====================
function closePartialPaymentModal() {
    const modal = document.getElementById('partialPaymentModal');
    if (modal) modal.remove();
}

// ==================== SUBMIT PARTIAL PAYMENT ====================
async function submitPartialPayment(studentId, year, term, maxBalance) {
    console.log('=== SUBMIT PARTIAL PAYMENT ===');
    
    const amountInput = document.getElementById('partialPaymentAmount');
    if (!amountInput) return;
    
    const amount = Math.round(parseFloat(amountInput.value) || 0);
    
    // Validate
    if (amount <= 0) {
        alert('⚠️ Please enter a valid amount');
        amountInput.focus();
        return;
    }
    
    if (amount > maxBalance) {
        alert(`⚠️ Amount cannot exceed UGX ${formatMoney(maxBalance)}`);
        amountInput.focus();
        return;
    }
    
    // Confirm
    const student = window.currentCollectingStudent;
    const itemsRemaining = student?.totalUnpaidItems || 0;
    
    const confirmed = confirm(
        `⚠️ Pay partial previous balance?\n\n` +
        `📅 Period: ${year} Term ${term}\n` +
        `💰 Amount: UGX ${formatMoney(amount)}\n` +
        `📊 Remaining: UGX ${formatMoney(maxBalance - amount)}\n` +
        `📦 Items remaining: ${itemsRemaining}\n\n` +
        `This payment will be recorded for ${year} Term ${term}.`
    );
    
    if (!confirmed) return;
    
    // Close modal
    closePartialPaymentModal();
    
    // Set the global target and trigger submission
    window.previousBalancePaymentTarget = {
        year: parseInt(year),
        term: parseInt(term)
    };
    window.isBulkPayment = false;
    window.bulkPaymentId = null;
    
    // Set the tuition amount to the partial amount
    const tuitionInput = document.getElementById('tuitionAmount');
    if (tuitionInput) {
        tuitionInput.value = amount;
        tuitionInput.dispatchEvent(new Event('input'));
    }
    
    // Submit the payment
    await submitCollectionPaymentFixed();
}

// ==================== PAY ALL PREVIOUS BALANCES ====================
async function payAllPreviousBalances() {
    console.log('=== PAY ALL PREVIOUS BALANCES ===');
    
    const student = window.currentCollectingStudent;
    if (!student) {
        alert('Student data not loaded');
        return;
    }
    
    const previousBalances = student.previousBalances || [];
    if (previousBalances.length === 0) {
        alert('No previous balances to pay');
        return;
    }
    
    const totalBalance = previousBalances.reduce((sum, p) => sum + p.balance, 0);
    const totalItems = previousBalances.reduce((sum, p) => sum + (p.totalUnpaidItems || 0), 0);
    
    if (totalBalance <= 0) {
        alert('No outstanding previous balances');
        return;
    }
    
    // Show confirmation with breakdown
    let breakdownMsg = '📋 Balance Breakdown:\n\n';
    for (const period of previousBalances) {
        breakdownMsg += `   📅 ${period.year} Term ${period.term}: UGX ${formatMoney(period.balance)}\n`;
        if (period.totalUnpaidItems > 0) {
            breakdownMsg += `      📦 ${period.totalUnpaidItems} item(s) remaining\n`;
        }
    }
    breakdownMsg += `\n${'='.repeat(40)}\n`;
    breakdownMsg += `💰 TOTAL: UGX ${formatMoney(totalBalance)}\n`;
    breakdownMsg += `📦 TOTAL ITEMS: ${totalItems} item(s)`;
    
    const confirmed = confirm(
        `⚠️ Pay ALL previous balances?\n\n` +
        `This will pay ${previousBalances.length} period(s) totaling UGX ${formatMoney(totalBalance)}.\n\n` +
        breakdownMsg
    );
    
    if (!confirmed) return;
    
    // Set bulk payment flag
    window.isBulkPayment = true;
    window.bulkPaymentId = 'bulk_' + Date.now().toString();
    
    // Pay each period sequentially
    let successCount = 0;
    let failCount = 0;
    let totalPaid = 0;
    
    for (const period of previousBalances) {
        // Set target for this period
        window.previousBalancePaymentTarget = {
            year: parseInt(period.year),
            term: parseInt(period.term)
        };
        
        // Set the tuition amount to this period's balance
        const tuitionInput = document.getElementById('tuitionAmount');
        if (tuitionInput) {
            tuitionInput.value = period.balance;
            tuitionInput.dispatchEvent(new Event('input'));
        }
        
        // Submit payment for this period
        try {
            const payload = {
                studentId: student.id,
                studentName: `${student.firstName} ${student.lastName}`,
                admissionNumber: student.admissionNumber,
                term: parseInt(period.term),
                academicYear: period.year.toString(),
                feeStructureId: student.feeStructure?.id || null,
                feeStructureName: student.feeStructure?.name || 'General Fee',
                bursaryId: student.appliedBursary?.id || null,
                bursaryName: student.appliedBursary?.name || null,
                tuitionPaid: Math.round(period.balance),
                activityItemPayments: [],
                totalAmount: Math.round(period.balance),
                method: document.getElementById('paymentMethodSelect')?.value || 'cash',
                receiptNumber: `PB${Date.now().toString().slice(-6)}${Math.floor(Math.random() * 900 + 100).toString()}`,
                reference: document.getElementById('paymentReference')?.value || `Bulk payment - ${period.year} Term ${period.term}`,
                notes: `Paid as part of bulk previous balance settlement`,
                hasCustomizations: false,
                customItemsCount: 0,
                studentCustomOverrides: student.customItemOverrides || {},
                hasPartialPayments: false,
                partialPaymentsCount: 0,
                isPreviousBalancePayment: true,
                targetPeriodYear: period.year.toString(),
                targetPeriodTerm: parseInt(period.term),
                originalPeriod: {
                    year: currentAcademicSettings.currentYear,
                    term: currentAcademicSettings.currentTerm
                },
                isBulkPayment: true,
                bulkPaymentId: window.bulkPaymentId
            };
            
            const response = await fetch('/api/fee/payments/enhanced', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(payload)
            });
            
            if (response.ok) {
                successCount++;
                totalPaid += period.balance;
            } else {
                failCount++;
                console.error('Failed to pay period:', period);
            }
        } catch (e) {
            failCount++;
            console.error('Error paying period:', period, e);
        }
    }
    
    // Clear bulk flags
    window.isBulkPayment = false;
    window.bulkPaymentId = null;
    window.previousBalancePaymentTarget = null;
    
    // Show result
    const displayDate = new Date().toLocaleString();
    alert(
        `✅ Bulk previous balance payment completed!\n\n` +
        `📊 ${successCount} period(s) paid successfully\n` +
        `${failCount > 0 ? `⚠️ ${failCount} period(s) failed\n` : ''}` +
        `💰 Total Paid: UGX ${formatMoney(totalPaid)}\n` +
        `📆 Processed at: ${displayDate}`
    );
    
    // Refresh the collection form
    if (student && student.id) {
        const { currentYear, currentTerm } = currentAcademicSettings;
        const termName = getTermName(currentTerm);
        await loadCollectionForm(student, currentYear, currentTerm, termName);
    } else {
        showFeeManagement();
    }
}

// ==================== TOGGLE PREVIOUS BALANCES ====================
function togglePreviousBalances() {
    const content = document.getElementById('previousBalancesContent');
    const icon = document.getElementById('prevBalancesIcon');
    
    if (!content) return;
    
    if (content.classList.contains('hidden')) {
        content.classList.remove('hidden');
        if (icon) {
            icon.classList.remove('fa-chevron-down');
            icon.classList.add('fa-chevron-up');
        }
    } else {
        content.classList.add('hidden');
        if (icon) {
            icon.classList.remove('fa-chevron-up');
            icon.classList.add('fa-chevron-down');
        }
    }
}

// ==================== TOGGLE PERIOD HISTORY ====================
function togglePeriodHistory(year, term) {
    const elementId = `periodHistory_${year}_${term}`;
    const element = document.getElementById(elementId);
    const icon = document.querySelector(`[onclick="togglePeriodHistory('${year}', '${term}')"] i`);
    
    if (!element) return;
    
    if (element.classList.contains('hidden')) {
        element.classList.remove('hidden');
        if (icon) {
            icon.classList.remove('fa-chevron-down');
            icon.classList.add('fa-chevron-up');
        }
        // Load history if not loaded
        loadPeriodPaymentHistory(year, term);
    } else {
        element.classList.add('hidden');
        if (icon) {
            icon.classList.remove('fa-chevron-up');
            icon.classList.add('fa-chevron-down');
        }
    }
}

// ==================== LOAD PERIOD PAYMENT HISTORY ====================
async function loadPeriodPaymentHistory(year, term) {
    const student = window.currentCollectingStudent;
    if (!student) return;
    
    const container = document.getElementById(`periodHistory_${year}_${term}`);
    if (!container) return;
    
    // Check if already loaded
    if (container.dataset.loaded === 'true') return;
    
    try {
        const response = await fetch(`/api/students/${student.id}/period-history/${year}/${term}`);
        if (response.ok) {
            const data = await response.json();
            if (data.success && data.payments && data.payments.length > 0) {
                // Update the container with payment history
                let historyHtml = '<p class="text-sm font-semibold mb-2">📜 Payment History:</p>';
                historyHtml += '<div class="max-h-48 overflow-y-auto">';
                
                for (const payment of data.payments) {
                    const isPrev = payment.isPreviousBalancePayment || false;
                    const prevBadge = isPrev ? ' <span class="text-xs text-amber-500">(Previous)</span>' : '';
                    historyHtml += `
                        <div class="flex justify-between text-sm border-b py-1">
                            <span>${new Date(payment.date).toLocaleDateString()}</span>
                            <span class="font-mono">${payment.receiptNumber || 'N/A'}</span>
                            <span class="font-semibold text-green-600">UGX ${formatMoney(payment.amount)}</span>
                            <span class="text-gray-500">${payment.method}</span>
                            ${prevBadge}
                        </div>
                    `;
                }
                
                historyHtml += '</div>';
                
                // Add summary
                if (data.summary) {
                    historyHtml += `
                        <div class="mt-2 pt-2 border-t text-sm">
                            <div class="flex justify-between">
                                <span>Total Paid:</span>
                                <span class="font-semibold text-green-600">UGX ${formatMoney(data.summary.totalPaid)}</span>
                            </div>
                            <div class="flex justify-between">
                                <span>Expected:</span>
                                <span class="font-semibold">UGX ${formatMoney(data.expected?.total || 0)}</span>
                            </div>
                            <div class="flex justify-between font-bold">
                                <span>Balance:</span>
                                <span class="${data.summary.balance > 0 ? 'text-red-600' : 'text-green-600'}">
                                    UGX ${formatMoney(Math.abs(data.summary.balance))}
                                    ${data.summary.balance > 0 ? ' (Due)' : ' (Paid)'}
                                </span>
                            </div>
                            ${data.summary.paymentCount > 0 ? `
                                <div class="flex justify-between text-xs text-gray-500 mt-1">
                                    <span>${data.summary.paymentCount} payment(s)</span>
                                    ${Object.keys(data.summary.paymentMethods || {}).map(m => 
                                        `${m.toUpperCase()}: ${data.summary.paymentMethods[m]}`
                                    ).join(' | ')}
                                </div>
                            ` : ''}
                        </div>
                    `;
                }
                
                container.innerHTML = historyHtml;
                container.dataset.loaded = 'true';
            } else {
                container.innerHTML = `
                    <p class="text-sm text-gray-500">No payment records found for this period</p>
                `;
                container.dataset.loaded = 'true';
            }
        }
    } catch (error) {
        console.error('Error loading period history:', error);
        container.innerHTML = `
            <p class="text-sm text-red-500">Error loading payment history</p>
        `;
    }
}

