// ========== PAY ALL PREVIOUS BALANCES ==========
async function payAllPreviousBalances() {
    console.log('=== PAY ALL PREVIOUS BALANCES ===');
    
    const previousBalances = window.previousBalancesData || [];
    if (previousBalances.length === 0) {
        alert('No previous balances to pay');
        return;
    }
    
    const totalBalance = previousBalances.reduce((sum, p) => sum + p.balance, 0);
    
    if (totalBalance <= 0) {
        alert('No outstanding previous balances');
        return;
    }
    
    // Show confirmation with breakdown
    let breakdownMsg = '📋 Balance Breakdown:\n\n';
    for (const period of previousBalances) {
        breakdownMsg += `   📅 ${period.year} Term ${period.term}: UGX ${formatMoney(period.balance)}\n`;
    }
    breakdownMsg += `\n${'='.repeat(40)}\n`;
    breakdownMsg += `💰 TOTAL: UGX ${formatMoney(totalBalance)}`;
    
    const confirmed = confirm(
        `⚠️ Pay ALL previous balances?\n\n` +
        `This will pay ${previousBalances.length} period(s) totaling UGX ${formatMoney(totalBalance)}.\n\n` +
        breakdownMsg
    );
    
    if (!confirmed) return;
    
    // Set bulk payment flag
    window.isBulkPayment = true;
    window.bulkPaymentId = 'bulk_' + Date.now().toString();
    
    // Pay each period sequentially
    let successCount = 0;
    let failCount = 0;
    let totalPaid = 0;
    
    for (const period of previousBalances) {
        // Set target for this period
        window.previousBalancePaymentTarget = {
            year: parseInt(period.year),
            term: parseInt(period.term)
        };
        
        // Set the tuition amount to this period's balance
        const tuitionInput = document.getElementById('tuitionAmount');
        if (tuitionInput) {
            tuitionInput.value = period.balance;
            tuitionInput.dispatchEvent(new Event('input'));
        }
        
        // Submit payment for this period
        try {
            // We need to use the same submission logic but we can't await submitCollectionPaymentFixed
            // because it shows alerts and refreshes. Instead, we'll use a direct fetch.
            
            const student = window.currentCollectingStudent;
            if (!student) {
                failCount++;
                continue;
            }
            
            // Build a simple payment payload for this period
            const payload = {
                studentId: student.id,
                studentName: `${student.firstName} ${student.lastName}`,
                admissionNumber: student.admissionNumber,
                term: parseInt(period.term),
                academicYear: period.year.toString(),
                feeStructureId: student.feeStructure?.id || null,
                feeStructureName: student.feeStructure?.name || 'General Fee',
                bursaryId: student.appliedBursary?.id || null,
                bursaryName: student.appliedBursary?.name || null,
                tuitionPaid: Math.round(period.balance),
                activityItemPayments: [],
                totalAmount: Math.round(period.balance),
                method: document.getElementById('paymentMethodSelect')?.value || 'cash',
                receiptNumber: `PB${Date.now().toString().slice(-6)}${Math.floor(Math.random() * 900 + 100).toString()}`,
                reference: document.getElementById('paymentReference')?.value || `Bulk payment - ${period.year} Term ${period.term}`,
                notes: `Paid as part of bulk previous balance settlement`,
                hasCustomizations: false,
                customItemsCount: 0,
                studentCustomOverrides: student.customItemOverrides || {},
                hasPartialPayments: false,
                partialPaymentsCount: 0,
                isPreviousBalancePayment: true,
                targetPeriodYear: period.year.toString(),
                targetPeriodTerm: parseInt(period.term),
                originalPeriod: {
                    year: currentAcademicSettings.currentYear,
                    term: currentAcademicSettings.currentTerm
                },
                isBulkPayment: true,
                bulkPaymentId: window.bulkPaymentId
            };
            
            const response = await fetch('/api/fee/payments/enhanced', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(payload)
            });
            
            if (response.ok) {
                successCount++;
                totalPaid += period.balance;
            } else {
                failCount++;
            }
        } catch (e) {
            failCount++;
            console.error('Error paying period:', period, e);
        }
    }
    
    // Clear bulk flags
    window.isBulkPayment = false;
    window.bulkPaymentId = null;
    window.previousBalancePaymentTarget = null;
    
    // Show result
    const displayDate = new Date().toLocaleString();
    alert(
        `✅ Bulk previous balance payment completed!\n\n` +
        `📊 ${successCount} period(s) paid successfully\n` +
        `${failCount > 0 ? `⚠️ ${failCount} period(s) failed\n` : ''}` +
        `💰 Total Paid: UGX ${formatMoney(totalPaid)}\n` +
        `📆 Processed at: ${displayDate}`
    );
    
    // Refresh the collection form
    const student = window.currentCollectingStudent;
    if (student && student.id) {
        const { currentYear, currentTerm } = currentAcademicSettings;
        const termName = getTermName(currentTerm);
        await loadCollectionForm(student, currentYear, currentTerm, termName);
    } else {
        showFeeManagement();
    }
}

