// ==================== CALCULATE COLLECTION TOTALS ====================
function calculateCollectionTotalsFixed() {
    console.log('=== CALCULATING COLLECTION TOTALS ===');

    const student = window.currentCollectingStudent;
    if (!student) {
        console.log('No student data available');
        return;
    }

    const tuitionInput = document.getElementById('tuitionAmount');
    let tuition = parseInt(tuitionInput?.value) || 0;
    const tuitionMax = parseInt(tuitionInput?.max) || 0;

    if (tuition > tuitionMax && tuitionMax > 0) {
        tuition = tuitionMax;
        if (tuitionInput) tuitionInput.value = tuition;
    }

    const tuitionPaidSoFar = student.tuitionPaid || 0;
    const tuitionExpected = student.expectedTuition || 0;
    const newTuitionPaid = tuitionPaidSoFar + tuition;
    const tuitionRemaining = Math.max(0, tuitionExpected - newTuitionPaid);

    // ========== BUILD CURRENT PAYMENTS MAP (with deduplication) ==========
    const currentItemPayments = {};
    const processedKeys = new Set();

    document.querySelectorAll('.cash-amount-input').forEach(input => {
        let amount = parseInt(input.value) || 0;
        if (amount <= 0) return;

        const itemName = input.dataset.itemName;
        const componentName = input.dataset.component;
        if (!itemName || !componentName) return;

        const key = `${componentName}_${itemName}`;
        if (processedKeys.has(key)) return;
        processedKeys.add(key);

        if (!currentItemPayments[key]) {
            currentItemPayments[key] = { cash: 0, items: 0 };
        }
        currentItemPayments[key].cash += amount;
    });

    document.querySelectorAll('.item-quantity-input').forEach(input => {
        let quantity = parseInt(input.value) || 0;
        if (quantity <= 0) return;

        const itemName = input.dataset.itemName;
        const componentName = input.dataset.component;
        if (!itemName || !componentName) return;

        const key = `${componentName}_${itemName}`;
        if (processedKeys.has(key)) return;
        processedKeys.add(key);

        if (!currentItemPayments[key]) {
            currentItemPayments[key] = { cash: 0, items: 0 };
        }
        currentItemPayments[key].items += quantity;
    });

    // ========== CALCULATE STATUS GROUP PAYMENTS ==========
    const statusGroupData = student.statusGroupData || {};
    const statusGroupPayments = {};
    let totalPayment = tuition;

    for (const [sgId, sgData] of Object.entries(statusGroupData)) {
        statusGroupPayments[sgId] = 0;

        for (const component of sgData.components) {
            for (const item of component.items) {
                const key = `${component.name}_${item.name}`;
                const payment = currentItemPayments[key];

                if (payment) {
                    const actualPayment = Math.min(payment.cash, item.remainingAmount);
                    const cashEquivalent = payment.items * item.unitPrice;
                    const actualItemPayment = Math.min(cashEquivalent, item.remainingAmount);
                    const totalForItem = actualPayment + actualItemPayment;
                    statusGroupPayments[sgId] += totalForItem;
                    totalPayment += totalForItem;
                }
            }
        }
    }

    // ========== UPDATE SUMMARY DISPLAYS ==========
    const summaryTuition = document.getElementById('summaryTuition');
    if (summaryTuition) summaryTuition.innerHTML = `UGX ${tuition.toLocaleString()}`;

    for (const [sgId, total] of Object.entries(statusGroupPayments)) {
        const summarySpan = document.getElementById(`summary_${sgId.replace(/[^a-zA-Z0-9]/g, '_')}`);
        if (summarySpan) summarySpan.innerHTML = `UGX ${total.toLocaleString()}`;
    }

    const summaryTotal = document.getElementById('summaryTotal');
    if (summaryTotal) summaryTotal.innerHTML = `UGX ${totalPayment.toLocaleString()}`;

    // ========== CALCULATE TOTAL OUTSTANDING ==========
    let totalOutstanding = tuitionRemaining;

    for (const [sgId, sgData] of Object.entries(statusGroupData)) {
        let groupPaid = statusGroupPayments[sgId] || 0;
        let groupRemaining = Math.max(0, sgData.totalRemaining - groupPaid);
        totalOutstanding += groupRemaining;
    }

    // ========== UPDATE OUTSTANDING DISPLAY ==========
    const outstandingSpan = document.getElementById('outstandingAfter');
    if (outstandingSpan) {
        outstandingSpan.innerHTML = `UGX ${Math.round(totalOutstanding).toLocaleString()}`;
        outstandingSpan.className = `font-bold text-xl ${totalOutstanding > 0 ? 'text-red-600' : 'text-green-600'}`;
    }

    console.log('Collection totals calculated:', {
        tuition,
        tuitionPaidSoFar,
        tuitionExpected,
        tuitionRemaining,
        totalPayment,
        totalOutstanding,
        statusGroupPayments
    });
}

