// ==================== FIXED GENERATE AUTO RECEIPT NUMBER ====================
async function generateAutoReceiptNumberFixed() {
    try {
        const schoolRes = await fetch('/api/school');
        const schoolData = await schoolRes.json();
        const school = schoolData.school || {};

        let schoolName = school.schoolName || 'School';
        let prefix = schoolName.replace(/[^a-zA-Z0-9]/g, '').substring(0, 4).toUpperCase();

        if (prefix.length < 2) {
            prefix = 'SCH';
        }

        const timestamp = Date.now().toString().slice(-6);
        const random = Math.floor(Math.random() * 900 + 100).toString();
        const receiptNumber = `${prefix}${timestamp}${random}`;

        const receiptInput = document.getElementById('receiptNumber');
        if (receiptInput) {
            receiptInput.value = receiptNumber;
            receiptInput.dataset.autoGenerated = 'true';
            receiptInput.style.borderColor = '#10b981';
            receiptInput.style.backgroundColor = '#f0fdf4';

            setTimeout(() => {
                if (receiptInput) {
                    receiptInput.style.borderColor = '';
                    receiptInput.style.backgroundColor = '';
                }
            }, 2000);
        }

        console.log('Auto-generated receipt number:', receiptNumber);
        return receiptNumber;

    } catch (error) {
        console.error('Error generating receipt number:', error);
        const timestamp = Date.now().toString().slice(-6);
        const random = Math.floor(Math.random() * 900 + 100).toString();
        const receiptNumber = `SCH${timestamp}${random}`;

        const receiptInput = document.getElementById('receiptNumber');
        if (receiptInput) {
            receiptInput.value = receiptNumber;
            receiptInput.dataset.autoGenerated = 'true';
        }
        return receiptNumber;
    }
}

