// ==================== FIX 2: TUITION VALIDATION - PREVENT EXCEEDING MAX ====================
// ==================== FIXED: TUITION VALIDATION (Allows any amount up to max) ====================
function validateAndCalculateTuition() {
    const tuitionInput = document.getElementById('tuitionAmount');
    if (!tuitionInput) return;
    
    let value = parseInt(tuitionInput.value) || 0;
    const maxValue = parseInt(tuitionInput.max) || 0;
    
    // ========== FIX: Allow any amount from 0 to max, not just full amounts ==========
    if (value > maxValue && maxValue > 0) {
        // Auto-fill to max and show alert
        tuitionInput.value = maxValue;
        value = maxValue;
        if (typeof showToast === 'function') {
            showToast(`⚠️ Amount cannot exceed the required balance of UGX ${maxValue.toLocaleString()}`, 'warning');
        } else {
            alert(`⚠️ Amount cannot exceed the required balance of UGX ${maxValue.toLocaleString()}`);
        }
    }
    
    if (value < 0) {
        tuitionInput.value = 0;
        value = 0;
    }
    
    // ========== FIX: Any positive amount is valid (including partial payments) ==========
    // No need to check if amount covers full items - tuition is always full amount
    
    if (typeof calculateCollectionTotalsFixed === 'function') {
        calculateCollectionTotalsFixed();
    }
}

// ========== MAKE GLOBAL ==========
window.validateAndCalculateTuition = validateAndCalculateTuition;

