// ==================== FIXED INITIALIZE COLLECTION ITEM HANDLERS ====================

function initializeCollectionItemHandlers() {
    console.log('Initializing collection item handlers...');
    
    // Handle payment type radio buttons - Toggle between cash and item inputs
    document.querySelectorAll('.payment-type-radio').forEach(radio => {
        // Remove existing listeners to avoid duplicates
        radio.removeEventListener('change', handlePaymentTypeChange);
        radio.addEventListener('change', handlePaymentTypeChange);
    });
    
    // Also handle any new radios that might be added dynamically
    const observer = new MutationObserver(function(mutations) {
        mutations.forEach(function(mutation) {
            if (mutation.type === 'childList' && mutation.addedNodes.length) {
                const newRadios = document.querySelectorAll('.payment-type-radio:not([data-listener])');
                newRadios.forEach(radio => {
                    radio.setAttribute('data-listener', 'true');
                    radio.addEventListener('change', handlePaymentTypeChange);
                });
            }
        });
    });
    
    observer.observe(document.body, {
        childList: true,
        subtree: true
    });
    
    console.log('Collection item handlers initialized');
}

// ==================== HANDLE PAYMENT TYPE CHANGE ====================

function handlePaymentTypeChange(e) {
    const radio = e.target;
    const itemId = radio.dataset.itemId;
    const isCash = radio.value === 'cash';
    
    console.log(`Payment type changed for ${itemId}: ${isCash ? 'Cash' : 'Item'}`);
    
    // Find the parent item row
    const row = document.getElementById(`itemRow_${itemId}`);
    if (!row) {
        console.error(`Row not found for itemId: ${itemId}`);
        return;
    }
    
    // Find the cash and item divs within this row
    const cashDiv = row.querySelector('#cashDiv_' + itemId);
    const itemDiv = row.querySelector('#itemDiv_' + itemId);
    
    if (cashDiv && itemDiv) {
        if (isCash) {
            // Show cash input, hide item input
            cashDiv.classList.remove('hidden');
            itemDiv.classList.add('hidden');
            // Clear the item input value
            const itemInput = itemDiv.querySelector('.item-quantity-input');
            if (itemInput) itemInput.value = '0';
            // Recalculate with cash
            const cashInput = cashDiv.querySelector('.cash-amount-input');
            if (cashInput) {
                const maxCash = parseFloat(cashInput.dataset.max) || 0;
                updateItemPaymentAmountFixed(itemId, maxCash, 0, 0);
            }
        } else {
            // Show item input, hide cash input
            cashDiv.classList.add('hidden');
            itemDiv.classList.remove('hidden');
            // Clear the cash input value
            const cashInput = cashDiv.querySelector('.cash-amount-input');
            if (cashInput) cashInput.value = '0';
            // Recalculate with items
            const itemInput = itemDiv.querySelector('.item-quantity-input');
            if (itemInput) {
                const maxItems = parseFloat(itemInput.dataset.max) || 0;
                const unitPrice = parseFloat(row.dataset.unitPrice) || 0;
                updateItemPaymentQuantityFixed(itemId, maxItems, 0, unitPrice);
            }
        }
    } else {
        console.warn(`Cash or Item div not found for ${itemId}`);
    }
}

// ==================== UPDATE ITEM PAYMENT AMOUNT FIXED ====================



// ==================== UPDATE ITEM STATUS ====================

function updateItemStatus(itemId) {
    const row = document.getElementById(`itemRow_${itemId}`);
    if (!row) return;
    
    const remainingCash = parseInt(row.dataset.remainingCash) || 0;
    const remainingItems = parseInt(row.dataset.remainingItems) || 0;
    const paymentOption = row.dataset.paymentOption || 'either';
    
    const statusSpan = row.querySelector('.rounded-full.text-xs');
    if (!statusSpan) return;
    
    // Determine if fully paid based on payment option
    let isFullyPaid = false;
    let statusText = '';
    let statusClass = '';
    
    if (paymentOption === 'cash_only') {
        isFullyPaid = remainingCash <= 0;
    } else if (paymentOption === 'item_only') {
        isFullyPaid = remainingItems <= 0;
    } else {
        // either - fully paid if both cash AND items are fully paid
        // OR if cash fully covers it
        // OR if items fully cover it
        const cashFullyPaid = remainingCash <= 0;
        const itemsFullyDelivered = remainingItems <= 0;
        isFullyPaid = cashFullyPaid || itemsFullyDelivered;
    }
    
    const hasPayment = (parseInt(row.dataset.remainingCash) || 0) < (parseInt(row.dataset.remainingCashOrig) || 0) ||
                       (parseInt(row.dataset.remainingItems) || 0) < (parseInt(row.dataset.remainingItemsOrig) || 0);
    
    if (isFullyPaid) {
        statusText = '✅ Fully Paid';
        statusClass = 'bg-green-100 text-green-800';
    } else if (hasPayment) {
        statusText = '⚠️ Partial';
        statusClass = 'bg-yellow-100 text-yellow-800';
    } else {
        statusText = '❌ Not Paid';
        statusClass = 'bg-red-100 text-red-600';
    }
    
    statusSpan.textContent = statusText;
    statusSpan.className = `px-2 py-0.5 rounded-full text-xs ${statusClass}`;
}

