// Update item payment for collection form
function updateItemPaymentForCollection(itemId, type) {
    const row = document.getElementById(`itemRow_${itemId}`);
    if (!row) return;
    
    const unitPrice = parseFloat(row.dataset.unitPrice) || 0;
    const remainingAmount = parseFloat(row.dataset.remainingAmt) || 0;
    const periodType = row.dataset.periodType;
    
    let amount = 0;
    let itemsCovered = 0;
    
    if (type === 'cash') {
        const cashInput = document.querySelector(`#cashInput_${itemId} .cashAmountInput`);
        let cashAmount = parseFloat(cashInput?.value) || 0;
        if (cashAmount < 0) cashAmount = 0;
        if (cashAmount > remainingAmount) cashAmount = remainingAmount;
        if (cashInput) cashInput.value = cashAmount || '';
        amount = cashAmount;
        itemsCovered = unitPrice > 0 ? (cashAmount / unitPrice) : 0;
    } else {
        const itemsInput = document.querySelector(`#itemInput_${itemId} .itemsBroughtInput`);
        let itemsCount = parseInt(itemsInput?.value) || 0;
        const maxQty = parseInt(itemsInput?.max) || 0;
        if (itemsCount < 0) itemsCount = 0;
        if (itemsCount > maxQty) itemsCount = maxQty;
        if (itemsInput) itemsInput.value = itemsCount || '';
        itemsCovered = itemsCount;
        amount = itemsCount * unitPrice;
    }
    
    // Update display
    const totalSpan = document.getElementById(`itemTotal_${itemId}`);
    if (totalSpan) totalSpan.innerHTML = `UGX ${Math.round(amount).toLocaleString()}`;
    
    const statusSpan = document.getElementById(`itemStatus_${itemId}`);
    if (statusSpan) {
        if (amount >= remainingAmount) {
            statusSpan.innerHTML = '✓ Fully Paid (This Payment)';
            statusSpan.className = 'font-medium px-2 py-0.5 rounded-full bg-green-100 text-green-800';
        } else if (amount > 0) {
            statusSpan.innerHTML = `⚠️ Partial (UGX ${Math.round(amount).toLocaleString()})`;
            statusSpan.className = 'font-medium px-2 py-0.5 rounded-full bg-yellow-100 text-yellow-600';
        } else {
            statusSpan.innerHTML = '❌ Not Paid';
            statusSpan.className = 'font-medium px-2 py-0.5 rounded-full bg-red-100 text-red-600';
        }
    }
    
    // Update period total
    updatePeriodTotalForCollection(periodType);
    calculateCollectionTotal();
}

// Update period total
function updatePeriodTotalForCollection(periodType) {
    let total = 0;
    const containerId = `${periodType}ItemsContainer`;
    const container = document.getElementById(containerId);
    
    if (container) {
        const cashInputs = container.querySelectorAll('.cashAmountInput');
        cashInputs.forEach(input => {
            total += parseFloat(input.value) || 0;
        });
        
        const itemInputs = container.querySelectorAll('.itemsBroughtInput');
        itemInputs.forEach(input => {
            const unitPrice = parseFloat(input.dataset.unitPrice) || 0;
            const itemsCount = parseInt(input.value) || 0;
            total += itemsCount * unitPrice;
        });
    }
    
    const totalSpan = document.getElementById(`${periodType}TotalAmount`);
    if (totalSpan) totalSpan.innerHTML = `UGX ${Math.round(total).toLocaleString()}`;
}

