// ==================== FIXED: GET ALL ITEMS WITH REMAINING (PROPER ROUNDING) ====================
// ==================== FIXED GET ALL ITEMS WITH REMAINING ====================
function getAllItemsWithRemaining(activities, student, periodType) {
    const items = [];
    
    if (!activities || activities.length === 0) return items;
    
    // Get paid items from student's record
    const paidItems = student.activityItemsPaid?.[periodType] || [];
    
    for (const activity of activities) {
        const activityItems = activity.items || [];
        
        for (const item of activityItems) {
            // Get the correct quantity - this is the REQUIRED quantity
            const originalQuantity = item.quantity || 1;
            // Get the correct total amount
            const originalAmount = Math.round(item.totalAmount || 0);
            // Calculate unit price correctly
            const unitPrice = Math.round((originalAmount / originalQuantity) * 100) / 100;
            
            // Find if this item has been paid
            const paidRecord = paidItems.find(p => p.itemName === item.name);
            
            let remainingQuantity = originalQuantity;
            let remainingAmount = originalAmount;
            let alreadyPaidAmount = 0;
            let itemsBrought = 0;
            let isFullyPaid = false;
            
            if (paidRecord) {
                // Calculate total paid from payments
                if (paidRecord.payments && paidRecord.payments.length > 0) {
                    for (const payment of paidRecord.payments) {
                        if (payment.type === 'paid_cash') {
                            alreadyPaidAmount += Math.round(payment.amount || 0);
                        } else if (payment.type === 'brought_item') {
                            itemsBrought += Math.round(payment.itemsBrought || 0);
                        }
                    }
                }
                
                // Also check direct fields
                alreadyPaidAmount = Math.max(alreadyPaidAmount, Math.round((paidRecord.amountPaid || 0) + (paidRecord.cashEquivalent || 0)));
                itemsBrought = Math.max(itemsBrought, Math.round(paidRecord.itemsBrought || 0));
                
                remainingQuantity = Math.max(0, originalQuantity - itemsBrought);
                // Calculate remaining amount based on remaining quantity
                remainingAmount = Math.max(0, Math.round(unitPrice * remainingQuantity));
                
                // Check if fully paid
                isFullyPaid = (remainingQuantity <= 0 && remainingAmount <= 0) || 
                              (alreadyPaidAmount >= originalAmount) || 
                              (itemsBrought >= originalQuantity);
            }
            
            // Show item if NOT fully paid AND remaining > 0
            if (!isFullyPaid && (remainingQuantity > 0 || remainingAmount > 0)) {
                items.push({
                    componentId: activity.id,
                    componentName: activity.name,
                    periodType: periodType,
                    itemId: item.id || item.name,
                    itemName: item.name,
                    quantity: originalQuantity,  // REQUIRED quantity
                    totalAmount: originalAmount,
                    unitPrice: unitPrice,
                    remainingQuantity: remainingQuantity,
                    remainingAmount: remainingAmount,
                    alreadyPaidAmount: alreadyPaidAmount,
                    itemsBrought: itemsBrought,
                    isFullyPaid: false,
                    paymentOption: item.paymentOption || 'either'
                });
            }
        }
    }
    
    return items;
}

