// ==================== SET FULL TUITION AMOUNT ====================

function setFullTuitionAmount() {
    const checkbox = document.getElementById('fullTuitionCheck');
    const tuitionInput = document.getElementById('tuitionAmount');
    if (checkbox?.checked && tuitionInput && !tuitionInput.disabled) {
        tuitionInput.value = tuitionInput.max;
        calculateAllCollectionTotals();
    } else if (tuitionInput && !checkbox?.checked) {
        tuitionInput.value = 0;
        calculateAllCollectionTotals();
    }
}

// ==================== RESET ALL COLLECTION FORM ====================

function resetAllCollectionForm() {
    const tuitionInput = document.getElementById('tuitionAmount');
    if (tuitionInput) tuitionInput.value = '0';
    
    const fullTuitionCheck = document.getElementById('fullTuitionCheck');
    if (fullTuitionCheck) fullTuitionCheck.checked = false;
    
    // Clear all payment inputs
    document.querySelectorAll('.cashAmountInput, .itemsBroughtInput').forEach(input => {
        input.value = '';
    });
    
    // Reset payment type radios to cash
    document.querySelectorAll('.paymentTypeRadio[value="cash"]').forEach(radio => {
        radio.checked = true;
    });
    
    // Show cash inputs, hide item inputs
    document.querySelectorAll('.payment-input-group').forEach(group => {
        if (group.id && group.id.startsWith('cashInput')) {
            group.classList.remove('hidden');
        } else if (group.id && group.id.startsWith('itemInput')) {
            group.classList.add('hidden');
        }
    });
    
    // Reset all item totals and statuses
    document.querySelectorAll('[id^="itemTotal_"]').forEach(span => {
        span.innerHTML = 'UGX 0';
    });
    
    document.querySelectorAll('[id^="itemStatus_"]').forEach(span => {
        span.innerHTML = '❌ Not Paid';
        span.className = 'font-medium px-2 py-0.5 rounded-full bg-red-100 text-red-600';
    });
    
    // Reset period totals
    ['oneTimeTotalAmount', 'termlyTotalAmount', 'yearlyTotalAmount'].forEach(id => {
        const span = document.getElementById(id);
        if (span) span.innerHTML = 'UGX 0';
    });
    
    // Clear payment details
    const paymentReference = document.getElementById('paymentReference');
    const paymentNotes = document.getElementById('paymentNotes');
    if (paymentReference) paymentReference.value = '';
    if (paymentNotes) paymentNotes.value = '';
    
    calculateAllCollectionTotals();
}

