// ==================== FIXED SUBMIT FEE COLLECTION ====================

async function submitAllFeeCollection() {
    const student = window.currentCollectingStudent;
    const feeStructure = window.currentFeeStructure;
    
    if (!student) {
        alert('No student selected');
        return;
    }
    
    // Get tuition amount
    const tuitionPaid = Math.round(parseInt(document.getElementById('tuitionAmount')?.value) || 0);
    
    // Collect all activity item payments from all period types
    const activityItemPayments = [];
    const periodTypes = ['one_time', 'termly', 'yearly'];
    
    for (const periodType of periodTypes) {
        const container = document.getElementById(`${periodType}ItemsContainer`);
        if (!container) continue;
        
        const itemRows = container.querySelectorAll('.bg-white.rounded-lg');
        for (const row of itemRows) {
            // Get item details from the row data
            const itemName = row.querySelector('h4')?.innerText?.replace('📦 ', '') || '';
            const componentName = row.querySelector('.text-xs.text-gray-500')?.innerText || '';
            const unitPrice = parseInt(row.dataset.unitPrice) || 0;
            const quantityRequired = parseInt(row.dataset.remainingQty) || 0;
            const remainingAmount = parseInt(row.dataset.remainingAmt) || 0;
            
            // Determine payment type
            const cashRadio = row.querySelector('input[value="cash"]');
            const isCash = cashRadio && cashRadio.checked;
            
            let amountPaid = 0;
            let itemsBrought = 0;
            
            if (isCash) {
                const cashInput = row.querySelector('.cashAmountInput');
                amountPaid = Math.round(parseInt(cashInput?.value) || 0);
                // Only include if amount > 0
                if (amountPaid <= 0) {
                    console.log(`Skipping ${itemName} - No cash amount entered`);
                    continue;
                }
                // Cap at remaining amount
                if (amountPaid > remainingAmount) {
                    amountPaid = remainingAmount;
                }
                console.log(`✅ Cash payment for ${itemName}: UGX ${amountPaid}`);
            } else {
                const itemsInput = row.querySelector('.itemsBroughtInput');
                itemsBrought = Math.round(parseInt(itemsInput?.value) || 0);
                // Only include if items brought > 0
                if (itemsBrought <= 0) {
                    console.log(`Skipping ${itemName} - No items entered`);
                    continue;
                }
                // Cap at remaining quantity
                if (itemsBrought > quantityRequired) {
                    itemsBrought = quantityRequired;
                }
                amountPaid = itemsBrought * unitPrice;
                console.log(`✅ Item brought for ${itemName}: ${itemsBrought} items (UGX ${amountPaid})`);
            }
            
            activityItemPayments.push({
                periodType: periodType,
                componentId: `comp_${periodType}_${Date.now()}_${itemName.replace(/\s/g, '_')}`,
                componentName: componentName,
                itemId: itemName.replace(/\s/g, '_'),
                itemName: itemName,
                unitPrice: unitPrice,
                quantityRequired: quantityRequired,
                paymentType: isCash ? 'paid_cash' : 'brought_item',
                amountPaid: isCash ? amountPaid : null,
                itemsBrought: !isCash ? itemsBrought : null,
                cashEquivalent: !isCash ? amountPaid : null
            });
        }
    }
    
    const activityTotal = activityItemPayments.reduce((sum, p) => 
        sum + (p.paymentType === 'paid_cash' ? (p.amountPaid || 0) : (p.cashEquivalent || 0)), 0);
    const totalAmount = tuitionPaid + activityTotal;
    
    if (totalAmount <= 0) {
        alert('Please enter an amount to pay or select items to pay');
        return;
    }
    
    const method = document.getElementById('paymentMethodSelect')?.value || 'cash';
    const reference = document.getElementById('paymentReference')?.value || '';
    const notes = document.getElementById('paymentNotes')?.value || '';
    
    const submitBtn = document.querySelector('#collectionForm button[type="button"]');
    const originalText = submitBtn.innerText;
    submitBtn.innerText = 'Processing...';
    submitBtn.disabled = true;
    
    try {
        const response = await fetch('/api/fee/payments/enhanced', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
                studentId: student.id,
                studentName: `${student.firstName} ${student.lastName}`,
                admissionNumber: student.admissionNumber,
                term: currentAcademicSettings.currentTerm,
                academicYear: currentAcademicSettings.currentYear.toString(),
                feeStructureId: feeStructure?.id || null,
                feeStructureName: feeStructure?.name || 'General Fee',
                bursaryId: student.appliedBursary?.id || null,
                bursaryName: student.appliedBursary?.name || null,
                tuitionPaid: tuitionPaid,
                activityItemPayments: activityItemPayments,
                totalAmount: totalAmount,
                method: method,
                reference: reference,
                notes: notes
            })
        });
        
        const result = await response.json();
        
        if (response.ok) {
            const expected = student.totalExpected || 0;
            const newTotalPaid = (student.totalPaid || 0) + totalAmount;
            const newBalance = expected - newTotalPaid;
            
            let message = `✅ Payment recorded!\nReceipt: ${result.receiptNumber}\nAmount: UGX ${Math.round(totalAmount).toLocaleString()}\n\n`;
            
            if (tuitionPaid > 0) {
                message += `💰 Tuition: UGX ${Math.round(tuitionPaid).toLocaleString()}\n`;
            }
            
            if (activityItemPayments.length > 0) {
                message += `\n📦 Items Paid:\n`;
                for (const p of activityItemPayments) {
                    const paidAmount = p.paymentType === 'paid_cash' ? p.amountPaid : p.cashEquivalent;
                    message += `   • ${p.itemName}: UGX ${Math.round(paidAmount).toLocaleString()} (${p.paymentType === 'paid_cash' ? 'Cash' : `${p.itemsBrought} items`})\n`;
                }
            }
            
            if (newBalance < 0) {
                message += `\n⚠️ Credit created: UGX ${Math.round(Math.abs(newBalance)).toLocaleString()} (will apply to next term)`;
            } else if (newBalance === 0) {
                message += `\n🎉 Student is now FULLY PAID for this term!`;
            } else {
                message += `\nRemaining balance: UGX ${Math.round(newBalance).toLocaleString()}`;
            }
            
            alert(message);
            showFeeManagement();
        } else {
            alert('❌ Error: ' + (result.error || 'Unknown error'));
        }
    } catch (error) {
        console.error('Payment error:', error);
        alert('Network error: ' + error.message);
    } finally {
        submitBtn.innerText = originalText;
        submitBtn.disabled = false;
    }
}

