// ==================== FIXED: UPDATE PERIOD TOTAL AMOUNT (WORKS FOR ALL TYPES) ====================
// ==================== FIXED: UPDATE PERIOD TOTAL AMOUNT ====================
function updatePeriodTotalAmount(periodType) {
    console.log(`Updating total for ${periodType}...`);
    let total = 0;
    
    // Try multiple possible container IDs
    let container = document.getElementById(`${periodType}ItemsContainer`);
    if (!container) {
        container = document.getElementById(`${periodType}ItemsList`);
    }
    if (!container) {
        container = document.getElementById(`${periodType}ItemsContainerFinal`);
    }
    
    if (container) {
        // Find all cash amount inputs
        const cashInputs = container.querySelectorAll('.cashAmountInput, .cashAmount');
        cashInputs.forEach(input => {
            const val = Math.round(parseFloat(input.value) || 0);
            if (val > 0) {
                console.log(`${periodType} cash input:`, val);
                total += val;
            }
        });
        
        // Find all items brought inputs
        const itemInputs = container.querySelectorAll('.itemsBroughtInput, .itemsBrought');
        itemInputs.forEach(input => {
            const unitPrice = parseFloat(input.dataset.unitPrice) || 0;
            const itemsCount = parseInt(input.value) || 0;
            const val = Math.round(itemsCount * unitPrice);
            if (val > 0) {
                console.log(`${periodType} items brought:`, itemsCount, 'items =', val);
                total += val;
            }
        });
    }
    
    // Update the display span - try multiple possible IDs
    let totalSpan = document.getElementById(`${periodType}TotalAmount`);
    if (!totalSpan) {
        totalSpan = document.getElementById(`${periodType}TotalSelected`);
    }
    if (!totalSpan) {
        totalSpan = document.getElementById(`${periodType}TotalAmountFinal`);
    }
    
    if (totalSpan) {
        totalSpan.innerHTML = `UGX ${Math.round(total).toLocaleString()}`;
        console.log(`${periodType} total set to:`, total);
    }
    
    // Also update the summary display
    let summaryId = '';
    if (periodType === 'one_time') summaryId = 'summaryOneTime';
    else if (periodType === 'termly') summaryId = 'summaryTermly';
    else if (periodType === 'yearly') summaryId = 'summaryYearly';
    
    const summarySpan = document.getElementById(summaryId);
    if (summarySpan) {
        summarySpan.innerHTML = `UGX ${Math.round(total).toLocaleString()}`;
    }
    
    calculateAllCollectionTotals();
}

