// ==================== FIXED: UPDATE ITEM PAYMENT ====================
// ==================== FIXED: UPDATE ITEM PAYMENT FOR ITEM (PROPER ROUNDING) ====================
// ==================== UPDATE ITEM PAYMENT FOR ITEM ====================
function updateItemPaymentForItem(itemId, type) {
    console.log(`updateItemPaymentForItem called for ${itemId}, type: ${type}`);
    
    const row = document.getElementById(`itemRow_${itemId}`);
    if (!row) {
        console.error(`Row not found for itemId: ${itemId}`);
        return;
    }
    
    const unitPrice = parseInt(row.dataset.unitPrice) || 0;
    const remainingAmount = parseInt(row.dataset.remainingAmt) || 0;
    const remainingQty = parseInt(row.dataset.remainingQty) || 0;
    const periodType = row.dataset.periodType;
    
    let amount = 0;
    let itemsCovered = 0;
    
    if (type === 'cash') {
        const cashInput = document.querySelector(`#cashInput_${itemId} .cashAmountInput`);
        if (!cashInput) {
            console.error(`Cash input not found for ${itemId}`);
            return;
        }
        let cashAmount = parseInt(cashInput.value) || 0;
        
        if (cashAmount < 0) cashAmount = 0;
        if (cashAmount > remainingAmount) cashAmount = remainingAmount;
        
        cashInput.value = cashAmount;
        amount = cashAmount;
        itemsCovered = unitPrice > 0 ? Math.floor(cashAmount / unitPrice) : 0;
        if (itemsCovered > remainingQty) itemsCovered = remainingQty;
        
        console.log(`Cash payment: UGX ${amount} (${itemsCovered} items)`);
        
    } else {
        const itemsInput = document.querySelector(`#itemInput_${itemId} .itemsBroughtInput`);
        if (!itemsInput) {
            console.error(`Items input not found for ${itemId}`);
            return;
        }
        let itemsCount = parseInt(itemsInput.value) || 0;
        
        if (itemsCount < 0) itemsCount = 0;
        if (itemsCount > remainingQty) itemsCount = remainingQty;
        
        itemsInput.value = itemsCount;
        itemsCovered = itemsCount;
        amount = itemsCount * unitPrice;
        
        console.log(`Item brought: ${itemsCount} items (UGX ${amount})`);
    }
    
    // Update display
    const totalSpan = document.getElementById(`itemTotal_${itemId}`);
    if (totalSpan) totalSpan.innerHTML = `UGX ${amount.toLocaleString()}`;
    
    const statusSpan = document.getElementById(`itemStatus_${itemId}`);
    if (statusSpan) {
        if (amount >= remainingAmount || itemsCovered >= remainingQty) {
            statusSpan.innerHTML = '✓ Fully Paid';
            statusSpan.className = 'font-medium px-2 py-0.5 rounded-full bg-green-100 text-green-600';
        } else if (amount > 0 || itemsCovered > 0) {
            statusSpan.innerHTML = `⚠️ Partial (${itemsCovered}/${remainingQty} items)`;
            statusSpan.className = 'font-medium px-2 py-0.5 rounded-full bg-yellow-100 text-yellow-600';
        } else {
            statusSpan.innerHTML = '❌ Not Paid';
            statusSpan.className = 'font-medium px-2 py-0.5 rounded-full bg-red-100 text-red-600';
        }
    }
    
    // Update period total
    updatePeriodTotalAmount(periodType);
}

// ==================== FIXED: UPDATE ALL PERIOD TOTALS ====================
function updateAllPeriodTotals() {
    const periodTypes = ['one_time', 'termly', 'yearly'];
    periodTypes.forEach(periodType => {
        updatePeriodTotalAmount(periodType);
    });
}

