// ==================== FIXED: RENDER ITEM ROW (make sure inputs have correct classes) ====================
// ==================== FIXED RENDER ITEM ROW - CASH INPUTS WORKING ====================
function renderItemRow(item, periodType, color) {
    const uniqueId = `${periodType}_${item.itemName.replace(/\s/g, '_')}_${Date.now()}`;
    const colorClass = color === 'purple' ? 'purple' : color === 'green' ? 'green' : 'orange';
    
    const isFullyPaid = (item.remainingQuantity <= 0 && item.remainingAmount <= 0);
    const remainingAmountFormatted = Math.round(item.remainingAmount).toLocaleString();
    const remainingQtyFormatted = item.remainingQuantity;
    
    return `
        <div id="itemRow_${uniqueId}" class="bg-white rounded-lg p-4 border shadow-sm mb-4" 
             data-item-name="${escapeHtml(item.itemName)}" 
             data-unit-price="${item.unitPrice}" 
             data-remaining-qty="${item.remainingQuantity}" 
             data-remaining-amt="${item.remainingAmount}"
             data-total-qty="${item.quantity}"
             data-total-amt="${item.totalAmount}"
             data-already-paid="${item.alreadyPaidAmount}"
             data-already-brought="${item.itemsBrought}"
             data-period-type="${periodType}">
            
            <!-- Item Header -->
            <div class="flex justify-between items-start mb-3">
                <div>
                    <h4 class="font-semibold text-md">📦 ${escapeHtml(item.itemName)}</h4>
                    <p class="text-xs text-gray-500">${escapeHtml(item.componentName)}</p>
                </div>
                <div class="text-right">
                    <p class="text-sm font-semibold text-${colorClass}-600">UGX ${Math.round(item.unitPrice).toLocaleString()} / each</p>
                    <p class="text-xs text-gray-500">Total: UGX ${Math.round(item.totalAmount).toLocaleString()} (${item.quantity} items)</p>
                    ${!isFullyPaid ? `<p class="text-xs text-orange-600 font-semibold">Remaining: ${remainingQtyFormatted} items (UGX ${remainingAmountFormatted})</p>` : ''}
                </div>
            </div>
            
            ${!isFullyPaid ? `
                <!-- Payment Type Selection -->
                <div class="mb-3">
                    <label class="block text-sm font-medium mb-2">💰 Payment Type:</label>
                    <div class="flex gap-6">
                        <label class="flex items-center cursor-pointer p-2 rounded-lg hover:bg-gray-50">
                            <input type="radio" name="paymentType_${uniqueId}" value="cash" 
                                   class="mr-2 w-4 h-4 paymentTypeRadio" 
                                   data-item-id="${uniqueId}" 
                                   data-period="${periodType}"
                                   onchange="togglePaymentInputForItem('${uniqueId}', 'cash')" checked>
                            <span class="text-sm">💵 Pay Cash</span>
                        </label>
                        <label class="flex items-center cursor-pointer p-2 rounded-lg hover:bg-gray-50">
                            <input type="radio" name="paymentType_${uniqueId}" value="item" 
                                   class="mr-2 w-4 h-4 paymentTypeRadio" 
                                   data-item-id="${uniqueId}" 
                                   data-period="${periodType}"
                                   onchange="togglePaymentInputForItem('${uniqueId}', 'item')">
                            <span class="text-sm">📦 Bring Item</span>
                        </label>
                    </div>
                </div>
                
                <!-- Cash Payment Input -->
                <div id="cashInput_${uniqueId}" class="payment-input-group mb-3">
                    <label class="block text-sm font-medium mb-1">Amount to Pay (UGX)</label>
                    <input type="number" 
                           class="w-full border rounded-lg px-3 py-2 cashAmountInput" 
                           data-item-id="${uniqueId}" 
                           data-period="${periodType}"
                           data-unit-price="${item.unitPrice}" 
                           data-max-amount="${item.remainingAmount}"
                           value="0"
                           min="0"
                           max="${item.remainingAmount}"
                           step="1000"
                           oninput="updateItemPaymentForItem('${uniqueId}', 'cash')">
                    <p class="text-xs text-gray-500 mt-1">Max: UGX ${remainingAmountFormatted} (${remainingQtyFormatted} items)</p>
                </div>
                
                <!-- Item Brought Input -->
                <div id="itemInput_${uniqueId}" class="payment-input-group hidden mb-3">
                    <label class="block text-sm font-medium mb-1">Number of Items to Bring</label>
                    <input type="number" 
                           class="w-full border rounded-lg px-3 py-2 itemsBroughtInput" 
                           data-item-id="${uniqueId}" 
                           data-period="${periodType}"
                           data-unit-price="${item.unitPrice}" 
                           data-remaining-qty="${item.remainingQuantity}"
                           value="0"
                           min="0"
                           max="${item.remainingQuantity}"
                           step="1"
                           oninput="updateItemPaymentForItem('${uniqueId}', 'item')">
                    <p class="text-xs text-gray-500 mt-1">Max: ${remainingQtyFormatted} items (UGX ${remainingAmountFormatted})</p>
                </div>
                
                <!-- Payment Summary -->
                <div class="mt-3 pt-2 border-t flex justify-between items-center">
                    <span class="text-sm font-semibold">Amount for this item:</span>
                    <span id="itemTotal_${uniqueId}" class="font-bold text-green-600 text-lg">UGX 0</span>
                </div>
                <div class="flex justify-between items-center text-xs mt-1">
                    <span>Payment Status:</span>
                    <span id="itemStatus_${uniqueId}" class="font-medium px-2 py-0.5 rounded-full bg-red-100 text-red-600">Not Paid</span>
                </div>
            ` : `
                <div class="text-center text-green-600 py-2">
                    <i class="fas fa-check-circle"></i> This item has been fully paid
                </div>
            `}
        </div>
    `;
}

