// ==================== SET FULL TUITION AMOUNT ====================

function setFullTuitionAmount() {
    const checkbox = document.getElementById('fullTuitionCheck');
    const tuitionInput = document.getElementById('tuitionAmount');
    if (checkbox?.checked && tuitionInput && !tuitionInput.disabled) {
        tuitionInput.value = tuitionInput.max;
        calculateAllCollectionTotals();
    } else if (tuitionInput && !checkbox?.checked) {
        tuitionInput.value = 0;
        calculateAllCollectionTotals();
    }
}

// ==================== RESET ALL COLLECTION FORM ====================

function resetAllCollectionForm() {
    const tuitionInput = document.getElementById('tuitionAmount');
    if (tuitionInput) tuitionInput.value = '0';
    
    const fullTuitionCheck = document.getElementById('fullTuitionCheck');
    if (fullTuitionCheck) fullTuitionCheck.checked = false;
    
    // Clear all payment inputs
    document.querySelectorAll('.cashAmountInput, .itemsBroughtInput').forEach(input => {
        input.value = '';
    });
    
    // Reset payment type radios to cash
    document.querySelectorAll('.paymentTypeRadio[value="cash"]').forEach(radio => {
        radio.checked = true;
    });
    
    // Show cash inputs, hide item inputs
    document.querySelectorAll('.payment-input-group').forEach(group => {
        if (group.id && group.id.startsWith('cashInput')) {
            group.classList.remove('hidden');
        } else if (group.id && group.id.startsWith('itemInput')) {
            group.classList.add('hidden');
        }
    });
    
    // Reset all item totals and statuses
    document.querySelectorAll('[id^="itemTotal_"]').forEach(span => {
        span.innerHTML = 'UGX 0';
    });
    
    document.querySelectorAll('[id^="itemStatus_"]').forEach(span => {
        span.innerHTML = '❌ Not Paid';
        span.className = 'font-medium px-2 py-0.5 rounded-full bg-red-100 text-red-600';
    });
    
    // Reset period totals
    ['oneTimeTotalAmount', 'termlyTotalAmount', 'yearlyTotalAmount'].forEach(id => {
        const span = document.getElementById(id);
        if (span) span.innerHTML = 'UGX 0';
    });
    
    // Clear payment details
    const paymentReference = document.getElementById('paymentReference');
    const paymentNotes = document.getElementById('paymentNotes');
    if (paymentReference) paymentReference.value = '';
    if (paymentNotes) paymentNotes.value = '';
    
    calculateAllCollectionTotals();
}

// ==================== SUBMIT ALL FEE COLLECTION ====================

async function submitAllFeeCollection() {
    const student = window.currentCollectingStudent;
    const feeStructure = window.currentFeeStructure;
    
    if (!student) {
        alert('No student selected');
        return;
    }
    
    // Get tuition amount
    const tuitionPaid = Math.round(parseInt(document.getElementById('tuitionAmount')?.value) || 0);
    
    // Collect all activity item payments from all period types
    const activityItemPayments = [];
    const periodTypes = ['one_time', 'termly', 'yearly'];
    
    for (const periodType of periodTypes) {
        const container = document.getElementById(`${periodType}ItemsContainer`);
        if (!container) continue;
        
        const itemRows = container.querySelectorAll('.bg-white.rounded-lg');
        for (const row of itemRows) {
            // Get item details from the row data
            const itemName = row.querySelector('h4')?.innerText?.replace('📦 ', '') || '';
            const componentName = row.querySelector('.text-xs.text-gray-500')?.innerText || '';
            const unitPrice = parseInt(row.dataset.unitPrice) || 0;
            const quantityRequired = parseInt(row.dataset.remainingQty) || 0;
            
            // Determine payment type
            const cashRadio = row.querySelector('input[value="cash"]');
            const isCash = cashRadio && cashRadio.checked;
            
            let amountPaid = 0;
            let itemsBrought = 0;
            
            if (isCash) {
                const cashInput = row.querySelector('.cashAmountInput');
                amountPaid = Math.round(parseInt(cashInput?.value) || 0);
                if (amountPaid <= 0) continue;
            } else {
                const itemsInput = row.querySelector('.itemsBroughtInput');
                itemsBrought = Math.round(parseInt(itemsInput?.value) || 0);
                if (itemsBrought <= 0) continue;
                amountPaid = itemsBrought * unitPrice;
            }
            
            activityItemPayments.push({
                periodType: periodType,
                componentId: `comp_${periodType}_${Date.now()}_${itemName.replace(/\s/g, '_')}`,
                componentName: componentName,
                itemId: itemName.replace(/\s/g, '_'),
                itemName: itemName,
                unitPrice: unitPrice,
                quantityRequired: quantityRequired,
                paymentType: isCash ? 'paid_cash' : 'brought_item',
                amountPaid: isCash ? amountPaid : null,
                itemsBrought: !isCash ? itemsBrought : null,
                cashEquivalent: !isCash ? amountPaid : null
            });
        }
    }
    
    const activityTotal = activityItemPayments.reduce((sum, p) => 
        sum + (p.paymentType === 'paid_cash' ? (p.amountPaid || 0) : (p.cashEquivalent || 0)), 0);
    const totalAmount = tuitionPaid + activityTotal;
    
    if (totalAmount <= 0) {
        alert('Please enter an amount to pay or select items to pay');
        return;
    }
    
    const method = document.getElementById('paymentMethodSelect')?.value || 'cash';
    const reference = document.getElementById('paymentReference')?.value || '';
    const notes = document.getElementById('paymentNotes')?.value || '';
    
    const submitBtn = document.querySelector('#collectionForm button[type="button"]');
    const originalText = submitBtn.innerText;
    submitBtn.innerText = 'Processing...';
    submitBtn.disabled = true;
    
    try {
        const response = await fetch('/api/fee/payments/enhanced', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
                studentId: student.id,
                studentName: `${student.firstName} ${student.lastName}`,
                admissionNumber: student.admissionNumber,
                term: currentAcademicSettings.currentTerm,
                academicYear: currentAcademicSettings.currentYear.toString(),
                feeStructureId: feeStructure?.id || null,
                feeStructureName: feeStructure?.name || 'General Fee',
                bursaryId: student.appliedBursary?.id || null,
                bursaryName: student.appliedBursary?.name || null,
                tuitionPaid: tuitionPaid,
                activityItemPayments: activityItemPayments,
                totalAmount: totalAmount,
                method: method,
                reference: reference,
                notes: notes
            })
        });
        
        const result = await response.json();
        
        if (response.ok) {
            const expected = student.totalExpected || 0;
            const newTotalPaid = (student.totalPaid || 0) + totalAmount;
            const newBalance = expected - newTotalPaid;
            
            let message = `✅ Payment recorded!\nReceipt: ${result.receiptNumber}\nAmount: UGX ${Math.round(totalAmount).toLocaleString()}\n\n`;
            
            if (tuitionPaid > 0) {
                message += `💰 Tuition: UGX ${Math.round(tuitionPaid).toLocaleString()}\n`;
            }
            
            if (activityItemPayments.length > 0) {
                message += `\n📦 Items Paid:\n`;
                for (const p of activityItemPayments) {
                    const paidAmount = p.paymentType === 'paid_cash' ? p.amountPaid : p.cashEquivalent;
                    message += `   • ${p.itemName}: UGX ${Math.round(paidAmount).toLocaleString()} (${p.paymentType === 'paid_cash' ? 'Cash' : `${p.itemsBrought} items`})\n`;
                }
            }
            
            if (newBalance < 0) {
                message += `\n⚠️ Credit created: UGX ${Math.round(Math.abs(newBalance)).toLocaleString()} (will apply to next term)`;
            } else if (newBalance === 0) {
                message += `\n🎉 Student is now FULLY PAID for this term!`;
            } else {
                message += `\nRemaining balance: UGX ${Math.round(newBalance).toLocaleString()}`;
            }
            
            alert(message);
            showFeeManagement();
        } else {
            alert('❌ Error: ' + (result.error || 'Unknown error'));
        }
    } catch (error) {
        console.error('Payment error:', error);
        alert('Network error: ' + error.message);
    } finally {
        submitBtn.innerText = originalText;
        submitBtn.disabled = false;
    }
}

// ==================== HELPER FUNCTIONS ====================

function getFeeStatusText(balance, expected) {
    if (balance < 0) return 'Credit Balance';
    if (balance === 0) return 'Fully Paid';
    if (balance > expected) return 'Critical Overdue';
    if (balance > 0) return 'Payment Due';
    return 'Unknown';
}

function escapeHtml(text) {
    if (!text) return '';
    const div = document.createElement('div');
    div.textContent = text;
    return div.innerHTML;
}

// Make sure all functions are global
window.loadCollectionForm = loadCollectionForm;
window.togglePaymentInputForItem = togglePaymentInputForItem;
window.updateItemPaymentForItem = updateItemPaymentForItem;
window.updatePeriodTotalAmount = updatePeriodTotalAmount;
window.calculateAllCollectionTotals = calculateAllCollectionTotals;
window.setFullTuitionAmount = setFullTuitionAmount;
window.resetAllCollectionForm = resetAllCollectionForm;
window.submitAllFeeCollection = submitAllFeeCollection;
window.getFeeStatusText = getFeeStatusText;

// ==================== GET ALL TERMLY ITEMS WITH REMAINING BALANCES ====================

function getAllTermlyItemsWithRemaining(feeStructure, student) {
    const items = [];
    
    if (!feeStructure || !feeStructure.termlyActivities || feeStructure.termlyActivities.length === 0) {
        console.log('No termly activities found in fee structure');
        return items;
    }
    
    // Get paid items from student's record
    const paidItems = student.activityItemsPaid?.termly || [];
    
    console.log('Paid items from student record:', paidItems);
    console.log('Termly activities from fee structure:', feeStructure.termlyActivities);
    
    for (const activity of feeStructure.termlyActivities) {
        const activityItems = activity.items || [];
        
        for (const item of activityItems) {
            const originalQuantity = Math.round(item.quantity || 1);
            const originalAmount = Math.round(item.totalAmount || 0);
            const unitPrice = Math.round(item.unitPrice || (originalAmount / originalQuantity));
            
            // Find if this item has been paid
            const paidRecord = paidItems.find(p => p.itemName === item.name);
            
            let remainingQuantity = originalQuantity;
            let remainingAmount = originalAmount;
            let alreadyPaidAmount = 0;
            let itemsBrought = 0;
            
            if (paidRecord) {
                alreadyPaidAmount = Math.round((paidRecord.amountPaid || 0) + (paidRecord.cashEquivalent || 0));
                itemsBrought = Math.round(paidRecord.itemsBrought || 0);
                remainingQuantity = Math.max(0, originalQuantity - itemsBrought);
                remainingAmount = Math.max(0, originalAmount - alreadyPaidAmount);
            }
            
            console.log(`Item ${item.name}: original=${originalQuantity}, remaining=${remainingQuantity}, paid=${alreadyPaidAmount}`);
            
            // Only show if not fully paid and remaining > 0
            if (remainingQuantity > 0 && remainingAmount > 0) {
                items.push({
                    componentId: activity.id,
                    componentName: activity.name,
                    periodType: 'termly',
                    itemId: item.id || item.name,
                    itemName: item.name,
                    quantity: originalQuantity,
                    totalAmount: originalAmount,
                    unitPrice: unitPrice,
                    remainingQuantity: remainingQuantity,
                    remainingAmount: remainingAmount,
                    alreadyPaidAmount: alreadyPaidAmount,
                    itemsBrought: itemsBrought,
                    isFullyPaid: false
                });
            }
        }
    }
    
    return items;
}

