// ==================== TOGGLE PAYMENT INPUT ====================

function togglePaymentInput(itemId, type) {
    const cashInput = document.getElementById(`cashInput_${itemId}`);
    const itemInput = document.getElementById(`itemInput_${itemId}`);
    
    if (type === 'cash') {
        if (cashInput) cashInput.classList.remove('hidden');
        if (itemInput) itemInput.classList.add('hidden');
        const itemsInput = itemInput?.querySelector('.itemsBrought');
        if (itemsInput) itemsInput.value = '';
    } else {
        if (cashInput) cashInput.classList.add('hidden');
        if (itemInput) itemInput.classList.remove('hidden');
        const cashAmountInput = cashInput?.querySelector('.cashAmount');
        if (cashAmountInput) cashAmountInput.value = '';
    }
    
    updateItemPayment(itemId, type);
}

// ==================== UPDATE ITEM PAYMENT ====================

function updateItemPayment(itemId, type) {
    const row = document.getElementById(`itemRow_${itemId}`);
    if (!row) return;
    
    const unitPrice = parseInt(row.dataset.unitPrice) || 0;
    const remainingAmount = parseInt(row.dataset.remainingAmt) || 0;
    const remainingQty = parseInt(row.dataset.remainingQty) || 0;
    
    let amount = 0;
    let itemsCovered = 0;
    
    if (type === 'cash') {
        const cashInput = document.querySelector(`#cashInput_${itemId} .cashAmount`);
        let cashAmount = Math.round(parseInt(cashInput?.value) || 0);
        if (cashAmount < 0) cashAmount = 0;
        if (cashAmount > remainingAmount) cashAmount = remainingAmount;
        if (cashInput) cashInput.value = cashAmount || '';
        amount = cashAmount;
        itemsCovered = unitPrice > 0 ? Math.round(cashAmount / unitPrice) : 0;
    } else {
        const itemsInput = document.querySelector(`#itemInput_${itemId} .itemsBrought`);
        let itemsCount = Math.round(parseInt(itemsInput?.value) || 0);
        if (itemsCount < 0) itemsCount = 0;
        if (itemsCount > remainingQty) itemsCount = remainingQty;
        if (itemsInput) itemsInput.value = itemsCount || '';
        itemsCovered = itemsCount;
        amount = itemsCount * unitPrice;
    }
    
    // Update display
    const totalSpan = document.getElementById(`itemTotal_${itemId}`);
    if (totalSpan) totalSpan.innerHTML = `UGX ${Math.round(amount).toLocaleString()}`;
    
    const statusSpan = document.getElementById(`itemStatus_${itemId}`);
    if (statusSpan) {
        if (amount >= remainingAmount || itemsCovered >= remainingQty) {
            statusSpan.innerHTML = '✓ Fully Paid';
            statusSpan.className = 'font-medium px-2 py-0.5 rounded-full bg-green-100 text-green-600';
        } else if (amount > 0 || itemsCovered > 0) {
            statusSpan.innerHTML = `⚠️ Partial (${itemsCovered}/${remainingQty} items)`;
            statusSpan.className = 'font-medium px-2 py-0.5 rounded-full bg-yellow-100 text-yellow-600';
        } else {
            statusSpan.innerHTML = '❌ Not Paid';
            statusSpan.className = 'font-medium px-2 py-0.5 rounded-full bg-red-100 text-red-600';
        }
    }
    
    // Update totals
    updateTermlyTotal();
    calculateCollectionTotals();
}

// ==================== UPDATE TERMLY TOTAL ====================

function updateTermlyTotal() {
    let total = 0;
    const termlyItems = document.querySelectorAll('#termlyItemsContainer .cashAmount, #termlyItemsContainer .itemsBrought');
    
    termlyItems.forEach(input => {
        const itemId = input.dataset.itemId;
        const row = document.getElementById(`itemRow_${itemId}`);
        if (!row) return;
        
        const unitPrice = parseInt(row.dataset.unitPrice) || 0;
        
        if (input.classList.contains('cashAmount')) {
            total += Math.round(parseInt(input.value) || 0);
        } else {
            const itemsCount = Math.round(parseInt(input.value) || 0);
            total += itemsCount * unitPrice;
        }
    });
    
    const totalSpan = document.getElementById('termlyTotalAmount');
    if (totalSpan) totalSpan.innerHTML = `UGX ${Math.round(total).toLocaleString()}`;
}

