// ==================== RENDER FEE STRUCTURES LIST ====================



function renderStructureGroup(structures, title) {
    if (!structures || structures.length === 0) {
        return `
            <div class="border rounded-xl p-6 text-center bg-gray-50">
                <div class="text-4xl mb-2">📁</div>
                <h3 class="font-semibold">${title}</h3>
                <p class="text-sm text-gray-500 mt-1">No fee structures</p>
                <button onclick="showAddFeeStructureModal()" class="mt-3 text-blue-600 text-sm">Add Fee Structure</button>
            </div>
        `;
    }
    
    return `
        <div class="border rounded-xl overflow-hidden shadow-sm">
            <div class="bg-gradient-to-r from-blue-500 to-blue-600 text-white p-3 text-center font-semibold">
                ${title}
            </div>
            <div class="p-3 max-h-[600px] overflow-y-auto">
                ${structures.map(s => {
                    const tuition = s.tuition || 0;
                    const oneTimeActivities = s.oneTimeActivities || [];
                    const termlyActivities = s.termlyActivities || [];
                    const yearlyActivities = s.yearlyActivities || [];
                    
                    return `
                        <div class="border-b pb-4 mb-4 last:border-0">
                            <div class="flex justify-between items-start mb-3">
                                <h4 class="font-bold text-lg">${s.name || 'Unnamed'}</h4>
                                <div class="flex gap-2">
                                    <button onclick="editFeeStructureItem('${s.id}')" class="text-blue-600 text-sm p-1" title="Edit">
                                        <i class="fas fa-edit"></i>
                                    </button>
                                    <button onclick="deleteFeeStructureItem('${s.id}')" class="text-red-600 text-sm p-1" title="Delete">
                                        <i class="fas fa-trash"></i>
                                    </button>
                                </div>
                            </div>
                            
                            <!-- Tuition -->
                            <div class="bg-blue-50 rounded-lg p-3 mb-3">
                                <div class="flex justify-between items-center">
                                    <span class="font-semibold flex items-center gap-2">
                                        <i class="fas fa-graduation-cap text-blue-600"></i> Tuition Fee
                                    </span>
                                    <span class="font-bold text-blue-600">UGX ${tuition.toLocaleString()}</span>
                                </div>
                                <p class="text-xs text-gray-500 mt-1">Bursaries are applied to this amount only</p>
                            </div>
                            
                            ${renderActivityGroup(oneTimeActivities, '⭐ One-Time Activities', 'purple', 'Paid once per year (first term only)')}
                            ${renderActivityGroup(termlyActivities, '📅 Termly Activities', 'green', 'Paid every term')}
                            ${renderActivityGroup(yearlyActivities, '📆 Yearly Activities', 'orange', 'Paid once per year (first term only)')}
                        </div>
                    `;
                }).join('')}
            </div>
        </div>
    `;
}

function renderActivityGroup(components, title, color, note) {
    if (!components || components.length === 0) return '';
    
    const total = components.reduce((sum, c) => sum + (c.totalAmount || 0), 0);
    const bgColor = color === 'purple' ? 'bg-purple-50' : color === 'green' ? 'bg-green-50' : 'bg-orange-50';
    const borderColor = color === 'purple' ? 'border-purple-200' : color === 'green' ? 'border-green-200' : 'border-orange-200';
    const textColor = color === 'purple' ? 'text-purple-600' : color === 'green' ? 'text-green-600' : 'text-orange-600';
    
    return `
        <div class="${bgColor} rounded-lg p-3 mb-3 border ${borderColor}">
            <div class="flex justify-between items-center mb-2">
                <span class="font-semibold flex items-center gap-2 ${textColor}">
                    <i class="fas ${color === 'purple' ? 'fa-star' : color === 'green' ? 'fa-calendar-alt' : 'fa-calendar-week'}"></i> ${title}
                </span>
                <span class="font-bold ${textColor}">UGX ${total.toLocaleString()}</span>
            </div>
            <div class="space-y-2">
                ${components.map(comp => `
                    <div class="bg-white rounded p-2 text-sm">
                        <div class="font-medium mb-1">📌 ${comp.name || 'Unnamed'}</div>
                        <div class="pl-4 space-y-1">
                            ${((comp.items || []).map(item => `
                                <div class="flex justify-between text-xs">
                                    <span>• ${item.name || 'Item'} (${item.quantity || 0} ${(item.quantity || 0) > 1 ? 'items' : 'item'})</span>
                                    <span class="font-mono">UGX ${(item.totalAmount || 0).toLocaleString()} <span class="text-gray-400">(UGX ${(item.unitPrice || 0).toLocaleString()}/each)</span></span>
                                </div>
                            `).join(''))}
                            <div class="flex justify-between text-xs font-semibold pt-1 border-t mt-1">
                                <span>Total:</span>
                                <span>UGX ${(comp.totalAmount || 0).toLocaleString()}</span>
                            </div>
                        </div>
                    </div>
                `).join('')}
            </div>
            <p class="text-xs text-gray-500 mt-2 italic">${note}</p>
        </div>
    `;
}

// ==================== RENDER BURSARIES LIST ====================

function renderBursariesList(bursaries) {
    if (!bursaries || bursaries.length === 0) {
        return '<div class="col-span-3 text-center py-8 text-gray-500">No bursaries added</div>';
    }
    
    return bursaries.map(b => `
        <div class="border rounded-lg p-4 bg-gradient-to-r from-gray-50 to-white">
            <div class="flex justify-between items-start">
                <h4 class="font-bold text-lg">${b.name || 'Unnamed'}</h4>
                <span class="px-2 py-1 rounded-full text-xs ${b.type === 'percentage' ? 'bg-blue-100 text-blue-800' : 'bg-green-100 text-green-800'}">
                    ${b.type === 'percentage' ? `${b.value}% OFF` : `UGX ${(b.value || 0).toLocaleString()} OFF`}
                </span>
            </div>
            <p class="text-sm text-gray-600 mt-1">${b.description || 'No description'}</p>
            <p class="text-xs text-gray-400 mt-2">Category: ${b.category || 'General'}</p>
            <div class="flex gap-2 mt-3 pt-2 border-t">
                <button onclick="editBursaryItem('${b.id}')" class="text-blue-600 text-sm hover:text-blue-800">
                    <i class="fas fa-edit"></i> Edit
                </button>
                <button onclick="deleteBursaryItem('${b.id}')" class="text-red-600 text-sm hover:text-red-800">
                    <i class="fas fa-trash"></i> Delete
                </button>
            </div>
        </div>
    `).join('');
}

// ==================== RENDER PAYMENT HISTORY TABLE ====================

// ==================== UPDATED PAYMENT HISTORY TAB RENDER FUNCTION ====================

// ==================== EXISTING PAYMENT HISTORY FUNCTION WITH SEARCH & PRINT ====================

// ==================== EXISTING PAYMENT HISTORY FUNCTION WITH SEARCH & PRINT ====================

// ==================== YOUR ORIGINAL FUNCTION - KEPT EXACTLY AS IS ====================

// ==================== COMPLETE REBUILT PAYMENT HISTORY TABLE ====================
// Version: 5.0 - Full numbers, no K abbreviations

// ==================== SIMPLE WORKING PAYMENT HISTORY TABLE ====================

// ==================== RENDER PAYMENT HISTORY TABLE ====================

// ==================== COMPLETE REBUILT PAYMENT HISTORY WITH STATUS GROUP COLUMNS ====================
// Version: 2.0 - Shows Status Groups as columns, not period types

async function renderPaymentHistoryTable(payments, students, feeStructures) {
    if (!payments || !Array.isArray(payments) || payments.length === 0) {
        return '<tr><td colspan="10" class="text-center p-8 text-gray-500">No payment records found</td></tr>';
    }
    
    // Build a map of all status groups from fee structures
    const statusGroupsMap = new Map(); // id -> { name, periodType, color }
    
    for (const fs of feeStructures) {
        if (fs.activityComponents) {
            for (const comp of fs.activityComponents) {
                if (comp.statusGroupId && comp.statusGroupName) {
                    if (!statusGroupsMap.has(comp.statusGroupId)) {
                        statusGroupsMap.set(comp.statusGroupId, {
                            id: comp.statusGroupId,
                            name: comp.statusGroupName,
                            periodType: comp.periodType,
                            color: comp.periodType === 'one_time' ? 'purple' : 
                                   comp.periodType === 'termly' ? 'green' : 'orange'
                        });
                    }
                }
            }
        }
    }
    
    // Also add any status groups that appear in payments but not in fee structures
    for (const payment of payments) {
        if (payment.paymentsByPeriodType) {
            for (const period of ['one_time', 'termly', 'yearly']) {
                const periodItems = payment.paymentsByPeriodType[period] || [];
                for (const item of periodItems) {
                    if (item.componentName && !Array.from(statusGroupsMap.values()).some(sg => sg.name === item.componentName)) {
                        statusGroupsMap.set(`temp_${item.componentName}`, {
                            id: `temp_${item.componentName}`,
                            name: item.componentName,
                            periodType: period,
                            color: period === 'one_time' ? 'purple' : period === 'termly' ? 'green' : 'orange'
                        });
                    }
                }
            }
        }
    }
    
    // Sort status groups (Transportation first, then alphabetical)
    const statusGroupsSorted = Array.from(statusGroupsMap.values()).sort((a, b) => {
        if (a.name.toLowerCase().includes('transport')) return -1;
        if (b.name.toLowerCase().includes('transport')) return 1;
        return a.name.localeCompare(b.name);
    });
    
    console.log('Status groups for columns:', statusGroupsSorted.map(sg => sg.name));
    
    // Sort payments by date (newest first)
    const sortedPayments = [...payments].filter(p => p && p.date).sort((a, b) => new Date(b.date) - new Date(a.date));
    
    // Helper to get all paid items from a payment
    function getAllPaidItems(payment) {
        const items = [];
        
        // From paymentsByPeriodType
        if (payment.paymentsByPeriodType) {
            for (const period of ['one_time', 'termly', 'yearly']) {
                const periodItems = payment.paymentsByPeriodType[period] || [];
                for (const item of periodItems) {
                    const paidAmount = item.paymentType === 'paid_cash' ? (item.amountPaid || 0) : (item.cashEquivalent || 0);
                    items.push({
                        name: item.itemName,
                        componentName: item.componentName || period,
                        periodType: period,
                        amount: paidAmount,
                        paymentType: item.paymentType,
                        itemsBrought: item.itemsBrought,
                        quantityRequired: item.quantityRequired,
                        unitPrice: item.unitPrice
                    });
                }
            }
        }
        
        // From activityItemPayments
        if (payment.activityItemPayments) {
            for (const item of payment.activityItemPayments) {
                const paidAmount = item.paymentType === 'paid_cash' ? (item.amountPaid || 0) : (item.cashEquivalent || 0);
                items.push({
                    name: item.itemName,
                    componentName: item.componentName,
                    periodType: item.periodType,
                    amount: paidAmount,
                    paymentType: item.paymentType,
                    itemsBrought: item.itemsBrought,
                    quantityRequired: item.quantityRequired,
                    unitPrice: item.unitPrice
                });
            }
        }
        
        return items;
    }
    
    let html = '';
    
    for (const payment of sortedPayments) {
        const allItems = getAllPaidItems(payment);
        const tuitionPaid = payment.tuitionPaid || 0;
        
        // Calculate totals by status group
        const statusGroupTotals = {};
        const statusGroupItems = {};
        
        for (const sg of statusGroupsSorted) {
            statusGroupTotals[sg.id] = 0;
            statusGroupItems[sg.id] = [];
        }
        
        // Distribute items to their status groups
        for (const item of allItems) {
            // Find matching status group
            let matchedSg = null;
            for (const sg of statusGroupsSorted) {
                if (item.componentName && sg.name.toLowerCase() === item.componentName.toLowerCase()) {
                    matchedSg = sg;
                    break;
                }
                if (sg.name.toLowerCase().includes(item.componentName?.toLowerCase()) ||
                    item.componentName?.toLowerCase().includes(sg.name.toLowerCase())) {
                    matchedSg = sg;
                    break;
                }
            }
            
            if (matchedSg) {
                statusGroupTotals[matchedSg.id] = (statusGroupTotals[matchedSg.id] || 0) + item.amount;
                statusGroupItems[matchedSg.id].push(item);
            }
        }
        
        const totalAmount = tuitionPaid + Object.values(statusGroupTotals).reduce((sum, val) => sum + val, 0);
        
        // Payment method styling
        const methodIcon = payment.method === 'cash' ? '💵' : payment.method === 'bank' ? '🏦' : payment.method === 'mobile' ? '📱' : '🏫';
        const methodClass = payment.method === 'cash' ? 'bg-green-100 text-green-800' : 
                           payment.method === 'bank' ? 'bg-blue-100 text-blue-800' : 
                           payment.method === 'mobile' ? 'bg-purple-100 text-purple-800' : 'bg-orange-100 text-orange-800';
        
        const rowId = `payment_row_${payment.receiptNumber?.replace(/[^a-zA-Z0-9]/g, '_') || Date.now()}`;
        const detailsId = `payment_details_${payment.receiptNumber?.replace(/[^a-zA-Z0-9]/g, '_') || Date.now()}`;
        
        // Build status group column cells
        let statusGroupCells = '';
        for (const sg of statusGroupsSorted) {
            const amount = statusGroupTotals[sg.id] || 0;
            const hasItems = statusGroupItems[sg.id].length > 0;
            statusGroupCells += `
                <td class="p-3 text-right">
                    ${amount > 0 ? 
                        `<span class="font-semibold text-green-600">UGX ${Math.round(amount).toLocaleString()}</span>` : 
                        `<span class="text-gray-400">-</span>`
                    }
                    ${hasItems ? `<div class="text-xs text-gray-400">${statusGroupItems[sg.id].length} item(s)</div>` : ''}
                </td>
            `;
        }
        
        html += `
            <tr class="border-b hover:bg-gray-50 payment-row cursor-pointer" 
                id="${rowId}"
                data-receipt="${payment.receiptNumber || ''}"
                data-student="${(payment.studentName || '').toLowerCase()}"
                data-admission="${(payment.admissionNumber || '').toLowerCase()}"
                data-method="${payment.method || 'cash'}"
                onclick="togglePaymentDetailsRow('${rowId}', '${detailsId}')">
                <td class="p-3 whitespace-nowrap">
                    <div class="flex items-center gap-2">
                        <i class="fas fa-chevron-right text-gray-400 text-xs" id="${rowId}_icon"></i>
                        <span class="text-sm">${new Date(payment.date).toLocaleDateString()}</span>
                    </div>
                </td>
                <td class="p-3 font-mono text-sm font-semibold text-blue-600">${payment.receiptNumber || 'N/A'}</td>
                <td class="p-3 font-medium">${escapeHtml(payment.studentName || 'N/A')}</td>
                ${statusGroupCells}
                <td class="p-3 text-right font-bold">UGX ${Math.round(totalAmount).toLocaleString()}</td>
                <td class="p-3">
                    <span class="px-2 py-1 rounded-full text-xs ${methodClass} inline-flex items-center gap-1">
                        ${methodIcon} ${(payment.method || 'CASH').toUpperCase()}
                    </span>
                </td>
                <td class="p-3 text-center">
                    <button onclick="event.stopPropagation(); printPaymentReceipt('${payment.receiptNumber}')" 
                            class="text-blue-600 hover:text-blue-800 p-1 rounded hover:bg-blue-50 transition"
                            title="Print Receipt">
                        <i class="fas fa-print"></i>
                    </button>
                </td>
            </tr>
            
            <!-- DETAILS ROW - Expandable with item breakdown by status group -->
            <tr id="${detailsId}" class="hidden bg-gray-50">
                <td colspan="${5 + statusGroupsSorted.length}" class="p-4">
                    <div class="border-l-4 border-blue-400 pl-4">
                        <p class="text-sm font-semibold mb-3 flex items-center gap-2">
                            <i class="fas fa-list-ul text-blue-600"></i> Payment Details
                        </p>
                        
                        <!-- Tuition -->
                        ${tuitionPaid > 0 ? `
                            <div class="mb-3">
                                <div class="flex justify-between items-center p-3 bg-white rounded-lg border">
                                    <div class="flex items-center gap-2">
                                        <i class="fas fa-money-bill-wave text-blue-600"></i>
                                        <span class="font-medium">💰 Tuition Fee</span>
                                    </div>
                                    <span class="font-semibold text-green-600">UGX ${Math.round(tuitionPaid).toLocaleString()}</span>
                                </div>
                            </div>
                        ` : ''}
                        
                        <!-- Status Group Details (Collapsible per group) -->
                        ${statusGroupsSorted.map(sg => {
                            const items = statusGroupItems[sg.id] || [];
                            if (items.length === 0) return '';
                            
                            const groupTotal = statusGroupTotals[sg.id] || 0;
                            const groupCollapseId = `${detailsId}_group_${sg.id.replace(/[^a-zA-Z0-9]/g, '_')}`;
                            
                            // Badge based on period type
                            let periodBadge = '';
                            if (sg.periodType === 'one_time') periodBadge = '<span class="bg-purple-100 text-purple-800 text-xs px-2 py-0.5 rounded-full ml-2">⭐ One-Time</span>';
                            else if (sg.periodType === 'termly') periodBadge = '<span class="bg-green-100 text-green-800 text-xs px-2 py-0.5 rounded-full ml-2">📅 Termly</span>';
                            else if (sg.periodType === 'yearly') periodBadge = '<span class="bg-orange-100 text-orange-800 text-xs px-2 py-0.5 rounded-full ml-2">📆 Yearly</span>';
                            
                            return `
                                <div class="mb-3 border rounded-lg overflow-hidden">
                                    <div class="flex justify-between items-center p-3 bg-white cursor-pointer hover:bg-gray-50"
                                         onclick="togglePaymentDetailsGroup('${groupCollapseId}')">
                                        <div class="flex items-center gap-2 flex-wrap">
                                            <i class="fas fa-tag text-purple-500"></i>
                                            <span class="font-semibold">🏷️ ${escapeHtml(sg.name)}</span>
                                            ${periodBadge}
                                        </div>
                                        <div class="flex items-center gap-3">
                                            <span class="font-bold text-green-600">UGX ${Math.round(groupTotal).toLocaleString()}</span>
                                            <i class="fas fa-chevron-down text-gray-400 text-xs transition-transform" id="${groupCollapseId}_icon"></i>
                                        </div>
                                    </div>
                                    <div id="${groupCollapseId}" class="hidden p-3 bg-gray-50 border-t">
                                        <div class="text-sm font-semibold mb-2 pb-1 border-b">📦 Items Breakdown:</div>
                                        <div class="space-y-2">
                                            ${items.map(item => {
                                                let paymentDetail = '';
                                                let detailColor = '';
                                                
                                                if (item.paymentType === 'paid_cash') {
                                                    paymentDetail = `💵 Paid Cash: UGX ${Math.round(item.amount).toLocaleString()}`;
                                                    detailColor = 'text-blue-600';
                                                } else if (item.paymentType === 'brought_item') {
                                                    paymentDetail = `📦 Items Brought: ${item.itemsBrought} of ${item.quantityRequired || 1} required`;
                                                    if (item.unitPrice) {
                                                        paymentDetail += ` (UGX ${Math.round(item.amount).toLocaleString()} value)`;
                                                    }
                                                    detailColor = 'text-green-600';
                                                } else {
                                                    paymentDetail = `💰 Amount: UGX ${Math.round(item.amount).toLocaleString()}`;
                                                    detailColor = 'text-green-600';
                                                }
                                                
                                                return `
                                                    <div class="bg-white rounded-lg p-3 border shadow-sm">
                                                        <div class="flex justify-between items-start">
                                                            <div>
                                                                <p class="font-medium">📦 ${escapeHtml(item.name)}</p>
                                                                <p class="text-xs text-gray-500">${escapeHtml(item.componentName)}</p>
                                                            </div>
                                                            <div class="text-right">
                                                                <p class="text-sm font-semibold text-green-600">UGX ${Math.round(item.amount).toLocaleString()}</p>
                                                                <p class="text-xs ${detailColor}">${paymentDetail}</p>
                                                            </div>
                                                        </div>
                                                        ${item.itemsBrought > 0 && item.quantityRequired ? `
                                                            <div class="mt-2 pt-2 border-t text-xs text-gray-500">
                                                                <span>📊 Progress: ${item.itemsBrought} of ${item.quantityRequired} items delivered</span>
                                                                <div class="w-full bg-gray-200 rounded-full h-1 mt-1">
                                                                    <div class="bg-green-500 rounded-full h-1" style="width: ${Math.min(100, (item.itemsBrought / item.quantityRequired) * 100)}%"></div>
                                                                </div>
                                                            </div>
                                                        ` : ''}
                                                    </div>
                                                `;
                                            }).join('')}
                                        </div>
                                    </div>
                                </div>
                            `;
                        }).join('')}
                        
                        ${payment.reference ? `
                            <div class="mt-3 text-sm text-gray-500 bg-white p-2 rounded border">
                                <i class="fas fa-hashtag"></i> Reference: ${payment.reference}
                            </div>
                        ` : ''}
                        
                        ${payment.notes ? `
                            <div class="mt-2 text-sm text-gray-500 bg-white p-2 rounded border">
                                <i class="fas fa-pencil-alt"></i> Notes: ${payment.notes}
                            </div>
                        ` : ''}
                    </div>
                </td>
            </tr>
        `;
    }
    
    return html;
}

// ==================== TOGGLE PAYMENT DETAILS GROUP ====================

function togglePaymentDetailsGroup(collapseId) {
    const detailsDiv = document.getElementById(collapseId);
    const icon = document.getElementById(`${collapseId}_icon`);
    
    if (detailsDiv) {
        if (detailsDiv.classList.contains('hidden')) {
            detailsDiv.classList.remove('hidden');
            if (icon) {
                icon.classList.remove('fa-chevron-down');
                icon.classList.add('fa-chevron-up');
            }
        } else {
            detailsDiv.classList.add('hidden');
            if (icon) {
                icon.classList.remove('fa-chevron-up');
                icon.classList.add('fa-chevron-down');
            }
        }
    }
}

