// ==================== PRINT RECEIPT ====================

async function printReceipt(receiptNumber) {
    try {
        const response = await fetch('/api/fee/payments');
        const payments = await response.json();
        const payment = payments.find(p => p.receiptNumber === receiptNumber);
        
        if (!payment) {
            alert('Payment record not found');
            return;
        }
        
        const schoolRes = await fetch('/api/school');
        const schoolData = await schoolRes.json();
        const school = schoolData.school || {};
        
        // Calculate totals
        let oneTimeTotal = 0, termlyTotal = 0, yearlyTotal = 0;
        
        if (payment.activityItemPayments) {
            for (const item of payment.activityItemPayments) {
                const amt = item.paymentType === 'paid_cash' ? (item.amountPaid || 0) : (item.cashEquivalent || 0);
                if (item.periodType === 'one_time') oneTimeTotal += amt;
                else if (item.periodType === 'termly') termlyTotal += amt;
                else if (item.periodType === 'yearly') yearlyTotal += amt;
            }
        }
        
        const total = (payment.tuitionPaid || 0) + oneTimeTotal + termlyTotal + yearlyTotal;
        
        const win = window.open('', '_blank');
        win.document.write(`
            <!DOCTYPE html>
            <html>
            <head>
                <title>Receipt - ${payment.receiptNumber}</title>
                <style>
                    body { font-family: Arial, sans-serif; padding: 40px; }
                    .receipt { max-width: 400px; margin: 0 auto; border: 1px solid #ddd; padding: 20px; border-radius: 10px; }
                    .header { text-align: center; margin-bottom: 20px; }
                    .title { font-size: 24px; font-weight: bold; }
                    .row { display: flex; justify-content: space-between; margin: 10px 0; padding: 5px 0; border-bottom: 1px dashed #eee; }
                    .total { font-size: 18px; font-weight: bold; border-top: 2px solid #333; padding-top: 10px; }
                    @media print { body { padding: 0; } .no-print { display: none; } }
                </style>
            </head>
            <body>
                <div class="receipt">
                    <div class="header">
                        <div class="title">FEE PAYMENT RECEIPT</div>
                        <div class="school-name">${escapeHtml(school.schoolName || 'School Name')}</div>
                        <div>Receipt: ${payment.receiptNumber}</div>
                    </div>
                    <div class="row"><strong>Date:</strong> <span>${new Date(payment.date).toLocaleDateString()}</span></div>
                    <div class="row"><strong>Student:</strong> <span>${escapeHtml(payment.studentName)}</span></div>
                    <div class="row"><strong>Admission:</strong> <span>${payment.admissionNumber}</span></div>
                    <div class="row"><strong>Term:</strong> <span>Term ${payment.term} - ${payment.academicYear}</span></div>
                    <div class="row"><strong>Method:</strong> <span>${payment.method?.toUpperCase() || 'CASH'}</span></div>
                    <div class="row"><strong>Tuition:</strong> <span>UGX ${(payment.tuitionPaid || 0).toLocaleString()}</span></div>
                    ${oneTimeTotal > 0 ? `<div class="row"><strong>One-Time:</strong> <span>UGX ${oneTimeTotal.toLocaleString()}</span></div>` : ''}
                    ${termlyTotal > 0 ? `<div class="row"><strong>Termly:</strong> <span>UGX ${termlyTotal.toLocaleString()}</span></div>` : ''}
                    ${yearlyTotal > 0 ? `<div class="row"><strong>Yearly:</strong> <span>UGX ${yearlyTotal.toLocaleString()}</span></div>` : ''}
                    <div class="row total"><strong>TOTAL:</strong> <span>UGX ${total.toLocaleString()}</span></div>
                    ${payment.notes ? `<div class="row"><strong>Notes:</strong> <span>${payment.notes}</span></div>` : ''}
                    <div class="footer" style="text-align:center; margin-top:20px; font-size:11px; color:#666;">Thank you for your payment!</div>
                </div>
                <div class="no-print" style="text-align:center; margin-top:20px;">
                    <button onclick="window.print()">Print</button>
                    <button onclick="window.close()">Close</button>
                </div>
            </body>
            </html>
        `);
        win.document.close();
    } catch (error) {
        alert('Error printing receipt: ' + error.message);
    }
}

