function escapeHtml(text) {
    if (!text) return '';
    const div = document.createElement('div');
    div.textContent = text;
    return div.innerHTML;
}


// ==================== ADD SEARCH BAR TO PAYMENT HISTORY ====================

function addPaymentHistorySearch() {
    const historyContainer = document.getElementById('history');
    if (!historyContainer) return;
    
    // Check if search bar already exists
    if (document.getElementById('paymentSearchInput')) return;
    
    // Get the table container
    const tableContainer = historyContainer.querySelector('.overflow-x-auto');
    if (!tableContainer) return;
    
    // Add search bar at the top
    const searchHtml = `
        <div id="paymentSearchContainer" class="mb-4 bg-white rounded-xl shadow-sm p-4 border border-gray-200">
            <div class="grid grid-cols-1 md:grid-cols-4 gap-3">
                <div class="relative md:col-span-2">
                    <i class="fas fa-search absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400 text-sm"></i>
                    <input type="text" 
                           id="paymentSearchInput" 
                           placeholder="Search by student name, admission number, or receipt..." 
                           class="w-full pl-10 pr-4 py-2 border rounded-lg text-sm focus:ring-2 focus:ring-blue-500">
                </div>
                <div>
                    <select id="paymentMethodFilter" class="w-full border rounded-lg px-3 py-2 text-sm">
                        <option value="">All Payment Methods</option>
                        <option value="cash">💵 Cash</option>
                        <option value="bank">🏦 Bank Transfer</option>
                        <option value="mobile">📱 Mobile Money</option>
                    </select>
                </div>
                <div class="flex gap-2">
                    <button onclick="resetPaymentFilters()" class="bg-gray-500 text-white px-3 py-2 rounded-lg text-sm hover:bg-gray-600 flex-1">
                        <i class="fas fa-undo-alt"></i> Reset
                    </button>
                    <button onclick="exportPaymentHistoryToCSV()" class="bg-green-600 text-white px-3 py-2 rounded-lg text-sm hover:bg-green-700 flex-1">
                        <i class="fas fa-download"></i> Export
                    </button>
                </div>
            </div>
            <div class="mt-3 text-right text-xs text-gray-500">
                Showing <span id="paymentFilteredCount">0</span> payments
            </div>
        </div>
    `;
    
    // Insert search bar before the table
    tableContainer.insertAdjacentHTML('beforebegin', searchHtml);
    
    // Initialize filter listeners
    initializePaymentFilters();
}

function initializePaymentFilters() {
    const searchInput = document.getElementById('paymentSearchInput');
    const methodFilter = document.getElementById('paymentMethodFilter');
    
    function filterPayments() {
        const searchTerm = (searchInput?.value || '').toLowerCase().trim();
        const methodValue = methodFilter?.value || '';
        
        const rows = document.querySelectorAll('#history .payment-row');
        let visibleCount = 0;
        
        rows.forEach(row => {
            const studentName = row.getAttribute('data-student-name') || '';
            const admission = row.getAttribute('data-admission') || '';
            const receipt = row.getAttribute('data-receipt') || '';
            const rowMethod = row.getAttribute('data-method') || '';
            
            let matchesSearch = true;
            if (searchTerm) {
                matchesSearch = studentName.includes(searchTerm) || 
                               admission.includes(searchTerm) || 
                               receipt.includes(searchTerm);
            }
            
            let matchesMethod = true;
            if (methodValue) {
                matchesMethod = rowMethod === methodValue;
            }
            
            const isVisible = matchesSearch && matchesMethod;
            row.style.display = isVisible ? '' : 'none';
            if (isVisible) visibleCount++;
            
            // Hide associated detail row
            const nextRow = row.nextElementSibling;
            if (nextRow && nextRow.id && nextRow.id.startsWith('payment_details_')) {
                nextRow.style.display = isVisible ? 'none' : 'none';
            }
        });
        
        const filteredCountSpan = document.getElementById('paymentFilteredCount');
        if (filteredCountSpan) filteredCountSpan.innerText = visibleCount;
    }
    
    if (searchInput) {
        searchInput.addEventListener('input', filterPayments);
        searchInput.addEventListener('keyup', filterPayments);
    }
    if (methodFilter) methodFilter.addEventListener('change', filterPayments);
    
    filterPayments();
}

function resetPaymentFilters() {
    const searchInput = document.getElementById('paymentSearchInput');
    const methodFilter = document.getElementById('paymentMethodFilter');
    
    if (searchInput) searchInput.value = '';
    if (methodFilter) methodFilter.value = '';
    
    initializePaymentFilters();
}

function togglePaymentDetails(rowId, detailsId) {
    const detailsRow = document.getElementById(detailsId);
    const button = document.querySelector(`#${rowId} button:last-child i`);
    
    if (detailsRow) {
        if (detailsRow.classList.contains('hidden')) {
            detailsRow.classList.remove('hidden');
            if (button) {
                button.classList.remove('fa-chevron-down');
                button.classList.add('fa-chevron-up');
            }
        } else {
            detailsRow.classList.add('hidden');
            if (button) {
                button.classList.remove('fa-chevron-up');
                button.classList.add('fa-chevron-down');
            }
        }
    }
}


