// ==================== EXPORT PAYMENT HISTORY TO CSV ====================

async function exportPaymentHistoryToCSV() {
    try {
        const { currentYear, currentTerm } = currentAcademicSettings;
        const response = await fetch('/api/fee/payments');
        let allPayments = await response.json();
        allPayments = Array.isArray(allPayments) ? allPayments : [];
        
        const currentTermPayments = allPayments.filter(p => p && p.term === currentTerm && p.academicYear === currentYear.toString());
        
        const exportData = currentTermPayments.map(p => {
            let oneTimeAmount = 0, termlyAmount = 0, yearlyAmount = 0;
            
            if (p.paymentsByPeriodType) {
                oneTimeAmount += (p.paymentsByPeriodType.one_time || []).reduce((s, i) => s + (i.amountPaid || i.cashEquivalent || 0), 0);
                termlyAmount += (p.paymentsByPeriodType.termly || []).reduce((s, i) => s + (i.amountPaid || i.cashEquivalent || 0), 0);
                yearlyAmount += (p.paymentsByPeriodType.yearly || []).reduce((s, i) => s + (i.amountPaid || i.cashEquivalent || 0), 0);
            }
            
            if (p.activityItemPayments) {
                oneTimeAmount += p.activityItemPayments.filter(i => i.periodType === 'one_time').reduce((s, i) => s + (i.amountPaid || i.cashEquivalent || 0), 0);
                termlyAmount += p.activityItemPayments.filter(i => i.periodType === 'termly').reduce((s, i) => s + (i.amountPaid || i.cashEquivalent || 0), 0);
                yearlyAmount += p.activityItemPayments.filter(i => i.periodType === 'yearly').reduce((s, i) => s + (i.amountPaid || i.cashEquivalent || 0), 0);
            }
            
            return {
                'Date': p.date ? new Date(p.date).toLocaleDateString() : 'N/A',
                'Receipt Number': p.receiptNumber || 'N/A',
                'Student Name': p.studentName || 'N/A',
                'Admission Number': p.admissionNumber || 'N/A',
                'Term': p.term,
                'Academic Year': p.academicYear,
                'Tuition Paid': p.tuitionPaid || 0,
                'One-Time Paid': oneTimeAmount,
                'Termly Paid': termlyAmount,
                'Yearly Paid': yearlyAmount,
                'Total Amount': (p.totalAmount || 0),
                'Payment Method': (p.method || 'cash').toUpperCase(),
                'Reference': p.reference || '',
                'Notes': p.notes || ''
            };
        });
        
        const headers = Object.keys(exportData[0]);
        const csvRows = [headers.join(',')];
        
        for (const row of exportData) {
            const values = headers.map(header => {
                const value = row[header] !== undefined && row[header] !== null ? row[header] : '';
                return `"${String(value).replace(/"/g, '""')}"`;
            });
            csvRows.push(values.join(','));
        }
        
        const csv = csvRows.join('\n');
        const blob = new Blob([csv], { type: 'text/csv;charset=utf-8;' });
        const link = document.createElement('a');
        link.href = URL.createObjectURL(blob);
        link.download = `payment_history_${currentYear}_term${currentTerm}_${new Date().toISOString().split('T')[0]}.csv`;
        link.click();
        URL.revokeObjectURL(link.href);
        
        alert(`✅ ${exportData.length} payment records exported successfully!`);
    } catch (error) {
        console.error('Error exporting payments:', error);
        alert('Error exporting payment history');
    }
}

function escapeHtml(text) {
    if (!text) return '';
    const div = document.createElement('div');
    div.textContent = text;
    return div.innerHTML;
}

