window.togglePaymentDetails = togglePaymentDetails;
window.resetPaymentFilters = resetPaymentFilters;
window.exportPaymentHistoryToCSV = exportPaymentHistoryToCSV;

// Helper function to get payment method class
function getPaymentMethodClass(method) {
    switch(method) {
        case 'cash': return 'bg-green-100 text-green-800';
        case 'bank': return 'bg-blue-100 text-blue-800';
        case 'mobile': return 'bg-purple-100 text-purple-800';
        default: return 'bg-gray-100 text-gray-800';
    }
}

// Helper function to get payment method icon
function getPaymentMethodIcon(method) {
    switch(method) {
        case 'cash': return '💵';
        case 'bank': return '🏦';
        case 'mobile': return '📱';
        default: return '💰';
    }
}

// Function to toggle payment details visibility
function togglePaymentDetails(rowId, detailsId) {
    const detailsRow = document.getElementById(detailsId);
    const button = document.querySelector(`#${rowId} button:last-child i`);
    
    if (detailsRow) {
        detailsRow.classList.toggle('hidden');
        if (button) {
            button.classList.toggle('fa-chevron-down');
            button.classList.toggle('fa-chevron-up');
        }
    }
}

