// ==================== COMPLETE REBUILT STUDENT BALANCES TABLE ====================
// Version: 5.0 - Full numbers, no K abbreviations

function renderBalancesTable(students) {
    if (!students || students.length === 0) {
        return '<tr><td colspan="12" class="text-center p-8 text-gray-500">No students found</td>' + '</tr>';
    }
    
    // Format currency - FULL NUMBERS (no K/M abbreviations)
    function formatMoney(amount) {
        const num = Math.round(Math.abs(amount || 0));
        return num.toLocaleString('en-US');
    }
    
    return students.map(student => {
        // Calculate proper status based on actual data
        let statusText = '';
        let statusColor = '';
        let statusIcon = '';
        
        const tuitionPaid = student.tuitionPaid || 0;
        const tuitionExpected = student.expectedTuition || 0;
        const termlyPaid = student.termlyPaid || 0;
        const termlyExpected = student.expectedTermly || 0;
        const oneTimePaid = student.oneTimePaid || 0;
        const oneTimeExpected = student.expectedOneTime || 0;
        const yearlyPaid = student.yearlyPaid || 0;
        const yearlyExpected = student.expectedYearly || 0;
        
        const totalPaid = (student.totalPaid !== undefined) ? student.totalPaid : (tuitionPaid + termlyPaid + oneTimePaid + yearlyPaid);
        const totalExpected = (student.totalExpected !== undefined) ? student.totalExpected : (tuitionExpected + termlyExpected + oneTimeExpected + yearlyExpected);
        const balance = totalExpected - totalPaid;
        
        // Determine status
        if (balance < -10) {
            statusText = 'Credit Balance';
            statusColor = 'bg-blue-100 text-blue-800';
            statusIcon = '💰';
        } else if (Math.abs(balance) <= 10 && totalPaid > 0) {
            statusText = 'Fully Paid';
            statusColor = 'bg-green-100 text-green-800';
            statusIcon = '✅';
        } else if (balance > 0 && totalPaid === 0) {
            statusText = 'No Payment';
            statusColor = 'bg-gray-100 text-gray-800';
            statusIcon = '📋';
        } else if (balance > 0 && totalPaid > 0) {
            statusText = 'Partial Payment';
            statusColor = 'bg-yellow-100 text-yellow-800';
            statusIcon = '⚠️';
        } else if (balance > totalExpected) {
            statusText = 'Critical Overdue';
            statusColor = 'bg-red-100 text-red-800';
            statusIcon = '🔴';
        } else {
            statusText = 'Good Standing';
            statusColor = 'bg-green-100 text-green-800';
            statusIcon = '✅';
        }
        
        // Tuition display
        const tuitionDisplay = tuitionPaid > 0 ? 
            `<span class="font-semibold">UGX ${formatMoney(tuitionPaid)}</span><br><span class="text-xs text-gray-400">/ ${formatMoney(tuitionExpected)}</span>` :
            `<span class="text-gray-400">UGX 0</span><br><span class="text-xs text-gray-400">/ ${formatMoney(tuitionExpected)}</span>`;
        
        // One-Time display
        const oneTimeDisplay = (oneTimeExpected || 0) > 0 ?
            (oneTimePaid > 0 ? 
                `<span class="font-semibold">UGX ${formatMoney(oneTimePaid)}</span><br><span class="text-xs text-gray-400">/ ${formatMoney(oneTimeExpected)}</span>` :
                `<span class="text-gray-400">UGX 0</span><br><span class="text-xs text-gray-400">/ ${formatMoney(oneTimeExpected)}</span>`) :
            `<span class="text-gray-400">-</span>`;
        
        // Termly display
        const termlyDisplay = termlyPaid > 0 ?
            `<span class="font-semibold">UGX ${formatMoney(termlyPaid)}</span><br><span class="text-xs text-gray-400">/ ${formatMoney(termlyExpected)}</span>` :
            `<span class="text-gray-400">UGX 0</span><br><span class="text-xs text-gray-400">/ ${formatMoney(termlyExpected)}</span>`;
        
        // Yearly display
        const yearlyDisplay = (yearlyExpected || 0) > 0 ?
            (yearlyPaid > 0 ? 
                `<span class="font-semibold">UGX ${formatMoney(yearlyPaid)}</span><br><span class="text-xs text-gray-400">/ ${formatMoney(yearlyExpected)}</span>` :
                `<span class="text-gray-400">UGX 0</span><br><span class="text-xs text-gray-400">/ ${formatMoney(yearlyExpected)}</span>`) :
            `<span class="text-gray-400">-</span>`;
        
        // Balance display
        let balanceDisplay = '';
        let balanceClass = '';
        if (balance < 0) {
            balanceDisplay = `Credit: UGX ${formatMoney(Math.abs(balance))}`;
            balanceClass = 'text-blue-600';
        } else if (balance > 0) {
            balanceDisplay = `UGX ${formatMoney(balance)}`;
            balanceClass = 'text-red-600 font-bold';
        } else {
            balanceDisplay = 'UGX 0';
            balanceClass = 'text-green-600';
        }
        
        // Total Paid display
        const totalPaidDisplay = totalPaid > 0 ? `UGX ${formatMoney(totalPaid)}` : 'UGX 0';
        
        // Bursary badge
        const bursaryBadge = student.bursaryName || student.discountDisplay ? 
            `<div class="text-xs text-green-600 mt-1">🎖️ ${student.bursaryName || student.discountDisplay}</div>` : '';
        
        // Initials for avatar
        const initials = `${(student.firstName || '').charAt(0)}${(student.lastName || '').charAt(0)}`;
        const avatarColors = ['bg-red-500', 'bg-blue-500', 'bg-green-500', 'bg-purple-500', 'bg-pink-500', 'bg-indigo-500', 'bg-orange-500'];
        const avatarColor = avatarColors[Math.floor(Math.random() * avatarColors.length)];
        
        return `
            <tr class="border-b hover:bg-gray-50 student-balance-row"
                data-student-name="${(student.firstName + ' ' + student.lastName).toLowerCase()}"
                data-admission="${(student.admissionNumber || '').toLowerCase()}"
                data-class="${(student.currentClass || '').toLowerCase()}"
                data-status="${statusText.toLowerCase()}">
                <td class="p-3 font-mono text-sm">${student.admissionNumber || 'N/A'}</td>
                <td class="p-3">
                    <div class="flex items-center gap-2">
                        <div class="w-8 h-8 ${avatarColor} rounded-full flex items-center justify-center text-white text-xs font-bold">${initials || 'S'}</div>
                        <div>
                            <p class="font-medium">${escapeHtml(student.firstName || '')} ${escapeHtml(student.lastName || '')}</p>
                            <p class="text-xs text-gray-500">${student.gender || ''}</p>
                        </div>
                    </div>
                </td>
                <td class="p-3">${student.currentClass || 'N/A'}</td>
                <td class="p-3 text-right">
                    ${tuitionDisplay}
                    ${bursaryBadge}
                </td>
                <td class="p-3 text-right">${oneTimeDisplay}</td>
                <td class="p-3 text-right">${termlyDisplay}</td>
                <td class="p-3 text-right">${yearlyDisplay}</td>
                <td class="p-3 text-right font-semibold text-green-600">${totalPaidDisplay}</td>
                <td class="p-3 text-right ${balanceClass}">${balanceDisplay}</td>
                <td class="p-3">
                    <span class="px-2 py-1 rounded-full text-xs ${statusColor}">
                        ${statusIcon} ${statusText}
                    </span>
                </td>
                <td class="p-3 text-center">
                    <div class="flex justify-center gap-2">
                        <button onclick="viewStudentDetailsList('${student.id}')" class="text-blue-600 hover:text-blue-800" title="View Details">
                            <i class="fas fa-eye"></i>
                        </button>
                        <button onclick="makePaymentForStudent('${student.id}')" class="text-green-600 hover:text-green-800" title="Make Payment">
                            <i class="fas fa-receipt"></i>
                        </button>
                    </div>
                </td>
            </tr>
        `;
    }).join('');
}

// Helper function to add search and filters to student balances
function addStudentBalancesSearch() {
    const balancesContainer = document.getElementById('balances');
    if (!balancesContainer) return;
    
    // Check if search bar already exists
    if (document.getElementById('balancesSearchInput')) return;
    
    // Get the table container
    const tableContainer = balancesContainer.querySelector('.overflow-x-auto');
    if (!tableContainer) return;
    
    // Get unique classes for filter
    const students = window.allStudentsData || [];
    const uniqueClasses = [...new Set(students.map(s => s.currentClass).filter(c => c && c !== 'Not Assigned'))];
    
    // Add search bar at the top
    const searchHtml = `
        <div id="balancesSearchContainer" class="mb-4 bg-white rounded-xl shadow-sm p-4 border border-gray-200">
            <div class="grid grid-cols-1 md:grid-cols-4 gap-3">
                <div class="relative md:col-span-2">
                    <i class="fas fa-search absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400 text-sm"></i>
                    <input type="text" 
                           id="balancesSearchInput" 
                           placeholder="Search by student name, admission number, or class..." 
                           class="w-full pl-10 pr-4 py-2 border rounded-lg text-sm focus:ring-2 focus:ring-blue-500">
                </div>
                <div>
                    <select id="balancesClassFilter" class="w-full border rounded-lg px-3 py-2 text-sm">
                        <option value="">All Classes</option>
                        ${uniqueClasses.map(c => `<option value="${c}">${escapeHtml(c)}</option>`).join('')}
                    </select>
                </div>
                <div>
                    <select id="balancesStatusFilter" class="w-full border rounded-lg px-3 py-2 text-sm">
                        <option value="">All Status</option>
                        <option value="fully paid">✅ Fully Paid</option>
                        <option value="credit balance">💰 Credit Balance</option>
                        <option value="partial payment">⚠️ Partial Payment</option>
                        <option value="no payment">📋 No Payment</option>
                        <option value="critical overdue">🔴 Critical Overdue</option>
                    </select>
                </div>
            </div>
            <div class="flex justify-between items-center mt-3 pt-2 border-t">
                <div class="text-xs text-gray-500">
                    Showing <span id="balancesFilteredCount">0</span> students
                </div>
                <div class="flex gap-2">
                    <button onclick="resetBalancesFilters()" class="bg-gray-500 text-white px-3 py-1.5 rounded-lg text-xs hover:bg-gray-600">
                        <i class="fas fa-undo-alt"></i> Reset Filters
                    </button>
                    <button onclick="exportBalancesToCSV()" class="bg-green-600 text-white px-3 py-1.5 rounded-lg text-xs hover:bg-green-700">
                        <i class="fas fa-download"></i> Export CSV
                    </button>
                </div>
            </div>
        </div>
    `;
    
    // Insert search bar before the table
    tableContainer.insertAdjacentHTML('beforebegin', searchHtml);
    
    // Initialize filter listeners
    initializeBalancesFilters();
}

function initializeBalancesFilters() {
    const searchInput = document.getElementById('balancesSearchInput');
    const classFilter = document.getElementById('balancesClassFilter');
    const statusFilter = document.getElementById('balancesStatusFilter');
    
    function filterBalances() {
        const searchTerm = (searchInput?.value || '').toLowerCase().trim();
        const classValue = classFilter?.value || '';
        const statusValue = statusFilter?.value || '';
        
        const rows = document.querySelectorAll('#balances .student-balance-row');
        let visibleCount = 0;
        
        rows.forEach(row => {
            const studentName = row.getAttribute('data-student-name') || '';
            const admission = row.getAttribute('data-admission') || '';
            const studentClass = row.getAttribute('data-class') || '';
            const studentStatus = row.getAttribute('data-status') || '';
            
            let matchesSearch = true;
            if (searchTerm) {
                matchesSearch = studentName.includes(searchTerm) || admission.includes(searchTerm);
            }
            
            let matchesClass = true;
            if (classValue) {
                matchesClass = studentClass === classValue.toLowerCase();
            }
            
            let matchesStatus = true;
            if (statusValue) {
                matchesStatus = studentStatus === statusValue;
            }
            
            const isVisible = matchesSearch && matchesClass && matchesStatus;
            row.style.display = isVisible ? '' : 'none';
            if (isVisible) visibleCount++;
        });
        
        const filteredCountSpan = document.getElementById('balancesFilteredCount');
        if (filteredCountSpan) filteredCountSpan.innerText = visibleCount;
    }
    
    if (searchInput) {
        searchInput.addEventListener('input', filterBalances);
        searchInput.addEventListener('keyup', filterBalances);
    }
    if (classFilter) classFilter.addEventListener('change', filterBalances);
    if (statusFilter) statusFilter.addEventListener('change', filterBalances);
    
    filterBalances();
}

function resetBalancesFilters() {
    const searchInput = document.getElementById('balancesSearchInput');
    const classFilter = document.getElementById('balancesClassFilter');
    const statusFilter = document.getElementById('balancesStatusFilter');
    
    if (searchInput) searchInput.value = '';
    if (classFilter) classFilter.value = '';
    if (statusFilter) statusFilter.value = '';
    
    initializeBalancesFilters();
}

async function exportBalancesToCSV() {
    const students = window.allStudentsData || [];
    if (students.length === 0) {
        alert('No data to export');
        return;
    }
    
    function formatMoney(amount) {
        const num = Math.round(amount || 0);
        return num.toLocaleString('en-US');
    }
    
    const exportData = students.map(s => {
        const totalPaid = s.totalPaid || (s.tuitionPaid + s.termlyPaid + s.oneTimePaid + s.yearlyPaid);
        const totalExpected = s.totalExpected || (s.expectedTuition + s.expectedTermly + s.expectedOneTime + s.expectedYearly);
        const balance = totalExpected - totalPaid;
        
        let status = '';
        if (balance < -10) status = 'Credit Balance';
        else if (Math.abs(balance) <= 10 && totalPaid > 0) status = 'Fully Paid';
        else if (balance > 0 && totalPaid === 0) status = 'No Payment';
        else if (balance > 0 && totalPaid > 0) status = 'Partial Payment';
        else if (balance > totalExpected) status = 'Critical Overdue';
        else status = 'Good Standing';
        
        return {
            'Admission Number': s.admissionNumber || '',
            'First Name': s.firstName || '',
            'Last Name': s.lastName || '',
            'Class': s.currentClass || '',
            'Tuition Paid': s.tuitionPaid || 0,
            'Tuition Expected': s.expectedTuition || 0,
            'Tuition Balance': (s.expectedTuition || 0) - (s.tuitionPaid || 0),
            'One-Time Paid': s.oneTimePaid || 0,
            'One-Time Expected': s.expectedOneTime || 0,
            'Termly Paid': s.termlyPaid || 0,
            'Termly Expected': s.expectedTermly || 0,
            'Yearly Paid': s.yearlyPaid || 0,
            'Yearly Expected': s.expectedYearly || 0,
            'Total Paid': totalPaid,
            'Total Expected': totalExpected,
            'Balance': balance,
            'Status': status,
            'Bursary': s.bursaryName || s.discountDisplay || 'None'
        };
    });
    
    const headers = Object.keys(exportData[0]);
    const csvRows = [headers.join(',')];
    
    for (const row of exportData) {
        const values = headers.map(header => {
            const value = row[header] !== undefined && row[header] !== null ? row[header] : '';
            return `"${String(value).replace(/"/g, '""')}"`;
        });
        csvRows.push(values.join(','));
    }
    
    const csv = csvRows.join('\n');
    const blob = new Blob([csv], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement('a');
    link.href = URL.createObjectURL(blob);
    link.download = `student_balances_${new Date().toISOString().split('T')[0]}.csv`;
    link.click();
    URL.revokeObjectURL(link.href);
    
    alert(`✅ ${exportData.length} student records exported successfully!`);
}

function escapeHtml(text) {
    if (!text) return '';
    const div = document.createElement('div');
    div.textContent = text;
    return div.innerHTML;
}


