function getUniqueClasses() {
    const students = window.allStudentsData || [];
    const classes = [...new Set(students.map(s => s.currentClass).filter(c => c && c !== 'Not Assigned'))];
    return classes.map(c => `<option value="${c}">${c}</option>`).join('');
}

function initializeBalancesFilters() {
    const searchInput = document.getElementById('balancesSearchInput');
    const classFilter = document.getElementById('balancesClassFilter');
    const statusFilter = document.getElementById('balancesStatusFilter');
    
    function filterBalances() {
        const searchTerm = (searchInput?.value || '').toLowerCase().trim();
        const classValue = classFilter?.value || '';
        const statusValue = statusFilter?.value || '';
        
        const rows = document.querySelectorAll('#balances .student-balance-row');
        let visibleCount = 0;
        
        rows.forEach(row => {
            const studentName = row.getAttribute('data-student-name') || '';
            const admission = row.getAttribute('data-admission') || '';
            const studentClass = row.getAttribute('data-class') || '';
            const studentStatus = row.getAttribute('data-status') || '';
            
            let matchesSearch = true;
            if (searchTerm) {
                matchesSearch = studentName.includes(searchTerm) || admission.includes(searchTerm);
            }
            
            let matchesClass = true;
            if (classValue) {
                matchesClass = studentClass === classValue.toLowerCase();
            }
            
            let matchesStatus = true;
            if (statusValue) {
                matchesStatus = studentStatus === statusValue;
            }
            
            const isVisible = matchesSearch && matchesClass && matchesStatus;
            row.style.display = isVisible ? '' : 'none';
            if (isVisible) visibleCount++;
        });
        
        const filteredCountSpan = document.getElementById('balancesFilteredCount');
        if (filteredCountSpan) filteredCountSpan.innerText = visibleCount;
    }
    
    if (searchInput) {
        searchInput.addEventListener('input', filterBalances);
        searchInput.addEventListener('keyup', filterBalances);
    }
    if (classFilter) classFilter.addEventListener('change', filterBalances);
    if (statusFilter) statusFilter.addEventListener('change', filterBalances);
    
    filterBalances();
}

function resetBalancesFilters() {
    const searchInput = document.getElementById('balancesSearchInput');
    const classFilter = document.getElementById('balancesClassFilter');
    const statusFilter = document.getElementById('balancesStatusFilter');
    
    if (searchInput) searchInput.value = '';
    if (classFilter) classFilter.value = '';
    if (statusFilter) statusFilter.value = '';
    
    initializeBalancesFilters();
}

