function setFullTuitionAmount() {
    const checkbox = document.getElementById('fullTuitionCheck');
    const tuitionInput = document.getElementById('tuitionAmount');
    if (checkbox?.checked && tuitionInput) {
        tuitionInput.value = tuitionInput.max;
        calculateCollectionTotal();
    } else if (tuitionInput) {
        tuitionInput.value = 0;
        calculateCollectionTotal();
    }
}

// ==================== REPLACE resetCollectionForm FUNCTION ====================
function resetCollectionForm() {
    const tuitionInput = document.getElementById('tuitionAmount');
    if (tuitionInput) tuitionInput.value = '0';
    
    const fullTuitionCheck = document.getElementById('fullTuitionCheck');
    if (fullTuitionCheck) fullTuitionCheck.checked = false;
    
    document.querySelectorAll('.cashAmountInput, .itemsBroughtInput').forEach(input => {
        input.value = '';
    });
    
    document.querySelectorAll('input[type="radio"][value="cash"]').forEach(radio => {
        radio.checked = true;
    });
    
    document.querySelectorAll('.payment-input-group').forEach(group => {
        if (group.id && group.id.startsWith('cashInput')) {
            group.classList.remove('hidden');
        } else if (group.id && group.id.startsWith('itemInput')) {
            group.classList.add('hidden');
        }
    });
    
    document.querySelectorAll('[id^="itemTotal_"]').forEach(span => {
        span.innerHTML = 'UGX 0';
    });
    
    document.querySelectorAll('[id^="itemStatus_"]').forEach(span => {
        span.innerHTML = '❌ Not Paid';
        span.className = 'font-medium px-2 py-0.5 rounded-full bg-red-100 text-red-600';
    });
    
    ['one_time', 'termly', 'yearly'].forEach(period => {
        const totalSpan = document.getElementById(`${period}TotalAmount`);
        if (totalSpan) totalSpan.innerHTML = 'UGX 0';
    });
    
    const paymentReference = document.getElementById('paymentReference');
    const paymentNotes = document.getElementById('paymentNotes');
    if (paymentReference) paymentReference.value = '';
    if (paymentNotes) paymentNotes.value = '';
    
    calculateCollectionTotal();
}

// ==================== INITIALIZATION FUNCTIONS ====================

function initializeFeeTabs() {
    const tabs = document.querySelectorAll('.fee-tab');
    tabs.forEach(tab => {
        tab.addEventListener('click', () => {
            const tabId = tab.dataset.tab;
            tabs.forEach(t => {
                t.classList.remove('active', 'border-b-2', 'border-blue-600', 'text-blue-600');
                t.classList.add('text-gray-600');
            });
            tab.classList.add('active', 'border-b-2', 'border-blue-600', 'text-blue-600');
            tab.classList.remove('text-gray-600');
            
            document.querySelectorAll('.fee-tab-content').forEach(c => c.classList.add('hidden'));
            const activeTab = document.getElementById(tabId);
            if (activeTab) activeTab.classList.remove('hidden');
            
            // Load statistics when stats tab is clicked
            if (tabId === 'stats' && typeof showFeeStructureStatistics === 'function') {
                showFeeStructureStatistics();
            }
        });
    });
} 

function initializeFeeSearchAndFilters(students) {
    const searchInput = document.getElementById('feeStudentSearch');
    const classFilter = document.getElementById('feeClassFilter');
    const statusFilter = document.getElementById('feeStatusFilter');
    const studentSelect = document.getElementById('collectStudentSelect');
    
    if (!studentSelect) return;
    
    function filterStudents() {
        const searchTerm = searchInput?.value.toLowerCase().trim() || '';
        const classValue = classFilter?.value || '';
        const statusValue = statusFilter?.value || '';
        
        let visibleCount = 0;
        let firstVisibleValue = null;
        
        for (let i = 1; i < studentSelect.options.length; i++) {
            const option = studentSelect.options[i];
            const optionText = option.text.toLowerCase();
            const optionAdmission = (option.getAttribute('data-admission') || '').toLowerCase();
            const optionClass = option.getAttribute('data-class') || '';
            const optionStatus = option.getAttribute('data-status') || '';
            
            let matchesSearch = true;
            if (searchTerm) {
                matchesSearch = optionText.includes(searchTerm) || optionAdmission.includes(searchTerm);
            }
            
            let matchesClass = true;
            if (classValue) {
                matchesClass = optionClass === classValue;
            }
            
            let matchesStatus = true;
            if (statusValue) {
                matchesStatus = optionStatus === statusValue;
            }
            
            const isVisible = matchesSearch && matchesClass && matchesStatus;
            option.style.display = isVisible ? '' : 'none';
            
            if (isVisible) {
                visibleCount++;
                if (!firstVisibleValue) {
                    firstVisibleValue = option.value;
                }
            }
        }
        
        const currentValue = studentSelect.value;
        if (visibleCount > 0 && (!currentValue || studentSelect.options[studentSelect.selectedIndex]?.style.display === 'none')) {
            if (firstVisibleValue) {
                studentSelect.value = firstVisibleValue;
                studentSelect.dispatchEvent(new Event('change'));
            }
        } else if (visibleCount === 0 && studentSelect.value) {
            studentSelect.value = '';
            document.getElementById('collectionFormContainer').innerHTML = '';
        }
    }
    
    if (searchInput) {
        searchInput.addEventListener('input', filterStudents);
        searchInput.addEventListener('keyup', filterStudents);
    }
    if (classFilter) classFilter.addEventListener('change', filterStudents);
    if (statusFilter) statusFilter.addEventListener('change', filterStudents);
    
    filterStudents();
}

function initializeBalanceFilters() {
    const balanceSearch = document.getElementById('balanceSearch');
    const balanceClassFilter = document.getElementById('balanceClassFilter');
    
    if (!balanceSearch || !balanceClassFilter) return;
    
    function filterBalances() {
        const searchTerm = balanceSearch.value.toLowerCase().trim();
        const classValue = balanceClassFilter.value;
        
        const rows = document.querySelectorAll('#balancesTableBody tr');
        rows.forEach(row => {
            const name = row.cells[1]?.innerText.toLowerCase() || '';
            const admission = row.cells[0]?.innerText.toLowerCase() || '';
            const rowClass = row.getAttribute('data-class') || '';
            
            let matchesSearch = true;
            if (searchTerm) {
                matchesSearch = name.includes(searchTerm) || admission.includes(searchTerm);
            }
            
            let matchesClass = true;
            if (classValue) {
                matchesClass = rowClass === classValue;
            }
            
            row.style.display = matchesSearch && matchesClass ? '' : 'none';
        });
    }
    
    balanceSearch.addEventListener('input', filterBalances);
    balanceSearch.addEventListener('keyup', filterBalances);
    balanceClassFilter.addEventListener('change', filterBalances);
    
    filterBalances();
}

function loadStudentForCollection(studentId) {
    const studentSelect = document.getElementById('collectStudentSelect');
    if (studentSelect) {
        studentSelect.value = studentId;
        studentSelect.dispatchEvent(new Event('change'));
    }
    document.querySelector('.fee-tab[data-tab="collect"]')?.click();
}

function exportBalancesReport() {
    const students = window.enhancedStudentsData || [];
    if (students.length === 0) {
        alert('No data to export');
        return;
    }
    
    const exportData = students.map(s => ({
        'Admission Number': s.admissionNumber,
        'Student Name': `${s.firstName} ${s.lastName}`,
        'Class': s.currentClass,
        'Fee Structure': s.feeStructure?.name || 'Not Assigned',
        'Bursary': s.appliedBursary?.name || 'None',
        'Tuition Expected': s.expectedTuition,
        'Tuition Paid': s.tuitionPaid,
        'Tuition Balance': s.tuitionBalance,
        'One-Time Expected': s.expectedOneTime,
        'One-Time Paid': s.oneTimePaid,
        'One-Time Balance': s.oneTimeBalance,
        'Termly Expected': s.expectedTermly,
        'Termly Paid': s.termlyPaid,
        'Termly Balance': s.termlyBalance,
        'Yearly Expected': s.expectedYearly,
        'Yearly Paid': s.yearlyPaid,
        'Yearly Balance': s.yearlyBalance,
        'Total Expected': s.totalExpected,
        'Total Paid': s.totalPaid,
        'Total Balance': s.balance,
        'Status': s.status
    }));
    
    const headers = Object.keys(exportData[0]);
    const csvRows = [headers.join(',')];
    
    for (const row of exportData) {
        const values = headers.map(header => {
            const value = row[header] !== undefined && row[header] !== null ? row[header] : '';
            return `"${String(value).replace(/"/g, '""')}"`;
        });
        csvRows.push(values.join(','));
    }
    
    const csv = csvRows.join('\n');
    const blob = new Blob([csv], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement('a');
    const url = URL.createObjectURL(blob);
    link.setAttribute('href', url);
    link.setAttribute('download', `fee_balances_${new Date().toISOString().split('T')[0]}.csv`);
    link.style.visibility = 'hidden';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
    
    alert(`✅ Balances exported successfully for ${students.length} students`);
}

