// ==================== RENDER PERIOD COLLECTION GROUP ====================
function renderPeriodCollectionGroup(items, periodType, title, color, note) {
    const bgColor = color === 'purple' ? 'bg-purple-50' : color === 'green' ? 'bg-green-50' : 'bg-orange-50';
    const borderColor = color === 'purple' ? 'border-purple-200' : color === 'green' ? 'border-green-200' : 'border-orange-200';
    const textColor = color === 'purple' ? 'text-purple-600' : color === 'green' ? 'text-green-600' : 'text-orange-600';
    
    return `
        <div class="border-2 ${borderColor} rounded-lg p-4 ${bgColor}">
            <h3 class="font-bold text-lg mb-3 flex items-center">
                <span class="bg-${color}-600 text-white rounded-full w-7 h-7 flex items-center justify-center text-sm mr-2">${periodType === 'one_time' ? '⭐' : periodType === 'termly' ? '📅' : '📆'}</span>
                ${title}
            </h3>
            <p class="text-sm text-gray-600 mb-3">${note}</p>
            <div id="${periodType}ItemsList" class="space-y-3 max-h-96 overflow-y-auto">
                ${items.map(item => `
                    <div class="bg-white rounded-lg p-3 border shadow-sm">
                        <div class="flex justify-between items-start mb-2">
                            <div>
                                <p class="font-semibold">${item.itemName}</p>
                                <p class="text-xs text-gray-500">${item.componentName}</p>
                            </div>
                            <div class="text-right">
                                <p class="text-sm font-semibold">UGX ${item.unitPrice.toLocaleString()} / each</p>
                                <p class="text-xs text-gray-500">Total: UGX ${item.totalAmount.toLocaleString()} (${item.quantity} items)</p>
                            </div>
                        </div>
                        
                        <div class="mt-3">
                            <label class="block text-sm font-medium mb-2">Payment Type:</label>
                            <div class="flex gap-4 mb-3">
                                <label class="flex items-center cursor-pointer">
                                    <input type="radio" name="paymentType_${item.itemId}" value="paid_cash" 
                                           class="mr-2 paymentTypeRadio" data-item-id="${item.itemId}" data-period-type="${periodType}"
                                           onchange="togglePaymentInputs('${item.itemId}', 'cash')" checked>
                                    <span class="text-sm">💵 Pay Cash</span>
                                </label>
                                ${item.isTangible !== false ? `
                                    <label class="flex items-center cursor-pointer">
                                        <input type="radio" name="paymentType_${item.itemId}" value="brought_item" 
                                               class="mr-2 paymentTypeRadio" data-item-id="${item.itemId}" data-period-type="${periodType}"
                                               onchange="togglePaymentInputs('${item.itemId}', 'item')">
                                        <span class="text-sm">📦 Bring Item</span>
                                    </label>
                                ` : ''}
                            </div>
                            
                            <!-- Cash Payment Input -->
                            <div id="cashInput_${item.itemId}" class="payment-input-group">
                                <label class="block text-sm font-medium mb-1">Amount to Pay (UGX)</label>
                                <input type="number" class="w-full border rounded-lg px-3 py-2 cashAmount" 
                                       data-item-id="${item.itemId}" data-period-type="${periodType}"
                                       data-unit-price="${item.unitPrice}" data-quantity="${item.remainingQuantity}"
                                       data-max="${item.remainingAmount}" placeholder="Max: UGX ${item.remainingAmount.toLocaleString()}"
                                       oninput="updateItemTotal('${item.itemId}', 'cash', ${item.unitPrice}, ${item.remainingQuantity})">
                                <p class="text-xs text-gray-500 mt-1">Remaining: UGX ${item.remainingAmount.toLocaleString()} (${item.remainingQuantity} items)</p>
                                <p id="thatToSay_${item.itemId}" class="text-xs text-gray-600 mt-1"></p>
                            </div>
                            
                            <!-- Item Brought Input -->
                            <div id="itemInput_${item.itemId}" class="payment-input-group hidden">
                                <label class="block text-sm font-medium mb-1">Number of Items Brought</label>
                                <input type="number" class="w-full border rounded-lg px-3 py-2 itemsBrought" 
                                       data-item-id="${item.itemId}" data-period-type="${periodType}"
                                       data-unit-price="${item.unitPrice}" data-quantity="${item.remainingQuantity}"
                                       max="${item.remainingQuantity}" placeholder="Max: ${item.remainingQuantity} items"
                                       oninput="updateItemTotal('${item.itemId}', 'item', ${item.unitPrice}, ${item.remainingQuantity})">
                                <p class="text-xs text-gray-500 mt-1">Remaining: ${item.remainingQuantity} items (UGX ${item.remainingAmount.toLocaleString()})</p>
                                <p id="thatToSay_${item.itemId}" class="text-xs text-gray-600 mt-1"></p>
                            </div>
                            
                            <div class="mt-2 pt-2 border-t text-right">
                                <span class="text-sm font-semibold">Amount for this item: </span>
                                <span id="itemTotal_${item.itemId}" class="font-bold text-green-600">UGX 0</span>
                            </div>
                        </div>
                    </div>
                `).join('')}
            </div>
            <div class="mt-3 pt-2 border-t flex justify-between font-semibold">
                <span>Total ${title}:</span>
                <span id="${periodType}TotalSelected" class="${textColor} font-bold text-lg">UGX 0</span>
            </div>
        </div>
    `;
}

// ==================== HELPER FUNCTIONS FOR COLLECTION FORM ====================

function getAllItemsFromComponents(components) {
    const items = [];
    components.forEach(comp => {
        (comp.items || []).forEach(item => {
            items.push({
                componentId: comp.id,
                componentName: comp.name,
                periodType: comp.periodType,
                itemId: item.id,
                itemName: item.name,
                quantity: item.quantity,
                totalAmount: item.totalAmount,
                unitPrice: item.unitPrice,
                isTangible: item.isTangible !== false,
                remainingQuantity: item.quantity,
                remainingAmount: item.totalAmount
            });
        });
    });
    return items;
}

function togglePaymentInputs(itemId, type) {
    const cashInput = document.getElementById(`cashInput_${itemId}`);
    const itemInput = document.getElementById(`itemInput_${itemId}`);
    
    if (type === 'cash') {
        if (cashInput) cashInput.classList.remove('hidden');
        if (itemInput) itemInput.classList.add('hidden');
        // Clear the items brought input
        const itemsInput = itemInput?.querySelector('input');
        if (itemsInput) itemsInput.value = '';
    } else {
        if (cashInput) cashInput.classList.add('hidden');
        if (itemInput) itemInput.classList.remove('hidden');
        // Clear the cash amount input
        const cashAmountInput = cashInput?.querySelector('input');
        if (cashAmountInput) cashAmountInput.value = '';
    }
    
    // Determine period type from the itemId
    let periodType = 'one_time';
    if (itemId.includes('termly')) periodType = 'termly';
    if (itemId.includes('yearly')) periodType = 'yearly';
    
    updatePeriodTotal(periodType);
}

window.togglePaymentInputs = togglePaymentInputs;

function updateItemTotal(itemId, type, unitPrice, maxQuantity) {
    let amount = 0;
    let itemsCovered = 0;
    
    if (type === 'cash') {
        const cashInput = document.querySelector(`#cashInput_${itemId} input.cashAmount`);
        let cashAmount = parseFloat(cashInput?.value) || 0;
        const maxAmount = parseFloat(cashInput?.dataset?.max) || null;
        if (cashAmount < 0) cashAmount = 0;
        if (maxAmount !== null && Number.isFinite(maxAmount)) {
            cashAmount = Math.min(cashAmount, maxAmount);
        }
        if (cashInput) cashInput.value = cashAmount ? cashAmount : '';
        amount = cashAmount;
        itemsCovered = unitPrice > 0 ? (cashAmount / unitPrice) : 0;
    } else {
        const itemsInput = document.querySelector(`#itemInput_${itemId} input.itemsBrought`);
        let itemsCount = parseInt(itemsInput?.value) || 0;
        if (itemsCount < 0) itemsCount = 0;
        itemsCovered = Math.min(itemsCount, maxQuantity);
        if (itemsInput) itemsInput.value = itemsCovered ? itemsCovered : '';
        amount = itemsCovered * unitPrice;
    }
    
    const totalSpan = document.getElementById(`itemTotal_${itemId}`);
    if (totalSpan) totalSpan.innerHTML = `UGX ${amount.toLocaleString()}`;

    const tts = document.getElementById(`thatToSay_${itemId}`);
    if (tts) {
        if (type === 'cash') {
            const itemsEq = itemsCovered;
            tts.innerHTML = amount > 0
                ? `That’s to say: ~${itemsEq.toFixed(2)} items`
                : '';
        } else {
            tts.innerHTML = itemsCovered > 0
                ? `That’s to say: UGX ${amount.toLocaleString()} for ${itemsCovered} items`
                : '';
        }
    }
    
    updatePeriodTotal();
}

function updatePeriodTotal() {
    const periodTypes = ['one_time', 'termly', 'yearly'];
    
    periodTypes.forEach(periodType => {
        let total = 0;
        
        // Get all items for this period type
        const items = document.querySelectorAll(`#${periodType}ItemsList .cashAmount, #${periodType}ItemsList .itemsBrought`);
        
        items.forEach(input => {
            const itemId = input.dataset.itemId;
            const unitPrice = parseFloat(input.dataset.unitPrice) || 0;
            let amount = 0;
            
            // Check if cash or item input is visible
            const cashInputGroup = document.getElementById(`cashInput_${itemId}`);
            const itemInputGroup = document.getElementById(`itemInput_${itemId}`);
            
            if (cashInputGroup && !cashInputGroup.classList.contains('hidden')) {
                let cashAmount = parseFloat(input.value) || 0;
                const maxAmount = parseFloat(input.dataset.max) || null;
                if (cashAmount < 0) cashAmount = 0;
                if (maxAmount !== null && Number.isFinite(maxAmount)) cashAmount = Math.min(cashAmount, maxAmount);
                input.value = cashAmount ? cashAmount : '';
                amount = cashAmount;
            } else if (itemInputGroup && !itemInputGroup.classList.contains('hidden')) {
                let itemsCount = parseInt(input.value) || 0;
                const maxQty = parseInt(input.max) || parseInt(input.dataset.quantity) || 0;
                if (itemsCount < 0) itemsCount = 0;
                if (maxQty > 0) itemsCount = Math.min(itemsCount, maxQty);
                input.value = itemsCount ? itemsCount : '';
                amount = itemsCount * unitPrice;
            }
            
            total += amount;
        });
        
        const totalSpan = document.getElementById(`${periodType}TotalSelected`);
        if (totalSpan) totalSpan.innerHTML = `UGX ${total.toLocaleString()}`;
    });
    
    calculateCollectionTotal();
}

function setFullTuitionAmount() {
    const checkbox = document.getElementById('fullTuitionCheck');
    const tuitionInput = document.getElementById('tuitionAmount');
    if (checkbox?.checked && tuitionInput) {
        tuitionInput.value = tuitionInput.max;
        calculateCollectionTotal();
    } else if (tuitionInput) {
        tuitionInput.value = 0;
        calculateCollectionTotal();
    }
}

function resetCollectionForm() {
    const tuitionInput = document.getElementById('tuitionAmount');
    if (tuitionInput) tuitionInput.value = '0';
    
    const fullTuitionCheck = document.getElementById('fullTuitionCheck');
    if (fullTuitionCheck) fullTuitionCheck.checked = false;
    
    // Clear all payment inputs
    document.querySelectorAll('.cashAmount, .itemsBrought').forEach(input => {
        input.value = '';
    });
    
    // Reset item totals
    document.querySelectorAll('[id^="itemTotal_"]').forEach(span => {
        span.innerHTML = 'UGX 0';
    });
    
    // Reset period totals
    ['one_time', 'termly', 'yearly'].forEach(period => {
        const totalSpan = document.getElementById(`${period}TotalSelected`);
        if (totalSpan) totalSpan.innerHTML = 'UGX 0';
    });
    
    const paymentReference = document.getElementById('paymentReference');
    const paymentNotes = document.getElementById('paymentNotes');
    if (paymentReference) paymentReference.value = '';
    if (paymentNotes) paymentNotes.value = '';
    
    calculateCollectionTotal();
}

