// ==================== SET FULL TUITION AMOUNT ====================
function setFullTuitionAmount() {
    const checkbox = document.getElementById('fullTuitionCheck');
    const tuitionInput = document.getElementById('tuitionAmount');
    if (checkbox?.checked && tuitionInput) {
        tuitionInput.value = tuitionInput.max;
        updateCollectionTotal();
    } else if (tuitionInput) {
        tuitionInput.value = 0;
        updateCollectionTotal();
    }
}

// ==================== RESET COLLECTION FORM ====================
function resetCollectionForm() {
    const tuitionInput = document.getElementById('tuitionAmount');
    if (tuitionInput) tuitionInput.value = '0';
    
    const fullTuitionCheck = document.getElementById('fullTuitionCheck');
    if (fullTuitionCheck) fullTuitionCheck.checked = false;
    
    document.querySelectorAll('.activityCheckbox, .developmentCheckbox').forEach(cb => {
        if (!cb.disabled) cb.checked = false;
    });
    
    const paymentReference = document.getElementById('paymentReference');
    const paymentNotes = document.getElementById('paymentNotes');
    if (paymentReference) paymentReference.value = '';
    if (paymentNotes) paymentNotes.value = '';
    
    updateCollectionTotal();
}

// ==================== SUBMIT FEE COLLECTION ====================
async function submitFeeCollectionSeparate(student, feeStructure, currentYear, currentTerm) {
    const tuitionPaid = parseInt(document.getElementById('tuitionAmount')?.value) || 0;
    const method = document.getElementById('paymentMethodSelect')?.value || 'cash';
    const reference = document.getElementById('paymentReference')?.value || '';
    const notes = document.getElementById('paymentNotes')?.value || '';
    
    const selectedActivityComponents = [];
    document.querySelectorAll('.activityCheckbox:checked:not(:disabled)').forEach(cb => {
        selectedActivityComponents.push({ 
            id: cb.dataset.id, 
            name: cb.dataset.name, 
            amount: parseInt(cb.dataset.amount) 
        });
    });
    
    const selectedDevelopmentComponents = [];
    document.querySelectorAll('.developmentCheckbox:checked:not(:disabled)').forEach(cb => {
        selectedDevelopmentComponents.push({ 
            id: cb.dataset.id, 
            name: cb.dataset.name, 
            amount: parseInt(cb.dataset.amount) 
        });
    });
    
    const totalAmount = tuitionPaid + 
        selectedActivityComponents.reduce((s,c)=>s+c.amount,0) + 
        selectedDevelopmentComponents.reduce((s,c)=>s+c.amount,0);
    
    if (totalAmount <= 0) {
        alert('Please enter an amount to pay or select components to pay');
        return;
    }
    
    const submitBtn = document.querySelector('#collectionForm button[type="submit"]');
    const originalText = submitBtn.innerText;
    submitBtn.innerText = 'Processing...';
    submitBtn.disabled = true;
    
    try {
        const response = await fetch('/api/fee/payments/enhanced', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
                studentId: student.id,
                studentName: `${student.firstName} ${student.lastName}`,
                admissionNumber: student.admissionNumber,
                term: currentTerm,
                academicYear: currentYear.toString(),
                feeStructureId: feeStructure.id,
                feeStructureName: feeStructure.name,
                bursaryId: student.appliedBursary?.id || null,
                bursaryName: student.appliedBursary?.name || null,
                tuitionPaid: tuitionPaid,
                selectedActivityComponents: selectedActivityComponents,
                selectedDevelopmentComponents: selectedDevelopmentComponents,
                totalAmount: totalAmount,
                method: method,
                reference: reference,
                notes: notes,
                isFirstPaymentOfTerm: student.totalPaid === 0
            })
        });
        
        if (response.ok) {
            const result = await response.json();
            const newTotalPaid = student.totalPaid + totalAmount;
            const newBalance = student.totalExpected - newTotalPaid;
            
            if (newBalance < 0) {
                alert(`✅ Payment recorded!\nReceipt: ${result.receiptNumber}\nAmount: UGX ${totalAmount.toLocaleString()}\n\n⚠️ Credit created: UGX ${Math.abs(newBalance).toLocaleString()} will apply to next term.`);
            } else if (newBalance === 0) {
                alert(`✅ Payment recorded!\nReceipt: ${result.receiptNumber}\nAmount: UGX ${totalAmount.toLocaleString()}\n\n🎉 Student is now FULLY PAID for ${getTermName(currentTerm)}!`);
            } else {
                alert(`✅ Payment recorded!\nReceipt: ${result.receiptNumber}\nAmount: UGX ${totalAmount.toLocaleString()}\nRemaining balance: UGX ${newBalance.toLocaleString()}`);
            }
            showFeeManagement();
        } else {
            const error = await response.json();
            alert('❌ Error: ' + (error.error || 'Unknown error'));
        }
    } catch (error) {
        alert('Network error: ' + error.message);
    } finally {
        submitBtn.innerText = originalText;
        submitBtn.disabled = false;
    }
}

// Make functions global
window.updateCollectionTotal = updateCollectionTotal;
window.setFullTuitionAmount = setFullTuitionAmount;
window.resetCollectionForm = resetCollectionForm;
// ==================== HELPER FUNCTION FOR BALANCES TABLE ====================
function renderStudentBalancesTable(students) {
    if (!students || students.length === 0) {
        return '<tr><td colspan="11" class="text-center p-8 text-gray-500">No students found</td></tr>';
    }
    
    return students.map(student => {
        let status = 'Good Standing';
        let statusClass = 'bg-green-100 text-green-800';
        
        if (student.isOverpaid) {
            status = 'Credit Balance';
            statusClass = 'bg-blue-100 text-blue-800';
        } else if (student.tuitionBalance > student.expectedTuition) {
            status = 'Critical Overdue';
            statusClass = 'bg-red-100 text-red-800';
        } else if (student.tuitionBalance > 0 || student.activityBalance > 0 || student.developmentBalance > 0) {
            status = 'Payment Due';
            statusClass = 'bg-yellow-100 text-yellow-800';
        } else if (student.tuitionBalance <= 0 && student.activityBalance <= 0 && student.developmentBalance <= 0 && 
                   (student.tuitionPaid > 0 || student.activityPaid > 0 || student.developmentPaid > 0)) {
            status = 'Fully Paid';
            statusClass = 'bg-green-100 text-green-800';
        }
        
        const totalPaid = student.tuitionPaid + student.activityPaid + student.developmentPaid;
        const totalExpected = student.expectedTuition + student.expectedActivityTotal + student.expectedDevelopmentTotal;
        const totalBalance = totalExpected - totalPaid;
        
        return `
            <tr data-name="${student.firstName} ${student.lastName}" data-admission="${student.admissionNumber}" data-class="${student.currentClass || ''}" data-status="${student.isOverpaid ? 'credit' : totalBalance > 0 ? 'due' : 'paid'}">
                <td class="p-3 font-mono text-sm">${student.admissionNumber}</td>
                <td class="p-3 font-medium">${student.firstName} ${student.lastName}</td>
                <td class="p-3">${student.currentClass || 'N/A'}</td>
                <td class="p-3 text-right">
                    <span class="${student.tuitionBalance > 0 ? 'text-red-600' : student.tuitionBalance < 0 ? 'text-blue-600' : 'text-green-600'} font-semibold">UGX ${student.tuitionPaid.toLocaleString()}</span>
                    <div class="text-xs text-gray-400">/ ${student.expectedTuition.toLocaleString()}</div>
                </td>
                <td class="p-3 text-right">
                    <span class="${student.activityBalance > 0 ? 'text-orange-600' : student.activityBalance < 0 ? 'text-blue-600' : 'text-green-600'}">UGX ${student.activityPaid.toLocaleString()}</span>
                    <div class="text-xs text-gray-400">/ ${student.expectedActivityTotal.toLocaleString()}</div>
                 </td>
                <td class="p-3 text-right">
                    <span class="${student.developmentBalance > 0 ? 'text-orange-600' : student.developmentBalance < 0 ? 'text-blue-600' : 'text-green-600'}">UGX ${student.developmentPaid.toLocaleString()}</span>
                    <div class="text-xs text-gray-400">/ ${student.expectedDevelopmentTotal.toLocaleString()}</div>
                 </td>
                <td class="p-3 text-right font-semibold text-green-600">UGX ${totalPaid.toLocaleString()}</td>
                <td class="p-3 text-right">UGX ${totalExpected.toLocaleString()}</td>
                <td class="p-3 text-right font-bold ${totalBalance > 0 ? 'text-red-600' : totalBalance < 0 ? 'text-blue-600' : 'text-green-600'}">
                    ${totalBalance > 0 ? `UGX ${totalBalance.toLocaleString()}` : totalBalance < 0 ? `(Credit: UGX ${Math.abs(totalBalance).toLocaleString()})` : 'UGX 0'}
                </td>
                <td class="p-3 text-center"><span class="px-2 py-1 rounded-full text-xs ${statusClass}">${status}</span></td>
                <td class="p-3 text-center">
                    <button onclick="viewStudentFullFeeDetails('${student.id}')" class="text-blue-600 hover:text-blue-800" title="View Details">
                        <i class="fas fa-eye"></i>
                    </button>
                    <button onclick="loadStudentForCollection('${student.id}')" class="text-green-600 hover:text-green-800 ml-2" title="Make Payment">
                        <i class="fas fa-receipt"></i>
                    </button>
                </td>
            </tr>
        `;
    }).join('');
}

// ==================== LOAD COLLECTION FORM ====================





function renderBursariesGrid(bursaries) {
    if (!bursaries.length) return '<div class="col-span-3 text-center py-8 text-gray-500">No bursaries added</div>';
    return bursaries.map(b => `
        <div class="border rounded-lg p-3">
            <div class="font-bold">${b.name}</div>
            <p class="text-sm text-gray-600">${b.description || ''}</p>
            <span class="inline-block mt-2 px-2 py-1 bg-blue-100 rounded-full text-sm">${b.type === 'percentage' ? b.value + '% OFF' : 'UGX ' + b.value.toLocaleString() + ' OFF'}</span>
            <div class="mt-2"><button onclick="editBursaryItem('${b.id}')" class="text-blue-600 text-sm mr-2">Edit</button><button onclick="deleteBursaryItem('${b.id}')" class="text-red-600 text-sm">Delete</button></div>
        </div>
    `).join('');
}


