// ==================== COMPLETE RENDER FEE STRUCTURES LIST ====================
// Version: 6.0 - Proper Card Width and Layout

function renderFeeStructuresList(structures) {
    if (!structures || structures.length === 0) {
        return `
            <div class="w-full text-center py-12 bg-white rounded-xl shadow-sm">
                <div class="flex flex-col items-center justify-center">
                    <div class="w-20 h-20 bg-gray-100 rounded-full flex items-center justify-center mb-4">
                        <i class="fas fa-file-invoice-dollar text-gray-400 text-4xl"></i>
                    </div>
                    <h3 class="text-lg font-semibold text-gray-600">No Fee Structures Yet</h3>
                    <p class="text-gray-500 mt-1">Click "Add Fee Structure" to create your first fee structure</p>
                    <button onclick="showAddFeeStructureModal()" class="mt-4 bg-blue-600 text-white px-4 py-2 rounded-lg hover:bg-blue-700 transition">
                        <i class="fas fa-plus"></i> Add Fee Structure
                    </button>
                </div>
            </div>
        `;
    }
    
    // Group structures by level
    const nurseryStructures = structures.filter(s => s.level === 'Nursery');
    const lowerPrimaryStructures = structures.filter(s => s.level === 'LowerPrimary');
    const upperPrimaryStructures = structures.filter(s => s.level === 'UpperPrimary');
    
    return `
        <div class="flex flex-col lg:flex-row gap-6">
            ${renderLevelColumn(nurseryStructures, 'Nursery', '🎨', 'Nursery Level', 'Baby, Middle, Top Class', 'lg:w-1/3')}
            ${renderLevelColumn(lowerPrimaryStructures, 'LowerPrimary', '📚', 'Lower Primary', 'P.1 - P.3', 'lg:w-1/3')}
            ${renderLevelColumn(upperPrimaryStructures, 'UpperPrimary', '🎓', 'Upper Primary', 'P.4 - P.7', 'lg:w-1/3')}
        </div>
    `;
}

// ==================== RENDER LEVEL COLUMN ====================

function renderLevelColumn(structures, levelKey, icon, title, subtitle, widthClass) {
    if (!structures || structures.length === 0) {
        return `
            <div class="${widthClass} border rounded-xl overflow-hidden shadow-sm bg-white flex flex-col">
                <div class="bg-gradient-to-r from-gray-600 to-gray-700 text-white p-4 text-center">
                    <div class="flex items-center justify-between">
                        <div>
                            <h4 class="font-bold text-lg">${icon} ${title}</h4>
                            <p class="text-xs opacity-80 mt-0.5">${subtitle}</p>
                        </div>
                        <i class="fas ${levelKey === 'Nursery' ? 'fa-baby-carriage' : levelKey === 'LowerPrimary' ? 'fa-book-open' : 'fa-graduation-cap'} text-2xl opacity-50"></i>
                    </div>
                </div>
                <div class="p-6 text-center flex-1 flex flex-col items-center justify-center">
                    <div class="w-16 h-16 bg-gray-100 rounded-full flex items-center justify-center mx-auto mb-3">
                        <i class="fas fa-plus text-gray-400 text-2xl"></i>
                    </div>
                    <p class="text-gray-500 text-sm">No fee structures</p>
                    <button onclick="showAddFeeStructureModal()" class="mt-3 text-blue-600 text-sm hover:text-blue-800">
                        Add Fee Structure
                    </button>
                </div>
            </div>
        `;
    }
    
    return `
        <div class="${widthClass} style="width:100em;" border rounded-xl overflow-hidden shadow-sm bg-white flex flex-col">
            <div class="bg-gradient-to-r from-blue-600 to-purple-600 text-white p-4 text-center">
                <div class="flex items-center justify-between">
                    <div>
                        <h4 class="font-bold text-lg">${icon} ${title}</h4>
                        <p class="text-xs opacity-80 mt-0.5">${subtitle}</p>
                    </div>
                    <div class="text-right">
                        <p class="text-2xl font-bold">${structures.length}</p>
                        <p class="text-xs opacity-80">Structure(s)</p>
                    </div>
                </div>
            </div>
            <div class="p-4 space-y-4 max-h-[600px] overflow-y-auto">
                ${structures.map(structure => renderFeeStructureCardItem(structure)).join('')}
            </div>
        </div>
    `;
}

