// ==================== FIXED UPDATE MODAL TOTALS - WITH DIRECT EVENT BINDING ====================

function updateModalTotals() {
    console.log('=== UPDATING MODAL TOTALS ===');
    
    // Get tuition value
    const tuitionInput = document.getElementById('modalFsTuition');
    const tuition = tuitionInput ? parseInt(tuitionInput.value) || 0 : 0;
    console.log('Tuition:', tuition);
    
    // Calculate one-time activities total
    let oneTimeTotal = 0;
    const oneTimeAmounts = document.querySelectorAll('#oneTimeActivitiesList .itemTotalAmount');
    console.log('One-time items found:', oneTimeAmounts.length);
    oneTimeAmounts.forEach(input => {
        const val = parseInt(input.value) || 0;
        console.log('One-time amount:', val);
        oneTimeTotal += val;
    });
    
    // Also check for items inside groups (fallback)
    const oneTimeGroups = document.querySelectorAll('#oneTimeActivitiesList > div[id^="ot_"]');
    oneTimeGroups.forEach(group => {
        const itemsContainer = group.querySelector(`#${group.id}_items`);
        if (itemsContainer) {
            const amounts = itemsContainer.querySelectorAll('.itemTotalAmount');
            amounts.forEach(input => {
                const val = parseInt(input.value) || 0;
                oneTimeTotal += val;
            });
        }
    });
    
    // Calculate termly activities total
    let termlyTotal = 0;
    const termlyAmounts = document.querySelectorAll('#termlyActivitiesList .itemTotalAmount');
    console.log('Termly items found:', termlyAmounts.length);
    termlyAmounts.forEach(input => {
        termlyTotal += parseInt(input.value) || 0;
    });
    
    // Also check for items inside termly groups
    const termlyGroups = document.querySelectorAll('#termlyActivitiesList > div[id^="term_"]');
    termlyGroups.forEach(group => {
        const itemsContainer = group.querySelector(`#${group.id}_items`);
        if (itemsContainer) {
            const amounts = itemsContainer.querySelectorAll('.itemTotalAmount');
            amounts.forEach(input => {
                termlyTotal += parseInt(input.value) || 0;
            });
        }
    });
    
    // Calculate yearly activities total
    let yearlyTotal = 0;
    const yearlyAmounts = document.querySelectorAll('#yearlyActivitiesList .itemTotalAmount');
    console.log('Yearly items found:', yearlyAmounts.length);
    yearlyAmounts.forEach(input => {
        yearlyTotal += parseInt(input.value) || 0;
    });
    
    // Also check for items inside yearly groups
    const yearlyGroups = document.querySelectorAll('#yearlyActivitiesList > div[id^="year_"]');
    yearlyGroups.forEach(group => {
        const itemsContainer = group.querySelector(`#${group.id}_items`);
        if (itemsContainer) {
            const amounts = itemsContainer.querySelectorAll('.itemTotalAmount');
            amounts.forEach(input => {
                yearlyTotal += parseInt(input.value) || 0;
            });
        }
    });
    
    console.log('TOTALS - Tuition:', tuition, 'OneTime:', oneTimeTotal, 'Termly:', termlyTotal, 'Yearly:', yearlyTotal);
    
    // Update the display spans
    const oneTimeTotalSpan = document.getElementById('modalOneTimeTotal');
    if (oneTimeTotalSpan) oneTimeTotalSpan.innerHTML = `UGX ${oneTimeTotal.toLocaleString()}`;
    
    const termlyTotalSpan = document.getElementById('modalTermlyTotal');
    if (termlyTotalSpan) termlyTotalSpan.innerHTML = `UGX ${termlyTotal.toLocaleString()}`;
    
    const yearlyTotalSpan = document.getElementById('modalYearlyTotal');
    if (yearlyTotalSpan) yearlyTotalSpan.innerHTML = `UGX ${yearlyTotal.toLocaleString()}`;
    
    // Update summary cards
    const summaryTuition = document.getElementById('summaryTuition');
    if (summaryTuition) summaryTuition.innerHTML = `UGX ${tuition.toLocaleString()}`;
    
    const summaryOneTime = document.getElementById('summaryOneTime');
    if (summaryOneTime) summaryOneTime.innerHTML = `UGX ${oneTimeTotal.toLocaleString()}`;
    
    const summaryTermly = document.getElementById('summaryTermly');
    if (summaryTermly) summaryTermly.innerHTML = `UGX ${termlyTotal.toLocaleString()}`;
    
    const summaryYearly = document.getElementById('summaryYearly');
    if (summaryYearly) summaryYearly.innerHTML = `UGX ${yearlyTotal.toLocaleString()}`;
}

// ==================== FIXED ADD ITEM TO GROUP - WITH DIRECT EVENT BINDING ====================

function addItemToGroup(groupId, periodType) {
    console.log('Adding item to group:', groupId, periodType);
    const itemId = 'item_' + Date.now() + '_' + Math.random().toString(36).substr(2, 6);
    
    const html = `
        <div id="${itemId}" class="flex gap-2 items-center bg-gray-50 p-2 rounded-lg border mb-2">
            <input type="text" placeholder="Item name" 
                   class="flex-1 border rounded px-2 py-1 text-sm itemName">
            <input type="number" placeholder="Qty" 
                   class="w-16 border rounded px-2 py-1 text-sm itemQuantity" value="1" min="1">
            <input type="number" placeholder="Total Amount" 
                   class="w-28 border rounded px-2 py-1 text-sm itemTotalAmount" value="0" min="0">
            <button type="button" onclick="removeItemFromGroup('${itemId}', '${groupId}')" 
                    class="text-red-600 hover:text-red-800 px-1">
                <i class="fas fa-times"></i>
            </button>
        </div>
    `;
    
    const container = document.getElementById(`${groupId}_items`);
    if (!container) return;
    
    // Remove empty message if exists
    const emptyMsg = container.querySelector('.text-center.text-gray-400');
    if (emptyMsg && emptyMsg.parentNode === container) {
        emptyMsg.remove();
    }
    
    container.insertAdjacentHTML('beforeend', html);
    
    // Add event listener to the new amount input
    const newAmountInput = container.querySelector(`#${itemId} .itemTotalAmount`);
    if (newAmountInput) {
        newAmountInput.addEventListener('input', function() {
            console.log('Amount changed for', itemId, 'New value:', this.value);
            updateModalTotals();
        });
        newAmountInput.addEventListener('change', function() {
            updateModalTotals();
        });
    }
    
    // Also add event listener to quantity input in case you want to auto-calculate
    const newQuantityInput = container.querySelector(`#${itemId} .itemQuantity`);
    if (newQuantityInput) {
        newQuantityInput.addEventListener('input', function() {
            updateModalTotals();
        });
    }
    
    updateModalTotals();
}

// ==================== FIXED REMOVE ITEM FROM GROUP ====================

function removeItemFromGroup(itemId, groupId) {
    console.log('Removing item:', itemId);
    const element = document.getElementById(itemId);
    if (element) {
        element.remove();
    }
    
    // Check if container is empty and add empty message back
    const container = document.getElementById(`${groupId}_items`);
    if (container && container.children.length === 0) {
        container.innerHTML = '<div class="text-center text-gray-400 text-xs py-2">No items added. Click "Add Item" to add.</div>';
    }
    
    updateModalTotals();
}

