function initTuitionListener() {
    const tuitionInput = document.getElementById('modalFsTuition');
    if (tuitionInput) {
        tuitionInput.addEventListener('input', function() {
            updateModalTotals();
        });
        tuitionInput.addEventListener('change', function() {
            updateModalTotals();
        });
    }
}

// Call this after the modal is added
function initModalEventListeners() {
    initTuitionListener();
    // Also watch for any dynamically added itemTotalAmount inputs
    const observer = new MutationObserver(function(mutations) {
        mutations.forEach(function(mutation) {
            if (mutation.type === 'childList') {
                const newAmountInputs = document.querySelectorAll('.itemTotalAmount:not([data-listener])');
                newAmountInputs.forEach(input => {
                    input.setAttribute('data-listener', 'true');
                    input.addEventListener('input', function() {
                        updateModalTotals();
                    });
                    input.addEventListener('change', function() {
                        updateModalTotals();
                    });
                });
            }
        });
    });
    
    observer.observe(document.body, {
        childList: true,
        subtree: true
    });
}

