function showAddBursaryModalDialog() {
    const modalHtml = `
        <div class="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50">
            <div class="bg-white rounded-2xl p-6 max-w-md w-full mx-4">
                <h3 class="text-xl font-bold mb-4">🎖️ Add Bursary/Scholarship</h3>
                <form id="bursaryModalForm" class="space-y-4">
                    <div><label class="block text-sm font-medium mb-1">Bursary Name *</label><input type="text" id="modalBursaryName" required class="w-full border rounded-lg px-3 py-2"></div>
                    <div><label class="block text-sm font-medium mb-1">Description</label><textarea id="modalBursaryDesc" rows="2" class="w-full border rounded-lg px-3 py-2"></textarea></div>
                    <div><label class="block text-sm font-medium mb-1">Type *</label><select id="modalBursaryType" class="w-full border rounded-lg px-3 py-2"><option value="percentage">Percentage (%)</option><option value="fixed">Fixed Amount (UGX)</option></select></div>
                    <div><label class="block text-sm font-medium mb-1">Value *</label><input type="number" id="modalBursaryValue" required class="w-full border rounded-lg px-3 py-2"></div>
                    <div><label class="block text-sm font-medium mb-1">Category</label><select id="modalBursaryCategory" class="w-full border rounded-lg px-3 py-2"><option value="Academic">Academic</option><option value="Sports">Sports</option><option value="Financial Need">Financial Need</option><option value="Staff">Staff Child</option></select></div>
                    <div class="flex gap-3"><button type="submit" class="flex-1 bg-blue-600 text-white py-2 rounded-lg">Save Bursary</button><button type="button" onclick="closeModal()" class="flex-1 bg-gray-300 text-gray-700 py-2 rounded-lg">Cancel</button></div>
                </form>
            </div>
        </div>
    `;
    document.body.insertAdjacentHTML('beforeend', modalHtml);
    
    document.getElementById('bursaryModalForm').onsubmit = async (e) => {
        e.preventDefault();
        const data = {
            name: document.getElementById('modalBursaryName').value,
            description: document.getElementById('modalBursaryDesc').value,
            type: document.getElementById('modalBursaryType').value,
            value: parseInt(document.getElementById('modalBursaryValue').value),
            category: document.getElementById('modalBursaryCategory').value,
            isActive: true
        };
        const response = await fetch('/api/fee/bursaries', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(data)
        });
        if (response.ok) {
            alert('✅ Bursary added successfully!');
            closeModal();
            showFeeManagement();
        } else {
            alert('❌ Error adding bursary');
        }
    };
}

function editBursaryItem(id) {
    // Find bursary from global data
    const bursary = window.feeBursariesData?.find(b => b.id === id);
    if (!bursary) return;
    
    const modalHtml = `
        <div class="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50">
            <div class="bg-white rounded-2xl p-6 max-w-md w-full mx-4">
                <h3 class="text-xl font-bold mb-4">Edit Bursary</h3>
                <form id="editBursaryModalForm" class="space-y-4">
                    <div><label class="block text-sm font-medium mb-1">Bursary Name</label><input type="text" id="editBursaryName" value="${bursary.name}" class="w-full border rounded-lg px-3 py-2"></div>
                    <div><label class="block text-sm font-medium mb-1">Description</label><textarea id="editBursaryDesc" rows="2" class="w-full border rounded-lg px-3 py-2">${bursary.description || ''}</textarea></div>
                    <div><label class="block text-sm font-medium mb-1">Type</label><select id="editBursaryType" class="w-full border rounded-lg px-3 py-2"><option value="percentage" ${bursary.type === 'percentage' ? 'selected' : ''}>Percentage (%)</option><option value="fixed" ${bursary.type === 'fixed' ? 'selected' : ''}>Fixed Amount (UGX)</option></select></div>
                    <div><label class="block text-sm font-medium mb-1">Value</label><input type="number" id="editBursaryValue" value="${bursary.value}" class="w-full border rounded-lg px-3 py-2"></div>
                    <div><label class="block text-sm font-medium mb-1">Category</label><select id="editBursaryCategory" class="w-full border rounded-lg px-3 py-2"><option value="Academic" ${bursary.category === 'Academic' ? 'selected' : ''}>Academic</option><option value="Sports" ${bursary.category === 'Sports' ? 'selected' : ''}>Sports</option><option value="Financial Need" ${bursary.category === 'Financial Need' ? 'selected' : ''}>Financial Need</option><option value="Staff" ${bursary.category === 'Staff' ? 'selected' : ''}>Staff Child</option></select></div>
                    <div class="flex gap-3"><button type="submit" class="flex-1 bg-blue-600 text-white py-2 rounded-lg">Update</button><button type="button" onclick="closeModal()" class="flex-1 bg-gray-300 text-gray-700 py-2 rounded-lg">Cancel</button></div>
                </form>
            </div>
        </div>
    `;
    document.body.insertAdjacentHTML('beforeend', modalHtml);
    
    document.getElementById('editBursaryModalForm').onsubmit = async (e) => {
        e.preventDefault();
        const updatedData = {
            name: document.getElementById('editBursaryName').value,
            description: document.getElementById('editBursaryDesc').value,
            type: document.getElementById('editBursaryType').value,
            value: parseInt(document.getElementById('editBursaryValue').value),
            category: document.getElementById('editBursaryCategory').value
        };
        const updateResponse = await fetch(`/api/fee/bursaries/${id}`, {
            method: 'PUT',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(updatedData)
        });
        if (updateResponse.ok) {
            alert('✅ Bursary updated successfully!');
            closeModal();
            showFeeManagement();
        } else {
            alert('❌ Error updating bursary');
        }
    };
}

function deleteBursaryItem(id) {
    if (confirm('Are you sure you want to delete this bursary?')) {
        fetch(`/api/fee/bursaries/${id}`, { method: 'DELETE' }).then(async response => {
            if (response.ok) {
                alert('✅ Bursary deleted successfully!');
                showFeeManagement();
            } else {
                alert('❌ Error deleting bursary');
            }
        });
    }
}

