// ==================== LOAD EXISTING FEE STRUCTURE FOR EDIT ====================

function loadExistingFeeStructureForEdit() {
    console.log('loadExistingFeeStructureForEdit called');
    
    const select = document.getElementById('loadEditFeeStructureSelect');
    const selectedId = select.value;
    const statusMsg = document.getElementById('editLoadStatusMsg');
    
    if (!selectedId) {
        alert('Please select a fee structure to load');
        return;
    }
    
    const feeStructure = window.existingFeeStructures.find(f => f.id === selectedId);
    if (!feeStructure) {
        alert('Fee structure not found');
        return;
    }
    
    console.log('Loading fee structure for edit:', feeStructure.name);
    console.log('Activity components:', feeStructure.activityComponents);
    
    // Confirm loading
    if (!confirm(`⚠️ Are you sure you want to load "${feeStructure.name}"?\n\nThis will REPLACE all current activity groups.\n\nAny unsaved changes will be lost.`)) {
        return;
    }
    
    // Clear existing groups
    window.activityGroupsData = [];
    
    // Load activity components
    if (feeStructure.activityComponents && feeStructure.activityComponents.length > 0) {
        for (const component of feeStructure.activityComponents) {
            console.log('Processing component:', component.name, 'Period:', component.periodType);
            
            // Skip if no items
            if (!component.items || component.items.length === 0) {
                console.log('Component has no items, skipping');
                continue;
            }
            
            // Create a new group
            const newGroup = {
                id: `group_${Date.now()}_${Math.random().toString(36).substr(2, 6)}`,
                name: component.name || 'Unnamed Group',
                periodType: component.periodType || 'termly',
                statusGroupId: component.statusGroupId || null,
                statusGroupName: component.statusGroupName || null,
                items: [],
                totalAmount: 0,
                createdAt: new Date().toISOString()
            };
            
            // Copy items
            for (const item of component.items) {
                const paymentOption = item.paymentOption || 'either';
                let cashAmount = item.cashAmount || item.totalAmount || 0;
                let quantity = item.quantity || 1;
                
                // If payment option is item_only, cashAmount should be 0
                if (paymentOption === 'item_only') {
                    cashAmount = 0;
                }
                // If payment option is cash_only, quantity should be 1
                if (paymentOption === 'cash_only') {
                    quantity = 1;
                }
                
                const newItem = {
                    id: `item_${Date.now()}_${Math.random().toString(36).substr(2, 6)}`,
                    name: item.name || 'Unnamed Item',
                    quantity: quantity,
                    cashAmount: cashAmount,
                    totalAmount: cashAmount || (quantity * (item.unitPrice || 0)),
                    paymentOption: paymentOption,
                    isTangible: paymentOption !== 'cash_only'
                };
                
                newGroup.items.push(newItem);
            }
            
            // Calculate group total
            newGroup.totalAmount = newGroup.items.reduce((sum, i) => sum + (i.cashAmount || i.totalAmount || 0), 0);
            
            window.activityGroupsData.push(newGroup);
            console.log('Added group:', newGroup.name, 'with', newGroup.items.length, 'items, total:', newGroup.totalAmount);
        }
        
        statusMsg.innerHTML = `✅ Loaded ${feeStructure.activityComponents.length} groups from "${feeStructure.name}"`;
        statusMsg.className = 'text-green-600 font-semibold';
    } else {
        statusMsg.innerHTML = '⚠️ No activity groups found in the selected structure';
        statusMsg.className = 'text-yellow-600 font-semibold';
    }
    
    // Re-render the activity groups
    renderEditActivityGroupsList();
    updateEditSummaryTotals();
    updateEditActivityCountBadge();
    
    // Show success message
    setTimeout(() => {
        statusMsg.innerHTML = '';
    }, 5000);
}

// ==================== CLEAR ALL EDIT ACTIVITY GROUPS ====================

function clearAllEditActivityGroups() {
    if (!window.activityGroupsData || window.activityGroupsData.length === 0) {
        alert('No activity groups to clear');
        return;
    }
    
    if (!confirm('⚠️ Are you sure you want to remove ALL activity groups?\n\nThis cannot be undone.')) {
        return;
    }
    
    window.activityGroupsData = [];
    renderEditActivityGroupsList();
    updateEditSummaryTotals();
    updateEditActivityCountBadge();
    
    showToast('All activity groups cleared', 'info');
}

// ==================== UPDATE EDIT ACTIVITY COUNT BADGE ====================

function updateEditActivityCountBadge() {
    const badge = document.getElementById('editActivityCountBadge');
    if (!badge) return;
    
    const count = window.activityGroupsData ? window.activityGroupsData.length : 0;
    const totalItems = window.activityGroupsData ? window.activityGroupsData.reduce((sum, g) => sum + (g.items ? g.items.length : 0), 0) : 0;
    
    if (count > 0) {
        badge.innerHTML = `(${count} groups, ${totalItems} items)`;
        badge.className = 'text-sm font-normal text-gray-500 ml-2';
    } else {
        badge.innerHTML = '';
    }
}

