function calculateEditTotals() {
    let activityTotal = 0;
    document.querySelectorAll('#editActivityList .editActAmount').forEach(input => { activityTotal += parseInt(input.value) || 0; });
    let developmentTotal = 0;
    document.querySelectorAll('#editDevelopmentList .editDevAmount').forEach(input => { developmentTotal += parseInt(input.value) || 0; });
    document.getElementById('editActivityTotal').innerHTML = `UGX ${activityTotal.toLocaleString()}`;
    document.getElementById('editDevelopmentTotal').innerHTML = `UGX ${developmentTotal.toLocaleString()}`;
}

