// ==================== COMPLETE FEE COLLECTION FORM WITH THREE ACTIVITY TYPES ====================
// Version: 7.0 - One-Time, Termly, Yearly activities with Cash/Item payment options



// ==================== HELPER FUNCTION TO EXTRACT ITEMS FROM ACTIVITIES ====================

function getItemsFromActivities(activities) {
    const items = [];
    activities.forEach(activity => {
        (activity.items || []).forEach(item => {
            items.push({
                componentId: activity.id,
                componentName: activity.name,
                periodType: activity.periodType,
                itemId: item.id,
                itemName: item.name,
                quantity: item.quantity || 1,
                totalAmount: item.totalAmount || 0,
                unitPrice: item.unitPrice || (item.totalAmount / (item.quantity || 1)),
                isTangible: item.isTangible !== false,
                remainingQuantity: item.quantity || 1,
                remainingAmount: item.totalAmount || 0
            });
        });
    });
    return items;
}

// ==================== RENDER ACTIVITY ITEMS SECTION ====================

function renderActivityItemsSection(items, periodType, title, color, note) {
    if (!items || items.length === 0) return '';
    
    const bgColor = color === 'purple' ? 'bg-purple-50' : color === 'green' ? 'bg-green-50' : 'bg-orange-50';
    const borderColor = color === 'purple' ? 'border-purple-300' : color === 'green' ? 'border-green-300' : 'border-orange-300';
    const textColor = color === 'purple' ? 'text-purple-600' : color === 'green' ? 'text-green-600' : 'text-orange-600';
    
    return `
        <div class="border-2 ${borderColor} rounded-lg p-4 ${bgColor}">
            <div class="flex justify-between items-center mb-3">
                <h3 class="font-bold text-lg flex items-center">
                    <span class="bg-${color}-600 text-white rounded-full w-7 h-7 flex items-center justify-center text-sm mr-2">${periodType === 'one_time' ? '⭐' : periodType === 'termly' ? '📅' : '📆'}</span>
                    ${title}
                </h3>
                <span class="text-sm text-gray-500 italic">${note}</span>
            </div>
            <div id="${periodType}ItemsContainer" class="space-y-4 max-h-96 overflow-y-auto">
                ${items.map(item => renderItemPaymentRow(item, periodType, color)).join('')}
            </div>
            <div class="mt-4 pt-3 border-t ${borderColor} flex justify-between items-center font-bold">
                <span>Total ${title}:</span>
                <span id="${periodType}TotalAmount" class="${textColor} text-xl">UGX 0</span>
            </div>
        </div>
    `;
}

// ==================== RENDER INDIVIDUAL ITEM PAYMENT ROW ====================

function renderItemPaymentRow(item, periodType, color) {
    const uniqueId = `${periodType}_${item.itemId}`;
    const unitPrice = item.unitPrice;
    const quantity = item.quantity;
    const totalAmount = item.totalAmount;
    
    return `
        <div id="itemRow_${uniqueId}" class="bg-white rounded-lg p-4 border shadow-sm">
            <div class="flex justify-between items-start mb-3">
                <div>
                    <h4 class="font-semibold text-md">${item.itemName}</h4>
                    <p class="text-xs text-gray-500">${item.componentName}</p>
                </div>
                <div class="text-right">
                    <p class="text-sm font-semibold">UGX ${unitPrice.toLocaleString()} / each</p>
                    <p class="text-xs text-gray-500">Total: UGX ${totalAmount.toLocaleString()} (${quantity} items)</p>
                </div>
            </div>
            
            <!-- Payment Type Selection -->
            <div class="mb-3">
                <label class="block text-sm font-medium mb-2">Payment Type:</label>
                <div class="flex gap-4">
                    <label class="flex items-center cursor-pointer">
                        <input type="radio" name="paymentType_${uniqueId}" value="cash" 
                               class="mr-2 paymentTypeRadio" data-item-id="${uniqueId}" data-period="${periodType}"
                               onchange="togglePaymentInputs('${uniqueId}', 'cash')" checked>
                        <span class="text-sm">💵 Pay Cash</span>
                    </label>
                    <label class="flex items-center cursor-pointer">
                        <input type="radio" name="paymentType_${uniqueId}" value="item" 
                               class="mr-2 paymentTypeRadio" data-item-id="${uniqueId}" data-period="${periodType}"
                               onchange="togglePaymentInputs('${uniqueId}', 'item')">
                        <span class="text-sm">📦 Bring Item</span>
                    </label>
                </div>
            </div>
            
            <!-- Cash Payment Input -->
            <div id="cashInput_${uniqueId}" class="payment-input-group mb-3">
                <label class="block text-sm font-medium mb-1">Amount to Pay (UGX)</label>
                <input type="number" class="w-full border rounded-lg px-3 py-2 cashAmountInput" 
                       data-item-id="${uniqueId}" data-period="${periodType}"
                       data-unit-price="${unitPrice}" data-quantity="${quantity}"
                       data-max-amount="${totalAmount}" data-remaining-quantity="${quantity}"
                       placeholder="Max: UGX ${totalAmount.toLocaleString()}"
                       oninput="updateItemPayment('${uniqueId}', 'cash', ${unitPrice}, ${quantity})">
                <p class="text-xs text-gray-500 mt-1">Remaining: UGX ${totalAmount.toLocaleString()} (${quantity} items)</p>
                <p id="thatToSay_${uniqueId}" class="text-xs text-blue-600 mt-1 font-medium"></p>
            </div>
            
            <!-- Item Brought Input -->
            <div id="itemInput_${uniqueId}" class="payment-input-group hidden mb-3">
                <label class="block text-sm font-medium mb-1">Number of Items Brought</label>
                <input type="number" class="w-full border rounded-lg px-3 py-2 itemsBroughtInput" 
                       data-item-id="${uniqueId}" data-period="${periodType}"
                       data-unit-price="${unitPrice}" data-quantity="${quantity}"
                       max="${quantity}" placeholder="Max: ${quantity} items"
                       oninput="updateItemPayment('${uniqueId}', 'item', ${unitPrice}, ${quantity})">
                <p class="text-xs text-gray-500 mt-1">Remaining: ${quantity} items (UGX ${totalAmount.toLocaleString()})</p>
                <p id="thatToSay_${uniqueId}_item" class="text-xs text-blue-600 mt-1 font-medium"></p>
            </div>
            
            <!-- Item Summary -->
            <div class="mt-3 pt-2 border-t flex justify-between items-center">
                <span class="text-sm font-semibold">Amount for this item:</span>
                <span id="itemTotal_${uniqueId}" class="font-bold text-green-600 text-lg">UGX 0</span>
            </div>
            <div class="flex justify-between items-center text-xs text-gray-500 mt-1">
                <span>Status:</span>
                <span id="itemStatus_${uniqueId}" class="font-medium text-yellow-600">Not Paid</span>
            </div>
        </div>
    `;
}

// ==================== TOGGLE PAYMENT INPUTS ====================

function togglePaymentInputs(itemId, type) {
    const cashInput = document.getElementById(`cashInput_${itemId}`);
    const itemInput = document.getElementById(`itemInput_${itemId}`);
    
    if (type === 'cash') {
        if (cashInput) cashInput.classList.remove('hidden');
        if (itemInput) itemInput.classList.add('hidden');
        // Clear items brought input
        const itemsInput = itemInput?.querySelector('.itemsBroughtInput');
        if (itemsInput) itemsInput.value = '';
    } else {
        if (cashInput) cashInput.classList.add('hidden');
        if (itemInput) itemInput.classList.remove('hidden');
        // Clear cash input
        const cashAmountInput = cashInput?.querySelector('.cashAmountInput');
        if (cashAmountInput) cashAmountInput.value = '';
    }
    
    // Recalculate this item's total
    const unitPrice = parseFloat(document.querySelector(`#cashInput_${itemId} .cashAmountInput`)?.dataset.unitPrice || 0);
    const quantity = parseInt(document.querySelector(`#cashInput_${itemId} .cashAmountInput`)?.dataset.quantity || 0);
    updateItemPayment(itemId, type, unitPrice, quantity);
}

// ==================== UPDATE ITEM PAYMENT (WITH "THAT'S TO SAY") ====================

function updateItemPayment(itemId, type, unitPrice, maxQuantity) {
    let amount = 0;
    let itemsCovered = 0;
    let paymentType = '';
    
    if (type === 'cash') {
        const cashInput = document.querySelector(`#cashInput_${itemId} .cashAmountInput`);
        let cashAmount = parseFloat(cashInput?.value) || 0;
        const maxAmount = parseFloat(cashInput?.dataset?.maxAmount) || 0;
        
        if (cashAmount < 0) cashAmount = 0;
        if (maxAmount > 0) cashAmount = Math.min(cashAmount, maxAmount);
        if (cashInput) cashInput.value = cashAmount || '';
        
        amount = cashAmount;
        itemsCovered = unitPrice > 0 ? (cashAmount / unitPrice) : 0;
        paymentType = 'cash';
        
        // Update "That's to say" message
        const ttsSpan = document.getElementById(`thatToSay_${itemId}`);
        if (ttsSpan) {
            ttsSpan.innerHTML = amount > 0 ? `📌 That's to say: ~${itemsCovered.toFixed(2)} items covered` : '';
        }
    } else {
        const itemsInput = document.querySelector(`#itemInput_${itemId} .itemsBroughtInput`);
        let itemsCount = parseInt(itemsInput?.value) || 0;
        
        if (itemsCount < 0) itemsCount = 0;
        itemsCovered = Math.min(itemsCount, maxQuantity);
        if (itemsInput) itemsInput.value = itemsCovered || '';
        
        amount = itemsCovered * unitPrice;
        paymentType = 'item';
        
        // Update "That's to say" message
        const ttsSpan = document.getElementById(`thatToSay_${itemId}_item`);
        if (ttsSpan) {
            ttsSpan.innerHTML = itemsCovered > 0 ? `📌 That's to say: UGX ${amount.toLocaleString()} for ${itemsCovered} items` : '';
        }
    }
    
    // Update item total display
    const totalSpan = document.getElementById(`itemTotal_${itemId}`);
    if (totalSpan) totalSpan.innerHTML = `UGX ${amount.toLocaleString()}`;
    
    // Update status
    const statusSpan = document.getElementById(`itemStatus_${itemId}`);
    const originalQuantity = maxQuantity;
    const remainingQuantity = originalQuantity - itemsCovered;
    
    if (statusSpan) {
        if (remainingQuantity <= 0) {
            statusSpan.innerHTML = '✓ Fully Paid';
            statusSpan.className = 'font-medium text-green-600';
        } else if (amount > 0 || itemsCovered > 0) {
            statusSpan.innerHTML = `⚠️ Partial (${itemsCovered}/${originalQuantity} items)`;
            statusSpan.className = 'font-medium text-yellow-600';
        } else {
            statusSpan.innerHTML = '❌ Not Paid';
            statusSpan.className = 'font-medium text-red-600';
        }
    }
    
    // Update the period total
    const periodType = document.querySelector(`#cashInput_${itemId} .cashAmountInput`)?.dataset.period || 
                       document.querySelector(`#itemInput_${itemId} .itemsBroughtInput`)?.dataset.period || 'one_time';
    updatePeriodTotal(periodType);
    
    // Update overall totals
    calculateAllTotals();
}

// ==================== UPDATE PERIOD TOTAL ====================

function updatePeriodTotal(periodType) {
    let total = 0;
    
    // Get all cash inputs for this period
    const cashInputs = document.querySelectorAll(`#${periodType}ItemsContainer .cashAmountInput`);
    cashInputs.forEach(input => {
        total += parseFloat(input.value) || 0;
    });
    
    // Get all item inputs for this period
    const itemInputs = document.querySelectorAll(`#${periodType}ItemsContainer .itemsBroughtInput`);
    itemInputs.forEach(input => {
        const unitPrice = parseFloat(input.dataset.unitPrice) || 0;
        const itemsCount = parseInt(input.value) || 0;
        total += itemsCount * unitPrice;
    });
    
    const totalSpan = document.getElementById(`${periodType}TotalAmount`);
    if (totalSpan) totalSpan.innerHTML = `UGX ${total.toLocaleString()}`;
}

// ==================== CALCULATE ALL TOTALS ====================

function calculateAllTotals() {
    // Get tuition amount
    const tuition = parseInt(document.getElementById('tuitionAmount')?.value) || 0;
    
    // Get period totals
    let oneTimeTotal = 0;
    let termlyTotal = 0;
    let yearlyTotal = 0;
    
    const oneTimeSpan = document.getElementById('one_timeTotalAmount');
    if (oneTimeSpan) {
        oneTimeTotal = parseInt(oneTimeSpan.innerText.replace(/[^0-9]/g, '')) || 0;
    }
    
    const termlySpan = document.getElementById('termlyTotalAmount');
    if (termlySpan) {
        termlyTotal = parseInt(termlySpan.innerText.replace(/[^0-9]/g, '')) || 0;
    }
    
    const yearlySpan = document.getElementById('yearlyTotalAmount');
    if (yearlySpan) {
        yearlyTotal = parseInt(yearlySpan.innerText.replace(/[^0-9]/g, '')) || 0;
    }
    
    const grandTotal = tuition + oneTimeTotal + termlyTotal + yearlyTotal;
    
    // Update summary displays
    const summaryTuition = document.getElementById('summaryTuition');
    const summaryOneTime = document.getElementById('summaryOneTime');
    const summaryTermly = document.getElementById('summaryTermly');
    const summaryYearly = document.getElementById('summaryYearly');
    const summaryTotal = document.getElementById('summaryTotal');
    const outstandingSpan = document.getElementById('outstandingAfter');
    
    if (summaryTuition) summaryTuition.innerHTML = `UGX ${tuition.toLocaleString()}`;
    if (summaryOneTime) summaryOneTime.innerHTML = `UGX ${oneTimeTotal.toLocaleString()}`;
    if (summaryTermly) summaryTermly.innerHTML = `UGX ${termlyTotal.toLocaleString()}`;
    if (summaryYearly) summaryYearly.innerHTML = `UGX ${yearlyTotal.toLocaleString()}`;
    if (summaryTotal) summaryTotal.innerHTML = `UGX ${grandTotal.toLocaleString()}`;
    
    // Calculate outstanding after payment
    const expected = window.currentCollectingStudent?.totalExpected || 0;
    const currentPaid = window.currentCollectingStudent?.totalPaid || 0;
    const totalAfterPayment = currentPaid + grandTotal;
    const balanceAfter = expected - totalAfterPayment;
    
    if (outstandingSpan) {
        if (balanceAfter > 0) {
            outstandingSpan.innerHTML = `UGX ${balanceAfter.toLocaleString()}`;
            outstandingSpan.className = 'font-bold text-xl text-red-600';
        } else if (balanceAfter < 0) {
            outstandingSpan.innerHTML = `Credit: UGX ${Math.abs(balanceAfter).toLocaleString()}`;
            outstandingSpan.className = 'font-bold text-xl text-blue-600';
        } else {
            outstandingSpan.innerHTML = 'Fully Paid';
            outstandingSpan.className = 'font-bold text-xl text-green-600';
        }
    }
}

// ==================== SET FULL TUITION AMOUNT ====================

function setFullTuitionAmount() {
    const checkbox = document.getElementById('fullTuitionCheck');
    const tuitionInput = document.getElementById('tuitionAmount');
    if (checkbox?.checked && tuitionInput) {
        tuitionInput.value = tuitionInput.max;
        calculateAllTotals();
    } else if (tuitionInput) {
        tuitionInput.value = 0;
        calculateAllTotals();
    }
}

// ==================== RESET ALL ACTIVITY PAYMENTS ====================

function resetAllActivityPayments() {
    // Reset tuition
    const tuitionInput = document.getElementById('tuitionAmount');
    if (tuitionInput) tuitionInput.value = '0';
    
    const fullTuitionCheck = document.getElementById('fullTuitionCheck');
    if (fullTuitionCheck) fullTuitionCheck.checked = false;
    
    // Reset all cash and item inputs
    document.querySelectorAll('.cashAmountInput, .itemsBroughtInput').forEach(input => {
        input.value = '';
    });
    
    // Reset payment type radios to cash
    document.querySelectorAll('.paymentTypeRadio[value="cash"]').forEach(radio => {
        radio.checked = true;
    });
    
    // Show cash inputs, hide item inputs
    document.querySelectorAll('.payment-input-group').forEach(group => {
        if (group.id.startsWith('cashInput')) {
            group.classList.remove('hidden');
        } else if (group.id.startsWith('itemInput')) {
            group.classList.add('hidden');
        }
    });
    
    // Reset all item totals and statuses
    document.querySelectorAll('[id^="itemTotal_"]').forEach(span => {
        span.innerHTML = 'UGX 0';
    });
    
    document.querySelectorAll('[id^="itemStatus_"]').forEach(span => {
        span.innerHTML = 'Not Paid';
        span.className = 'font-medium text-red-600';
    });
    
    // Reset "That's to say" messages
    document.querySelectorAll('[id^="thatToSay_"]').forEach(span => {
        span.innerHTML = '';
    });
    
    // Reset period totals
    ['one_time', 'termly', 'yearly'].forEach(period => {
        const totalSpan = document.getElementById(`${period}TotalAmount`);
        if (totalSpan) totalSpan.innerHTML = 'UGX 0';
    });
    
    // Reset payment details
    const paymentReference = document.getElementById('paymentReference');
    const paymentNotes = document.getElementById('paymentNotes');
    if (paymentReference) paymentReference.value = '';
    if (paymentNotes) paymentNotes.value = '';
    
    // Recalculate totals
    calculateAllTotals();
}

