// ==================== SUBMIT ACTIVITY BASED PAYMENT ====================

async function submitActivityBasedPayment(student, feeStructure, currentYear, currentTerm) {
    const tuitionPaid = parseInt(document.getElementById('tuitionAmount')?.value) || 0;
    const method = document.getElementById('paymentMethodSelect')?.value || 'cash';
    const reference = document.getElementById('paymentReference')?.value || '';
    const notes = document.getElementById('paymentNotes')?.value || '';
    
    // Collect all activity item payments
    const activityItemPayments = [];
    const periodTypes = ['one_time', 'termly', 'yearly'];
    
    for (const periodType of periodTypes) {
        const container = document.getElementById(`${periodType}ItemsContainer`);
        if (!container) continue;
        
        const itemRows = container.querySelectorAll('.bg-white.rounded-lg');
        for (const row of itemRows) {
            // Get the unique ID from the row
            const cashInput = row.querySelector('.cashAmountInput');
            const itemsInput = row.querySelector('.itemsBroughtInput');
            
            if (!cashInput && !itemsInput) continue;
            
            const itemUniqueId = cashInput?.dataset.itemId || itemsInput?.dataset.itemId;
            if (!itemUniqueId) continue;
            
            // Determine payment type
            const cashRadio = row.querySelector('input[value="cash"]');
            const isCash = cashRadio && cashRadio.checked;
            
            let amountPaid = 0;
            let itemsBrought = 0;
            let unitPrice = 0;
            let quantity = 0;
            let itemName = '';
            let componentName = '';
            
            if (isCash) {
                const cashAmountInput = row.querySelector('.cashAmountInput');
                amountPaid = parseFloat(cashAmountInput?.value) || 0;
                if (amountPaid <= 0) continue;
                unitPrice = parseFloat(cashAmountInput?.dataset.unitPrice) || 0;
                quantity = parseInt(cashAmountInput?.dataset.quantity) || 0;
                itemName = row.querySelector('h4')?.innerText || '';
                componentName = row.querySelector('.text-xs.text-gray-500')?.innerText || '';
            } else {
                const itemsBroughtInput = row.querySelector('.itemsBroughtInput');
                itemsBrought = parseInt(itemsBroughtInput?.value) || 0;
                if (itemsBrought <= 0) continue;
                unitPrice = parseFloat(itemsBroughtInput?.dataset.unitPrice) || 0;
                quantity = parseInt(itemsBroughtInput?.dataset.quantity) || 0;
                itemName = row.querySelector('h4')?.innerText || '';
                componentName = row.querySelector('.text-xs.text-gray-500')?.innerText || '';
            }
            
            activityItemPayments.push({
                periodType: periodType,
                itemName: itemName,
                componentName: componentName,
                unitPrice: unitPrice,
                quantity: quantity,
                paymentType: isCash ? 'paid_cash' : 'brought_item',
                amountPaid: isCash ? amountPaid : null,
                itemsBrought: !isCash ? itemsBrought : null,
                cashEquivalent: !isCash ? (itemsBrought * unitPrice) : null
            });
        }
    }
    
    const activityTotal = activityItemPayments.reduce((sum, p) => 
        sum + (p.paymentType === 'paid_cash' ? (p.amountPaid || 0) : (p.cashEquivalent || 0)), 0);
    
    const totalAmount = tuitionPaid + activityTotal;
    
    if (totalAmount <= 0) {
        alert('Please enter an amount to pay or select items to pay');
        return;
    }
    
    const submitBtn = document.querySelector('#collectionForm button[type="submit"]');
    const originalText = submitBtn.innerText;
    submitBtn.innerText = 'Processing...';
    submitBtn.disabled = true;
    
    try {
        const response = await fetch('/api/fee/payments/enhanced', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
                studentId: student.id,
                studentName: `${student.firstName} ${student.lastName}`,
                admissionNumber: student.admissionNumber,
                term: currentTerm,
                academicYear: currentYear.toString(),
                feeStructureId: feeStructure?.id || null,
                feeStructureName: feeStructure?.name || 'General Fee',
                bursaryId: student.appliedBursary?.id || null,
                bursaryName: student.appliedBursary?.name || null,
                tuitionPaid: tuitionPaid,
                activityItemPayments: activityItemPayments,
                totalAmount: totalAmount,
                method: method,
                reference: reference,
                notes: notes,
                isFirstPaymentOfTerm: student.totalPaid === 0
            })
        });
        
        if (response.ok) {
            const result = await response.json();
            alert(`✅ Payment recorded successfully!\nReceipt: ${result.receiptNumber}\nAmount: UGX ${totalAmount.toLocaleString()}`);
            showFeeManagement();
        } else {
            const error = await response.json();
            alert('❌ Error: ' + (error.error || 'Unknown error'));
        }
    } catch (error) {
        console.error('Payment error:', error);
        alert('Network error: ' + error.message);
    } finally {
        submitBtn.innerText = originalText;
        submitBtn.disabled = false;
    }
}

