// ==================== SUBMIT PAYMENT WITH OVERPAYMENT CHECK ====================

async function submitFeeCollectionWithOverpayment(student, feeStructure, currentYear, currentTerm) {
    // Prevent submission if student has overpaid
    if (student.isOverpaid) {
        alert('This student has a credit balance. No additional payment is required for this term.');
        return;
    }
    
    const tuitionPaid = parseInt(document.getElementById('tuitionAmount')?.value) || 0;
    const method = document.getElementById('paymentMethodSelect')?.value || 'cash';
    const reference = document.getElementById('paymentReference')?.value || '';
    const notes = document.getElementById('paymentNotes')?.value || '';
    
    const selectedActivityComponents = [];
    document.querySelectorAll('.activityCheckbox:checked').forEach(cb => {
        selectedActivityComponents.push({ id: cb.dataset.id, name: cb.dataset.name, amount: parseInt(cb.dataset.amount) });
    });
    
    const selectedDevelopmentComponents = [];
    document.querySelectorAll('.developmentCheckbox:checked').forEach(cb => {
        selectedDevelopmentComponents.push({ id: cb.dataset.id, name: cb.dataset.name, amount: parseInt(cb.dataset.amount) });
    });
    
    const totalAmount = tuitionPaid + selectedActivityComponents.reduce((s,c)=>s+c.amount,0) + selectedDevelopmentComponents.reduce((s,c)=>s+c.amount,0);
    
    if (totalAmount <= 0) {
        alert('Please enter an amount to pay');
        return;
    }
    
    const submitBtn = document.querySelector('#collectionForm button[type="submit"]');
    const originalText = submitBtn.innerText;
    submitBtn.innerText = 'Processing...';
    submitBtn.disabled = true;
    
    try {
        const response = await fetch('/api/fee/payments/enhanced', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
                studentId: student.id,
                studentName: `${student.firstName} ${student.lastName}`,
                admissionNumber: student.admissionNumber,
                term: currentTerm,
                academicYear: currentYear.toString(),
                feeStructureId: feeStructure.id,
                feeStructureName: feeStructure.name,
                tuitionPaid: tuitionPaid,
                selectedActivityComponents: selectedActivityComponents,
                selectedDevelopmentComponents: selectedDevelopmentComponents,
                selectedTangibleRequirements: window.selectedTangibleItems || [],
                totalAmount: totalAmount,
                method: method,
                reference: reference,
                notes: notes,
                isFirstPaymentOfTerm: window.isFirstPaymentPeriod || false
            })
        });
        
        if (response.ok) {
            const result = await response.json();
            const newTotalPaid = student.currentTermPaid + totalAmount;
            const newBalance = student.expectedPerTerm - newTotalPaid;
            
            if (newBalance < 0) {
                alert(`✅ Payment recorded successfully!\nReceipt: ${result.receiptNumber}\nAmount: UGX ${totalAmount.toLocaleString()}\n\n⚠️ Note: This payment creates a credit of UGX ${Math.abs(newBalance).toLocaleString()} which will be applied to next term.`);
            } else if (newBalance === 0) {
                alert(`✅ Payment recorded successfully!\nReceipt: ${result.receiptNumber}\nAmount: UGX ${totalAmount.toLocaleString()}\n\nStudent is now fully paid for this term.`);
            } else {
                alert(`✅ Payment recorded successfully!\nReceipt: ${result.receiptNumber}\nAmount: UGX ${totalAmount.toLocaleString()}\nRemaining balance: UGX ${newBalance.toLocaleString()}`);
            }
            showFeeManagement();
        } else {
            const error = await response.json();
            alert('❌ Error: ' + (error.error || 'Unknown error'));
        }
    } catch (error) {
        alert('Network error: ' + error.message);
    } finally {
        submitBtn.innerText = originalText;
        submitBtn.disabled = false;
    }
}

