function removeModalComponent(elementId) {
    const element = document.getElementById(elementId);
    if (element) element.remove();
    updateModalTotals();
}

function updateModalTotals() {
    let activityTotal = 0;
    document.querySelectorAll('#modalActivityList .actAmount').forEach(input => { activityTotal += parseInt(input.value) || 0; });
    let developmentTotal = 0;
    document.querySelectorAll('#modalDevelopmentList .devAmount').forEach(input => { developmentTotal += parseInt(input.value) || 0; });
    const tuition = parseInt(document.getElementById('modalFsTuition').value) || 0;
    const total = tuition + activityTotal + developmentTotal;
    document.getElementById('modalActivityTotal').innerHTML = `UGX ${activityTotal.toLocaleString()}`;
    document.getElementById('modalDevelopmentTotal').innerHTML = `UGX ${developmentTotal.toLocaleString()}`;
    document.getElementById('modalSummaryTuition').innerHTML = `UGX ${tuition.toLocaleString()}`;
    document.getElementById('modalSummaryActivity').innerHTML = `UGX ${activityTotal.toLocaleString()}`;
    document.getElementById('modalSummaryDevelopment').innerHTML = `UGX ${developmentTotal.toLocaleString()}`;
    document.getElementById('modalSummaryTotal').innerHTML = `UGX ${total.toLocaleString()}`;
}

async function saveFeeStructureFromModal() {
    const name = document.getElementById('modalFsName').value;
    const level = document.getElementById('modalFsLevel').value;
    const tuition = parseInt(document.getElementById('modalFsTuition').value) || 0;
    if (!name) { alert('Please enter a structure name'); return; }
    
    const activityComponents = [];
    document.querySelectorAll('#modalActivityList .actName').forEach((input, idx) => {
        const name = input.value;
        const amount = parseInt(document.querySelectorAll('#modalActivityList .actAmount')[idx]?.value) || 0;
        if (name && amount > 0) activityComponents.push({ id: `act_${Date.now()}_${idx}`, name, amount });
    });
    
    const developmentComponents = [];
    document.querySelectorAll('#modalDevelopmentList .devName').forEach((input, idx) => {
        const name = input.value;
        const amount = parseInt(document.querySelectorAll('#modalDevelopmentList .devAmount')[idx]?.value) || 0;
        if (name && amount > 0) developmentComponents.push({ id: `dev_${Date.now()}_${idx}`, name, amount });
    });
    
    const tangibleRequirements = [];
    document.querySelectorAll('#modalTangibleList .tangibleName').forEach((input, idx) => {
        const name = input.value;
        if (name) tangibleRequirements.push({ id: `req_${Date.now()}_${idx}`, name });
    });
    
    const response = await fetch('/api/fee/structures/enhanced', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ name, level, tuition, activityComponents, developmentComponents, tangibleRequirements, isActive: true })
    });
    
    if (response.ok) {
        alert('✅ Fee structure saved!');
        closeModal();
        showFeeManagement();
    } else {
        alert('❌ Error saving fee structure');
    }
}

