function exportBalancesReport() {
    const students = window.enhancedStudentsData || [];
    const data = students.map(s => ({
        'Admission': s.admissionNumber, 'Student': `${s.firstName} ${s.lastName}`, 'Class': s.currentClass,
        'Expected': s.expectedPerTerm, 'Paid': s.currentTermPaid, 'Balance': s.currentTermBalance, 'Status': s.status
    }));
    const csv = ['Admission,Student,Class,Expected,Paid,Balance,Status', ...data.map(d => `${d.Admission},${d.Student},${d.Class},${d.Expected},${d.Paid},${d.Balance},${d.Status}`)].join('\n');
    const blob = new Blob([csv], { type: 'text/csv' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
        a.href = url;
    a.download = `fee_balances_${new Date().toISOString().split('T')[0]}.csv`;
    a.click();
    URL.revokeObjectURL(url);
    alert('✅ Balances exported successfully');
}

