function renderEditActivityGroupsList() {
    console.log('renderEditActivityGroupsList called. Groups:', window.activityGroupsData);
    
    if (!window.activityGroupsData || window.activityGroupsData.length === 0) {
        return '<div class="text-center text-gray-400 py-8">No activity groups added yet. Click "Add Activity Group" to create one.</div>';
    }
    
    const oneTimeGroups = window.activityGroupsData.filter(g => g.periodType === 'one_time');
    const termlyGroups = window.activityGroupsData.filter(g => g.periodType === 'termly');
    const yearlyGroups = window.activityGroupsData.filter(g => g.periodType === 'yearly');
    
    let html = '';
    
    // One-Time Groups Section
    if (oneTimeGroups.length > 0) {
        html += `
            <div class="mb-4">
                <h4 class="font-bold text-lg mb-2">⭐ One-Time Activities</h4>
                <div class="space-y-3">
                    ${oneTimeGroups.map(group => `
                        <div class="border-2 border-purple-300 rounded-lg p-4 bg-purple-50">
                            <div class="flex justify-between items-start mb-3">
                                <div>
                                    <h5 class="font-bold text-md">${escapeHtml(group.name)}</h5>
                                    ${group.statusGroupName ? `<p class="text-xs text-gray-500 mt-1">🏷️ Status: ${escapeHtml(group.statusGroupName)}</p>` : ''}
                                </div>
                                <div class="flex gap-2">
                                    <button type="button" onclick="editExistingActivityGroup('${group.id}')" class="bg-blue-500 text-white px-3 py-1 rounded text-sm">Edit</button>
                                    <button type="button" onclick="deleteExistingActivityGroup('${group.id}')" class="bg-red-500 text-white px-3 py-1 rounded text-sm">Delete</button>
                                </div>
                            </div>
                            <div class="space-y-2">
                                ${group.items.map(item => {
                                    let details = '';
                                    if (item.paymentOption === 'cash_only') {
                                        details = `UGX ${(item.cashAmount || item.totalAmount || 0).toLocaleString()}`;
                                    } else if (item.paymentOption === 'item_only') {
                                        details = `${item.quantity} item(s)`;
                                    } else {
                                        const parts = [];
                                        if (item.cashAmount > 0) parts.push(`UGX ${item.cashAmount.toLocaleString()}`);
                                        if (item.quantity > 0) parts.push(`${item.quantity} item(s)`);
                                        details = parts.join(' + ');
                                    }
                                    return `
                                        <div class="bg-white rounded p-2 flex justify-between items-center">
                                            <span class="font-medium">📦 ${escapeHtml(item.name)}</span>
                                            <span class="font-semibold text-green-600">${details}</span>
                                        </div>
                                    `;
                                }).join('')}
                            </div>
                            <div class="mt-3 pt-2 border-t border-purple-300 flex justify-between font-semibold">
                                <span>Group Total:</span>
                                <span class="text-purple-600">UGX ${(group.totalAmount || 0).toLocaleString()}</span>
                            </div>
                        </div>
                    `).join('')}
                </div>
            </div>
        `;
    }
    
    // Termly Groups Section
    if (termlyGroups.length > 0) {
        html += `
            <div class="mb-4">
                <h4 class="font-bold text-lg mb-2">📅 Termly Activities</h4>
                <div class="space-y-3">
                    ${termlyGroups.map(group => `
                        <div class="border-2 border-green-300 rounded-lg p-4 bg-green-50">
                            <div class="flex justify-between items-start mb-3">
                                <div>
                                    <h5 class="font-bold text-md">${escapeHtml(group.name)}</h5>
                                    ${group.statusGroupName ? `<p class="text-xs text-gray-500 mt-1">🏷️ Status: ${escapeHtml(group.statusGroupName)}</p>` : ''}
                                </div>
                                <div class="flex gap-2">
                                    <button type="button" onclick="editExistingActivityGroup('${group.id}')" class="bg-blue-500 text-white px-3 py-1 rounded text-sm">Edit</button>
                                    <button type="button" onclick="deleteExistingActivityGroup('${group.id}')" class="bg-red-500 text-white px-3 py-1 rounded text-sm">Delete</button>
                                </div>
                            </div>
                            <div class="space-y-2">
                                ${group.items.map(item => {
                                    let details = '';
                                    if (item.paymentOption === 'cash_only') {
                                        details = `UGX ${(item.cashAmount || item.totalAmount || 0).toLocaleString()}`;
                                    } else if (item.paymentOption === 'item_only') {
                                        details = `${item.quantity} item(s)`;
                                    } else {
                                        const parts = [];
                                        if (item.cashAmount > 0) parts.push(`UGX ${item.cashAmount.toLocaleString()}`);
                                        if (item.quantity > 0) parts.push(`${item.quantity} item(s)`);
                                        details = parts.join(' + ');
                                    }
                                    return `
                                        <div class="bg-white rounded p-2 flex justify-between items-center">
                                            <span class="font-medium">📦 ${escapeHtml(item.name)}</span>
                                            <span class="font-semibold text-green-600">${details}</span>
                                        </div>
                                    `;
                                }).join('')}
                            </div>
                            <div class="mt-3 pt-2 border-t border-green-300 flex justify-between font-semibold">
                                <span>Group Total:</span>
                                <span class="text-green-600">UGX ${(group.totalAmount || 0).toLocaleString()}</span>
                            </div>
                        </div>
                    `).join('')}
                </div>
            </div>
        `;
    }
    
    // Yearly Groups Section
    if (yearlyGroups.length > 0) {
        html += `
            <div class="mb-4">
                <h4 class="font-bold text-lg mb-2">📆 Yearly Activities</h4>
                <div class="space-y-3">
                    ${yearlyGroups.map(group => `
                        <div class="border-2 border-orange-300 rounded-lg p-4 bg-orange-50">
                            <div class="flex justify-between items-start mb-3">
                                <div>
                                    <h5 class="font-bold text-md">${escapeHtml(group.name)}</h5>
                                    ${group.statusGroupName ? `<p class="text-xs text-gray-500 mt-1">🏷️ Status: ${escapeHtml(group.statusGroupName)}</p>` : ''}
                                </div>
                                <div class="flex gap-2">
                                    <button type="button" onclick="editExistingActivityGroup('${group.id}')" class="bg-blue-500 text-white px-3 py-1 rounded text-sm">Edit</button>
                                    <button type="button" onclick="deleteExistingActivityGroup('${group.id}')" class="bg-red-500 text-white px-3 py-1 rounded text-sm">Delete</button>
                                </div>
                            </div>
                            <div class="space-y-2">
                                ${group.items.map(item => {
                                    let details = '';
                                    if (item.paymentOption === 'cash_only') {
                                        details = `UGX ${(item.cashAmount || item.totalAmount || 0).toLocaleString()}`;
                                    } else if (item.paymentOption === 'item_only') {
                                        details = `${item.quantity} item(s)`;
                                    } else {
                                        const parts = [];
                                        if (item.cashAmount > 0) parts.push(`UGX ${item.cashAmount.toLocaleString()}`);
                                        if (item.quantity > 0) parts.push(`${item.quantity} item(s)`);
                                        details = parts.join(' + ');
                                    }
                                    return `
                                        <div class="bg-white rounded p-2 flex justify-between items-center">
                                            <span class="font-medium">📦 ${escapeHtml(item.name)}</span>
                                            <span class="font-semibold text-green-600">${details}</span>
                                        </div>
                                    `;
                                }).join('')}
                            </div>
                            <div class="mt-3 pt-2 border-t border-orange-300 flex justify-between font-semibold">
                                <span>Group Total:</span>
                                <span class="text-orange-600">UGX ${(group.totalAmount || 0).toLocaleString()}</span>
                            </div>
                        </div>
                    `).join('')}
                </div>
            </div>
        `;
    }
    
    if (html === '') {
        html = '<div class="text-center text-gray-400 py-8">No activity groups added yet. Click "Add Activity Group" to create one.</div>';
    }
    
    return html;
}

// ==================== SHOW EDIT ADD ACTIVITY GROUP MODAL ====================

function showEditAddActivityGroupModal() {
    const periodTypes = [
        { value: 'one_time', label: '⭐ One-Time (Paid Once)', color: 'purple' },
        { value: 'termly', label: '📅 Termly (Every term)', color: 'green' },
        { value: 'yearly', label: '📆 Yearly (Once per year)', color: 'orange' }
    ];
    
    const modalHtml = `
        <div class="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-[60] overflow-y-auto">
            <div class="bg-white rounded-2xl p-6 max-w-2xl w-full mx-4 my-8">
                <div class="flex justify-between items-center mb-4 pb-3 border-b">
                    <h3 class="text-xl font-bold flex items-center gap-2">
                        <i class="fas fa-layer-group text-green-600"></i>
                        Add Activity Group
                    </h3>
                    <button onclick="closeSubModal()" class="text-gray-500 text-2xl hover:text-gray-700">&times;</button>
                </div>
                
                <div class="space-y-5">
                    <div class="grid grid-cols-1 md:grid-cols-2 gap-4">
                        <div>
                            <label class="block text-sm font-medium mb-1 required-field">Group Name *</label>
                            <input type="text" id="editGroupName" class="w-full border rounded-lg px-3 py-2">
                        </div>
                        <div>
                            <label class="block text-sm font-medium mb-1 required-field">Period Type *</label>
                            <select id="editGroupPeriodType" class="w-full border rounded-lg px-3 py-2">
                                ${periodTypes.map(p => `<option value="${p.value}">${p.label}</option>`).join('')}
                            </select>
                        </div>
                    </div>
                    
                    <div>
                        <label class="block text-sm font-medium mb-1">Status Group (Optional)</label>
                        <div class="flex gap-2">
                            <select id="editGroupStatusGroupId" class="flex-1 border rounded-lg px-3 py-2">
                                <option value="">-- No Status Group --</option>
                                ${window.existingStatusGroups.map(g => `<option value="${g.id}">${escapeHtml(g.name)}</option>`).join('')}
                            </select>
                            <button type="button" onclick="showQuickAddStatusGroupForEdit()" class="bg-purple-600 text-white px-3 py-2 rounded-lg text-sm">
                                <i class="fas fa-plus"></i> New
                            </button>
                        </div>
                    </div>
                    
                    <div class="border rounded-lg p-4 bg-gray-50">
                        <div class="flex justify-between items-center mb-3">
                            <h4 class="font-semibold">📦 Items in this Group</h4>
                            <button type="button" onclick="showEditAddItemModal()" class="bg-green-600 text-white px-3 py-1 rounded-lg text-sm">
                                <i class="fas fa-plus"></i> Add Item
                            </button>
                        </div>
                        <div id="editCurrentGroupItemsContainer" class="space-y-3 max-h-60 overflow-y-auto">
                            <div class="text-center text-gray-400 py-4">No items added. Click "Add Item" to add.</div>
                        </div>
                    </div>
                    
                    <div class="flex gap-3">
                        <button type="button" onclick="saveEditActivityGroup()" class="flex-1 bg-blue-600 text-white py-2 rounded-lg font-semibold">
                            <i class="fas fa-save"></i> Save Activity Group
                        </button>
                        <button type="button" onclick="closeSubModal()" class="flex-1 bg-gray-300 text-gray-700 py-2 rounded-lg">
                            Cancel
                        </button>
                    </div>
                </div>
            </div>
        </div>
    `;
    
    document.body.insertAdjacentHTML('beforeend', modalHtml);
    window.tempGroupItems = [];
}

