// ==================== UPDATE ACTIVITY GROUP ====================
function updateActivityGroupInTemp() {
    console.log('updateActivityGroupInTemp called');
    
    const groupName = document.getElementById('editGroupName')?.value?.trim() || '';
    const periodType = document.getElementById('editGroupPeriodType')?.value || '';
    const statusGroupId = document.getElementById('editGroupStatusGroupId')?.value || null;
    
    if (!groupName) {
        alert('Please enter a group name');
        return;
    }
    
    if (!window.tempGroupItems || window.tempGroupItems.length === 0) {
        alert('Please add at least one item to the group');
        return;
    }
    
    let statusGroupInfo = null;
    if (statusGroupId && window.existingStatusGroups) {
        statusGroupInfo = window.existingStatusGroups.find(g => g.id === statusGroupId);
    }
    
    // Calculate total cash amount
    let totalCashAmount = 0;
    for (const item of window.tempGroupItems) {
        if (item.paymentOption === 'cash_only') {
            totalCashAmount += item.cashAmount || item.totalAmount || 0;
        } else if (item.paymentOption === 'either') {
            totalCashAmount += item.cashAmount || 0;
        }
    }
    
    // Find and update the group
    const groupIndex = window.activityGroupsData.findIndex(g => g.id === window.editGroupId);
    
    if (groupIndex !== -1) {
        window.activityGroupsData[groupIndex] = {
            ...window.activityGroupsData[groupIndex],
            name: groupName,
            periodType: periodType,
            statusGroupId: statusGroupId,
            statusGroupName: statusGroupInfo?.name || null,
            items: JSON.parse(JSON.stringify(window.tempGroupItems)),
            totalAmount: totalCashAmount,
            updatedAt: new Date().toISOString()
        };
        
        console.log('Group updated successfully:', window.activityGroupsData[groupIndex].name);
    } else {
        console.error('Group not found for update:', window.editGroupId);
        alert('Error: Group not found');
        return;
    }
    
    // Clear temporary data
    window.tempGroupItems = [];
    window.editGroupId = null;
    window.isEditingGroup = false;
    
    // Close modal and refresh display
    closeSubModal();
    renderActivityGroupsList();
    updateSummaryTotals();
    
    alert(`✅ Activity group "${groupName}" updated successfully!`);
}

