// ==================== RENDER EDIT CURRENT GROUP ITEMS ====================
function renderEditCurrentGroupItems() {
    console.log('renderEditCurrentGroupItems called');
    console.log('window.tempGroupItems length:', window.tempGroupItems?.length || 0);
    
    // First try to find the container in the current DOM
    let container = document.getElementById('editGroupItemsContainer');
    
    // If not found, try to find it by searching for the edit modal
    if (!container) {
        console.log('editGroupItemsContainer not found directly, searching for edit modal...');
        
        // Try to find the edit modal
        const editModal = document.querySelector('.z-\\[60\\] .bg-white.rounded-2xl');
        if (editModal) {
            container = editModal.querySelector('#editGroupItemsContainer');
            console.log('Found container inside edit modal:', !!container);
        }
    }
    
    // If still not found, try to find it by class or parent
    if (!container) {
        console.log('Still not found, searching by parent elements...');
        const containers = document.querySelectorAll('.border.rounded-lg.p-4.bg-gray-50');
        for (const c of containers) {
            const itemsContainer = c.querySelector('.space-y-3.max-h-60.overflow-y-auto');
            if (itemsContainer && itemsContainer.id === 'editGroupItemsContainer') {
                container = itemsContainer;
                console.log('Found container by traversal');
                break;
            }
        }
    }
    
    // If still not found, try to create it
    if (!container) {
        console.log('Container not found, attempting to create it...');
        const parentContainer = document.querySelector('.border.rounded-lg.p-4.bg-gray-50');
        if (parentContainer) {
            // Find the h4 and button wrapper
            const header = parentContainer.querySelector('.flex.justify-between.items-center.mb-3');
            if (header) {
                // Check if container already exists with different ID
                const existingContainer = parentContainer.querySelector('.space-y-3.max-h-60.overflow-y-auto');
                if (existingContainer) {
                    container = existingContainer;
                    console.log('Found existing container with different ID');
                } else {
                    // Create the container
                    const newContainer = document.createElement('div');
                    newContainer.id = 'editGroupItemsContainer';
                    newContainer.className = 'space-y-3 max-h-60 overflow-y-auto';
                    parentContainer.appendChild(newContainer);
                    container = newContainer;
                    console.log('Created new container');
                }
            }
        }
    }
    
    // If we have a container, update it
    if (container) {
        console.log('Container found, updating...');
        
        if (!window.tempGroupItems || window.tempGroupItems.length === 0) {
            container.innerHTML = '<div class="text-center text-gray-400 py-4">No items added. Click "Add Item" to add.</div>';
            return;
        }
        
        container.innerHTML = window.tempGroupItems.map((item, idx) => {
            let detailsDisplay = '';
            if (item.paymentOption === 'cash_only') {
                detailsDisplay = `UGX ${(item.cashAmount || item.totalAmount || 0).toLocaleString()}`;
            } else if (item.paymentOption === 'item_only') {
                detailsDisplay = `${item.quantity} item(s)`;
            } else {
                const parts = [];
                if (item.cashAmount > 0) parts.push(`UGX ${item.cashAmount.toLocaleString()}`);
                if (item.quantity > 0) parts.push(`${item.quantity} item(s)`);
                detailsDisplay = parts.join(' + ');
            }
            
            return `
                <div class="bg-white rounded-lg p-3 border flex justify-between items-center hover:bg-gray-50">
                    <div>
                        <p class="font-medium">${escapeHtml(item.name)}</p>
                        <p class="text-xs text-gray-500">${detailsDisplay}</p>
                    </div>
                    <button type="button" onclick="removeEditTempItem(${idx})" class="text-red-600 text-sm hover:text-red-800 p-1 rounded hover:bg-red-50">
                        <i class="fas fa-times"></i> Remove
                    </button>
                </div>
            `;
        }).join('');
        
        console.log('Container updated successfully');
    } else {
        console.error('CRITICAL: Could not find or create editGroupItemsContainer');
        console.log('Current DOM structure:', document.body.innerHTML.substring(0, 500) + '...');
        
        // Show a fallback message
        alert('Error: Could not update the items list. Please close and re-open the edit modal.');
    }
}

