function renderEditExistingGroupItems() {
    if (!window.tempGroupItems || window.tempGroupItems.length === 0) {
        return '<div class="text-center text-gray-400 py-4">No items added.</div>';
    }
    return window.tempGroupItems.map((item, idx) => {
        let details = '';
        if (item.paymentOption === 'cash_only') details = `UGX ${item.cashAmount.toLocaleString()}`;
        else if (item.paymentOption === 'item_only') details = `${item.quantity} item(s)`;
        else {
            const parts = [];
            if (item.cashAmount > 0) parts.push(`UGX ${item.cashAmount.toLocaleString()}`);
            if (item.quantity > 0) parts.push(`${item.quantity} item(s)`);
            details = parts.join(' + ');
        }
        return `<div class="bg-white rounded-lg p-3 border flex justify-between items-center"><div><p class="font-medium">📦 ${escapeHtml(item.name)}</p><p class="text-sm text-green-600">${details}</p></div><button onclick="removeEditExistingItem(${idx})" class="text-red-600 text-sm">Remove</button></div>`;
    }).join('');
}

