// ==================== DELETE EXISTING ACTIVITY GROUP ====================

function deleteExistingActivityGroup(groupId) {
    if (!confirm('Are you sure you want to delete this activity group?')) return;
    const groupIndex = window.activityGroupsData.findIndex(g => g.id === groupId);
    if (groupIndex !== -1) {
        const groupName = window.activityGroupsData[groupIndex].name;
        window.activityGroupsData.splice(groupIndex, 1);
        const container = document.getElementById('editActivityGroupsContainer');
        if (container) container.innerHTML = renderEditActivityGroupsList();
        updateEditSummaryTotals();
        alert(`✅ "${groupName}" deleted!`);
    }
}

// ==================== UPDATE EDIT SUMMARY TOTALS ====================

function updateEditSummaryTotals() {
    const tuition = parseInt(document.getElementById('editFsTuition')?.value) || 0;
    
    let oneTimeTotal = 0;
    let termlyTotal = 0;
    let yearlyTotal = 0;
    
    if (window.activityGroupsData && window.activityGroupsData.length > 0) {
        for (const group of window.activityGroupsData) {
            if (group.periodType === 'one_time') oneTimeTotal += group.totalAmount;
            else if (group.periodType === 'termly') termlyTotal += group.totalAmount;
            else if (group.periodType === 'yearly') yearlyTotal += group.totalAmount;
        }
    }
    
    const total = tuition + termlyTotal;
    
    const summaryTuition = document.getElementById('editSummaryTuition');
    const summaryOneTime = document.getElementById('editSummaryOneTime');
    const summaryTermly = document.getElementById('editSummaryTermly');
    const summaryYearly = document.getElementById('editSummaryYearly');
    const summaryTotal = document.getElementById('editSummaryTotal');
    
    if (summaryTuition) summaryTuition.innerHTML = `UGX ${tuition.toLocaleString()}`;
    if (summaryOneTime) summaryOneTime.innerHTML = `UGX ${oneTimeTotal.toLocaleString()}`;
    if (summaryTermly) summaryTermly.innerHTML = `UGX ${termlyTotal.toLocaleString()}`;
    if (summaryYearly) summaryYearly.innerHTML = `UGX ${yearlyTotal.toLocaleString()}`;
    if (summaryTotal) summaryTotal.innerHTML = `UGX ${total.toLocaleString()}`;
}

// ==================== UPDATE FEE STRUCTURE IN SERVER ====================

async function updateFeeStructureInServer(id) {
    const name = document.getElementById('editFsName').value.trim();
    const level = document.getElementById('editFsLevel').value;
    const tuition = parseInt(document.getElementById('editFsTuition').value) || 0;
    
    if (!name) {
        alert('Please enter a fee structure name');
        return;
    }
    
    const activityComponents = [];
    for (const group of window.activityGroupsData) {
        activityComponents.push({
            id: group.id,
            name: group.name,
            periodType: group.periodType,
            statusGroupId: group.statusGroupId,
            statusGroupName: group.statusGroupName,
            items: group.items.map(item => ({
                id: item.id,
                name: item.name,
                quantity: item.quantity,
                cashAmount: item.cashAmount,
                totalAmount: item.cashAmount,
                paymentOption: item.paymentOption,
                isTangible: item.paymentOption !== 'cash_only'
            })),
            totalAmount: group.totalAmount,
            createdAt: group.createdAt
        });
    }
    
    const feeStructureData = { name, level, tuition, activityComponents };
    console.log('Updating fee structure:', feeStructureData);
    
    const submitBtn = document.querySelector('#editFeeStructureModalForm button[type="submit"]');
    const originalText = submitBtn.innerHTML;
    submitBtn.innerHTML = '<i class="fas fa-spinner fa-spin"></i> Updating...';
    submitBtn.disabled = true;
    
    try {
        const response = await fetch(`/api/fee/structures/enhanced/${id}`, {
            method: 'PUT',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(feeStructureData)
        });
        
        if (response.ok) {
            alert(`✅ Fee structure "${name}" updated successfully!`);
            closeModal();
            if (typeof showFeeManagement === 'function') {
                showFeeManagement();
            } else {
                window.location.reload();
            }
        } else {
            const error = await response.json();
            alert('❌ Error: ' + (error.error || 'Unknown error'));
        }
    } catch (error) {
        alert('Network error: ' + error.message);
    } finally {
        submitBtn.innerHTML = originalText;
        submitBtn.disabled = false;
    }
}

// ==================== QUICK ADD STATUS GROUP FOR EDIT ====================

function showQuickAddStatusGroupForEdit() {
    const modalHtml = `
        <div class="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-[70]">
            <div class="bg-white rounded-2xl p-6 max-w-md w-full mx-4">
                <h4 class="text-lg font-bold mb-4">Create Status Group</h4>
                <div class="space-y-4">
                    <div><input type="text" id="quickStatusNameEdit" placeholder="Group Name" class="w-full border rounded-lg px-3 py-2"></div>
                    <div><textarea id="quickStatusDescEdit" rows="2" placeholder="Description" class="w-full border rounded-lg px-3 py-2"></textarea></div>
                    <div class="flex gap-3"><button id="quickCreateBtnEdit" class="flex-1 bg-blue-600 text-white py-2 rounded-lg">Create & Select</button><button onclick="closeSubModal()" class="flex-1 bg-gray-300 text-gray-700 py-2 rounded-lg">Cancel</button></div>
                </div>
            </div>
        </div>
    `;
    document.body.insertAdjacentHTML('beforeend', modalHtml);
    
    document.getElementById('quickCreateBtnEdit').addEventListener('click', async () => {
        const name = document.getElementById('quickStatusNameEdit').value.trim();
        if (!name) { alert('Enter group name'); return; }
        const description = document.getElementById('quickStatusDescEdit').value;
        const response = await fetch('/api/fee/status-groups', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ name, description, color: '#6b7280', isActive: true })
        });
        if (response.ok) {
            const result = await response.json();
            window.existingStatusGroups.push(result.group);
            const select = document.getElementById('editGroupStatusGroupId') || document.getElementById('editExistingGroupStatusGroupId');
            if (select) {
                const opt = document.createElement('option');
                opt.value = result.group.id;
                opt.textContent = name;
                select.appendChild(opt);
                select.value = result.group.id;
            }
            closeSubModal();
            alert('✅ Status group created and selected!');
        } else alert('❌ Error creating status group');
    });
}

// ==================== RENDER EDIT ACTIVITY GROUPS ====================
function renderEditActivityGroups(groups, periodType, color) {
    if (!groups || groups.length === 0) {
        return `<div class="text-center text-gray-400 py-4" id="empty${periodType}Msg">No ${periodType} activity groups added. Click "Add Group" to add.</div>`;
    }
    
    return groups.map((group, index) => `
        <div id="${periodType}_group_${index}" class="border-2 border-${color}-200 rounded-lg p-3 bg-white" data-group-index="${index}" data-period-type="${periodType}">
            <div class="flex justify-between items-center mb-3">
                <input type="text" placeholder="Group Name" value="${escapeHtml(group.name)}" 
                       class="flex-1 border rounded-lg px-3 py-2 text-sm focus:ring-2 focus:ring-${color}-500 group-name-input">
                <button type="button" onclick="removeEditGroup('${periodType}_group_${index}')" 
                        class="text-red-600 hover:text-red-800 ml-2 px-2 py-1">
                    <i class="fas fa-trash"></i> Remove
                </button>
            </div>
            <div class="ml-4">
                <div class="flex justify-between items-center mb-2">
                    <h4 class="text-sm font-semibold text-${color}-600">Items:</h4>
                    <button type="button" onclick="addEditItemToGroup('${periodType}_group_${index}', '${periodType}')" 
                            class="bg-${color}-100 text-${color}-600 px-2 py-1 rounded text-xs hover:bg-${color}-200">
                        <i class="fas fa-plus"></i> Add Item
                    </button>
                </div>
                <div id="${periodType}_group_${index}_items" class="space-y-2">
                    ${renderEditItems(group.items || [], periodType, color)}
                </div>
            </div>
        </div>
    `).join('');
}

// ==================== RENDER EDIT ITEMS ====================
function renderEditItems(items, periodType, color) {
    if (!items || items.length === 0) {
        return '<div class="text-center text-gray-400 text-xs py-2">No items added. Click "Add Item" to add.</div>';
    }
    
    return items.map((item, idx) => `
        <div class="flex gap-2 items-center bg-gray-50 p-2 rounded-lg border mb-2" data-item-index="${idx}">
            <input type="text" placeholder="Item name" value="${escapeHtml(item.name)}" 
                   class="flex-1 border rounded px-2 py-1 text-sm item-name-input">
            <input type="number" placeholder="Qty" value="${item.quantity || 1}" 
                   class="w-16 border rounded px-2 py-1 text-sm item-qty-input" min="1">
            <input type="number" placeholder="Total Amount" value="${item.totalAmount || 0}" 
                   class="w-28 border rounded px-2 py-1 text-sm item-amount-input" min="0">
            <button type="button" onclick="this.closest('.flex').remove(); updateEditTotals()" 
                    class="text-red-600 hover:text-red-800 px-1">
                <i class="fas fa-times"></i>
            </button>
        </div>
    `).join('');
}

// ==================== ADD EDIT GROUP FUNCTIONS ====================
let editGroupCounter = { one_time: 0, termly: 0, yearly: 0 };

function addEditOneTimeGroup() {
    addEditGroup('one_time', 'purple', 'One-Time');
}

function addEditTermlyGroup() {
    addEditGroup('termly', 'green', 'Termly');
}

function addEditYearlyGroup() {
    addEditGroup('yearly', 'orange', 'Yearly');
}

function addEditGroup(periodType, color, displayName) {
    editGroupCounter[periodType]++;
    const groupId = `${periodType}_group_${Date.now()}_${editGroupCounter[periodType]}`;
    const containerId = `edit${periodType.charAt(0).toUpperCase() + periodType.slice(1)}GroupsContainer`;
    
    const html = `
        <div id="${groupId}" class="border-2 border-${color}-200 rounded-lg p-3 bg-white" data-period-type="${periodType}">
            <div class="flex justify-between items-center mb-3">
                <input type="text" placeholder="${displayName} Group Name" 
                       class="flex-1 border rounded-lg px-3 py-2 text-sm focus:ring-2 focus:ring-${color}-500 group-name-input">
                <button type="button" onclick="removeEditGroup('${groupId}')" 
                        class="text-red-600 hover:text-red-800 ml-2 px-2 py-1">
                    <i class="fas fa-trash"></i> Remove
                </button>
            </div>
            <div class="ml-4">
                <div class="flex justify-between items-center mb-2">
                    <h4 class="text-sm font-semibold text-${color}-600">Items:</h4>
                    <button type="button" onclick="addEditItemToGroup('${groupId}', '${periodType}')" 
                            class="bg-${color}-100 text-${color}-600 px-2 py-1 rounded text-xs hover:bg-${color}-200">
                        <i class="fas fa-plus"></i> Add Item
                    </button>
                </div>
                <div id="${groupId}_items" class="space-y-2">
                    <div class="text-center text-gray-400 text-xs py-2">No items added. Click "Add Item" to add.</div>
                </div>
            </div>
        </div>
    `;
    
    const container = document.getElementById(containerId);
    const emptyMsg = document.getElementById(`empty${periodType}Msg`);
    if (emptyMsg && emptyMsg.parentNode === container) {
        emptyMsg.remove();
    }
    container.insertAdjacentHTML('beforeend', html);
    updateEditTotals();
}

// ==================== ADD EDIT ITEM TO GROUP ====================
function addEditItemToGroup(groupId, periodType) {
    const itemsContainer = document.getElementById(`${groupId}_items`);
    if (!itemsContainer) return;
    
    const emptyMsg = itemsContainer.querySelector('.text-center.text-gray-400');
    if (emptyMsg && emptyMsg.parentNode === itemsContainer) {
        emptyMsg.remove();
    }
    
    const color = periodType === 'one_time' ? 'purple' : periodType === 'termly' ? 'green' : 'orange';
    const html = `
        <div class="flex gap-2 items-center bg-gray-50 p-2 rounded-lg border mb-2">
            <input type="text" placeholder="Item name" class="flex-1 border rounded px-2 py-1 text-sm item-name-input">
            <input type="number" placeholder="Qty" class="w-16 border rounded px-2 py-1 text-sm item-qty-input" value="1" min="1">
            <input type="number" placeholder="Total Amount" class="w-28 border rounded px-2 py-1 text-sm item-amount-input" value="0" min="0">
            <button type="button" onclick="this.closest('.flex').remove(); updateEditTotals()" class="text-red-600 hover:text-red-800 px-1">
                <i class="fas fa-times"></i>
            </button>
        </div>
    `;
    
    itemsContainer.insertAdjacentHTML('beforeend', html);
    updateEditTotals();
}

// ==================== REMOVE EDIT GROUP ====================
function removeEditGroup(groupId) {
    const element = document.getElementById(groupId);
    if (element) element.remove();
    updateEditTotals();
}

// ==================== UPDATE EDIT TOTALS ====================
function updateEditTotals() {
    // Get tuition
    const tuition = parseInt(document.getElementById('editFsTuition')?.value) || 0;
    
    // Calculate One-Time total
    let oneTimeTotal = 0;
    document.querySelectorAll('#editOneTimeGroupsContainer .item-amount-input').forEach(input => {
        oneTimeTotal += parseInt(input.value) || 0;
    });
    
    // Calculate Termly total
    let termlyTotal = 0;
    document.querySelectorAll('#editTermlyGroupsContainer .item-amount-input').forEach(input => {
        termlyTotal += parseInt(input.value) || 0;
    });
    
    // Calculate Yearly total
    let yearlyTotal = 0;
    document.querySelectorAll('#editYearlyGroupsContainer .item-amount-input').forEach(input => {
        yearlyTotal += parseInt(input.value) || 0;
    });
    
    // Update displays
    document.getElementById('editOneTimeTotal').innerHTML = `UGX ${oneTimeTotal.toLocaleString()}`;
    document.getElementById('editTermlyTotal').innerHTML = `UGX ${termlyTotal.toLocaleString()}`;
    document.getElementById('editYearlyTotal').innerHTML = `UGX ${yearlyTotal.toLocaleString()}`;
    
    document.getElementById('summaryTuition').innerHTML = `UGX ${tuition.toLocaleString()}`;
    document.getElementById('summaryOneTime').innerHTML = `UGX ${oneTimeTotal.toLocaleString()}`;
    document.getElementById('summaryTermly').innerHTML = `UGX ${termlyTotal.toLocaleString()}`;
    document.getElementById('summaryYearly').innerHTML = `UGX ${yearlyTotal.toLocaleString()}`;
    
    const grandTotal = tuition + oneTimeTotal + termlyTotal + yearlyTotal;
    document.getElementById('summaryTotal').innerHTML = `UGX ${grandTotal.toLocaleString()}`;
}

// ==================== INIT EDIT EVENT LISTENERS ====================
function initEditEventListeners() {
    // Listen to tuition changes
    const tuitionInput = document.getElementById('editFsTuition');
    if (tuitionInput) {
        tuitionInput.addEventListener('input', () => updateEditTotals());
        tuitionInput.addEventListener('change', () => updateEditTotals());
    }
    
    // Also watch for dynamically added amount inputs
    const observer = new MutationObserver(() => {
        updateEditTotals();
    });
    
    observer.observe(document.getElementById('editOneTimeGroupsContainer'), { childList: true, subtree: true });
    observer.observe(document.getElementById('editTermlyGroupsContainer'), { childList: true, subtree: true });
    observer.observe(document.getElementById('editYearlyGroupsContainer'), { childList: true, subtree: true });
}

// ==================== SAVE EDITED FEE STRUCTURE ====================
async function saveEditedFeeStructure(id) {
    const name = document.getElementById('editFsName')?.value.trim();
    const level = document.getElementById('editFsLevel')?.value;
    const tuition = parseInt(document.getElementById('editFsTuition')?.value) || 0;
    
    if (!name) {
        alert('Please enter a fee structure name');
        return;
    }
    
    // Collect One-Time Activities
    const oneTimeActivities = [];
    const oneTimeGroups = document.querySelectorAll('#editOneTimeGroupsContainer > div[id^="one_time_group"]');
    for (const groupDiv of oneTimeGroups) {
        const groupNameInput = groupDiv.querySelector('.group-name-input');
        const groupName = groupNameInput ? groupNameInput.value.trim() : '';
        
        const items = [];
        const itemDivs = groupDiv.querySelectorAll(`#${groupDiv.id}_items > div`);
        for (const itemDiv of itemDivs) {
            const nameInput = itemDiv.querySelector('.item-name-input');
            const qtyInput = itemDiv.querySelector('.item-qty-input');
            const amountInput = itemDiv.querySelector('.item-amount-input');
            
            const itemName = nameInput ? nameInput.value.trim() : '';
            const quantity = qtyInput ? parseInt(qtyInput.value) || 1 : 1;
            const totalAmount = amountInput ? parseInt(amountInput.value) || 0 : 0;
            
            if (itemName && totalAmount > 0) {
                items.push({
                    id: `item_${Date.now()}_${Math.random().toString(36).substr(2, 6)}`,
                    name: itemName,
                    quantity: quantity,
                    totalAmount: totalAmount,
                    unitPrice: Math.round(totalAmount / quantity),
                    isTangible: true
                });
            }
        }
        
        if (groupName && items.length > 0) {
            oneTimeActivities.push({
                id: `comp_${Date.now()}_${Math.random().toString(36).substr(2, 6)}`,
                name: groupName,
                periodType: 'one_time',
                items: items,
                totalAmount: items.reduce((sum, i) => sum + i.totalAmount, 0),
                createdAt: new Date().toISOString()
            });
        }
    }
    
    // Collect Termly Activities
    const termlyActivities = [];
    const termlyGroups = document.querySelectorAll('#editTermlyGroupsContainer > div[id^="termly_group"]');
    for (const groupDiv of termlyGroups) {
        const groupNameInput = groupDiv.querySelector('.group-name-input');
        const groupName = groupNameInput ? groupNameInput.value.trim() : '';
        
        const items = [];
        const itemDivs = groupDiv.querySelectorAll(`#${groupDiv.id}_items > div`);
        for (const itemDiv of itemDivs) {
            const nameInput = itemDiv.querySelector('.item-name-input');
            const qtyInput = itemDiv.querySelector('.item-qty-input');
            const amountInput = itemDiv.querySelector('.item-amount-input');
            
            const itemName = nameInput ? nameInput.value.trim() : '';
            const quantity = qtyInput ? parseInt(qtyInput.value) || 1 : 1;
            const totalAmount = amountInput ? parseInt(amountInput.value) || 0 : 0;
            
            if (itemName && totalAmount > 0) {
                items.push({
                    id: `item_${Date.now()}_${Math.random().toString(36).substr(2, 6)}`,
                    name: itemName,
                    quantity: quantity,
                    totalAmount: totalAmount,
                    unitPrice: Math.round(totalAmount / quantity),
                    isTangible: true
                });
            }
        }
        
        if (groupName && items.length > 0) {
            termlyActivities.push({
                id: `comp_${Date.now()}_${Math.random().toString(36).substr(2, 6)}`,
                name: groupName,
                periodType: 'termly',
                items: items,
                totalAmount: items.reduce((sum, i) => sum + i.totalAmount, 0),
                createdAt: new Date().toISOString()
            });
        }
    }
    
    // Collect Yearly Activities
    const yearlyActivities = [];
    const yearlyGroups = document.querySelectorAll('#editYearlyGroupsContainer > div[id^="yearly_group"]');
    for (const groupDiv of yearlyGroups) {
        const groupNameInput = groupDiv.querySelector('.group-name-input');
        const groupName = groupNameInput ? groupNameInput.value.trim() : '';
        
        const items = [];
        const itemDivs = groupDiv.querySelectorAll(`#${groupDiv.id}_items > div`);
        for (const itemDiv of itemDivs) {
            const nameInput = itemDiv.querySelector('.item-name-input');
            const qtyInput = itemDiv.querySelector('.item-qty-input');
            const amountInput = itemDiv.querySelector('.item-amount-input');
            
            const itemName = nameInput ? nameInput.value.trim() : '';
            const quantity = qtyInput ? parseInt(qtyInput.value) || 1 : 1;
            const totalAmount = amountInput ? parseInt(amountInput.value) || 0 : 0;
            
            if (itemName && totalAmount > 0) {
                items.push({
                    id: `item_${Date.now()}_${Math.random().toString(36).substr(2, 6)}`,
                    name: itemName,
                    quantity: quantity,
                    totalAmount: totalAmount,
                    unitPrice: Math.round(totalAmount / quantity),
                    isTangible: true
                });
            }
        }
        
        if (groupName && items.length > 0) {
            yearlyActivities.push({
                id: `comp_${Date.now()}_${Math.random().toString(36).substr(2, 6)}`,
                name: groupName,
                periodType: 'yearly',
                items: items,
                totalAmount: items.reduce((sum, i) => sum + i.totalAmount, 0),
                createdAt: new Date().toISOString()
            });
        }
    }
    
    const activityComponents = [...oneTimeActivities, ...termlyActivities, ...yearlyActivities];
    
    const updatedData = {
        name: name,
        level: level,
        tuition: tuition,
        activityComponents: activityComponents,
        updatedAt: new Date().toISOString()
    };
    
    const submitBtn = document.querySelector('#editFeeStructureForm button[type="submit"]');
    const originalText = submitBtn.innerHTML;
    submitBtn.innerHTML = '<i class="fas fa-spinner fa-spin"></i> Updating...';
    submitBtn.disabled = true;
    
    try {
        const response = await fetch(`/api/fee/structures/enhanced/${id}`, {
            method: 'PUT',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(updatedData)
        });
        
        if (response.ok) {
            alert('✅ Fee structure updated successfully!');
            closeModal();
            showFeeManagement();
        } else {
            const error = await response.json();
            alert('❌ Error updating fee structure: ' + (error.error || 'Unknown error'));
        }
    } catch (error) {
        console.error('Error:', error);
        alert('Network error: ' + error.message);
    } finally {
        submitBtn.innerHTML = originalText;
        submitBtn.disabled = false;
    }
}

