function addEditActivityComponent() {
    const html = `<div class="flex gap-2 items-center bg-white p-2 rounded-lg border mb-2"><input type="text" placeholder="Component name" class="flex-1 border rounded px-3 py-2 text-sm editActName"><input type="number" placeholder="Amount" class="w-32 border rounded px-3 py-2 text-sm editActAmount"><button type="button" onclick="this.parentElement.remove(); calculateEditTotals()" class="text-red-600"><i class="fas fa-trash"></i></button></div>`;
    document.getElementById('editActivityList').insertAdjacentHTML('beforeend', html);
    document.querySelectorAll('#editActivityList .editActAmount').forEach(input => input.addEventListener('input', () => calculateEditTotals()));
    calculateEditTotals();
}

function addEditDevelopmentComponent() {
    const html = `<div class="flex gap-2 items-center bg-white p-2 rounded-lg border mb-2"><input type="text" placeholder="Component name" class="flex-1 border rounded px-3 py-2 text-sm editDevName"><input type="number" placeholder="Amount" class="w-32 border rounded px-3 py-2 text-sm editDevAmount"><button type="button" onclick="this.parentElement.remove(); calculateEditTotals()" class="text-red-600"><i class="fas fa-trash"></i></button></div>`;
    document.getElementById('editDevelopmentList').insertAdjacentHTML('beforeend', html);
    document.querySelectorAll('#editDevelopmentList .editDevAmount').forEach(input => input.addEventListener('input', () => calculateEditTotals()));
    calculateEditTotals();
}

function addEditTangibleRequirement() {
    const html = `<div class="flex gap-2 items-center bg-white p-2 rounded-lg border mb-2"><input type="text" placeholder="Item name" class="flex-1 border rounded px-3 py-2 text-sm editTangName"><button type="button" onclick="this.parentElement.remove()" class="text-red-600"><i class="fas fa-trash"></i></button></div>`;
    document.getElementById('editTangibleList').insertAdjacentHTML('beforeend', html);
}

function calculateEditTotals() {
    let activityTotal = 0;
    document.querySelectorAll('#editActivityList .editActAmount').forEach(input => { activityTotal += parseInt(input.value) || 0; });
    let developmentTotal = 0;
    document.querySelectorAll('#editDevelopmentList .editDevAmount').forEach(input => { developmentTotal += parseInt(input.value) || 0; });
    document.getElementById('editActivityTotal').innerHTML = `UGX ${activityTotal.toLocaleString()}`;
    document.getElementById('editDevelopmentTotal').innerHTML = `UGX ${developmentTotal.toLocaleString()}`;
}

async function deleteFeeStructureItem(id) {
    if (confirm('⚠️ Are you sure you want to delete this fee structure? This will affect all students assigned to it.')) {
        const response = await fetch(`/api/fee/structures/${id}`, { method: 'DELETE' });
        if (response.ok) {
            alert('✅ Fee structure deleted successfully!');
            showFeeManagement();
        } else {
            alert('❌ Error deleting fee structure');
        }
    }
}

