// Simple render functions
function renderSimpleFeeStructuresList(structures) {
    if (!structures || structures.length === 0) {
        return '<div class="text-center py-8 text-gray-500">No fee structures added yet</div>';
    }
    
    return `
        <div class="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
            ${structures.map(s => `
                <div class="border rounded-lg p-4">
                    <h3 class="font-bold text-lg">${s.name}</h3>
                    <p class="text-sm text-gray-600">${s.level === 'Nursery' ? 'Nursery' : s.level === 'LowerPrimary' ? 'Lower Primary' : 'Upper Primary'}</p>
                    <div class="mt-2">
                        <p>Tuition: UGX ${(s.tuition || 0).toLocaleString()}</p>
                        ${s.activityComponents?.length ? `<p>Activity: ${s.activityComponents.length} items</p>` : ''}
                        ${s.developmentComponents?.length ? `<p>Development: ${s.developmentComponents.length} items</p>` : ''}
                        <p class="font-bold mt-2">Total: UGX ${(s.total || 0).toLocaleString()}</p>
                    </div>
                    <div class="mt-3 flex gap-2">
                        <button onclick="editFeeStructure('${s.id}')" class="text-blue-600 text-sm">Edit</button>
                        <button onclick="deleteFeeStructure('${s.id}')" class="text-red-600 text-sm">Delete</button>
                    </div>
                </div>
            `).join('')}
        </div>
    `;
}

function renderSimpleBursariesList(bursaries) {
    if (!bursaries || bursaries.length === 0) {
        return '<div class="text-center py-8 text-gray-500">No bursaries added yet</div>';
    }
    
    return `
        <div class="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
            ${bursaries.map(b => `
                <div class="border rounded-lg p-4">
                    <h3 class="font-bold text-lg">${b.name}</h3>
                    <p class="text-sm text-gray-600">${b.description || ''}</p>
                    <p class="mt-2"><span class="px-2 py-1 rounded-full bg-blue-100 text-sm">${b.type === 'percentage' ? b.value + '% OFF' : 'UGX ' + b.value.toLocaleString() + ' OFF'}</span></p>
                    <div class="mt-3 flex gap-2">
                        <button onclick="editBursary('${b.id}')" class="text-blue-600 text-sm">Edit</button>
                        <button onclick="deleteBursary('${b.id}')" class="text-red-600 text-sm">Delete</button>
                    </div>
                </div>
            `).join('')}
        </div>
    `;
}

// Simple modal functions
function showAddFeeStructureForm() {
    const modalHtml = `
        <div class="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50">
            <div class="bg-white rounded-2xl p-6 max-w-md w-full mx-4">
                <h3 class="text-xl font-bold mb-4">Add Fee Structure</h3>
                <form id="simpleFeeStructureForm">
                    <div class="space-y-3">
                        <div><label class="block text-sm font-medium mb-1">Structure Name</label><input type="text" id="simpleFsName" required class="w-full border rounded-lg px-3 py-2"></div>
                        <div><label class="block text-sm font-medium mb-1">Level</label><select id="simpleFsLevel" class="w-full border rounded-lg px-3 py-2"><option value="Nursery">Nursery</option><option value="LowerPrimary">Lower Primary</option><option value="UpperPrimary">Upper Primary</option></select></div>
                        <div><label class="block text-sm font-medium mb-1">Tuition Fee (UGX)</label><input type="number" id="simpleFsTuition" class="w-full border rounded-lg px-3 py-2" value="0"></div>
                    </div>
                    <div class="flex gap-3 mt-6">
                        <button type="submit" class="flex-1 bg-blue-600 text-white py-2 rounded-lg">Save</button>
                        <button type="button" onclick="closeModal()" class="flex-1 bg-gray-300 text-gray-700 py-2 rounded-lg">Cancel</button>
                    </div>
                </form>
            </div>
        </div>
    `;
    document.body.insertAdjacentHTML('beforeend', modalHtml);
    
    document.getElementById('simpleFeeStructureForm').onsubmit = async (e) => {
        e.preventDefault();
        const data = {
            name: document.getElementById('simpleFsName').value,
            level: document.getElementById('simpleFsLevel').value,
            tuition: parseInt(document.getElementById('simpleFsTuition').value) || 0,
            activityComponents: [],
            developmentComponents: [],
            tangibleRequirements: [],
            isActive: true
        };
        
        const response = await fetch('/api/fee/structures/enhanced', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(data)
        });
        
        if (response.ok) {
            alert('✅ Fee structure added!');
            closeModal();
            showFeeManagement();
        } else {
            alert('❌ Error adding fee structure');
        }
    };
}

