// ==================== TAB INITIALIZATION ====================
function initializeFeeTabs() {
    const tabs = document.querySelectorAll('.fee-tab');
    tabs.forEach(tab => {
        tab.addEventListener('click', () => {
            const tabId = tab.dataset.tab;
            tabs.forEach(t => {
                t.classList.remove('active', 'border-b-2', 'border-blue-600', 'text-blue-600');
                t.classList.add('text-gray-600');
            });
            tab.classList.add('active', 'border-b-2', 'border-blue-600', 'text-blue-600');
            tab.classList.remove('text-gray-600');
            
            document.querySelectorAll('.fee-tab-content').forEach(c => c.classList.add('hidden'));
            document.getElementById(tabId).classList.remove('hidden');
        });
    });
}

// ==================== PAYMENT FORM SETUP ====================
function setupFeeFormListener() {
    const form = document.getElementById('feeCollectionForm');
    if (form) {
        form.addEventListener('submit', async (e) => {
            e.preventDefault();
            
            const studentId = document.getElementById('feeStudent').value;
            const term = parseInt(document.getElementById('paymentTerm').value);
            const feeStructureId = document.getElementById('feeStructureSelect').value;
            const amount = parseInt(document.getElementById('amountPaid').value);
            const method = document.getElementById('paymentMethod').value;
            const reference = document.getElementById('paymentReference').value;
            
            if (!studentId || !feeStructureId || !amount || amount <= 0) {
                alert('Please fill all required fields');
                return;
            }
            
            // Get student name
            const studentSelect = document.getElementById('feeStudent');
            const studentName = studentSelect.options[studentSelect.selectedIndex]?.text || '';
            
            const submitBtn = form.querySelector('button[type="submit"]');
            const originalText = submitBtn.innerText;
            submitBtn.innerText = 'Processing...';
            submitBtn.disabled = true;
            
            try {
                const response = await fetch('/api/fee/payments', {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({ 
                        studentId, 
                        studentName,
                        term, 
                        amount, 
                        method, 
                        reference,
                        feeStructureId,
                        academicYear: new Date().getFullYear().toString()
                    })
                });
                
                if (response.ok) {
                    const result = await response.json();
                    alert(`✅ Payment recorded successfully!\nReceipt Number: ${result.receiptNumber}`);
                    document.getElementById('amountPaid').value = '';
                    document.getElementById('paymentReference').value = '';
                    showFeeManagement(); // Refresh the page
                } else {
                    const error = await response.text();
                    alert('❌ Error recording payment: ' + error);
                }
            } catch (error) {
                console.error('Payment error:', error);
                alert('Network error: ' + error.message);
            } finally {
                submitBtn.innerText = originalText;
                submitBtn.disabled = false;
            }
        });
    }
    
    // Calculate amount due when fee structure changes
    const feeSelect = document.getElementById('feeStructureSelect');
    const amountDueSpan = document.getElementById('amountDue');
    if (feeSelect && amountDueSpan) {
        feeSelect.addEventListener('change', () => {
            const selected = feeSelect.options[feeSelect.selectedIndex];
            const total = selected?.dataset?.total || 0;
            amountDueSpan.innerHTML = `UGX ${parseInt(total).toLocaleString()}`;
            document.getElementById('feeSummary').classList.remove('hidden');
        });
    }
}

