// ==================== FEE MANAGEMENT HELPER RENDER FUNCTIONS ====================
function renderFeeStructureCardsByLevelStructures(structures, levelName) {
    const levelColors = { 'Nursery': 'from-pink-500 to-pink-600', 'LowerPrimary': 'from-blue-500 to-blue-600', 'UpperPrimary': 'from-purple-500 to-purple-600' };
    const levelTitles = { 'Nursery': '🎨 Nursery Level', 'LowerPrimary': '📚 Lower Primary', 'UpperPrimary': '🎓 Upper Primary' };
    if (!structures || structures.length === 0) return `<div class="border rounded-xl overflow-hidden shadow-sm"><div class="bg-gradient-to-r ${levelColors[levelName]} text-white p-4"><div class="flex items-center justify-between"><div><h4 class="font-bold text-lg">${levelTitles[levelName]}</h4><p class="text-sm opacity-90">${levelName === 'Nursery' ? 'Baby, Middle, Top Class' : levelName === 'LowerPrimary' ? 'P.1 - P.3' : 'P.4 - P.7'}</p></div><i class="fas ${levelName === 'Nursery' ? 'fa-baby-carriage' : levelName === 'LowerPrimary' ? 'fa-book-open' : 'fa-graduation-cap'} text-3xl opacity-50"></i></div></div><div class="p-4 text-center py-8 text-gray-500"><i class="fas fa-info-circle text-3xl mb-2"></i><p>No fee structures added yet</p><button onclick="showAddFeeStructureModal()" class="mt-2 text-blue-600 text-sm">Add Fee Structure</button></div></div>`;
    
    return `<div class="border rounded-xl overflow-hidden shadow-sm"><div class="bg-gradient-to-r ${levelColors[levelName]} text-white p-4"><div class="flex items-center justify-between"><div><h4 class="font-bold text-lg">${levelTitles[levelName]}</h4><p class="text-sm opacity-90">${levelName === 'Nursery' ? 'Baby, Middle, Top Class' : levelName === 'LowerPrimary' ? 'P.1 - P.3' : 'P.4 - P.7'}</p></div><i class="fas ${levelName === 'Nursery' ? 'fa-baby-carriage' : levelName === 'LowerPrimary' ? 'fa-book-open' : 'fa-graduation-cap'} text-3xl opacity-50"></i></div></div><div class="p-4 max-h-96 overflow-y-auto">${structures.map(s => `<div class="bg-white border rounded-lg p-4 mb-4 shadow-sm hover:shadow-md transition"><div class="flex justify-between items-start mb-3"><div><h5 class="font-bold text-gray-800 text-lg">${s.name}</h5><p class="text-xs text-gray-500">${s.level === 'Nursery' ? 'Nursery Level' : s.level === 'LowerPrimary' ? 'Lower Primary (P.1-P.3)' : 'Upper Primary (P.4-P.7)'}</p></div><div class="flex gap-1"><button onclick="editFeeStructureSystem('${s.id}')" class="text-blue-600 hover:text-blue-800 text-sm p-1" title="Edit Structure"><i class="fas fa-edit"></i></button><button onclick="deleteFeeStructureSystem('${s.id}')" class="text-red-600 hover:text-red-800 text-sm p-1" title="Delete Structure"><i class="fas fa-trash"></i></button></div></div><div class="bg-gray-50 rounded-lg p-3 mb-3"><p class="font-semibold text-sm mb-2">Core Fees:</p><div class="space-y-1 text-sm"><div class="flex justify-between"><span>Tuition:</span><span>UGX ${(s.tuition || 0).toLocaleString()}</span></div><div class="flex justify-between"><span>Activity:</span><span>UGX ${(s.activity || 0).toLocaleString()}</span></div><div class="flex justify-between"><span>Development:</span><span>UGX ${(s.development || 0).toLocaleString()}</span></div></div></div>${s.additionalFees && s.additionalFees.length > 0 ? `<div class="mb-3"><p class="font-semibold text-sm mb-2">Additional Fees:</p><div class="space-y-1">${s.additionalFees.map(fee => `<div class="flex justify-between text-sm"><span>${fee.name} ${fee.isCompulsory ? '(Compulsory)' : '(Optional)'}</span><span class="font-medium">UGX ${fee.amount.toLocaleString()}</span></div>`).join('')}</div></div>` : ''}<div class="flex justify-between pt-2 border-t mt-2"><span class="font-bold">Total Per Term:</span><span class="font-bold text-blue-600 text-lg">UGX ${(s.total || 0).toLocaleString()}</span></div></div>`).join('')}</div></div>`;
}

function renderBursariesListSystemStructures(bursaries) {
    if (!bursaries || bursaries.length === 0) return '<div class="col-span-3 text-center py-8 text-gray-500">No bursaries added. Click "Add Bursary" to create one.</div>';
    return bursaries.map(b => `<div class="border rounded-lg p-4 ${b.isActive ? 'bg-gradient-to-r from-green-50 to-teal-50' : 'bg-gray-50'} shadow-sm"><div class="flex justify-between items-start mb-2"><h4 class="font-bold text-gray-800">${b.name}</h4><span class="px-2 py-1 rounded-full text-xs ${b.type === 'percentage' ? 'bg-blue-100 text-blue-800' : 'bg-orange-100 text-orange-800'}">${b.type === 'percentage' ? `${b.value}% OFF` : `UGX ${b.value.toLocaleString()} OFF`}</span></div><p class="text-sm text-gray-600 mb-2">${b.description || 'No description provided'}</p><div class="flex items-center justify-between mt-3 pt-2 border-t"><span class="text-xs flex items-center gap-1"><i class="fas fa-tag"></i> ${b.category || 'General'}</span><span class="text-xs ${b.isActive ? 'text-green-600' : 'text-gray-500'}">${b.isActive ? '● Active' : '○ Inactive'}</span><div class="flex gap-2"><button onclick="editBursarySystem('${b.id}')" class="text-blue-600 hover:text-blue-800 text-sm"><i class="fas fa-edit"></i></button><button onclick="deleteBursarySystem('${b.id}')" class="text-red-600 hover:text-red-800 text-sm"><i class="fas fa-trash"></i></button></div></div></div>`).join('');
}

function getActiveBursariesOptionsSystemStructures(bursaries) {
    if (!bursaries) return '';
    return bursaries.filter(b => b.isActive).map(b => `<option value="${b.id}" data-type="${b.type}" data-value="${b.value}" data-name="${b.name}">${b.name} - ${b.type === 'percentage' ? `${b.value}% off` : `UGX ${b.value.toLocaleString()} off`}</option>`).join('');
}

async function renderPaymentsTableSystemFromData(payments) {
    if (!payments || payments.length === 0) return '<tr><td colspan="9" class="text-center p-8 text-gray-500">No payment records found</td></tr>';
    return payments.slice().reverse().map(p => `<tr class="border-b hover:bg-gray-50"><td class="p-3 text-sm">${new Date(p.date).toLocaleDateString()}</td><td class="p-3 font-mono text-sm font-semibold text-blue-600">${p.receiptNumber}</td><td class="p-3">${p.studentName || 'N/A'}</td><td class="p-3 text-sm">${p.admissionNumber || 'N/A'}</td><td class="p-3 text-sm">${p.academicYear || '2026'} / Term ${p.term}</td><td class="p-3 text-sm">${p.feeStructureName || 'Fee Payment'}${p.additionalFeeName ? ` (${p.additionalFeeName})` : ''}</td><td class="p-3 text-right font-semibold">UGX ${(p.amount || 0).toLocaleString()}</td><td class="p-3"><span class="px-2 py-1 rounded-full text-xs ${getPaymentMethodClass(p.method)}">${getPaymentMethodIcon(p.method)} ${(p.method || 'CASH').toUpperCase()}</span></td><td class="p-3 text-center"><button onclick="viewPaymentReceipt('${p.id}')" class="text-blue-600 hover:text-blue-800 mr-2" title="View Receipt"><i class="fas fa-print"></i></button></td></tr>`).join('');
}

function renderStudentBalancesTableSystemFromData(students) {
    if (!students || students.length === 0) return '<tr><td colspan="12" class="text-center p-8 text-gray-500">No students found</td></tr>';
    return students.map(student => { let status = 'Good Standing'; let statusClass = 'bg-green-100 text-green-800'; if (student.balance > student.expectedPerTerm) { status = 'Critical Overdue'; statusClass = 'bg-red-100 text-red-800'; } else if (student.balance > 0) { status = 'Partial Payment'; statusClass = 'bg-yellow-100 text-yellow-800'; } else if (student.balance < 0) { status = 'Credit Balance'; statusClass = 'bg-blue-100 text-blue-800'; } return `<tr class="border-b hover:bg-gray-50 ${student.balance > student.expectedPerTerm ? 'bg-red-50' : ''}"><td class="p-3 font-mono text-sm">${student.admissionNumber}</td><td class="p-3 font-medium">${student.firstName} ${student.lastName}</td><td class="p-3">${student.currentClass || 'N/A'}</td><td class="p-3 text-sm">${student.feeStructure ? student.feeStructure.name : 'Not Assigned'}</td><td class="p-3 text-right"><span class="text-sm ${student.term1Paid >= student.expectedPerTerm ? 'text-green-600' : student.term1Paid > 0 ? 'text-orange-600' : 'text-red-600'}">UGX ${(student.term1Paid || 0).toLocaleString()}</span><br><span class="text-xs text-gray-400">/ ${(student.expectedPerTerm || 0).toLocaleString()}</span></td><td class="p-3 text-right"><span class="text-sm ${student.term2Paid >= student.expectedPerTerm ? 'text-green-600' : student.term2Paid > 0 ? 'text-orange-600' : 'text-red-600'}">UGX ${(student.term2Paid || 0).toLocaleString()}</span><br><span class="text-xs text-gray-400">/ ${(student.expectedPerTerm || 0).toLocaleString()}</span></td><td class="p-3 text-right"><span class="text-sm ${student.term3Paid >= student.expectedPerTerm ? 'text-green-600' : student.term3Paid > 0 ? 'text-orange-600' : 'text-red-600'}">UGX ${(student.term3Paid || 0).toLocaleString()}</span><br><span class="text-xs text-gray-400">/ ${(student.expectedPerTerm || 0).toLocaleString()}</span></td><td class="p-3 text-right font-semibold">UGX ${(student.totalPaid || 0).toLocaleString()}</td><td class="p-3 text-right">UGX ${(student.totalExpected || 0).toLocaleString()}</td><td class="p-3 text-right font-bold ${student.balance > 0 ? 'text-red-600' : 'text-green-600'}">UGX ${Math.abs(student.balance || 0).toLocaleString()}</td><td class="p-3 text-center"><span class="px-2 py-1 rounded-full text-xs ${statusClass}">${status}</span></td><td class="p-3 text-center"><button onclick="viewStudentFeeDetails('${student.id}')" class="text-blue-600 hover:text-blue-800" title="View Details"><i class="fas fa-eye"></i></button><button onclick="makePaymentForStudentFromBalance('${student.id}')" class="text-green-600 hover:text-green-800 ml-2" title="Make Payment"><i class="fas fa-receipt"></i></button></td></tr>`; }).join('');
}

function initializeFeeChartsSystemFromData(payments) {
    const methodCanvas = document.getElementById('paymentMethodChartSystem');
    if (methodCanvas && payments) {
        const methodData = { cash: payments.filter(p => p.method === 'cash').reduce((s, p) => s + (p.amount || 0), 0), bank: payments.filter(p => p.method === 'bank').reduce((s, p) => s + (p.amount || 0), 0), mobile: payments.filter(p => p.method === 'mobile').reduce((s, p) => s + (p.amount || 0), 0), cheque: payments.filter(p => p.method === 'cheque').reduce((s, p) => s + (p.amount || 0), 0) };
        new Chart(methodCanvas, { type: 'doughnut', data: { labels: ['Cash', 'Bank Transfer', 'Mobile Money', 'Cheque'], datasets: [{ data: [methodData.cash, methodData.bank, methodData.mobile, methodData.cheque], backgroundColor: ['#10b981', '#3b82f6', '#8b5cf6', '#f59e0b'], borderWidth: 0 }] }, options: { responsive: true, maintainAspectRatio: true, plugins: { legend: { position: 'bottom' } } } });
    }
    const trendCanvas = document.getElementById('monthlyTrendChartSystem');
    if (trendCanvas && payments) {
        const monthlyData = {};
        payments.forEach(p => { if (p.date) { const month = new Date(p.date).toLocaleString('default', { month: 'short' }); monthlyData[month] = (monthlyData[month] || 0) + (p.amount || 0); } });
        new Chart(trendCanvas, { type: 'line', data: { labels: Object.keys(monthlyData), datasets: [{ label: 'Amount Collected (UGX)', data: Object.values(monthlyData), borderColor: '#3b82f6', backgroundColor: 'rgba(59, 130, 246, 0.1)', tension: 0.4, fill: true }] }, options: { responsive: true, maintainAspectRatio: true, scales: { y: { beginAtZero: true, ticks: { callback: value => 'UGX ' + value.toLocaleString() } } } } });
    }
}

function loadLevelWiseCollectionSystemFromData(students, classes) {
    const levels = ['Nursery', 'LowerPrimary', 'UpperPrimary'];
    const container = document.getElementById('levelWiseCollectionSystem');
    if (container && students) {
        const getStudentLevel = (student) => { const classObj = classes.find(c => c.name === student.currentClass); return classObj ? classObj.level : 'Unknown'; };
        const levelData = [];
        for (const level of levels) {
            const levelStudents = students.filter(s => getStudentLevel(s) === level);
            const totalCollected = levelStudents.reduce((s, student) => s + (student.totalPaid || 0), 0);
            const totalExpected = levelStudents.reduce((s, student) => s + (student.totalExpected || 0), 0);
            const percent = totalExpected > 0 ? (totalCollected / totalExpected * 100).toFixed(1) : 0;
            levelData.push({ level, totalCollected, totalExpected, percent, count: levelStudents.length });
        }
        container.innerHTML = levelData.map(d => `<div class="mb-4"><div class="flex justify-between text-sm mb-1"><span class="font-medium">${d.level === 'Nursery' ? '🎨 Nursery' : d.level === 'LowerPrimary' ? '📚 Lower Primary' : '🎓 Upper Primary'}</span><span>UGX ${d.totalCollected.toLocaleString()} / UGX ${d.totalExpected.toLocaleString()}</span></div><div class="w-full bg-gray-200 rounded-full h-2"><div class="bg-blue-600 rounded-full h-2" style="width: ${d.percent}%"></div></div><p class="text-xs text-gray-500 mt-1">${d.count} students | ${d.percent}% collected</p></div>`).join('');
    }
}

function loadBursaryImpactSystemFromData(payments) {
    const container = document.getElementById('bursaryImpactSystem');
    if (container && payments) {
        const bursaryMap = {};
        payments.forEach(p => { if (p.bursaryName) { if (!bursaryMap[p.bursaryName]) bursaryMap[p.bursaryName] = 0; bursaryMap[p.bursaryName] += p.amount || 0; } });
        if (Object.keys(bursaryMap).length === 0) container.innerHTML = '<p class="text-gray-500 text-center">No bursary data available</p>';
        else container.innerHTML = Object.entries(bursaryMap).map(([name, amount]) => `<div class="flex justify-between items-center p-2 bg-gray-50 rounded mb-2"><span class="text-sm">🎖️ ${name}</span><span class="font-semibold text-green-600">UGX ${amount.toLocaleString()}</span></div>`).join('');
    }
}



function editFeeStructureSystem(id) { const fs = feeStructuresData.find(f => f.id === id); if (!fs) return; const modalHtml = `<div class="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50"><div class="bg-white rounded-2xl p-6 max-w-md w-full mx-4"><h3 class="text-xl font-bold mb-4">Edit Fee Structure</h3><form id="editFeeStructureFormSystem"><div class="space-y-3"><div><label class="block text-sm font-medium mb-1">Structure Name</label><input type="text" id="editFsName" value="${fs.name}" class="w-full border rounded-lg px-3 py-2"></div><div><label class="block text-sm font-medium mb-1">Education Level</label><select id="editFsLevel" class="w-full border rounded-lg px-3 py-2"><option value="Nursery" ${fs.level === 'Nursery' ? 'selected' : ''}>Nursery Level</option><option value="LowerPrimary" ${fs.level === 'LowerPrimary' ? 'selected' : ''}>Lower Primary</option><option value="UpperPrimary" ${fs.level === 'UpperPrimary' ? 'selected' : ''}>Upper Primary</option></select></div><div><label class="block text-sm font-medium mb-1">Tuition Fee</label><input type="number" id="editFsTuition" value="${fs.tuition}" class="w-full border rounded-lg px-3 py-2"></div><div><label class="block text-sm font-medium mb-1">Activity Fee</label><input type="number" id="editFsActivity" value="${fs.activity}" class="w-full border rounded-lg px-3 py-2"></div><div><label class="block text-sm font-medium mb-1">Development Fee</label><input type="number" id="editFsDevelopment" value="${fs.development}" class="w-full border rounded-lg px-3 py-2"></div><div class="bg-blue-50 p-3 rounded-lg"><div class="flex justify-between"><span class="font-semibold">Total Per Term:</span><span id="editFsTotal" class="font-bold text-blue-600">UGX ${fs.total.toLocaleString()}</span></div></div></div><div class="flex gap-3 mt-6"><button type="submit" class="flex-1 bg-blue-600 text-white py-2 rounded-lg">Save Changes</button><button type="button" onclick="closeModalSystem()" class="flex-1 bg-gray-300 text-gray-700 py-2 rounded-lg">Cancel</button></div></form></div></div>`;
    document.body.insertAdjacentHTML('beforeend', modalHtml);
    ['editFsTuition', 'editFsActivity', 'editFsDevelopment'].forEach(id => { document.getElementById(id).addEventListener('input', () => { const tuition = parseInt(document.getElementById('editFsTuition').value) || 0; const activity = parseInt(document.getElementById('editFsActivity').value) || 0; const development = parseInt(document.getElementById('editFsDevelopment').value) || 0; document.getElementById('editFsTotal').innerHTML = `UGX ${(tuition + activity + development).toLocaleString()}`; }); });
    document.getElementById('editFeeStructureFormSystem').addEventListener('submit', async (e) => { e.preventDefault(); fs.name = document.getElementById('editFsName').value; fs.level = document.getElementById('editFsLevel').value; fs.tuition = parseInt(document.getElementById('editFsTuition').value) || 0; fs.activity = parseInt(document.getElementById('editFsActivity').value) || 0; fs.development = parseInt(document.getElementById('editFsDevelopment').value) || 0; fs.total = fs.tuition + fs.activity + fs.development; fs.updatedAt = new Date().toISOString(); const response = await fetch(`/api/fee/structures/${id}`, { method: 'PUT', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(fs) }); if (response.ok) { alert('✅ Fee structure updated successfully!'); closeModalSystem(); showFeeManagement(); } else { alert('❌ Error updating fee structure'); } });
}

