// Global arrays to store components temporarily


// Function to toggle the enhanced fee form visibility
function toggleEnhancedFeeForm() {
    const container = document.getElementById('enhancedFeeFormContainer');
    if (container) {
        container.classList.toggle('hidden');
        if (!container.classList.contains('hidden')) {
            updateEnhancedFeeTotals();
        }
    }
}

// Function to add an activity component
function addActivityComponent() {
    const componentId = Date.now();
    const componentHtml = `
        <div id="activityComp_${componentId}" class="flex gap-2 items-center bg-white p-2 rounded-lg border">
            <input type="text" placeholder="Component name (e.g., Brooms, TP, Soap)" 
                   class="flex-1 border rounded-lg px-3 py-2 text-sm" id="actName_${componentId}">
            <input type="number" placeholder="Amount (UGX)" 
                   class="w-32 border rounded-lg px-3 py-2 text-sm" id="actAmount_${componentId}" 
                   oninput="updateEnhancedFeeTotals()">
            <button type="button" onclick="removeActivityComponent(${componentId})" 
                    class="text-red-600 hover:text-red-800 px-2">
                <i class="fas fa-trash"></i>
            </button>
        </div>
    `;
    
    const container = document.getElementById('activityComponentsList');
    if (container) {
        container.insertAdjacentHTML('beforeend', componentHtml);
        
        // Store reference
        tempActivityComponents.push({
            tempId: componentId,
            name: '',
            amount: 0
        });
        
        updateEnhancedFeeTotals();
    }
}

// Function to remove an activity component
function removeActivityComponent(tempId) {
    const element = document.getElementById(`activityComp_${tempId}`);
    if (element) element.remove();
    
    tempActivityComponents = tempActivityComponents.filter(c => c.tempId !== tempId);
    updateEnhancedFeeTotals();
}

