// Function to remove a tangible requirement
function removeTangibleRequirement(tempId) {
    const element = document.getElementById(`tangibleReq_${tempId}`);
    if (element) element.remove();
    
    tempTangibleRequirements = tempTangibleRequirements.filter(r => r.tempId !== tempId);
}

// Function to update all totals in real-time
function updateEnhancedFeeTotals() {
    // Calculate activity total
    let activityTotal = 0;
    tempActivityComponents.forEach(comp => {
        const amountInput = document.getElementById(`actAmount_${comp.tempId}`);
        if (amountInput) {
            const amount = parseInt(amountInput.value) || 0;
            comp.amount = amount;
            activityTotal += amount;
        }
    });
    
    // Calculate development total
    let developmentTotal = 0;
    tempDevelopmentComponents.forEach(comp => {
        const amountInput = document.getElementById(`devAmount_${comp.tempId}`);
        if (amountInput) {
            const amount = parseInt(amountInput.value) || 0;
            comp.amount = amount;
            developmentTotal += amount;
        }
    });
    
    // Get tuition
    const tuitionInput = document.getElementById('efsTuition');
    const tuition = parseInt(tuitionInput?.value) || 0;
    
    // Update display
    const activityTotalSpan = document.getElementById('efsActivityTotal');
    if (activityTotalSpan) activityTotalSpan.innerHTML = `UGX ${activityTotal.toLocaleString()}`;
    
    const developmentTotalSpan = document.getElementById('efsDevelopmentTotal');
    if (developmentTotalSpan) developmentTotalSpan.innerHTML = `UGX ${developmentTotal.toLocaleString()}`;
    
    // Update summary
    const summaryTuition = document.getElementById('summaryTuition');
    if (summaryTuition) summaryTuition.innerHTML = `UGX ${tuition.toLocaleString()}`;
    
    const summaryActivity = document.getElementById('summaryActivity');
    if (summaryActivity) summaryActivity.innerHTML = `UGX ${activityTotal.toLocaleString()}`;
    
    const summaryDevelopment = document.getElementById('summaryDevelopment');
    if (summaryDevelopment) summaryDevelopment.innerHTML = `UGX ${developmentTotal.toLocaleString()}`;
    
    const total = tuition + activityTotal + developmentTotal;
    const summaryTotal = document.getElementById('summaryTotal');
    if (summaryTotal) summaryTotal.innerHTML = `UGX ${total.toLocaleString()}`;
}

// Function to collect all components from the form
function collectEnhancedFeeComponents() {
    const activityComponents = [];
    tempActivityComponents.forEach(comp => {
        const nameInput = document.getElementById(`actName_${comp.tempId}`);
        const amountInput = document.getElementById(`actAmount_${comp.tempId}`);
        
        if (nameInput && nameInput.value && amountInput && parseInt(amountInput.value) > 0) {
            activityComponents.push({
                id: `act_${Date.now()}_${Math.random().toString(36).substr(2, 6)}`,
                name: nameInput.value,
                amount: parseInt(amountInput.value)
            });
        }
    });
    
    const developmentComponents = [];
    tempDevelopmentComponents.forEach(comp => {
        const nameInput = document.getElementById(`devName_${comp.tempId}`);
        const amountInput = document.getElementById(`devAmount_${comp.tempId}`);
        
        if (nameInput && nameInput.value && amountInput && parseInt(amountInput.value) > 0) {
            developmentComponents.push({
                id: `dev_${Date.now()}_${Math.random().toString(36).substr(2, 6)}`,
                name: nameInput.value,
                amount: parseInt(amountInput.value)
            });
        }
    });
    
    const tangibleRequirements = [];
    tempTangibleRequirements.forEach(req => {
        const nameInput = document.getElementById(`reqName_${req.tempId}`);
        
        if (nameInput && nameInput.value) {
            tangibleRequirements.push({
                id: `req_${Date.now()}_${Math.random().toString(36).substr(2, 6)}`,
                name: nameInput.value
            });
        }
    });
    
    return { activityComponents, developmentComponents, tangibleRequirements };
}

// Function to reset the enhanced fee form
function resetEnhancedFeeForm() {
    // Clear input fields
    const nameInput = document.getElementById('efsName');
    if (nameInput) nameInput.value = '';
    
    const levelSelect = document.getElementById('efsLevel');
    if (levelSelect) levelSelect.value = 'Nursery';
    
    const tuitionInput = document.getElementById('efsTuition');
    if (tuitionInput) tuitionInput.value = '0';
    
    // Clear all component lists
    const activityContainer = document.getElementById('activityComponentsList');
    if (activityContainer) activityContainer.innerHTML = '';
    
    const developmentContainer = document.getElementById('developmentComponentsList');
    if (developmentContainer) developmentContainer.innerHTML = '';
    
    const tangibleContainer = document.getElementById('tangibleRequirementsList');
    if (tangibleContainer) tangibleContainer.innerHTML = '';
    
    // Reset temporary arrays
    tempActivityComponents = [];
    tempDevelopmentComponents = [];
    tempTangibleRequirements = [];
    
    // Update totals
    updateEnhancedFeeTotals();
}

// Handle enhanced fee structure form submission
async function handleEnhancedFeeStructureSubmit(e) {
    e.preventDefault();
    
    const name = document.getElementById('efsName')?.value;
    const level = document.getElementById('efsLevel')?.value;
    const tuition = parseInt(document.getElementById('efsTuition')?.value) || 0;
    
    if (!name) {
        alert('Please enter a fee structure name');
        return;
    }
    
    const { activityComponents, developmentComponents, tangibleRequirements } = collectEnhancedFeeComponents();
    
    const feeStructureData = {
        name: name,
        level: level,
        tuition: tuition,
        activityComponents: activityComponents,
        developmentComponents: developmentComponents,
        tangibleRequirements: tangibleRequirements,
        isActive: true
    };
    
    const submitBtn = e.target.querySelector('button[type="submit"]');
    const originalText = submitBtn.innerText;
    submitBtn.innerText = 'Saving...';
    submitBtn.disabled = true;
    
    try {
        const response = await fetch('/api/fee/structures/enhanced', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(feeStructureData)
        });
        
        if (response.ok) {
            alert('✅ Enhanced fee structure saved successfully!');
            resetEnhancedFeeForm();
            // Refresh the fee management view to show new structure
            showFeeManagement();
        } else {
            const error = await response.json();
            alert('❌ Error saving fee structure: ' + (error.error || 'Unknown error'));
        }
    } catch (error) {
        console.error('Error:', error);
        alert('Network error: ' + error.message);
    } finally {
        submitBtn.innerText = originalText;
        submitBtn.disabled = false;
    }
}

// Function to display existing enhanced fee structures
function renderEnhancedFeeStructuresList(structures) {
    if (!structures || structures.length === 0) {
        return '<div class="text-center py-8 text-gray-500">No fee structures added yet. Use the form above to create one.</div>';
    }
    
    // Group by level
    const nurseryStructures = structures.filter(s => s.level === 'Nursery');
    const lowerPrimaryStructures = structures.filter(s => s.level === 'LowerPrimary');
    const upperPrimaryStructures = structures.filter(s => s.level === 'UpperPrimary');
    
    return `
        <div class="grid grid-cols-1 lg:grid-cols-3 gap-6">
            ${renderEnhancedStructureGroup(nurseryStructures, 'Nursery', '🎨')}
            ${renderEnhancedStructureGroup(lowerPrimaryStructures, 'Lower Primary', '📚')}
            ${renderEnhancedStructureGroup(upperPrimaryStructures, 'Upper Primary', '🎓')}
        </div>
    `;
}

function renderEnhancedStructureGroup(structures, levelName, icon) {
    if (structures.length === 0) {
        return `
            <div class="border rounded-xl p-4 text-center bg-gray-50">
                <div class="text-3xl mb-2">${icon}</div>
                <h3 class="font-semibold">${levelName}</h3>
                <p class="text-sm text-gray-500">No fee structures</p>
            </div>
        `;
    }
    
    return `
        <div class="border rounded-xl overflow-hidden shadow-sm">
            <div class="bg-gradient-to-r from-blue-500 to-blue-600 text-white p-3 text-center font-semibold">
                ${icon} ${levelName}
            </div>
            <div class="p-3 max-h-96 overflow-y-auto">
                ${structures.map(s => `
                    <div class="border-b pb-3 mb-3 last:border-0">
                        <div class="flex justify-between items-start">
                            <h4 class="font-bold text-lg">${s.name}</h4>
                            <div class="flex gap-1">
                                <button onclick="editEnhancedFeeStructure('${s.id}')" class="text-blue-600 text-sm">
                                    <i class="fas fa-edit"></i>
                                </button>
                                <button onclick="deleteEnhancedFeeStructure('${s.id}')" class="text-red-600 text-sm">
                                    <i class="fas fa-trash"></i>
                                </button>
                            </div>
                        </div>
                        
                        <div class="mt-2 space-y-2">
                            <div class="bg-gray-50 p-2 rounded">
                                <span class="font-semibold">Tuition:</span>
                                <span>UGX ${(s.tuition || 0).toLocaleString()}</span>
                            </div>
                            
                            ${s.activityComponents && s.activityComponents.length > 0 ? `
                                <div class="bg-blue-50 p-2 rounded">
                                    <p class="font-semibold text-sm mb-1">📌 Activity Components:</p>
                                    ${s.activityComponents.map(c => `
                                        <div class="flex justify-between text-sm">
                                            <span>• ${c.name}</span>
                                            <span>UGX ${c.amount.toLocaleString()}</span>
                                        </div>
                                    `).join('')}
                                    <div class="flex justify-between text-sm font-semibold mt-1 pt-1 border-t border-blue-200">
                                        <span>Total Activity:</span>
                                        <span>UGX ${(s.activityTotal || 0).toLocaleString()}</span>
                                    </div>
                                </div>
                            ` : ''}
                            
                            ${s.developmentComponents && s.developmentComponents.length > 0 ? `
                                <div class="bg-green-50 p-2 rounded">
                                    <p class="font-semibold text-sm mb-1">🏗️ Development Components:</p>
                                    ${s.developmentComponents.map(c => `
                                        <div class="flex justify-between text-sm">
                                            <span>• ${c.name}</span>
                                            <span>UGX ${c.amount.toLocaleString()}</span>
                                        </div>
                                    `).join('')}
                                    <div class="flex justify-between text-sm font-semibold mt-1 pt-1 border-t border-green-200">
                                        <span>Total Development:</span>
                                        <span>UGX ${(s.developmentTotal || 0).toLocaleString()}</span>
                                    </div>
                                </div>
                            ` : ''}
                            
                            ${s.tangibleRequirements && s.tangibleRequirements.length > 0 ? `
                                <div class="bg-yellow-50 p-2 rounded">
                                    <p class="font-semibold text-sm mb-1">📦 Tangible Items:</p>
                                    <div class="flex flex-wrap gap-1">
                                        ${s.tangibleRequirements.map(r => `
                                            <span class="px-2 py-1 bg-yellow-100 rounded-full text-xs">${r.name}</span>
                                        `).join('')}
                                    </div>
                                </div>
                            ` : ''}
                        </div>
                        
                        <div class="mt-3 pt-2 border-t">
                            <div class="flex justify-between font-bold">
                                <span>TOTAL PER TERM:</span>
                                <span class="text-blue-600">UGX ${(s.total || 0).toLocaleString()}</span>
                            </div>
                        </div>
                    </div>
                `).join('')}
            </div>
        </div>
    `;
}

// Edit enhanced fee structure
async function editEnhancedFeeStructure(id) {
    try {
        const response = await fetch('/api/fee/structures');
        const structures = await response.json();
        const structure = structures.find(s => s.id === id);
        
        if (!structure) {
            alert('Fee structure not found');
            return;
        }
        
        // Populate the form
        const nameInput = document.getElementById('efsName');
        if (nameInput) nameInput.value = structure.name;
        
        const levelSelect = document.getElementById('efsLevel');
        if (levelSelect) levelSelect.value = structure.level;
        
        const tuitionInput = document.getElementById('efsTuition');
        if (tuitionInput) tuitionInput.value = structure.tuition;
        
        // Clear and repopulate activity components
        tempActivityComponents = [];
        const activityContainer = document.getElementById('activityComponentsList');
        if (activityContainer) activityContainer.innerHTML = '';
        
        if (structure.activityComponents && structure.activityComponents.length > 0) {
            structure.activityComponents.forEach(comp => {
                const componentId = Date.now();
                const componentHtml = `
                    <div id="activityComp_${componentId}" class="flex gap-2 items-center bg-white p-2 rounded-lg border">
                        <input type="text" placeholder="Component name" 
                               class="flex-1 border rounded-lg px-3 py-2 text-sm" id="actName_${componentId}" value="${comp.name}">
                        <input type="number" placeholder="Amount (UGX)" 
                               class="w-32 border rounded-lg px-3 py-2 text-sm" id="actAmount_${componentId}" 
                               value="${comp.amount}" oninput="updateEnhancedFeeTotals()">
                        <button type="button" onclick="removeActivityComponent(${componentId})" 
                                class="text-red-600 hover:text-red-800 px-2">
                            <i class="fas fa-trash"></i>
                        </button>
                    </div>
                `;
                activityContainer.insertAdjacentHTML('beforeend', componentHtml);
                tempActivityComponents.push({ tempId: componentId, name: comp.name, amount: comp.amount });
            });
        }
        
        // Clear and repopulate development components
        tempDevelopmentComponents = [];
        const developmentContainer = document.getElementById('developmentComponentsList');
        if (developmentContainer) developmentContainer.innerHTML = '';
        
        if (structure.developmentComponents && structure.developmentComponents.length > 0) {
            structure.developmentComponents.forEach(comp => {
                const componentId = Date.now();
                const componentHtml = `
                    <div id="devComp_${componentId}" class="flex gap-2 items-center bg-white p-2 rounded-lg border">
                        <input type="text" placeholder="Component name" 
                               class="flex-1 border rounded-lg px-3 py-2 text-sm" id="devName_${componentId}" value="${comp.name}">
                        <input type="number" placeholder="Amount (UGX)" 
                               class="w-32 border rounded-lg px-3 py-2 text-sm" id="devAmount_${componentId}" 
                               value="${comp.amount}" oninput="updateEnhancedFeeTotals()">
                        <button type="button" onclick="removeDevelopmentComponent(${componentId})" 
                                class="text-red-600 hover:text-red-800 px-2">
                            <i class="fas fa-trash"></i>
                        </button>
                    </div>
                `;
                developmentContainer.insertAdjacentHTML('beforeend', componentHtml);
                tempDevelopmentComponents.push({ tempId: componentId, name: comp.name, amount: comp.amount });
            });
        }
        
        // Clear and repopulate tangible requirements
        tempTangibleRequirements = [];
        const tangibleContainer = document.getElementById('tangibleRequirementsList');
        if (tangibleContainer) tangibleContainer.innerHTML = '';
        
        if (structure.tangibleRequirements && structure.tangibleRequirements.length > 0) {
            structure.tangibleRequirements.forEach(req => {
                const reqId = Date.now();
                const reqHtml = `
                    <div id="tangibleReq_${reqId}" class="flex gap-2 items-center bg-white p-2 rounded-lg border">
                        <input type="text" placeholder="Item name" 
                               class="flex-1 border rounded-lg px-3 py-2 text-sm" id="reqName_${reqId}" value="${req.name}">
                        <button type="button" onclick="removeTangibleRequirement(${reqId})" 
                                class="text-red-600 hover:text-red-800 px-2">
                            <i class="fas fa-trash"></i>
                        </button>
                    </div>
                `;
                tangibleContainer.insertAdjacentHTML('beforeend', reqHtml);
                tempTangibleRequirements.push({ tempId: reqId, name: req.name });
            });
        }
        
        updateEnhancedFeeTotals();
        
        // Show the form
        const container = document.getElementById('enhancedFeeFormContainer');
        if (container && container.classList.contains('hidden')) {
            container.classList.remove('hidden');
        }
        
        // Change submit button text for update
        const form = document.getElementById('enhancedFeeStructureForm');
        if (form) {
            // Store the ID for update
            form.dataset.editingId = id;
            const submitBtn = form.querySelector('button[type="submit"]');
            if (submitBtn) submitBtn.innerHTML = '<i class="fas fa-save"></i> Update Fee Structure';
        }
        
    } catch (error) {
        console.error('Error loading fee structure for edit:', error);
        alert('Error loading fee structure details');
    }
}

// Delete enhanced fee structure
async function deleteEnhancedFeeStructure(id) {
    if (confirm('Are you sure you want to delete this fee structure? This will affect all students assigned to it.')) {
        try {
            const response = await fetch(`/api/fee/structures/${id}`, { method: 'DELETE' });
            if (response.ok) {
                alert('✅ Fee structure deleted successfully');
                showFeeManagement();
            } else {
                alert('❌ Error deleting fee structure');
            }
        } catch (error) {
            console.error('Error:', error);
            alert('Network error');
        }
    }
}

// Initialize enhanced fee form event listener
function initEnhancedFeeForm() {
    const form = document.getElementById('enhancedFeeStructureForm');
    if (form) {
        // Remove existing listener to avoid duplicates
        form.removeEventListener('submit', handleEnhancedFeeStructureSubmit);
        form.addEventListener('submit', handleEnhancedFeeStructureSubmit);
    }
}

