// Function to update empty messages visibility
function updateEmptyMessages() {
    const activityContainer = document.getElementById('modalActivityList');
    const devContainer = document.getElementById('modalDevelopmentList');
    const tangibleContainer = document.getElementById('modalTangibleList');
    
    if (activityContainer && activityContainer.children.length === 0 && !document.getElementById('emptyActivityMsg')) {
        activityContainer.innerHTML = '<div class="text-center text-gray-400 py-4" id="emptyActivityMsg">No activity components added. Click "Add Component" to add.</div>';
    }
    
    if (devContainer && devContainer.children.length === 0 && !document.getElementById('emptyDevMsg')) {
        devContainer.innerHTML = '<div class="text-center text-gray-400 py-4" id="emptyDevMsg">No development components added. Click "Add Component" to add.</div>';
    }
    
    if (tangibleContainer && tangibleContainer.children.length === 0 && !document.getElementById('emptyTangibleMsg')) {
        tangibleContainer.innerHTML = '<div class="text-center text-gray-400 py-4" id="emptyTangibleMsg">No tangible items added. Click "Add Item" to add.</div>';
    }
}

// Function to update all totals in real-time
function updateModalTotals() {
    // Calculate activity total
    let activityTotal = 0;
    let activityCount = 0;
    document.querySelectorAll('#modalActivityList .actAmount').forEach(input => {
        const val = parseInt(input.value) || 0;
        activityTotal += val;
        if (val > 0) activityCount++;
    });
    
    // Calculate development total
    let developmentTotal = 0;
    let developmentCount = 0;
    document.querySelectorAll('#modalDevelopmentList .devAmount').forEach(input => {
        const val = parseInt(input.value) || 0;
        developmentTotal += val;
        if (val > 0) developmentCount++;
    });
    
    // Get tuition
    const tuition = parseInt(document.getElementById('modalFsTuition')?.value) || 0;
    
    // Calculate grand total
    const grandTotal = tuition + activityTotal + developmentTotal;
    
    // Update displays
    const activityTotalSpan = document.getElementById('modalActivityTotal');
    if (activityTotalSpan) activityTotalSpan.innerHTML = `UGX ${activityTotal.toLocaleString()}`;
    
    const developmentTotalSpan = document.getElementById('modalDevelopmentTotal');
    if (developmentTotalSpan) developmentTotalSpan.innerHTML = `UGX ${developmentTotal.toLocaleString()}`;
    
    const summaryTuition = document.getElementById('modalSummaryTuition');
    if (summaryTuition) summaryTuition.innerHTML = `UGX ${tuition.toLocaleString()}`;
    
    const summaryActivity = document.getElementById('modalSummaryActivity');
    if (summaryActivity) summaryActivity.innerHTML = `UGX ${activityTotal.toLocaleString()}`;
    
    const summaryDevelopment = document.getElementById('modalSummaryDevelopment');
    if (summaryDevelopment) summaryDevelopment.innerHTML = `UGX ${developmentTotal.toLocaleString()}`;
    
    const summaryTotal = document.getElementById('modalSummaryTotal');
    if (summaryTotal) summaryTotal.innerHTML = `UGX ${grandTotal.toLocaleString()}`;
    
    const activityCountSpan = document.getElementById('modalActivityCount');
    if (activityCountSpan) activityCountSpan.innerHTML = `(${activityCount} components)`;
    
    const developmentCountSpan = document.getElementById('modalDevelopmentCount');
    if (developmentCountSpan) developmentCountSpan.innerHTML = `(${developmentCount} components)`;
}

// Function to collect all components from the form
function collectModalComponents() {
    const activityComponents = [];
    const activityNames = document.querySelectorAll('#modalActivityList .actName');
    const activityAmounts = document.querySelectorAll('#modalActivityList .actAmount');
    
    for (let i = 0; i < activityNames.length; i++) {
        const name = activityNames[i].value.trim();
        const amount = parseInt(activityAmounts[i]?.value) || 0;
        if (name && amount > 0) {
            activityComponents.push({
                id: `act_${Date.now()}_${i}`,
                name: name,
                amount: amount
            });
        }
    }
    
    const developmentComponents = [];
    const devNames = document.querySelectorAll('#modalDevelopmentList .devName');
    const devAmounts = document.querySelectorAll('#modalDevelopmentList .devAmount');
    
    for (let i = 0; i < devNames.length; i++) {
        const name = devNames[i].value.trim();
        const amount = parseInt(devAmounts[i]?.value) || 0;
        if (name && amount > 0) {
            developmentComponents.push({
                id: `dev_${Date.now()}_${i}`,
                name: name,
                amount: amount
            });
        }
    }
    
    const tangibleRequirements = [];
    const tangibleNames = document.querySelectorAll('#modalTangibleList .tangibleName');
    
    for (let i = 0; i < tangibleNames.length; i++) {
        const name = tangibleNames[i].value.trim();
        if (name) {
            tangibleRequirements.push({
                id: `req_${Date.now()}_${i}`,
                name: name
            });
        }
    }
    
    return { activityComponents, developmentComponents, tangibleRequirements };
}

// Function to save fee structure
async function saveFeeStructureFromModal() {
    const name = document.getElementById('modalFsName').value.trim();
    const level = document.getElementById('modalFsLevel').value;
    const tuition = parseInt(document.getElementById('modalFsTuition').value) || 0;
    
    if (!name) {
        alert('Please enter a fee structure name');
        return;
    }
    
    const { activityComponents, developmentComponents, tangibleRequirements } = collectModalComponents();
    
    const activityTotal = activityComponents.reduce((s, c) => s + c.amount, 0);
    const developmentTotal = developmentComponents.reduce((s, c) => s + c.amount, 0);
    const total = tuition + activityTotal + developmentTotal;
    
    const feeStructureData = {
        name: name,
        level: level,
        tuition: tuition,
        activityComponents: activityComponents,
        developmentComponents: developmentComponents,
        tangibleRequirements: tangibleRequirements,
        isActive: true
    };
    
    console.log('Saving fee structure:', feeStructureData);
    
    const submitBtn = document.querySelector('#addFeeStructureModalForm button[type="submit"]');
    const originalText = submitBtn.innerText;
    submitBtn.innerText = 'Saving...';
    submitBtn.disabled = true;
    
    try {
        const response = await fetch('/api/fee/structures/enhanced', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(feeStructureData)
        });
        
        if (response.ok) {
            alert(`✅ Fee structure "${name}" saved successfully!\n\n📊 Summary:\n- Tuition: UGX ${tuition.toLocaleString()}\n- Activity (${activityComponents.length} items): UGX ${activityTotal.toLocaleString()}\n- Development (${developmentComponents.length} items): UGX ${developmentTotal.toLocaleString()}\n- TOTAL PER TERM: UGX ${total.toLocaleString()}`);
            closeModal();
            showFeeManagement();
        } else {
            const error = await response.json();
            alert('❌ Error saving fee structure: ' + (error.error || 'Unknown error'));
        }
    } catch (error) {
        console.error('Error:', error);
        alert('Network error: ' + error.message);
    } finally {
        submitBtn.innerText = originalText;
        submitBtn.disabled = false;
    }
}

