// ==================== UTILITY FUNCTIONS ====================

function closeSubModal() {
    const modals = document.querySelectorAll('[class*="z-6"], [class*="z-7"]');
    if (modals.length > 0) modals[modals.length - 1].remove();
    else { const modal = document.querySelector('.fixed.inset-0.bg-black.bg-opacity-50'); if (modal && modal !== document.querySelector('.z-50')) modal.remove(); }
}

function closeModal() {
    const modal = document.querySelector('.fixed.inset-0.bg-black.bg-opacity-50.z-50');
    if (modal) modal.remove();
}

function escapeHtml(text) {
    if (!text) return '';
    const div = document.createElement('div');
    div.textContent = text;
    return div.innerHTML;
}

// ==================== UPDATE SUMMARY TOTALS ====================

function updateSummaryTotals() {
    const tuition = parseInt(document.getElementById('modalFsTuition')?.value) || 0;
    
    let oneTimeTotal = 0;
    let termlyTotal = 0;
    let yearlyTotal = 0;
    
    if (window.activityGroupsData && window.activityGroupsData.length > 0) {
        for (const group of window.activityGroupsData) {
            if (group.periodType === 'one_time') oneTimeTotal += group.totalAmount;
            else if (group.periodType === 'termly') termlyTotal += group.totalAmount;
            else if (group.periodType === 'yearly') yearlyTotal += group.totalAmount;
        }
    }
    
    const total = tuition + oneTimeTotal + termlyTotal + yearlyTotal;
    
    const summaryTuition = document.getElementById('summaryTuition');
    const summaryOneTime = document.getElementById('summaryOneTime');
    const summaryTermly = document.getElementById('summaryTermly');
    const summaryYearly = document.getElementById('summaryYearly');
    const summaryTotal = document.getElementById('summaryTotal');
    
    if (summaryTuition) summaryTuition.innerHTML = `UGX ${tuition.toLocaleString()}`;
    if (summaryOneTime) summaryOneTime.innerHTML = `UGX ${oneTimeTotal.toLocaleString()}`;
    if (summaryTermly) summaryTermly.innerHTML = `UGX ${termlyTotal.toLocaleString()}`;
    if (summaryYearly) summaryYearly.innerHTML = `UGX ${yearlyTotal.toLocaleString()}`;
    if (summaryTotal) summaryTotal.innerHTML = `UGX ${total.toLocaleString()}`;
}

