// ==================== SHOW ADD ITEM MODAL ====================

function showAddItemModal() {
    const modalHtml = `
        <div class="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-[70]">
            <div class="bg-white rounded-2xl p-6 max-w-md w-full mx-4">
                <div class="flex justify-between items-center mb-4 pb-2 border-b">
                    <h4 class="text-lg font-bold">Add Item to Group</h4>
                    <button onclick="closeAddItemModal()" class="text-gray-500 hover:text-gray-700">&times;</button>
                </div>
                
                <div class="space-y-4">
                    <div>
                        <label class="block text-sm font-medium mb-1 required-field">Item Name *</label>
                        <input type="text" id="itemName" class="w-full border rounded-lg px-3 py-2">
                    </div>
                    
                    <div>
                        <label class="block text-sm font-medium mb-1 required-field">Payment Option *</label>
                        <div class="space-y-2">
                            <label class="flex items-start p-3 border rounded-lg cursor-pointer">
                                <input type="radio" name="paymentOption" value="cash_only" class="mr-3 mt-1">
                                <div><div class="font-medium">💵 Cash Only</div><div class="text-xs text-gray-500">Must be paid in cash</div></div>
                            </label>
                            <label class="flex items-start p-3 border rounded-lg cursor-pointer">
                                <input type="radio" name="paymentOption" value="item_only" class="mr-3 mt-1">
                                <div><div class="font-medium">📦 Item Only</div><div class="text-xs text-gray-500">Must be brought physically</div></div>
                            </label>
                            <label class="flex items-start p-3 border rounded-lg cursor-pointer">
                                <input type="radio" name="paymentOption" value="either" class="mr-3 mt-1" checked>
                                <div><div class="font-medium">🔄 Either (Cash or Item)</div><div class="text-xs text-gray-500">Can be paid cash OR bring items</div></div>
                            </label>
                        </div>
                    </div>
                    
                    <div id="addItemDynamicFields">
                        <div class="grid grid-cols-2 gap-3">
                            <div>
                                <label class="block text-sm font-medium mb-1">Cash Amount (UGX)</label>
                                <input type="number" id="itemCashAmount" class="w-full border rounded-lg px-3 py-2" value="0" min="0">
                            </div>
                            <div>
                                <label class="block text-sm font-medium mb-1">Quantity to Bring</label>
                                <input type="number" id="itemQuantity" class="w-full border rounded-lg px-3 py-2" value="0" min="0">
                            </div>
                        </div>
                        <div class="bg-yellow-50 p-2 rounded text-xs text-yellow-700 mt-2">Enter either cash amount, quantity, or both</div>
                    </div>
                    
                    <div class="flex gap-3 pt-2">
                        <button type="button" id="confirmAddItem" class="flex-1 bg-blue-600 text-white py-2 rounded-lg">Add Item</button>
                        <button type="button" onclick="closeAddItemModal()" class="flex-1 bg-gray-300 text-gray-700 py-2 rounded-lg">Cancel</button>
                    </div>
                </div>
            </div>
        </div>
    `;
    
    document.body.insertAdjacentHTML('beforeend', modalHtml);
    
    // Handle payment option changes
    const radioButtons = document.querySelectorAll('input[name="paymentOption"]');
    radioButtons.forEach(radio => {
        radio.addEventListener('change', (e) => {
            const container = document.getElementById('addItemDynamicFields');
            if (e.target.value === 'cash_only') {
                container.innerHTML = `<input type="number" id="itemCashAmount" class="w-full border rounded-lg px-3 py-2" placeholder="Amount (UGX)" value="0" min="0">`;
            } else if (e.target.value === 'item_only') {
                container.innerHTML = `<input type="number" id="itemQuantity" class="w-full border rounded-lg px-3 py-2" placeholder="Quantity" value="1" min="1">`;
            } else {
                container.innerHTML = `
                    <div class="grid grid-cols-2 gap-3">
                        <div><label class="block text-sm font-medium mb-1">Cash Amount (UGX)</label><input type="number" id="itemCashAmount" class="w-full border rounded-lg px-3 py-2" value="0" min="0"></div>
                        <div><label class="block text-sm font-medium mb-1">Quantity to Bring</label><input type="number" id="itemQuantity" class="w-full border rounded-lg px-3 py-2" value="0" min="0"></div>
                    </div>
                    <div class="bg-yellow-50 p-2 rounded text-xs text-yellow-700 mt-2">Enter either cash amount, quantity, or both</div>
                `;
            }
        });
    });
    
    document.getElementById('confirmAddItem').addEventListener('click', () => {
        const itemName = document.getElementById('itemName').value.trim();
        const paymentOption = document.querySelector('input[name="paymentOption"]:checked')?.value || 'either';
        
        if (!itemName) {
            alert('Please enter an item name');
            return;
        }
        
        let quantity = 0;
        let cashAmount = 0;
        
        if (paymentOption === 'cash_only') {
            cashAmount = parseInt(document.getElementById('itemCashAmount')?.value) || 0;
            if (cashAmount <= 0) {
                alert('Please enter a valid cash amount');
                return;
            }
            quantity = 1;
        } else if (paymentOption === 'item_only') {
            quantity = parseInt(document.getElementById('itemQuantity')?.value) || 0;
            if (quantity <= 0) {
                alert('Please enter a valid quantity');
                return;
            }
            cashAmount = 0;
        } else {
            cashAmount = parseInt(document.getElementById('itemCashAmount')?.value) || 0;
            quantity = parseInt(document.getElementById('itemQuantity')?.value) || 0;
            if (cashAmount <= 0 && quantity <= 0) {
                alert('Please enter either cash amount, quantity, or both');
                return;
            }
        }
        
        const newItem = {
            id: `item_${Date.now()}_${Math.random().toString(36).substr(2, 6)}`,
            name: itemName,
            quantity: quantity,
            cashAmount: cashAmount,
            totalAmount: cashAmount,
            paymentOption: paymentOption
        };
        
        window.tempGroupItems.push(newItem);
        closeAddItemModal();
        renderCurrentGroupItems();
    });
}



// ==================== RENDER CURRENT GROUP ITEMS ====================

function renderCurrentGroupItems() {
    const container = document.getElementById('currentGroupItemsContainer');
    if (!container) return;
    
    if (!window.tempGroupItems || window.tempGroupItems.length === 0) {
        container.innerHTML = '<div class="text-center text-gray-400 py-4">No items added. Click "Add Item" to add.</div>';
        return;
    }
    
    container.innerHTML = window.tempGroupItems.map((item, index) => {
        let details = '';
        if (item.paymentOption === 'cash_only') {
            details = `💵 UGX ${item.cashAmount.toLocaleString()}`;
        } else if (item.paymentOption === 'item_only') {
            details = `📦 ${item.quantity} item(s)`;
        } else {
            const parts = [];
            if (item.cashAmount > 0) parts.push(`💵 UGX ${item.cashAmount.toLocaleString()}`);
            if (item.quantity > 0) parts.push(`📦 ${item.quantity} item(s)`);
            details = parts.join(' + ');
        }
        
        return `
            <div class="bg-white rounded-lg p-3 border flex justify-between items-center">
                <div>
                    <p class="font-medium">📦 ${escapeHtml(item.name)}</p>
                    <p class="text-sm text-green-600">${details}</p>
                </div>
                <button type="button" onclick="removeTempItem(${index})" class="text-red-600 hover:text-red-800">Remove</button>
            </div>
        `;
    }).join('');
}

function removeTempItem(index) {
    window.tempGroupItems.splice(index, 1);
    renderCurrentGroupItems();
}

// ==================== SAVE ACTIVITY GROUP ====================

function saveActivityGroup() {
    const groupName = document.getElementById('groupName').value.trim();
    const periodType = document.getElementById('groupPeriodType').value;
    const statusGroupId = document.getElementById('groupStatusGroupId').value || null;
    
    if (!groupName) {
        alert('Please enter a group name');
        return;
    }
    
    if (!window.tempGroupItems || window.tempGroupItems.length === 0) {
        alert('Please add at least one item to the group');
        return;
    }
    
    let statusGroupInfo = null;
    if (statusGroupId && window.existingStatusGroups) {
        statusGroupInfo = window.existingStatusGroups.find(g => g.id === statusGroupId);
    }
    
    let totalCashAmount = 0;
    for (const item of window.tempGroupItems) {
        if (item.paymentOption === 'cash_only') {
            totalCashAmount += item.cashAmount;
        } else if (item.paymentOption === 'either') {
            totalCashAmount += item.cashAmount;
        }
    }
    
    const newGroup = {
        id: `group_${Date.now()}_${Math.random().toString(36).substr(2, 6)}`,
        name: groupName,
        periodType: periodType,
        statusGroupId: statusGroupId,
        statusGroupName: statusGroupInfo?.name || null,
        items: [...window.tempGroupItems],
        totalAmount: totalCashAmount,
        createdAt: new Date().toISOString()
    };
    
    if (!window.activityGroupsData) window.activityGroupsData = [];
    window.activityGroupsData.push(newGroup);
    
    window.tempGroupItems = [];
    
    closeSubModal();
    renderActivityGroupsList();
    updateSummaryTotals();
}

// ==================== RENDER ACTIVITY GROUPS LIST ====================

function renderActivityGroupsList() {
    const container = document.getElementById('activityGroupsContainer');
    if (!container) return;
    
    if (!window.activityGroupsData || window.activityGroupsData.length === 0) {
        container.innerHTML = '<div class="text-center text-gray-400 py-8">No activity groups added yet. Click "Add Activity Group" to create one.</div>';
        return;
    }
    
    const oneTimeGroups = window.activityGroupsData.filter(g => g.periodType === 'one_time');
    const termlyGroups = window.activityGroupsData.filter(g => g.periodType === 'termly');
    const yearlyGroups = window.activityGroupsData.filter(g => g.periodType === 'yearly');
    
    function renderGroupSection(groups, title, icon, bgColor, borderColor, textColor) {
        if (groups.length === 0) return '';
        
        return `
            <div class="mb-4">
                <h4 class="font-bold text-lg mb-2">${icon} ${title}</h4>
                <div class="space-y-3">
                    ${groups.map(group => `
                        <div class="border-2 ${borderColor} rounded-lg p-4 ${bgColor}">
                            <div class="flex justify-between items-start mb-3">
                                <div>
                                    <h5 class="font-bold text-md">${escapeHtml(group.name)}</h5>
                                    ${group.statusGroupName ? `<p class="text-xs text-gray-500 mt-1">🏷️ Status: ${escapeHtml(group.statusGroupName)}</p>` : ''}
                                </div>
                                <div class="flex gap-2">
                                    <button type="button" onclick="editActivityGroup('${group.id}')" class="bg-blue-500 text-white px-3 py-1 rounded text-sm">Edit</button>
                                    <button type="button" onclick="deleteActivityGroup('${group.id}')" class="bg-red-500 text-white px-3 py-1 rounded text-sm">Delete</button>
                                </div>
                            </div>
                            <div class="space-y-2">
                                ${group.items.map(item => {
                                    let details = '';
                                    if (item.paymentOption === 'cash_only') {
                                        details = `UGX ${item.cashAmount.toLocaleString()}`;
                                    } else if (item.paymentOption === 'item_only') {
                                        details = `${item.quantity} item(s)`;
                                    } else {
                                        const parts = [];
                                        if (item.cashAmount > 0) parts.push(`UGX ${item.cashAmount.toLocaleString()}`);
                                        if (item.quantity > 0) parts.push(`${item.quantity} item(s)`);
                                        details = parts.join(' + ');
                                    }
                                    return `<div class="bg-white rounded p-2">📦 ${escapeHtml(item.name)}: <span class="font-semibold">${details}</span></div>`;
                                }).join('')}
                            </div>
                            <div class="mt-3 pt-2 border-t ${borderColor} flex justify-between font-semibold">
                                <span>Group Total:</span>
                                <span class="${textColor}">UGX ${group.totalAmount.toLocaleString()}</span>
                            </div>
                        </div>
                    `).join('')}
                </div>
            </div>
        `;
    }
    
    container.innerHTML = `
        ${renderGroupSection(oneTimeGroups, 'One-Time Activities', '⭐', 'bg-purple-50', 'border-purple-300', 'text-purple-600')}
        ${renderGroupSection(termlyGroups, 'Termly Activities', '📅', 'bg-green-50', 'border-green-300', 'text-green-600')}
        ${renderGroupSection(yearlyGroups, 'Yearly Activities', '📆', 'bg-orange-50', 'border-orange-300', 'text-orange-600')}
    `;
}

