// ==================== RENDER EDIT GROUP ITEMS WITH EDIT BUTTON ====================

function renderEditGroupItems() {
    if (!window.tempGroupItems || window.tempGroupItems.length === 0) {
        return '<div class="text-center text-gray-400 py-4">No items added. Click "Add Item" to add.</div>';
    }
    
    return window.tempGroupItems.map((item, idx) => {
        let detailsDisplay = '';
        let paymentOptionLabel = '';
        
        if (item.paymentOption === 'cash_only') {
            paymentOptionLabel = '<span class="bg-blue-100 text-blue-800 text-xs px-1.5 py-0.5 rounded-full">💵 Cash</span>';
            detailsDisplay = `UGX ${(item.cashAmount || item.totalAmount || 0).toLocaleString()}`;
        } else if (item.paymentOption === 'item_only') {
            paymentOptionLabel = '<span class="bg-green-100 text-green-800 text-xs px-1.5 py-0.5 rounded-full">📦 Item</span>';
            detailsDisplay = `${item.quantity} item(s)`;
        } else {
            paymentOptionLabel = '<span class="bg-purple-100 text-purple-800 text-xs px-1.5 py-0.5 rounded-full">🔄 Cash/Item</span>';
            const parts = [];
            if (item.cashAmount > 0) parts.push(`UGX ${item.cashAmount.toLocaleString()}`);
            if (item.quantity > 0) parts.push(`${item.quantity} item(s)`);
            detailsDisplay = parts.join(' + ');
        }
        
        return `
            <div class="bg-white rounded-lg p-3 border flex justify-between items-center hover:bg-gray-50 transition" data-item-index="${idx}">
                <div class="flex-1">
                    <div class="flex items-center gap-2 flex-wrap">
                        <p class="font-medium">📦 ${escapeHtml(item.name)}</p>
                        ${paymentOptionLabel}
                    </div>
                    <p class="text-sm text-green-600">${detailsDisplay}</p>
                    <p class="text-xs text-gray-400">Total Amount: UGX ${(item.totalAmount || 0).toLocaleString()}</p>
                </div>
                <div class="flex gap-2">
                    <button onclick="editEditTempItem(${idx})" class="text-blue-600 hover:text-blue-800 text-sm p-1 rounded hover:bg-blue-50 transition" title="Edit Item">
                        <i class="fas fa-edit"></i> Edit
                    </button>
                    <button onclick="removeEditTempItem(${idx})" class="text-red-600 hover:text-red-800 text-sm p-1 rounded hover:bg-red-50 transition" title="Remove Item">
                        <i class="fas fa-times"></i> Remove
                    </button>
                </div>
            </div>
        `;
    }).join('');
}

// ==================== EDIT TEMP ITEM ====================

function editEditTempItem(index) {
    console.log('editEditTempItem called for index:', index);
    
    const item = window.tempGroupItems[index];
    if (!item) {
        alert('Item not found');
        return;
    }
    
    const paymentOptions = [
        { value: 'cash_only', label: '💵 Cash Only', description: 'Must be paid in cash' },
        { value: 'item_only', label: '📦 Item Only', description: 'Must be brought physically' },
        { value: 'either', label: '🔄 Either (Cash or Item)', description: 'Can be paid cash OR bring items' }
    ];
    
    // Store the index being edited
    window.editingItemIndex = index;
    
    const modalHtml = `
        <div class="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-[201]">
            <div class="bg-white rounded-2xl p-6 max-w-md w-full mx-4">
                <div class="flex justify-between items-center mb-4 pb-2 border-b">
                    <h4 class="text-lg font-bold">✏️ Edit Item</h4>
                    <button onclick="closeEditItemModal()" class="text-gray-500 hover:text-gray-700 text-2xl">&times;</button>
                </div>
                
                <form id="editItemForm" class="space-y-4" onsubmit="return false;">
                    <div>
                        <label class="block text-sm font-medium mb-1 required-field">Item Name *</label>
                        <input type="text" id="editItemName" value="${escapeHtml(item.name)}" class="w-full border rounded-lg px-3 py-2">
                    </div>
                    
                    <div>
                        <label class="block text-sm font-medium mb-1 required-field">Payment Option *</label>
                        <div class="space-y-2">
                            ${paymentOptions.map(opt => `
                                <label class="flex items-start p-3 border rounded-lg cursor-pointer hover:bg-gray-50">
                                    <input type="radio" name="editPaymentOption" value="${opt.value}" class="mr-3 mt-1" ${item.paymentOption === opt.value ? 'checked' : ''}>
                                    <div>
                                        <div class="font-medium">${opt.label}</div>
                                        <div class="text-xs text-gray-500">${opt.description}</div>
                                    </div>
                                </label>
                            `).join('')}
                        </div>
                    </div>
                    
                    <div id="editItemDynamicFields" class="space-y-4">
                        <div class="grid grid-cols-2 gap-3">
                            <div>
                                <label class="block text-sm font-medium mb-1">Cash Amount (UGX)</label>
                                <input type="number" id="editItemCashAmount" class="w-full border rounded-lg px-3 py-2" value="${item.cashAmount || 0}" min="0" step="1">
                                <p class="text-xs text-gray-400 mt-1">Enter any amount</p>
                            </div>
                            <div>
                                <label class="block text-sm font-medium mb-1">Quantity to Bring</label>
                                <input type="number" id="editItemQuantity" class="w-full border rounded-lg px-3 py-2" value="${item.quantity || 0}" min="0" step="1">
                            </div>
                        </div>
                        <div class="bg-yellow-50 p-2 rounded text-xs text-yellow-700">Enter either cash amount, quantity, or both</div>
                    </div>
                    
                    <div class="flex gap-3 pt-2">
                        <button type="submit" id="confirmEditItem" class="flex-1 bg-blue-600 text-white py-2 rounded-lg">Save Changes</button>
                        <button type="button" onclick="closeEditItemModal()" class="flex-1 bg-gray-300 text-gray-700 py-2 rounded-lg">Cancel</button>
                    </div>
                </form>
            </div>
        </div>
    `;
    
    document.body.insertAdjacentHTML('beforeend', modalHtml);
    
    // Handle payment option changes
    const radioButtons = document.querySelectorAll('input[name="editPaymentOption"]');
    radioButtons.forEach(radio => {
        radio.addEventListener('change', (e) => {
            const container = document.getElementById('editItemDynamicFields');
            if (e.target.value === 'cash_only') {
                container.innerHTML = `
                    <div>
                        <label class="block text-sm font-medium mb-1 required-field">Amount (UGX) *</label>
                        <input type="number" id="editItemCashAmount" class="w-full border rounded-lg px-3 py-2" value="${item.cashAmount || 0}" min="0" step="1">
                        <p class="text-xs text-gray-400 mt-1">Enter any amount</p>
                    </div>
                `;
            } else if (e.target.value === 'item_only') {
                container.innerHTML = `
                    <div>
                        <label class="block text-sm font-medium mb-1 required-field">Quantity to Bring *</label>
                        <input type="number" id="editItemQuantity" class="w-full border rounded-lg px-3 py-2" value="${item.quantity || 0}" min="1" step="1">
                    </div>
                `;
            } else {
                container.innerHTML = `
                    <div class="grid grid-cols-2 gap-3">
                        <div>
                            <label class="block text-sm font-medium mb-1">Cash Amount (UGX)</label>
                            <input type="number" id="editItemCashAmount" class="w-full border rounded-lg px-3 py-2" value="${item.cashAmount || 0}" min="0" step="1">
                            <p class="text-xs text-gray-400 mt-1">Enter any amount</p>
                        </div>
                        <div>
                            <label class="block text-sm font-medium mb-1">Quantity to Bring</label>
                            <input type="number" id="editItemQuantity" class="w-full border rounded-lg px-3 py-2" value="${item.quantity || 0}" min="0" step="1">
                        </div>
                    </div>
                    <div class="bg-yellow-50 p-2 rounded text-xs text-yellow-700">Enter either cash amount, quantity, or both</div>
                `;
            }
        });
    });
    
    document.getElementById('confirmEditItem').addEventListener('click', () => {
        const itemName = document.getElementById('editItemName').value.trim();
        const paymentOption = document.querySelector('input[name="editPaymentOption"]:checked')?.value || 'either';
        
        if (!itemName) {
            alert('Please enter an item name');
            return;
        }
        
        let quantity = 0;
        let cashAmount = 0;
        
        if (paymentOption === 'cash_only') {
            cashAmount = parseFloat(document.getElementById('editItemCashAmount')?.value) || 0;
            if (cashAmount <= 0) {
                alert('Please enter a valid cash amount');
                return;
            }
            quantity = 1;
        } else if (paymentOption === 'item_only') {
            quantity = parseInt(document.getElementById('editItemQuantity')?.value) || 0;
            if (quantity <= 0) {
                alert('Please enter a valid quantity');
                return;
            }
            cashAmount = 0;
        } else {
            cashAmount = parseFloat(document.getElementById('editItemCashAmount')?.value) || 0;
            quantity = parseInt(document.getElementById('editItemQuantity')?.value) || 0;
            if (cashAmount <= 0 && quantity <= 0) {
                alert('Please enter either cash amount, quantity, or both');
                return;
            }
        }
        
        // Update the item
        const updatedItem = {
            ...item,
            name: itemName,
            quantity: quantity,
            cashAmount: cashAmount,
            totalAmount: cashAmount,
            paymentOption: paymentOption,
            isTangible: paymentOption !== 'cash_only'
        };
        
        window.tempGroupItems[window.editingItemIndex] = updatedItem;
        window.editingItemIndex = null;
        
        closeEditItemModal();
        
        // Re-render the items list
        const container = document.getElementById('editGroupItemsContainer');
        if (container) {
            container.innerHTML = renderEditGroupItems();
        }
        
        showToast('✅ Item updated successfully!', 'success');
    });
}

