// ==================== REMOVE EDIT TEMP ITEM (UPDATED) ====================

function removeEditTempItem(index) {
    console.log('removeEditTempItem called for index:', index);
    
    if (!window.tempGroupItems || index >= window.tempGroupItems.length) {
        console.error('Invalid index or tempGroupItems not found');
        return;
    }
    
    const itemName = window.tempGroupItems[index]?.name || 'Item';
    
    if (!confirm(`⚠️ Remove "${itemName}" from this group?`)) {
        return;
    }
    
    // Remove the item
    window.tempGroupItems.splice(index, 1);
    console.log('Remaining items:', window.tempGroupItems.length);
    
    // Update the display
    const container = document.getElementById('editGroupItemsContainer');
    if (container) {
        container.innerHTML = renderEditGroupItems();
    }
    
    showToast(`✅ "${itemName}" removed`, 'info');
}

// ==================== SHOW TOAST ====================

function showToast(message, type = 'success') {
    const toast = document.createElement('div');
    const bgColor = type === 'success' ? 'bg-green-500' : type === 'error' ? 'bg-red-500' : type === 'info' ? 'bg-blue-500' : 'bg-gray-700';
    toast.className = `fixed bottom-4 right-4 ${bgColor} text-white px-4 py-2 rounded-lg shadow-lg z-50 transition-opacity duration-300`;
    toast.innerHTML = message;
    document.body.appendChild(toast);
    setTimeout(() => {
        toast.style.opacity = '0';
        setTimeout(() => toast.remove(), 300);
    }, 3000);
}



function updateActivityGroup() {
    const groupName = document.getElementById('editGroupName').value.trim();
    const periodType = document.getElementById('editGroupPeriodType').value;
    const statusGroupId = document.getElementById('editGroupStatusGroupId').value || null;
    if (!groupName) { alert('Enter group name'); return; }
    if (window.tempGroupItems.length === 0) { alert('Add at least one item'); return; }
    
    let statusGroupInfo = null;
    if (statusGroupId && window.existingStatusGroups) statusGroupInfo = window.existingStatusGroups.find(g => g.id === statusGroupId);
    
    let totalCashAmount = 0;
    for (const item of window.tempGroupItems) {
        if (item.paymentOption === 'cash_only' || item.paymentOption === 'either') totalCashAmount += item.cashAmount;
    }
    
    const groupIndex = window.activityGroupsData.findIndex(g => g.id === window.editGroupId);
    if (groupIndex !== -1) {
        window.activityGroupsData[groupIndex] = { ...window.activityGroupsData[groupIndex], name: groupName, periodType, statusGroupId, statusGroupName: statusGroupInfo?.name || null, items: [...window.tempGroupItems], totalAmount: totalCashAmount, updatedAt: new Date().toISOString() };
    }
    
    window.tempGroupItems = [];
    window.editGroupId = null;
    closeSubModal();
    renderActivityGroupsList();
    updateSummaryTotals();
    alert('✅ Activity group updated!');
}

// ==================== DELETE ACTIVITY GROUP ====================

function deleteActivityGroup(groupId) {
    if (!confirm('Are you sure you want to delete this activity group?')) return;
    const groupIndex = window.activityGroupsData.findIndex(g => g.id === groupId);
    if (groupIndex !== -1) {
        const groupName = window.activityGroupsData[groupIndex].name;
        window.activityGroupsData.splice(groupIndex, 1);
        renderActivityGroupsList();
        updateSummaryTotals();
        alert(`✅ "${groupName}" deleted!`);
    }
}

