// ==================== UTILITY FUNCTIONS ====================

function closeSubModal() {
    const modals = document.querySelectorAll('[class*="z-6"], [class*="z-7"]');
    if (modals.length > 0) modals[modals.length - 1].remove();
    else { const modal = document.querySelector('.fixed.inset-0.bg-black.bg-opacity-50'); if (modal && modal !== document.querySelector('.z-50')) modal.remove(); }
}

function closeModal() {
    const modal = document.querySelector('.fixed.inset-0.bg-black.bg-opacity-50.z-50');
    if (modal) modal.remove();
}

function escapeHtml(text) {
    if (!text) return '';
    const div = document.createElement('div');
    div.textContent = text;
    return div.innerHTML;
}

// ==================== UPDATE SUMMARY TOTALS ====================

function updateSummaryTotals() {
    const tuition = parseInt(document.getElementById('modalFsTuition')?.value) || 0;
    
    const statusGroupTotals = {};
    
    if (window.activityGroupsData && window.activityGroupsData.length > 0) {
        for (const group of window.activityGroupsData) {
            const statusName = group.statusGroupName || 'Ungrouped Items';
            if (!statusGroupTotals[statusName]) {
                statusGroupTotals[statusName] = 0;
            }
            statusGroupTotals[statusName] += group.totalAmount || 0;
        }
    }
    
    // Render status group summary
    const summaryContainer = document.getElementById('statusGroupsSummaryContainer');
    if (summaryContainer) {
        if (Object.keys(statusGroupTotals).length === 0 && tuition === 0) {
            summaryContainer.innerHTML = '<div class="text-center text-gray-500 py-4"><i class="fas fa-tags text-3xl mb-2"></i><p>No status groups added yet.</p></div>';
        } else {
            const summaryHtml = [];
            for (const [statusName, total] of Object.entries(statusGroupTotals)) {
                summaryHtml.push(`
                    <div class="bg-white rounded-lg p-3 border shadow-sm">
                        <div class="flex justify-between items-center">
                            <span class="font-bold">🏷️ ${escapeHtml(statusName)}</span>
                            <span class="text-xl font-bold text-green-600">UGX ${total.toLocaleString()}</span>
                        </div>
                    </div>
                `);
            }
            summaryContainer.innerHTML = summaryHtml.join('');
        }
    }
    
    const summaryTuitionAmount = document.getElementById('summaryTuitionAmount');
    if (summaryTuitionAmount) summaryTuitionAmount.innerHTML = `UGX ${tuition.toLocaleString()}`;
    
    const grandTotal = tuition + Object.values(statusGroupTotals).reduce((sum, val) => sum + val, 0);
    const summaryGrandTotal = document.getElementById('summaryGrandTotal');
    if (summaryGrandTotal) summaryGrandTotal.innerHTML = `UGX ${grandTotal.toLocaleString()}`;
}

