// ==================== CLOSE FUNCTIONS ====================

function closeSubModal() {
    const modals = document.querySelectorAll('[class*="z-6"], [class*="z-7"]');
    if (modals.length > 0) {
        const lastModal = modals[modals.length - 1];
        lastModal.remove();
    } else {
        const modal = document.querySelector('.fixed.inset-0.bg-black.bg-opacity-50');
        if (modal && modal !== document.querySelector('.z-50')) modal.remove();
    }
}

function closeModal() {
    const modal = document.querySelector('.fixed.inset-0.bg-black.bg-opacity-50.z-50');
    if (modal) modal.remove();
}

function escapeHtml(text) {
    if (!text) return '';
    const div = document.createElement('div');
    div.textContent = text;
    return div.innerHTML;
}

// ==================== UPDATE SUMMARY TOTALS BY STATUS GROUP ====================

function updateSummaryTotals() {
    const tuition = parseInt(document.getElementById('modalFsTuition')?.value) || 0;
    
    // Group items by status group
    const statusGroupTotals = {};
    const statusGroupDetails = {};
    
    if (window.activityGroupsData && window.activityGroupsData.length > 0) {
        for (const group of window.activityGroupsData) {
            const statusGroupId = group.statusGroupId || 'ungrouped';
            const statusGroupName = group.statusGroupName || 'Ungrouped Items';
            
            if (!statusGroupTotals[statusGroupId]) {
                statusGroupTotals[statusGroupId] = 0;
                statusGroupDetails[statusGroupId] = {
                    name: statusGroupName,
                    items: [],
                    periodTypes: new Set(),
                    totalCash: 0,
                    totalItems: 0
                };
            }
            
            // Calculate total for this group's items
            for (const item of group.items) {
                let itemValue = 0;
                if (item.paymentOption === 'cash_only') {
                    itemValue = item.cashAmount || item.totalAmount || 0;
                    statusGroupDetails[statusGroupId].totalCash += itemValue;
                } else if (item.paymentOption === 'item_only') {
                    itemValue = 0;
                    statusGroupDetails[statusGroupId].totalItems += item.quantity || 0;
                } else { // either
                    const cashPart = item.cashAmount || 0;
                    const itemPart = item.quantity || 0;
                    itemValue = cashPart;
                    statusGroupDetails[statusGroupId].totalCash += cashPart;
                    statusGroupDetails[statusGroupId].totalItems += itemPart;
                }
                
                statusGroupTotals[statusGroupId] += itemValue;
                statusGroupDetails[statusGroupId].items.push({
                    name: item.name,
                    groupName: group.name,
                    periodType: group.periodType,
                    paymentOption: item.paymentOption,
                    cashAmount: item.cashAmount,
                    quantity: item.quantity,
                    value: itemValue
                });
                statusGroupDetails[statusGroupId].periodTypes.add(group.periodType);
            }
        }
    }
    
    // Render status group summary cards
    const summaryContainer = document.getElementById('statusGroupsSummaryContainer');
    if (summaryContainer) {
        if (Object.keys(statusGroupTotals).length === 0 && tuition === 0) {
            summaryContainer.innerHTML = '<div class="text-center text-gray-500 py-4"><i class="fas fa-tags text-3xl mb-2"></i><p>No status groups added yet. Add items with status groups to see summary.</p></div>';
        } else {
            const summaryHtml = [];
            
            for (const [groupId, total] of Object.entries(statusGroupTotals)) {
                const details = statusGroupDetails[groupId];
                const periodTypesArray = Array.from(details.periodTypes);
                let periodBadges = '';
                if (periodTypesArray.includes('one_time')) periodBadges += '<span class="bg-purple-100 text-purple-800 text-xs px-2 py-0.5 rounded-full">⭐ One-Time</span> ';
                if (periodTypesArray.includes('termly')) periodBadges += '<span class="bg-green-100 text-green-800 text-xs px-2 py-0.5 rounded-full">📅 Termly</span> ';
                if (periodTypesArray.includes('yearly')) periodBadges += '<span class="bg-orange-100 text-orange-800 text-xs px-2 py-0.5 rounded-full">📆 Yearly</span> ';
                
                summaryHtml.push(`
                    <div class="bg-white rounded-lg p-4 border shadow-sm">
                        <div class="flex justify-between items-start mb-3">
                            <div>
                                <h4 class="font-bold text-lg flex items-center gap-2">
                                    <i class="fas fa-tag text-purple-600"></i>
                                    ${escapeHtml(details.name)}
                                </h4>
                                <div class="flex flex-wrap gap-1 mt-1">${periodBadges}</div>
                            </div>
                            <div class="text-right">
                                <p class="text-2xl font-bold text-green-600">UGX ${total.toLocaleString()}</p>
                                ${details.totalItems > 0 ? `<p class="text-xs text-gray-500">+ ${details.totalItems} physical item(s)</p>` : ''}
                            </div>
                        </div>
                        <div class="text-sm text-gray-600 border-t pt-2 mt-2">
                            <div class="flex justify-between">
                                <span>Cash Component:</span>
                                <span class="font-semibold">UGX ${details.totalCash.toLocaleString()}</span>
                            </div>
                            ${details.totalItems > 0 ? `
                                <div class="flex justify-between">
                                    <span>Items Component:</span>
                                    <span class="font-semibold">${details.totalItems} item(s)</span>
                                </div>
                            ` : ''}
                        </div>
                        <div class="mt-2 text-xs text-gray-400">
                            ${details.items.length} item(s) from ${new Set(details.items.map(i => i.groupName)).size} activity group(s)
                        </div>
                    </div>
                `);
            }
            
            summaryContainer.innerHTML = summaryHtml.join('');
        }
    }
    
    // Update tuition display
    const summaryTuitionAmount = document.getElementById('summaryTuitionAmount');
    if (summaryTuitionAmount) summaryTuitionAmount.innerHTML = `UGX ${tuition.toLocaleString()}`;
    
    // Calculate grand total
    const grandTotal = tuition + Object.values(statusGroupTotals).reduce((sum, val) => sum + val, 0);
    const summaryGrandTotal = document.getElementById('summaryGrandTotal');
    if (summaryGrandTotal) summaryGrandTotal.innerHTML = `UGX ${grandTotal.toLocaleString()}`;
}

