// ==================== DELETE ACTIVITY GROUP ====================

function deleteActivityGroup(groupId) {
    console.log('deleteActivityGroup called for groupId:', groupId);
    
    // Show confirmation dialog
    if (!confirm('Are you sure you want to delete this activity group? This action cannot be undone.')) {
        return;
    }
    
    // Find the group to delete
    const groupIndex = window.activityGroupsData.findIndex(g => g.id === groupId);
    
    if (groupIndex === -1) {
        console.error('Group not found:', groupId);
        alert('Group not found');
        return;
    }
    
    const groupName = window.activityGroupsData[groupIndex].name;
    console.log('Deleting group:', groupName);
    
    // Remove the group from the array
    window.activityGroupsData.splice(groupIndex, 1);
    
    console.log('Remaining groups:', window.activityGroupsData.length);
    
    // Re-render the activity groups list
    renderActivityGroupsList();
    
    // Update the summary totals
    updateSummaryTotals();
    
    // Show success message
    alert(`✅ Activity group "${groupName}" deleted successfully!`);
}

// ==================== EDIT ACTIVITY GROUP ====================





function updateActivityGroupInTemp() {
    const groupName = document.getElementById('editGroupName').value.trim();
    const periodType = document.getElementById('editGroupPeriodType').value;
    const statusGroupId = document.getElementById('editGroupStatusGroupId').value || null;
    
    if (!groupName) {
        alert('Please enter a group name');
        return;
    }
    
    if (window.tempGroupItems.length === 0) {
        alert('Please add at least one item to the group');
        return;
    }
    
    let statusGroupInfo = null;
    if (statusGroupId && window.existingStatusGroups) {
        statusGroupInfo = window.existingStatusGroups.find(g => g.id === statusGroupId);
    }
    
    const totalCashAmount = window.tempGroupItems.reduce((sum, i) => {
        if (i.paymentOption === 'cash_only') return sum + (i.cashAmount || i.totalAmount || 0);
        if (i.paymentOption === 'either') return sum + (i.cashAmount || 0);
        return sum;
    }, 0);
    
    const groupIndex = window.activityGroupsData.findIndex(g => g.id === window.editGroupId);
    if (groupIndex !== -1) {
        window.activityGroupsData[groupIndex] = {
            ...window.activityGroupsData[groupIndex],
            name: groupName,
            periodType: periodType,
            statusGroupId: statusGroupId,
            statusGroupName: statusGroupInfo?.name || null,
            items: [...window.tempGroupItems],
            totalAmount: totalCashAmount,
            updatedAt: new Date().toISOString()
        };
    }
    
    window.tempGroupItems = [];
    window.editGroupId = null;
    
    closeSubModal();
    renderActivityGroupsList();
    updateSummaryTotals();
}

