function showAddStatusGroupModal() {
    const modalHtml = `
        <div class="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-[70]">
            <div class="bg-white rounded-2xl p-6 max-w-md w-full mx-4">
                <div class="flex justify-between items-center mb-4 pb-2 border-b">
                    <h4 class="text-lg font-bold">Create Status Group</h4>
                    <button onclick="closeSubModal()" class="text-gray-500 hover:text-gray-700">&times;</button>
                </div>
                
                <form id="addStatusGroupForm" class="space-y-4" onsubmit="return false;">
                    <div>
                        <label class="block text-sm font-medium mb-1 required-field">Group Name *</label>
                        <input type="text" id="statusGroupName" required class="w-full border rounded-lg px-3 py-2" placeholder="e.g., Scholastic, Sports, Sanitary">
                    </div>
                    <div>
                        <label class="block text-sm font-medium mb-1">Description</label>
                        <textarea id="statusGroupDesc" rows="2" class="w-full border rounded-lg px-3 py-2" placeholder="Optional description"></textarea>
                    </div>
                    <div>
                        <label class="block text-sm font-medium mb-1">Color</label>
                        <input type="color" id="statusGroupColor" value="#6b7280" class="w-full h-10 border rounded-lg">
                    </div>
                    <div class="flex gap-3 pt-2">
                        <button type="submit" class="flex-1 bg-blue-600 text-white py-2 rounded-lg">Create Group</button>
                        <button type="button" onclick="closeSubModal()" class="flex-1 bg-gray-300 text-gray-700 py-2 rounded-lg">Cancel</button>
                    </div>
                </form>
            </div>
        </div>
    `;
    
    document.body.insertAdjacentHTML('beforeend', modalHtml);
    
    document.getElementById('addStatusGroupForm').addEventListener('submit', async () => {
        const name = document.getElementById('statusGroupName').value.trim();
        const description = document.getElementById('statusGroupDesc').value;
        const color = document.getElementById('statusGroupColor').value;
        
        if (!name) {
            alert('Please enter a group name');
            return;
        }
        
        try {
            const response = await fetch('/api/fee/status-groups', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ name, description, color, isActive: true })
            });
            
            if (response.ok) {
                const result = await response.json();
                if (!window.existingStatusGroups) window.existingStatusGroups = [];
                window.existingStatusGroups.push(result.group);
                updateStatusGroupDropdowns();
                closeSubModal();
                alert('✅ Status group created successfully!');
            } else {
                alert('❌ Error creating status group');
            }
        } catch (error) {
            console.error('Error:', error);
            alert('Network error: ' + error.message);
        }
    });
}

