// ==================== RENDER CURRENT GROUP ITEMS ====================

function renderCurrentGroupItems() {
    const container = document.getElementById('currentGroupItemsContainer');
    if (!container) return;
    
    if (!window.tempGroupItems || window.tempGroupItems.length === 0) {
        container.innerHTML = '<div class="text-center text-gray-400 py-4">No items added. Click "Add Item" to add.</div>';
        return;
    }
    
    container.innerHTML = window.tempGroupItems.map((item, index) => {
        let paymentOptionDisplay = '';
        let detailsDisplay = '';
        
        if (item.paymentOption === 'cash_only') {
            paymentOptionDisplay = '<span class="bg-blue-100 text-blue-800 px-2 py-0.5 rounded-full text-xs">💵 Cash Only</span>';
            detailsDisplay = `UGX ${(item.cashAmount || item.totalAmount || 0).toLocaleString()}`;
        }
        else if (item.paymentOption === 'item_only') {
            paymentOptionDisplay = '<span class="bg-green-100 text-green-800 px-2 py-0.5 rounded-full text-xs">📦 Item Only</span>';
            detailsDisplay = `${item.quantity} item(s)`;
        }
        else {
            paymentOptionDisplay = '<span class="bg-purple-100 text-purple-800 px-2 py-0.5 rounded-full text-xs">🔄 Cash or Item</span>';
            const parts = [];
            if (item.cashAmount > 0) parts.push(`UGX ${item.cashAmount.toLocaleString()}`);
            if (item.quantity > 0) parts.push(`${item.quantity} item(s)`);
            detailsDisplay = parts.join(' + ');
        }
        
        return `
            <div class="bg-white rounded-lg p-3 border shadow-sm flex justify-between items-center">
                <div>
                    <p class="font-medium">${escapeHtml(item.name)}</p>
                    <div class="flex gap-2 mt-1">${paymentOptionDisplay}</div>
                    <div class="mt-1 text-sm font-semibold text-green-600">${detailsDisplay}</div>
                </div>
                <button type="button" onclick="removeTempItem(${index})" class="text-red-600 hover:text-red-800 text-sm">Remove</button>
            </div>
        `;
    }).join('');
}

function removeTempItem(index) {
    window.tempGroupItems.splice(index, 1);
    renderCurrentGroupItems();
}

// ==================== REMOVE TEMP ITEM ====================

function removeTempItem(index) {
    window.tempGroupItems.splice(index, 1);
    renderCurrentGroupItems();
}

