// Version: FINAL - Allows any cash amount value (2500, 2300, 5700, 45500, etc.)

function addItemToCurrentGroup() {
    const paymentOptions = [
        { value: 'cash_only', label: '💵 Cash Only', description: 'Must be paid in cash' },
        { value: 'item_only', label: '📦 Item Only', description: 'Must be brought physically' },
        { value: 'either', label: '🔄 Either (Cash or Item)', description: 'Can be paid cash OR bring items' }
    ];
    
    const modalHtml = `
        <div class="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-[70]">
            <div class="bg-white rounded-2xl p-6 max-w-md w-full mx-4">
                <div class="flex justify-between items-center mb-4 pb-2 border-b">
                    <h4 class="text-lg font-bold">Add Item to Group</h4>
                    <button onclick="closeSubModal()" class="text-gray-500 hover:text-gray-700">&times;</button>
                </div>
                
                <form id="addItemForm" class="space-y-4" onsubmit="return false;">
                    <div>
                        <label class="block text-sm font-medium mb-1 required-field">Item Name *</label>
                        <input type="text" id="itemName" required class="w-full border rounded-lg px-3 py-2" placeholder="e.g., Brooms, Pens, Books">
                    </div>
                    
                    <div>
                        <label class="block text-sm font-medium mb-1 required-field">Payment Option *</label>
                        <div class="space-y-2">
                            ${paymentOptions.map(opt => `
                                <label class="flex items-start p-3 border rounded-lg cursor-pointer hover:bg-gray-50">
                                    <input type="radio" name="paymentOption" value="${opt.value}" class="mr-3 mt-1 payment-option-radio" ${opt.value === 'either' ? 'checked' : ''}>
                                    <div>
                                        <div class="font-medium">${opt.label}</div>
                                        <div class="text-xs text-gray-500">${opt.description}</div>
                                    </div>
                                </label>
                            `).join('')}
                        </div>
                    </div>
                    
                    <div id="dynamicFieldsContainer" class="space-y-4">
                        <div class="bg-blue-50 p-4 rounded-lg text-center text-blue-600">Select a payment option above</div>
                    </div>
                    
                    <div class="flex gap-3 pt-2">
                        <button type="submit" class="flex-1 bg-blue-600 text-white py-2 rounded-lg">Add Item</button>
                        <button type="button" onclick="closeSubModal()" class="flex-1 bg-gray-300 text-gray-700 py-2 rounded-lg">Cancel</button>
                    </div>
                </form>
            </div>
        </div>
    `;
    
    document.body.insertAdjacentHTML('beforeend', modalHtml);
    
    function updateDynamicFields(selectedOption) {
        const container = document.getElementById('dynamicFieldsContainer');
        if (!container) return;
        
        if (selectedOption === 'cash_only') {
            container.innerHTML = `
                <div>
                    <label class="block text-sm font-medium mb-1 required-field">Amount (UGX) *</label>
                    <input type="number" id="itemCashAmount" class="w-full border rounded-lg px-3 py-2" value="0" min="0" step="1">
                    <p class="text-xs text-gray-400 mt-1">Enter any amount (e.g., 2500, 3500, 5700, 45500, etc.)</p>
                </div>
            `;
        } 
        else if (selectedOption === 'item_only') {
            container.innerHTML = `
                <div>
                    <label class="block text-sm font-medium mb-1 required-field">Quantity to Bring *</label>
                    <input type="number" id="itemQuantity" class="w-full border rounded-lg px-3 py-2" value="1" min="1" step="1">
                </div>
            `;
        } 
        else if (selectedOption === 'either') {
            container.innerHTML = `
                <div class="grid grid-cols-2 gap-3">
                    <div>
                        <label class="block text-sm font-medium mb-1">Cash Amount (UGX)</label>
                        <input type="number" id="itemCashAmount" class="w-full border rounded-lg px-3 py-2" value="0" min="0" step="1">
                        <p class="text-xs text-gray-400 mt-1">Enter any amount</p>
                    </div>
                    <div>
                        <label class="block text-sm font-medium mb-1">Quantity to Bring</label>
                        <input type="number" id="itemQuantity" class="w-full border rounded-lg px-3 py-2" value="0" min="0" step="1">
                    </div>
                </div>
                <div class="bg-yellow-50 p-2 rounded text-xs text-yellow-700">Enter either cash amount, quantity, or both</div>
            `;
        }
    }
    
    const radioButtons = document.querySelectorAll('.payment-option-radio');
    radioButtons.forEach(radio => {
        radio.addEventListener('change', (e) => {
            if (e.target.checked) updateDynamicFields(e.target.value);
        });
    });
    
    updateDynamicFields('either');
    
    document.getElementById('addItemForm').addEventListener('submit', () => {
        const itemName = document.getElementById('itemName').value.trim();
        const paymentOption = document.querySelector('input[name="paymentOption"]:checked')?.value || 'either';
        
        if (!itemName) {
            alert('Please enter an item name');
            return;
        }
        
        let quantity = 0;
        let cashAmount = 0;
        
        if (paymentOption === 'cash_only') {
            cashAmount = parseFloat(document.getElementById('itemCashAmount')?.value) || 0;
            if (cashAmount <= 0) {
                alert('Please enter a valid cash amount');
                return;
            }
            quantity = 1;
        } 
        else if (paymentOption === 'item_only') {
            quantity = parseInt(document.getElementById('itemQuantity')?.value) || 0;
            if (quantity <= 0) {
                alert('Please enter a valid quantity');
                return;
            }
            cashAmount = 0;
        } 
        else {
            cashAmount = parseFloat(document.getElementById('itemCashAmount')?.value) || 0;
            quantity = parseInt(document.getElementById('itemQuantity')?.value) || 0;
            if (cashAmount <= 0 && quantity <= 0) {
                alert('Please enter either cash amount, quantity, or both');
                return;
            }
        }
        
        // Ensure cashAmount is a number with 0 decimal places
        cashAmount = Math.round(cashAmount);
        
        const newItem = {
            id: `item_${Date.now()}_${Math.random().toString(36).substr(2, 6)}`,
            name: itemName,
            quantity: quantity,
            cashAmount: cashAmount,
            totalAmount: cashAmount,
            paymentOption: paymentOption,
            isTangible: paymentOption !== 'cash_only'
        };
        
        if (!window.tempGroupItems) window.tempGroupItems = [];
        window.tempGroupItems.push(newItem);
        
        console.log('Item added to tempGroupItems:', newItem);
        
        closeSubModal();
        
        // Re-render the items display based on whether we're in edit mode or add mode
        if (document.getElementById('editGroupItemsContainer')) {
            // In edit mode
            const container = document.getElementById('editGroupItemsContainer');
            if (container) {
                if (window.tempGroupItems.length === 0) {
                    container.innerHTML = '<div class="text-center text-gray-400 py-4">No items added. Click "Add Item" to add.</div>';
                } else {
                    container.innerHTML = window.tempGroupItems.map((item, idx) => {
                        let detailsDisplay = '';
                        if (item.paymentOption === 'cash_only') {
                            detailsDisplay = `UGX ${(item.cashAmount || item.totalAmount || 0).toLocaleString()}`;
                        } else if (item.paymentOption === 'item_only') {
                            detailsDisplay = `${item.quantity} item(s)`;
                        } else {
                            const parts = [];
                            if (item.cashAmount > 0) parts.push(`UGX ${item.cashAmount.toLocaleString()}`);
                            if (item.quantity > 0) parts.push(`${item.quantity} item(s)`);
                            detailsDisplay = parts.join(' + ');
                        }
                        
                        return `
                            <div class="bg-white rounded-lg p-3 border flex justify-between items-center">
                                <div>
                                    <p class="font-medium">${escapeHtml(item.name)}</p>
                                    <p class="text-xs text-gray-500">${detailsDisplay}</p>
                                </div>
                                <button type="button" onclick="removeEditTempItem(${idx})" class="text-red-600 text-sm hover:text-red-800">Remove</button>
                            </div>
                        `;
                    }).join('');
                }
            }
        } else {
            // In add mode
            renderCurrentGroupItems();
        }
    });
}


