// ==================== UPDATE STATUS GROUP DROPDOWNS ====================

function updateStatusGroupDropdowns() {
    const optionsHtml = '<option value="">-- No Status Group (Independent) --</option>' + 
        (window.existingStatusGroups || []).map(g => `<option value="${g.id}" data-color="${g.color}">${escapeHtml(g.name)}</option>`).join('');
    
    const dropdowns = ['groupStatusGroupId', 'editGroupStatusGroupId'];
    dropdowns.forEach(id => {
        const select = document.getElementById(id);
        if (select) {
            const currentValue = select.value;
            select.innerHTML = optionsHtml;
            if (currentValue && window.existingStatusGroups?.some(g => g.id === currentValue)) {
                select.value = currentValue;
            }
        }
    });
}

// ==================== EDIT STATUS GROUP ====================

function editStatusGroup(groupId) {
    const group = window.existingStatusGroups.find(g => g.id === groupId);
    if (!group) return;
    
    const modalHtml = `
        <div class="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-[70]">
            <div class="bg-white rounded-2xl p-6 max-w-md w-full mx-4">
                <div class="flex justify-between items-center mb-4 pb-2 border-b">
                    <h4 class="text-lg font-bold">Edit Status Group</h4>
                    <button onclick="closeSubModal()" class="text-gray-500 hover:text-gray-700">&times;</button>
                </div>
                
                <form id="editStatusGroupForm" class="space-y-4" onsubmit="return false;">
                    <div>
                        <label class="block text-sm font-medium mb-1 required-field">Group Name *</label>
                        <input type="text" id="editStatusGroupName" value="${escapeHtml(group.name)}" required class="w-full border rounded-lg px-3 py-2">
                    </div>
                    <div>
                        <label class="block text-sm font-medium mb-1">Description</label>
                        <textarea id="editStatusGroupDesc" rows="2" class="w-full border rounded-lg px-3 py-2">${escapeHtml(group.description || '')}</textarea>
                    </div>
                    <div>
                        <label class="block text-sm font-medium mb-1">Color</label>
                        <input type="color" id="editStatusGroupColor" value="${group.color || '#6b7280'}" class="w-full h-10 border rounded-lg">
                    </div>
                    <div class="flex gap-3 pt-2">
                        <button type="submit" class="flex-1 bg-blue-600 text-white py-2 rounded-lg">Update Group</button>
                        <button type="button" onclick="closeSubModal()" class="flex-1 bg-gray-300 text-gray-700 py-2 rounded-lg">Cancel</button>
                    </div>
                </form>
            </div>
        </div>
    `;
    
    document.body.insertAdjacentHTML('beforeend', modalHtml);
    
    document.getElementById('editStatusGroupForm').addEventListener('submit', async () => {
        const name = document.getElementById('editStatusGroupName').value.trim();
        const description = document.getElementById('editStatusGroupDesc').value;
        const color = document.getElementById('editStatusGroupColor').value;
        
        if (!name) {
            alert('Please enter a group name');
            return;
        }
        
        try {
            const response = await fetch(`/api/fee/status-groups/${groupId}`, {
                method: 'PUT',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ name, description, color })
            });
            
            if (response.ok) {
                const result = await response.json();
                const index = window.existingStatusGroups.findIndex(g => g.id === groupId);
                if (index !== -1) {
                    window.existingStatusGroups[index] = result.group;
                }
                updateStatusGroupDropdowns();
                closeSubModal();
                alert('✅ Status group updated successfully!');
                showManageStatusGroupsModal();
            } else {
                alert('❌ Error updating status group');
            }
        } catch (error) {
            console.error('Error:', error);
            alert('Network error: ' + error.message);
        }
    });
}

// ==================== DELETE STATUS GROUP ====================

async function deleteStatusGroup(groupId) {
    if (confirm('Are you sure you want to delete this status group? This will not delete the activity groups using it, but they will become independent.')) {
        try {
            const response = await fetch(`/api/fee/status-groups/${groupId}`, {
                method: 'DELETE'
            });
            
            if (response.ok) {
                window.existingStatusGroups = window.existingStatusGroups.filter(g => g.id !== groupId);
                updateStatusGroupDropdowns();
                closeSubModal();
                alert('✅ Status group deleted successfully!');
                showManageStatusGroupsModal();
            } else {
                alert('❌ Error deleting status group');
            }
        } catch (error) {
            console.error('Error:', error);
            alert('Network error: ' + error.message);
        }
    }
}

