// ==================== CLOSE SUB MODAL ====================

function closeSubModal() {
    const modals = document.querySelectorAll('.fixed.inset-0[class*="z-["]');
    if (modals.length > 0) {
        const lastModal = modals[modals.length - 1];
        lastModal.remove();
    } else {
        // Fallback to find any modal with z-index 60 or higher
        const modal = document.querySelector('[class*="z-6"], [class*="z-7"]');
        if (modal) modal.remove();
    }
}

// ==================== CLOSE MODAL ====================

function closeModal() {
    const modal = document.querySelector('.fixed.inset-0.bg-black.bg-opacity-50.z-50');
    if (modal) modal.remove();
}

// ==================== ESCAPE HTML ====================

function escapeHtml(text) {
    if (!text) return '';
    const div = document.createElement('div');
    div.textContent = text;
    return div.innerHTML;
}

// ==================== SIMPLE ADD GROUP FUNCTION ====================

function addSimpleGroup(periodType) {
    console.log('addSimpleGroup called for:', periodType);
    
    window.groupCounters[periodType]++;
    const groupId = `${periodType}_group_${window.groupCounters[periodType]}`;
    
    let color, containerId, emptyMsgId, bgColor;
    if (periodType === 'one_time') {
        color = 'purple';
        containerId = 'oneTimeGroupsContainer';
        emptyMsgId = 'emptyOneTimeMsg';
        bgColor = 'bg-purple-50';
    } else if (periodType === 'termly') {
        color = 'green';
        containerId = 'termlyGroupsContainer';
        emptyMsgId = 'emptyTermlyMsg';
        bgColor = 'bg-green-50';
    } else {
        color = 'orange';
        containerId = 'yearlyGroupsContainer';
        emptyMsgId = 'emptyYearlyMsg';
        bgColor = 'bg-orange-50';
    }
    
    const html = `
        <div id="${groupId}" class="border-2 border-${color}-300 rounded-lg p-3 ${bgColor} mb-3" data-group-id="${groupId}" data-period-type="${periodType}">
            <div class="flex justify-between items-center mb-3">
                <input type="text" placeholder="Activity Group Name" 
                       class="flex-1 border rounded-lg px-3 py-2 text-sm group-name-input" 
                       data-group-id="${groupId}">
                <button type="button" class="text-red-600 hover:text-red-800 ml-2 px-2 py-1" onclick="removeSimpleGroup('${groupId}')">
                    <i class="fas fa-trash"></i> Remove
                </button>
            </div>
            <div class="ml-4">
                <div class="flex justify-between items-center mb-2">
                    <h4 class="text-sm font-semibold text-${color}-600">Items:</h4>
                    <button type="button" class="bg-${color}-100 text-${color}-600 px-2 py-1 rounded text-xs hover:bg-${color}-200" onclick="addSimpleItem('${groupId}', '${periodType}')">
                        <i class="fas fa-plus"></i> Add Item
                    </button>
                </div>
                <div id="${groupId}_items" class="space-y-2">
                    <div class="text-center text-gray-400 text-xs py-2">No items added.</div>
                </div>
            </div>
        </div>
    `;
    
    const container = document.getElementById(containerId);
    const emptyMsg = document.getElementById(emptyMsgId);
    if (emptyMsg && emptyMsg.parentNode === container) {
        emptyMsg.remove();
    }
    
    container.insertAdjacentHTML('beforeend', html);
    updateSimpleTotals();
}

// ==================== SIMPLE ADD ITEM FUNCTION ====================

function addSimpleItem(groupId, periodType) {
    console.log('addSimpleItem called for group:', groupId);
    
    const itemId = `${groupId}_item_${Date.now()}`;
    const itemsContainer = document.getElementById(`${groupId}_items`);
    
    if (!itemsContainer) return;
    
    // Remove empty message
    const emptyMsg = itemsContainer.querySelector('.text-center.text-gray-400');
    if (emptyMsg && emptyMsg.parentNode === itemsContainer) {
        emptyMsg.remove();
    }
    
    const html = `
        <div id="${itemId}" class="flex gap-2 items-center bg-white p-2 rounded-lg border mb-2">
            <input type="text" placeholder="Item name" class="flex-1 border rounded px-2 py-1 text-sm item-name-input" data-group-id="${groupId}" data-item-id="${itemId}">
            <input type="number" placeholder="Qty" class="w-16 border rounded px-2 py-1 text-sm item-qty-input" value="1" min="1" data-group-id="${groupId}" data-item-id="${itemId}" oninput="updateSimpleTotals()">
            <input type="number" placeholder="Total Amount" class="w-28 border rounded px-2 py-1 text-sm item-amount-input" value="0" min="0" data-group-id="${groupId}" data-item-id="${itemId}" oninput="updateSimpleTotals()">
            <button type="button" class="text-red-600 hover:text-red-800 px-1" onclick="removeSimpleItem('${itemId}', '${groupId}')">
                <i class="fas fa-times"></i>
            </button>
        </div>
    `;
    
    itemsContainer.insertAdjacentHTML('beforeend', html);
    updateSimpleTotals();
}

// ==================== SIMPLE REMOVE FUNCTIONS ====================

function removeSimpleItem(itemId, groupId) {
    const element = document.getElementById(itemId);
    if (element) element.remove();
    
    const itemsContainer = document.getElementById(`${groupId}_items`);
    if (itemsContainer && itemsContainer.children.length === 0) {
        itemsContainer.innerHTML = '<div class="text-center text-gray-400 text-xs py-2">No items added.</div>';
    }
    
    updateSimpleTotals();
}

function removeSimpleGroup(groupId) {
    const element = document.getElementById(groupId);
    if (element) element.remove();
    
    // Check if containers are empty and add back empty messages
    const oneTimeContainer = document.getElementById('oneTimeGroupsContainer');
    if (oneTimeContainer && oneTimeContainer.children.length === 0 && !document.getElementById('emptyOneTimeMsg')) {
        oneTimeContainer.innerHTML = '<div class="text-center text-gray-400 py-4" id="emptyOneTimeMsg">No one-time activity groups added. Click "Add Activity Group" to add.</div>';
    }
    
    const termlyContainer = document.getElementById('termlyGroupsContainer');
    if (termlyContainer && termlyContainer.children.length === 0 && !document.getElementById('emptyTermlyMsg')) {
        termlyContainer.innerHTML = '<div class="text-center text-gray-400 py-4" id="emptyTermlyMsg">No termly activity groups added. Click "Add Activity Group" to add.</div>';
    }
    
    const yearlyContainer = document.getElementById('yearlyGroupsContainer');
    if (yearlyContainer && yearlyContainer.children.length === 0 && !document.getElementById('emptyYearlyMsg')) {
        yearlyContainer.innerHTML = '<div class="text-center text-gray-400 py-4" id="emptyYearlyMsg">No yearly activity groups added. Click "Add Activity Group" to add.</div>';
    }
    
    updateSimpleTotals();
}

// ==================== UPDATE TOTALS ====================

function updateSimpleTotals() {
    // Get tuition
    const tuition = parseInt(document.getElementById('modalFsTuition').value) || 0;
    
    // Calculate One-Time total
    let oneTimeTotal = 0;
    document.querySelectorAll('#oneTimeGroupsContainer .item-amount-input').forEach(input => {
        oneTimeTotal += parseInt(input.value) || 0;
    });
    
    // Calculate Termly total
    let termlyTotal = 0;
    document.querySelectorAll('#termlyGroupsContainer .item-amount-input').forEach(input => {
        termlyTotal += parseInt(input.value) || 0;
    });
    
    // Calculate Yearly total
    let yearlyTotal = 0;
    document.querySelectorAll('#yearlyGroupsContainer .item-amount-input').forEach(input => {
        yearlyTotal += parseInt(input.value) || 0;
    });
    
    // Update displays
    document.getElementById('totalOneTimeFees').innerHTML = `UGX ${oneTimeTotal.toLocaleString()}`;
    document.getElementById('totalTermlyFees').innerHTML = `UGX ${termlyTotal.toLocaleString()}`;
    document.getElementById('totalYearlyFees').innerHTML = `UGX ${yearlyTotal.toLocaleString()}`;
    
    document.getElementById('summaryTuition').innerHTML = `UGX ${tuition.toLocaleString()}`;
    document.getElementById('summaryOneTime').innerHTML = `UGX ${oneTimeTotal.toLocaleString()}`;
    document.getElementById('summaryTermly').innerHTML = `UGX ${termlyTotal.toLocaleString()}`;
    document.getElementById('summaryYearly').innerHTML = `UGX ${yearlyTotal.toLocaleString()}`;
}

// ==================== COLLECT AND SAVE ====================

function collectSimpleFeeStructureData() {
    const name = document.getElementById('modalFsName').value.trim();
    const level = document.getElementById('modalFsLevel').value;
    const tuition = parseInt(document.getElementById('modalFsTuition').value) || 0;
    
    const oneTimeActivities = [];
    const termlyActivities = [];
    const yearlyActivities = [];
    
    // Collect One-Time
    const oneTimeGroups = document.querySelectorAll('#oneTimeGroupsContainer > div[id^="one_time_group_"]');
    for (const groupDiv of oneTimeGroups) {
        const groupNameInput = groupDiv.querySelector('.group-name-input');
        const groupName = groupNameInput ? groupNameInput.value.trim() : '';
        
        const items = [];
        const itemDivs = groupDiv.querySelectorAll('.item-name-input');
        for (const itemDiv of itemDivs) {
            const parentDiv = itemDiv.closest('div[id^="one_time_group_"] > div > div > div');
            if (!parentDiv) continue;
            
            const nameInput = parentDiv.querySelector('.item-name-input');
            const qtyInput = parentDiv.querySelector('.item-qty-input');
            const amountInput = parentDiv.querySelector('.item-amount-input');
            
            const itemName = nameInput ? nameInput.value.trim() : '';
            const quantity = qtyInput ? parseInt(qtyInput.value) || 1 : 1;
            const totalAmount = amountInput ? parseInt(amountInput.value) || 0 : 0;
            
            if (itemName && totalAmount > 0) {
                items.push({ name: itemName, quantity: quantity, totalAmount: totalAmount });
            }
        }
        
        if (groupName && items.length > 0) {
            oneTimeActivities.push({ name: groupName, items: items });
        }
    }
    
    // Collect Termly
    const termlyGroups = document.querySelectorAll('#termlyGroupsContainer > div[id^="termly_group_"]');
    for (const groupDiv of termlyGroups) {
        const groupNameInput = groupDiv.querySelector('.group-name-input');
        const groupName = groupNameInput ? groupNameInput.value.trim() : '';
        
        const items = [];
        const itemDivs = groupDiv.querySelectorAll('.item-name-input');
        for (const itemDiv of itemDivs) {
            const parentDiv = itemDiv.closest('div[id^="termly_group_"] > div > div > div');
            if (!parentDiv) continue;
            
            const nameInput = parentDiv.querySelector('.item-name-input');
            const qtyInput = parentDiv.querySelector('.item-qty-input');
            const amountInput = parentDiv.querySelector('.item-amount-input');
            
            const itemName = nameInput ? nameInput.value.trim() : '';
            const quantity = qtyInput ? parseInt(qtyInput.value) || 1 : 1;
            const totalAmount = amountInput ? parseInt(amountInput.value) || 0 : 0;
            
            if (itemName && totalAmount > 0) {
                items.push({ name: itemName, quantity: quantity, totalAmount: totalAmount });
            }
        }
        
        if (groupName && items.length > 0) {
            termlyActivities.push({ name: groupName, items: items });
        }
    }
    
    // Collect Yearly
    const yearlyGroups = document.querySelectorAll('#yearlyGroupsContainer > div[id^="yearly_group_"]');
    for (const groupDiv of yearlyGroups) {
        const groupNameInput = groupDiv.querySelector('.group-name-input');
        const groupName = groupNameInput ? groupNameInput.value.trim() : '';
        
        const items = [];
        const itemDivs = groupDiv.querySelectorAll('.item-name-input');
        for (const itemDiv of itemDivs) {
            const parentDiv = itemDiv.closest('div[id^="yearly_group_"] > div > div > div');
            if (!parentDiv) continue;
            
            const nameInput = parentDiv.querySelector('.item-name-input');
            const qtyInput = parentDiv.querySelector('.item-qty-input');
            const amountInput = parentDiv.querySelector('.item-amount-input');
            
            const itemName = nameInput ? nameInput.value.trim() : '';
            const quantity = qtyInput ? parseInt(qtyInput.value) || 1 : 1;
            const totalAmount = amountInput ? parseInt(amountInput.value) || 0 : 0;
            
            if (itemName && totalAmount > 0) {
                items.push({ name: itemName, quantity: quantity, totalAmount: totalAmount });
            }
        }
        
        if (groupName && items.length > 0) {
            yearlyActivities.push({ name: groupName, items: items });
        }
    }
    
    return {
        name: name,
        level: level,
        tuition: tuition,
        oneTimeActivities: oneTimeActivities,
        termlyActivities: termlyActivities,
        yearlyActivities: yearlyActivities
    };
}

async function saveSimpleFeeStructure() {
    console.log('saveSimpleFeeStructure called');
    
    const feeData = collectSimpleFeeStructureData();
    
    console.log('Saving:', JSON.stringify(feeData, null, 2));
    
    if (!feeData.name) {
        alert('Please enter a fee structure name');
        return;
    }
    
    const hasData = feeData.tuition > 0 || 
                    feeData.oneTimeActivities.length > 0 || 
                    feeData.termlyActivities.length > 0 || 
                    feeData.yearlyActivities.length > 0;
    
    if (!hasData) {
        alert('Please add at least tuition fee or some activities before saving');
        return;
    }
    
    const submitBtn = document.querySelector('#addFeeStructureModalForm button[type="submit"]');
    const originalText = submitBtn.innerHTML;
    submitBtn.innerHTML = '<i class="fas fa-spinner fa-spin"></i> Saving...';
    submitBtn.disabled = true;
    
    try {
        const response = await fetch('/api/fee/structures/enhanced', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(feeData)
        });
        
        if (response.ok) {
            const result = await response.json();
            const oneTimeTotal = feeData.oneTimeActivities.reduce((sum, act) => 
                sum + act.items.reduce((s, i) => s + i.totalAmount, 0), 0);
            const termlyTotal = feeData.termlyActivities.reduce((sum, act) => 
                sum + act.items.reduce((s, i) => s + i.totalAmount, 0), 0);
            const yearlyTotal = feeData.yearlyActivities.reduce((sum, act) => 
                sum + act.items.reduce((s, i) => s + i.totalAmount, 0), 0);
            
            alert(`✅ Fee structure "${feeData.name}" saved!\n\nTuition: UGX ${feeData.tuition.toLocaleString()}\nOne-Time: UGX ${oneTimeTotal.toLocaleString()}\nTermly: UGX ${termlyTotal.toLocaleString()}\nYearly: UGX ${yearlyTotal.toLocaleString()}`);
            
            closeModal();
            showFeeManagement();
        } else {
            const error = await response.json();
            alert('❌ Error: ' + (error.error || 'Unknown error'));
        }
    } catch (error) {
        alert('Network error: ' + error.message);
    } finally {
        submitBtn.innerHTML = originalText;
        submitBtn.disabled = false;
    }
}

