// ==================== ADD ACTIVITY GROUP ====================

function addActivityGroup(periodType) {
    console.log('addActivityGroup called for:', periodType);
    
    const groupId = `${periodType}_${Date.now()}_${Math.random().toString(36).substr(2, 6)}`;
    const color = periodType === 'one_time' ? 'purple' : periodType === 'termly' ? 'green' : 'orange';
    const bgColor = periodType === 'one_time' ? 'bg-purple-50' : periodType === 'termly' ? 'bg-green-50' : 'bg-orange-50';
    const borderColor = periodType === 'one_time' ? 'border-purple-200' : periodType === 'termly' ? 'border-green-200' : 'border-orange-200';
    const textColor = periodType === 'one_time' ? 'text-purple-600' : periodType === 'termly' ? 'text-green-600' : 'text-orange-600';
    
    const html = `
        <div id="${groupId}" class="border-2 ${borderColor} rounded-lg p-3 ${bgColor} mb-3" data-group-id="${groupId}" data-period-type="${periodType}">
            <div class="flex justify-between items-center mb-3">
                <input type="text" placeholder="Activity Group Name (e.g., Sports Equipment)" 
                       class="flex-1 border rounded-lg px-3 py-2 text-sm focus:ring-2 focus:ring-${color}-500 groupNameInput" 
                       data-group-id="${groupId}">
                <button type="button" onclick="removeActivityGroup('${groupId}')" 
                        class="text-red-600 hover:text-red-800 ml-2 px-2 py-1">
                    <i class="fas fa-trash"></i> Remove
                </button>
            </div>
            <div class="ml-4">
                <div class="flex justify-between items-center mb-2">
                    <h4 class="text-sm font-semibold ${textColor}">Items in this group:</h4>
                    <button type="button" onclick="addItemToGroup('${groupId}')" 
                            class="bg-${color}-100 text-${color}-600 px-2 py-1 rounded text-xs hover:bg-${color}-200">
                        <i class="fas fa-plus"></i> Add Item
                    </button>
                </div>
                <div id="${groupId}_items" class="space-y-2">
                    <div class="text-center text-gray-400 text-xs py-2">No items added. Click "Add Item" to add.</div>
                </div>
            </div>
        </div>
    `;
    
    let container;
    if (periodType === 'one_time') {
        container = document.getElementById('oneTimeGroupsContainer');
    } else if (periodType === 'termly') {
        container = document.getElementById('termlyGroupsContainer');
    } else {
        container = document.getElementById('yearlyGroupsContainer');
    }
    
    if (!container) return;
    
    // Remove empty message
    const emptyMsgId = periodType === 'one_time' ? 'emptyOneTimeMsg' : periodType === 'termly' ? 'emptyTermlyMsg' : 'emptyYearlyMsg';
    const emptyMsg = document.getElementById(emptyMsgId);
    if (emptyMsg && emptyMsg.parentNode === container) {
        emptyMsg.remove();
    }
    
    container.insertAdjacentHTML('beforeend', html);
    
    // Store reference
    if (!window.tempActivityGroups) {
        window.tempActivityGroups = { one_time: [], termly: [], yearly: [] };
    }
    window.tempActivityGroups[periodType].push({
        groupId: groupId,
        name: '',
        items: []
    });
    
    updateFeeStructureTotals();
}

// ==================== ADD ITEM TO GROUP ====================

function addItemToGroup(groupId) {
    console.log('addItemToGroup called for group:', groupId);
    
    const itemId = `item_${Date.now()}_${Math.random().toString(36).substr(2, 6)}`;
    const groupDiv = document.getElementById(groupId);
    const periodType = groupDiv ? groupDiv.dataset.periodType : 'one_time';
    
    const html = `
        <div id="${itemId}" class="flex gap-2 items-center bg-white p-2 rounded-lg border mb-2" data-item-id="${itemId}">
            <input type="text" placeholder="Item name" 
                   class="flex-1 border rounded px-2 py-1 text-sm itemName" 
                   data-item-id="${itemId}">
            <input type="number" placeholder="Qty" 
                   class="w-16 border rounded px-2 py-1 text-sm itemQty" 
                   value="1" min="1" data-item-id="${itemId}">
            <input type="number" placeholder="Total Amount" 
                   class="w-28 border rounded px-2 py-1 text-sm itemAmount" 
                   value="0" min="0" data-item-id="${itemId}">
            <button type="button" onclick="removeItemFromGroup('${itemId}', '${groupId}')" 
                    class="text-red-600 hover:text-red-800 px-1">
                <i class="fas fa-times"></i>
            </button>
        </div>
    `;
    
    const itemsContainer = document.getElementById(`${groupId}_items`);
    if (!itemsContainer) return;
    
    // Remove empty message if it exists
    const emptyMsg = itemsContainer.querySelector('.text-center.text-gray-400');
    if (emptyMsg && emptyMsg.parentNode === itemsContainer) {
        emptyMsg.remove();
    }
    
    itemsContainer.insertAdjacentHTML('beforeend', html);
    
    // Add event listeners to the new inputs
    const amountInput = itemsContainer.querySelector(`#${itemId} .itemAmount`);
    if (amountInput) {
        amountInput.addEventListener('input', function() {
            updateFeeStructureTotals();
        });
        amountInput.addEventListener('change', function() {
            updateFeeStructureTotals();
        });
    }
    
    const qtyInput = itemsContainer.querySelector(`#${itemId} .itemQty`);
    if (qtyInput) {
        qtyInput.addEventListener('input', function() {
            updateFeeStructureTotals();
        });
    }
    
    const nameInput = itemsContainer.querySelector(`#${itemId} .itemName`);
    if (nameInput) {
        nameInput.addEventListener('input', function() {
            updateFeeStructureTotals();
        });
    }
    
    updateFeeStructureTotals();
}

// ==================== REMOVE ITEM FROM GROUP ====================

function removeItemFromGroup(itemId, groupId) {
    console.log('removeItemFromGroup called for item:', itemId);
    
    const element = document.getElementById(itemId);
    if (element) element.remove();
    
    // Check if container is empty and add back empty message
    const itemsContainer = document.getElementById(`${groupId}_items`);
    if (itemsContainer && itemsContainer.children.length === 0) {
        itemsContainer.innerHTML = '<div class="text-center text-gray-400 text-xs py-2">No items added. Click "Add Item" to add.</div>';
    }
    
    updateFeeStructureTotals();
}

// ==================== REMOVE ACTIVITY GROUP ====================

function removeActivityGroup(groupId) {
    console.log('removeActivityGroup called for group:', groupId);
    
    const groupDiv = document.getElementById(groupId);
    const periodType = groupDiv ? groupDiv.dataset.periodType : null;
    
    if (groupDiv) groupDiv.remove();
    
    // Remove from temp array
    if (periodType && window.tempActivityGroups && window.tempActivityGroups[periodType]) {
        window.tempActivityGroups[periodType] = window.tempActivityGroups[periodType].filter(g => g.groupId !== groupId);
    }
    
    // Check if containers are empty and add back empty messages
    const oneTimeContainer = document.getElementById('oneTimeGroupsContainer');
    if (oneTimeContainer && oneTimeContainer.children.length === 0 && !document.getElementById('emptyOneTimeMsg')) {
        oneTimeContainer.innerHTML = '<div class="text-center text-gray-400 py-4" id="emptyOneTimeMsg">No one-time activity groups added. Click "Add Activity Group" to add.</div>';
    }
    
    const termlyContainer = document.getElementById('termlyGroupsContainer');
    if (termlyContainer && termlyContainer.children.length === 0 && !document.getElementById('emptyTermlyMsg')) {
        termlyContainer.innerHTML = '<div class="text-center text-gray-400 py-4" id="emptyTermlyMsg">No termly activity groups added. Click "Add Activity Group" to add.</div>';
    }
    
    const yearlyContainer = document.getElementById('yearlyGroupsContainer');
    if (yearlyContainer && yearlyContainer.children.length === 0 && !document.getElementById('emptyYearlyMsg')) {
        yearlyContainer.innerHTML = '<div class="text-center text-gray-400 py-4" id="emptyYearlyMsg">No yearly activity groups added. Click "Add Activity Group" to add.</div>';
    }
    
    updateFeeStructureTotals();
}

// ==================== UPDATE FEE STRUCTURE TOTALS ====================

function updateFeeStructureTotals() {
    console.log('Updating fee structure totals...');
    
    // Get tuition
    const tuitionInput = document.getElementById('modalFsTuition');
    const tuition = tuitionInput ? parseInt(tuitionInput.value) || 0 : 0;
    
    // Calculate One-Time total - find all itemAmount inputs in one-time section
    let oneTimeTotal = 0;
    const oneTimeAmounts = document.querySelectorAll('#oneTimeGroupsContainer .itemAmount');
    oneTimeAmounts.forEach(input => {
        const val = parseInt(input.value) || 0;
        oneTimeTotal += val;
    });
    
    // Calculate Termly total
    let termlyTotal = 0;
    const termlyAmounts = document.querySelectorAll('#termlyGroupsContainer .itemAmount');
    termlyAmounts.forEach(input => {
        const val = parseInt(input.value) || 0;
        termlyTotal += val;
    });
    
    // Calculate Yearly total
    let yearlyTotal = 0;
    const yearlyAmounts = document.querySelectorAll('#yearlyGroupsContainer .itemAmount');
    yearlyAmounts.forEach(input => {
        const val = parseInt(input.value) || 0;
        yearlyTotal += val;
    });
    
    console.log('Totals - Tuition:', tuition, 'OneTime:', oneTimeTotal, 'Termly:', termlyTotal, 'Yearly:', yearlyTotal);
    
    // Update display totals
    const totalOneTimeSpan = document.getElementById('totalOneTimeFees');
    if (totalOneTimeSpan) totalOneTimeSpan.innerHTML = `UGX ${oneTimeTotal.toLocaleString()}`;
    
    const totalTermlySpan = document.getElementById('totalTermlyFees');
    if (totalTermlySpan) totalTermlySpan.innerHTML = `UGX ${termlyTotal.toLocaleString()}`;
    
    const totalYearlySpan = document.getElementById('totalYearlyFees');
    if (totalYearlySpan) totalYearlySpan.innerHTML = `UGX ${yearlyTotal.toLocaleString()}`;
    
    // Update summary cards
    const summaryTuition = document.getElementById('summaryTuition');
    if (summaryTuition) summaryTuition.innerHTML = `UGX ${tuition.toLocaleString()}`;
    
    const summaryOneTime = document.getElementById('summaryOneTime');
    if (summaryOneTime) summaryOneTime.innerHTML = `UGX ${oneTimeTotal.toLocaleString()}`;
    
    const summaryTermly = document.getElementById('summaryTermly');
    if (summaryTermly) summaryTermly.innerHTML = `UGX ${termlyTotal.toLocaleString()}`;
    
    const summaryYearly = document.getElementById('summaryYearly');
    if (summaryYearly) summaryYearly.innerHTML = `UGX ${yearlyTotal.toLocaleString()}`;
}

// ==================== COLLECT FEE STRUCTURE DATA ====================

function collectFeeStructureData() {
    const name = document.getElementById('modalFsName')?.value.trim();
    const level = document.getElementById('modalFsLevel')?.value;
    const tuition = parseInt(document.getElementById('modalFsTuition')?.value) || 0;
    
    const oneTimeActivities = [];
    const termlyActivities = [];
    const yearlyActivities = [];
    
    // Collect One-Time Activities
    const oneTimeGroups = document.querySelectorAll('#oneTimeGroupsContainer > div[id^="one_time_"]');
    console.log('One-time groups found:', oneTimeGroups.length);
    
    for (const groupDiv of oneTimeGroups) {
        const groupNameInput = groupDiv.querySelector('.groupNameInput');
        const groupName = groupNameInput ? groupNameInput.value.trim() : '';
        
        const items = [];
        const itemsContainer = document.getElementById(`${groupDiv.id}_items`);
        if (itemsContainer) {
            const itemDivs = itemsContainer.querySelectorAll('div[id^="item_"]');
            for (const itemDiv of itemDivs) {
                const nameInput = itemDiv.querySelector('.itemName');
                const qtyInput = itemDiv.querySelector('.itemQty');
                const amountInput = itemDiv.querySelector('.itemAmount');
                
                const itemName = nameInput ? nameInput.value.trim() : '';
                const quantity = qtyInput ? parseInt(qtyInput.value) || 1 : 1;
                const totalAmount = amountInput ? parseInt(amountInput.value) || 0 : 0;
                
                if (itemName && totalAmount > 0) {
                    items.push({
                        name: itemName,
                        quantity: quantity,
                        totalAmount: totalAmount
                    });
                    console.log(`Item: ${itemName}, Qty: ${quantity}, Amount: ${totalAmount}`);
                }
            }
        }
        
        if (groupName && items.length > 0) {
            oneTimeActivities.push({
                name: groupName,
                items: items
            });
            console.log(`One-time group: ${groupName} with ${items.length} items`);
        }
    }
    
    // Collect Termly Activities
    const termlyGroups = document.querySelectorAll('#termlyGroupsContainer > div[id^="termly_"]');
    console.log('Termly groups found:', termlyGroups.length);
    
    for (const groupDiv of termlyGroups) {
        const groupNameInput = groupDiv.querySelector('.groupNameInput');
        const groupName = groupNameInput ? groupNameInput.value.trim() : '';
        
        const items = [];
        const itemsContainer = document.getElementById(`${groupDiv.id}_items`);
        if (itemsContainer) {
            const itemDivs = itemsContainer.querySelectorAll('div[id^="item_"]');
            for (const itemDiv of itemDivs) {
                const nameInput = itemDiv.querySelector('.itemName');
                const qtyInput = itemDiv.querySelector('.itemQty');
                const amountInput = itemDiv.querySelector('.itemAmount');
                
                const itemName = nameInput ? nameInput.value.trim() : '';
                const quantity = qtyInput ? parseInt(qtyInput.value) || 1 : 1;
                const totalAmount = amountInput ? parseInt(amountInput.value) || 0 : 0;
                
                if (itemName && totalAmount > 0) {
                    items.push({
                        name: itemName,
                        quantity: quantity,
                        totalAmount: totalAmount
                    });
                }
            }
        }
        
        if (groupName && items.length > 0) {
            termlyActivities.push({
                name: groupName,
                items: items
            });
        }
    }
    
    // Collect Yearly Activities
    const yearlyGroups = document.querySelectorAll('#yearlyGroupsContainer > div[id^="yearly_"]');
    console.log('Yearly groups found:', yearlyGroups.length);
    
    for (const groupDiv of yearlyGroups) {
        const groupNameInput = groupDiv.querySelector('.groupNameInput');
        const groupName = groupNameInput ? groupNameInput.value.trim() : '';
        
        const items = [];
        const itemsContainer = document.getElementById(`${groupDiv.id}_items`);
        if (itemsContainer) {
            const itemDivs = itemsContainer.querySelectorAll('div[id^="item_"]');
            for (const itemDiv of itemDivs) {
                const nameInput = itemDiv.querySelector('.itemName');
                const qtyInput = itemDiv.querySelector('.itemQty');
                const amountInput = itemDiv.querySelector('.itemAmount');
                
                const itemName = nameInput ? nameInput.value.trim() : '';
                const quantity = qtyInput ? parseInt(qtyInput.value) || 1 : 1;
                const totalAmount = amountInput ? parseInt(amountInput.value) || 0 : 0;
                
                if (itemName && totalAmount > 0) {
                    items.push({
                        name: itemName,
                        quantity: quantity,
                        totalAmount: totalAmount
                    });
                }
            }
        }
        
        if (groupName && items.length > 0) {
            yearlyActivities.push({
                name: groupName,
                items: items
            });
        }
    }
    
    console.log('Final collected - OneTime:', oneTimeActivities.length, 'Termly:', termlyActivities.length, 'Yearly:', yearlyActivities.length);
    
    return {
        name: name,
        level: level,
        tuition: tuition,
        oneTimeActivities: oneTimeActivities,
        termlyActivities: termlyActivities,
        yearlyActivities: yearlyActivities
    };
}

