    yearlyAmounts.forEach(input => {
        const val = parseInt(input.value) || 0;
        console.log('Yearly amount value:', val);
        yearlyTotal += val;
    });
    
    console.log('Final totals - OneTime:', oneTimeTotal, 'Termly:', termlyTotal, 'Yearly:', yearlyTotal);
    
