// ==================== SAVE FEE STRUCTURE ====================

async function saveEnhancedFeeStructure() {
    const name = document.getElementById('modalFsName')?.value.trim();
    const level = document.getElementById('modalFsLevel')?.value;
    const tuition = parseInt(document.getElementById('modalFsTuition')?.value) || 0;
    
    if (!name) {
        alert('Please enter a fee structure name');
        return;
    }
    
    // Collect One-Time Activities
    const oneTimeActivities = [];
    const oneTimeGroups = document.querySelectorAll('#oneTimeGroupsContainer > div[id^="ot_"]');
    for (const groupDiv of oneTimeGroups) {
        const groupNameInput = groupDiv.querySelector('.groupNameInput');
        const groupName = groupNameInput ? groupNameInput.value.trim() : '';
        
        const items = [];
        const itemDivs = groupDiv.querySelectorAll(`#${groupDiv.id}_items > div[id^="item_"]`);
        for (const itemDiv of itemDivs) {
            const nameInput = itemDiv.querySelector('.itemNameInput');
            const quantityInput = itemDiv.querySelector('.itemQuantityInput');
            const amountInput = itemDiv.querySelector('.itemAmountInput');
            
            const itemName = nameInput ? nameInput.value.trim() : '';
            const quantity = quantityInput ? parseInt(quantityInput.value) || 1 : 1;
            const totalAmount = amountInput ? parseInt(amountInput.value) || 0 : 0;
            
            if (itemName && totalAmount > 0) {
                items.push({
                    name: itemName,
                    quantity: quantity,
                    totalAmount: totalAmount
                });
            }
        }
        
        if (groupName && items.length > 0) {
            oneTimeActivities.push({
                name: groupName,
                items: items
            });
        }
    }
    
    // Collect Termly Activities
    const termlyActivities = [];
    const termlyGroups = document.querySelectorAll('#termlyGroupsContainer > div[id^="term_"]');
    for (const groupDiv of termlyGroups) {
        const groupNameInput = groupDiv.querySelector('.groupNameInput');
        const groupName = groupNameInput ? groupNameInput.value.trim() : '';
        
        const items = [];
        const itemDivs = groupDiv.querySelectorAll(`#${groupDiv.id}_items > div[id^="item_"]`);
        for (const itemDiv of itemDivs) {
            const nameInput = itemDiv.querySelector('.itemNameInput');
            const quantityInput = itemDiv.querySelector('.itemQuantityInput');
            const amountInput = itemDiv.querySelector('.itemAmountInput');
            
            const itemName = nameInput ? nameInput.value.trim() : '';
            const quantity = quantityInput ? parseInt(quantityInput.value) || 1 : 1;
            const totalAmount = amountInput ? parseInt(amountInput.value) || 0 : 0;
            
            if (itemName && totalAmount > 0) {
                items.push({
                    name: itemName,
                    quantity: quantity,
                    totalAmount: totalAmount
                });
            }
        }
        
        if (groupName && items.length > 0) {
            termlyActivities.push({
                name: groupName,
                items: items
            });
        }
    }
    
    // Collect Yearly Activities
    const yearlyActivities = [];
    const yearlyGroups = document.querySelectorAll('#yearlyGroupsContainer > div[id^="year_"]');
    for (const groupDiv of yearlyGroups) {
        const groupNameInput = groupDiv.querySelector('.groupNameInput');
        const groupName = groupNameInput ? groupNameInput.value.trim() : '';
        
        const items = [];
        const itemDivs = groupDiv.querySelectorAll(`#${groupDiv.id}_items > div[id^="item_"]`);
        for (const itemDiv of itemDivs) {
            const nameInput = itemDiv.querySelector('.itemNameInput');
            const quantityInput = itemDiv.querySelector('.itemQuantityInput');
            const amountInput = itemDiv.querySelector('.itemAmountInput');
            
            const itemName = nameInput ? nameInput.value.trim() : '';
            const quantity = quantityInput ? parseInt(quantityInput.value) || 1 : 1;
            const totalAmount = amountInput ? parseInt(amountInput.value) || 0 : 0;
            
            if (itemName && totalAmount > 0) {
                items.push({
                    name: itemName,
                    quantity: quantity,
                    totalAmount: totalAmount
                });
            }
        }
        
        if (groupName && items.length > 0) {
            yearlyActivities.push({
                name: groupName,
                items: items
            });
        }
    }
    
    const feeStructureData = {
        name: name,
        level: level,
        tuition: tuition,
        oneTimeActivities: oneTimeActivities,
        termlyActivities: termlyActivities,
        yearlyActivities: yearlyActivities,
        developmentComponents: []  // Empty array since we removed development fee
    };
    
    console.log('Saving fee structure:', feeStructureData);
    
    const submitBtn = document.querySelector('#addFeeStructureModalForm button[type="submit"]');
    const originalText = submitBtn.innerText;
    submitBtn.innerText = 'Saving...';
    submitBtn.disabled = true;
    
    try {
        const response = await fetch('/api/fee/structures/enhanced', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(feeStructureData)
        });
        
        if (response.ok) {
            const result = await response.json();
            const oneTimeTotal = oneTimeActivities.reduce((sum, act) => 
                sum + act.items.reduce((s, i) => s + i.totalAmount, 0), 0);
            const termlyTotal = termlyActivities.reduce((sum, act) => 
                sum + act.items.reduce((s, i) => s + i.totalAmount, 0), 0);
            const yearlyTotal = yearlyActivities.reduce((sum, act) => 
                sum + act.items.reduce((s, i) => s + i.totalAmount, 0), 0);
            
            alert(`✅ Fee structure "${name}" saved successfully!\n\n📊 Summary:\n- Tuition: UGX ${tuition.toLocaleString()}/term\n- One-Time: UGX ${oneTimeTotal.toLocaleString()}\n- Termly: UGX ${termlyTotal.toLocaleString()}/term\n- Yearly: UGX ${yearlyTotal.toLocaleString()}`);
            closeModal();
            showFeeManagement();
        } else {
            const error = await response.json();
            alert('❌ Error saving fee structure: ' + (error.error || 'Unknown error'));
        }
    } catch (error) {
        console.error('Error:', error);
        alert('Network error: ' + error.message);
    } finally {
        submitBtn.innerText = originalText;
        submitBtn.disabled = false;
    }
}

