    const termlyTotalSpan = document.getElementById('modalTermlyTotal');
    if (termlyTotalSpan) termlyTotalSpan.innerHTML = `UGX ${termlyTotal.toLocaleString()}`;
    
    const yearlyTotalSpan = document.getElementById('modalYearlyTotal');
    if (yearlyTotalSpan) yearlyTotalSpan.innerHTML = `UGX ${yearlyTotal.toLocaleString()}`;
    
