// ==================== FIXED ADD ITEM TO GROUP FUNCTION ====================

function addItemToGroup(groupId, periodType) {
    const itemId = 'item_' + Date.now() + '_' + Math.random().toString(36).substr(2, 6);
    const html = `
        <div id="${itemId}" class="flex gap-2 items-center bg-gray-50 p-2 rounded-lg border mb-2">
            <input type="text" placeholder="Item name" 
                   class="flex-1 border rounded px-2 py-1 text-sm itemNameInput" 
                   data-item-id="${itemId}">
            <input type="number" placeholder="Qty" 
                   class="w-16 border rounded px-2 py-1 text-sm itemQuantityInput" 
                   value="1" min="1" data-item-id="${itemId}">
            <input type="number" placeholder="Total Amount" 
                   class="w-28 border rounded px-2 py-1 text-sm itemAmountInput" 
                   value="0" min="0" data-item-id="${itemId}"
                   oninput="updateModalTotals()" onchange="updateModalTotals()">
            <button type="button" onclick="removeItem('${itemId}', '${groupId}')" 
                    class="text-red-600 hover:text-red-800 px-1">
                <i class="fas fa-times"></i>
            </button>
        </div>
    `;
    
    const container = document.getElementById(`${groupId}_items`);
    if (!container) return;
    
    // Remove empty message
    const emptyMsg = container.querySelector('.text-center.text-gray-400');
    if (emptyMsg && emptyMsg.parentNode === container) {
        emptyMsg.remove();
    }
    
    container.insertAdjacentHTML('beforeend', html);
    
    // Add event listener to the amount input
    const amountInput = container.querySelector(`#${itemId} .itemAmountInput`);
    if (amountInput) {
        amountInput.addEventListener('input', function() {
            updateModalTotals();
        });
        amountInput.addEventListener('change', function() {
            updateModalTotals();
        });
    }
    
    // Also listen to quantity input changes
    const quantityInput = container.querySelector(`#${itemId} .itemQuantityInput`);
    if (quantityInput) {
        quantityInput.addEventListener('input', function() {
            updateModalTotals();
        });
    }
    
    updateModalTotals();
}

