// Function to add an item to a group
function addItemToGroup(groupId, periodType) {
    const itemId = 'item_' + Date.now() + '_' + Math.random().toString(36).substr(2, 6);
    const html = `
        <div id="${itemId}" class="flex gap-2 items-center bg-gray-50 p-2 rounded-lg border">
            <input type="text" placeholder="Item name (e.g., Brooms)" 
                   class="flex-1 border rounded px-2 py-1 text-sm itemName">
            <input type="number" placeholder="Quantity" 
                   class="w-20 border rounded px-2 py-1 text-sm itemQuantity" value="1" min="1">
            <input type="number" placeholder="Total Amount (UGX)" 
                   class="w-28 border rounded px-2 py-1 text-sm itemTotalAmount" value="0" min="0"
                   oninput="updateModalTotals()">
            <button type="button" onclick="removeItemFromGroup('${itemId}', '${groupId}')" 
                    class="text-red-600 hover:text-red-800 px-1">
                <i class="fas fa-times"></i>
            </button>
        </div>
    `;
    
    const container = document.getElementById(`${groupId}_items`);
    const emptyMsg = container.querySelector('.text-center.text-gray-400');
    if (emptyMsg && emptyMsg.parentNode === container && container.children.length === 1) {
        emptyMsg.remove();
    }
    container.insertAdjacentHTML('beforeend', html);
    
    // Store reference in the appropriate temp array
    let targetArray;
    if (periodType === 'one_time') {
        targetArray = window.tempOneTimeActivities;
    } else if (periodType === 'termly') {
        targetArray = window.tempTermlyActivities;
    } else {
        targetArray = window.tempYearlyActivities;
    }
    
    const group = targetArray.find(g => g.groupId === groupId);
    if (group) {
        group.items.push({
            itemId: itemId,
            name: '',
            quantity: 1,
            totalAmount: 0
        });
    }
    
    updateModalTotals();
}

// Function to remove an item from a group
function removeItemFromGroup(itemId, groupId) {
    const element = document.getElementById(itemId);
    if (element) element.remove();
    
    // Find and remove from temp array
    for (const periodType of ['one_time', 'termly', 'yearly']) {
        let targetArray;
        if (periodType === 'one_time') targetArray = window.tempOneTimeActivities;
        else if (periodType === 'termly') targetArray = window.tempTermlyActivities;
        else targetArray = window.tempYearlyActivities;
        
        const group = targetArray.find(g => g.groupId === groupId);
        if (group) {
            group.items = group.items.filter(i => i.itemId !== itemId);
            break;
        }
    }
    
    updateModalTotals();
    updateEmptyMessages();
}

// Function to remove an entire activity group
function removeOneTimeActivityGroup(groupId) {
    const element = document.getElementById(groupId);
    if (element) element.remove();
    
    window.tempOneTimeActivities = window.tempOneTimeActivities.filter(g => g.groupId !== groupId);
    updateModalTotals();
    updateEmptyMessages();
}

