// Replace the updateCollectionTotal function with this fixed version
function updateCollectionTotal() {
    console.log('updateCollectionTotal called');
    
    const tuitionInput = document.getElementById('tuitionAmount');
    const tuition = tuitionInput ? parseInt(tuitionInput.value) || 0 : 0;
    
    let termlyTotal = 0;
    const termlyTotalSpan = document.getElementById('termlyTotalAmount');
    if (termlyTotalSpan) {
        const termlyText = termlyTotalSpan.innerText;
        termlyTotal = parseInt(termlyText.replace(/[^0-9]/g, '')) || 0;
    }
    
    let yearlyTotal = 0;
    const yearlyTotalSpan = document.getElementById('yearlyTotalAmount');
    if (yearlyTotalSpan) {
        const yearlyText = yearlyTotalSpan.innerText;
        yearlyTotal = parseInt(yearlyText.replace(/[^0-9]/g, '')) || 0;
    }
    
    const grandTotal = tuition + termlyTotal + yearlyTotal;
    
    const summaryTuition = document.getElementById('summaryTuition');
    const summaryTermly = document.getElementById('summaryTermly');
    const summaryYearly = document.getElementById('summaryYearly');
    const summaryTotal = document.getElementById('summaryTotal');
    const outstandingSpan = document.getElementById('outstandingAfter');
    
    if (summaryTuition) summaryTuition.innerHTML = `UGX ${tuition.toLocaleString()}`;
    if (summaryTermly) summaryTermly.innerHTML = `UGX ${termlyTotal.toLocaleString()}`;
    if (summaryYearly) summaryYearly.innerHTML = `UGX ${yearlyTotal.toLocaleString()}`;
    if (summaryTotal) summaryTotal.innerHTML = `UGX ${grandTotal.toLocaleString()}`;
    
    // Use the stored student data
    const expected = window.currentCollectingStudent?.totalExpected || 0;
    const currentPaid = window.currentCollectingStudent?.totalPaid || 0;
    const totalAfterPayment = currentPaid + grandTotal;
    const balanceAfter = expected - totalAfterPayment;
    
    if (outstandingSpan) {
        if (balanceAfter > 0) {
            outstandingSpan.innerHTML = `UGX ${balanceAfter.toLocaleString()}`;
            outstandingSpan.className = 'font-bold text-xl text-red-600';
        } else if (balanceAfter < 0) {
            outstandingSpan.innerHTML = `Credit: UGX ${Math.abs(balanceAfter).toLocaleString()}`;
            outstandingSpan.className = 'font-bold text-xl text-blue-600';
        } else {
            outstandingSpan.innerHTML = 'Fully Paid';
            outstandingSpan.className = 'font-bold text-xl text-green-600';
        }
    }
}

// Alias for calculateCollectionTotal to handle both function names

// Function to update period totals (supports being called with or without periodType)
function updatePeriodTotal() {
    const periodTypes = ['one_time', 'termly', 'yearly'];
    
    periodTypes.forEach(periodType => {
        let total = 0;
        
        const items = document.querySelectorAll(`#${periodType}ItemsList .cashAmount, #${periodType}ItemsList .itemsBrought`);
        
        items.forEach(input => {
            const itemId = input.dataset.itemId;
            const unitPrice = parseFloat(input.dataset.unitPrice) || 0;
            let amount = 0;
            
            const cashInputGroup = document.getElementById(`cashInput_${itemId}`);
            const itemInputGroup = document.getElementById(`itemInput_${itemId}`);
            
            if (cashInputGroup && !cashInputGroup.classList.contains('hidden')) {
                let cashAmount = parseFloat(input.value) || 0;
                const maxAmount = parseFloat(input.dataset.max) || null;
                if (cashAmount < 0) cashAmount = 0;
                if (maxAmount !== null && Number.isFinite(maxAmount)) cashAmount = Math.min(cashAmount, maxAmount);
                input.value = cashAmount ? cashAmount : '';
                amount = cashAmount;
            } else if (itemInputGroup && !itemInputGroup.classList.contains('hidden')) {
                let itemsCount = parseInt(input.value) || 0;
                const maxQty = parseInt(input.max) || parseInt(input.dataset.quantity) || 0;
                if (itemsCount < 0) itemsCount = 0;
                if (maxQty > 0) itemsCount = Math.min(itemsCount, maxQty);
                input.value = itemsCount ? itemsCount : '';
                amount = itemsCount * unitPrice;
            }
            
            total += amount;
        });
        
        const totalSpan = document.getElementById(`${periodType}TotalSelected`);
        if (totalSpan) totalSpan.innerHTML = `UGX ${total.toLocaleString()}`;
    });
    
    updateCollectionTotal();
}

// Function to update item total when cash or items are entered (with caps + “That’s to say”)
function updateItemTotal(itemId, type, unitPrice, maxQuantity) {
    let amount = 0;
    let itemsCovered = 0;
    
    if (type === 'cash') {
        const cashInput = document.querySelector(`#cashInput_${itemId} input.cashAmount`);
        let cashAmount = parseFloat(cashInput?.value) || 0;
        const maxAmount = parseFloat(cashInput?.dataset?.max) || null;
        if (cashAmount < 0) cashAmount = 0;
        if (maxAmount !== null && Number.isFinite(maxAmount)) cashAmount = Math.min(cashAmount, maxAmount);
        if (cashInput) cashInput.value = cashAmount ? cashAmount : '';
        amount = cashAmount;
        itemsCovered = unitPrice > 0 ? (cashAmount / unitPrice) : 0;
    } else {
        const itemsInput = document.querySelector(`#itemInput_${itemId} input.itemsBrought`);
        let itemsCount = parseInt(itemsInput?.value) || 0;
        if (itemsCount < 0) itemsCount = 0;
        itemsCovered = Math.min(itemsCount, maxQuantity);
        if (itemsInput) itemsInput.value = itemsCovered ? itemsCovered : '';
        amount = itemsCovered * unitPrice;
    }
    
    const totalSpan = document.getElementById(`itemTotal_${itemId}`);
    if (totalSpan) totalSpan.innerHTML = `UGX ${amount.toLocaleString()}`;
    
    const tts = document.getElementById(`thatToSay_${itemId}`);
    if (tts) {
        if (type === 'cash') {
            tts.innerHTML = amount > 0 ? `That’s to say: ~${itemsCovered.toFixed(2)} items` : '';
        } else {
            tts.innerHTML = itemsCovered > 0 ? `That’s to say: UGX ${amount.toLocaleString()} for ${itemsCovered} items` : '';
        }
    }
    
    updatePeriodTotal();
}

// Make sure all functions are global
window.updateCollectionTotal = updateCollectionTotal;
window.calculateCollectionTotal = calculateCollectionTotal;
window.updatePeriodTotal = updatePeriodTotal;
window.updateItemTotal = updateItemTotal;

// ==================== FINAL OVERRIDES: 3-PERIOD FEE MODEL ====================
const PERIOD_KEYS = ['one_time', 'termly', 'yearly'];
const PERIOD_LABELS = { one_time: 'One-Time', termly: 'Termly', yearly: 'Yearly' };

function _sumPeriodPayments(paymentsByPeriodType, periodKey) {
    return (paymentsByPeriodType?.[periodKey] || []).reduce((s, i) => s + (i.amountPaid || i.cashEquivalent || 0), 0);
}

function _sumPeriodItems(itemsByPeriodType, periodKey) {
    return (itemsByPeriodType?.[periodKey] || []).reduce((s, i) => s + (i.itemsBrought || 0), 0);
}

function _safeCsv(val) {
    const v = val === null || val === undefined ? '' : String(val);
    return `"${v.replace(/"/g, '""')}"`;
}

async function _buildFeeContext() {
    const { currentYear, currentTerm } = currentAcademicSettings;
    const [studentsRes, classesRes, structuresRes, assignmentsRes, paymentsRes, recordsRes] = await Promise.all([
        fetch(`/api/students?year=${currentYear}`),
        fetch('/api/school/classes'),
        fetch('/api/fee/structures'),
        fetch('/api/student-fee-assignments'),
        fetch(`/api/fee/payments?year=${currentYear}&term=${currentTerm}`),
        fetch('/api/student-term-records').catch(() => ({ ok: false, json: async () => ({}) }))
    ]);

    const students = await studentsRes.json();
    const classes = await classesRes.json();
    const feeStructures = await structuresRes.json();
    const assignments = await assignmentsRes.json();
    const payments = await paymentsRes.json();
    const termRecords = recordsRes.ok ? await recordsRes.json() : {};

    const clsById = Object.fromEntries(classes.map(c => [c.id, c]));
    const fsById = Object.fromEntries(feeStructures.map(f => [f.id, f]));
    const assignmentByStudent = Object.fromEntries(assignments.map(a => [a.studentId, a]));

    const enriched = students.map(st => {
        const assignment = assignmentByStudent[st.id] || {};
        const fs = fsById[assignment.feeStructureId] || null;
        const classObj = st.currentClassId ? clsById[st.currentClassId] : null;
        const className = classObj?.name || st.currentClass || 'N/A';

        const oneTimeActivities = fs?.oneTimeActivities || [];
        const termlyActivities = fs?.termlyActivities || [];
        const yearlyActivities = fs?.yearlyActivities || [];
        const isFirstTerm = Number(currentTerm) === 1;

        const oneTimeExpectedRaw = oneTimeActivities.reduce((s, c) => s + (c.totalAmount || 0), 0);
        const termlyExpectedRaw = termlyActivities.reduce((s, c) => s + (c.totalAmount || 0), 0);
        const yearlyExpectedRaw = yearlyActivities.reduce((s, c) => s + (c.totalAmount || 0), 0);

        const oneTimeExpected = isFirstTerm ? oneTimeExpectedRaw : 0;
        const termlyExpected = termlyExpectedRaw;
        const yearlyExpected = isFirstTerm ? yearlyExpectedRaw : 0;
        const tuitionExpected = fs?.tuition || 0;

        const myPayments = payments.filter(p => p.studentId === st.id);
        const tuitionPaid = myPayments.reduce((s, p) => s + (p.tuitionPaid || 0), 0);
        const oneTimePaidFromPayments = myPayments.reduce((s, p) => s + _sumPeriodPayments(p.paymentsByPeriodType, 'one_time'), 0);
        const termlyPaidFromPayments = myPayments.reduce((s, p) => s + _sumPeriodPayments(p.paymentsByPeriodType, 'termly'), 0);
        const yearlyPaidFromPayments = myPayments.reduce((s, p) => s + _sumPeriodPayments(p.paymentsByPeriodType, 'yearly'), 0);

        const recordKey = `${st.id}_${currentYear}_${currentTerm}`;
        const termRecord = termRecords?.[recordKey] || {};
        const recordByPeriod = termRecord.activityItemsPaid || { one_time: [], termly: [], yearly: [] };

        const oneTimePaid = Math.max(oneTimePaidFromPayments, _sumPeriodPayments(recordByPeriod, 'one_time'));
        const termlyPaid = Math.max(termlyPaidFromPayments, _sumPeriodPayments(recordByPeriod, 'termly'));
        const yearlyPaid = Math.max(yearlyPaidFromPayments, _sumPeriodPayments(recordByPeriod, 'yearly'));

        const totalExpected = tuitionExpected + oneTimeExpected + termlyExpected + yearlyExpected;
        const totalPaid = tuitionPaid + oneTimePaid + termlyPaid + yearlyPaid;
        const balance = totalExpected - totalPaid;

        return {
            ...st,
            feeStructure: fs,
            currentClass: className,
            expectedTuition: tuitionExpected,
            oneTimeTotal: oneTimeExpected,
            termlyTotal: termlyExpected,
            yearlyTotal: yearlyExpected,
            tuitionPaid,
            oneTimePaid,
            termlyPaid,
            yearlyPaid,
            totalPaidThisTerm: totalPaid,
            expectedThisTerm: totalExpected,
            balance,
            status: balance <= 0 ? 'Good Standing' : (balance > (termlyExpected || 0) ? 'Critical Overdue' : 'Partial Payment'),
            statusColor: balance <= 0 ? 'bg-green-100 text-green-800' : (balance > (termlyExpected || 0) ? 'bg-red-100 text-red-800' : 'bg-orange-100 text-orange-800'),
            _termRecord: termRecord,
            _payments: myPayments
        };
    });

    return { currentYear, currentTerm, students: enriched, classes, feeStructures, payments, termRecords };
}

function renderPaymentHistoryRows(payments) {
    if (!payments || payments.length === 0) return '<tr><td colspan="10" class="text-center p-8 text-gray-500">No payment records found</td></tr>';
    return payments.slice().reverse().map(p => {
        const oneTimePaid = _sumPeriodPayments(p.paymentsByPeriodType, 'one_time');
        const termlyPaid = _sumPeriodPayments(p.paymentsByPeriodType, 'termly');
        const yearlyPaid = _sumPeriodPayments(p.paymentsByPeriodType, 'yearly');
        return `<tr class="border-b hover:bg-gray-50">
            <td class="p-3">${p.date ? new Date(p.date).toLocaleDateString() : 'N/A'}</td>
            <td class="p-3 font-mono text-sm font-semibold text-blue-600">${p.receiptNumber || 'N/A'}</td>
            <td class="p-3">${p.studentName || 'N/A'}</td>
            <td class="p-3 text-right">UGX ${(p.tuitionPaid || 0).toLocaleString()}</td>
            <td class="p-3 text-right">UGX ${oneTimePaid.toLocaleString()}</td>
            <td class="p-3 text-right">UGX ${termlyPaid.toLocaleString()}</td>
            <td class="p-3 text-right">UGX ${yearlyPaid.toLocaleString()}</td>
            <td class="p-3 text-right font-bold">UGX ${(p.totalAmount || 0).toLocaleString()}</td>
            <td class="p-3 capitalize">${p.method || 'cash'}</td>
            <td class="p-3"><button onclick="viewPaymentReceipt('${p.id}')" class="text-blue-600 hover:text-blue-800"><i class="fas fa-print"></i></button></td>
        </tr>`;
    }).join('');
}

