async function showPerformanceAnalysis() {
    const pageTitle = document.getElementById('pageTitle');
    if (pageTitle) pageTitle.innerHTML = '<i class="fas fa-chart-line mr-2"></i>Performance Analysis';
    const mainContent = document.getElementById('mainContent');
    if (mainContent) mainContent.innerHTML = '<div class="p-6">Loading...</div>';
    try {
        const ctx = await _buildFeeContext();
        const sts = ctx.students;
        const avg = (arr, keyE, keyP) => {
            const e = arr.reduce((s, x) => s + (x[keyE] || 0), 0);
            const p = arr.reduce((s, x) => s + (x[keyP] || 0), 0);
            return e > 0 ? ((p / e) * 100).toFixed(1) : '0.0';
        };
        const fully = sts.filter(s => s.balance <= 0).length;
        const partial = sts.filter(s => s.balance > 0 && s.totalPaidThisTerm > 0).length;
        const critical = sts.filter(s => s.balance > 0 && s.totalPaidThisTerm === 0).length;

        const compRate = (period) => {
            const all = sts.reduce((sum, s) => {
                const src = period === 'one_time' ? (s.feeStructure?.oneTimeActivities || []) : period === 'termly' ? (s.feeStructure?.termlyActivities || []) : (s.feeStructure?.yearlyActivities || []);
                return sum + src.reduce((x, c) => x + (c.items || []).length, 0);
            }, 0);
            const done = sts.reduce((sum, s) => sum + ((s._termRecord?.activityItemsPaid?.[period] || []).filter(i => i.status === 'fully_paid').length), 0);
            return all > 0 ? ((done / all) * 100).toFixed(1) : '0.0';
        };

        mainContent.innerHTML = `<div class="space-y-6">
            <div class="bg-white rounded-xl p-6 shadow-sm">
                <h2 class="font-bold text-xl mb-4">Academic Performance</h2>
                <p class="text-sm text-gray-600">Use class performance page for score analytics.</p>
            </div>
            <div class="bg-white rounded-xl p-6 shadow-sm">
                <h2 class="font-bold text-xl mb-4">Fee Performance</h2>
                <div class="grid grid-cols-1 md:grid-cols-2 gap-3 text-sm">
                    <div>Tuition Collection Rate: <b>${avg(sts, 'expectedTuition', 'tuitionPaid')}%</b></div>
                    <div>One-Time Collection Rate: <b>${avg(sts, 'oneTimeTotal', 'oneTimePaid')}%</b></div>
                    <div>Termly Collection Rate: <b>${avg(sts, 'termlyTotal', 'termlyPaid')}%</b></div>
                    <div>Yearly Collection Rate: <b>${avg(sts, 'yearlyTotal', 'yearlyPaid')}%</b></div>
                </div>
                <div class="mt-4 grid grid-cols-1 md:grid-cols-3 gap-3">
                    <div class="p-3 bg-green-50 rounded">Fully Paid: <b>${fully}</b></div>
                    <div class="p-3 bg-yellow-50 rounded">Partial Payment: <b>${partial}</b></div>
                    <div class="p-3 bg-red-50 rounded">Critical Overdue: <b>${critical}</b></div>
                </div>
                <div class="mt-4 grid grid-cols-1 md:grid-cols-3 gap-3 text-sm">
                    <div>One-Time Items Completed: <b>${compRate('one_time')}%</b></div>
                    <div>Termly Items Completed: <b>${compRate('termly')}%</b></div>
                    <div>Yearly Items Completed: <b>${compRate('yearly')}%</b></div>
                </div>
            </div>
        </div>`;
    } catch (e) {
        mainContent.innerHTML = `<div class="p-6 text-red-600">Failed to load performance analysis: ${e.message}</div>`;
    }
}

async function showTranscript() {
    const pageTitle = document.getElementById('pageTitle');
    if (pageTitle) pageTitle.innerHTML = '<i class="fas fa-scroll mr-2"></i>Student Transcript';
    const mainContent = document.getElementById('mainContent');
    const students = await (await fetch('/api/students')).json();
    mainContent.innerHTML = `<div class="bg-white rounded-xl shadow-sm p-6">
        <h2 class="text-xl font-bold mb-4">Student Transcript + Fee History</h2>
        <div class="mb-4"><select id="transcriptStudent" class="w-full md:w-1/2 border rounded-lg px-3 py-2">
            <option value="">Choose Student</option>${students.map(s => `<option value="${s.id}">${s.admissionNumber} - ${s.firstName} ${s.lastName}</option>`).join('')}
        </select></div>
        <button onclick="generateTranscript()" class="bg-purple-600 text-white px-6 py-2 rounded-lg">Generate</button>
        <div id="transcriptResult" class="mt-6"></div>
    </div>`;
    window.generateTranscript = async () => {
        const studentId = document.getElementById('transcriptStudent').value;
        if (!studentId) return alert('Select a student');
        const payments = await (await fetch('/api/fee/payments/student/' + studentId)).json();
        const byYearTerm = {};
        payments.forEach(p => {
            const y = p.academicYear || 'Unknown';
            const t = p.term || 'N/A';
            if (!byYearTerm[y]) byYearTerm[y] = {};
            if (!byYearTerm[y][t]) byYearTerm[y][t] = { tuition: 0, one_time: 0, termly: 0, yearly: 0 };
            byYearTerm[y][t].tuition += (p.tuitionPaid || 0);
            byYearTerm[y][t].one_time += _sumPeriodPayments(p.paymentsByPeriodType, 'one_time');
            byYearTerm[y][t].termly += _sumPeriodPayments(p.paymentsByPeriodType, 'termly');
            byYearTerm[y][t].yearly += _sumPeriodPayments(p.paymentsByPeriodType, 'yearly');
        });
        const rows = Object.keys(byYearTerm).sort().reverse().map(y => Object.keys(byYearTerm[y]).sort((a, b) => Number(a) - Number(b)).map(t => {
            const v = byYearTerm[y][t];
            return `<tr><td class="p-2 border">${y}</td><td class="p-2 border">${t}</td><td class="p-2 border text-right">UGX ${v.tuition.toLocaleString()}</td><td class="p-2 border text-right">UGX ${v.one_time.toLocaleString()}</td><td class="p-2 border text-right">UGX ${v.termly.toLocaleString()}</td><td class="p-2 border text-right">UGX ${v.yearly.toLocaleString()}</td></tr>`;
        }).join('')).join('');
        document.getElementById('transcriptResult').innerHTML = `<h3 class="font-bold mb-3">Fee Payment History</h3>
            <table class="w-full text-sm"><thead><tr class="bg-gray-100"><th class="p-2 border">Year</th><th class="p-2 border">Term</th><th class="p-2 border">Tuition</th><th class="p-2 border">One-Time</th><th class="p-2 border">Termly</th><th class="p-2 border">Yearly</th></tr></thead><tbody>${rows || '<tr><td colspan="6" class="p-3 text-center border">No fee history</td></tr>'}</tbody></table>`;
    };
}

