// ==================== TOGGLE ITEM HISTORY (FIXED) ====================

function toggleItemHistory(itemId) {
    // Initialize expandedItems if not exists
    if (typeof window.expandedItems === 'undefined') {
        window.expandedItems = {};
    }
    
    // Find the element by ID
    var element = document.getElementById(itemId);
    if (!element) {
        console.warn('Element not found for ID:', itemId);
        return;
    }
    
    // Toggle the expanded state
    window.expandedItems[itemId] = !window.expandedItems[itemId];
    element.classList.toggle('hidden');
    
    // Find the parent cell and update the button
    var parentCell = element.closest('td');
    if (parentCell) {
        var button = parentCell.querySelector('button');
        if (button) {
            // Get the count of history items
            var historyItems = element.querySelectorAll('.flex.justify-between.py-0\\.5').length;
            
            // Update button text
            button.innerHTML = '';
            var icon = document.createElement('i');
            icon.className = window.expandedItems[itemId] ? 'fas fa-chevron-up' : 'fas fa-chevron-down';
            button.appendChild(icon);
            var textNode = document.createTextNode(' ' + (window.expandedItems[itemId] ? 'Hide' : 'View') + ' History (' + historyItems + ')');
            button.appendChild(textNode);
        }
        
        // Also update the clickable div above
        var clickableDiv = parentCell.querySelector('.cursor-pointer');
        if (clickableDiv) {
            // Optional: change appearance when expanded
        }
    }
}

// ==================== ATTACH EXPAND HANDLERS (FIXED) ====================

function attachExpandHandlers() {
    // Add click handlers for any cells with payment history
    document.querySelectorAll('#reportTable td .cursor-pointer').forEach(function(cell) {
        // Remove any existing listeners to avoid duplicates
        cell.removeEventListener('click', handleCellClick);
        cell.addEventListener('click', handleCellClick);
    });
}

function handleCellClick(e) {
    // Find the parent td
    var parentTd = this.closest('td');
    if (!parentTd) return;
    
    // Find the toggle button within this td
    var button = parentTd.querySelector('button');
    if (button) {
        // Trigger the button click to toggle history
        button.click();
    }
}

