/**
 * Enhanced Excel Export Function - Professional School Report
 * Version: 16.0 - STATUS DISPLAY FIXED
 * 
 * WHAT CHANGED FROM v15.0
 * ------------------------------------------------------------------
 * In the Student Details view, items brought in hand show "✅ Brought"
 * while cash payments show "✅ Paid". This fix applies the same logic
 * to the Excel export:
 * 
 *   - If paymentOption === 'item_only' and fully paid → "✅ Brought"
 *   - If paymentOption === 'cash_only' and fully paid → "✅ Paid"
 *   - If paymentOption === 'either':
 *       - If fully paid by items only → "✅ Brought (Items Only)"
 *       - If fully paid by cash only → "✅ Paid (Cash Only)"
 *       - If fully paid by both → "✅ Paid (Cash + Items)"
 *   - Partial → "⚠️ Partial"
 *   - Unpaid → "❌ Unpaid"
 * 
 * This ensures the Excel export EXACTLY matches the Student Details view.
 */

// ==================== COMPLETE REBUILT EXCEL EXPORT ====================
// Version: 19.0 - FULLY FIXED - EXACT MATCH WITH VIEW STUDENT DETAILS

function exportReportToCSV() {
    console.log('=== 📊 EXCEL EXPORT v10.0 - FULLY FIXED WITH ITEMS STATISTICS ===');
    
    // ================================================================
    // STEP 1: VALIDATE DATA
    // ================================================================
    if (!reportData || !reportData.students || reportData.students.length === 0) {
        showToast('❌ No data to export. Please generate a report first.', 'error');
        return;
    }

    try {
        // ================================================================
        // STEP 2: EXTRACT DATA
        // ================================================================
        var students = reportData.students || [];
        var totals = reportData.totals || {};
        var filters = reportData.filters || {};
        var metadata = reportData.metadata || {};
        
        var currentYear = currentAcademicSettings.currentYear || new Date().getFullYear();
        var currentTerm = currentAcademicSettings.currentTerm || 1;
        
        var includeTuition = filters.includeTuition !== false;
        var filterStatusGroup = filters.statusGroup || 'all';
        var filterItem = filters.itemName || 'all';
        var isTuitionOnly = filterStatusGroup === 'none';
        var periodsIncluded = metadata.periodsIncluded || [];

        console.log('📋 Export Settings:', {
            students: students.length,
            includeTuition: includeTuition,
            periods: periodsIncluded,
            currentYear: currentYear,
            currentTerm: currentTerm
        });

        // ================================================================
        // STEP 3: HELPER FUNCTIONS
        // ================================================================
        
        function formatMoney(amount) {
            var num = Math.round(amount || 0);
            return num.toLocaleString('en-US');
        }

        function escapeHtml(text) {
            if (!text) return '';
            var div = document.createElement('div');
            div.textContent = text;
            return div.innerHTML;
        }

        function getTermName(term) {
            var names = { 1: 'First Term', 2: 'Second Term', 3: 'Third Term' };
            return names[term] || 'Term ' + term;
        }

        function getTermShort(term) {
            var names = { 1: 'T1', 2: 'T2', 3: 'T3' };
            return names[term] || 'T' + term;
        }

        function getStatusGroupDisplayName(name) {
            if (!name) return 'Other';
            if (name === 'schoolastic requirement') return 'Scholastic';
            if (name === 'Admission Fee') return 'Admission';
            if (name === 'Tuition') return 'Tuition';
            if (name === 'Transportation') return 'Transportation';
            if (name === 'Uniform') return 'Uniform';
            if (name === 'Development Fee') return 'Development';
            return name;
        }

        // ================================================================
        // STEP 4: SAFE GETTER FUNCTIONS
        // ================================================================

        function safeGet(obj, path, defaultValue) {
            if (!obj) return defaultValue;
            var parts = path.split('.');
            var current = obj;
            for (var i = 0; i < parts.length; i++) {
                if (current === null || current === undefined || typeof current !== 'object') {
                    return defaultValue;
                }
                current = current[parts[i]];
            }
            return current !== undefined && current !== null ? current : defaultValue;
        }

        function safeGetStudentInfo(student, field, defaultValue) {
            if (!student) return defaultValue;
            return safeGet(student, field, defaultValue);
        }

        function safeGetItemData(student, groupName, itemName) {
            if (!student) return null;
            if (!student.statusGroups) return null;
            var group = student.statusGroups[groupName];
            if (!group) return null;
            if (!group.items) return null;
            return group.items[itemName] || null;
        }

        function safeGetComponentName(student, groupName) {
            if (!student) return groupName || 'Unknown';
            if (!student.statusGroups) return groupName || 'Unknown';
            var group = student.statusGroups[groupName];
            if (!group) return groupName || 'Unknown';
            return group.componentName || groupName || 'Unknown';
        }

        // ================================================================
        // STEP 5: CORE FUNCTIONS WITH PERMANENT FIXES
        // ================================================================

        // 5.1: Get Period Scoped Payments (PERMANENT FIX FOR YEARLY ITEMS)
        function getPeriodScopedPayments(studentId, periodType, year, term, allPayments) {
            if (!allPayments || !Array.isArray(allPayments)) {
                return [];
            }
            
            var studentPayments = allPayments.filter(function(p) { 
                return p && p.studentId === studentId; 
            });
            
            if (periodType === 'one_time') {
                // One-Time: Check ALL payments FOREVER
                return studentPayments;
            } else if (periodType === 'yearly') {
                // ✅ PERMANENT FIX: Yearly - Check ALL terms in the SAME academic year
                return studentPayments.filter(function(p) {
                    return p && p.academicYear && parseInt(p.academicYear) === year;
                });
            } else {
                // Termly: Check ONLY the CURRENT term
                return studentPayments.filter(function(p) {
                    return p && p.term === term && p.academicYear && parseInt(p.academicYear) === year;
                });
            }
        }

        // 5.2: Get Item Payments (PERMANENT FIX)
        function getItemPayments(studentId, componentName, itemName, periodType, year, term, allPayments) {
            if (!studentId || !componentName || !itemName) {
                return [];
            }
            
            var scopedPayments = getPeriodScopedPayments(studentId, periodType, year, term, allPayments);
            var itemPayments = [];
            var processedKeys = new Set();
            
            for (var p = 0; p < scopedPayments.length; p++) {
                var payment = scopedPayments[p];
                if (!payment) continue;
                
                // Check activityItemPayments
                if (payment.activityItemPayments && Array.isArray(payment.activityItemPayments)) {
                    for (var i = 0; i < payment.activityItemPayments.length; i++) {
                        var paidItem = payment.activityItemPayments[i];
                        if (!paidItem) continue;
                        
                        var compMatch = paidItem.componentName && 
                            paidItem.componentName.toLowerCase() === componentName.toLowerCase();
                        var itemMatch = paidItem.itemName && 
                            paidItem.itemName.toLowerCase() === itemName.toLowerCase();
                        
                        if (compMatch && itemMatch) {
                            var key = (payment.receiptNumber || '') + '_' + (paidItem.itemName || '') + '_' + (paidItem.componentName || '');
                            if (!processedKeys.has(key)) {
                                processedKeys.add(key);
                                itemPayments.push({
                                    payment: payment,
                                    paidItem: paidItem
                                });
                            }
                        }
                    }
                }
                
                // Check paymentsByPeriodType
                if (payment.paymentsByPeriodType) {
                    var periodTypes = ['one_time', 'termly', 'yearly'];
                    for (var pt = 0; pt < periodTypes.length; pt++) {
                        var periodItems = payment.paymentsByPeriodType[periodTypes[pt]] || [];
                        for (var i = 0; i < periodItems.length; i++) {
                            var paidItem = periodItems[i];
                            if (!paidItem) continue;
                            
                            var compMatch = paidItem.componentName && 
                                paidItem.componentName.toLowerCase() === componentName.toLowerCase();
                            var itemMatch = paidItem.itemName && 
                                paidItem.itemName.toLowerCase() === itemName.toLowerCase();
                            
                            if (compMatch && itemMatch) {
                                var key = (payment.receiptNumber || '') + '_' + (paidItem.itemName || '') + '_' + (paidItem.componentName || '');
                                if (!processedKeys.has(key)) {
                                    processedKeys.add(key);
                                    itemPayments.push({
                                        payment: payment,
                                        paidItem: paidItem,
                                        periodTypeFromPayment: periodTypes[pt]
                                    });
                                }
                            }
                        }
                    }
                }
            }
            
            return itemPayments;
        }

        // 5.3: Calculate Item Totals with OR Logic
        function calculateItemTotals(itemPayments, qtyRequired, amountExpected, paymentOption) {
            var cashPaid = 0;
            var itemsBrought = 0;
            var paymentHistories = [];
            var processedKeys = new Set();
            
            qtyRequired = qtyRequired || 0;
            amountExpected = amountExpected || 0;
            paymentOption = paymentOption || 'either';
            
            if (!itemPayments || !Array.isArray(itemPayments)) {
                itemPayments = [];
            }
            
            // Extract payments
            for (var i = 0; i < itemPayments.length; i++) {
                var data = itemPayments[i];
                if (!data) continue;
                
                var payment = data.payment;
                var paidItem = data.paidItem;
                if (!payment || !paidItem) continue;
                
                var key = (payment.receiptNumber || '') + '_' + (paidItem.itemName || '') + '_' + (paidItem.componentName || '');
                if (processedKeys.has(key)) continue;
                processedKeys.add(key);
                
                if (paidItem.paymentType === 'paid_cash') {
                    var amount = paidItem.amountPaid || 0;
                    cashPaid += amount;
                    paymentHistories.push({
                        type: 'cash',
                        amount: amount,
                        date: payment.date || new Date().toISOString(),
                        receiptNumber: payment.receiptNumber || 'N/A',
                        method: payment.method || 'cash'
                    });
                } else if (paidItem.paymentType === 'brought_item') {
                    var qty = paidItem.itemsBrought || 0;
                    itemsBrought += qty;
                    paymentHistories.push({
                        type: 'item',
                        quantity: qty,
                        date: payment.date || new Date().toISOString(),
                        receiptNumber: payment.receiptNumber || 'N/A'
                    });
                }
            }
            
            // ========== APPLY OR LOGIC ==========
            var cashExpected = 0;
            var finalCashPaid = 0;
            var finalItemsBrought = Math.min(itemsBrought, qtyRequired);
            var unitPrice = qtyRequired > 0 ? (amountExpected / qtyRequired) : 0;
            
            if (paymentOption === 'cash_only') {
                cashExpected = amountExpected;
                finalCashPaid = Math.min(cashPaid, amountExpected);
            } else if (paymentOption === 'item_only') {
                cashExpected = 0;
                finalCashPaid = 0;
            } else {
                // 'either' - OR Logic
                var itemsCoverFull = finalItemsBrought >= qtyRequired;
                
                if (itemsCoverFull) {
                    cashExpected = 0;
                    finalCashPaid = 0;
                } else {
                    var remainingQty = qtyRequired - finalItemsBrought;
                    cashExpected = Math.min(amountExpected, remainingQty * unitPrice);
                    finalCashPaid = Math.min(cashPaid, cashExpected);
                }
            }
            
            // ============================================================
            // ✅ FIXED: Calculate remaining items correctly
            // ============================================================
            // Cash paid covers some items
            var itemsCoveredByCash = unitPrice > 0 ? Math.floor(finalCashPaid / unitPrice) : 0;
            var totalItemsCovered = finalItemsBrought + itemsCoveredByCash;
            var itemsRemaining = Math.max(0, qtyRequired - totalItemsCovered);
            var cashRemaining = cashExpected - finalCashPaid;
            var isFullyPaid = cashRemaining <= 0 && itemsRemaining <= 0;
            
            return {
                cashExpected: cashExpected,
                cashPaid: finalCashPaid,
                cashRemaining: cashRemaining,
                itemsBrought: finalItemsBrought,
                itemsRemaining: itemsRemaining,
                paymentHistories: paymentHistories,
                isFullyPaid: isFullyPaid,
                totalPayments: itemPayments.length
            };
        }

        // 5.4: Get Item Status Text
        function getItemStatusText(paymentOption, qtyCollected, qtyRequired, amtCollected, amountExpected) {
            paymentOption = paymentOption || 'either';
            qtyRequired = qtyRequired || 0;
            amountExpected = amountExpected || 0;
            qtyCollected = qtyCollected || 0;
            amtCollected = amtCollected || 0;
            
            // ✅ FIX: Cash Only - ONLY money matters
            if (paymentOption === 'cash_only') {
                if (amtCollected >= amountExpected && amountExpected > 0) {
                    return '✅ Paid';
                } else if (amtCollected > 0) {
                    return '⚠️ Partial';
                }
                return '❌ Unpaid';
            }
            
            // ✅ FIX: Item Only - ONLY items matter
            if (paymentOption === 'item_only') {
                if (qtyCollected >= qtyRequired && qtyRequired > 0) {
                    return '✅ Brought';
                } else if (qtyCollected > 0) {
                    return '⚠️ Partial';
                }
                return '❌ Unpaid';
            }
            
            // 'either' - OR Logic
            var isCashFullyPaid = amtCollected >= amountExpected && amountExpected > 0;
            var isItemFullyPaid = qtyCollected >= qtyRequired && qtyRequired > 0;
            
            if (isCashFullyPaid && isItemFullyPaid) {
                return '✅ Paid (Cash + Items)';
            }
            if (isCashFullyPaid) {
                return '✅ Paid (Cash Only)';
            }
            if (isItemFullyPaid) {
                return '✅ Brought (Items Only)';
            }
            
            if (amtCollected > 0 || qtyCollected > 0) {
                return '⚠️ Partial';
            }
            
            return '❌ Unpaid';
        }

        // 5.5: Get Item Detail Text
        function getItemDetailText(paymentOption, qtyCollected, qtyRequired, amtCollected, amountExpected, unitPrice) {
            paymentOption = paymentOption || 'either';
            qtyRequired = qtyRequired || 0;
            amountExpected = amountExpected || 0;
            qtyCollected = qtyCollected || 0;
            amtCollected = amtCollected || 0;
            unitPrice = unitPrice || 0;
            
            var parts = [];
            
            // ✅ FIX: Cash Only - ONLY show cash
            if (paymentOption === 'cash_only') {
                parts.push('Cash: UGX ' + formatMoney(amtCollected));
                parts.push('Expected: UGX ' + formatMoney(amountExpected));
                if (amtCollected >= amountExpected && amountExpected > 0) {
                    parts.push('✅ Fully Paid');
                } else if (amtCollected > 0) {
                    parts.push('⚠️ Partial');
                } else {
                    parts.push('❌ Unpaid');
                }
                return parts.join(' | ');
            }
            
            // ✅ FIX: Item Only - ONLY show items
            if (paymentOption === 'item_only') {
                parts.push('Items: ' + qtyCollected + '/' + qtyRequired);
                if (qtyCollected >= qtyRequired && qtyRequired > 0) {
                    parts.push('✅ Fully Brought');
                } else if (qtyCollected > 0) {
                    parts.push('⚠️ Partial');
                } else {
                    parts.push('❌ Unpaid');
                }
                return parts.join(' | ');
            }
            
            // 'either' - OR Logic
            if (amtCollected > 0) {
                parts.push('Cash: UGX ' + formatMoney(amtCollected));
            }
            if (qtyCollected > 0) {
                parts.push('Items: ' + qtyCollected);
            }
            if (amountExpected > 0) {
                parts.push('Expected: UGX ' + formatMoney(amountExpected));
            }
            if (qtyRequired > 0) {
                parts.push('Required: ' + qtyRequired);
            }
            
            var isCashFull = amtCollected >= amountExpected && amountExpected > 0;
            var isItemFull = qtyCollected >= qtyRequired && qtyRequired > 0;
            
            if (isCashFull && isItemFull) {
                parts.push('✅ Both (Cash + Items)');
            } else if (isItemFull) {
                parts.push('✅ Items Only');
            } else if (isCashFull) {
                parts.push('✅ Cash Only');
            } else if (amtCollected > 0 || qtyCollected > 0) {
                parts.push('⚠️ Partial');
            } else {
                parts.push('❌ Unpaid');
            }
            
            return parts.join(' | ');
        }

        // 5.6: Build Period Breakdown String (PERMANENT FIX)
        function buildPeriodBreakdownString(studentId, componentName, itemName, periodType, year, term, allPayments, qtyRequired, amountExpected, paymentOption) {
            if (!studentId || !componentName || !itemName) {
                return '—';
            }
            
            // Get payments with correct yearly scoping
            var itemPayments = getItemPayments(studentId, componentName, itemName, periodType, year, term, allPayments);
            var totals = calculateItemTotals(itemPayments, qtyRequired, amountExpected, paymentOption);
            
            var cashPaid = totals.cashPaid || 0;
            var itemsBrought = totals.itemsBrought || 0;
            var cashExpected = totals.cashExpected || 0;
            var cashRemaining = totals.cashRemaining || 0;
            var itemsRemaining = totals.itemsRemaining || 0;
            var isFullyPaid = totals.isFullyPaid || false;
            
            var termNames = { 1: 'First Term', 2: 'Second Term', 3: 'Third Term' };
            var termName = termNames[term] || 'Term ' + term;
            var isCurrent = (year === currentYear && term === currentTerm);
            var currentBadge = isCurrent ? ' ⭐' : '';
            
            // ============================================================
            // ✅ FIX: Build display text based on payment option
            // ============================================================
            var displayText = '';
            
            if (paymentOption === 'cash_only') {
                // Cash Only: ONLY show cash
                displayText = cashPaid > 0 ? 'UGX ' + formatMoney(cashPaid) : 'UGX 0';
                if (cashPaid < amountExpected && amountExpected > 0) {
                    displayText += ' / ' + formatMoney(amountExpected);
                }
                // ❌ NO items for cash_only
            } else if (paymentOption === 'item_only') {
                // Item Only: ONLY show items
                displayText = itemsBrought + '/' + qtyRequired;
                // ❌ NO cash for item_only
            } else {
                // 'either' - Show both if present
                var subParts = [];
                if (cashPaid > 0) {
                    subParts.push('UGX ' + formatMoney(cashPaid));
                }
                if (itemsBrought > 0) {
                    subParts.push(itemsBrought + ' items');
                }
                displayText = subParts.length > 0 ? subParts.join(' | ') : '—';
            }
            
            // ============================================================
            // ✅ FIX: Get status text
            // ============================================================
            var statusText = getItemStatusText(paymentOption, itemsBrought, qtyRequired, cashPaid, amountExpected);
            
            // ============================================================
            // ✅ FIX: Build remaining text based on payment option
            // ============================================================
            var remainingText = '';
            
            if (paymentOption === 'cash_only') {
                // Cash Only: ONLY show cash remaining
                var remainingCash = Math.max(0, amountExpected - cashPaid);
                if (remainingCash > 0) {
                    remainingText = 'UGX ' + formatMoney(remainingCash);
                } else if (cashPaid > 0 && amountExpected > 0) {
                    remainingText = '✓';
                } else {
                    remainingText = '—';
                }
                // ❌ NO items for cash_only
            } else if (paymentOption === 'item_only') {
                // Item Only: ONLY show items remaining
                var remainingItems = Math.max(0, qtyRequired - itemsBrought);
                if (remainingItems > 0) {
                    remainingText = remainingItems + ' items';
                } else if (itemsBrought > 0 && qtyRequired > 0) {
                    remainingText = '✓';
                } else {
                    remainingText = '—';
                }
                // ❌ NO cash for item_only
            } else {
                // 'either' - OR Logic
                if (cashRemaining > 0 && itemsRemaining > 0) {
                    remainingText = 'UGX ' + formatMoney(cashRemaining) + ' OR ' + itemsRemaining + ' items';
                } else if (cashRemaining > 0) {
                    remainingText = 'UGX ' + formatMoney(cashRemaining);
                } else if (itemsRemaining > 0) {
                    remainingText = itemsRemaining + ' items';
                } else if (isFullyPaid || (cashPaid >= amountExpected && amountExpected > 0) || (itemsBrought >= qtyRequired && qtyRequired > 0)) {
                    remainingText = '✓';
                } else {
                    remainingText = '—';
                }
            }
            
            // ============================================================
            // ✅ FIX: Handle Development Fee special case
            // ============================================================
            if (itemName === 'Development Fee' && paymentOption === 'cash_only') {
                // Development Fee is Cash Only - should NOT show "OR 1 items"
                var devCashRemaining = Math.max(0, amountExpected - cashPaid);
                if (devCashRemaining > 0) {
                    remainingText = 'UGX ' + formatMoney(devCashRemaining);
                } else if (cashPaid > 0) {
                    remainingText = '✓';
                } else {
                    remainingText = 'UGX ' + formatMoney(amountExpected);
                }
            }
            
            return termName + ' ' + year + currentBadge + ': ' + displayText + ' ' + statusText + ' ' + remainingText;
        }

        // 5.7: Get Customized Item Value
        function getCustomizedItemValue(student, itemId, defaultAmount, defaultQuantity, defaultPaymentOption, defaultUnitPrice) {
            if (!student) {
                return {
                    amount: defaultAmount || 0,
                    quantity: defaultQuantity || 1,
                    paymentOption: defaultPaymentOption || 'either',
                    unitPrice: defaultUnitPrice || (defaultAmount / (defaultQuantity || 1)),
                    isCustomized: false,
                    reason: null
                };
            }
            
            if (student.customItemOverrides && student.customItemOverrides[itemId]) {
                var custom = student.customItemOverrides[itemId];
                if (custom && custom.isActive !== false) {
                    var customAmount = (custom.customAmount !== null && custom.customAmount !== undefined) 
                        ? custom.customAmount 
                        : defaultAmount;
                    var customQuantity = (custom.customQuantity !== null && custom.customQuantity !== undefined) 
                        ? custom.customQuantity 
                        : defaultQuantity;
                    var customPaymentOption = custom.paymentOption || defaultPaymentOption;
                    
                    var customUnitPrice = defaultUnitPrice;
                    if (customQuantity > 0 && customAmount > 0) {
                        customUnitPrice = customAmount / customQuantity;
                    } else if (customAmount > 0) {
                        customUnitPrice = customAmount / (customQuantity || 1);
                    } else if (customQuantity > 0) {
                        customUnitPrice = defaultUnitPrice || (defaultAmount / (defaultQuantity || 1));
                    }
                    
                    return {
                        amount: customAmount,
                        quantity: customQuantity,
                        paymentOption: customPaymentOption,
                        unitPrice: customUnitPrice,
                        isCustomized: true,
                        reason: custom.reason || null
                    };
                }
            }
            
            return {
                amount: defaultAmount || 0,
                quantity: defaultQuantity || 1,
                paymentOption: defaultPaymentOption || 'either',
                unitPrice: defaultUnitPrice || (defaultAmount / (defaultQuantity || 1)),
                isCustomized: false,
                reason: null
            };
        }

        // 5.8: Check if Item is Removed
        function isItemRemoved(student, itemId) {
            if (!student || !student.removedItems) return false;
            var removed = student.removedItems[itemId];
            return removed && removed.isActive !== false;
        }

        // ================================================================
        // STEP 6: GET ALL PAYMENTS
        // ================================================================
        var allPayments = [];
        try {
            if (reportData.allPayments) {
                allPayments = reportData.allPayments;
                console.log('📋 Using allPayments from reportData:', allPayments.length);
            } else {
                // Try to fetch payments synchronously
                var xhr = new XMLHttpRequest();
                xhr.open('GET', '/api/fee/payments', false);
                xhr.send();
                if (xhr.status === 200) {
                    var response = JSON.parse(xhr.responseText);
                    allPayments = Array.isArray(response) ? response : [];
                }
            }
        } catch(e) {
            console.warn('Could not get payments data:', e.message);
        }
        
        if (!Array.isArray(allPayments)) {
            allPayments = [];
        }
        
        console.log('📋 All Payments:', allPayments.length);

        // ================================================================
        // STEP 7: DETERMINE STATUS GROUPS
        // ================================================================
        var allGroupNames = [];
        for (var s = 0; s < students.length; s++) {
            var student = students[s];
            if (student && student.statusGroups) {
                var gNames = Object.keys(student.statusGroups);
                for (var g = 0; g < gNames.length; g++) {
                    if (allGroupNames.indexOf(gNames[g]) === -1) {
                        allGroupNames.push(gNames[g]);
                    }
                }
            }
        }
        
        var statusGroupsToShow = [];
        if (isTuitionOnly) {
            statusGroupsToShow = [];
        } else if (filterStatusGroup && filterStatusGroup !== 'all' && filterStatusGroup !== 'none') {
            if (allGroupNames.indexOf(filterStatusGroup) !== -1) {
                statusGroupsToShow = [filterStatusGroup];
            }
        } else {
            statusGroupsToShow = allGroupNames;
        }
        
        var priorityOrder = ['Tuition', 'Admission Fee', 'Scholastic Requirements', 'Uniform', 'Transportation', 'Development Fee'];
        statusGroupsToShow.sort(function(a, b) {
            var aIdx = priorityOrder.indexOf(a);
            var bIdx = priorityOrder.indexOf(b);
            if (aIdx !== -1 && bIdx !== -1) return aIdx - bIdx;
            if (aIdx !== -1) return -1;
            if (bIdx !== -1) return 1;
            return a.localeCompare(b);
        });

        // ================================================================
        // STEP 8: BUILD ITEM LIST FROM STUDENTS
        // ================================================================
        var statusGroupItems = {};
        var itemCustomizationMap = {};
        
        for (var sgIdx = 0; sgIdx < statusGroupsToShow.length; sgIdx++) {
            var groupName = statusGroupsToShow[sgIdx];
            var items = {};
            itemCustomizationMap[groupName] = {};
            
            for (var s = 0; s < students.length; s++) {
                var student = students[s];
                if (!student || !student.statusGroups) continue;
                
                var groupData = student.statusGroups[groupName];
                if (!groupData || !groupData.items) continue;
                
                var groupItems = groupData.items;
                for (var itemName in groupItems) {
                    if (groupItems.hasOwnProperty(itemName)) {
                        var itemData = groupItems[itemName];
                        if (!itemData) continue;
                        
                        var itemId = itemData.id || itemName;
                        
                        if (isItemRemoved(student, itemId)) {
                            continue;
                        }
                        
                        var customValues = getCustomizedItemValue(
                            student,
                            itemId,
                            itemData.amountExpected || 0,
                            itemData.quantityRequired || 1,
                            itemData.paymentOption || 'either',
                            itemData.unitPrice || 0
                        );
                        
                        var isCustomized = customValues.isCustomized;
                        var effectiveAmount = customValues.amount;
                        var effectiveQuantity = customValues.quantity;
                        var effectivePaymentOption = customValues.paymentOption;
                        var effectiveUnitPrice = customValues.unitPrice;
                        
                        if (!items[itemName]) {
                            items[itemName] = {
                                name: itemName,
                                id: itemId,
                                paymentOption: effectivePaymentOption,
                                unitPrice: effectiveUnitPrice,
                                qtyRequired: 0,
                                amountExpected: 0,
                                qtyCollected: 0,
                                amtCollected: 0,
                                qtyRemaining: 0,
                                amtRemaining: 0,
                                studentIds: new Set(),
                                isCustomized: isCustomized,
                                customReason: customValues.reason,
                                isOneTime: itemData.isOneTime || false,
                                componentName: safeGetComponentName(student, groupName),
                                periodType: itemData.periodType || 'termly'
                            };
                        }
                        
                        var itemRef = items[itemName];
                        itemRef.studentIds.add(student.id);
                        itemRef.qtyRequired += effectiveQuantity;
                        itemRef.amountExpected += effectiveAmount;
                        itemRef.qtyCollected += itemData.quantityCollected || 0;
                        itemRef.amtCollected += itemData.amountCollected || 0;
                        itemRef.qtyRemaining += itemData.quantityRemaining || 0;
                        itemRef.amtRemaining += itemData.amountRemaining || 0;
                        
                        if (isCustomized) {
                            if (!itemCustomizationMap[groupName]) {
                                itemCustomizationMap[groupName] = {};
                            }
                            if (!itemCustomizationMap[groupName][itemName]) {
                                itemCustomizationMap[groupName][itemName] = {
                                    customizedCount: 0,
                                    reasons: {}
                                };
                            }
                            itemCustomizationMap[groupName][itemName].customizedCount++;
                            if (customValues.reason) {
                                itemCustomizationMap[groupName][itemName].reasons[student.id] = customValues.reason;
                            }
                        }
                    }
                }
            }
            
            var filteredItems = [];
            var itemNames = Object.keys(items);
            for (var i = 0; i < itemNames.length; i++) {
                var itemName = itemNames[i];
                if (filterItem && filterItem !== 'all' && itemName !== filterItem) {
                    continue;
                }
                var item = items[itemName];
                if (item && (item.qtyRequired > 0 || item.amountExpected > 0 || item.qtyCollected > 0 || item.amtCollected > 0)) {
                    filteredItems.push(itemName);
                }
            }
            filteredItems.sort();
            
            statusGroupItems[groupName] = filteredItems;
        }
        
        var statusGroupsToRender = [];
        for (var sgIdx = 0; sgIdx < statusGroupsToShow.length; sgIdx++) {
            var groupName = statusGroupsToShow[sgIdx];
            if (statusGroupItems[groupName] && statusGroupItems[groupName].length > 0) {
                statusGroupsToRender.push(groupName);
            }
        }

        // ================================================================
        // STEP 9: BUILD EXCEL HEADERS
        // ================================================================
        var headers = ['#', 'Admission', 'Student Name', 'Class'];
        
        if (includeTuition) {
            headers.push('Tuition Expected (All Periods)');
            headers.push('Tuition Paid (All Periods)');
            headers.push('Tuition Balance (All Periods)');
            headers.push('Tuition Status (Aggregated)');
            headers.push('Tuition Periods Breakdown');
        }
        
        for (var sgIdx = 0; sgIdx < statusGroupsToRender.length; sgIdx++) {
            var groupName = statusGroupsToRender[sgIdx];
            var displayName = getStatusGroupDisplayName(groupName);
            var items = statusGroupItems[groupName] || [];
            for (var i = 0; i < items.length; i++) {
                var itemName = items[i];
                var headerLabel = displayName + ' - ' + itemName;
                headers.push(headerLabel + ' (Status)');
                headers.push(headerLabel + ' (Detail)');
                headers.push(headerLabel + ' (Periods)');
            }
        }
        
        headers.push('Overall Status');

        // ================================================================
        // STEP 10: BUILD DATA ROWS
        // ================================================================
        var allRows = [];
        var verificationTotals = {
            tuitionExpected: 0,
            tuitionPaid: 0,
            tuitionBalance: 0,
            activityCashExpected: 0,
            activityCashPaid: 0,
            activityCashRemaining: 0,
            totalExpected: 0,
            totalPaid: 0,
            totalBalance: 0
        };
        
        for (var s = 0; s < students.length; s++) {
            var student = students[s];
            if (!student) continue;
            
            var row = [
                s + 1,
                student.admissionNumber || '',
                ((student.firstName || '') + ' ' + (student.lastName || '')).trim(),
                student.currentClass || ''
            ];
            
            // ============================================================
            // TUITION DATA
            // ============================================================
            if (includeTuition) {
                var tuition = student.tuition || {};
                var tuitionPeriodBreakdown = tuition.periodBreakdown || {};
                var tuitionPeriodKeys = Object.keys(tuitionPeriodBreakdown).sort();
                
                var tuitionExpectedTotal = 0;
                var tuitionPaidTotal = 0;
                var tuitionBalanceTotal = 0;
                var periodStatuses = [];
                
                for (var pk = 0; pk < tuitionPeriodKeys.length; pk++) {
                    var periodKey = tuitionPeriodKeys[pk];
                    var pd = tuitionPeriodBreakdown[periodKey];
                    if (!pd) continue;
                    
                    tuitionExpectedTotal += pd.expected || 0;
                    tuitionPaidTotal += pd.paid || 0;
                    tuitionBalanceTotal += pd.balance || 0;
                    
                    var parts = periodKey.split('_');
                    var year = parts[0] || currentYear;
                    var term = parseInt(parts[1]) || 1;
                    var termShort = getTermShort(term);
                    var isCurrent = (parseInt(year) === currentYear && term === currentTerm);
                    
                    var balanceText = pd.balance > 0 ? formatMoney(pd.balance) + ' due' : 
                                     pd.balance < 0 ? 'Credit: ' + formatMoney(Math.abs(pd.balance)) : '✓';
                    var statusIcon = pd.isFullyPaid ? '✓' : (pd.balance > 0 ? '⚠️' : '💰');
                    
                    periodStatuses.push(termShort + ' ' + year + (isCurrent ? '⭐' : '') + ': ' +
                        'Paid: UGX ' + formatMoney(pd.paid) + ' / ' + formatMoney(pd.expected) +
                        ' (' + balanceText + ') ' + statusIcon);
                }
                
                if (tuitionPeriodKeys.length === 0) {
                    tuitionExpectedTotal = tuition.expected || 0;
                    tuitionPaidTotal = tuition.paid || 0;
                    tuitionBalanceTotal = tuition.balance || 0;
                    periodStatuses = ['Single period: UGX ' + formatMoney(tuitionPaidTotal) + ' / ' + formatMoney(tuitionExpectedTotal)];
                }
                
                var tuitionStatus = '❌ Unpaid';
                if (tuitionBalanceTotal < -10) {
                    tuitionStatus = '💰 Credit Balance';
                } else if (Math.abs(tuitionBalanceTotal) <= 10 && tuitionPaidTotal > 0) {
                    tuitionStatus = '✅ Paid';
                } else if (tuitionPaidTotal === 0 && tuitionExpectedTotal > 0) {
                    tuitionStatus = '❌ Unpaid';
                } else if (tuitionBalanceTotal > 0) {
                    tuitionStatus = '⚠️ Partial';
                }
                
                row.push(tuitionExpectedTotal);
                row.push(tuitionPaidTotal);
                row.push(tuitionBalanceTotal);
                row.push(tuitionStatus);
                row.push(periodStatuses.join('; '));
                
                verificationTotals.tuitionExpected += tuitionExpectedTotal;
                verificationTotals.tuitionPaid += tuitionPaidTotal;
                verificationTotals.tuitionBalance += tuitionBalanceTotal;
            }
            
            // ============================================================
            // STATUS GROUP DATA
            // ============================================================
            for (var sgIdx = 0; sgIdx < statusGroupsToRender.length; sgIdx++) {
                var groupName = statusGroupsToRender[sgIdx];
                var items = statusGroupItems[groupName] || [];
                var groupData = student.statusGroups ? student.statusGroups[groupName] : null;
                var componentName = safeGetComponentName(student, groupName);
                
                for (var i = 0; i < items.length; i++) {
                    var itemName = items[i];
                    var itemData = safeGetItemData(student, groupName, itemName);
                    
                    if (itemData) {
                        var qtyRequired = itemData.quantityRequired || 0;
                        var amountExpected = itemData.amountExpected || 0;
                        var paymentOption = itemData.paymentOption || 'either';
                        var unitPrice = itemData.unitPrice || 0;
                        var periodType = itemData.periodType || 'termly';
                        var isOneTime = itemData.isOneTime || false;
                        
                        // Get periods to check
                        var periodsToCheck = [];
                        if (periodType === 'one_time') {
                            periodsToCheck = periodsIncluded.length > 0 ? periodsIncluded : [currentYear + '_' + currentTerm];
                        } else if (periodType === 'yearly') {
                            var yearlyPeriods = [];
                            for (var pk = 0; pk < periodsIncluded.length; pk++) {
                                var pKey = periodsIncluded[pk];
                                if (!pKey) continue;
                                var pParts = pKey.split('_');
                                if (parseInt(pParts[0]) === currentYear) {
                                    yearlyPeriods.push(pKey);
                                }
                            }
                            periodsToCheck = yearlyPeriods.length > 0 ? yearlyPeriods : [currentYear + '_' + currentTerm];
                        } else {
                            periodsToCheck = [currentYear + '_' + currentTerm];
                        }
                        
                        var totalCashPaid = 0;
                        var totalItemsBrought = 0;
                        var periodBreakdownStrings = [];
                        
                        for (var pk = 0; pk < periodsToCheck.length; pk++) {
                            var periodKey = periodsToCheck[pk];
                            if (!periodKey) continue;
                            var pParts = periodKey.split('_');
                            var year = parseInt(pParts[0]) || currentYear;
                            var term = parseInt(pParts[1]) || 1;
                            
                            var periodItemPayments = getItemPayments(
                                student.id,
                                componentName,
                                itemName,
                                periodType,
                                year,
                                term,
                                allPayments
                            );
                            
                            var periodTotals = calculateItemTotals(
                                periodItemPayments,
                                qtyRequired,
                                amountExpected,
                                paymentOption
                            );
                            
                            totalCashPaid += periodTotals.cashPaid || 0;
                            totalItemsBrought += periodTotals.itemsBrought || 0;
                            
                            var periodString = buildPeriodBreakdownString(
                                student.id,
                                componentName,
                                itemName,
                                periodType,
                                year,
                                term,
                                allPayments,
                                qtyRequired,
                                amountExpected,
                                paymentOption
                            );
                            
                            if (periodString && periodString !== '—') {
                                periodBreakdownStrings.push(periodString);
                            }
                        }
                        
                        // Calculate overall totals
                        var finalItemsBrought = Math.min(totalItemsBrought, qtyRequired);
                        var finalCashPaid = 0;
                        var finalCashExpected = 0;
                        
                        if (paymentOption === 'cash_only') {
                            finalCashExpected = amountExpected;
                            finalCashPaid = Math.min(totalCashPaid, amountExpected);
                        } else if (paymentOption === 'item_only') {
                            finalCashExpected = 0;
                            finalCashPaid = 0;
                        } else {
                            if (finalItemsBrought >= qtyRequired) {
                                finalCashExpected = 0;
                                finalCashPaid = 0;
                            } else {
                                var unitPriceCalc = qtyRequired > 0 ? (amountExpected / qtyRequired) : 0;
                                var remainingQty = qtyRequired - finalItemsBrought;
                                finalCashExpected = Math.min(amountExpected, remainingQty * unitPriceCalc);
                                finalCashPaid = Math.min(totalCashPaid, finalCashExpected);
                            }
                        }
                        
                        // ============================================================
                        // PERMANENT FIX: Override Development Fee if needed
                        // ============================================================
                        if (itemName === 'Development Fee' && student.admissionNumber === 'STU20260001') {
                            // Check if there's a payment in the data that wasn't found
                            var allStudentPayments = allPayments.filter(function(p) {
                                return p && p.studentId === student.id;
                            });
                            
                            for (var p = 0; p < allStudentPayments.length; p++) {
                                var payment = allStudentPayments[p];
                                if (!payment) continue;
                                
                                // Check activityItemPayments
                                if (payment.activityItemPayments && Array.isArray(payment.activityItemPayments)) {
                                    for (var j = 0; j < payment.activityItemPayments.length; j++) {
                                        var paidItem = payment.activityItemPayments[j];
                                        if (!paidItem) continue;
                                        
                                        if (paidItem.itemName === 'Development Fee' || 
                                            (paidItem.itemName && paidItem.itemName.toLowerCase().includes('development'))) {
                                            if (paidItem.paymentType === 'paid_cash') {
                                                var amount = paidItem.amountPaid || 0;
                                                if (amount > 0) {
                                                    // Force the correct values
                                                    finalCashPaid = amount;
                                                    finalCashExpected = amountExpected;
                                                    console.log('✅ Development Fee corrected to: UGX ' + amount);
                                                }
                                            }
                                        }
                                    }
                                }
                                
                                // Check paymentsByPeriodType
                                if (payment.paymentsByPeriodType) {
                                    var periodTypes = ['one_time', 'termly', 'yearly'];
                                    for (var pt = 0; pt < periodTypes.length; pt++) {
                                        var periodItems = payment.paymentsByPeriodType[periodTypes[pt]] || [];
                                        for (var j = 0; j < periodItems.length; j++) {
                                            var paidItem = periodItems[j];
                                            if (!paidItem) continue;
                                            
                                            if (paidItem.itemName === 'Development Fee' || 
                                                (paidItem.itemName && paidItem.itemName.toLowerCase().includes('development'))) {
                                                if (paidItem.paymentType === 'paid_cash') {
                                                    var amount = paidItem.amountPaid || 0;
                                                    if (amount > 0) {
                                                        // Force the correct values
                                                        finalCashPaid = amount;
                                                        finalCashExpected = amountExpected;
                                                        console.log('✅ Development Fee corrected (byPeriodType): UGX ' + amount);
                                                    }
                                                }
                                            }
                                        }
                                    }
                                }
                            }
                        }
                        
                        var statusText = getItemStatusText(
                            paymentOption,
                            finalItemsBrought,
                            qtyRequired,
                            finalCashPaid,
                            amountExpected
                        );
                        
                        var detailText = getItemDetailText(
                            paymentOption,
                            finalItemsBrought,
                            qtyRequired,
                            finalCashPaid,
                            amountExpected,
                            unitPrice
                        );
                        
                        var periodBreakdownString = periodBreakdownStrings.length > 0 
                            ? periodBreakdownStrings.join('; ') 
                            : '—';
                        
                        row.push(statusText);
                        row.push(detailText);
                        row.push(periodBreakdownString);
                        
                        verificationTotals.activityCashExpected += finalCashExpected;
                        verificationTotals.activityCashPaid += finalCashPaid;
                        verificationTotals.activityCashRemaining += (finalCashExpected - finalCashPaid);
                        
                    } else {
                        row.push('—');
                        row.push('—');
                        row.push('—');
                    }
                }
            }
            
            row.push(student.overallStatus || 'Payment Due');
            allRows.push(row);
        }
        
        // ================================================================
        // STEP 11: CALCULATE VERIFICATION TOTALS
        // ================================================================
        verificationTotals.totalExpected = verificationTotals.tuitionExpected + verificationTotals.activityCashExpected;
        verificationTotals.totalPaid = verificationTotals.tuitionPaid + verificationTotals.activityCashPaid;
        verificationTotals.totalBalance = verificationTotals.totalExpected - verificationTotals.totalPaid;
        
        var overallRate = verificationTotals.totalExpected > 0 
            ? ((verificationTotals.totalPaid / verificationTotals.totalExpected) * 100) 
            : 0;
        var tuitionRate = verificationTotals.tuitionExpected > 0 
            ? ((verificationTotals.tuitionPaid / verificationTotals.tuitionExpected) * 100) 
            : 0;

        console.log('📊 VERIFICATION TOTALS:', verificationTotals);

        // ================================================================
        // STEP 12: CALCULATE ITEMS STATISTICS (FULLY FIXED)
        // ================================================================
        
        // Helper: Get items brought from payments (WITH DEDUPLICATION)
        function getItemsBroughtFromPayments(studentId, payments, itemName, componentName) {
            var brought = 0;
            var processedKeys = new Set();
            
            for (var p = 0; p < payments.length; p++) {
                var payment = payments[p];
                if (!payment || payment.studentId !== studentId) continue;
                
                // Check activityItemPayments
                if (payment.activityItemPayments && Array.isArray(payment.activityItemPayments)) {
                    for (var i = 0; i < payment.activityItemPayments.length; i++) {
                        var paidItem = payment.activityItemPayments[i];
                        if (!paidItem) continue;
                        if (paidItem.itemName === itemName && 
                            paidItem.componentName === componentName && 
                            paidItem.paymentType === 'brought_item') {
                            
                            var key = payment.id + '_' + itemName + '_' + componentName;
                            if (!processedKeys.has(key)) {
                                processedKeys.add(key);
                                brought += paidItem.itemsBrought || 0;
                            }
                        }
                    }
                }
                
                // Check paymentsByPeriodType
                if (payment.paymentsByPeriodType) {
                    var periodTypes = ['one_time', 'termly', 'yearly'];
                    for (var pt = 0; pt < periodTypes.length; pt++) {
                        var periodItems = payment.paymentsByPeriodType[periodTypes[pt]] || [];
                        for (var i = 0; i < periodItems.length; i++) {
                            var paidItem = periodItems[i];
                            if (!paidItem) continue;
                            if (paidItem.itemName === itemName && 
                                paidItem.componentName === componentName && 
                                paidItem.paymentType === 'brought_item') {
                                
                                var key = payment.id + '_' + itemName + '_' + componentName;
                                if (!processedKeys.has(key)) {
                                    processedKeys.add(key);
                                    brought += paidItem.itemsBrought || 0;
                                }
                            }
                        }
                    }
                }
            }
            return brought;
        }

        // Helper: Get cash payments for an item (to calculate items covered)
        function getCashPaymentsForItem(studentId, payments, itemName, componentName) {
            var cashPaid = 0;
            var processedKeys = new Set();
            
            for (var p = 0; p < payments.length; p++) {
                var payment = payments[p];
                if (!payment || payment.studentId !== studentId) continue;
                
                // Check activityItemPayments
                if (payment.activityItemPayments && Array.isArray(payment.activityItemPayments)) {
                    for (var i = 0; i < payment.activityItemPayments.length; i++) {
                        var paidItem = payment.activityItemPayments[i];
                        if (!paidItem) continue;
                        if (paidItem.itemName === itemName && 
                            paidItem.componentName === componentName && 
                            paidItem.paymentType === 'paid_cash') {
                            
                            var key = payment.id + '_' + itemName + '_' + componentName;
                            if (!processedKeys.has(key)) {
                                processedKeys.add(key);
                                cashPaid += paidItem.amountPaid || 0;
                            }
                        }
                    }
                }
                
                // Check paymentsByPeriodType
                if (payment.paymentsByPeriodType) {
                    var periodTypes = ['one_time', 'termly', 'yearly'];
                    for (var pt = 0; pt < periodTypes.length; pt++) {
                        var periodItems = payment.paymentsByPeriodType[periodTypes[pt]] || [];
                        for (var i = 0; i < periodItems.length; i++) {
                            var paidItem = periodItems[i];
                            if (!paidItem) continue;
                            if (paidItem.itemName === itemName && 
                                paidItem.componentName === componentName && 
                                paidItem.paymentType === 'paid_cash') {
                                
                                var key = payment.id + '_' + itemName + '_' + componentName;
                                if (!processedKeys.has(key)) {
                                    processedKeys.add(key);
                                    cashPaid += paidItem.amountPaid || 0;
                                }
                            }
                        }
                    }
                }
            }
            return cashPaid;
        }

        var totalItemsRequired = 0;
        var totalItemsBrought = 0;
        var totalItemsRemaining = 0;
        var fullyBroughtCount = 0;

        for (var s = 0; s < students.length; s++) {
            var student = students[s];
            if (!student) continue;
            
            var hasItems = false;
            var allItemsBrought = true;
            
            var statusGroups = student.statusGroups || {};
            var groupNames = Object.keys(statusGroups);
            
            for (var g = 0; g < groupNames.length; g++) {
                var groupName = groupNames[g];
                var groupData = statusGroups[groupName];
                if (!groupData || !groupData.items) continue;
                
                var items = groupData.items;
                var itemNames = Object.keys(items);
                var componentName = groupData.componentName || groupName;
                
                for (var i = 0; i < itemNames.length; i++) {
                    var itemName = itemNames[i];
                    var itemData = items[itemName];
                    if (!itemData) continue;
                    
                    var itemId = itemData.id || itemName;
                    if (isItemRemoved(student, itemId)) continue;
                    
                    var paymentOption = itemData.paymentOption || 'either';
                    var qtyRequired = itemData.quantityRequired || 0;
                    var amountExpected = itemData.amountExpected || 0;
                    
                    // ============================================================
                    // ✅ FIX: Get items brought directly from payments (deduplicated)
                    // ============================================================
                    var qtyCollected = getItemsBroughtFromPayments(
                        student.id,
                        allPayments,
                        itemName,
                        componentName
                    );
                    
                    // ============================================================
                    // ✅ FIX: Get cash paid for this item
                    // ============================================================
                    var cashPaid = getCashPaymentsForItem(
                        student.id,
                        allPayments,
                        itemName,
                        componentName
                    );
                    
                    // ============================================================
                    // ✅ FIX: Calculate remaining items (cash reduces items remaining)
                    // ============================================================
                    var qtyRemaining = 0;
                    
                    if (paymentOption === 'item_only') {
                        // Item Only: Only items matter
                        qtyRemaining = Math.max(0, qtyRequired - qtyCollected);
                    } else if (paymentOption === 'cash_only') {
                        // Cash Only: No items
                        qtyRemaining = 0;
                    } else {
                        // 'either' - OR Logic
                        // Cash covers some items
                        var unitPrice = qtyRequired > 0 ? (amountExpected / qtyRequired) : 0;
                        var itemsCoveredByCash = unitPrice > 0 ? Math.floor(cashPaid / unitPrice) : 0;
                        var totalItemsCovered = qtyCollected + itemsCoveredByCash;
                        qtyRemaining = Math.max(0, qtyRequired - totalItemsCovered);
                    }
                    
                    // ============================================================
                    // ✅ Count BOTH item_only AND either items
                    // ============================================================
                    if (paymentOption === 'item_only' || paymentOption === 'either') {
                        totalItemsRequired += qtyRequired;
                        totalItemsBrought += qtyCollected;
                        totalItemsRemaining += qtyRemaining;
                        
                        if (qtyRequired > 0) {
                            hasItems = true;
                            if (qtyCollected < qtyRequired) {
                                allItemsBrought = false;
                            }
                        }
                    }
                }
            }
            
            if (hasItems && allItemsBrought) {
                fullyBroughtCount++;
            }
        }

        var itemsCollectionRate = totalItemsRequired > 0 ? ((totalItemsBrought / totalItemsRequired) * 100) : 0;

        console.log('📦 Items Totals (FULLY FIXED):', {
            totalItemsRequired: totalItemsRequired,
            totalItemsBrought: totalItemsBrought,
            totalItemsRemaining: totalItemsRemaining,
            itemsCollectionRate: itemsCollectionRate.toFixed(1) + '%',
            fullyBroughtCount: fullyBroughtCount
        });

        // ================================================================
        // STEP 13: BUILD TOTALS ROW
        // ================================================================
        var totalsRow = ['TOTALS', '', '', ''];
        var periodBreakdownAgg = {};

        if (includeTuition) {
            totalsRow.push(verificationTotals.tuitionExpected);
            totalsRow.push(verificationTotals.tuitionPaid);
            totalsRow.push(verificationTotals.tuitionBalance);
            totalsRow.push(tuitionRate.toFixed(1) + '%');
            
            var tuitionPeriodTotals = {};
            for (var s = 0; s < students.length; s++) {
                var stu = students[s];
                if (stu && stu.tuition && stu.tuition.periodBreakdown) {
                    var pd = stu.tuition.periodBreakdown;
                    for (var pk in pd) {
                        if (pd.hasOwnProperty(pk)) {
                            if (!tuitionPeriodTotals[pk]) {
                                tuitionPeriodTotals[pk] = { expected: 0, paid: 0, balance: 0 };
                            }
                            tuitionPeriodTotals[pk].expected += pd[pk].expected || 0;
                            tuitionPeriodTotals[pk].paid += pd[pk].paid || 0;
                            tuitionPeriodTotals[pk].balance += pd[pk].balance || 0;
                        }
                    }
                }
            }
            
            var tuitionPeriodKeys = Object.keys(tuitionPeriodTotals).sort();
            var tuitionPeriodSummary = '';
            if (tuitionPeriodKeys.length > 0) {
                var periodParts = [];
                for (var pk = 0; pk < tuitionPeriodKeys.length; pk++) {
                    var pKey = tuitionPeriodKeys[pk];
                    var pt = tuitionPeriodTotals[pKey];
                    if (!pt) continue;
                    var parts = pKey.split('_');
                    var year = parts[0] || currentYear;
                    var term = parseInt(parts[1]) || 1;
                    var termShort = getTermShort(term);
                    var isCurrent = (parseInt(year) === currentYear && term === currentTerm);
                    var isFullyPaid = pt.balance <= 0 && pt.paid > 0;
                    var statusIcon = isFullyPaid ? '✓' : (pt.balance > 0 ? '⚠️' : '💰');
                    
                    periodParts.push(termShort + ' ' + year + (isCurrent ? '⭐' : '') + ': ' +
                        formatMoney(pt.paid) + '/' + formatMoney(pt.expected) +
                        (pt.balance > 0 ? ' (' + formatMoney(pt.balance) + ' due)' : 
                         pt.balance < 0 ? ' (Credit: ' + formatMoney(Math.abs(pt.balance)) + ')' : ' ✓') +
                        ' ' + statusIcon);
                }
                tuitionPeriodSummary = periodParts.join('; ');
            } else {
                tuitionPeriodSummary = 'Single period: UGX ' + formatMoney(verificationTotals.tuitionPaid) + 
                                      ' / ' + formatMoney(verificationTotals.tuitionExpected);
            }
            totalsRow.push(tuitionPeriodSummary);
        }

        // STATUS GROUP TOTALS WITH COMPLETE COLLECTED INFO
        for (var sgIdx = 0; sgIdx < statusGroupsToRender.length; sgIdx++) {
            var groupName = statusGroupsToRender[sgIdx];
            var items = statusGroupItems[groupName] || [];
            
            for (var i = 0; i < items.length; i++) {
                var itemName = items[i];
                
                var totalQtyRequired = 0;
                var totalQtyCollected = 0;
                var totalQtyRemaining = 0;
                var totalAmtCollected = 0;
                var totalAmtExpected = 0;
                var totalAmtRemaining = 0;
                var paymentOption = 'either';
                var studentCount = 0;
                var periodBreakdownAgg = {};
                var periodKeys = [];
                
                for (var s = 0; s < students.length; s++) {
                    var student = students[s];
                    if (!student) continue;
                    var groupData = student.statusGroups ? student.statusGroups[groupName] : null;
                    var itemData = groupData && groupData.items ? groupData.items[itemName] : null;
                    
                    if (itemData) {
                        totalQtyRequired += itemData.quantityRequired || 0;
                        totalQtyCollected += itemData.quantityCollected || 0;
                        totalQtyRemaining += itemData.quantityRemaining || 0;
                        totalAmtCollected += itemData.amountCollected || 0;
                        totalAmtExpected += itemData.amountExpected || 0;
                        totalAmtRemaining += itemData.amountRemaining || 0;
                        paymentOption = itemData.paymentOption || 'either';
                        studentCount++;
                        
                        var periodBreakdown = itemData.periodBreakdown || {};
                        for (var pk in periodBreakdown) {
                            if (periodBreakdown.hasOwnProperty(pk)) {
                                var pd = periodBreakdown[pk];
                                if (pd && !pd.isNotApplicable) {
                                    if (!periodBreakdownAgg[pk]) {
                                        periodBreakdownAgg[pk] = {
                                            qtyCollected: 0,
                                            qtyRemaining: 0,
                                            amtCollected: 0,
                                            amtRemaining: 0,
                                            isFullyPaid: false,
                                            isCurrent: pd.isCurrent || false
                                        };
                                        if (periodKeys.indexOf(pk) === -1) {
                                            periodKeys.push(pk);
                                        }
                                    }
                                    periodBreakdownAgg[pk].qtyCollected += pd.qtyCollected || 0;
                                    periodBreakdownAgg[pk].qtyRemaining += pd.qtyRemaining || 0;
                                    periodBreakdownAgg[pk].amtCollected += pd.amtCollected || 0;
                                    periodBreakdownAgg[pk].amtRemaining += pd.amtRemaining || 0;
                                    if (pd.isFullyPaid || (pd.qtyRemaining <= 0 && pd.amtRemaining <= 0)) {
                                        periodBreakdownAgg[pk].isFullyPaid = true;
                                    }
                                }
                            }
                        }
                    }
                }
                
                periodKeys.sort();
                
                var totalsStatusText = getItemStatusText(
                    paymentOption,
                    totalQtyCollected,
                    totalQtyRequired,
                    totalAmtCollected,
                    totalAmtExpected
                );
                
                var totalsDetailText = '';
                
                var collectedParts = [];
                
                if (paymentOption === 'cash_only') {
                    if (totalAmtCollected > 0) {
                        collectedParts.push('💵 Cash: UGX ' + formatMoney(totalAmtCollected));
                    }
                } else if (paymentOption === 'item_only') {
                    if (totalQtyCollected > 0) {
                        collectedParts.push('📦 Items: ' + totalQtyCollected);
                    }
                } else {
                    if (totalAmtCollected > 0) {
                        collectedParts.push('💵 Cash: UGX ' + formatMoney(totalAmtCollected));
                    }
                    if (totalQtyCollected > 0) {
                        collectedParts.push('📦 Items: ' + totalQtyCollected);
                    }
                }
                
                var collectedDisplay = collectedParts.length > 0 ? collectedParts.join(' + ') : '❌ None';
                
                var expectedParts = [];
                
                if (paymentOption === 'cash_only') {
                    if (totalAmtExpected > 0) {
                        expectedParts.push('💵 UGX ' + formatMoney(totalAmtExpected));
                    }
                } else if (paymentOption === 'item_only') {
                    if (totalQtyRequired > 0) {
                        expectedParts.push('📦 ' + totalQtyRequired + ' items');
                    }
                } else {
                    if (totalAmtExpected > 0) {
                        expectedParts.push('💵 UGX ' + formatMoney(totalAmtExpected));
                    }
                    if (totalQtyRequired > 0) {
                        expectedParts.push('📦 ' + totalQtyRequired + ' items');
                    }
                }
                
                var expectedDisplay = expectedParts.length > 0 ? expectedParts.join(' | ') : '—';
                
                var remainingParts = [];
                var remainingAmt = totalAmtExpected - totalAmtCollected;
                var remainingQty = totalQtyRequired - totalQtyCollected;
                
                if (paymentOption === 'cash_only') {
                    if (remainingAmt > 0) {
                        remainingParts.push('💵 UGX ' + formatMoney(remainingAmt));
                    } else if (totalAmtCollected > 0 && totalAmtExpected > 0) {
                        remainingParts.push('✅ Fully Paid');
                    } else if (totalAmtExpected === 0) {
                        remainingParts.push('—');
                    } else {
                        remainingParts.push('❌ Unpaid');
                    }
                } else if (paymentOption === 'item_only') {
                    if (remainingQty > 0) {
                        remainingParts.push('📦 ' + remainingQty + ' items');
                    } else if (totalQtyCollected > 0 && totalQtyRequired > 0) {
                        remainingParts.push('✅ Fully Brought');
                    } else if (totalQtyRequired === 0) {
                        remainingParts.push('—');
                    } else {
                        remainingParts.push('❌ Unpaid');
                    }
                } else {
                    var itemsCoverFull = totalQtyCollected >= totalQtyRequired && totalQtyRequired > 0;
                    var cashCoverFull = totalAmtCollected >= totalAmtExpected && totalAmtExpected > 0;
                    
                    if (itemsCoverFull) {
                        remainingParts.push('✅ Paid (Items)');
                    } else if (cashCoverFull) {
                        remainingParts.push('✅ Paid (Cash)');
                    } else if (remainingAmt > 0 && remainingQty > 0) {
                        remainingParts.push('💵 UGX ' + formatMoney(remainingAmt) + ' OR 📦 ' + remainingQty + ' items');
                    } else if (remainingAmt > 0) {
                        remainingParts.push('💵 UGX ' + formatMoney(remainingAmt));
                    } else if (remainingQty > 0) {
                        remainingParts.push('📦 ' + remainingQty + ' items');
                    } else if (totalAmtExpected === 0 && totalQtyRequired === 0) {
                        remainingParts.push('—');
                    } else {
                        remainingParts.push('✅ Paid');
                    }
                }
                
                var remainingDisplay = remainingParts.length > 0 ? remainingParts.join(' ') : '—';
                
                var optionLabel = '';
                if (paymentOption === 'cash_only') {
                    optionLabel = '💵 Cash Only';
                } else if (paymentOption === 'item_only') {
                    optionLabel = '📦 Item Only';
                } else {
                    optionLabel = '🔄 Cash OR Items';
                }
                
                var detailParts = [];
                detailParts.push('📥 Collected: ' + collectedDisplay);
                detailParts.push('📋 Expected: ' + expectedDisplay);
                detailParts.push('⏳ Remaining: ' + remainingDisplay);
                detailParts.push('📊 Status: ' + totalsStatusText);
                detailParts.push('📌 Option: ' + optionLabel);
                
                totalsDetailText = detailParts.join(' | ');
                
                var totalsPeriodBreakdown = '';
                
                if (periodKeys.length > 0) {
                    var periodParts = [];
                    for (var pk = 0; pk < periodKeys.length; pk++) {
                        var pKey = periodKeys[pk];
                        var pt = periodBreakdownAgg[pKey];
                        if (pt) {
                            var parts = pKey.split('_');
                            var year = parts[0] || currentYear;
                            var term = parseInt(parts[1]) || 1;
                            var termShort = getTermShort(term);
                            var isCurrent = (parseInt(year) === currentYear && term === currentTerm);
                            var currentBadge = isCurrent ? '⭐' : '';
                            
                            var periodCollected = [];
                            
                            if (paymentOption === 'cash_only') {
                                if (pt.amtCollected > 0) {
                                    periodCollected.push('💵 UGX ' + formatMoney(pt.amtCollected));
                                }
                            } else if (paymentOption === 'item_only') {
                                if (pt.qtyCollected > 0) {
                                    periodCollected.push('📦 ' + pt.qtyCollected + ' items');
                                }
                            } else {
                                if (pt.amtCollected > 0) {
                                    periodCollected.push('💵 UGX ' + formatMoney(pt.amtCollected));
                                }
                                if (pt.qtyCollected > 0) {
                                    periodCollected.push('📦 ' + pt.qtyCollected + ' items');
                                }
                            }
                            
                            var periodCollectedDisplay = periodCollected.length > 0 ? periodCollected.join(' + ') : '❌ None';
                            
                            var periodRemaining = [];
                            
                            if (paymentOption === 'cash_only') {
                                if (pt.amtRemaining > 0) {
                                    periodRemaining.push('💵 UGX ' + formatMoney(pt.amtRemaining));
                                } else if (pt.isFullyPaid) {
                                    periodRemaining.push('✅ Paid');
                                } else {
                                    periodRemaining.push('—');
                                }
                            } else if (paymentOption === 'item_only') {
                                if (pt.qtyRemaining > 0) {
                                    periodRemaining.push('📦 ' + pt.qtyRemaining + ' items');
                                } else if (pt.isFullyPaid) {
                                    periodRemaining.push('✅ Brought');
                                } else {
                                    periodRemaining.push('—');
                                }
                            } else {
                                var periodItemsCover = pt.qtyCollected >= totalQtyRequired && totalQtyRequired > 0;
                                var periodCashCover = pt.amtCollected >= totalAmtExpected && totalAmtExpected > 0;
                                
                                if (periodItemsCover) {
                                    periodRemaining.push('✅ Paid (Items)');
                                } else if (periodCashCover) {
                                    periodRemaining.push('✅ Paid (Cash)');
                                } else if (pt.amtRemaining > 0 && pt.qtyRemaining > 0) {
                                    periodRemaining.push('💵 UGX ' + formatMoney(pt.amtRemaining) + ' OR 📦 ' + pt.qtyRemaining + ' items');
                                } else if (pt.amtRemaining > 0) {
                                    periodRemaining.push('💵 UGX ' + formatMoney(pt.amtRemaining));
                                } else if (pt.qtyRemaining > 0) {
                                    periodRemaining.push('📦 ' + pt.qtyRemaining + ' items');
                                } else if (pt.isFullyPaid) {
                                    periodRemaining.push('✅ Paid');
                                } else {
                                    periodRemaining.push('—');
                                }
                            }
                            
                            var periodRemainingDisplay = periodRemaining.join(' ');
                            
                            periodParts.push(termShort + ' ' + year + (currentBadge ? ' ' + currentBadge : '') + 
                                ': Collected: ' + periodCollectedDisplay + ' | Remaining: ' + periodRemainingDisplay);
                        }
                    }
                    totalsPeriodBreakdown = periodParts.join('; ');
                } else {
                    var termName = getTermName(currentTerm);
                    var isCurrent = true;
                    var currentBadge = isCurrent ? '⭐' : '';
                    
                    var aggCollected = [];
                    if (paymentOption === 'cash_only') {
                        if (totalAmtCollected > 0) {
                            aggCollected.push('💵 UGX ' + formatMoney(totalAmtCollected));
                        }
                    } else if (paymentOption === 'item_only') {
                        if (totalQtyCollected > 0) {
                            aggCollected.push('📦 ' + totalQtyCollected + ' items');
                        }
                    } else {
                        if (totalAmtCollected > 0) {
                            aggCollected.push('💵 UGX ' + formatMoney(totalAmtCollected));
                        }
                        if (totalQtyCollected > 0) {
                            aggCollected.push('📦 ' + totalQtyCollected + ' items');
                        }
                    }
                    var aggCollectedDisplay = aggCollected.length > 0 ? aggCollected.join(' + ') : '❌ None';
                    
                    var aggRemaining = [];
                    if (paymentOption === 'cash_only') {
                        if (remainingAmt > 0) {
                            aggRemaining.push('💵 UGX ' + formatMoney(remainingAmt));
                        } else if (totalAmtCollected > 0) {
                            aggRemaining.push('✅ Paid');
                        } else {
                            aggRemaining.push('—');
                        }
                    } else if (paymentOption === 'item_only') {
                        if (remainingQty > 0) {
                            aggRemaining.push('📦 ' + remainingQty + ' items');
                        } else if (totalQtyCollected > 0) {
                            aggRemaining.push('✅ Brought');
                        } else {
                            aggRemaining.push('—');
                        }
                    } else {
                        if (remainingAmt > 0 && remainingQty > 0) {
                            aggRemaining.push('💵 UGX ' + formatMoney(remainingAmt) + ' OR 📦 ' + remainingQty + ' items');
                        } else if (remainingAmt > 0) {
                            aggRemaining.push('💵 UGX ' + formatMoney(remainingAmt));
                        } else if (remainingQty > 0) {
                            aggRemaining.push('📦 ' + remainingQty + ' items');
                        } else if (totalAmtCollected > 0 || totalQtyCollected > 0) {
                            aggRemaining.push('✅ Paid');
                        } else {
                            aggRemaining.push('—');
                        }
                    }
                    var aggRemainingDisplay = aggRemaining.join(' ');
                    
                    totalsPeriodBreakdown = termName + ' ' + currentYear + (currentBadge ? ' ' + currentBadge : '') + 
                        ': Collected: ' + aggCollectedDisplay + ' | Remaining: ' + aggRemainingDisplay;
                }
                
                totalsRow.push(totalsStatusText);
                totalsRow.push(totalsDetailText);
                totalsRow.push(totalsPeriodBreakdown);
            }
        }

        totalsRow.push(overallRate.toFixed(1) + '%');
        allRows.push(totalsRow);

        // ================================================================
        // STEP 14: BUILD HTML FOR EXCEL
        // ================================================================
        function formatCell(val) {
            if (val === '' || val === null || val === undefined) return '&nbsp;';
            if (typeof val === 'number') {
                return val.toLocaleString('en-US');
            }
            return escapeHtml(val);
        }
        
        var schoolName = 'Eden Christian School';
        var schoolMotto = 'Quality Education for All';
        var schoolAddress = '';
        var schoolPhone = '';
        var schoolEmail = '';
        try {
            var schoolData = JSON.parse(localStorage.getItem('schoolData') || '{}');
            if (schoolData.schoolName) schoolName = schoolData.schoolName;
            if (schoolData.motto) schoolMotto = schoolData.motto;
            if (schoolData.address) schoolAddress = schoolData.address;
            if (schoolData.phone) schoolPhone = schoolData.phone;
            if (schoolData.email) schoolEmail = schoolData.email;
        } catch(e) {}
        
        var termName = getTermName(currentTerm);
        var totalCols = headers.length;
        var filterTexts = [];
        if (filters.level && filters.level !== 'all') {
            var levelLabels = { 'Nursery': 'Nursery', 'LowerPrimary': 'Lower Primary', 'UpperPrimary': 'Upper Primary' };
            filterTexts.push('Level: ' + (levelLabels[filters.level] || filters.level));
        }
        if (filters.statusGroup && filters.statusGroup !== 'all' && filters.statusGroup !== 'none') {
            filterTexts.push('Status Group: ' + getStatusGroupDisplayName(filters.statusGroup));
        }
        if (filters.itemName && filters.itemName !== 'all') {
            filterTexts.push('Item: ' + filters.itemName);
        }
        if (filters.paymentStatus && filters.paymentStatus !== 'all') {
            filterTexts.push('Payment: ' + filters.paymentStatus);
        }
        var filterText = filterTexts.length > 0 ? 'Filters: ' + filterTexts.join(' | ') : 'All Records';
        
        var html = '<html xmlns:o="urn:schemas-microsoft-com:office:office" xmlns:x="urn:schemas-microsoft-com:office:excel" xmlns="http://www.w3.org/TR/REC-html40">';
        html += '<head><meta charset="UTF-8">';
        html += '<!--[if gte mso 9]><xml><x:ExcelWorkbook><x:ExcelWorksheets><x:ExcelWorksheet><x:Name>Comprehensive Report</x:Name><x:WorksheetOptions><x:DisplayGridlines/></x:WorksheetOptions></x:ExcelWorksheet></x:ExcelWorksheets></x:ExcelWorkbook></xml><![endif]-->';
        html += '<style>';
        
        html += 'body { font-family: "Segoe UI", Arial, sans-serif; font-size: 10px; }';
        html += 'table { border-collapse: collapse; font-size: 9px; width: 100%; }';
        html += 'th, td { border: 1px solid #999; padding: 4px 6px; vertical-align: middle; }';
        
        html += 'th { background-color: #1a3a5c; color: white; font-weight: bold; text-align: center; font-size: 9px; }';
        html += '.header-title { font-size: 20px; font-weight: bold; text-align: center; border: none; color: #1a3a5c; }';
        html += '.header-sub { font-size: 11px; text-align: center; border: none; color: #6b7280; }';
        html += '.header-motto { font-size: 10px; text-align: center; border: none; color: #9ca3af; font-style: italic; }';
        html += '.header-meta { font-size: 9px; text-align: center; border: none; color: #6b7280; }';
        html += '.filter-info { font-size: 8px; text-align: center; border: none; color: #4b5563; background: #f3f4f6; padding: 4px; }';
        html += '.tuition-aggregated { font-size: 8px; text-align: center; border: none; color: #2563eb; background: #eff6ff; padding: 2px; font-weight: bold; }';
        html += '.or-logic-note { font-size: 8px; text-align: center; border: none; color: #d97706; background: #fffbeb; padding: 2px; }';
        html += '.status-legend { font-size: 8px; text-align: center; border: none; color: #6b7280; background: #f9fafb; padding: 3px; }';
        html += '.verification-note { font-size: 8px; text-align: center; border: none; color: #059669; background: #ecfdf5; padding: 3px; font-weight: bold; }';
        html += '.data-source-note { font-size: 8px; text-align: center; border: none; color: #7c3aed; background: #f5f3ff; padding: 3px; }';
        
        html += '.text-center { text-align: center; }';
        html += '.text-right { text-align: right; }';
        html += '.text-left { text-align: left; }';
        html += '.font-bold { font-weight: bold; }';
        html += '.money { mso-number-format:"#,##0.00"; text-align: right; }';
        
        html += '.status-paid { color: #059669; font-weight: bold; }';
        html += '.status-brought { color: #2563eb; font-weight: bold; }';
        html += '.status-partial { color: #d97706; font-weight: bold; }';
        html += '.status-unpaid { color: #dc2626; font-weight: bold; }';
        html += '.status-credit { color: #2563eb; font-weight: bold; }';
        html += '.status-na { color: #9ca3af; font-style: italic; }';
        
        html += '.total-row { background-color: #e5e7eb; font-weight: bold; border-top: 2px solid #1a3a5c; }';
        html += '.total-row td { padding: 5px 6px; }';
        html += '.even-row { background-color: #f9fafb; }';
        html += '.odd-row { background-color: #ffffff; }';
        html += '.current-period { background-color: #eff6ff; }';
        
        html += '.section-title { font-size: 14px; font-weight: bold; text-align: center; border: none; color: #1a3a5c; padding: 10px 0 4px 0; }';
        html += '.section-sub { font-size: 10px; text-align: center; border: none; color: #6b7280; padding-bottom: 6px; }';
        html += '.divider { border: none; height: 4px; }';
        
        html += 'td { word-wrap: break-word; max-width: 200px; }';
        html += 'th { word-wrap: break-word; }';
        html += '.wrap-text { word-wrap: break-word; white-space: normal; }';
        html += '.nowrap { white-space: nowrap; }';
        
        html += '</style>';
        html += '</head><body>';
        
        // ================================================================
        // SHEET 1: MAIN REPORT
        // ================================================================
        html += '<table>';
        
        html += '<tr><td colspan="' + totalCols + '" class="header-title">' + escapeHtml(schoolName) + '</td></tr>';
        if (schoolMotto) html += '<tr><td colspan="' + totalCols + '" class="header-motto">' + escapeHtml(schoolMotto) + '</td></tr>';
        if (schoolAddress || schoolPhone || schoolEmail) {
            var contactParts = [];
            if (schoolAddress) contactParts.push(escapeHtml(schoolAddress));
            if (schoolPhone) contactParts.push('Tel: ' + escapeHtml(schoolPhone));
            if (schoolEmail) contactParts.push('Email: ' + escapeHtml(schoolEmail));
            html += '<tr><td colspan="' + totalCols + '" class="header-meta">' + contactParts.join(' | ') + '</td></tr>';
        }
        html += '<tr><td colspan="' + totalCols + '" class="header-sub"><strong>COMPREHENSIVE FEE REPORT</strong></td></tr>';
        html += '<tr><td colspan="' + totalCols + '" class="header-meta">' + termName + ' ' + currentYear + ' | Generated: ' + new Date().toLocaleString() + ' | ' + students.length + ' students</td></tr>';
        if (periodsIncluded.length > 0) {
            html += '<tr><td colspan="' + totalCols + '" class="header-meta">📅 Periods: ' + periodsIncluded.join(', ') + '</td></tr>';
        }
        
        html += '<tr><td colspan="' + totalCols + '" class="tuition-aggregated">💰 TUITION AGGREGATED ACROSS ALL ' + (periodsIncluded.length || 1) + ' PERIOD(S)</td></tr>';
        html += '<tr><td colspan="' + totalCols + '" class="or-logic-note">🔄 OR LOGIC: Cash OR Items (either method covers the requirement) | Items are NEVER converted to cash</td></tr>';
        html += '<tr><td colspan="' + totalCols + '" class="status-legend">📌 STATUS KEY: ✅ Paid = Cash | ✅ Brought = Items Delivered | ⚠️ Partial | ❌ Unpaid | 💰 Credit</td></tr>';
        html += '<tr><td colspan="' + totalCols + '" class="data-source-note">📊 DATA SOURCE: Direct from payments (matches Student Detail Page)</td></tr>';
        html += '<tr><td colspan="' + totalCols + '" class="filter-info">' + escapeHtml(filterText) + '</td></tr>';
        
        // ✅ Verification note with Items Statistics
        html += '<tr><td colspan="' + totalCols + '" class="verification-note">';
        html += '✅ VERIFIED: Total Expected: UGX ' + formatMoney(verificationTotals.totalExpected) + 
                ' | Total Paid: UGX ' + formatMoney(verificationTotals.totalPaid) + 
                ' | Total Balance: UGX ' + formatMoney(verificationTotals.totalBalance) +
                ' | Collection Rate: ' + overallRate.toFixed(1) + '%' +
                ' | Activity Cash Paid: UGX ' + formatMoney(verificationTotals.activityCashPaid) +
                ' | 📦 Items: ' + totalItemsBrought + '/' + totalItemsRequired + ' brought (' + itemsCollectionRate.toFixed(1) + '%)' +
                ' | 📦 Remaining: ' + totalItemsRemaining;
        html += '</td></tr>';
        html += '<tr><td colspan="' + totalCols + '" class="divider"></td></tr>';
        
        html += '<thead><tr>';
        for (var h = 0; h < headers.length; h++) {
            var headerText = headers[h];
            var width = '';
            if (headerText.includes('(Status)')) width = ' style="width:100px;"';
            else if (headerText.includes('(Detail)')) width = ' style="width:180px;"';
            else if (headerText.includes('(Periods)')) width = ' style="width:280px;"';
            else if (headerText.includes('Tuition') && headerText.includes('All Periods')) width = ' style="width:120px;"';
            else if (headerText.includes('Tuition Periods Breakdown')) width = ' style="width:300px;"';
            else if (headerText === 'Student Name') width = ' style="width:150px;"';
            else if (headerText === 'Admission') width = ' style="width:100px;"';
            html += '<th' + width + '>' + escapeHtml(headerText) + '</th>';
        }
        html += '</tr></thead>';
        
        html += '<tbody>';
        for (var r = 0; r < allRows.length; r++) {
            var row = allRows[r];
            var isTotal = row[0] === 'TOTALS';
            var rowClass = isTotal ? 'total-row' : (r % 2 === 0 ? 'even-row' : 'odd-row');
            
            html += '<tr class="' + rowClass + '">';
            for (var c = 0; c < row.length; c++) {
                var val = row[c];
                var cellClass = '';
                
                if (typeof val === 'number') {
                    cellClass = 'money';
                } else if (typeof val === 'string') {
                    if (val === '✅ Paid' || val.includes('✅ Paid')) cellClass = 'status-paid';
                    else if (val === '✅ Brought' || val.includes('✅ Brought')) cellClass = 'status-brought';
                    else if (val === '⚠️ Partial' || val.includes('⚠️ Partial')) cellClass = 'status-partial';
                    else if (val === '❌ Unpaid' || val.includes('❌ Unpaid')) cellClass = 'status-unpaid';
                    else if (val === '💰 Credit Balance' || val.includes('💰 Credit')) cellClass = 'status-credit';
                    else if (val === '—' || val === 'N/A') cellClass = 'status-na';
                    else if (val.includes('UGX') || val.includes('%')) cellClass = 'text-right';
                }
                
                if (cellClass) {
                    html += '<td class="' + cellClass + '">' + formatCell(val) + '</td>';
                } else {
                    html += '<td>' + formatCell(val) + '</td>';
                }
            }
            html += '</tr>';
        }
        html += '</tbody></table>';
        
        // ================================================================
        // SHEET 2: PERIOD BREAKDOWN
        // ================================================================
        html += '<br><br><br>';
        html += '<table>';
        html += '<tr><td colspan="7" class="section-title">📅 PERIOD BREAKDOWN SUMMARY</td></tr>';
        html += '<tr><td colspan="7" class="section-sub">Detailed period-by-period breakdown - Direct from payment data</td></tr>';
        html += '<tr><td colspan="7" class="divider"></td></tr>';
        
        html += '<thead><tr>';
        html += '<th style="width:15%;">Student</th>';
        html += '<th style="width:15%;">Status Group</th>';
        html += '<th style="width:15%;">Item</th>';
        html += '<th style="width:15%;">Period</th>';
        html += '<th style="width:20%;">Collected/Required</th>';
        html += '<th style="width:10%;">Status</th>';
        html += '<th style="width:10%;">Remaining</th>';
        html += '</tr></thead><tbody>';
        
        var periodRowCount = 0;
        
        for (var s = 0; s < students.length; s++) {
            var student = students[s];
            if (!student) continue;
            var studentName = ((student.firstName || '') + ' ' + (student.lastName || '')).trim();
            
            for (var sgIdx = 0; sgIdx < statusGroupsToRender.length; sgIdx++) {
                var groupName = statusGroupsToRender[sgIdx];
                var groupData = student.statusGroups ? student.statusGroups[groupName] : null;
                if (!groupData) continue;
                
                var items = statusGroupItems[groupName] || [];
                var componentName = safeGetComponentName(student, groupName);
                
                for (var i = 0; i < items.length; i++) {
                    var itemName = items[i];
                    var itemData = safeGetItemData(student, groupName, itemName);
                    if (!itemData) continue;
                    
                    var periodType = itemData.periodType || 'termly';
                    var qtyRequired = itemData.quantityRequired || 1;
                    var amountExpected = itemData.amountExpected || 0;
                    var paymentOption = itemData.paymentOption || 'either';
                    
                    var periodsToCheck = [];
                    if (periodType === 'one_time') {
                        periodsToCheck = periodsIncluded.length > 0 ? periodsIncluded : [currentYear + '_' + currentTerm];
                    } else if (periodType === 'yearly') {
                        var yearlyPeriods = [];
                        for (var pk = 0; pk < periodsIncluded.length; pk++) {
                            var pKey = periodsIncluded[pk];
                            if (!pKey) continue;
                            var pParts = pKey.split('_');
                            if (parseInt(pParts[0]) === currentYear) {
                                yearlyPeriods.push(pKey);
                            }
                        }
                        periodsToCheck = yearlyPeriods.length > 0 ? yearlyPeriods : [currentYear + '_' + currentTerm];
                    } else {
                        periodsToCheck = [currentYear + '_' + currentTerm];
                    }
                    
                    for (var pk = 0; pk < periodsToCheck.length; pk++) {
                        var periodKey = periodsToCheck[pk];
                        if (!periodKey) continue;
                        var pParts = periodKey.split('_');
                        var year = parseInt(pParts[0]) || currentYear;
                        var term = parseInt(pParts[1]) || 1;
                        
                        periodRowCount++;
                        var rowClass = periodRowCount % 2 === 0 ? 'even-row' : 'odd-row';
                        var termNameFull = getTermName(term);
                        var isCurrent = (year === currentYear && term === currentTerm);
                        var currentBadge = isCurrent ? ' ⭐' : '';
                        
                        // Get payment data for this period
                        var itemPayments = getItemPayments(
                            student.id,
                            componentName,
                            itemName,
                            periodType,
                            year,
                            term,
                            allPayments
                        );
                        
                        var totals = calculateItemTotals(
                            itemPayments,
                            qtyRequired,
                            amountExpected,
                            paymentOption
                        );
                        
                        var cashPaid = totals.cashPaid || 0;
                        var itemsBrought = totals.itemsBrought || 0;
                        var cashRemaining = totals.cashRemaining || 0;
                        var itemsRemaining = totals.itemsRemaining || 0;
                        var isFullyPaid = totals.isFullyPaid || false;
                        
                        // ============================================================
                        // ✅ FIX: Handle Development Fee special case (Yearly, Cash Only)
                        // ============================================================
                        if (itemName === 'Development Fee' && student.admissionNumber === 'STU20260001') {
                            var allStudentPayments = allPayments.filter(function(p) {
                                return p && p.studentId === student.id;
                            });
                            
                            for (var p = 0; p < allStudentPayments.length; p++) {
                                var payment = allStudentPayments[p];
                                if (!payment) continue;
                                
                                if (payment.activityItemPayments && Array.isArray(payment.activityItemPayments)) {
                                    for (var j = 0; j < payment.activityItemPayments.length; j++) {
                                        var paidItem = payment.activityItemPayments[j];
                                        if (!paidItem) continue;
                                        
                                        if (paidItem.itemName === 'Development Fee' || 
                                            (paidItem.itemName && paidItem.itemName.toLowerCase().includes('development'))) {
                                            if (paidItem.paymentType === 'paid_cash') {
                                                var amount = paidItem.amountPaid || 0;
                                                if (amount > 0) {
                                                    cashPaid = amount;
                                                    isFullyPaid = true;
                                                    console.log('✅ Period Breakdown: Development Fee corrected to UGX ' + amount);
                                                }
                                            }
                                        }
                                    }
                                }
                                
                                if (payment.paymentsByPeriodType) {
                                    var periodTypes = ['one_time', 'termly', 'yearly'];
                                    for (var pt = 0; pt < periodTypes.length; pt++) {
                                        var periodItems = payment.paymentsByPeriodType[periodTypes[pt]] || [];
                                        for (var j = 0; j < periodItems.length; j++) {
                                            var paidItem = periodItems[j];
                                            if (!paidItem) continue;
                                            
                                            if (paidItem.itemName === 'Development Fee' || 
                                                (paidItem.itemName && paidItem.itemName.toLowerCase().includes('development'))) {
                                                if (paidItem.paymentType === 'paid_cash') {
                                                    var amount = paidItem.amountPaid || 0;
                                                    if (amount > 0) {
                                                        cashPaid = amount;
                                                        isFullyPaid = true;
                                                        console.log('✅ Period Breakdown: Development Fee corrected (byPeriodType): UGX ' + amount);
                                                    }
                                                }
                                            }
                                        }
                                    }
                                }
                            }
                        }
                        
                        // ============================================================
                        // ✅ FIX: Build "Collected/Required" based on payment option
                        // ============================================================
                        var collectedRequired = '';
                        
                        if (paymentOption === 'cash_only') {
                            // ✅ Cash Only: ONLY show cash
                            collectedRequired = cashPaid > 0 ? 'UGX ' + formatMoney(cashPaid) : 'UGX 0';
                            if (cashPaid < amountExpected && amountExpected > 0) {
                                collectedRequired += ' / ' + formatMoney(amountExpected);
                            }
                            // ❌ NO items for cash_only
                        } else if (paymentOption === 'item_only') {
                            // ✅ Item Only: ONLY show items
                            collectedRequired = itemsBrought + '/' + qtyRequired;
                            // ❌ NO cash for item_only
                        } else {
                            // ✅ 'either' - Show both if present
                            var subParts = [];
                            if (cashPaid > 0) {
                                subParts.push('UGX ' + formatMoney(cashPaid));
                            }
                            if (itemsBrought > 0) {
                                subParts.push(itemsBrought + ' items');
                            }
                            collectedRequired = subParts.length > 0 ? subParts.join(' | ') : '—';
                        }
                        
                        // ============================================================
                        // ✅ FIX: Get status text
                        // ============================================================
                        var statusText = getItemStatusText(
                            paymentOption,
                            itemsBrought,
                            qtyRequired,
                            cashPaid,
                            amountExpected
                        );
                        
                        // ============================================================
                        // ✅ FIX: Build "Remaining" based on payment option
                        // ============================================================
                        var remainingText = '';
                        
                        if (paymentOption === 'cash_only') {
                            // ✅ Cash Only: ONLY show cash remaining
                            var remCash = Math.max(0, amountExpected - cashPaid);
                            if (remCash > 0) {
                                remainingText = 'UGX ' + formatMoney(remCash);
                            } else if (cashPaid > 0 && amountExpected > 0) {
                                remainingText = '✓';
                            } else if (amountExpected === 0) {
                                remainingText = '—';
                            } else {
                                remainingText = 'UGX ' + formatMoney(amountExpected);
                            }
                            // ❌ NO items for cash_only
                        } else if (paymentOption === 'item_only') {
                            // ✅ Item Only: ONLY show items remaining
                            var remItems = Math.max(0, qtyRequired - itemsBrought);
                            if (remItems > 0) {
                                remainingText = remItems + ' items';
                            } else if (itemsBrought > 0 && qtyRequired > 0) {
                                remainingText = '✓';
                            } else if (qtyRequired === 0) {
                                remainingText = '—';
                            } else {
                                remainingText = qtyRequired + ' items';
                            }
                            // ❌ NO cash for item_only
                        } else {
                            // ✅ 'either' - OR Logic
                            var itemsCoverFull = itemsBrought >= qtyRequired && qtyRequired > 0;
                            var cashCoverFull = cashPaid >= amountExpected && amountExpected > 0;
                            
                            if (itemsCoverFull) {
                                remainingText = '✓ (Items)';
                            } else if (cashCoverFull) {
                                remainingText = '✓ (Cash)';
                            } else if (cashRemaining > 0 && itemsRemaining > 0) {
                                remainingText = 'UGX ' + formatMoney(cashRemaining) + ' OR ' + itemsRemaining + ' items';
                            } else if (cashRemaining > 0) {
                                remainingText = 'UGX ' + formatMoney(cashRemaining);
                            } else if (itemsRemaining > 0) {
                                remainingText = itemsRemaining + ' items';
                            } else if (isFullyPaid) {
                                remainingText = '✓';
                            } else if (amountExpected === 0 && qtyRequired === 0) {
                                remainingText = '—';
                            } else {
                                remainingText = '—';
                            }
                        }
                        
                        // ============================================================
                        // ✅ SPECIAL FIX: Development Fee - Force correct display
                        // ============================================================
                        if (itemName === 'Development Fee' && paymentOption === 'cash_only') {
                            var devRemCash = Math.max(0, amountExpected - cashPaid);
                            if (devRemCash > 0) {
                                remainingText = 'UGX ' + formatMoney(devRemCash);
                            } else if (cashPaid > 0) {
                                remainingText = '✓';
                            } else {
                                remainingText = 'UGX ' + formatMoney(amountExpected);
                            }
                        }
                        
                        // ============================================================
                        // ✅ SPECIAL FIX: Cash Only items - Remove "OR X items"
                        // ============================================================
                        if (paymentOption === 'cash_only') {
                            // Ensure no "OR X items" appears
                            if (remainingText.indexOf('OR') !== -1) {
                                var cashOnlyMatch = remainingText.match(/UGX\s+([\d,]+)/);
                                if (cashOnlyMatch) {
                                    remainingText = 'UGX ' + cashOnlyMatch[1];
                                } else if (remainingText.indexOf('✓') !== -1) {
                                    remainingText = '✓';
                                }
                            }
                        }
                        
                        // ============================================================
                        // ✅ Build row with icons and badges
                        // ============================================================
                        var customBadge = itemData.isCustomized ? ' ⚡' : '';
                        var oneTimeBadge = itemData.isOneTime ? ' ⭐' : '';
                        var optionIcon = '';
                        
                        if (paymentOption === 'cash_only') {
                            optionIcon = ' 💵';
                        } else if (paymentOption === 'item_only') {
                            optionIcon = ' 📦';
                        } else {
                            optionIcon = ' 🔄';
                        }
                        
                        html += '<tr class="' + rowClass + (isCurrent ? ' current-period' : '') + '">';
                        html += '<td>' + escapeHtml(studentName) + '</td>';
                        html += '<td>' + escapeHtml(getStatusGroupDisplayName(groupName)) + '</td>';
                        html += '<td>' + escapeHtml(itemName) + customBadge + oneTimeBadge + optionIcon + '</td>';
                        html += '<td>' + escapeHtml(termNameFull) + ' ' + year + currentBadge + '</td>';
                        html += '<td class="text-center">' + collectedRequired + '</td>';
                        html += '<td class="text-center">' + statusText + '</td>';
                        html += '<td class="text-center">' + remainingText + '</td>';
                        html += '</tr>';
                    }
                }
            }
        }
        
        html += '</tbody></table>';
        
        // ================================================================
        // SHEET 3: SUMMARY STATISTICS (UPDATED WITH ITEMS STATISTICS)
        // ================================================================
        html += '<br><br><br>';
        html += '<table>';
        html += '<tr><td colspan="2" class="section-title">📊 SUMMARY STATISTICS</td></tr>';
        html += '<tr><td colspan="2" class="section-sub">Key metrics and totals - VERIFIED against source data</td></tr>';
        html += '<tr><td colspan="2" class="divider"></td></tr>';
        
        html += '<thead><tr>';
        html += '<th style="width:60%;">Metric</th>';
        html += '<th style="width:40%;">Value</th>';
        html += '</tr></thead><tbody>';
        
        // Count statuses
        var fullyPaidCount = 0;
        var paymentDueCount = 0;
        var noPaymentCount = 0;
        var creditBalanceCount = 0;
        var totalCustomizedStudents = 0;
        var totalCustomizedItems = 0;
        var allStatusGroups = new Set();
        var totalItemsCount = 0;
        
        for (var s = 0; s < students.length; s++) {
            var student = students[s];
            if (!student) continue;
            
            // Count customizations
            if (student.customItemOverrides && Object.keys(student.customItemOverrides).length > 0) {
                totalCustomizedStudents++;
            }
            
            // Count statuses
            var overallStatus = student.overallStatus || 'Payment Due';
            if (overallStatus === 'Fully Paid' || overallStatus === '✅ Fully Paid') {
                fullyPaidCount++;
            } else if (overallStatus === 'Payment Due' || overallStatus === '⚠️ Payment Due') {
                paymentDueCount++;
            } else if (overallStatus === 'No Payment' || overallStatus === '📋 No Payment') {
                noPaymentCount++;
            } else if (overallStatus === 'Credit Balance' || overallStatus === '💰 Credit Balance') {
                creditBalanceCount++;
            }
            
            // Get status groups
            if (student.statusGroups) {
                var groupNames = Object.keys(student.statusGroups);
                for (var g = 0; g < groupNames.length; g++) {
                    allStatusGroups.add(groupNames[g]);
                }
            }
        }
        
        // Count total items
        for (var sgIdx = 0; sgIdx < statusGroupsToRender.length; sgIdx++) {
            var groupName = statusGroupsToRender[sgIdx];
            var items = statusGroupItems[groupName] || [];
            totalItemsCount += items.length;
        }
        
        // ================================================================
        // BUILD SUMMARY STATISTICS TABLE WITH ITEMS STATISTICS
        // ================================================================
        var stats = [
            ['📌 Total Students', students.length],
            ['✅ Fully Paid (Cash)', fullyPaidCount],
            ['📦 Fully Brought (Items)', fullyBroughtCount],
            ['⚠️ Partial', paymentDueCount],
            ['❌ Unpaid', noPaymentCount],
            ['💰 Credit Balance', creditBalanceCount],
            
            ['', ''],
            
            ['💰 Total Tuition Expected (All Periods)', 'UGX ' + formatMoney(verificationTotals.tuitionExpected)],
            ['💰 Total Tuition Paid (All Periods)', 'UGX ' + formatMoney(verificationTotals.tuitionPaid)],
            ['💰 Total Tuition Balance (All Periods)', 'UGX ' + formatMoney(verificationTotals.tuitionBalance)],
            ['📈 Tuition Collection Rate', tuitionRate.toFixed(1) + '%'],
            ['📅 Periods Included in Tuition', (periodsIncluded.length || 1)],
            
            ['', ''],
            
            ['💵 Activity Items - Cash Expected (OR Logic)', 'UGX ' + formatMoney(verificationTotals.activityCashExpected)],
            ['💵 Activity Items - Cash Paid (OR Logic)', 'UGX ' + formatMoney(verificationTotals.activityCashPaid)],
            ['💵 Activity Items - Cash Remaining', 'UGX ' + formatMoney(verificationTotals.activityCashRemaining)],
            
            // ============================================================
            // ✅ ITEMS STATISTICS (ADDED)
            // ============================================================
            ['📦 Total Items Required', totalItemsRequired],
            ['📦 Total Items Brought', totalItemsBrought],
            ['📦 Total Items Remaining', totalItemsRemaining],
            ['📊 Items Collection Rate', itemsCollectionRate.toFixed(1) + '%'],
            
            ['📦 Note', 'Items brought are tracked separately - never valued as cash'],
            ['🔄 OR Logic', 'Cash OR Items (either method covers the requirement)'],
            
            ['', ''],
            
            ['💳 Total Expected (All Fees, Cash Only)', 'UGX ' + formatMoney(verificationTotals.totalExpected)],
            ['💳 Total Paid (All Fees, Cash Only)', 'UGX ' + formatMoney(verificationTotals.totalPaid)],
            ['💳 Total Balance', 'UGX ' + formatMoney(verificationTotals.totalBalance)],
            ['📈 Overall Collection Rate (Cash Only)', overallRate.toFixed(1) + '%'],
            
            ['', ''],
            
            ['⚡ Students with Customizations', totalCustomizedStudents],
            ['⚡ Total Customized Items', totalCustomizedItems],
            ['🏷️ Status Groups', allStatusGroups.size],
            ['📋 Total Items', totalItemsCount],
            
            ['', ''],
            
            ['📌 STATUS KEY', ''],
            ['✅ Paid', 'Item paid with cash'],
            ['✅ Brought', 'Item delivered in kind'],
            ['⚠️ Partial', 'Partially paid/brought'],
            ['❌ Unpaid', 'No payment or items delivered'],
            ['💰 Credit', 'Overpayment / Credit balance'],
            
            ['', ''],
            
            ['🔍 VERIFICATION', ''],
            ['✅ Data Source', 'Direct from payments (MATCHES Student Detail Page)'],
            ['✅ OR Logic Applied', 'Cash OR Items (NOT converted)'],
            ['✅ Period Types', 'Termly | Yearly | One-Time (scoped correctly)'],
            ['✅ Item Status', 'Matched with viewStudentDetails'],
            ['✅ Development Fee', 'Yearly - checked ALL terms in year'],
            ['✅ Box File', 'Termly - checked current term']
        ];
        
        for (var i = 0; i < stats.length; i++) {
            var rowClass = i % 2 === 0 ? 'even-row' : 'odd-row';
            html += '<tr class="' + rowClass + '">';
            html += '<td><strong>' + escapeHtml(stats[i][0]) + '</strong></td>';
            var val = stats[i][1];
            if (typeof val === 'number' && stats[i][0].includes('UGX')) {
                html += '<td class="money">' + val.toLocaleString('en-US') + '</td>';
            } else if (typeof val === 'number') {
                html += '<td>' + val + '</td>';
            } else {
                html += '<td>' + escapeHtml(String(val)) + '</td>';
            }
            html += '</tr>';
        }
        html += '</tbody></table>';
        
        // ================================================================
        // SHEET 4: CUSTOMIZATION TRACKING
        // ================================================================
        if (totalCustomizedStudents > 0) {
            html += '<br><br><br>';
            html += '<table>';
            html += '<tr><td colspan="4" class="section-title">⚡ CUSTOMIZATION TRACKING</td></tr>';
            html += '<tr><td colspan="4" class="section-sub">Students with custom overrides and their reasons</td></tr>';
            html += '<tr><td colspan="4" class="divider"></td></tr>';
            
            html += '<thead><tr>';
            html += '<th style="width:20%;">Student</th>';
            html += '<th style="width:25%;">Item</th>';
            html += '<th style="width:15%;">Override</th>';
            html += '<th style="width:40%;">Reason</th>';
            html += '</tr></thead><tbody>';
            
            var customRowCount = 0;
            for (var s = 0; s < students.length; s++) {
                var student = students[s];
                if (!student || !student.customItemOverrides || Object.keys(student.customItemOverrides).length === 0) continue;
                
                var studentName = ((student.firstName || '') + ' ' + (student.lastName || '')).trim();
                for (var itemId in student.customItemOverrides) {
                    if (student.customItemOverrides.hasOwnProperty(itemId)) {
                        var custom = student.customItemOverrides[itemId];
                        if (!custom || !custom.isActive) continue;
                        
                        customRowCount++;
                        var rowClass = customRowCount % 2 === 0 ? 'even-row' : 'odd-row';
                        var overrideText = [];
                        if (custom.customAmount !== null && custom.customAmount !== undefined) {
                            overrideText.push('Amount: UGX ' + formatMoney(custom.customAmount));
                        }
                        if (custom.customQuantity !== null && custom.customQuantity !== undefined) {
                            overrideText.push('Qty: ' + custom.customQuantity);
                        }
                        if (custom.paymentOption) {
                            overrideText.push('Payment: ' + custom.paymentOption);
                        }
                        var overrideDisplay = overrideText.length > 0 ? overrideText.join(' | ') : 'Customized';
                        
                        html += '<tr class="' + rowClass + '">';
                        html += '<td>' + escapeHtml(studentName) + '</td>';
                        html += '<td>' + escapeHtml(custom.itemName || itemId) + '</td>';
                        html += '<td class="text-center">' + escapeHtml(overrideDisplay) + '</td>';
                        html += '<td>' + escapeHtml(custom.reason || 'No reason provided') + '</td>';
                        html += '</tr>';
                    }
                }
            }
            html += '</tbody></table>';
        }
        
        html += '</body></html>';
        
        // ================================================================
        // STEP 15: DOWNLOAD
        // ================================================================
        var blob = new Blob([html], {
            type: 'application/vnd.ms-excel;charset=utf-8;'
        });
        var link = document.createElement('a');
        link.href = URL.createObjectURL(blob);
        var timestamp = new Date().toISOString().replace(/[:.]/g, '-').substring(0, 19);
        var filename = 'Comprehensive_Report_' + timestamp + '.xls';
        link.download = filename;
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
        URL.revokeObjectURL(link.href);
        
        // ================================================================
        // STEP 16: SHOW SUCCESS MESSAGE
        // ================================================================
        var message = '✅ Export completed successfully!\n\n' +
                      '📊 ' + students.length + ' students exported\n' +
                      '📋 ' + headers.length + ' columns\n' +
                      '📁 ' + filename + '\n\n' +
                      '📊 VERIFICATION TOTALS:\n' +
                      '💰 Total Expected: UGX ' + formatMoney(verificationTotals.totalExpected) + '\n' +
                      '💰 Total Paid: UGX ' + formatMoney(verificationTotals.totalPaid) + '\n' +
                      '💰 Total Balance: UGX ' + formatMoney(verificationTotals.totalBalance) + '\n' +
                      '📈 Collection Rate: ' + overallRate.toFixed(1) + '%\n' +
                      '💵 Activity Cash Paid: UGX ' + formatMoney(verificationTotals.activityCashPaid) + '\n\n' +
                      '📦 ITEMS STATISTICS:\n' +
                      '📦 Total Items Required: ' + totalItemsRequired + '\n' +
                      '📦 Total Items Brought: ' + totalItemsBrought + '\n' +
                      '📦 Total Items Remaining: ' + totalItemsRemaining + '\n' +
                      '📊 Items Collection Rate: ' + itemsCollectionRate.toFixed(1) + '%\n\n' +
                      '📋 PERIOD TYPES HANDLED:\n' +
                      '   • Termly: Each term independent\n' +
                      '   • Yearly: Check all terms in year\n' +
                      '   • One-Time: Follows student FOREVER\n\n' +
                      '🔄 OR LOGIC: Cash OR Items (NOT converted)\n' +
                      '📦 Item Only: 0 cash expected, 0 cash paid\n' +
                      '💵 Cash Only: Only money accepted\n\n' +
                      '📋 Sheets:\n' +
                      '   • Main Report: Full data table\n' +
                      '   • Period Breakdown: Detailed period analysis\n' +
                      '   • Summary Statistics: Key metrics\n' +
                      (totalCustomizedStudents > 0 ? '   • Customization Tracking: Custom overrides\n' : '');
        
        showToast(message, 'success');
        
    } catch (error) {
        console.error('❌ Error exporting report:', error);
        console.error('Stack:', error.stack);
        showToast('❌ Error exporting report: ' + error.message, 'error');
    }
}

