// ================================================================
// HELPER FUNCTIONS
// ================================================================

function formatMoney(amount) {
    var num = Math.round(amount || 0);
    return num.toLocaleString('en-US');
}

function escapeHtml(text) {
    if (!text) return '';
    var div = document.createElement('div');
    div.textContent = text;
    return div.innerHTML;
}

function getTermName(term) {
    var names = { 1: 'First Term', 2: 'Second Term', 3: 'Third Term' };
    return names[term] || 'Term ' + term;
}

function getTermShort(term) {
    var names = { 1: 'T1', 2: 'T2', 3: 'T3' };
    return names[term] || 'T' + term;
}

function showToast(message, type) {
    var toast = document.createElement('div');
    var bgColor = type === 'success' ? 'bg-green-500' :
                  type === 'error' ? 'bg-red-500' :
                  type === 'warning' ? 'bg-yellow-500' : 'bg-blue-500';
    toast.className = 'fixed bottom-4 right-4 ' + bgColor + ' text-white px-4 py-3 rounded-lg shadow-lg z-50 max-w-sm text-sm';
    toast.innerHTML = message.replace(/\n/g, '<br>');
    document.body.appendChild(toast);
    setTimeout(function() {
        toast.style.opacity = '0';
        toast.style.transition = 'opacity 0.3s';
        setTimeout(function() { toast.remove(); }, 400);
    }, 6000);
}


