// Get color class for status based on percentage
function getStatusColor(rate) {
    if (rate >= 85) return 'text-green-600';
    if (rate >= 70) return 'text-yellow-600';
    if (rate >= 50) return 'text-orange-600';
    return 'text-red-600';
}

// Get bar color for status based on percentage
function getStatusBarColor(rate) {
    if (rate >= 85) return 'bg-green-500';
    if (rate >= 70) return 'bg-yellow-500';
    if (rate >= 50) return 'bg-orange-500';
    return 'bg-red-500';
}

// Get status badge HTML based on percentage
function getStatusBadge(rate) {
    if (rate >= 85) return '<span class="px-2 py-0.5 rounded-full text-xs bg-green-100 text-green-800">Excellent</span>';
    if (rate >= 70) return '<span class="px-2 py-0.5 rounded-full text-xs bg-yellow-100 text-yellow-800">Good</span>';
    if (rate >= 50) return '<span class="px-2 py-0.5 rounded-full text-xs bg-orange-100 text-orange-800">Needs Attention</span>';
    return '<span class="px-2 py-0.5 rounded-full text-xs bg-red-100 text-red-800">Critical</span>';
}

// Get status group color class
function getStatusGroupColor(name) {
    if (!name) return 'bg-gray-100 text-gray-800 border-gray-200';
    
    const colors = {
        'Transportation': 'bg-orange-100 text-orange-800 border-orange-200',
        'Admission Fee': 'bg-purple-100 text-purple-800 border-purple-200',
        'schoolastic requirement': 'bg-green-100 text-green-800 border-green-200',
        'Scholastic': 'bg-green-100 text-green-800 border-green-200',
        'Sports': 'bg-blue-100 text-blue-800 border-blue-200',
        'Development': 'bg-red-100 text-red-800 border-red-200',
        'Tuition': 'bg-indigo-100 text-indigo-800 border-indigo-200'
    };
    
    const lowerName = (name || '').toLowerCase();
    for (const [key, color] of Object.entries(colors)) {
        if (lowerName.includes(key.toLowerCase()) || key.toLowerCase().includes(lowerName)) {
            return color;
        }
    }
    
    return 'bg-gray-100 text-gray-800 border-gray-200';
}

