// ==================== ENHANCED METRIC CARD (WITH HOVER EXPAND & PRIVACY TOGGLE) ====================
function renderMetricCardEnhanced(label, value, icon, color, subtext) {
    const colorMap = {
        blue: 'from-blue-500 to-blue-600 border-blue-500',
        green: 'from-green-500 to-green-600 border-green-500',
        red: 'from-red-500 to-red-600 border-red-500',
        yellow: 'from-yellow-500 to-yellow-600 border-yellow-500',
        purple: 'from-purple-500 to-purple-600 border-purple-500',
        indigo: 'from-indigo-500 to-indigo-600 border-indigo-500',
        pink: 'from-pink-500 to-pink-600 border-pink-500',
        emerald: 'from-emerald-500 to-emerald-600 border-emerald-500',
        orange: 'from-orange-500 to-orange-600 border-orange-500',
        teal: 'from-teal-500 to-teal-600 border-teal-500'
    };
    
    const gradient = colorMap[color] || 'from-gray-500 to-gray-600 border-gray-500';
    const bgLight = color === 'blue' ? 'bg-blue-100' : 
                    color === 'green' ? 'bg-green-100' : 
                    color === 'red' ? 'bg-red-100' : 
                    color === 'yellow' ? 'bg-yellow-100' : 
                    color === 'purple' ? 'bg-purple-100' : 
                    color === 'indigo' ? 'bg-indigo-100' : 
                    color === 'pink' ? 'bg-pink-100' : 
                    color === 'emerald' ? 'bg-emerald-100' : 
                    color === 'orange' ? 'bg-orange-100' : 
                    color === 'teal' ? 'bg-teal-100' : 'bg-gray-100';
    
    // Determine if this is a financial card
    const isFinancial = label.includes('Expected') || label.includes('Collected') || label.includes('Outstanding') || label.includes('Collection Rate');
    const cardId = 'metric_' + label.replace(/\s/g, '_');
    
    return `
        <div class="bg-white rounded-xl shadow-sm border-l-4 ${gradient} p-3 transition-all duration-300 hover:shadow-lg hover:scale-105 hover:z-10 group relative cursor-pointer" 
             id="${cardId}"
             onclick="toggleMetricVisibility('${cardId}')">
            <div class="flex justify-between items-start">
                <div class="min-w-0 flex-1">
                    <p class="text-xs text-gray-500 truncate flex items-center gap-1">
                        ${label}
                        ${isFinancial ? `<span class="text-gray-300 text-[10px]">👁️</span>` : ''}
                    </p>
                    <p class="text-lg font-bold truncate metric-value" id="${cardId}_value">
                        ${isFinancial ? '••••••••••' : value}
                    </p>
                    ${subtext ? `<p class="text-xs text-gray-400 truncate metric-sub" id="${cardId}_sub">${subtext}</p>` : ''}
                </div>
                <div class="w-8 h-8 ${bgLight} rounded-full flex items-center justify-center flex-shrink-0 transition-transform group-hover:scale-110">
                    <i class="fas ${icon} text-sm"></i>
                </div>
            </div>
            <!-- Hover tooltip with full details -->
            <div class="absolute hidden group-hover:block bg-gray-900 text-white text-xs rounded-lg p-3 z-50 -bottom-2 left-1/2 transform -translate-x-1/2 translate-y-full w-64 shadow-xl">
                <p class="font-bold">${label}</p>
                <p class="text-lg font-mono">${value}</p>
                ${subtext ? `<p class="text-gray-300 text-xs mt-1">${subtext}</p>` : ''}
                <div class="absolute -top-1 left-1/2 transform -translate-x-1/2 w-2 h-2 bg-gray-900 rotate-45"></div>
                <p class="text-[10px] text-gray-400 mt-1">Click to toggle visibility</p>
            </div>
        </div>
    `;
}

// ==================== TOGGLE METRIC VISIBILITY (PRIVACY TOGGLE) ====================
let metricVisibilityState = {};

function toggleMetricVisibility(cardId) {
    const valueEl = document.getElementById(cardId + '_value');
    const subEl = document.getElementById(cardId + '_sub');
    
    if (!valueEl) return;
    
    // Toggle state
    if (!metricVisibilityState[cardId]) {
        metricVisibilityState[cardId] = false;
    }
    metricVisibilityState[cardId] = !metricVisibilityState[cardId];
    
    const isVisible = metricVisibilityState[cardId];
    
    // Get original values from data attribute or from the card
    const card = document.getElementById(cardId);
    const originalValue = card?.dataset.originalValue || valueEl.textContent;
    const originalSub = card?.dataset.originalSub || (subEl ? subEl.textContent : '');
    
    if (isVisible) {
        // Show numbers
        valueEl.textContent = originalValue;
        if (subEl && originalSub) subEl.textContent = originalSub;
        valueEl.className = 'text-lg font-bold truncate metric-value text-green-600';
    } else {
        // Hide numbers (password format)
        const isFinancial = cardId.includes('Expected') || cardId.includes('Collected') || cardId.includes('Outstanding') || cardId.includes('Collection Rate');
        if (isFinancial) {
            valueEl.textContent = '••••••••••';
            valueEl.className = 'text-lg font-bold truncate metric-value text-gray-400';
            if (subEl) subEl.textContent = '••••••••';
        }
    }
}

// ==================== RENDER STATUS GROUP CARD ====================
function renderStatusGroupCard(sg) {
    const rate = sg.totalRequired > 0 ? (sg.totalCollected / sg.totalRequired * 100) : 0;
    const rateColor = getStatusColor(rate);
    const barColor = getStatusBarColor(rate);
    const badge = getStatusBadge(rate);
    
    // Get top items
    const items = Object.values(sg.items || {});
    const topItems = items
        .sort((a, b) => (b.collected / b.required || 0) - (a.collected / a.required || 0))
        .slice(0, 4);
    
    const colorClass = sg.color || 'bg-gray-100 text-gray-800 border-gray-200';
    const borderColor = colorClass.split(' ').find(c => c.startsWith('border-')) || 'border-gray-200';
    
    return `
        <div class="bg-white rounded-xl shadow-sm border ${borderColor} overflow-hidden hover:shadow-md transition">
            <div class="p-4">
                <div class="flex justify-between items-start mb-3">
                    <div>
                        <div class="flex items-center gap-2">
                            <i class="fas fa-tag text-purple-500"></i>
                            <h4 class="font-bold text-lg">🏷️ ${escapeHtml(sg.name)}</h4>
                            ${badge}
                        </div>
                        <p class="text-xs text-gray-500">${sg.periodType === 'one_time' ? '⭐ One-Time' : sg.periodType === 'termly' ? '📅 Termly' : '📆 Yearly'}</p>
                    </div>
                    <div class="text-right">
                        <p class="text-2xl font-bold ${rateColor}">${rate.toFixed(1)}%</p>
                    </div>
                </div>
                
                <div class="grid grid-cols-4 gap-2 mb-3">
                    <div class="bg-gray-50 rounded-lg p-2 text-center">
                        <p class="text-xs text-gray-500">Required</p>
                        <p class="text-lg font-bold">${sg.totalRequired}</p>
                    </div>
                    <div class="bg-gray-50 rounded-lg p-2 text-center">
                        <p class="text-xs text-gray-500">Collected</p>
                        <p class="text-lg font-bold text-green-600">${sg.totalCollected}</p>
                    </div>
                    <div class="bg-gray-50 rounded-lg p-2 text-center">
                        <p class="text-xs text-gray-500">Remaining</p>
                        <p class="text-lg font-bold text-red-600">${sg.totalRemaining}</p>
                    </div>
                    <div class="bg-gray-50 rounded-lg p-2 text-center">
                        <p class="text-xs text-gray-500">Students</p>
                        <p class="text-lg font-bold">${sg.studentCount || 0}</p>
                    </div>
                </div>
                
                <div class="w-full bg-gray-200 rounded-full h-2 mb-3">
                    <div class="${barColor} rounded-full h-2 transition-all" style="width: ${Math.min(100, rate)}%"></div>
                </div>
                
                ${topItems.length > 0 ? `
                    <div class="mt-3 pt-3 border-t">
                        <p class="text-xs font-semibold text-gray-600 mb-2">📦 Items:</p>
                        <div class="space-y-1.5">
                            ${topItems.map(item => {
                                const itemRate = item.required > 0 ? (item.collected / item.required * 100) : 0;
                                const itemColor = getStatusColor(itemRate);
                                const itemBar = getStatusBarColor(itemRate);
                                return `
                                    <div class="flex items-center gap-2">
                                        <span class="text-xs font-medium flex-1">${escapeHtml(item.name)}</span>
                                        <span class="text-xs font-bold ${itemColor}">${item.collected}/${item.required}</span>
                                        <div class="w-16 bg-gray-200 rounded-full h-1">
                                            <div class="${itemBar} rounded-full h-1" style="width: ${Math.min(100, itemRate)}%"></div>
                                        </div>
                                    </div>
                                `;
                            }).join('')}
                            ${Object.values(sg.items || {}).length > 4 ? `
                                <p class="text-xs text-gray-400 text-center">+${Object.values(sg.items || {}).length - 4} more items</p>
                            ` : ''}
                        </div>
                    </div>
                ` : ''}
                
                <button onclick="navigateToStatusGroupReport('${escapeHtml(sg.name)}')" 
                        class="mt-3 w-full bg-purple-50 hover:bg-purple-100 text-purple-700 text-sm py-1.5 rounded-lg transition font-medium">
                    <i class="fas fa-eye mr-1"></i> View Details
                </button>
            </div>
        </div>
    `;
}

// ==================== RENDER CLASS PERFORMANCE TABLE ====================
function renderClassPerformanceTable(statusGroups) {
    const classSet = new Set();
    statusGroups.forEach(sg => {
        Object.keys(sg.classBreakdown || {}).forEach(cls => classSet.add(cls));
    });
    const classes = Array.from(classSet).sort();
    
    if (classes.length === 0) {
        return `
            <div class="text-center py-8 text-gray-500">
                <i class="fas fa-chalkboard text-3xl mb-2"></i>
                <p>No class performance data available</p>
                <p class="text-sm text-gray-400">Data will appear once students are assigned to classes</p>
            </div>
        `;
    }
    
    const groupsWithData = statusGroups.filter(sg => Object.keys(sg.classBreakdown || {}).length > 0);
    
    if (groupsWithData.length === 0) {
        return `
            <div class="text-center py-8 text-gray-500">
                <i class="fas fa-tags text-3xl mb-2"></i>
                <p>No status group data by class</p>
            </div>
        `;
    }
    
    let html = `
        <div class="overflow-x-auto">
            <table class="w-full text-xs">
                <thead class="bg-gray-100 sticky top-0">
                    <tr>
                        <th class="p-2 text-left sticky left-0 bg-gray-100 z-10">Status Group</th>
                        ${classes.map(cls => `
                            <th class="p-2 text-center min-w-12">${escapeHtml(cls)}</th>
                        `).join('')}
                    </tr>
                </thead>
                <tbody>
    `;
    
    for (const sg of groupsWithData) {
        const breakdown = sg.classBreakdown || {};
        const rate = sg.totalRequired > 0 ? (sg.totalCollected / sg.totalRequired * 100) : 0;
        const rowColor = rate >= 85 ? 'bg-green-50' : rate >= 70 ? 'bg-yellow-50' : rate >= 50 ? 'bg-orange-50' : 'bg-red-50';
        
        html += `
            <tr class="border-b ${rowColor} hover:bg-gray-50 cursor-pointer" 
                onclick="navigateToStatusGroupReport('${escapeHtml(sg.name)}')">
                <td class="p-2 font-medium sticky left-0 bg-inherit z-10">${escapeHtml(sg.name)}</td>
        `;
        
        for (const cls of classes) {
            const data = breakdown[cls] || { required: 0, collected: 0 };
            const clsRate = data.required > 0 ? (data.collected / data.required * 100) : 0;
            const clsColor = clsRate >= 85 ? 'text-green-600' : clsRate >= 70 ? 'text-yellow-600' : clsRate >= 50 ? 'text-orange-600' : 'text-red-600';
            const clsBg = clsRate >= 85 ? 'bg-green-100' : clsRate >= 70 ? 'bg-yellow-100' : clsRate >= 50 ? 'bg-orange-100' : 'bg-red-100';
            
            html += `
                <td class="p-2 text-center ${clsBg} rounded">
                    ${data.required > 0 ? `<span class="font-bold ${clsColor}">${clsRate.toFixed(0)}%</span>` : '-'}
                    ${data.required > 0 ? `<div class="text-xs text-gray-400">${data.collected}/${data.required}</div>` : ''}
                </td>
            `;
        }
        
        html += `</tr>`;
    }
    
    html += `
                </tbody>
            </table>
        </div>
        <div class="mt-3 text-xs text-gray-400 text-center">
            <span class="inline-block w-3 h-3 bg-green-100 rounded mr-1"></span> ≥85% 
            <span class="inline-block w-3 h-3 bg-yellow-100 rounded ml-2 mr-1"></span> 70-84% 
            <span class="inline-block w-3 h-3 bg-orange-100 rounded ml-2 mr-1"></span> 50-69% 
            <span class="inline-block w-3 h-3 bg-red-100 rounded ml-2 mr-1"></span> &lt;50%
            <span class="ml-2 text-gray-400">Click a row to view details</span>
        </div>
    `;
    
    return html;
}

// ==================== INITIALIZE PAYMENT STATUS CHART ====================
function initializePaymentStatusChart(paymentStatus) {
    const canvas = document.getElementById('paymentStatusChart');
    if (!canvas) return;
    
    const ctx = canvas.getContext('2d');
    
    const data = {
        labels: ['Fully Paid', 'Payment Due', 'Critical Overdue', 'No Payment', 'Credit Balance'],
        datasets: [{
            data: [
                paymentStatus.fullyPaid || 0,
                paymentStatus.paymentDue || 0,
                paymentStatus.criticalOverdue || 0,
                paymentStatus.noPayment || 0,
                paymentStatus.creditBalance || 0
            ],
            backgroundColor: ['#10b981', '#f59e0b', '#ef4444', '#9ca3af', '#3b82f6'],
            borderWidth: 2,
            borderColor: '#ffffff'
        }]
    };
    
    const total = data.datasets[0].data.reduce((a, b) => a + b, 0);
    
    new Chart(ctx, {
        type: 'doughnut',
        data: data,
        options: {
            responsive: true,
            maintainAspectRatio: true,
            cutout: '65%',
            plugins: {
                legend: {
                    position: 'bottom',
                    labels: {
                        padding: 10,
                        usePointStyle: true,
                        font: { size: 11 }
                    }
                },
                tooltip: {
                    callbacks: {
                        label: function(context) {
                            const value = context.raw;
                            const percentage = total > 0 ? ((value / total) * 100).toFixed(1) : 0;
                            return `${context.label}: ${value} (${percentage}%)`;
                        }
                    }
                }
            }
        }
    });
}

// ==================== ITEM FILTERS ====================
function initializeItemFilters() {
    const searchInput = document.getElementById('itemSearchInput');
    const groupFilter = document.getElementById('itemStatusGroupFilter');
    
    if (searchInput) {
        searchInput.addEventListener('keyup', filterItemsTable);
        searchInput.addEventListener('input', filterItemsTable);
    }
    if (groupFilter) {
        groupFilter.addEventListener('change', filterItemsTable);
    }
}

function filterItemsTable() {
    const searchTerm = (document.getElementById('itemSearchInput')?.value || '').toLowerCase().trim();
    const groupValue = document.getElementById('itemStatusGroupFilter')?.value || '';
    
    const rows = document.querySelectorAll('#itemsTable .item-row');
    let visibleCount = 0;
    
    rows.forEach(row => {
        const name = row.getAttribute('data-name') || '';
        const group = row.getAttribute('data-group') || '';
        
        let matchesSearch = true;
        if (searchTerm) {
            matchesSearch = name.includes(searchTerm);
        }
        
        let matchesGroup = true;
        if (groupValue) {
            matchesGroup = group === groupValue.toLowerCase();
        }
        
        const isVisible = matchesSearch && matchesGroup;
        row.style.display = isVisible ? '' : 'none';
        if (isVisible) visibleCount++;
    });
    
    const countSpan = document.getElementById('itemsVisibleCount');
    if (countSpan) countSpan.innerText = visibleCount;
}

function resetItemFilters() {
    const searchInput = document.getElementById('itemSearchInput');
    const groupFilter = document.getElementById('itemStatusGroupFilter');
    
    if (searchInput) searchInput.value = '';
    if (groupFilter) groupFilter.value = '';
    
    filterItemsTable();
}

let itemsSortDirection = {};

function sortItemsTable(column) {
    const rows = document.querySelectorAll('#itemsTable .item-row');
    const rowArray = Array.from(rows);
    
    if (!itemsSortDirection[column]) itemsSortDirection[column] = 'asc';
    else if (itemsSortDirection[column] === 'asc') itemsSortDirection[column] = 'desc';
    else itemsSortDirection[column] = 'asc';
    
    const direction = itemsSortDirection[column];
    
    rowArray.sort((a, b) => {
        let aVal, bVal;
        
        switch(column) {
            case 'name':
                aVal = a.getAttribute('data-name') || '';
                bVal = b.getAttribute('data-name') || '';
                break;
            case 'statusGroup':
                aVal = a.getAttribute('data-group') || '';
                bVal = b.getAttribute('data-group') || '';
                break;
            case 'required':
                aVal = parseInt(a.getAttribute('data-required')) || 0;
                bVal = parseInt(b.getAttribute('data-required')) || 0;
                break;
            case 'collected':
                aVal = parseInt(a.getAttribute('data-collected')) || 0;
                bVal = parseInt(b.getAttribute('data-collected')) || 0;
                break;
            case 'remaining':
                aVal = parseInt(a.getAttribute('data-remaining')) || 0;
                bVal = parseInt(b.getAttribute('data-remaining')) || 0;
                break;
            case 'rate':
                aVal = parseFloat(a.getAttribute('data-rate')) || 0;
                bVal = parseFloat(b.getAttribute('data-rate')) || 0;
                break;
            case 'students':
                aVal = parseInt(a.getAttribute('data-students')) || 0;
                bVal = parseInt(b.getAttribute('data-students')) || 0;
                break;
            default:
                return 0;
        }
        
        if (typeof aVal === 'string') {
            return direction === 'asc' ? aVal.localeCompare(bVal) : bVal.localeCompare(aVal);
        }
        return direction === 'asc' ? aVal - bVal : bVal - aVal;
    });
    
    const tbody = document.querySelector('#itemsTable tbody');
    if (tbody) {
        rowArray.forEach(row => tbody.appendChild(row));
    }
}

// ==================== NAVIGATION FUNCTIONS ====================
function navigateToStatusGroupReport(statusGroupName) {
    showReports();
    setTimeout(() => {
        const filterSelect = document.getElementById('reportStatusGroupFilter');
        if (filterSelect) {
            for (let i = 0; i < filterSelect.options.length; i++) {
                if (filterSelect.options[i].value === statusGroupName) {
                    filterSelect.value = statusGroupName;
                    break;
                }
            }
            setTimeout(() => {
                if (typeof generateReportV2 === 'function') {
                    generateReportV2();
                }
            }, 200);
        }
    }, 300);
}

// ==================== FIXED PRINT RECEIPT FUNCTION ====================
async function printReceipt(receiptNumber) {
    console.log('printReceipt called with:', receiptNumber);
    
    if (!receiptNumber || receiptNumber === 'undefined' || receiptNumber === 'null') {
        alert('Invalid receipt number. Cannot print receipt.');
        return;
    }
    
    try {
        // Fetch all payments
        const response = await fetch('/api/fee/payments');
        if (!response.ok) {
            throw new Error('Failed to fetch payments');
        }
        
        const payments = await response.json();
        console.log('All payments:', payments);
        
        // Find payment by receipt number (try multiple matching methods)
        let payment = payments.find(p => p.receiptNumber === receiptNumber);
        if (!payment) {
            payment = payments.find(p => p.receiptNumber?.toLowerCase() === receiptNumber.toLowerCase());
        }
        if (!payment) {
            payment = payments.find(p => p.receiptNumber?.includes(receiptNumber) || receiptNumber.includes(p.receiptNumber));
        }
        if (!payment) {
            // Try to find by ID if receipt number is actually an ID
            payment = payments.find(p => p.id === receiptNumber);
        }
        
        if (!payment) {
            console.error('Payment not found for receipt:', receiptNumber);
            alert('Payment record not found for receipt: ' + receiptNumber);
            return;
        }
        
        console.log('Found payment:', payment);
        
        // Now print the receipt
        const schoolRes = await fetch('/api/school');
        const schoolData = await schoolRes.json();
        const school = schoolData.school || {};
        
        // Calculate period totals
        let oneTimeTotal = 0, termlyTotal = 0, yearlyTotal = 0;
        
        if (payment.activityItemPayments) {
            oneTimeTotal += payment.activityItemPayments.filter(i => i.periodType === 'one_time').reduce((s, i) => s + (i.amountPaid || i.cashEquivalent || 0), 0);
            termlyTotal += payment.activityItemPayments.filter(i => i.periodType === 'termly').reduce((s, i) => s + (i.amountPaid || i.cashEquivalent || 0), 0);
            yearlyTotal += payment.activityItemPayments.filter(i => i.periodType === 'yearly').reduce((s, i) => s + (i.amountPaid || i.cashEquivalent || 0), 0);
        }
        
        if (payment.paymentsByPeriodType) {
            oneTimeTotal += (payment.paymentsByPeriodType.one_time || []).reduce((s, i) => s + (i.amountPaid || i.cashEquivalent || 0), 0);
            termlyTotal += (payment.paymentsByPeriodType.termly || []).reduce((s, i) => s + (i.amountPaid || i.cashEquivalent || 0), 0);
            yearlyTotal += (payment.paymentsByPeriodType.yearly || []).reduce((s, i) => s + (i.amountPaid || i.cashEquivalent || 0), 0);
        }
        
        const totalPaid = (payment.tuitionPaid || 0) + oneTimeTotal + termlyTotal + yearlyTotal;
        
        const printWindow = window.open('', '_blank');
        if (!printWindow) {
            alert('Please allow popups to print receipts');
            return;
        }
        
        printWindow.document.write(`
            <!DOCTYPE html>
            <html>
            <head>
                <title>Payment Receipt - ${payment.receiptNumber}</title>
                <style>
                    * { margin: 0; padding: 0; box-sizing: border-box; }
                    body { font-family: 'Segoe UI', Arial, sans-serif; padding: 40px; background: #f0f0f0; }
                    .receipt { max-width: 450px; margin: 0 auto; background: white; border-radius: 16px; overflow: hidden; box-shadow: 0 10px 25px rgba(0,0,0,0.1); }
                    .header { background: linear-gradient(135deg, #1e3c72, #2a5298); color: white; text-align: center; padding: 25px; }
                    .title { font-size: 24px; font-weight: bold; margin-bottom: 5px; }
                    .school-name { font-size: 16px; font-weight: bold; margin-top: 5px; }
                    .receipt-no { font-size: 12px; margin-top: 10px; opacity: 0.8; }
                    .content { padding: 25px; }
                    .row { display: flex; justify-content: space-between; margin: 12px 0; padding: 5px 0; border-bottom: 1px dashed #eee; }
                    .total { font-size: 18px; font-weight: bold; border-top: 2px solid #333; padding-top: 15px; margin-top: 10px; border-bottom: none; }
                    .footer { background: #f8f9fa; text-align: center; padding: 15px; font-size: 11px; color: #666; }
                    .highlight { color: #2a5298; font-weight: bold; }
                    .period-section { background: #f8f9fa; border-radius: 8px; padding: 12px; margin: 12px 0; }
                    .period-title { font-weight: bold; margin-bottom: 8px; color: #2a5298; }
                    .items-list { font-size: 12px; margin-top: 8px; }
                    .items-list div { display: flex; justify-content: space-between; padding: 4px 0; }
                    @media print {
                        body { padding: 0; background: white; }
                        .no-print { display: none; }
                    }
                </style>
            </head>
            <body>
                <div class="receipt">
                    <div class="header">
                        <div class="title">FEE PAYMENT RECEIPT</div>
                        <div class="school-name">${escapeHtml(school.schoolName || 'School Name')}</div>
                        <div class="receipt-no">Receipt No: ${payment.receiptNumber}</div>
                    </div>
                    <div class="content">
                        <div class="row"><strong>Date:</strong> <span>${new Date(payment.date).toLocaleDateString()}</span></div>
                        <div class="row"><strong>Student Name:</strong> <span>${escapeHtml(payment.studentName)}</span></div>
                        <div class="row"><strong>Admission No:</strong> <span>${payment.admissionNumber}</span></div>
                        <div class="row"><strong>Academic Year:</strong> <span>${payment.academicYear} - Term ${payment.term}</span></div>
                        <div class="row"><strong>Payment Method:</strong> <span>${payment.method?.toUpperCase() || 'CASH'}</span></div>
                        ${payment.reference ? `<div class="row"><strong>Reference:</strong> <span>${payment.reference}</span></div>` : ''}
                        
                        ${payment.tuitionPaid > 0 ? `
                            <div class="period-section">
                                <div class="period-title">💰 Tuition Payment</div>
                                <div class="row" style="margin:0;padding:5px 0"><strong>Amount:</strong> <span>UGX ${(payment.tuitionPaid || 0).toLocaleString()}</span></div>
                            </div>
                        ` : ''}
                        
                        ${termlyTotal > 0 ? `
                            <div class="period-section">
                                <div class="period-title">📅 Termly Items Payment</div>
                                <div class="items-list">
                                    ${(payment.activityItemPayments || []).filter(i => i.periodType === 'termly').map(i => `
                                        <div><span>${escapeHtml(i.itemName)}</span><span>UGX ${(i.amountPaid || i.cashEquivalent || 0).toLocaleString()}</span></div>
                                    `).join('')}
                                    ${(payment.paymentsByPeriodType?.termly || []).map(i => `
                                        <div><span>${escapeHtml(i.itemName)}</span><span>UGX ${(i.amountPaid || i.cashEquivalent || 0).toLocaleString()}</span></div>
                                    `).join('')}
                                </div>
                                <div class="row" style="margin-top:8px;border-top:1px solid #ddd"><strong>Total:</strong> <span>UGX ${termlyTotal.toLocaleString()}</span></div>
                            </div>
                        ` : ''}
                        
                        ${oneTimeTotal > 0 ? `
                            <div class="period-section">
                                <div class="period-title">⭐ One-Time Items Payment</div>
                                <div class="items-list">
                                    ${(payment.activityItemPayments || []).filter(i => i.periodType === 'one_time').map(i => `
                                        <div><span>${escapeHtml(i.itemName)}</span><span>UGX ${(i.amountPaid || i.cashEquivalent || 0).toLocaleString()}</span></div>
                                    `).join('')}
                                    ${(payment.paymentsByPeriodType?.one_time || []).map(i => `
                                        <div><span>${escapeHtml(i.itemName)}</span><span>UGX ${(i.amountPaid || i.cashEquivalent || 0).toLocaleString()}</span></div>
                                    `).join('')}
                                </div>
                                <div class="row" style="margin-top:8px;border-top:1px solid #ddd"><strong>Total:</strong> <span>UGX ${oneTimeTotal.toLocaleString()}</span></div>
                            </div>
                        ` : ''}
                        
                        ${yearlyTotal > 0 ? `
                            <div class="period-section">
                                <div class="period-title">📆 Yearly Items Payment</div>
                                <div class="items-list">
                                    ${(payment.activityItemPayments || []).filter(i => i.periodType === 'yearly').map(i => `
                                        <div><span>${escapeHtml(i.itemName)}</span><span>UGX ${(i.amountPaid || i.cashEquivalent || 0).toLocaleString()}</span></div>
                                    `).join('')}
                                    ${(payment.paymentsByPeriodType?.yearly || []).map(i => `
                                        <div><span>${escapeHtml(i.itemName)}</span><span>UGX ${(i.amountPaid || i.cashEquivalent || 0).toLocaleString()}</span></div>
                                    `).join('')}
                                </div>
                                <div class="row" style="margin-top:8px;border-top:1px solid #ddd"><strong>Total:</strong> <span>UGX ${yearlyTotal.toLocaleString()}</span></div>
                            </div>
                        ` : ''}
                        
                        <div class="row total"><strong>TOTAL PAID:</strong> <span class="highlight">UGX ${totalPaid.toLocaleString()}</span></div>
                        ${payment.notes ? `<div class="row"><strong>Notes:</strong> <span>${payment.notes}</span></div>` : ''}
                    </div>
                    <div class="footer">
                        Thank you for your payment!<br>
                        This is a computer-generated receipt.
                    </div>
                </div>
                <div class="no-print" style="text-align:center;margin-top:20px;">
                    <button onclick="window.print()" style="padding:10px 20px;background:#2a5298;color:white;border:none;border-radius:5px;cursor:pointer;">🖨️ Print Receipt</button>
                    <button onclick="window.close()" style="padding:10px 20px;background:#6c757d;color:white;border:none;border-radius:5px;cursor:pointer;">Close</button>
                </div>
            </body>
            </html>
        `);
        printWindow.document.close();
        
    } catch (error) {
        console.error('Error printing receipt:', error);
        alert('Error printing receipt: ' + error.message);
    }
}

// ==================== VIEW PAYMENT RECEIPT ====================
function viewPaymentReceipt(receiptNumber) {
    printReceipt(receiptNumber);
}

// ==================== PRINT DASHBOARD ====================
function printDashboard() {
    window.print();
}

// ==================== REFRESH DASHBOARD ====================
async function refreshDashboard() {
    const btn = document.querySelector('[onclick="refreshDashboard()"]');
    if (btn) {
        const originalHtml = btn.innerHTML;
        btn.innerHTML = '<i class="fas fa-spinner fa-spin"></i> Loading...';
        btn.disabled = true;
        
        await showDashboard();
        
        btn.innerHTML = originalHtml;
        btn.disabled = false;
    } else {
        await showDashboard();
    }
}

// ==================== ESCAPE HTML HELPER ====================
function escapeHtml(text) {
    if (!text) return '';
    const div = document.createElement('div');
    div.textContent = text;
    return div.innerHTML;
}

// ==================== GET TERM NAME ====================
function getTermName(term) {
    const names = { 1: 'First Term', 2: 'Second Term', 3: 'Third Term' };
    return names[term] || `Term ${term}`;
}

// ==================== PRINT DASHBOARD REPORT ====================
async function printDashboardReport() {
    const { currentYear, currentTerm } = currentAcademicSettings;
    const termName = getTermName(currentTerm);
    
    const schoolRes = await fetch('/api/school');
    const schoolData = await schoolRes.json();
    const school = schoolData.school || {};
    
    const students = window.dashboardStudents || [];
    
    const totalExpected = students.reduce((sum, s) => sum + s.totalExpected, 0);
    const totalCollected = students.reduce((sum, s) => sum + s.totalPaid, 0);
    const totalOutstanding = totalExpected - totalCollected;
    const collectionRate = totalExpected > 0 ? (totalCollected / totalExpected * 100).toFixed(1) : 0;
    
    // Get fee structure stats for print
    const feeStructuresRes = await fetch('/api/fee/structures');
    const feeStructures = await feeStructuresRes.json();
    
    const printWindow = window.open('', '_blank');
    
    if (!printWindow) {
        alert('Please allow popups to print the report');
        return;
    }
    
    printWindow.document.write(`
        <!DOCTYPE html>
        <html>
        <head>
            <title>Dashboard Report - ${school.schoolName || 'School'}</title>
            <style>
                * { margin: 0; padding: 0; box-sizing: border-box; }
                body { font-family: 'Segoe UI', Arial, sans-serif; padding: 40px; background: white; }
                .report { max-width: 1200px; margin: 0 auto; }
                .header { text-align: center; margin-bottom: 30px; border-bottom: 2px solid #2a5298; padding-bottom: 20px; }
                .title { font-size: 28px; font-weight: bold; color: #1e3c72; margin-bottom: 8px; }
                .subtitle { font-size: 16px; color: #666; margin-bottom: 5px; }
                .date { font-size: 12px; color: #999; margin-top: 10px; }
                .section { margin-bottom: 30px; }
                .section-title { font-size: 18px; font-weight: bold; border-left: 4px solid #2a5298; padding-left: 15px; margin-bottom: 20px; color: #333; }
                .stats-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(200px, 1fr)); gap: 15px; margin-bottom: 25px; }
                .stat-card { background: #f8f9fa; border-radius: 12px; padding: 15px; text-align: center; border: 1px solid #e0e0e0; }
                .stat-label { font-size: 12px; color: #666; margin-bottom: 5px; }
                .stat-value { font-size: 22px; font-weight: bold; color: #2a5298; }
                .footer { text-align: center; margin-top: 40px; padding-top: 20px; border-top: 1px solid #ddd; font-size: 11px; color: #666; }
                @media print { body { padding: 20px; } .no-print { display: none; } }
            </style>
        </head>
        <body>
            <div class="report">
                <div class="header">
                    <div class="title">DASHBOARD SUMMARY REPORT</div>
                    <div class="subtitle">${escapeHtml(school.schoolName || 'School Name')}</div>
                    <div class="subtitle">${termName} ${currentYear}</div>
                    <div class="date">Generated: ${new Date().toLocaleString()}</div>
                </div>
                
                <div class="section">
                    <h3 class="section-title">📊 Executive Summary</h3>
                    <div class="stats-grid">
                        <div class="stat-card"><div class="stat-label">Total Students</div><div class="stat-value">${students.length}</div></div>
                        <div class="stat-card"><div class="stat-label">Total Expected</div><div class="stat-value">UGX ${(totalExpected / 1000000).toFixed(1)}M</div></div>
                        <div class="stat-card"><div class="stat-label">Total Collected</div><div class="stat-value">UGX ${(totalCollected / 1000000).toFixed(1)}M</div></div>
                        <div class="stat-card"><div class="stat-label">Collection Rate</div><div class="stat-value">${collectionRate}%</div></div>
                    </div>
                </div>
                
                <div class="section">
                    <h3 class="section-title">🏫 Fee Structures Overview</h3>
                    <div class="stats-grid">
                        <div class="stat-card"><div class="stat-label">Total Fee Structures</div><div class="stat-value">${feeStructures.length}</div></div>
                        <div class="stat-card"><div class="stat-label">Nursery Structures</div><div class="stat-value">${feeStructures.filter(f => f.level === 'Nursery').length}</div></div>
                        <div class="stat-card"><div class="stat-label">Lower Primary</div><div class="stat-value">${feeStructures.filter(f => f.level === 'LowerPrimary').length}</div></div>
                        <div class="stat-card"><div class="stat-label">Upper Primary</div><div class="stat-value">${feeStructures.filter(f => f.level === 'UpperPrimary').length}</div></div>
                    </div>
                </div>
                
                <div class="footer">
                    This is a computer-generated dashboard report. For detailed analytics, please refer to the Fee Statistics page.<br>
                    Generated by School Management System
                </div>
            </div>
            <div class="no-print" style="text-align:center;margin-top:20px;">
                <button onclick="window.print()" style="padding:10px 20px;background:#2a5298;color:white;border:none;border-radius:5px;cursor:pointer;">🖨️ Print</button>
                <button onclick="window.close()" style="padding:10px 20px;background:#6c757d;color:white;border:none;border-radius:5px;cursor:pointer;">Close</button>
            </div>
        </body>
        </html>
    `);
    printWindow.document.close();
}

