// ========== EXPORT INVENTORY REPORT V7 ==========
function exportInventoryReportV7() {
    if (!inventoryDataGlobal) {
        alert('No data to export');
        return;
    }
    
    var scholasticItems = getScholasticItemsOnly();
    var itemEntries = Object.entries(scholasticItems);
    
    if (itemEntries.length === 0) {
        alert('No scholastic inventory data to export');
        return;
    }
    
    var headers = ['Item Name', 'Status Group', 'Total Required', 'Brought (Items)', 'Cash Covered (Items)', 
                   'Total Collected', 'Remaining', 'Collection Rate', 'Students'];
    
    var sortedPeriods = Array.from(inventoryPeriodsWithStock).sort();
    sortedPeriods.forEach(function(p) {
        var [year, term] = p.split('_').map(Number);
        var termName = getTermNameFromNumber(term);
        headers.push(termName + ' ' + year + ' Available');
        headers.push(termName + ' ' + year + ' Issued');
    });
    
    var rows = itemEntries.map(function(item) {
        var name = item[0];
        var data = item[1];
        var totalCollected = Math.min((data.totalBrought || 0) + (data.totalCashCoveredItems || 0), data.totalItemsRequired || 0);
        var totalRequired = data.totalItemsRequired || 0;
        var rate = totalRequired > 0 ? Math.min(100, (totalCollected / totalRequired) * 100).toFixed(1) : 0;
        var statusGroup = data.statusGroup || 'Scholastic';
        
        var row = [
            name,
            statusGroup,
            totalRequired,
            data.totalBrought || 0,
            data.totalCashCoveredItems || 0,
            totalCollected,
            Math.max(0, totalRequired - totalCollected),
            rate + '%',
            data.studentsCount || 0
        ];
        
        sortedPeriods.forEach(function(p) {
            var stockData = getStockForItemAndPeriod(name, p);
            row.push(stockData ? stockData.available || 0 : 0);
            row.push(stockData ? stockData.issued || 0 : 0);
        });
        
        return row;
    });
    
    var csv = [headers.join(','), ...rows.map(function(r) { return r.join(','); })].join('\n');
    
    var blob = new Blob([csv], { type: 'text/csv;charset=utf-8;' });
    var link = document.createElement('a');
    link.href = URL.createObjectURL(blob);
    link.download = 'scholastic_inventory_report_' + new Date().toISOString().split('T')[0] + '.csv';
    link.click();
    URL.revokeObjectURL(link.href);
    
    alert('✅ Scholastic inventory report exported successfully!');
}

