// ========== GET STOCK FOR ITEM AND PERIOD (GLOBAL) ==========
function getStockForItemAndPeriod(itemName, periodKey) {
    var key1 = itemName + '_' + periodKey;
    if (inventoryStockGlobal[key1]) return inventoryStockGlobal[key1];
    
    var parts = periodKey.split('_');
    if (parts.length === 2) {
        var key2 = itemName + '_' + parts[0] + '_' + parts[1];
        if (inventoryStockGlobal[key2]) return inventoryStockGlobal[key2];
    }
    
    for (var key in inventoryStockGlobal) {
        if (key.startsWith(itemName + '_') && key.includes(periodKey)) {
            return inventoryStockGlobal[key];
        }
    }
    
    return null;
}

// ========== HELPER FUNCTIONS ==========
function getTermName(term) {
    const names = { 1: 'First Term', 2: 'Second Term', 3: 'Third Term' };
    return names[term] || 'Term ' + term;
}

function getTermNameFromNumber(term) {
    const names = { 1: 'First Term', 2: 'Second Term', 3: 'Third Term' };
    return names[term] || 'Term ' + term;
}

function showToast(message, type) {
    if (typeof type === 'undefined') type = 'success';
    var toast = document.createElement('div');
    var bgColor = type === 'success' ? 'bg-green-500' : type === 'error' ? 'bg-red-500' : 'bg-blue-500';
    toast.className = 'fixed bottom-4 right-4 ' + bgColor + ' text-white px-4 py-2 rounded-lg shadow-lg z-50';
    toast.innerHTML = message;
    document.body.appendChild(toast);
    setTimeout(function() { toast.remove(); }, 3000);
}

function escapeHtml(text) {
    if (!text) return '';
    var div = document.createElement('div');
    div.textContent = text;
    return div.innerHTML;
}

function closeModal() {
    var modal = document.querySelector('.fixed.inset-0');
    if (modal) modal.remove();
}

