// ==================== IS UNIFORM ITEM HELPER ====================

function isUniformItem(itemName, componentName, statusGroupName) {
    if (!itemName) return false;
    
    var lowerName = itemName.toLowerCase();
    var lowerComponent = (componentName || '').toLowerCase();
    var lowerStatusGroup = (statusGroupName || '').toLowerCase();
    
    // ============================================================
    // STEP 1: Check if this is explicitly a uniform status group
    // ============================================================
    var isUniformStatusGroup = 
        lowerStatusGroup === 'uniform' ||
        lowerStatusGroup.includes('uniform') ||
        lowerStatusGroup === 'school uniform' ||
        lowerStatusGroup === 'uniforms';
    
    // ============================================================
    // STEP 2: Check if component name is uniform-related
    // ============================================================
    var isUniformComponent = 
        lowerComponent === 'uniform' ||
        lowerComponent.includes('uniform') ||
        lowerComponent === 'school uniform' ||
        lowerComponent === 'uniforms';
    
    // ============================================================
    // STEP 3: EXCLUDE non-uniform items
    // ============================================================
    var excludedItems = [
        'passport', 'photo', 'picture', 'image',
        'registration', 'admission', 'application',
        'development', 'building', 'construction',
        'tuition', 'fee', 'charges', 'levy',
        'sports', 'sport', 'games', 'athletic',
        'medical', 'health', 'clinic', 'hospital',
        'stationery', 'book', 'notebook', 'exercise book',
        'pen', 'pencil', 'eraser', 'ruler', 'crayon'
    ];
    
    var isExcluded = excludedItems.some(function(keyword) {
        return lowerName.includes(keyword);
    });
    
    // If it's an excluded item, it's NOT a uniform
    if (isExcluded) {
        return false;
    }
    
    // ============================================================
    // STEP 4: UNIFORM KEYWORDS - items that ARE uniforms
    // ============================================================
    var uniformKeywords = [
        // Core uniforms
        'dress', 'shirt', 'skirt', 'trouser', 'pants', 'short', 'blouse', 'tunic',
        'stocking', 'sock', 'belt', 'tie', 'scarf', 'beret', 'cap', 'hat', 
        'blazer', 'jumper', 'sweater', 'cardigan', 'vest', 'pinafore', 'gown', 'frock', 'kilt',
        'badge', 'name tag',
        // Uniform sets
        'school uniform', 'school wear', 'pe kit', 'games kit', 'track suit', 'tracksuit',
        'sportswear', 'sports kit'
    ];
    
    // ============================================================
    // STEP 5: Check if item matches uniform keywords
    // ============================================================
    var matchesKeyword = uniformKeywords.some(function(keyword) {
        return lowerName.includes(keyword);
    });
    
    // ============================================================
    // STEP 6: Check for compound uniform items (e.g., "Dress/Shirt & Short")
    // ============================================================
    var hasSlash = lowerName.includes('/') || lowerName.includes('&') || lowerName.includes('+');
    var hasUniformRelated = lowerName.includes('dress') || 
                            lowerName.includes('shirt') || 
                            lowerName.includes('skirt') ||
                            lowerName.includes('trouser') ||
                            lowerName.includes('short') ||
                            lowerName.includes('blazer') ||
                            lowerName.includes('jumper') ||
                            lowerName.includes('sweater') ||
                            lowerName.includes('vest') ||
                            lowerName.includes('sock') ||
                            lowerName.includes('stocking');
    
    var isCompoundUniform = hasSlash && hasUniformRelated;
    
    // ============================================================
    // FINAL DECISION: It's a uniform if...
    // ============================================================
    // 1. It has a uniform status group, OR
    // 2. It has a uniform component name, OR
    // 3. It matches uniform keywords, OR
    // 4. It's a compound uniform item
    // AND it's not excluded
    
    var isUniform = (isUniformStatusGroup || isUniformComponent || matchesKeyword || isCompoundUniform);
    
    // Debug log
    if (isUniform) {
        console.log('✅ UNIFORM DETECTED:', itemName, '| StatusGroup:', statusGroupName || 'none', '| Component:', componentName || 'none');
    }
    
    return isUniform && !isExcluded;
}


// ==================== GET UNIFORM ITEMS FROM FEE STRUCTURE ====================

function getUniformItemsFromFeeStructure(feeStructure) {
    var uniformItems = [];
    
    if (!feeStructure || !feeStructure.activityComponents) {
        return uniformItems;
    }
    
    for (var i = 0; i < feeStructure.activityComponents.length; i++) {
        var comp = feeStructure.activityComponents[i];
        if (!comp || !comp.items) continue;
        
        var componentName = comp.name || '';
        var statusGroupName = comp.statusGroupName || '';
        
        // Check if this component is uniform-related
        var isUniformComponent = 
            statusGroupName.toLowerCase() === 'uniform' ||
            statusGroupName.toLowerCase().includes('uniform') ||
            componentName.toLowerCase() === 'uniform' ||
            componentName.toLowerCase().includes('uniform');
        
        for (var j = 0; j < comp.items.length; j++) {
            var item = comp.items[j];
            if (!item || !item.name) continue;
            
            // Check if this item is a uniform using the improved function
            var isUniform = isUniformItem(item.name, componentName, statusGroupName);
            
            // Also check if the component is uniform-related
            if (isUniformComponent) {
                isUniform = true;
            }
            
            if (isUniform) {
                uniformItems.push({
                    name: item.name,
                    componentName: componentName,
                    componentId: comp.id,
                    statusGroupName: statusGroupName,
                    periodType: comp.periodType || 'termly',
                    quantity: item.quantity || 1,
                    totalAmount: item.totalAmount || 0,
                    unitPrice: item.unitPrice || (item.totalAmount / (item.quantity || 1)),
                    paymentOption: item.paymentOption || 'either',
                    isTangible: item.paymentOption !== 'cash_only',
                    itemId: item.id || item.name,
                    isUniform: true,
                    isScholastic: false
                });
            }
        }
    }
    
    return uniformItems;
}

// ==================== FETCH ALL STUDENTS WITH UNIFORM REQUIREMENTS ====================

async function fetchAllStudentsWithUniformRequirements() {
    console.log('📊 fetchAllStudentsWithUniformRequirements called');
    
    try {
        var studentsRes = await fetch('/api/students');
        if (!studentsRes.ok) throw new Error('Failed to fetch students');
        var students = await studentsRes.json();
        uniformAllStudentsList = Array.isArray(students) ? students : [];
        console.log('📊 Students loaded:', uniformAllStudentsList.length);
        
        var feeRes = await fetch('/api/fee/structures');
        if (!feeRes.ok) throw new Error('Failed to fetch fee structures');
        var feeStructures = await feeRes.json();
        console.log('📊 Fee structures loaded:', feeStructures.length);
        
        var assignRes = await fetch('/api/student-fee-assignments');
        if (!assignRes.ok) throw new Error('Failed to fetch fee assignments');
        var assignments = await assignRes.json();
        console.log('📊 Fee assignments loaded:', assignments.length);
        
        var classesRes = await fetch('/api/school/classes');
        if (!classesRes.ok) throw new Error('Failed to fetch classes');
        var classes = await classesRes.json();
        uniformAllClassesList = Array.isArray(classes) ? classes : [];
        console.log('📊 Classes loaded:', uniformAllClassesList.length);
        
        var feeStructureMap = {};
        feeStructures.forEach(function(fs) {
            if (fs && fs.id) feeStructureMap[fs.id] = fs;
        });
        
        var assignmentMap = {};
        assignments.forEach(function(a) {
            if (a && a.studentId) assignmentMap[a.studentId] = a;
        });
        
        var classMap = {};
        uniformAllClassesList.forEach(function(c) {
            if (c && c.id) classMap[c.id] = c;
        });
        
        var studentRequirements = {};
        
        for (var i = 0; i < uniformAllStudentsList.length; i++) {
            var student = uniformAllStudentsList[i];
            if (!student || !student.id) continue;
            
            var assignment = assignmentMap[student.id] || {};
            var feeStructure = feeStructureMap[assignment.feeStructureId];
            
            var currentClass = 'Not Assigned';
            var classLevel = 'Unknown';
            if (student.currentClassId && classMap[student.currentClassId]) {
                var classObj = classMap[student.currentClassId];
                currentClass = classObj.name || 'Not Assigned';
                classLevel = classObj.level || 'Unknown';
            } else if (student.currentClass) {
                currentClass = student.currentClass;
            }
            
            var uniformItems = feeStructure ? getUniformItemsFromFeeStructure(feeStructure) : [];
            
            studentRequirements[student.id] = {
                id: student.id,
                firstName: student.firstName || '',
                lastName: student.lastName || '',
                admissionNumber: student.admissionNumber || '',
                currentClass: currentClass,
                classLevel: classLevel,
                feeStructureId: assignment.feeStructureId || null,
                uniformItems: uniformItems,
                totalUniformItems: uniformItems.length
            };
        }
        
        console.log('📊 Student requirements built:', Object.keys(studentRequirements).length);
        return studentRequirements;
        
    } catch (error) {
        console.error('Error fetching student requirements:', error);
        return {};
    }
}

// ==================== BUILD STUDENT DETAILS FROM ALL STUDENTS ====================

async function buildUniformStudentDetailsFromAllStudents() {
    console.log('🔄 buildUniformStudentDetailsFromAllStudents called - FILTERING UNIFORMS ONLY');
    
    try {
        var studentRequirements = await fetchAllStudentsWithUniformRequirements();
        console.log('📊 Student requirements:', Object.keys(studentRequirements).length);
        
        if (!uniformDataGlobal) {
            uniformDataGlobal = {
                levels: {
                    Nursery: { items: {}, students: [], totalItems: 0, collected: 0, remaining: 0 },
                    LowerPrimary: { items: {}, students: [], totalItems: 0, collected: 0, remaining: 0 },
                    UpperPrimary: { items: {}, students: [], totalItems: 0, collected: 0, remaining: 0 }
                },
                classDetails: {},
                studentDetails: {}
            };
        }
        
        var studentIds = Object.keys(studentRequirements);
        var processedCount = 0;
        
        for (var i = 0; i < studentIds.length; i++) {
            var studentId = studentIds[i];
            var req = studentRequirements[studentId];
            if (!req) continue;
            
            // Get uniform transactions for this student
            var studentTxs = uniformTransactionsGlobal.filter(function(t) {
                return t.studentId === studentId && t.transactionType === 'issue';
            });
            
            // Get uniform items from fee structure (already filtered)
            var uniformItems = req.uniformItems || [];
            
            // Build student uniform data
            var uniformData = updateStudentUniformStatus(req, uniformItems, studentTxs);
            
            if (uniformData.hasUniformItems) {
                var studentEntry = {
                    id: studentId,
                    admissionNumber: req.admissionNumber || '',
                    firstName: req.firstName || '',
                    lastName: req.lastName || '',
                    currentClass: req.currentClass || 'Not Assigned',
                    classLevel: req.classLevel || 'Unknown',
                    items: uniformData.items,
                    totalRequired: uniformData.totalRequired,
                    totalCollected: uniformData.totalCollected,
                    totalIssued: uniformData.totalIssued,
                    totalRemaining: uniformData.totalRemaining,
                    uniformStatus: uniformData.uniformStatus,
                    isComplete: uniformData.isComplete,
                    hasUniformItems: uniformData.hasUniformItems
                };
                
                uniformDataGlobal.studentDetails[studentId] = studentEntry;
                processedCount++;
                
                // Add to level data
                var levelKey = getLevelKey(req.classLevel, req.currentClass);
                
                if (levelKey !== 'Unknown' && uniformDataGlobal.levels[levelKey]) {
                    var levelData = uniformDataGlobal.levels[levelKey];
                    if (!levelData.items) levelData.items = {};
                    if (!levelData.students) levelData.students = [];
                    
                    if (levelData.students.indexOf(studentId) === -1) {
                        levelData.students.push(studentId);
                    }
                    
                    var itemKeys = Object.keys(uniformData.items);
                    for (var ik = 0; ik < itemKeys.length; ik++) {
                        var itemKey = itemKeys[ik];
                        var itemData = uniformData.items[itemKey];
                        if (!levelData.items[itemKey]) {
                            levelData.items[itemKey] = {
                                totalRequired: 0,
                                totalCollected: 0,
                                totalRemaining: 0,
                                studentsCount: 0
                            };
                        }
                        levelData.items[itemKey].totalRequired += itemData.quantityRequired || 0;
                        levelData.items[itemKey].totalCollected += itemData.collected || 0;
                        levelData.items[itemKey].totalRemaining += itemData.remaining || 0;
                        levelData.items[itemKey].studentsCount++;
                    }
                    
                    levelData.totalItems += uniformData.totalRequired;
                    levelData.collected += uniformData.totalCollected;
                    levelData.remaining += uniformData.totalRemaining;
                }
            }
        }
        
        uniformStudentDetailsBuilt = true;
        console.log('✅ Built ' + processedCount + ' student uniform details (UNIFORMS ONLY)');
        console.log('📊 Students with uniform items:', Object.keys(uniformDataGlobal.studentDetails).length);
        
        // Log what items are being tracked
        var allItems = {};
        var studentIdsWithUniforms = Object.keys(uniformDataGlobal.studentDetails);
        for (var s = 0; s < studentIdsWithUniforms.length; s++) {
            var sid = studentIdsWithUniforms[s];
            var sData = uniformDataGlobal.studentDetails[sid];
            if (sData && sData.items) {
                var itemKeys = Object.keys(sData.items);
                for (var ik = 0; ik < itemKeys.length; ik++) {
                    var key = itemKeys[ik];
                    if (!allItems[key]) allItems[key] = 0;
                    allItems[key]++;
                }
            }
        }
        console.log('📊 Uniform items being tracked:', allItems);
        
        return uniformDataGlobal.studentDetails;
        
    } catch (error) {
        console.error('Error building student details:', error);
        return {};
    }
}

// ==================== REFRESH UNIFORM DATA ====================

async function refreshUniformData() {
    console.log('🔄 refreshUniformData called');
    
    try {
        var summaryRes = await fetch('/api/uniform/summary');
        if (!summaryRes.ok) throw new Error('Server error ' + summaryRes.status);
        var summary = await summaryRes.json();
        
        console.log('📊 Summary received:', {
            students: Object.keys(summary.data?.studentDetails || {}).length,
            stock: Object.keys(summary.stock || {}).length,
            transactions: summary.transactions?.length || 0
        });

        uniformDataGlobal = summary.data || { levels: {}, classDetails: {}, studentDetails: {}, itemTotals: {} };
        uniformStockGlobal = summary.stock || {};
        uniformTransactionsGlobal = summary.transactions || [];
        uniformAssignmentsGlobal = summary.assignments || {};
        uniformItemsListGlobal = summary.uniformItems || [];

        console.log('📊 Transactions loaded:', uniformTransactionsGlobal.length);
        console.log('📊 Stock items:', Object.keys(uniformStockGlobal).length);

        var feeRes = await fetch('/api/fee/structures');
        if (feeRes.ok) {
            window.feeStructuresData = await feeRes.json();
            console.log('📊 Fee structures loaded:', window.feeStructuresData?.length || 0);
        }

        var paymentsRes = await fetch('/api/fee/payments');
        if (paymentsRes.ok) {
            window.allPaymentsData = await paymentsRes.json();
            console.log('📊 Payments loaded:', window.allPaymentsData?.length || 0);
        }

        var studentsRes = await fetch('/api/students');
        if (studentsRes.ok) {
            var studentsData = await studentsRes.json();
            uniformAllStudentsList = Array.isArray(studentsData) ? studentsData : [];
            console.log('📊 Students loaded:', uniformAllStudentsList.length);
        }

        var classesRes = await fetch('/api/school/classes');
        if (classesRes.ok) {
            var classesData = await classesRes.json();
            uniformAllClassesList = Array.isArray(classesData) ? classesData : [];
            console.log('📊 Classes loaded:', uniformAllClassesList.length);
        }

        await buildUniformStudentDetailsFromAllStudents();
        
        var studentIds = Object.keys(uniformDataGlobal.studentDetails || {});
        var issuedCount = 0, paidCount = 0, partialCount = 0, notPaidCount = 0;
        
        studentIds.forEach(function(id) {
            var s = uniformDataGlobal.studentDetails[id];
            if (!s) return;
            var status = s.uniformStatus || 'none';
            if (status === 'fully_issued') issuedCount++;
            else if (status === 'paid_ready') paidCount++;
            else if (status === 'partial') partialCount++;
            else if (status === 'not_paid') notPaidCount++;
        });
        
        console.log('📊 Student status breakdown:');
        console.log('  ✅ Fully Issued:', issuedCount);
        console.log('  💰 Paid Ready:', paidCount);
        console.log('  ⚠️ Partial:', partialCount);
        console.log('  ❌ Not Paid:', notPaidCount);
        
    } catch (err) {
        console.error('refreshUniformData error:', err);
    }
}

// ==================== BUILD STOCK SECTION ====================

function buildStockSection() {
    var itemNames = Object.keys(uniformStockGlobal);

    if (itemNames.length === 0) {
        return `
            <div class="bg-white rounded-xl border border-gray-200 p-8 text-center shadow-sm">
                <i class="fas fa-tshirt text-gray-300 text-5xl mb-3"></i>
                <p class="text-gray-500 font-medium">No uniform items in stock yet</p>
                <p class="text-gray-400 text-sm mt-1">Use the Stock Management section below to add items</p>
            </div>`;
    }

    var totalReceived = 0, totalIssued = 0, totalAvailable = 0;
    itemNames.forEach(function(n) {
        var s = uniformStockGlobal[n] || {};
        totalReceived += (s.totalReceived || 0);
        totalIssued += (s.issued || 0);
        totalAvailable += (s.available || 0);
    });

    var itemCards = itemNames.map(function(name) {
        var s = uniformStockGlobal[name] || {};
        var received = s.totalReceived || 0;
        var issued = s.issued || 0;
        var available = s.available || 0;
        var usagePct = received > 0 ? Math.min(100, (issued / received) * 100).toFixed(1) : 0;

        var borderCls = available === 0 ? 'border-red-300 bg-red-50'
                      : available < 5  ? 'border-yellow-300 bg-yellow-50'
                      :                  'border-green-300 bg-green-50';
        var statusLbl = available === 0 ? 'Out of Stock'
                      : available < 5  ? 'Low Stock'
                      :                  'In Stock';
        var statusCls = available === 0 ? 'text-red-600'
                      : available < 5  ? 'text-yellow-600'
                      :                  'text-green-600';
        var barCls = usagePct >= 70  ? 'bg-red-500'
                    : usagePct >= 40  ? 'bg-yellow-500'
                    :                   'bg-green-500';

        return `
            <div class="border rounded-xl p-4 ${borderCls} flex flex-col gap-2">
                <div class="flex justify-between items-start">
                    <p class="font-bold text-sm">👕 ${uEscapeHtml(name)}</p>
                    <span class="text-xs font-bold px-2 py-0.5 rounded-full bg-white/60 ${statusCls}">${statusLbl}</span>
                </div>
                <div class="grid grid-cols-3 gap-1 text-center text-xs">
                    <div class="bg-white/70 rounded p-1">
                        <p class="font-bold text-gray-800">${received}</p>
                        <p class="text-gray-500">Received</p>
                    </div>
                    <div class="bg-white/70 rounded p-1">
                        <p class="font-bold text-orange-600">${issued}</p>
                        <p class="text-gray-500">Issued</p>
                    </div>
                    <div class="bg-white/70 rounded p-1">
                        <p class="font-bold ${available === 0 ? 'text-red-600' : 'text-green-700'}">${available}</p>
                        <p class="text-gray-500">Available</p>
                    </div>
                </div>
                <div class="w-full bg-gray-200 rounded-full h-1.5">
                    <div class="${barCls} rounded-full h-1.5 transition-all" style="width:${usagePct}%"></div>
                </div>
                <div class="flex justify-between items-center text-xs text-gray-500">
                    <span>Issued: ${usagePct}%</span>
                    <button onclick="viewItemHistory('${uEscapeHtml(name)}')"
                            class="text-blue-600 hover:text-blue-800 font-medium">
                        <i class="fas fa-history mr-1"></i>History
                    </button>
                </div>
            </div>`;
    }).join('');

    return `
        <div class="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden">
            <div class="bg-gradient-to-r from-blue-600 to-indigo-600 p-4 text-white">
                <div class="flex justify-between items-center flex-wrap gap-3">
                    <div>
                        <h4 class="font-bold text-base flex items-center gap-2">
                            <i class="fas fa-warehouse"></i> Uniform Stock Summary
                        </h4>
                        <p class="text-xs opacity-80">All items persist across all academic periods</p>
                    </div>
                    <div class="flex gap-6 text-center">
                        <div>
                            <p class="text-2xl font-bold">${totalReceived}</p>
                            <p class="text-xs opacity-75">Total Received</p>
                        </div>
                        <div>
                            <p class="text-2xl font-bold text-yellow-300">${totalIssued}</p>
                            <p class="text-xs opacity-75">Issued</p>
                        </div>
                        <div>
                            <p class="text-2xl font-bold text-green-300">${totalAvailable}</p>
                            <p class="text-xs opacity-75">Available</p>
                        </div>
                    </div>
                </div>
            </div>
            <div class="p-4 grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-3">
                ${itemCards}
            </div>
        </div>`;
}

// ==================== BUILD LEVEL CARDS ====================

function buildLevelCards() {
    var levels = ['Nursery', 'LowerPrimary', 'UpperPrimary'];
    var levelColors = {
        Nursery: 'from-pink-500 to-rose-500',
        LowerPrimary: 'from-blue-500 to-indigo-500',
        UpperPrimary: 'from-purple-500 to-violet-500'
    };
    var levelLabels = {
        Nursery: '🎨 Nursery',
        LowerPrimary: '📚 Lower Primary (P.1–P.3)',
        UpperPrimary: '🎓 Upper Primary (P.4–P.7)'
    };

    var totalStudents = Object.keys(uniformDataGlobal.studentDetails || {}).length;
    if (totalStudents === 0) {
        return `
            <div class="col-span-full bg-white rounded-xl border border-gray-200 p-8 text-center">
                <i class="fas fa-user-graduate text-gray-300 text-4xl mb-3"></i>
                <p class="text-gray-500 font-medium">No student uniform data available</p>
                <p class="text-gray-400 text-sm mt-1">Students will appear here once they have uniform items</p>
                <button onclick="refreshUniform()" class="mt-3 bg-blue-600 text-white px-4 py-2 rounded-lg text-sm hover:bg-blue-700">
                    <i class="fas fa-sync-alt mr-1"></i> Refresh
                </button>
            </div>
        `;
    }

    return levels.map(function(level) {
        var ld = (uniformDataGlobal.levels || {})[level] || { 
            items: {}, 
            students: [], 
            totalItems: 0, 
            collected: 0, 
            remaining: 0 
        };
        
        var studentCount = Array.isArray(ld.students) ? ld.students.length : 0;
        var itemEntries = Object.entries(ld.items || {});

        if (itemEntries.length === 0 && studentCount === 0) {
            return `
                <div class="bg-white rounded-xl border border-gray-200 p-6 text-center shadow-sm">
                    <i class="fas fa-tshirt text-gray-300 text-3xl mb-2"></i>
                    <h4 class="font-bold text-gray-400">${uEscapeHtml(levelLabels[level])}</h4>
                    <p class="text-sm text-gray-400">No uniform data</p>
                </div>`;
        }

        var totalRequired = ld.totalItems || 0;
        var totalCollected = ld.collected || 0;
        var totalRemaining = ld.remaining || 0;
        var rate = totalRequired > 0 ? Math.min(100, (totalCollected / totalRequired) * 100).toFixed(1) : 0;
        var gradient = levelColors[level] || 'from-gray-500 to-gray-600';

        var itemRows = '';
        if (itemEntries.length > 0) {
            itemRows = itemEntries.map(function(entry) {
                var iName = entry[0];
                var iData = entry[1];
                var iRate = (iData.totalRequired || 0) > 0
                    ? Math.min(100, ((iData.totalCollected || 0) / iData.totalRequired) * 100).toFixed(0)
                    : 0;
                var iColor = iRate >= 80 ? 'text-green-600' : iRate >= 50 ? 'text-yellow-600' : 'text-red-600';
                var collectedDisplay = iData.totalCollected || 0;
                var requiredDisplay = iData.totalRequired || 0;
                return `
                    <div class="bg-gray-50 rounded-lg p-2 text-center">
                        <p class="text-xs font-semibold text-gray-700 truncate" title="${uEscapeHtml(iName)}">${uEscapeHtml(iName)}</p>
                        <p class="text-sm font-bold ${iColor}">${collectedDisplay}/${requiredDisplay}</p>
                        <p class="text-xs text-gray-400">${iData.studentsCount || 0} students</p>
                    </div>`;
            }).join('');
        } else {
            itemRows = `
                <div class="text-center text-gray-400 text-sm py-4">
                    <i class="fas fa-tshirt text-2xl mb-1 block"></i>
                    No uniform items in this level
                </div>`;
        }

        var studentDisplay = studentCount > 0 ? studentCount + ' student' + (studentCount !== 1 ? 's' : '') : '0 students';

        return `
            <div class="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden">
                <div class="bg-gradient-to-r ${gradient} p-4 text-white">
                    <div class="flex justify-between items-center">
                        <div>
                            <h4 class="font-bold">${uEscapeHtml(levelLabels[level])}</h4>
                            <p class="text-xs opacity-80">${studentDisplay}</p>
                        </div>
                        <div class="text-right">
                            <p class="text-2xl font-bold">${rate}%</p>
                            <p class="text-xs opacity-75">Collection Rate</p>
                        </div>
                    </div>
                    <div class="w-full bg-white/25 rounded-full h-1.5 mt-2">
                        <div class="bg-white rounded-full h-1.5" style="width:${rate}%"></div>
                    </div>
                </div>
                <div class="p-3">
                    <div class="grid grid-cols-2 gap-2 mb-3">
                        ${itemRows}
                    </div>
                    <div class="flex justify-between text-xs font-semibold border-t pt-2">
                        <span class="text-gray-600">Required: ${totalRequired}</span>
                        <span class="text-green-600">Paid: ${totalCollected}</span>
                        <span class="text-red-600">Pending: ${totalRemaining}</span>
                    </div>
                </div>
            </div>`;
    }).join('');
}

// ==================== BUILD STUDENT STATUS COLUMNS ====================

function buildStudentStatusColumns() {
    var studentDetails = uniformDataGlobal.studentDetails || {};
    var studentIds = Object.keys(studentDetails);
    
    if (studentIds.length === 0) {
        return `
            <div class="bg-white rounded-xl border border-gray-200 p-8 text-center shadow-sm col-span-full">
                <i class="fas fa-user-graduate text-gray-300 text-4xl mb-3"></i>
                <p class="text-gray-500 font-medium">No uniform data available</p>
                <p class="text-gray-400 text-sm mt-1">Students will appear here once they have uniform requirements</p>
            </div>
        `;
    }
    
    var fullyIssuedStudents = [];
    var paidReadyStudents = [];
    var partialStudents = [];
    var notPaidStudents = [];
    
    studentIds.forEach(function(id) {
        var student = studentDetails[id];
        if (!student) return;
        
        var totalRequired = student.totalRequired || 0;
        var totalCollected = student.totalCollected || 0;
        var totalIssued = student.totalIssued || 0;
        
        if (totalRequired === 0) return;
        
        var status = student.uniformStatus || 'none';
        
        if (status === 'fully_issued' || totalIssued >= totalRequired) {
            fullyIssuedStudents.push(student);
        } else if (status === 'paid_ready' || totalCollected >= totalRequired) {
            paidReadyStudents.push(student);
        } else if (status === 'partial' || totalCollected > 0) {
            partialStudents.push(student);
        } else {
            notPaidStudents.push(student);
        }
    });
    
    console.log('📊 Student categorization:');
    console.log('  ✅ Fully Issued:', fullyIssuedStudents.length);
    console.log('  💰 Paid Ready:', paidReadyStudents.length);
    console.log('  ⚠️ Partial:', partialStudents.length);
    console.log('  ❌ Not Paid:', notPaidStudents.length);
    
    var sortStudents = function(a, b) {
        var nameA = (a.firstName + ' ' + a.lastName).toLowerCase();
        var nameB = (b.firstName + ' ' + b.lastName).toLowerCase();
        return nameA.localeCompare(nameB);
    };
    
    fullyIssuedStudents.sort(sortStudents);
    paidReadyStudents.sort(sortStudents);
    partialStudents.sort(sortStudents);
    notPaidStudents.sort(sortStudents);
    
    function renderStudentListColumn(students, title, icon, bgColor, emptyMsg, statusType) {
        if (students.length === 0) {
            return `
                <div class="bg-white rounded-xl border border-gray-200 p-6 text-center shadow-sm">
                    <div class="flex items-center justify-center gap-2 mb-2">
                        ${icon}
                        <h4 class="font-bold text-lg">${title}</h4>
                        <span class="text-sm text-gray-400">(0)</span>
                    </div>
                    <p class="text-gray-400 text-sm">${emptyMsg}</p>
                </div>`;
        }
        
        var studentCards = students.map(function(student) {
            var name = (student.firstName || '') + ' ' + (student.lastName || '');
            var admission = student.admissionNumber || 'N/A';
            var currentClass = student.currentClass || 'N/A';
            var totalRequired = student.totalRequired || 0;
            var totalCollected = student.totalCollected || 0;
            var totalIssued = student.totalIssued || 0;
            var remaining = Math.max(0, totalRequired - totalCollected);
            
            var itemStatuses = {
                issued: 0,
                paid: 0,
                partial: 0,
                notPaid: 0
            };
            
            var itemEntries = Object.entries(student.items || {});
            for (var i = 0; i < itemEntries.length; i++) {
                var itemData = itemEntries[i][1];
                var qtyRequired = itemData.quantityRequired || 0;
                var qtyCollected = itemData.collected || 0;
                var qtyIssued = itemData.issued || 0;
                
                if (qtyRequired === 0) continue;
                
                if (qtyIssued >= qtyRequired) {
                    itemStatuses.issued++;
                } else if (qtyCollected >= qtyRequired) {
                    itemStatuses.paid++;
                } else if (qtyCollected > 0) {
                    itemStatuses.partial++;
                } else {
                    itemStatuses.notPaid++;
                }
            }
            
            var statusSummary = [];
            if (itemStatuses.issued > 0) {
                statusSummary.push('<span class="text-blue-600">✅ Issued: ' + itemStatuses.issued + '</span>');
            }
            if (itemStatuses.paid > 0) {
                statusSummary.push('<span class="text-green-600">💰 Paid: ' + itemStatuses.paid + '</span>');
            }
            if (itemStatuses.partial > 0) {
                statusSummary.push('<span class="text-yellow-600">⚠️ Partial: ' + itemStatuses.partial + '</span>');
            }
            if (itemStatuses.notPaid > 0) {
                statusSummary.push('<span class="text-red-600">❌ Not Paid: ' + itemStatuses.notPaid + '</span>');
            }
            
            var itemsHtml = Object.entries(student.items || {}).map(function(entry) {
                var itemName = entry[0];
                var itemData = entry[1];
                var qtyRequired = itemData.quantityRequired || 0;
                var qtyCollected = itemData.collected || 0;
                var qtyIssued = itemData.issued || 0;
                var stockAvail = (uniformStockGlobal[itemName] || {}).available || 0;
                
                if (qtyRequired === 0) return '';
                
                var isFullyIssued = qtyIssued >= qtyRequired && qtyRequired > 0;
                var isFullyPaid = qtyCollected >= qtyRequired && qtyRequired > 0;
                var canIssue = qtyCollected > 0 && !isFullyIssued && stockAvail > 0;
                
                var statusBadge = '';
                if (isFullyIssued) {
                    statusBadge = '<span class="text-xs text-blue-600 font-semibold">✅ Issued</span>';
                } else if (isFullyPaid) {
                    statusBadge = '<span class="text-xs text-green-600 font-semibold">💰 Paid</span>';
                } else if (qtyCollected > 0) {
                    statusBadge = '<span class="text-xs text-yellow-600 font-semibold">⚠️ Partial</span>';
                } else {
                    statusBadge = '<span class="text-xs text-red-600 font-semibold">❌ Not Paid</span>';
                }
                
                var issueButton = '';
                if (canIssue) {
                    var maxIssue = Math.min(qtyCollected - qtyIssued, stockAvail);
                    issueButton = `
                        <button onclick="issueUniformToStudentWithQuantity('${student.id}','${uEscapeHtml(itemName)}', ${maxIssue})" 
                                 class="bg-green-600 hover:bg-green-700 text-white px-2 py-1 rounded text-xs font-semibold transition">
                            <i class="fas fa-tshirt mr-1"></i> Issue
                        </button>
                    `;
                } else if (isFullyIssued) {
                    issueButton = `<span class="text-xs text-blue-600 font-semibold">✓ Issued</span>`;
                } else if (stockAvail === 0 && qtyCollected > 0) {
                    issueButton = `<span class="text-xs text-red-400">Out of Stock</span>`;
                }
                
                return `
                    <div class="border-b border-gray-100 pb-1 mb-1 last:border-0 last:mb-0">
                        <div class="flex justify-between items-center flex-wrap gap-1">
                            <div>
                                <span class="font-medium text-sm">👕 ${uEscapeHtml(itemName)}</span>
                                <span class="text-xs text-gray-500 ml-2">${qtyCollected}/${qtyRequired}</span>
                            </div>
                            <div class="flex items-center gap-1 flex-wrap">
                                ${statusBadge}
                                ${issueButton}
                            </div>
                        </div>
                        <div class="flex justify-between text-xs text-gray-400">
                            <span>Issued: ${qtyIssued}</span>
                            <span>Stock: ${stockAvail}</span>
                        </div>
                    </div>
                `;
            }).filter(function(html) { return html !== ''; }).join('');
            
            var cardColor = '';
            var statusText = '';
            if (statusType === 'fully_issued') {
                cardColor = 'border-blue-200 bg-blue-50';
                statusText = '✅ All Issued';
            } else if (statusType === 'paid_ready') {
                cardColor = 'border-green-200 bg-green-50';
                statusText = '💰 Ready to Issue';
            } else if (statusType === 'partial') {
                cardColor = 'border-yellow-200 bg-yellow-50';
                statusText = '⚠️ Partial';
            } else {
                cardColor = 'border-gray-200 bg-white';
                statusText = '❌ Not Paid';
            }
            
            return `
                <div class="border rounded-lg p-3 ${cardColor} hover:shadow-md transition">
                    <div class="flex justify-between items-start">
                        <div>
                            <p class="font-bold text-sm">${uEscapeHtml(name)}</p>
                            <p class="text-xs text-gray-500">${uEscapeHtml(admission)} | ${uEscapeHtml(currentClass)}</p>
                        </div>
                        <div class="text-right text-xs">
                            <p class="text-green-600">Collected: ${totalCollected}</p>
                            <p class="text-blue-600">Issued: ${totalIssued}</p>
                            <p class="text-red-500">Remaining: ${remaining}</p>
                            <p class="font-semibold ${cardColor.split(' ')[1] === 'bg-blue-50' ? 'text-blue-600' : cardColor.split(' ')[1] === 'bg-green-50' ? 'text-green-600' : cardColor.split(' ')[1] === 'bg-yellow-50' ? 'text-yellow-600' : 'text-red-600'}">${statusText}</p>
                        </div>
                    </div>
                    <div class="mt-1 text-xs flex flex-wrap gap-1">
                        ${statusSummary.join(' ')}
                    </div>
                    <div class="mt-2 pt-2 border-t">
                        ${itemsHtml}
                    </div>
                    <div class="mt-2 pt-2 border-t flex gap-2">
                        <button onclick="viewUniformStudentHistory('${student.id}')"
                                class="bg-blue-600 hover:bg-blue-700 text-white px-2 py-1 rounded text-xs font-semibold transition flex-1 text-center">
                            <i class="fas fa-history mr-1"></i> History
                        </button>
                        <button onclick="showStudentUniformDetail('${student.id}')"
                                class="bg-purple-600 hover:bg-purple-700 text-white px-2 py-1 rounded text-xs font-semibold transition flex-1 text-center">
                            <i class="fas fa-eye mr-1"></i> View
                        </button>
                    </div>
                </div>
            `;
        }).join('');
        
        var columnId = 'uniform_col_' + statusType;
        var searchId = 'uniform_search_' + statusType;
        
        return `
            <div class="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden flex flex-col" style="min-height: 400px;">
                <div class="bg-gradient-to-r ${bgColor} p-3 text-white flex justify-between items-center">
                    <div>
                        <h4 class="font-bold flex items-center gap-2">
                            ${icon} ${title}
                            <span class="text-sm bg-white/20 px-2 py-0.5 rounded-full">${students.length}</span>
                        </h4>
                    </div>
                    <div class="flex items-center gap-2">
                        <div class="relative">
                            <i class="fas fa-search absolute left-2 top-1/2 -translate-y-1/2 text-white/60 text-xs"></i>
                            <input type="text" id="${searchId}" 
                                   placeholder="Search..."
                                   class="w-32 sm:w-48 pl-7 pr-2 py-1 bg-white/20 border border-white/30 rounded text-xs text-white placeholder-white/60 focus:outline-none focus:bg-white/30"
                                   oninput="filterUniformColumn('${columnId}', '${searchId}')">
                        </div>
                        <button onclick="clearUniformColumnSearch('${searchId}', '${columnId}')"
                                class="text-white/60 hover:text-white text-xs">
                            <i class="fas fa-times"></i>
                        </button>
                    </div>
                </div>
                <div id="${columnId}" class="p-3 overflow-y-auto flex-1" style="max-height: 500px;">
                    ${studentCards}
                </div>
            </div>
        `;
    }
    
    var fullyIssuedColumn = renderStudentListColumn(
        fullyIssuedStudents,
        '✅ Fully Issued',
        '<i class="fas fa-check-circle text-blue-400"></i>',
        'from-blue-600 to-blue-700',
        'No students have all uniforms issued.',
        'fully_issued'
    );
    
    var paidReadyColumn = renderStudentListColumn(
        paidReadyStudents,
        '💰 Paid - Ready to Issue',
        '<i class="fas fa-money-bill-wave text-green-400"></i>',
        'from-green-600 to-green-700',
        'No students have paid for all uniforms but not yet issued.',
        'paid_ready'
    );
    
    var partialColumn = renderStudentListColumn(
        partialStudents,
        '⚠️ Partial Payment',
        '<i class="fas fa-clock text-yellow-400"></i>',
        'from-yellow-600 to-yellow-700',
        'No students with partial uniform payments.',
        'partial'
    );
    
    var notPaidColumn = renderStudentListColumn(
        notPaidStudents,
        '❌ Not Paid',
        '<i class="fas fa-times-circle text-red-400"></i>',
        'from-red-600 to-red-700',
        'No students without uniform payments.',
        'not_paid'
    );
    
    return `
        <div class="grid grid-cols-1 lg:grid-cols-4 gap-4">
            ${fullyIssuedColumn}
            ${paidReadyColumn}
            ${partialColumn}
            ${notPaidColumn}
        </div>
    `;
}

// ==================== BUILD STUDENT SEARCH SECTION ====================

function buildStudentSearchSection() {
    return `
        <div class="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden">
            <div class="bg-gradient-to-r from-purple-600 to-pink-600 p-4 text-white">
                <h4 class="font-bold text-base flex items-center gap-2">
                    <i class="fas fa-user-graduate"></i> Student Uniform Status
                </h4>
                <p class="text-xs opacity-80">Search for a student to view and manage their uniform items</p>
            </div>
            <div class="p-4">
                <div class="flex gap-2 flex-wrap">
                    <div class="flex-1 min-w-[220px] relative">
                        <i class="fas fa-search absolute left-3 top-1/2 -translate-y-1/2 text-gray-400 text-sm"></i>
                        <input type="text" id="uniformStudentSearch"
                               placeholder="Search by name or admission number..."
                               class="w-full pl-9 pr-4 py-2 border border-gray-300 rounded-lg text-sm
                                      focus:ring-2 focus:ring-purple-400 focus:border-purple-400 outline-none">
                    </div>
                    <button onclick="searchUniformStudent()"
                            class="bg-purple-600 hover:bg-purple-700 text-white px-4 py-2 rounded-lg text-sm font-semibold transition">
                        <i class="fas fa-search mr-1"></i> Search
                    </button>
                    <button onclick="clearUniformStudentSearch()"
                            class="bg-gray-200 hover:bg-gray-300 text-gray-700 px-4 py-2 rounded-lg text-sm font-semibold transition">
                        <i class="fas fa-times mr-1"></i> Clear
                    </button>
                </div>
                <div id="uniformStudentResult" class="mt-4">
                    <div class="text-center py-6 text-gray-400">
                        <i class="fas fa-search text-2xl mb-2"></i>
                        <p class="text-sm">Search for a student to view their uniform status</p>
                    </div>
                </div>
            </div>
        </div>`;
}

// ==================== BUILD STOCK MANAGEMENT SECTION ====================

function buildStockManagementSection() {
    var allItemNames = new Set(uniformItemsListGlobal);
    Object.keys(uniformStockGlobal).forEach(function(n) { allItemNames.add(n); });
    var itemOptions = Array.from(allItemNames).sort().map(function(item) {
        return `<option value="${uEscapeHtml(item)}">${uEscapeHtml(item)}</option>`;
    }).join('');

    return `
        <div class="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden">
            <div class="bg-gradient-to-r from-green-600 to-teal-600 p-4 text-white">
                <h4 class="font-bold text-base flex items-center gap-2">
                    <i class="fas fa-boxes"></i> Manage Uniform Stock
                </h4>
                <p class="text-xs opacity-80">Add received uniform stock or manually remove items</p>
            </div>
            <div class="p-4">
                <form id="uniformStockForm" onsubmit="return false;">
                    <div class="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4 mb-4">

                        <div>
                            <label class="block text-sm font-semibold text-gray-700 mb-1">Item Name <span class="text-red-500">*</span></label>
                            <div class="flex gap-2">
                                <select id="uniformStockItem"
                                        class="flex-1 border border-gray-300 rounded-lg px-3 py-2 text-sm
                                               focus:ring-2 focus:ring-green-400 focus:border-green-400 outline-none">
                                    <option value="">— Select item —</option>
                                    ${itemOptions}
                                </select>
                                <button type="button" onclick="addNewUniformItem()"
                                        class="bg-blue-600 hover:bg-blue-700 text-white px-3 py-2 rounded-lg text-xs whitespace-nowrap transition">
                                    <i class="fas fa-plus"></i> New
                                </button>
                            </div>
                        </div>

                        <div>
                            <label class="block text-sm font-semibold text-gray-700 mb-1">Quantity <span class="text-red-500">*</span></label>
                            <input type="number" id="uniformStockQuantity" min="1" value="1"
                                   class="w-full border border-gray-300 rounded-lg px-3 py-2 text-sm
                                          focus:ring-2 focus:ring-green-400 outline-none">
                        </div>

                        <div>
                            <label class="block text-sm font-semibold text-gray-700 mb-1">Operation <span class="text-red-500">*</span></label>
                            <select id="uniformStockOperation"
                                    class="w-full border border-gray-300 rounded-lg px-3 py-2 text-sm
                                           focus:ring-2 focus:ring-green-400 outline-none">
                                <option value="add">📦 Add to Stock (Received)</option>
                                <option value="remove">📤 Remove from Stock</option>
                            </select>
                        </div>

                        <div>
                            <label class="block text-sm font-semibold text-gray-700 mb-1">Comment</label>
                            <input type="text" id="uniformStockComment" placeholder="e.g. Delivered by supplier..."
                                   class="w-full border border-gray-300 rounded-lg px-3 py-2 text-sm
                                          focus:ring-2 focus:ring-green-400 outline-none">
                        </div>

                    </div>
                    <div class="flex items-center gap-3 flex-wrap">
                        <button type="submit"
                                class="bg-green-600 hover:bg-green-700 text-white px-6 py-2 rounded-lg font-semibold text-sm transition">
                            <i class="fas fa-save mr-1"></i> Update Stock
                        </button>
                        <p class="text-xs text-gray-500 flex items-center gap-1">
                            <i class="fas fa-info-circle text-blue-400"></i>
                            When a student fully pays for a uniform item it is automatically deducted from stock.
                        </p>
                    </div>
                </form>
            </div>
        </div>`;
}

// ==================== BUILD TRANSACTION HISTORY SECTION ====================

function buildTransactionHistorySection() {
    var txs = uniformTransactionsGlobal.slice().sort(function(a, b) {
        return new Date(b.timestamp || b.date) - new Date(a.timestamp || a.date);
    });

    if (txs.length === 0) {
        return `
            <div class="bg-white rounded-xl border border-gray-200 p-8 text-center shadow-sm">
                <i class="fas fa-history text-gray-300 text-4xl mb-3"></i>
                <p class="text-gray-500">No transactions recorded yet</p>
            </div>`;
    }

    var rows = txs.slice(0, 50).map(function(t) {
        var typeBg = t.transactionType === 'issue' ? 'bg-red-100 text-red-800'
                    : t.transactionType === 'restock' ? 'bg-green-100 text-green-800'
                    : t.transactionType === 'remove' ? 'bg-orange-100 text-orange-800'
                    : 'bg-blue-100 text-blue-800';
        var typeLbl = t.transactionType === 'issue' ? '📤 Issued'
                    : t.transactionType === 'restock' ? '📦 Restock'
                    : t.transactionType === 'remove' ? '➖ Removed'
                    : t.transactionType;
        var dateStr = '';
        try { dateStr = new Date(t.timestamp || t.date).toLocaleDateString('en-UG'); } catch(e) { dateStr = '-'; }

        return `
            <tr class="border-b hover:bg-gray-50 text-xs">
                <td class="p-2 whitespace-nowrap">${dateStr}</td>
                <td class="p-2 font-medium">${uEscapeHtml(t.studentName || 'System')}</td>
                <td class="p-2 font-mono text-gray-500">${uEscapeHtml(t.admissionNumber || '-')}</td>
                <td class="p-2">👕 ${uEscapeHtml(t.itemName || '-')}</td>
                <td class="p-2 text-right font-bold">${t.quantity || 0}</td>
                <td class="p-2 text-center">
                    <span class="px-2 py-0.5 rounded-full text-xs font-semibold ${typeBg}">${typeLbl}</span>
                </td>
                <td class="p-2 text-right text-gray-600">${t.stockAfter != null ? t.stockAfter : '-'}</td>
                <td class="p-2 text-gray-500 max-w-[140px] truncate" title="${uEscapeHtml(t.comment || '')}">${uEscapeHtml(t.comment || '-')}</td>
            </tr>`;
    }).join('');

    return `
        <div class="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden">
            <div class="bg-gradient-to-r from-gray-700 to-gray-900 p-4 text-white">
                <div class="flex justify-between items-center flex-wrap gap-2">
                    <h4 class="font-bold text-base flex items-center gap-2">
                        <i class="fas fa-history"></i> Transaction History
                    </h4>
                    <span class="text-xs opacity-75">${txs.length} total transaction${txs.length !== 1 ? 's' : ''}</span>
                </div>
                <div class="mt-2 flex gap-2">
                    <div class="relative flex-1">
                        <i class="fas fa-search absolute left-2.5 top-1/2 -translate-y-1/2 text-white/60 text-xs"></i>
                        <input type="text" id="uniformTransactionSearch"
                               placeholder="Search by student, item, type..."
                               class="w-full pl-8 pr-3 py-1.5 bg-white/15 border border-white/30 rounded text-sm
                                      text-white placeholder-white/60 focus:outline-none focus:bg-white/25">
                    </div>
                    <button onclick="filterUniformTransactions()"
                            class="bg-white/20 hover:bg-white/30 px-3 py-1.5 rounded text-sm transition">
                        <i class="fas fa-filter"></i>
                    </button>
                    <button onclick="clearTransactionFilter()"
                            class="bg-white/20 hover:bg-white/30 px-3 py-1.5 rounded text-sm transition">
                        <i class="fas fa-times"></i>
                    </button>
                </div>
            </div>
            <div class="overflow-x-auto max-h-96 overflow-y-auto">
                <table class="w-full text-sm" id="uniformTransactionTable">
                    <thead class="bg-gray-100 sticky top-0 z-10">
                        <tr>
                            <th class="p-2 text-left text-xs font-semibold text-gray-600">Date</th>
                            <th class="p-2 text-left text-xs font-semibold text-gray-600">Student</th>
                            <th class="p-2 text-left text-xs font-semibold text-gray-600">Admission</th>
                            <th class="p-2 text-left text-xs font-semibold text-gray-600">Item</th>
                            <th class="p-2 text-right text-xs font-semibold text-gray-600">Qty</th>
                            <th class="p-2 text-center text-xs font-semibold text-gray-600">Type</th>
                            <th class="p-2 text-right text-xs font-semibold text-gray-600">Stock After</th>
                            <th class="p-2 text-left text-xs font-semibold text-gray-600">Comment</th>
                        </tr>
                    </thead>
                    <tbody>${rows}</tbody>
                </table>
            </div>
            ${txs.length > 50 ? `<div class="p-3 text-center text-xs text-gray-400 border-t">Showing latest 50 of ${txs.length} transactions</div>` : ''}
        </div>`;
}

// ==================== SHOW UNIFORM MANAGEMENT (ENTRY POINT) ====================

async function showUniformManagement() {
    console.log('showUniformManagement called - Version 6.1 with Persistent Data');
    
    var pageTitle = document.getElementById('pageTitle');
    if (pageTitle) pageTitle.innerHTML = '<i class="fas fa-tshirt mr-2"></i>Uniform Management';

    var mainContent = document.getElementById('mainContent');
    if (mainContent) {
        mainContent.innerHTML = `
            <div class="flex flex-col justify-center items-center h-64 gap-3">
                <div class="loading-spinner"></div>
                <p class="text-gray-500 text-sm">Loading uniform data...</p>
            </div>`;
    }

    try {
        if (typeof initializeAcademicSettings === 'function') {
            await initializeAcademicSettings();
        }
        uniformCurrentYear = currentAcademicSettings ? currentAcademicSettings.currentYear : new Date().getFullYear();
        uniformCurrentTerm = currentAcademicSettings ? currentAcademicSettings.currentTerm : 1;
        uniformTermName = uGetTermName(uniformCurrentTerm);

        await refreshUniformData();
        renderUniformPageV6();

    } catch (error) {
        console.error('Error loading uniform data:', error);
        if (mainContent) {
            mainContent.innerHTML = `
                <div class="bg-red-50 p-8 text-center rounded-xl border border-red-200">
                    <i class="fas fa-exclamation-triangle text-red-500 text-4xl mb-3"></i>
                    <p class="text-red-700 font-semibold text-lg">Failed to load uniform data</p>
                    <p class="text-red-500 text-sm mt-1">${uEscapeHtml(error.message)}</p>
                    <button onclick="showUniformManagement()"
                            class="mt-4 bg-red-600 text-white px-5 py-2 rounded-lg hover:bg-red-700">
                        <i class="fas fa-sync-alt mr-1"></i> Retry
                    </button>
                </div>`;
        }
    }
}

// ==================== MAIN PAGE RENDERER V6 ====================

function renderUniformPageV6() {
    var mainContent = document.getElementById('mainContent');
    if (!mainContent) return;

    var stockSection = buildStockSection();
    var levelCards = buildLevelCards();
    var statusColumns = buildStudentStatusColumns();
    var studentSearch = buildStudentSearchSection();
    var stockManagement = buildStockManagementSection();
    var transactionHistory = buildTransactionHistorySection();

    var stockCount = Object.keys(uniformStockGlobal).length;
    var studentCount = Object.keys(uniformDataGlobal.studentDetails || {}).length;
    var txCount = uniformTransactionsGlobal.length;
    
    var issuedCount = 0, paidCount = 0, partialCount = 0, notPaidCount = 0;
    var studentDetails = uniformDataGlobal.studentDetails || {};
    Object.keys(studentDetails).forEach(function(id) {
        var student = studentDetails[id];
        if (!student) return;
        var status = student.uniformStatus || 'none';
        var totalRequired = student.totalRequired || 0;
        if (totalRequired === 0) return;
        if (status === 'fully_issued') issuedCount++;
        else if (status === 'paid_ready') paidCount++;
        else if (status === 'partial') partialCount++;
        else notPaidCount++;
    });

    mainContent.innerHTML = `
        <div class="space-y-6">

            <!-- ===== PAGE HEADER ===== -->
            <div class="bg-gradient-to-r from-blue-700 via-indigo-700 to-purple-700 rounded-2xl p-5 text-white shadow-lg">
                <div class="flex justify-between items-center flex-wrap gap-3">
                    <div>
                        <h1 class="text-2xl font-bold flex items-center gap-2">
                            <i class="fas fa-tshirt"></i> Uniform Management
                        </h1>
                        <p class="text-sm opacity-80 mt-0.5">
                            <span class="bg-white/20 px-2 py-0.5 rounded-full text-xs">${uEscapeHtml(uniformTermName)} ${uniformCurrentYear}</span>
                            <span class="ml-2">— Uniforms persist across all academic periods (One-time items)</span>
                        </p>
                        <p class="text-xs opacity-70 mt-1">
                            ${studentCount} students · ${stockCount} stock items · ${txCount} transactions
                        </p>
                    </div>
                    <div class="flex gap-2 flex-wrap">
                        <button onclick="refreshUniform()"
                                class="bg-white/20 hover:bg-white/30 text-white px-4 py-2 rounded-lg text-sm font-semibold transition">
                            <i class="fas fa-sync-alt mr-1"></i> Refresh
                        </button>
                        <button onclick="exportUniformReport()"
                                class="bg-white/20 hover:bg-white/30 text-white px-4 py-2 rounded-lg text-sm font-semibold transition">
                            <i class="fas fa-file-export mr-1"></i> Export Report
                        </button>
                    </div>
                </div>
                <div class="flex gap-3 mt-2 text-sm flex-wrap">
                    <span class="bg-blue-500/30 px-3 py-1 rounded-full">✅ Fully Issued: ${issuedCount}</span>
                    <span class="bg-green-500/30 px-3 py-1 rounded-full">💰 Ready to Issue: ${paidCount}</span>
                    <span class="bg-yellow-500/30 px-3 py-1 rounded-full">⚠️ Partial: ${partialCount}</span>
                    <span class="bg-red-500/30 px-3 py-1 rounded-full">❌ Not Paid: ${notPaidCount}</span>
                </div>
            </div>

            <!-- ===== STOCK SUMMARY ===== -->
            <div>
                <h2 class="text-lg font-bold mb-3 flex items-center gap-2 text-gray-800">
                    <i class="fas fa-warehouse text-green-600"></i> Uniform Stock
                </h2>
                ${stockSection}
            </div>

            <!-- ===== LEVEL SUMMARY ===== -->
            <div>
                <h2 class="text-lg font-bold mb-3 flex items-center gap-2 text-gray-800">
                    <i class="fas fa-layer-group text-blue-600"></i> Level Summary
                </h2>
                <div class="grid grid-cols-1 lg:grid-cols-3 gap-4">
                    ${levelCards}
                </div>
            </div>

            <!-- ===== STUDENT STATUS COLUMNS ===== -->
            <div>
                <h2 class="text-lg font-bold mb-3 flex items-center gap-2 text-gray-800">
                    <i class="fas fa-users text-purple-600"></i> Student Uniform Status
                </h2>
                ${statusColumns}
            </div>

            <!-- ===== STUDENT SEARCH ===== -->
            <div>
                <h2 class="text-lg font-bold mb-3 flex items-center gap-2 text-gray-800">
                    <i class="fas fa-search text-blue-600"></i> Search Student Details
                </h2>
                ${studentSearch}
            </div>

            <!-- ===== STOCK MANAGEMENT ===== -->
            <div>
                <h2 class="text-lg font-bold mb-3 flex items-center gap-2 text-gray-800">
                    <i class="fas fa-boxes text-teal-600"></i> Stock Management
                </h2>
                ${stockManagement}
            </div>

            <!-- ===== TRANSACTION HISTORY ===== -->
            <div>
                <h2 class="text-lg font-bold mb-3 flex items-center gap-2 text-gray-800">
                    <i class="fas fa-history text-gray-600"></i> Transaction History
                </h2>
                ${transactionHistory}
            </div>

        </div>`;

    var stockForm = document.getElementById('uniformStockForm');
    if (stockForm) {
        stockForm.removeEventListener('submit', handleUniformStockUpdate);
        stockForm.addEventListener('submit', handleUniformStockUpdate);
    }

    var searchInput = document.getElementById('uniformStudentSearch');
    if (searchInput) {
        searchInput.removeEventListener('keyup', handleUniformSearchKeyup);
        searchInput.addEventListener('keyup', handleUniformSearchKeyup);
    }

    var txSearch = document.getElementById('uniformTransactionSearch');
    if (txSearch) {
        txSearch.removeEventListener('keyup', handleTransactionSearchKeyup);
        txSearch.addEventListener('keyup', handleTransactionSearchKeyup);
    }
}

// ==================== SEARCH UNIFORM STUDENT ====================

function searchUniformStudent() {
    var searchTerm = (document.getElementById('uniformStudentSearch')?.value || '').toLowerCase().trim();
    var resultContainer = document.getElementById('uniformStudentResult');
    if (!resultContainer) return;

    if (!searchTerm) {
        resultContainer.innerHTML = `
            <div class="text-center py-6 text-gray-400">
                <i class="fas fa-search text-2xl mb-2"></i>
                <p class="text-sm">Enter a student name or admission number to search</p>
            </div>`;
        return;
    }

    var studentDetails = uniformDataGlobal?.studentDetails || {};
    var matches = [];

    Object.keys(studentDetails).forEach(function(id) {
        var s = studentDetails[id];
        if (!s) return;
        
        var fullName = ((s.firstName || '') + ' ' + (s.lastName || '')).toLowerCase();
        var admission = (s.admissionNumber || '').toLowerCase();
        
        if (fullName.includes(searchTerm) || admission.includes(searchTerm)) {
            matches.push(s);
        }
    });

    if (matches.length === 0 && uniformAllStudentsList && uniformAllStudentsList.length > 0) {
        uniformAllStudentsList.forEach(function(s) {
            if (!s) return;
            var fullName = ((s.firstName || '') + ' ' + (s.lastName || '')).toLowerCase();
            var admission = (s.admissionNumber || '').toLowerCase();
            
            if (fullName.includes(searchTerm) || admission.includes(searchTerm)) {
                if (!studentDetails[s.id]) {
                    var newEntry = {
                        id: s.id,
                        admissionNumber: s.admissionNumber || '',
                        firstName: s.firstName || '',
                        lastName: s.lastName || '',
                        currentClass: s.currentClass || 'Not Assigned',
                        classLevel: 'Unknown',
                        levelKey: 'Unknown',
                        items: {},
                        totalRequired: 0,
                        totalCollected: 0,
                        totalRemaining: 0,
                        uniformStatus: 'none',
                        isComplete: false
                    };
                    studentDetails[s.id] = newEntry;
                    matches.push(newEntry);
                } else {
                    matches.push(studentDetails[s.id]);
                }
            }
        });
    }

    if (matches.length === 0) {
        resultContainer.innerHTML = `
            <div class="text-center py-6 text-gray-400">
                <i class="fas fa-user-slash text-3xl mb-2"></i>
                <p class="text-sm">No student found matching "<strong>${uEscapeHtml(searchTerm)}</strong>"</p>
                <p class="text-xs text-gray-400 mt-1">Try searching by full name or admission number</p>
            </div>`;
        return;
    }

    if (matches.length > 1) {
        var listItems = matches.slice(0, 10).map(function(s) {
            var name = (s.firstName || '') + ' ' + (s.lastName || '');
            var admission = s.admissionNumber || 'N/A';
            var classDisplay = s.currentClass || 'N/A';
            var collected = s.totalCollected || 0;
            var remaining = s.totalRemaining || 0;
            var total = s.totalRequired || 0;
            var issued = s.totalIssued || 0;
            
            var statusText = '';
            var statusColor = '';
            if (total === 0) {
                statusText = 'No Items';
                statusColor = 'text-gray-400';
            } else if (issued >= total) {
                statusText = '✅ Issued';
                statusColor = 'text-blue-600';
            } else if (collected >= total) {
                statusText = '💰 Paid';
                statusColor = 'text-green-600';
            } else if (collected > 0) {
                statusText = '⚠️ Partial';
                statusColor = 'text-yellow-600';
            } else {
                statusText = '❌ Not Paid';
                statusColor = 'text-red-600';
            }

            return `
                <div onclick="showStudentUniformDetail('${s.id}')"
                     class="flex justify-between items-center p-3 border rounded-lg hover:bg-purple-50
                            hover:border-purple-300 cursor-pointer transition">
                    <div>
                        <p class="font-semibold text-sm">${uEscapeHtml(name)}</p>
                        <p class="text-xs text-gray-500">${uEscapeHtml(admission)} | ${uEscapeHtml(classDisplay)}</p>
                    </div>
                    <div class="text-right text-xs">
                        <p class="text-green-600">Collected: ${collected}</p>
                        <p class="text-blue-600">Issued: ${issued}</p>
                        <p class="text-red-500">Remaining: ${remaining}</p>
                        <p class="font-medium ${statusColor}">${statusText}</p>
                    </div>
                </div>`;
        }).join('');

        resultContainer.innerHTML = `
            <div class="space-y-2">
                <p class="text-xs text-gray-500 mb-2">Found ${matches.length} student${matches.length !== 1 ? 's' : ''} — click to view:</p>
                ${listItems}
                ${matches.length > 10 ? `<p class="text-xs text-gray-400 text-center">Showing first 10 results. Refine your search.</p>` : ''}
            </div>`;
        return;
    }

    showStudentUniformDetail(matches[0].id);
}

// ==================== SHOW STUDENT UNIFORM DETAIL ====================

function showStudentUniformDetail(studentId) {
    var resultContainer = document.getElementById('uniformStudentResult');
    if (!resultContainer) return;

    var student = (uniformDataGlobal?.studentDetails || {})[studentId];
    
    if (!student && uniformAllStudentsList) {
        var found = uniformAllStudentsList.find(function(s) { return s.id === studentId; });
        if (found) {
            student = {
                id: found.id,
                admissionNumber: found.admissionNumber || '',
                firstName: found.firstName || '',
                lastName: found.lastName || '',
                currentClass: found.currentClass || 'Not Assigned',
                items: {},
                totalRequired: 0,
                totalCollected: 0,
                totalRemaining: 0,
                totalIssued: 0,
                uniformStatus: 'none',
                isComplete: false
            };
            if (uniformDataGlobal.studentDetails) {
                uniformDataGlobal.studentDetails[studentId] = student;
            }
        }
    }

    if (!student) {
        resultContainer.innerHTML = `
            <div class="border rounded-xl p-4 bg-yellow-50 border-yellow-200">
                <p class="text-yellow-700 text-sm">
                    <i class="fas fa-exclamation-triangle mr-1"></i> 
                    Student data not found. Try refreshing the page.
                </p>
                <button onclick="refreshUniform()" class="mt-2 bg-blue-600 text-white px-3 py-1 rounded text-sm">
                    Refresh
                </button>
            </div>`;
        return;
    }

    var items = student.items || {};
    var itemNames = Object.keys(items);

    if (itemNames.length === 0) {
        var studentTxs = uniformTransactionsGlobal.filter(function(t) {
            return t.studentId === studentId && t.transactionType === 'issue';
        });
        
        var txItemNames = [];
        studentTxs.forEach(function(t) {
            if (t.itemName && txItemNames.indexOf(t.itemName) === -1) {
                txItemNames.push(t.itemName);
            }
        });

        if (txItemNames.length > 0) {
            txItemNames.forEach(function(itemName) {
                var txForItem = studentTxs.filter(function(t) { return t.itemName === itemName; });
                var totalIssued = txForItem.reduce(function(sum, t) { return sum + (t.quantity || 0); }, 0);
                
                items[itemName] = {
                    quantityRequired: totalIssued,
                    collected: totalIssued,
                    remaining: 0,
                    issued: totalIssued
                };
            });
            
            student.items = items;
            student.totalRequired = Object.values(items).reduce(function(sum, i) { return sum + (i.quantityRequired || 0); }, 0);
            student.totalCollected = Object.values(items).reduce(function(sum, i) { return sum + (i.collected || 0); }, 0);
            student.totalRemaining = student.totalRequired - student.totalCollected;
            student.totalIssued = Object.values(items).reduce(function(sum, i) { return sum + (i.issued || 0); }, 0);
            student.uniformStatus = student.totalIssued >= student.totalRequired && student.totalRequired > 0 ? 'fully_issued' : 'partial';
            
            if (uniformDataGlobal.studentDetails) {
                uniformDataGlobal.studentDetails[studentId] = student;
            }
        }
    }

    itemNames = Object.keys(items);

    if (itemNames.length === 0) {
        resultContainer.innerHTML = `
            <div class="border rounded-xl p-4 bg-white shadow-sm">
                <h5 class="font-bold text-lg">${uEscapeHtml(student.firstName)} ${uEscapeHtml(student.lastName)}</h5>
                <p class="text-sm text-gray-500">${uEscapeHtml(student.admissionNumber || 'N/A')} | ${uEscapeHtml(student.currentClass || 'N/A')}</p>
                <div class="mt-3 p-4 bg-yellow-50 rounded-lg border border-yellow-200">
                    <p class="text-yellow-700 text-sm">
                        <i class="fas fa-info-circle mr-1"></i> 
                        No uniform items found for this student.
                    </p>
                </div>
            </div>`;
        return;
    }

    var itemCards = itemNames.map(function(itemName) {
        var itemData = items[itemName] || {};

        var issuedToStudent = uniformTransactionsGlobal.filter(function(t) {
            return t.studentId === student.id
                && t.itemName === itemName
                && t.transactionType === 'issue';
        });
        var totalPhysicallyIssued = issuedToStudent.reduce(function(sum, t) {
            return sum + (t.quantity || 0);
        }, 0);

        var stockAvail = (uniformStockGlobal[itemName] || {}).available || 0;

        var qtyRequired = itemData.quantityRequired || 0;
        var qtyCollected = itemData.collected || 0;
        var qtyRemaining = Math.max(0, qtyRequired - qtyCollected);
        var qtyToIssue = Math.min(qtyCollected - totalPhysicallyIssued, stockAvail);

        var canIssue = qtyToIssue > 0 && stockAvail > 0 && qtyCollected > 0;
        var isFullyIssued = totalPhysicallyIssued >= qtyRequired && qtyRequired > 0;
        var isFullyPaid = qtyCollected >= qtyRequired && qtyRequired > 0;

        var payBadge = '';
        if (qtyRequired === 0) {
            payBadge = '<span class="px-2 py-0.5 rounded-full text-xs font-semibold bg-gray-100 text-gray-600">No Requirement</span>';
        } else if (isFullyPaid) {
            payBadge = '<span class="px-2 py-0.5 rounded-full text-xs font-semibold bg-green-100 text-green-800">✅ Fully Paid</span>';
        } else if (qtyCollected > 0) {
            payBadge = `<span class="px-2 py-0.5 rounded-full text-xs font-semibold bg-yellow-100 text-yellow-800">⚠️ Partial (${qtyCollected}/${qtyRequired})</span>`;
        } else {
            payBadge = '<span class="px-2 py-0.5 rounded-full text-xs font-semibold bg-red-100 text-red-800">❌ Not Paid</span>';
        }

        var issBadge = '';
        if (qtyRequired === 0) {
            issBadge = '<span class="px-2 py-0.5 rounded-full text-xs font-semibold bg-gray-100 text-gray-600">No Requirement</span>';
        } else if (isFullyIssued) {
            issBadge = '<span class="px-2 py-0.5 rounded-full text-xs font-semibold bg-blue-100 text-blue-800">📦 Fully Issued</span>';
        } else if (totalPhysicallyIssued > 0) {
            issBadge = `<span class="px-2 py-0.5 rounded-full text-xs font-semibold bg-orange-100 text-orange-800">📦 Partially Issued (${totalPhysicallyIssued}/${qtyRequired})</span>`;
        } else {
            issBadge = '<span class="px-2 py-0.5 rounded-full text-xs font-semibold bg-gray-100 text-gray-600">📭 Not Yet Issued</span>';
        }

        var issueBtn = '';
        
        if (canIssue) {
            var maxIssue = Math.min(qtyCollected - totalPhysicallyIssued, stockAvail);
            issueBtn = `
                <button onclick="issueUniformToStudentWithQuantity('${student.id}','${uEscapeHtml(itemName)}', ${maxIssue})"
                        class="bg-green-600 hover:bg-green-700 text-white px-4 py-2 rounded-lg text-sm font-semibold transition flex items-center gap-2 shadow-sm">
                    <i class="fas fa-tshirt"></i> 
                    Issue Uniform (${maxIssue} available)
                </button>
            `;
        } else if (qtyCollected > 0 && qtyRemaining > 0 && stockAvail === 0) {
            issueBtn = `
                <button disabled
                        class="bg-gray-300 text-gray-500 px-4 py-2 rounded-lg text-sm font-semibold cursor-not-allowed flex items-center gap-2">
                    <i class="fas fa-exclamation-circle"></i> 
                    Out of Stock - Restock First
                </button>
            `;
        } else if (isFullyIssued) {
            issueBtn = `
                <span class="text-sm text-green-600 font-semibold flex items-center gap-2 bg-green-50 px-3 py-1.5 rounded-lg">
                    <i class="fas fa-check-circle"></i> All Issued (${totalPhysicallyIssued}/${qtyRequired})
                </span>
            `;
        } else if (qtyCollected === 0) {
            issueBtn = `
                <span class="text-sm text-red-500 font-semibold flex items-center gap-2 bg-red-50 px-3 py-1.5 rounded-lg">
                    <i class="fas fa-times-circle"></i> Payment Required First
                </span>
            `;
        } else {
            issueBtn = `
                <span class="text-sm text-gray-400 flex items-center gap-2">
                    <i class="fas fa-info-circle"></i> No items to issue
                </span>
            `;
        }

        var paymentPct = qtyRequired > 0 ? Math.min(100, (qtyCollected / qtyRequired) * 100).toFixed(0) : 0;
        var issuancePct = qtyRequired > 0 ? Math.min(100, (totalPhysicallyIssued / qtyRequired) * 100).toFixed(0) : 0;

        var cardBg = (isFullyIssued) 
            ? 'bg-blue-50 border-blue-200' 
            : (isFullyPaid) 
                ? 'bg-green-50 border-green-200' 
                : 'bg-white border-gray-200';

        return `
            <div class="border rounded-xl p-4 ${cardBg}">
                <div class="flex justify-between items-start flex-wrap gap-2 mb-3">
                    <p class="font-bold text-sm">👕 ${uEscapeHtml(itemName)}</p>
                    <div class="flex flex-col items-end gap-1">
                        ${payBadge}
                        ${issBadge}
                    </div>
                </div>

                <div class="grid grid-cols-2 sm:grid-cols-4 gap-2 text-center text-xs mb-3">
                    <div class="bg-gray-50 rounded p-1.5">
                        <p class="font-bold text-gray-800">${qtyRequired}</p>
                        <p class="text-gray-500">Required</p>
                    </div>
                    <div class="bg-gray-50 rounded p-1.5">
                        <p class="font-bold text-green-700">${qtyCollected}</p>
                        <p class="text-gray-500">Paid For</p>
                    </div>
                    <div class="bg-gray-50 rounded p-1.5">
                        <p class="font-bold text-orange-600">${totalPhysicallyIssued}</p>
                        <p class="text-gray-500">Issued</p>
                    </div>
                    <div class="bg-gray-50 rounded p-1.5">
                        <p class="font-bold ${stockAvail === 0 ? 'text-red-600' : 'text-blue-700'}">${stockAvail}</p>
                        <p class="text-gray-500">In Stock</p>
                    </div>
                </div>

                <div class="mb-1">
                    <div class="flex justify-between text-xs text-gray-500 mb-0.5">
                        <span>Payment</span><span>${paymentPct}%</span>
                    </div>
                    <div class="w-full bg-gray-200 rounded-full h-1.5">
                        <div class="${paymentPct >= 100 ? 'bg-green-500' : paymentPct >= 50 ? 'bg-yellow-500' : 'bg-red-400'} rounded-full h-1.5"
                             style="width:${paymentPct}%"></div>
                    </div>
                </div>
                <div class="mb-3">
                    <div class="flex justify-between text-xs text-gray-500 mb-0.5">
                        <span>Physically Issued</span><span>${issuancePct}%</span>
                    </div>
                    <div class="w-full bg-gray-200 rounded-full h-1.5">
                        <div class="${issuancePct >= 100 ? 'bg-blue-500' : issuancePct >= 50 ? 'bg-blue-400' : 'bg-gray-400'} rounded-full h-1.5"
                             style="width:${issuancePct}%"></div>
                    </div>
                </div>

                ${qtyCollected < qtyRequired && qtyCollected > 0 ? `
                <div class="text-xs text-orange-600 bg-orange-50 border border-orange-200 rounded p-2 mb-3 flex items-center gap-1">
                    <i class="fas fa-info-circle"></i>
                    Partial payment — you can still issue ${qtyCollected} item(s)
                </div>` : ''}

                ${qtyCollected >= qtyRequired && qtyCollected > 0 && !isFullyIssued ? `
                <div class="text-xs text-green-600 bg-green-50 border border-green-200 rounded p-2 mb-3 flex items-center gap-1">
                    <i class="fas fa-check-circle"></i>
                    Fully paid! Ready to issue ${Math.min(qtyCollected - totalPhysicallyIssued, stockAvail)} item(s)
                </div>` : ''}

                <div class="flex gap-2 flex-wrap">
                    ${issueBtn}
                    <button onclick="viewUniformStudentHistory('${student.id}')"
                            class="bg-blue-600 hover:bg-blue-700 text-white px-3 py-2 rounded-lg text-sm font-semibold transition flex items-center gap-1">
                        <i class="fas fa-history"></i> History
                    </button>
                </div>
            </div>`;
    }).join('');

    var allPaid = (student.totalCollected || 0) >= (student.totalRequired || 1);
    var allIssued = (student.totalIssued || 0) >= (student.totalRequired || 1);
    
    var headerBg = 'bg-white border-gray-200';
    if (allIssued && student.totalRequired > 0) {
        headerBg = 'bg-blue-50 border-blue-200';
    } else if (allPaid && student.totalRequired > 0) {
        headerBg = 'bg-green-50 border-green-200';
    }

    resultContainer.innerHTML = `
        <div class="border rounded-xl p-4 shadow-sm ${headerBg}">
            <div class="flex justify-between items-start flex-wrap gap-2 mb-4 pb-3 border-b">
                <div>
                    <h5 class="font-bold text-lg">${uEscapeHtml(student.firstName)} ${uEscapeHtml(student.lastName)}</h5>
                    <p class="text-sm text-gray-500">
                        ${uEscapeHtml(student.admissionNumber || 'N/A')} | ${uEscapeHtml(student.currentClass || 'N/A')}
                    </p>
                </div>
                <div class="text-right text-sm">
                    <p>Total items: <strong>${student.totalRequired || 0}</strong></p>
                    <p class="text-green-600">Collected: <strong>${student.totalCollected || 0}</strong></p>
                    <p class="text-blue-600">Issued: <strong>${student.totalIssued || 0}</strong></p>
                    <p class="text-red-500">Remaining: <strong>${student.totalRemaining || 0}</strong></p>
                    ${allIssued && student.totalRequired > 0 ? 
                        '<p class="text-blue-600 font-bold text-sm">✅ All items issued!</p>' : 
                        allPaid && student.totalRequired > 0 ? 
                            '<p class="text-green-600 font-bold text-sm">💰 All items paid — ready to issue!</p>' : 
                            student.totalCollected > 0 ? 
                                '<p class="text-yellow-600 font-bold text-sm">⚠️ Some items paid</p>' : 
                                '<p class="text-red-600 font-bold text-sm">❌ No payments yet</p>'
                    }
                </div>
            </div>
            <div class="space-y-3">${itemCards}</div>
        </div>`;
}

// ==================== VIEW STUDENT UNIFORM HISTORY ====================

async function viewUniformStudentHistory(studentId) {
    var old = document.getElementById('uniStudentHistoryModal');
    if (old) old.remove();

    try {
        var res = await fetch('/api/uniform/transactions?studentId=' + studentId);
        var txs = await res.json();

        var student = (uniformDataGlobal?.studentDetails || {})[studentId];
        var studentName = student ? (student.firstName + ' ' + student.lastName) : studentId;

        if (!Array.isArray(txs) || txs.length === 0) {
            showUniformToast('No uniform transactions found for ' + studentName, 'info');
            return;
        }

        txs.sort(function(a, b) { return new Date(b.timestamp || b.date) - new Date(a.timestamp || a.date); });

        var rows = txs.map(function(t) {
            var typeColor = t.transactionType === 'issue' ? 'text-red-600 font-semibold' : 'text-green-600 font-semibold';
            var typeLbl = t.transactionType === 'issue' ? '📤 Issued' : '📦 Restock';
            var dateStr = '';
            try { dateStr = new Date(t.timestamp || t.date).toLocaleDateString('en-UG'); } catch(e) { dateStr = '-'; }
            return `
                <tr class="border-b hover:bg-gray-50 text-xs">
                    <td class="p-2 whitespace-nowrap">${dateStr}</td>
                    <td class="p-2">👕 ${uEscapeHtml(t.itemName || '-')}</td>
                    <td class="p-2 text-right font-bold">${t.quantity || 0}</td>
                    <td class="p-2 ${typeColor}">${typeLbl}</td>
                    <td class="p-2 text-gray-500">${uEscapeHtml(t.comment || '-')}</td>
                </tr>`;
        }).join('');

        var modal = `
            <div id="uniStudentHistoryModal"
                 class="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
                <div class="bg-white rounded-2xl shadow-2xl w-full max-w-2xl max-h-[85vh] flex flex-col">
                    <div class="flex justify-between items-center p-5 border-b">
                        <div>
                            <h3 class="text-xl font-bold flex items-center gap-2">
                                <i class="fas fa-history text-blue-600"></i> Uniform History
                            </h3>
                            <p class="text-sm text-gray-500">${uEscapeHtml(studentName)}</p>
                        </div>
                        <button onclick="uCloseModal('uniStudentHistoryModal')"
                                class="text-gray-400 hover:text-gray-600 text-2xl leading-none">&times;</button>
                    </div>
                    <div class="overflow-auto flex-1">
                        <table class="w-full text-sm">
                            <thead class="bg-gray-100 sticky top-0">
                                <tr>
                                    <th class="p-2 text-left text-xs">Date</th>
                                    <th class="p-2 text-left text-xs">Item</th>
                                    <th class="p-2 text-right text-xs">Qty</th>
                                    <th class="p-2 text-left text-xs">Type</th>
                                    <th class="p-2 text-left text-xs">Comment</th>
                                </tr>
                            </thead>
                            <tbody>${rows}</tbody>
                        </table>
                    </div>
                    <div class="p-4 border-t flex justify-between items-center">
                        <span class="text-sm text-gray-500">${txs.length} transaction${txs.length !== 1 ? 's' : ''}</span>
                        <button onclick="uCloseModal('uniStudentHistoryModal')"
                                class="bg-gray-200 hover:bg-gray-300 text-gray-700 px-4 py-2 rounded-lg text-sm font-semibold">
                            Close
                        </button>
                    </div>
                </div>
            </div>`;
        document.body.insertAdjacentHTML('beforeend', modal);

    } catch (err) {
        console.error('Error loading student history:', err);
        alert('Error loading history: ' + err.message);
    }
}

