// ==================== ISSUE UNIFORM TO STUDENT WITH QUANTITY ====================

async function issueUniformToStudentWithQuantity(studentId, itemName, maxQuantity) {
    var student = (uniformDataGlobal?.studentDetails || {})[studentId];
    var studentName = student ? (student.firstName + ' ' + student.lastName) : 'this student';

    var stockAvail = (uniformStockGlobal[itemName] || {}).available || 0;
    
    var canIssue = Math.min(maxQuantity || 1, stockAvail);
    
    if (canIssue <= 0) {
        showUniformToast('❌ No stock available for ' + itemName + '. Please restock first.', 'error');
        return;
    }

    var quantity = prompt(
        'Issue "' + itemName + '" to ' + studentName + '\n\n' +
        'Paid for: ' + maxQuantity + ' items\n' +
        'Stock available: ' + stockAvail + '\n' +
        'Max can issue: ' + canIssue + '\n\n' +
        'How many to issue?', 
        String(canIssue)
    );
    
    if (!quantity) return;
    var qty = parseInt(quantity);
    if (isNaN(qty) || qty <= 0) {
        alert('Please enter a valid quantity (1 or more).');
        return;
    }
    if (qty > canIssue) {
        alert('❌ Cannot issue ' + qty + '. Only ' + canIssue + ' can be issued (paid for items).');
        return;
    }

    var comment = prompt('Comment (optional):', 'Uniform issued to student');
    if (comment === null) return;

    if (!confirm('Issue ' + qty + ' × "' + itemName + '" to ' + studentName + '?')) return;

    try {
        var res = await fetch('/api/uniform/issue', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
                studentId: studentId,
                itemName: itemName,
                quantity: qty,
                comment: comment || 'Uniform issued to student'
            })
        });
        var result = await res.json();
        if (result.success) {
            showUniformToast('✅ ' + result.message, 'success');
            await refreshUniformData();
            showStudentUniformDetail(studentId);
            renderUniformPageV6();
        } else {
            alert('❌ Error: ' + (result.error || 'Unknown error'));
        }
    } catch (err) {
        console.error('Issue uniform error:', err);
        alert('Network error: ' + err.message);
    }
}

// ==================== HANDLE STOCK UPDATE FORM ====================

async function handleUniformStockUpdate(e) {
    e.preventDefault();

    var itemName = (document.getElementById('uniformStockItem')?.value || '').trim();
    var quantity = parseInt(document.getElementById('uniformStockQuantity')?.value || '0');
    var operation = document.getElementById('uniformStockOperation')?.value || 'add';
    var comment = (document.getElementById('uniformStockComment')?.value || '').trim();

    if (!itemName) {
        alert('Please select or enter an item name.');
        return;
    }
    if (!quantity || quantity <= 0) {
        alert('Please enter a valid quantity (1 or more).');
        return;
    }

    var opLabel = operation === 'add' ? 'Add ' + quantity + ' × "' + itemName + '" to stock?'
                                      : 'Remove ' + quantity + ' × "' + itemName + '" from stock?';
    if (!confirm(opLabel)) return;

    var btn = e.target.querySelector('button[type="submit"]');
    var origHtml = btn ? btn.innerHTML : '';
    if (btn) { btn.innerHTML = '<i class="fas fa-spinner fa-spin mr-1"></i>Processing...'; btn.disabled = true; }

    try {
        var res = await fetch('/api/uniform/stock', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
                itemName: itemName,
                quantity: quantity,
                operation: operation,
                comment: comment || (operation === 'add' ? 'Stock received' : 'Stock removed')
            })
        });
        var result = await res.json();

        if (result.success) {
            showUniformToast('✅ ' + result.message, 'success');
            document.getElementById('uniformStockQuantity').value = '1';
            document.getElementById('uniformStockComment').value = '';
            await refreshUniformData();
            renderUniformPageV6();
        } else {
            alert('❌ ' + (result.error || 'Unknown error'));
        }
    } catch (err) {
        console.error('Stock update error:', err);
        alert('Network error: ' + err.message);
    } finally {
        if (btn) { btn.innerHTML = origHtml; btn.disabled = false; }
    }
}

// ==================== ADD NEW UNIFORM ITEM ====================

function addNewUniformItem() {
    var newItem = prompt('Enter the name of the new uniform item:');
    if (!newItem || !newItem.trim()) return;
    newItem = newItem.trim();

    var select = document.getElementById('uniformStockItem');
    if (!select) return;

    var exists = Array.from(select.options).some(function(opt) {
        return opt.value.toLowerCase() === newItem.toLowerCase();
    });
    if (exists) {
        var matchingOpt = Array.from(select.options).find(function(opt) {
            return opt.value.toLowerCase() === newItem.toLowerCase();
        });
        if (matchingOpt) {
            select.value = matchingOpt.value;
        }
        showUniformToast('Item "' + newItem + '" already exists — selected.', 'info');
        return;
    }

    var opt = document.createElement('option');
    opt.value = newItem;
    opt.textContent = newItem;
    select.appendChild(opt);
    select.value = newItem;
    showUniformToast('✅ "' + newItem + '" added to the list. Set the quantity and click Update Stock.', 'success');
}

// ==================== FILTER UNIFORM COLUMN ====================

function filterUniformColumn(columnId, searchId) {
    var searchInput = document.getElementById(searchId);
    if (!searchInput) return;
    
    var searchTerm = searchInput.value.toLowerCase().trim();
    var column = document.getElementById(columnId);
    if (!column) return;
    
    var studentCards = column.querySelectorAll('.border.rounded-lg');
    studentCards.forEach(function(card) {
        var text = card.textContent.toLowerCase();
        if (searchTerm === '' || text.includes(searchTerm)) {
            card.style.display = '';
        } else {
            card.style.display = 'none';
        }
    });
}

function clearUniformColumnSearch(searchId, columnId) {
    var searchInput = document.getElementById(searchId);
    if (searchInput) {
        searchInput.value = '';
        filterUniformColumn(columnId, searchId);
    }
}

// ==================== FILTER TRANSACTIONS ====================

function filterUniformTransactions() {
    var term = (document.getElementById('uniformTransactionSearch')?.value || '').toLowerCase().trim();
    var rows = document.querySelectorAll('#uniformTransactionTable tbody tr');
    rows.forEach(function(row) {
        row.style.display = (!term || row.textContent.toLowerCase().includes(term)) ? '' : 'none';
    });
}

function clearTransactionFilter() {
    var inp = document.getElementById('uniformTransactionSearch');
    if (inp) inp.value = '';
    var rows = document.querySelectorAll('#uniformTransactionTable tbody tr');
    rows.forEach(function(row) { row.style.display = ''; });
}

