function refreshUniform() {
    showUniformToast('🔄 Refreshing...', 'info');
    showUniformManagement();
}

// ==================== EXPORT REPORT ====================

function exportUniformReport() {
    try {
        var lines = [];
        lines.push('=== UNIFORM MANAGEMENT REPORT ===');
        lines.push('Generated: ' + new Date().toLocaleString('en-UG'));
        lines.push('Note: Uniforms are ONE-TIME items that persist across all academic periods');
        lines.push('');

        lines.push('=== STOCK SUMMARY ===');
        var itemNames = Object.keys(uniformStockGlobal);
        if (itemNames.length === 0) {
            lines.push('No stock items');
        } else {
            itemNames.forEach(function(n) {
                var s = uniformStockGlobal[n] || {};
                lines.push(n + ' | Received: ' + (s.totalReceived || 0) + ' | Issued: ' + (s.issued || 0) + ' | Available: ' + (s.available || 0));
            });
        }
        lines.push('');

        lines.push('=== STUDENT STATUS ===');
        var studentDetails = uniformDataGlobal.studentDetails || {};
        var studentIds = Object.keys(studentDetails);
        if (studentIds.length === 0) {
            lines.push('No student uniform data');
        } else {
            studentIds.forEach(function(id) {
                var s = studentDetails[id];
                if (!s) return;
                var status = s.uniformStatus || 'none';
                var statusLabel = status === 'fully_issued' ? 'FULLY ISSUED' : 
                                 status === 'paid_ready' ? 'PAID (READY)' : 
                                 status === 'partial' ? 'PARTIAL' : 
                                 'NOT PAID';
                lines.push(s.firstName + ' ' + s.lastName + ' (' + (s.admissionNumber || '') + ') - ' + statusLabel);
                var itemEntries = Object.entries(s.items || {});
                if (itemEntries.length > 0) {
                    itemEntries.forEach(function(ie) {
                        var iN = ie[0];
                        var iD = ie[1];
                        lines.push('  ' + iN + ': Required=' + (iD.quantityRequired || 0) + ' Collected=' + (iD.collected || 0) + ' Issued=' + (iD.issued || 0));
                    });
                }
                lines.push('');
            });
        }

        var blob = new Blob([lines.join('\n')], { type: 'text/plain' });
        var url = URL.createObjectURL(blob);
        var a = document.createElement('a');
        a.href = url;
        a.download = 'uniform_report_' + new Date().toISOString().split('T')[0] + '.txt';
        a.click();
        URL.revokeObjectURL(url);
        showUniformToast('✅ Report exported', 'success');
    } catch (err) {
        alert('Export error: ' + err.message);
    }
}

// ==================== AUTO-DEDUCT ON FULL PAYMENT ====================

async function checkAndDeductUniformFromStock(studentId, payment) {
    try {
        if (!payment || !payment.activityItemPayments) return;

        var uniformKeywords = [
            'trouser', 'dress', 'shirt', 'skirt', 'stocking', 'sock', 'belt', 'tie',
            'blazer', 'jumper', 'sweater', 'cardigan', 'vest', 'shorts', 'pinafore',
            'gown', 'frock', 'kilt', 'scarf', 'beret', 'cap', 'hat', 'badge', 'name tag',
            'sports', 'track suit', 'tracksuit', 'jersey', 'kit', 'uniform'
        ];

        var toDeduct = [];

        payment.activityItemPayments.forEach(function(item) {
            var iName = (item.itemName || '').toLowerCase();
            var isUniform = uniformKeywords.some(function(k) { return iName.includes(k); });
            var isFullyPaid = item.status === 'fully_paid' || item.remainingQuantity === 0;
            if (isUniform && isFullyPaid && (item.quantityRequired || 0) > 0) {
                toDeduct.push({ itemName: item.itemName, quantity: item.quantityRequired });
            }
        });

        if (toDeduct.length === 0) return;

        for (var i = 0; i < toDeduct.length; i++) {
            var u = toDeduct[i];
            try {
                var res = await fetch('/api/uniform/issue', {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({
                        studentId: studentId,
                        itemName: u.itemName,
                        quantity: u.quantity,
                        comment: 'Auto-issued on full payment'
                    })
                });
                var result = await res.json();
                if (result.success) {
                    console.log('✅ Auto-issued ' + u.quantity + ' × ' + u.itemName);
                } else {
                    console.warn('⚠️ Auto-issue failed for ' + u.itemName + ':', result.error);
                }
            } catch (err) {
                console.error('Auto-issue error for ' + u.itemName + ':', err);
            }
        }
    } catch (err) {
        console.error('checkAndDeductUniformFromStock error:', err);
    }
}

