async function refreshSchoolStock() {
    showToast('🔄 Refreshing school stock data...', 'info');
    await showSchoolStockManagement();
}

// ========== EXPORT SCHOOL STOCK REPORT ==========
function exportSchoolStockReport() {
    var items = schoolStockData || {};
    var itemNames = Object.keys(items);
    
    if (itemNames.length === 0) {
        alert('No stock data to export');
        return;
    }
    
    var headers = ['Item Name', 'Category', 'Total Received', 'Issued', 'Available', 'Last Updated'];
    
    var rows = itemNames.map(function(name) {
        var item = items[name] || {};
        var categoryName = getCategoryName(item.category);
        return [
            name,
            categoryName,
            item.totalReceived || 0,
            item.issued || 0,
            item.available || 0,
            item.lastUpdated ? new Date(item.lastUpdated).toLocaleDateString() : '-'
        ];
    });
    
    var csv = [headers.join(','), ...rows.map(function(r) { return r.join(','); })].join('\n');
    
    var blob = new Blob([csv], { type: 'text/csv;charset=utf-8;' });
    var link = document.createElement('a');
    link.href = URL.createObjectURL(blob);
    link.download = 'school_stock_report_' + new Date().toISOString().split('T')[0] + '.csv';
    link.click();
    URL.revokeObjectURL(link.href);
    
    showToast('✅ School stock report exported successfully!', 'success');
}

