// Add this function to add the School Stock link to the sidebar
function addSchoolStockToSidebar() {
    var sidebar = document.querySelector('.sidebar-menu') || document.querySelector('#sidebarNav');
    if (!sidebar) return;
    
    // Check if already exists
    if (document.querySelector('.sidebar-item[onclick*="showSchoolStockManagement"]')) return;
    
    var stockItem = document.createElement('div');
    stockItem.className = 'sidebar-item px-4 py-2 rounded-lg cursor-pointer hover:bg-gray-100 flex items-center gap-3';
    stockItem.setAttribute('onclick', 'showSchoolStockManagement()');
    stockItem.innerHTML = `
        <i class="fas fa-warehouse text-blue-500 w-5"></i>
        <span>School Stock</span>
    `;
    
    // Find appropriate position (after Inventory)
    var inventoryItem = document.querySelector('.sidebar-item[onclick*="showInventory"]');
    if (inventoryItem && inventoryItem.parentNode) {
        inventoryItem.parentNode.insertBefore(stockItem, inventoryItem.nextSibling);
    } else {
        sidebar.appendChild(stockItem);
    }
}

