// ========== TOGGLE PERIOD HISTORY ==========
function togglePeriodHistory(historyId) {
    console.log('togglePeriodHistory called for:', historyId);
    const historyDiv = document.getElementById(historyId);
    if (!historyDiv) return;
    
    historyDiv.classList.toggle('hidden');
    
    // If showing, load the payment history data
    if (!historyDiv.classList.contains('hidden')) {
        const parts = historyId.split('_');
        if (parts.length >= 3) {
            const year = parseInt(parts[1]);
            const term = parseInt(parts[2]);
            const studentId = window.currentCollectingStudent?.id;
            
            if (studentId) {
                loadPeriodPaymentHistory(studentId, year, term, historyId);
            }
        }
    }
}

// ========== LOAD PERIOD PAYMENT HISTORY ==========
async function loadPeriodPaymentHistory(studentId, year, term, historyId) {
    console.log('Loading period history:', year, term);
    
    const contentDiv = document.getElementById(`${historyId}_content`);
    const countSpan = document.getElementById(`${historyId}_count`);
    const totalSpan = document.getElementById(`${historyId}_total`);
    
    if (!contentDiv) return;
    
    contentDiv.innerHTML = `
        <div class="text-center text-gray-400 py-2">
            <i class="fas fa-spinner fa-spin mr-2"></i> Loading...
        </div>
    `;
    
    try {
        const result = await fetchPeriodHistory(studentId, year, term);
        
        if (!result.success || !result.payments || result.payments.length === 0) {
            contentDiv.innerHTML = `
                <div class="text-center text-gray-400 py-2">
                    <i class="fas fa-info-circle"></i> No payment records found for ${year} Term ${term}
                </div>
            `;
            if (countSpan) countSpan.textContent = '0 payments';
            if (totalSpan) totalSpan.textContent = 'UGX 0';
            return;
        }
        
        let historyHtml = '';
        let totalPaid = 0;
        
        for (const payment of result.payments) {
            const paymentDate = payment.date ? new Date(payment.date).toLocaleDateString() : 'N/A';
            const amount = payment.totalAmount || payment.amount || 0;
            totalPaid += amount;
            const receipt = payment.receiptNumber || 'N/A';
            const method = payment.method || 'cash';
            const methodIcon = method === 'cash' ? '💵' : 
                              method === 'bank' ? '🏦' : 
                              method === 'mobile' ? '📱' : '🏫';
            
            const isPreviousBalancePayment = payment.isPreviousBalancePayment || false;
            const prevBadge = isPreviousBalancePayment ? ' <span class="text-amber-500 text-[10px]">(Previous)</span>' : '';
            
            historyHtml += `
                <div class="flex justify-between items-center border-b border-gray-100 py-1.5 hover:bg-gray-50 px-1 rounded text-xs">
                    <span class="text-gray-500 w-24">${paymentDate}</span>
                    <span class="font-semibold text-green-600 w-28">UGX ${formatMoney(amount)}</span>
                    <span class="text-blue-600 font-mono w-28">${receipt}</span>
                    <span class="flex items-center gap-1 w-20">${methodIcon} ${method.toUpperCase()}${prevBadge}</span>
                </div>
            `;
        }
        
        historyHtml += `
            <div class="flex justify-between font-semibold pt-2 mt-2 border-t-2 border-gray-300 text-sm">
                <span>TOTAL PAID:</span>
                <span class="text-green-600">UGX ${formatMoney(totalPaid)}</span>
                <span></span>
                <span></span>
            </div>
        `;
        
        contentDiv.innerHTML = historyHtml;
        if (countSpan) countSpan.textContent = `${result.payments.length} payment(s)`;
        if (totalSpan) totalSpan.textContent = `UGX ${formatMoney(totalPaid)}`;
        
    } catch (error) {
        console.error('Error loading period history:', error);
        contentDiv.innerHTML = `
            <div class="text-center text-red-400 py-2">
                <i class="fas fa-exclamation-triangle"></i> Error loading payment history
            </div>
        `;
    }
}

// ========== FETCH PERIOD PAYMENT HISTORY ==========
async function fetchPeriodHistory(studentId, year, term) {
    console.log('=== FETCH PERIOD HISTORY ===');
    console.log('Student:', studentId, 'Year:', year, 'Term:', term);
    
    try {
        const response = await fetch(`/api/students/${studentId}/period-history/${year}/${term}`);
        
        if (!response.ok) {
            throw new Error(`Failed to fetch period history: ${response.status}`);
        }
        
        const result = await response.json();
        return result;
    } catch (error) {
        console.error('Error fetching period history:', error);
        return { success: false, payments: [], totalPaid: 0, count: 0 };
    }
}

// ========== FETCH PREVIOUS BALANCES ==========
async function fetchPreviousBalances(studentId) {
    console.log('=== FETCH PREVIOUS BALANCES ===');
    console.log('Student ID:', studentId);
    
    try {
        const response = await fetch(`/api/students/${studentId}/previous-balances`);
        
        if (!response.ok) {
            console.warn('Failed to fetch previous balances:', response.status);
            return [];
        }
        
        const result = await response.json();
        
        if (result.success) {
            window.previousBalancesData = result.previousBalances || [];
            window.previousBalancesTotal = result.totalPreviousBalance || 0;
            
            console.log(`✅ Found ${window.previousBalancesData.length} previous balances`);
            console.log(`📊 Total: UGX ${formatMoney(window.previousBalancesTotal)}`);
            
            return window.previousBalancesData;
        } else {
            console.warn('API returned error:', result.error);
            return [];
        }
    } catch (error) {
        console.error('Error fetching previous balances:', error);
        return [];
    }
}

// ========== RENDER PREVIOUS BALANCES ACCORDION ==========
function renderPreviousBalancesAccordion(previousBalances, studentId) {
    console.log('=== RENDER PREVIOUS BALANCES ACCORDION ===');
    console.log('Balances count:', previousBalances ? previousBalances.length : 0);
    
    if (!previousBalances || previousBalances.length === 0) {
        return `
            <div class="border-2 border-amber-300 rounded-xl overflow-hidden mt-4">
                <div class="bg-gradient-to-r from-amber-500 to-orange-500 px-4 py-3 text-white">
                    <div class="flex justify-between items-center">
                        <div class="flex items-center gap-2">
                            <i class="fas fa-clock-rotate-left text-xl"></i>
                            <h3 class="font-bold text-lg">📋 Previous Academic Period Balances</h3>
                            <span class="text-xs bg-green-600 px-2 py-0.5 rounded-full">✅ No Outstanding Balances</span>
                        </div>
                    </div>
                </div>
                <div class="p-4 bg-gray-50 text-center text-gray-500">
                    <i class="fas fa-check-circle text-green-500 text-2xl mb-2"></i>
                    <p>All previous academic period balances have been cleared.</p>
                </div>
            </div>
        `;
    }
    
    const totalBalance = previousBalances.reduce((sum, p) => sum + p.balance, 0);
    
    let html = `
        <div class="border-2 border-amber-300 rounded-xl overflow-hidden mt-4 shadow-sm" id="previousBalancesSection">
            <div class="bg-gradient-to-r from-amber-500 to-orange-500 px-4 py-3 text-white cursor-pointer hover:from-amber-600 hover:to-orange-600 transition" 
                 onclick="togglePreviousBalances()">
                <div class="flex justify-between items-center">
                    <div class="flex items-center gap-2 flex-wrap">
                        <i class="fas fa-clock-rotate-left text-xl"></i>
                        <h3 class="font-bold text-lg">📋 Previous Academic Period Balances</h3>
                        <span class="text-xs bg-amber-700 px-2 py-0.5 rounded-full">
                            Total: UGX ${formatMoney(totalBalance)}
                        </span>
                        <span class="text-xs bg-amber-700/70 px-2 py-0.5 rounded-full">
                            ${previousBalances.length} period(s)
                        </span>
                    </div>
                    <div class="flex items-center gap-3">
                        <button onclick="event.stopPropagation(); payAllPreviousBalances()" 
                                class="bg-green-600 hover:bg-green-700 text-white px-3 py-1 rounded-lg text-sm font-semibold transition">
                            <i class="fas fa-check-double"></i> Pay All
                        </button>
                        <i class="fas fa-chevron-down transition-transform duration-300" id="prevBalancesIcon"></i>
                    </div>
                </div>
            </div>
            <div id="previousBalancesContainer" class="p-4 bg-amber-50 hidden">
    `;
    
    // Render each period
    for (const period of previousBalances) {
        const periodId = `period_${period.year}_${period.term}`;
        const historyId = `history_${period.year}_${period.term}`;
        const balance = period.balance;
        const expected = period.expected;
        const paid = period.paid;
        const isFullyPaid = balance <= 0;
        const displayName = `${period.year} Term ${period.term}`;
        
        html += `
            <div class="border rounded-lg p-3 mb-3 bg-white border-amber-200 shadow-sm hover:shadow-md transition" id="${periodId}">
                <div class="flex justify-between items-center flex-wrap gap-3">
                    <div>
                        <div class="flex items-center gap-2 flex-wrap">
                            <span class="font-bold text-amber-800">📅 ${displayName}</span>
                            ${!isFullyPaid ? `
                                <span class="px-2 py-0.5 rounded-full text-xs bg-red-100 text-red-800">
                                    Balance: UGX ${formatMoney(balance)}
                                </span>
                            ` : `
                                <span class="px-2 py-0.5 rounded-full text-xs bg-green-100 text-green-800">
                                    ✅ Fully Paid
                                </span>
                            `}
                        </div>
                        <div class="text-sm text-gray-600 mt-1">
                            Expected: UGX ${formatMoney(expected)} 
                            <span class="mx-1">|</span> 
                            Paid: <span class="text-green-600 font-semibold">UGX ${formatMoney(paid)}</span>
                            <span class="mx-1">|</span> 
                            Due: <span class="${balance > 0 ? 'text-red-600 font-semibold' : 'text-green-600'}">UGX ${formatMoney(Math.abs(balance))}</span>
                        </div>
                        ${period.breakdown ? `
                            <div class="text-xs text-gray-400 mt-0.5 flex gap-3 flex-wrap">
                                ${period.breakdown.tuition ? `<span>💰 Tuition: UGX ${formatMoney(period.breakdown.tuition)}</span>` : ''}
                                ${period.breakdown.termly ? `<span>📅 Termly: UGX ${formatMoney(period.breakdown.termly)}</span>` : ''}
                                ${period.breakdown.oneTime ? `<span>⭐ One-Time: UGX ${formatMoney(period.breakdown.oneTime)}</span>` : ''}
                                ${period.breakdown.yearly ? `<span>📆 Yearly: UGX ${formatMoney(period.breakdown.yearly)}</span>` : ''}
                            </div>
                        ` : ''}
                    </div>
                    <div class="flex gap-2 flex-wrap">
                        <button onclick="togglePeriodHistory('${historyId}')" 
                                class="text-blue-600 hover:text-blue-800 text-sm px-2 py-1 rounded hover:bg-blue-50 transition flex items-center gap-1">
                            <i class="fas fa-history"></i> History
                        </button>
                        ${!isFullyPaid ? `
                            <button onclick="payFullPreviousBalance('${studentId}', '${period.year}', '${period.term}', ${balance})" 
                                    class="bg-green-600 hover:bg-green-700 text-white px-3 py-1 rounded-lg text-sm font-semibold transition flex items-center gap-1">
                                <i class="fas fa-check"></i> Pay Full
                            </button>
                            <button onclick="showPartialPaymentModal('${studentId}', '${period.year}', '${period.term}', ${balance})" 
                                    class="bg-yellow-600 hover:bg-yellow-700 text-white px-3 py-1 rounded-lg text-sm font-semibold transition flex items-center gap-1">
                                <i class="fas fa-pen"></i> Partial
                            </button>
                        ` : `
                            <span class="text-green-600 text-sm font-semibold px-2 py-1">✅ Paid</span>
                        `}
                    </div>
                </div>
                
                <!-- Payment History (hidden by default) -->
                <div id="${historyId}" class="hidden mt-3 pt-3 border-t border-gray-200">
                    <div class="flex justify-between items-center mb-2">
                        <p class="font-semibold text-sm flex items-center gap-2">
                            <i class="fas fa-receipt text-blue-600"></i> 
                            📜 Payment History - ${displayName}
                        </p>
                        <span class="text-xs text-gray-400" id="${historyId}_count">Loading...</span>
                    </div>
                    <div id="${historyId}_content" class="space-y-1 text-sm max-h-60 overflow-y-auto">
                        <div class="text-center text-gray-400 py-2">
                            <i class="fas fa-spinner fa-spin mr-2"></i> Loading payment history...
                        </div>
                    </div>
                    <div class="mt-2 pt-2 border-t flex justify-between font-semibold text-sm" id="${historyId}_totals">
                        <span>Total Paid:</span>
                        <span class="text-green-600" id="${historyId}_total">UGX 0</span>
                    </div>
                </div>
            </div>
        `;
    }
    
    // Add Pay All button at bottom
    if (totalBalance > 0) {
        html += `
            <div class="mt-3 pt-3 border-t border-amber-300 flex justify-between items-center">
                <div>
                    <span class="font-bold text-amber-800">Total Previous Balance:</span>
                    <span class="text-2xl font-bold text-red-600 ml-2">UGX ${formatMoney(totalBalance)}</span>
                </div>
                <button onclick="payAllPreviousBalances()" 
                        class="bg-green-600 hover:bg-green-700 text-white px-6 py-2 rounded-lg font-semibold transition flex items-center gap-2">
                    <i class="fas fa-check-double"></i> Pay All (UGX ${formatMoney(totalBalance)})
                </button>
            </div>
        `;
    }
    
    html += `
            </div>
        </div>
    `;
    
    return html;
}

// ========== FORMAT MONEY HELPER ==========
function formatMoney(amount) {
    const num = Math.round(amount || 0);
    return num.toLocaleString('en-US');
}

// ========== ESCAPE HTML HELPER ==========
function escapeHtml(text) {
    if (!text) return '';
    const div = document.createElement('div');
    div.textContent = text;
    return div.innerHTML;
}

// ========== GET TERM NAME HELPER ==========
function getTermName(term) {
    const names = { 1: 'First Term', 2: 'Second Term', 3: 'Third Term' };
    return names[term] || `Term ${term}`;
}

