// Immediately invoked function to initialize sidebar
(function initializeSidebarImmediately() {
    console.log('=== 🚀 IMMEDIATE SIDEBAR INITIALIZATION ===');
    
    // Function to update sidebar UI
    function updateSidebarUI(schoolData) {
        console.log('=== UPDATE SIDEBAR UI ===', schoolData);
        
        // Update school name
        const nameEl = document.getElementById('sidebarSchoolName');
        if (nameEl) {
            if (schoolData && schoolData.schoolName) {
                nameEl.textContent = schoolData.schoolName;
                console.log('✅ Sidebar name updated to:', schoolData.schoolName);
            } else {
                nameEl.textContent = 'My School';
                console.log('⚠️ Using default name: My School');
            }
        } else {
            console.warn('❌ sidebarSchoolName element not found!');
        }
        
        // Update logo
        const logoImg = document.getElementById('sidebarSchoolLogo');
        const iconEl = document.getElementById('sidebarSchoolIcon');
        const container = document.getElementById('schoolLogoContainer');
        
        if (schoolData && schoolData.logo) {
            if (logoImg) {
                logoImg.src = schoolData.logo;
                logoImg.classList.remove('hidden');
                logoImg.classList.add('block');
            }
            if (iconEl) {
                iconEl.classList.add('hidden');
            }
            if (container) {
                container.classList.remove('bg-gradient-to-r', 'from-blue-600', 'to-purple-600');
                container.classList.add('bg-white');
            }
        } else {
            if (logoImg) {
                logoImg.classList.add('hidden');
                logoImg.classList.remove('block');
            }
            if (iconEl) {
                iconEl.classList.remove('hidden');
            }
            if (container) {
                container.classList.add('bg-gradient-to-r', 'from-blue-600', 'to-purple-600');
                container.classList.remove('bg-white');
            }
        }
        
        // Update page title
        if (schoolData && schoolData.schoolName) {
            document.title = schoolData.schoolName + ' - School Management System';
        }
    }
    
    // Try to load school data from localStorage first
    let schoolData = null;
    try {
        const saved = localStorage.getItem('schoolData');
        if (saved) {
            schoolData = JSON.parse(saved);
            console.log('📦 Loaded school from localStorage:', schoolData);
            // Immediately update sidebar with localStorage data
            updateSidebarUI(schoolData);
        }
    } catch (e) {
        console.warn('Could not load school from localStorage:', e);
    }
    
    // If not in localStorage or fetch to get latest
    if (!schoolData || !schoolData.schoolName) {
        console.log('📡 Fetching school data from backend...');
        fetch('/api/school')
            .then(res => {
                if (!res.ok) throw new Error('Failed to fetch school');
                return res.json();
            })
            .then(data => {
                if (data && data.school) {
                    schoolData = data.school;
                    try {
                        localStorage.setItem('schoolData', JSON.stringify(schoolData));
                        console.log('✅ School data saved to localStorage');
                    } catch (e) {}
                    updateSidebarUI(schoolData);
                }
            })
            .catch(err => {
                console.warn('Could not fetch school data:', err);
                // Use default if nothing works
                updateSidebarUI(null);
            });
    }
    
    // Make functions globally accessible
    window.updateSidebarUI = updateSidebarUI;
    window.refreshSidebarAfterSave = function(schoolData) {
        console.log('=== REFRESH SIDEBAR AFTER SAVE ===', schoolData);
        try {
            localStorage.setItem('schoolData', JSON.stringify(schoolData));
        } catch (e) {}
        updateSidebarUI(schoolData);
        if (typeof showToast === 'function') {
            showToast('✅ School profile updated successfully!', 'success');
        }
    };
    window.forceRefreshSidebar = function() {
        console.log('=== FORCE REFRESH SIDEBAR ===');
        try {
            const saved = localStorage.getItem('schoolData');
            if (saved) {
                const data = JSON.parse(saved);
                updateSidebarUI(data);
                console.log('✅ Sidebar refreshed from localStorage');
            } else {
                fetch('/api/school')
                    .then(res => res.json())
                    .then(data => {
                        if (data && data.school) {
                            localStorage.setItem('schoolData', JSON.stringify(data.school));
                            updateSidebarUI(data.school);
                            console.log('✅ Sidebar refreshed from backend');
                        }
                    })
                    .catch(err => console.warn('Could not refresh sidebar:', err));
            }
        } catch (e) {
            console.warn('Could not refresh sidebar:', e);
        }
    };
    
    console.log('✅ Sidebar initialization complete!');
})();

