function openPaymentHistoryEditor(historyEntryId) {
    const element = document.getElementById(historyEntryId);
    if (!element) return;

    const paymentId = element.dataset.paymentId;
    const receipt = element.dataset.receipt;
    const amount = element.dataset.amount;
    const quantity = element.dataset.quantity;
    const type = element.dataset.type;
    const date = element.dataset.date;
    const method = element.dataset.method;
    const periodKey = element.dataset.period;
    const itemName = element.dataset.itemName;
    const componentName = element.dataset.component;

    if (!paymentId) {
        showToast('⚠️ Cannot edit this payment (no ID found)', 'warning');
        return;
    }

    // Show a modal with edit/delete options
    const modalHtml = `
        <div class="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50" id="paymentEditorModal">
            <div class="bg-white rounded-2xl p-6 max-w-md w-full mx-4 shadow-2xl">
                <div class="flex justify-between items-center mb-4 pb-3 border-b">
                    <h3 class="text-lg font-bold">💰 Edit Payment</h3>
                    <button onclick="closePaymentEditor()" class="text-gray-500 hover:text-gray-700 text-2xl">&times;</button>
                </div>
                <div class="space-y-3">
                    <div class="bg-gray-50 p-3 rounded-lg">
                        <p class="text-sm text-gray-500">Item</p>
                        <p class="font-medium">📦 ${escapeHtml(itemName || 'Unknown')}</p>
                        <p class="text-xs text-gray-400">${escapeHtml(componentName || '')}</p>
                    </div>
                    <div class="grid grid-cols-2 gap-3">
                        <div>
                            <p class="text-sm text-gray-500">Amount / Quantity</p>
                            <p class="font-semibold">${type === 'cash' ? `UGX ${formatMoney(amount)}` : `${quantity} items`}</p>
                        </div>
                        <div>
                            <p class="text-sm text-gray-500">Method</p>
                            <p class="font-semibold">${method || 'cash'}</p>
                        </div>
                    </div>
                    <div>
                        <p class="text-sm text-gray-500">Date</p>
                        <p class="font-semibold">${date ? new Date(date).toLocaleString() : 'N/A'}</p>
                    </div>
                    <div>
                        <p class="text-sm text-gray-500">Receipt</p>
                        <p class="font-mono text-sm text-blue-600">#${receipt || 'N/A'}</p>
                    </div>
                </div>
                <div class="flex gap-3 mt-6 pt-4 border-t">
                    <button onclick="closePaymentEditor(); confirmDeletePayment('${paymentId}', '${periodKey}')" 
                            class="flex-1 bg-red-600 text-white py-2 rounded-lg hover:bg-red-700 transition">
                        <i class="fas fa-trash"></i> Delete Payment
                    </button>
                    <button onclick="closePaymentEditor()" 
                            class="flex-1 bg-gray-300 text-gray-700 py-2 rounded-lg hover:bg-gray-400 transition">
                        Close
                    </button>
                </div>
            </div>
        </div>
    `;

    document.body.insertAdjacentHTML('beforeend', modalHtml);
}
window.openPaymentHistoryEditor = openPaymentHistoryEditor;

function closePaymentEditor() {
    const modal = document.getElementById('paymentEditorModal');
    if (modal) modal.remove();
}
window.closePaymentEditor = closePaymentEditor;

function showPaymentHistoryEditorModal(paymentData, periodKey, itemId, itemName, componentName) {
    console.log('=== SHOW PAYMENT HISTORY EDITOR MODAL ===');

    // Remove existing modal
    const existingModal = document.getElementById('paymentHistoryEditorModal');
    if (existingModal) existingModal.remove();

    // Determine payment type from paymentData
    const isCashPayment = paymentData.activityItemPayments?.some(p => p.paymentType === 'paid_cash') ||
                          (paymentData.tuitionPaid && paymentData.tuitionPaid > 0);
    const isItemPayment = paymentData.activityItemPayments?.some(p => p.paymentType === 'brought_item');

    // Get the actual payment type (prefer activity item over tuition)
    let paymentType = 'cash'; // default
    let currentAmount = 0;
    let currentQuantity = 0;
    let currentUnitPrice = 0;

    if (isCashPayment) {
        paymentType = 'cash';
        const cashItem = paymentData.activityItemPayments?.find(p => p.paymentType === 'paid_cash');
        currentAmount = cashItem?.amountPaid || paymentData.tuitionPaid || 0;
        currentUnitPrice = cashItem?.unitPrice || 0;
    } else if (isItemPayment) {
        paymentType = 'item';
        const itemPayment = paymentData.activityItemPayments?.find(p => p.paymentType === 'brought_item');
        currentQuantity = itemPayment?.itemsBrought || 0;
        currentUnitPrice = itemPayment?.unitPrice || 0;
    } else {
        // Fallback: if payment has no activity items, treat as cash (tuition)
        if (paymentData.tuitionPaid) {
            paymentType = 'cash';
            currentAmount = paymentData.tuitionPaid || 0;
        } else {
            showToast('Unknown payment type', 'error');
            return;
        }
    }

    // Determine display name
    const displayItemName = paymentData.activityItemPayments?.[0]?.itemName || itemName || 'Payment';
    const displayComponentName = paymentData.activityItemPayments?.[0]?.componentName || componentName || '';

    // Format date for inputs
    const paymentDate = paymentData.date ? paymentData.date.split('T')[0] : new Date().toISOString().split('T')[0];
    const paymentTime = paymentData.date ? paymentData.date.split('T')[1]?.substring(0, 5) || '12:00' : '12:00';

    // Build modal HTML
    const modalHtml = `
        <div class="fixed inset-0 bg-black bg-opacity-60 backdrop-blur-sm flex items-center justify-center z-[200] overflow-y-auto" id="paymentHistoryEditorModal">
            <div class="bg-white rounded-2xl p-6 max-w-lg w-full mx-4 my-8 shadow-2xl transform transition-all duration-300 scale-100" id="paymentEditorContent">
                <!-- Header -->
                <div class="flex justify-between items-center mb-4 pb-3 border-b">
                    <div>
                        <h3 class="text-xl font-bold flex items-center gap-2">
                            <i class="fas fa-edit text-blue-600"></i>
                            Edit Payment
                        </h3>
                        <p class="text-xs text-gray-500">${displayItemName} ${displayComponentName ? `- ${displayComponentName}` : ''}</p>
                    </div>
                    <button onclick="closePaymentHistoryEditor()" class="text-gray-500 hover:text-gray-700 text-2xl">&times;</button>
                </div>

                <!-- Payment Info -->
                <div class="bg-blue-50 rounded-lg p-3 mb-4 border border-blue-200">
                    <div class="flex justify-between text-sm">
                        <span class="text-gray-500">Receipt Number:</span>
                        <span class="font-mono font-semibold">${paymentData.receiptNumber || 'N/A'}</span>
                    </div>
                    <div class="flex justify-between text-sm">
                        <span class="text-gray-500">Payment Type:</span>
                        <span class="font-semibold">${paymentType === 'cash' ? '💵 Cash Payment' : '📦 Items Brought'}</span>
                    </div>
                    <div class="flex justify-between text-sm">
                        <span class="text-gray-500">Method:</span>
                        <span class="font-semibold">${(paymentData.method || 'cash').toUpperCase()}</span>
                    </div>
                </div>

                <!-- Edit Form -->
                <div class="space-y-4">
                    <!-- Only show the relevant input based on payment type -->
                    ${paymentType === 'cash' ? `
                        <div>
                            <label class="block text-sm font-medium mb-1">💵 Amount (UGX)</label>
                            <input type="number" id="editPaymentAmount"
                                   class="w-full border rounded-lg px-4 py-2 text-lg focus:ring-2 focus:ring-blue-500"
                                   value="${currentAmount}" min="0" step="1000">
                            ${currentUnitPrice > 0 ? `<p class="text-xs text-gray-400 mt-1">Unit price: UGX ${formatMoney(currentUnitPrice)} (amount must be a multiple)</p>` : ''}
                            <input type="hidden" id="editPaymentType" value="cash">
                        </div>
                    ` : `
                        <div>
                            <label class="block text-sm font-medium mb-1">📦 Items Brought</label>
                            <input type="number" id="editPaymentQuantity"
                                   class="w-full border rounded-lg px-4 py-2 text-lg focus:ring-2 focus:ring-blue-500"
                                   value="${currentQuantity}" min="0" step="1">
                            ${currentUnitPrice > 0 ? `<p class="text-xs text-gray-400 mt-1">Unit price: UGX ${formatMoney(currentUnitPrice)}</p>` : ''}
                            <input type="hidden" id="editPaymentType" value="item">
                        </div>
                    `}

                    <!-- Receipt Number -->
                    <div>
                        <label class="block text-sm font-medium mb-1">📋 Receipt Number</label>
                        <input type="text" id="editPaymentReceipt"
                               class="w-full border rounded-lg px-4 py-2 focus:ring-2 focus:ring-blue-500"
                               value="${paymentData.receiptNumber || ''}" placeholder="Enter receipt number">
                    </div>

                    <!-- Date & Time -->
                    <div class="grid grid-cols-2 gap-3">
                        <div>
                            <label class="block text-sm font-medium mb-1">📅 Date</label>
                            <input type="date" id="editPaymentDate"
                                   class="w-full border rounded-lg px-4 py-2 focus:ring-2 focus:ring-blue-500"
                                   value="${paymentDate}">
                        </div>
                        <div>
                            <label class="block text-sm font-medium mb-1">🕐 Time</label>
                            <input type="time" id="editPaymentTime"
                                   class="w-full border rounded-lg px-4 py-2 focus:ring-2 focus:ring-blue-500"
                                   value="${paymentTime}">
                        </div>
                    </div>

                    <!-- Notes -->
                    <div>
                        <label class="block text-sm font-medium mb-1">📝 Notes</label>
                        <input type="text" id="editPaymentNotes"
                               class="w-full border rounded-lg px-4 py-2 focus:ring-2 focus:ring-blue-500"
                               value="${paymentData.notes || ''}" placeholder="Optional notes">
                    </div>
                </div>

                <!-- Action Buttons -->
                <div class="mt-6 pt-4 border-t flex gap-3">
                    <button onclick="savePaymentHistoryEdit('${paymentData.id}', '${periodKey}')"
                            class="flex-1 bg-green-600 text-white py-2.5 rounded-lg font-semibold hover:bg-green-700 transition flex items-center justify-center gap-2">
                        <i class="fas fa-save"></i> Save Changes
                    </button>
                    <button onclick="confirmDeletePayment('${paymentData.id}', '${periodKey}')"
                            class="flex-1 bg-red-600 text-white py-2.5 rounded-lg font-semibold hover:bg-red-700 transition flex items-center justify-center gap-2">
                        <i class="fas fa-trash"></i> Delete Payment
                    </button>
                    <button onclick="closePaymentHistoryEditor()"
                            class="bg-gray-300 text-gray-700 px-4 py-2.5 rounded-lg font-semibold hover:bg-gray-400 transition">
                        Cancel
                    </button>
                </div>

                <div class="mt-2 text-xs text-gray-400 text-center">
                    <i class="fas fa-info-circle"></i> Editing this payment will recalculate all affected balances
                </div>
            </div>
        </div>
    `;

    document.body.insertAdjacentHTML('beforeend', modalHtml);

    // Focus on the input
    setTimeout(() => {
        const firstInput = document.querySelector('#editPaymentAmount, #editPaymentQuantity');
        if (firstInput) firstInput.focus();
    }, 100);
}

async function savePaymentHistoryEdit(paymentId, periodKey) {
    console.log('=== SAVE PAYMENT HISTORY EDIT ===');
    console.log('Payment ID:', paymentId);

    // Get values from the form
    const amountInput = document.getElementById('editPaymentAmount');
    const quantityInput = document.getElementById('editPaymentQuantity');
    const typeInput = document.getElementById('editPaymentType');
    const receiptInput = document.getElementById('editPaymentReceipt');
    const dateInput = document.getElementById('editPaymentDate');
    const timeInput = document.getElementById('editPaymentTime');
    const notesInput = document.getElementById('editPaymentNotes');

    const paymentType = typeInput?.value || 'cash';

    // Build the update payload
    const updateData = {
        paymentType: paymentType,                     // 'cash' or 'item'
        amount: amountInput ? parseFloat(amountInput.value) || 0 : null,
        quantity: quantityInput ? parseInt(quantityInput.value) || 0 : null,
        receiptNumber: receiptInput?.value?.trim() || '',
        date: dateInput?.value || '',
        time: timeInput?.value || '',
        notes: notesInput?.value?.trim() || ''
    };

    // Combine date and time
    if (updateData.date && updateData.time) {
        updateData.date = `${updateData.date}T${updateData.time}`;
    } else if (updateData.date) {
        updateData.date = `${updateData.date}T12:00:00`;
    }

    console.log('Update data:', updateData);

    // Confirm with user
    const confirmMsg = `⚠️ Update this payment?\n\n` +
                       `Type: ${paymentType === 'cash' ? '💵 Cash' : '📦 Items'}\n` +
                       `Value: ${paymentType === 'cash' ? `UGX ${formatMoney(updateData.amount)}` : `${updateData.quantity} items`}\n` +
                       `Receipt: ${updateData.receiptNumber || 'N/A'}\n` +
                       `Date: ${new Date(updateData.date).toLocaleString()}\n\n` +
                       `This will update the payment record.`;

    if (!confirm(confirmMsg)) return;

    // Disable buttons
    const saveBtn = document.querySelector('#paymentHistoryEditorModal .bg-green-600');
    const deleteBtn = document.querySelector('#paymentHistoryEditorModal .bg-red-600');
    if (saveBtn) { saveBtn.innerHTML = '<i class="fas fa-spinner fa-spin"></i> Saving...'; saveBtn.disabled = true; }
    if (deleteBtn) deleteBtn.disabled = true;

    try {
        // Send update to server
        const response = await fetch(`/api/fee/payments/${paymentId}`, {
            method: 'PUT',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(updateData)
        });

        if (!response.ok) {
            throw new Error(`Failed to update payment: ${response.status}`);
        }

        const result = await response.json();
        console.log('Update result:', result);

        // Close the modal
        closePaymentHistoryEditor();

        // Show success message
        showToast('✅ Payment updated successfully!', 'success');

        // Refresh the collection form
        const studentId = window.currentStudent?.id;
        if (studentId) {
            await loadMultiPeriodCollectionForm(studentId);
        } else {
            location.reload();
        }

    } catch (error) {
        console.error('Error saving payment edit:', error);
        showToast('❌ Error updating payment: ' + error.message, 'error');

        // Re-enable buttons
        if (saveBtn) { saveBtn.innerHTML = '<i class="fas fa-save"></i> Save Changes'; saveBtn.disabled = false; }
        if (deleteBtn) deleteBtn.disabled = false;
    }
}


function closePaymentHistoryEditor() {
    const modal = document.getElementById('paymentHistoryEditorModal');
    if (modal) {
        // Animate out
        const content = document.getElementById('paymentEditorContent');
        if (content) {
            content.classList.add('scale-95', 'opacity-0');
            setTimeout(() => {
                modal.remove();
            }, 300);
        } else {
            modal.remove();
        }
    }
}

async function deletePaymentRecord(paymentId, periodKey) {
    console.log('Deleting payment with ID:', paymentId);
    
    if (!paymentId || paymentId === 'undefined' || paymentId === 'null' || paymentId === '') {
        showToast('❌ Invalid payment ID', 'error');
        return;
    }

    try {
        const response = await fetch(`/api/fee/payments/${paymentId}`, {
            method: 'DELETE',
            headers: { 'Content-Type': 'application/json' }
        });

        if (!response.ok) {
            const error = await response.json();
            throw new Error(error.error || `Failed to delete payment (${response.status})`);
        }

        const result = await response.json();
        console.log('Delete result:', result);
        
        showToast('✅ Payment record deleted successfully', 'success');

        // Reload the collection form to refresh data
        const student = window.currentStudent;
        if (student && student.id) {
            await loadMultiPeriodCollectionForm(student.id);
        } else {
            // Try to get student from other sources
            const studentId = window.currentStudentId || document.getElementById('collectStudentSelect')?.value;
            if (studentId) {
                await loadMultiPeriodCollectionForm(studentId);
            } else {
                location.reload();
            }
        }
    } catch (error) {
        console.error('Error deleting payment:', error);
        showToast('❌ ' + error.message, 'error');
    }
}
window.deletePaymentRecord = deletePaymentRecord;
window.deletePaymentRecord = deletePaymentRecord;

function confirmDeletePayment(paymentId, periodKey) {
    if (!paymentId || paymentId === 'undefined' || paymentId === 'null' || paymentId === '') {
        showToast('⚠️ Cannot delete: This payment does not have a valid ID', 'warning');
        console.warn('Delete attempted with invalid payment ID:', paymentId);
        return;
    }

    if (!confirm('⚠️ Are you sure you want to delete this payment record?\n\nThis action cannot be undone.')) {
        return;
    }

    deletePaymentRecord(paymentId, periodKey);
}
window.confirmDeletePayment = confirmDeletePayment;
window.confirmDeletePayment = confirmDeletePayment;

function toggleTuitionHistory(tuitionHistoryId) {
    const element = document.getElementById(tuitionHistoryId);
    if (!element) return;
    
    element.classList.toggle('hidden');
    
    // Update the button
    const button = element.parentElement.querySelector('button');
    if (button) {
        const icon = button.querySelector('i');
        if (icon) {
            icon.classList.toggle('fa-chevron-down');
            icon.classList.toggle('fa-chevron-up');
        }
        const isHidden = element.classList.contains('hidden');
        button.innerHTML = button.innerHTML.replace(/View|Hide/, isHidden ? 'View' : 'Hide');
    }
    
    // Store state
    if (!window.expandedTuitionHistories) window.expandedTuitionHistories = {};
    window.expandedTuitionHistories[tuitionHistoryId] = !element.classList.contains('hidden');
}
window.toggleTuitionHistory = toggleTuitionHistory;

function openTuitionPaymentEditor(historyEntryId) {
    const element = document.getElementById(historyEntryId);
    if (!element) {
        showToast('⚠️ Tuition payment entry not found', 'warning');
        return;
    }

    const paymentId = element.dataset.paymentId;
    const receipt = element.dataset.receipt;
    const amount = element.dataset.amount;
    const date = element.dataset.date;
    const method = element.dataset.method;
    const periodKey = element.dataset.period;

    if (!paymentId || paymentId === 'undefined' || paymentId === 'null' || paymentId === '') {
        showToast('⚠️ Cannot edit this payment (no valid ID)', 'warning');
        return;
    }

    // Show a modal with edit/delete options
    const modalHtml = `
        <div class="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50" id="tuitionPaymentEditorModal">
            <div class="bg-white rounded-2xl p-6 max-w-md w-full mx-4 shadow-2xl">
                <div class="flex justify-between items-center mb-4 pb-3 border-b">
                    <h3 class="text-lg font-bold">💰 Tuition Payment</h3>
                    <button onclick="closeTuitionPaymentEditor()" class="text-gray-500 hover:text-gray-700 text-2xl">&times;</button>
                </div>
                <div class="space-y-3">
                    <div class="bg-blue-50 p-3 rounded-lg">
                        <p class="text-sm text-gray-500">Tuition Payment</p>
                        <p class="font-semibold text-lg text-blue-600">UGX ${formatMoney(amount)}</p>
                    </div>
                    <div class="grid grid-cols-2 gap-3">
                        <div>
                            <p class="text-sm text-gray-500">Method</p>
                            <p class="font-semibold">${method || 'cash'}</p>
                        </div>
                        <div>
                            <p class="text-sm text-gray-500">Receipt</p>
                            <p class="font-mono text-sm text-blue-600">#${receipt || 'N/A'}</p>
                        </div>
                    </div>
                    <div>
                        <p class="text-sm text-gray-500">Date</p>
                        <p class="font-semibold">${date ? new Date(date).toLocaleString() : 'N/A'}</p>
                    </div>
                </div>
                <div class="flex gap-3 mt-6 pt-4 border-t">
                    <button onclick="closeTuitionPaymentEditor(); confirmDeletePayment('${paymentId}', '${periodKey}')" 
                            class="flex-1 bg-red-600 text-white py-2 rounded-lg hover:bg-red-700 transition">
                        <i class="fas fa-trash"></i> Delete Payment
                    </button>
                    <button onclick="closeTuitionPaymentEditor()" 
                            class="flex-1 bg-gray-300 text-gray-700 py-2 rounded-lg hover:bg-gray-400 transition">
                        Close
                    </button>
                </div>
            </div>
        </div>
    `;

    // Remove any existing modal
    const existingModal = document.getElementById('tuitionPaymentEditorModal');
    if (existingModal) existingModal.remove();
    
    document.body.insertAdjacentHTML('beforeend', modalHtml);
}
window.openTuitionPaymentEditor = openTuitionPaymentEditor;

function closeTuitionPaymentEditor() {
    const modal = document.getElementById('tuitionPaymentEditorModal');
    if (modal) modal.remove();
}
window.closeTuitionPaymentEditor = closeTuitionPaymentEditor;

// Reset all payments for a specific item
// Reset all payments for a specific item
async function confirmResetItemPayments(itemId, itemName, componentName, periodKey) {
    console.log('🔧 confirmResetItemPayments called with:', { itemId, itemName, componentName, periodKey });

    const student = window.currentStudent || window.currentCollectingStudent;
    if (!student) {
        showToast('❌ Error: Student data not loaded. Please refresh.', 'error');
        return;
    }

    console.log('✅ Student found:', student.firstName, student.lastName, student.id);

    if (!confirm(`⚠️ Reset all payments for "${itemName}"?\n\nThis will permanently delete ALL payment records for this item for ${student.firstName} ${student.lastName}.\n\nThis action cannot be undone!\n\nAre you sure?`)) {
        return;
    }

    if (!confirm(`Are you absolutely sure? This will remove all payments for "${itemName}" and the item will become unpaid.`)) {
        return;
    }

    const payload = {
        studentId: student.id,
        itemName: itemName,
        componentName: componentName
    };

    console.log('📤 Sending DELETE request to /api/fee/payments/reset-item with payload:', payload);

    try {
        showToast('⏳ Resetting payments...', 'info');

        const response = await fetch('/api/fee/payments/reset-item', {
            method: 'DELETE',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(payload)
        });

        const result = await response.json();
        console.log('📥 Response:', result);

        if (!response.ok) {
            throw new Error(result.error || `HTTP ${response.status}`);
        }

        // Display result based on deletedCount
        if (result.deletedCount === undefined || result.deletedCount === null) {
            showToast('⚠️ No payment records were found for this item.', 'warning');
        } else if (result.deletedCount === 0) {
            showToast(`⚠️ No payments found for "${itemName}". Nothing deleted.`, 'warning');
        } else {
            showToast(`✅ ${result.message || `Deleted ${result.deletedCount} payment(s) for "${itemName}"`}`, 'success');
        }

        // Reload the collection form to reflect changes
        console.log('🔄 Reloading collection form...');
        await loadMultiPeriodCollectionForm(student.id);

    } catch (error) {
        console.error('❌ Error resetting payments:', error);
        showToast('❌ ' + error.message, 'error');
    }
}

window.confirmResetItemPayments = confirmResetItemPayments;

