function showHistoryTooltip(el) {
    const tooltip = el.querySelector('.history-tooltip');
    if (tooltip) {
        tooltip.style.display = 'block';
        // Optional: position adjustment to prevent overflow
        const rect = el.getBoundingClientRect();
        const tooltipRect = tooltip.getBoundingClientRect();
        if (rect.right + tooltipRect.width > window.innerWidth) {
            tooltip.style.left = 'auto';
            tooltip.style.right = '0';
        } else {
            tooltip.style.left = '0';
            tooltip.style.right = 'auto';
        }
        el.classList.add('show');
    }
}

function hideHistoryTooltip(el) {
    const tooltip = el.querySelector('.history-tooltip');
    if (tooltip) {
        tooltip.style.display = 'none';
        el.classList.remove('show');
    }
}